### Formatação defensiva de datas/horários técnicos -------------------------
### Evita warning residual de as.POSIXlt.POSIXct quando metadados de arquivos
### apresentam mtime ausente/ilegível em mounts, caches ou arquivos legados.
monitora_posixct_na <- function() {
  structure(NA_real_, class = c("POSIXct", "POSIXt"), tzone = "")
}

monitora_formatar_posixct_seguro <- function(x, formato = "%Y-%m-%d %H:%M:%S") {
  if (is.null(x) || !length(x)) return(NA_character_)
  out <- rep(NA_character_, length(x))
  ok <- !is.na(x)
  if (any(ok)) {
    out[ok] <- suppressWarnings(format(as.POSIXct(x[ok]), formato))
  }
  out
}
MONITORA_LOG_EXECUCAO <- data.table(
  etapa = character(),
  severidade = character(),
  arquivo = character(),
  detalhe = character(),
  acao = character()
)

monitora_log_registrar_evento <- function(etapa, severidade = "INFO", arquivo = NA_character_, detalhe = NA_character_, acao = NA_character_) {
  # Mantém o log de execução em estrutura data.table, usando rbindlist() para reduzir sobrecarga
  # em relação a rbind() incremental.
  MONITORA_LOG_EXECUCAO <<- data.table::rbindlist(
    list(
      MONITORA_LOG_EXECUCAO,
      data.table::data.table(
        etapa = as.character(etapa),
        severidade = as.character(severidade),
        arquivo = as.character(arquivo),
        detalhe = as.character(detalhe),
        acao = as.character(acao)
      )
    ),
    fill = TRUE,
    use.names = TRUE
  )
  invisible(TRUE)
}

monitora_esquema_colunas_resumo <- function(dt, arquivo = NA_character_, fase = NA_character_) {
  nm <- names(dt)
  bytes <- nchar(nm, type = "bytes", allowNA = TRUE, keepNA = TRUE)
  nm_norm <- tolower(trimws(nm))
  data.table::data.table(
    fase = as.character(fase)[1L],
    arquivo = as.character(arquivo)[1L],
    n_linhas = if (is.null(dt)) NA_integer_ else nrow(dt),
    n_colunas = length(nm),
    n_colunas_duplicadas = sum(duplicated(nm)),
    n_colunas_duplicadas_norm = sum(duplicated(nm_norm)),
    max_bytes_nome_coluna = if (length(bytes)) max(bytes, na.rm = TRUE) else 0L,
    soma_bytes_nomes_colunas = if (length(bytes)) sum(bytes, na.rm = TRUE) else 0L,
    n_colunas_com_html = sum(grepl("<[^>]+>|&[A-Za-z]+;", nm), na.rm = TRUE),
    n_colunas_com_sufixo_excel = sum(grepl("\\.[0-9]+$", nm), na.rm = TRUE),
    n_colunas_vazias = sum(!nzchar(trimws(nm)) | is.na(nm)),
    n_colunas_longas_100b = sum(bytes > 100L, na.rm = TRUE),
    n_colunas_longas_120b = sum(bytes > 120L, na.rm = TRUE),
    esquema_extremo = length(nm) > monitora_global_get("MONITORA_ESQUEMA_EXTREMO_NCOLS", 150L) |
      (if (length(bytes)) sum(bytes, na.rm = TRUE) else 0L) > monitora_global_get("MONITORA_ESQUEMA_EXTREMO_SOMA_BYTES", 9000L) |
      (if (length(bytes)) max(bytes, na.rm = TRUE) else 0L) > monitora_global_get("MONITORA_ESQUEMA_EXTREMO_MAX_BYTES", 120L)
  )
}

monitora_auditar_esquema_colunas <- function(dt, fase = "esquema", arquivo = NA_character_) {
  if (!isTRUE(monitora_global_get("MONITORA_AUDITORIA_ESQUEMA_COLUNAS", TRUE))) return(invisible(data.table::data.table()))
  resumo <- monitora_esquema_colunas_resumo(dt, arquivo = arquivo, fase = fase)
  out_dir <- tryCatch(monitora_dir_global_obrigatorio("MONITORA_OUTPUT_DIR", criar = TRUE), error = function(e) NULL)
  log_dir <- tryCatch(monitora_dir_global_obrigatorio("MONITORA_LOG_DIR", criar = TRUE), error = function(e) NULL)
  exec_id <- as.character(monitora_global_get("MONITORA_EXEC_ID", format(Sys.time(), "%Y%m%d_%H%M%S")))
  if (!is.null(out_dir)) monitora_fwrite(resumo, file.path(out_dir, "auditoria_esquema_colunas_ultima_execucao.csv"), na = "")
  if (!is.null(log_dir)) monitora_fwrite(resumo, file.path(log_dir, paste0("auditoria_esquema_colunas_", fase, "_", exec_id, ".csv")), na = "")
  if (isTRUE(resumo$esquema_extremo[1])) {
    msg <- paste0(
      "Esquema amplo/histórico detectado em ", fase, ": ",
      resumo$n_colunas, " colunas; soma_bytes_nomes_colunas=", resumo$soma_bytes_nomes_colunas,
      "; max_bytes_nome_coluna=", resumo$max_bytes_nome_coluna,
      ". Cache de relatórios usará chave hash curta e fallback seguro."
    )
    if (exists("monitora_log_registrar_evento", mode = "function")) {
      monitora_log_registrar_evento("auditoria_esquema_colunas", "AVISO", arquivo, msg, "seguir em modo tolerante para dados heterogêneos/manipulados")
    }
    message(msg)
  }
  invisible(resumo)
}

monitora_dt_referenciar <- function(x) {
  # Converte para data.table por referência sempre que possível.
  # Evita cópias desnecessárias de objetos grandes.
  if (!data.table::is.data.table(x)) data.table::setDT(x)
  x
}

monitora_rm_seguro <- function(..., envir = .GlobalEnv) {
  # Remove objetos temporários apenas se existirem no ambiente informado.
  # Evita warnings quando exists() encontra funções em pacotes anexados, como utils::data().
  objs <- as.character(unlist(list(...), use.names = FALSE))
  objs <- unique(objs[!is.na(objs) & nzchar(objs)])
  objs <- objs[vapply(objs, exists, logical(1), envir = envir, inherits = FALSE)]
  if (length(objs)) rm(list = objs, envir = envir)
  invisible(TRUE)
}


monitora_join_padronizar_chaves <- function(x, y, by) {
  # Padroniza tipos das chaves antes das junções com data.table.
  # Isso evita erros como integer vs character em ANO e reduz coerções implícitas caras.
  for (cc in by) {
    if (!(cc %in% names(x)) || !(cc %in% names(y))) next
    cx <- class(x[[cc]])[1]
    cy <- class(y[[cc]])[1]
    if (!identical(cx, cy)) {
      data.table::set(x, j = cc, value = as.character(x[[cc]]))
      data.table::set(y, j = cc, value = as.character(y[[cc]]))
    }
  }
  invisible(TRUE)
}

monitora_dt_unique_por_chaves <- function(dt, by, contexto = "join") {
  # Garante uma linha por chave antes das junções de anotação ou estatística.
  # Usa duplicated.data.table()/unique.data.table() por chave, evitando a tabela agregada
  # dt[, .N, by=] quando só precisamos saber se existe duplicidade.
  dt <- monitora_dt_referenciar(dt)
  by <- by[by %in% names(dt)]
  if (length(by) == 0 || nrow(dt) == 0) return(dt)
  pos_dup <- duplicated(dt, by = by)
  if (any(pos_dup)) {
    if (exists("monitora_stat_registrar_msg", mode = "function") && exists("MONITORA_STAT_VERBOSE", inherits = TRUE) && isTRUE(get("MONITORA_STAT_VERBOSE", inherits = TRUE))) {
      monitora_stat_registrar_msg(sprintf(
        "deduplicando %s antes do join: %s linha(s) duplicada(s)",
        contexto,
        format(sum(pos_dup), big.mark = ".", decimal.mark = ",")
      ))
    }
    dt <- unique(dt, by = by)
  }
  dt[]
}

monitora_dt_left_join <- function(x, y, by) {
  # Junção à esquerda com chaves data.table, preservando a ordem original de x.
  # Evita o merge() genérico e reduz cópias em junções frequentes.
  x <- monitora_dt_referenciar(x)
  y <- monitora_dt_referenciar(y)
  by <- by[by %in% names(x) & by %in% names(y)]
  if (length(by) == 0) return(x)
  ord_col <- ".MONITORA_ORDEM_JOIN_TMP"
  while (ord_col %in% names(x) || ord_col %in% names(y)) ord_col <- paste0(ord_col, "_")
  data.table::set(x, j = ord_col, value = seq_len(nrow(x)))
  monitora_join_padronizar_chaves(x, y, by)
  y <- monitora_dt_unique_por_chaves(y, by, contexto = "tabela direita em left_join")
  data.table::setkeyv(x, by)
  data.table::setkeyv(y, by)
  out <- y[x]
  data.table::setorderv(out, ord_col)
  out[, (ord_col) := NULL]
  if (ord_col %in% names(x)) x[, (ord_col) := NULL]
  out[]
}

monitora_dt_full_join_list <- function(lst, by) {
  # Junção completa de várias tabelas por data.table: primeiro cria a união das chaves,
  # depois anexa cada tabela por junção à esquerda chaveada. Evita Reduce()+merge().
  lst <- Filter(function(z) !is.null(z) && nrow(z) > 0, lst)
  if (length(lst) == 0) return(data.table::data.table())
  lst <- lapply(lst, monitora_dt_referenciar)
  by <- by[Reduce(`&`, lapply(lst, function(z) by %in% names(z)))]
  if (length(by) == 0) return(data.table::rbindlist(lst, fill = TRUE, use.names = TRUE))
  keys <- data.table::rbindlist(lapply(lst, function(z) unique(z[, ..by])), fill = TRUE, use.names = TRUE)
  keys <- unique(keys)
  data.table::setkeyv(keys, by)
  out <- keys
  for (ii in seq_along(lst)) {
    z <- lst[[ii]]
    monitora_join_padronizar_chaves(out, z, by)
    z <- monitora_dt_unique_por_chaves(z, by, contexto = paste0("tabela ", ii, " em full_join"))
    data.table::setkeyv(out, by)
    data.table::setkeyv(z, by)
    out <- z[out]
    if (exists("monitora_recurso_deve_gc", mode = "function") && monitora_recurso_deve_gc()) gc(verbose = FALSE)
  }
  out[]
}

monitora_dt_mover_colunas_antes <- function(dt, cols, before) {
  # Reposiciona colunas por referência, sem copiar objetos grandes.
  if (!data.table::is.data.table(dt)) data.table::setDT(dt)
  cols <- cols[cols %in% names(dt)]
  if (length(cols) == 0 || !(before %in% names(dt))) return(invisible(dt))
  base <- setdiff(names(dt), cols)
  pos <- match(before, base)
  if (is.na(pos)) return(invisible(dt))
  new_order <- append(base, cols, after = pos - 1L)
  data.table::setcolorder(dt, new_order)
  invisible(dt)
}

monitora_dt_somar_colunas <- function(dt, cols) {
  # Soma colunas por linha usando .SD; em geral é usado em registros_corrig_stat,
  # que é menor que registros_corrig, mas ainda deve evitar cópias desnecessárias.
  if (!data.table::is.data.table(dt)) data.table::setDT(dt)
  cols <- cols[cols %in% names(dt)]
  if (length(cols) == 0) return(rep(0, nrow(dt)))
  dt[, rowSums(.SD, na.rm = TRUE), .SDcols = cols]
}

monitora_geo_separar_colunas_coordenadas <- function(dt, col, novos) {
  # Divide coordenadas já normalizadas por espaço, sem depender de objetos intermediários grandes.
  if (!data.table::is.data.table(dt)) data.table::setDT(dt)
  if (!(col %in% names(dt))) {
    for (nm in novos) data.table::set(dt, j = nm, value = NA_character_)
    return(invisible(dt))
  }
  parts <- data.table::tstrsplit(as.character(dt[[col]]), "[[:space:]]+", perl = TRUE, keep = seq_along(novos), type.convert = FALSE)
  for (i in seq_along(novos)) {
    val <- if (length(parts) >= i && !is.null(parts[[i]])) parts[[i]] else rep(NA_character_, nrow(dt))
    data.table::set(dt, j = novos[i], value = val)
  }
  invisible(dt)
}

### Controle dinâmico de memória e processamento
### Objetivo: preservar velocidade quando há memória disponível e reduzir uso de recursos
### somente quando o volume de dados ou o ambiente indicarem risco de estouro de RAM.
### Perfis configuráveis por variável de ambiente:
### MONITORA_PERFIL_EXECUCAO = "auto" (padrão: equilíbrio adaptativo)
### MONITORA_PERFIL_EXECUCAO = "rapido" (maior performance; exige RAM folgada)
### MONITORA_PERFIL_EXECUCAO = "economico" (menor pico de RAM; pode ser mais lento)
monitora_cfg_env_bool <- function(nome, default = FALSE) {
  val <- Sys.getenv(nome, unset = ifelse(default, "true", "false"))
  tolower(trimws(val)) %in% c("1", "true", "t", "sim", "s", "yes", "y")
}
monitora_cfg_env_int <- function(nome, default) {
  val <- suppressWarnings(as.integer(Sys.getenv(nome, unset = as.character(default))))
  ifelse(is.na(val) || val < 1L, as.integer(default), val)
}
monitora_cfg_env_chr <- function(nome, default) {
  val <- Sys.getenv(nome, unset = default)
  val <- tolower(trimws(val))
  if (!nzchar(val)) default else val
}

MONITORA_PERFIL_EXECUCAO <- monitora_cfg_env_chr("MONITORA_PERFIL_EXECUCAO", "auto")
if (!(MONITORA_PERFIL_EXECUCAO %in% c("auto", "rapido", "economico", "conservador"))) {
  MONITORA_PERFIL_EXECUCAO <- "auto"
}
if (identical(MONITORA_PERFIL_EXECUCAO, "conservador")) MONITORA_PERFIL_EXECUCAO <- "economico"

perfil_rapido <- identical(MONITORA_PERFIL_EXECUCAO, "rapido")
perfil_economico <- identical(MONITORA_PERFIL_EXECUCAO, "economico")

# Valores padrão por perfil. Variáveis de ambiente explícitas continuam tendo prioridade.
default_batch <- if (perfil_rapido) 100L else if (perfil_economico) 10L else 50L
default_threads <- if (perfil_rapido) {
  max(1L, parallel::detectCores(logical = FALSE))
} else if (perfil_economico) {
  2L
} else {
  min(4L, max(1L, parallel::detectCores(logical = FALSE)))
}

MONITORA_BATCH_SIZE_CSV <- monitora_cfg_env_int("MONITORA_BATCH_SIZE_CSV", default_batch)
MONITORA_AUDITORIA_COORDENADAS_COMPLETA <- monitora_cfg_env_bool("MONITORA_AUDITORIA_COORDENADAS_COMPLETA", FALSE)
MONITORA_EXPORTAR_GRAFICOS <- monitora_cfg_env_bool("MONITORA_EXPORTAR_GRAFICOS", !perfil_economico)
### Controle fino da exportação de PNGs.
### - completo: exporta PNGs por padrão (validação/publicação);
### - auto: exporta PNGs quando os demais limites permitirem; não desliga apenas por haver painel;
### - edicao: pula PNGs quando o painel de correções estiver aberto, por escolha explícita;
### - indice: gera índice/relatório textual sem gravar PNGs;
### - desligado: não exporta PNGs.
MONITORA_EXPORTAR_PNG_MODO <- monitora_cfg_env_chr("MONITORA_EXPORTAR_PNG_MODO", "completo")
if (!(MONITORA_EXPORTAR_PNG_MODO %in% c("auto", "completo", "edicao", "desligado", "indice"))) MONITORA_EXPORTAR_PNG_MODO <- "completo"
MONITORA_EXPORTAR_GRAFICOS_PNG <- monitora_cfg_env_bool("MONITORA_EXPORTAR_GRAFICOS_PNG", !(MONITORA_EXPORTAR_PNG_MODO %in% c("desligado", "indice")))
MONITORA_VALIDAR_PRODUTOS_FINAIS <- monitora_cfg_env_bool("MONITORA_VALIDAR_PRODUTOS_FINAIS", TRUE)
MONITORA_FALHAR_PRODUTOS_FINAIS_AUSENTES <- monitora_cfg_env_bool("MONITORA_FALHAR_PRODUTOS_FINAIS_AUSENTES", TRUE)
### Modo tolerante para conjuntos heterogêneos/manipulados em planilha.
### O script continua preservando travas de integridade, mas trata relatórios
### auxiliares e caches como componentes opcionais: falhas devem gerar auditoria,
### não derrubar produtos principais já calculados.
MONITORA_MODO_DADOS_SUJOS <- monitora_cfg_env_bool("MONITORA_MODO_DADOS_SUJOS", FALSE)
MONITORA_CACHE_RELATORIOS_HABILITADO <- monitora_cfg_env_bool("MONITORA_CACHE_RELATORIOS_HABILITADO", TRUE)
MONITORA_AUDITORIA_ESQUEMA_COLUNAS <- monitora_cfg_env_bool("MONITORA_AUDITORIA_ESQUEMA_COLUNAS", TRUE)
### Auditoria semântica completa antes/depois das correções pode ser cara em
### conjuntos largos. O padrão é incremental, restrito às linhas-alvo das correções.
MONITORA_AUDITORIA_SEMANTICA_CORRECOES_COMPLETA <- monitora_cfg_env_bool("MONITORA_AUDITORIA_SEMANTICA_CORRECOES_COMPLETA", FALSE)
MONITORA_ESQUEMA_EXTREMO_NCOLS <- monitora_cfg_env_int("MONITORA_ESQUEMA_EXTREMO_NCOLS", 150L)
MONITORA_ESQUEMA_EXTREMO_SOMA_BYTES <- monitora_cfg_env_int("MONITORA_ESQUEMA_EXTREMO_SOMA_BYTES", 9000L)
MONITORA_ESQUEMA_EXTREMO_MAX_BYTES <- monitora_cfg_env_int("MONITORA_ESQUEMA_EXTREMO_MAX_BYTES", 120L)
MONITORA_EXPORTAR_KML <- monitora_cfg_env_bool("MONITORA_EXPORTAR_KML", !perfil_economico)
if (isTRUE(MONITORA_MODO_DESLIGAR_PNG)) {
  MONITORA_EXPORTAR_PNG_MODO <- "desligado"
  MONITORA_EXPORTAR_GRAFICOS_PNG <- FALSE
}
if (isTRUE(MONITORA_MODO_DESLIGAR_GRAFICOS)) {
  MONITORA_EXPORTAR_GRAFICOS <- FALSE
  MONITORA_EXPORTAR_GRAFICOS_PNG <- FALSE
  MONITORA_EXPORTAR_PNG_MODO <- "desligado"
  MONITORA_EXPORTAR_KML <- FALSE
}

MONITORA_MAX_LINHAS_GRAFICOS_AUTO <- monitora_cfg_env_int("MONITORA_MAX_LINHAS_GRAFICOS_AUTO", if (perfil_rapido) 500000L else 250000L)
MONITORA_MAX_UAS_KML_AUTO <- monitora_cfg_env_int("MONITORA_MAX_UAS_KML_AUTO", if (perfil_rapido) 10000L else 5000L)
MONITORA_MAX_CHAVES_AUDITORIA_DUP_SEMANTICA <- monitora_cfg_env_int("MONITORA_MAX_CHAVES_AUDITORIA_DUP_SEMANTICA", if (perfil_economico) 50000L else 100000L)

# Coleta de lixo: "auto" preserva desempenho e executa gc() apenas quando a memória disponível fica
# baixa.
# "agressivo" força gc() nos pontos instrumentados; "desligado" evita gc() manual.
MONITORA_GC_MODO <- monitora_cfg_env_chr("MONITORA_GC_MODO", if (perfil_economico) "auto" else "auto")
