monitora_correcao_colapsar_contexto_valores <- function(x, max_valores = 12L) {
  x <- unique(trimws(as.character(x)))
  x <- x[!is.na(x) & nzchar(x)]
  if (!length(x)) return(NA_character_)
  if (length(x) == 1L) return(x[1L])
  x <- sort(x)
  if (length(x) <= max_valores) return(paste(x, collapse = "; "))
  paste0("multiplos(", length(x), "): ", paste(utils::head(x, max_valores), collapse = "; "), "; ...")
}

monitora_correcao_contexto_linhas <- function(dt, linhas, chaves = monitora_correcao_colunas_chave(dt)) {
  dt <- data.table::as.data.table(dt)
  linhas <- unique(as.integer(linhas))
  linhas <- linhas[!is.na(linhas) & linhas >= 1L & linhas <= nrow(dt)]
  get_ctx <- function(col) {
    if (is.na(col) || !nzchar(col) || !(col %in% names(dt)) || !length(linhas)) return(NA_character_)
    monitora_correcao_colapsar_contexto_valores(dt[[col]][linhas])
  }
  data.table::data.table(
    UC = get_ctx(chaves$uc),
    EA = get_ctx(chaves$ea),
    UA = get_ctx(chaves$ua),
    CICLO = get_ctx(chaves$ciclo),
    CAMPANHA = get_ctx(chaves$campanha),
    ANO = get_ctx(chaves$ano),
    `Data (data_hora)` = get_ctx(chaves$data_hora),
    `Ponto amostral` = get_ctx(chaves$ponto_amostral),
    `Ponto metro` = get_ctx(chaves$ponto_metro)
  )
}

monitora_correcao_anexar_contexto_operacao <- function(op, dt, linhas, chaves = monitora_correcao_colunas_chave(dt)) {
  op <- data.table::as.data.table(op)
  linhas <- unique(as.integer(linhas))
  linhas <- linhas[!is.na(linhas) & linhas >= 1L & linhas <= nrow(dt)]
  if (!("linha_indice" %in% names(op))) op[, linha_indice := NA_integer_]
  dt_parece_global <- FALSE
  if (exists("registros_corrig", envir = .GlobalEnv, inherits = FALSE)) {
    rr_global <- get("registros_corrig", envir = .GlobalEnv, inherits = FALSE)
    dt_parece_global <- tryCatch(nrow(dt) == nrow(rr_global), error = function(e) FALSE)
  }
  ### Só gravar linha_indice quando as linhas são índices globais de registros_corrig.
  ### Chamadas com subconjuntos filtrados continuam usando coleta/ponto/uuid como fallback.
  if (isTRUE(dt_parece_global) && nrow(op) == 1L && length(linhas) == 1L) data.table::set(op, j = "linha_indice", value = as.integer(linhas[1L]))
  ctx <- monitora_correcao_contexto_linhas(dt, linhas, chaves)
  for (cc in names(ctx)) {
    if (!(cc %in% names(op))) op[, (cc) := NA_character_]
    data.table::set(op, j = cc, value = ctx[[cc]][1L])
  }
  ### v2.6.1: manter também as chaves técnicas de ponto nas operações compostas.
  ### A aplicação das correções usa ponto_amostral/ponto_metro como chaves estáveis;
  ### se apenas os rótulos "Ponto amostral"/"Ponto metro" forem preenchidos, ações
  ### contratuais derivadas podem voltar para o escopo da COLETA inteira.
  preencher_chave_tecnica <- function(dest, src) {
    if (!(src %in% names(op))) return(invisible(FALSE))
    if (!(dest %in% names(op))) op[, (dest) := NA_character_]
    val_src <- as.character(op[[src]][1L])
    val_dst <- as.character(op[[dest]][1L])
    if (nrow(op) == 1L && monitora_correcao_vazio(val_dst) && !monitora_correcao_vazio(val_src)) {
      data.table::set(op, j = dest, value = val_src)
    }
    invisible(TRUE)
  }
  preencher_chave_tecnica("ponto_amostral", "Ponto amostral")
  preencher_chave_tecnica("ponto_metro", "Ponto metro")
  op[]
}

monitora_correcao_anexar_contexto_auditoria <- function(audit, dt, chaves = monitora_correcao_colunas_chave(dt)) {
  audit <- data.table::as.data.table(audit)
  if (!nrow(audit)) return(audit)
  dt <- data.table::as.data.table(dt)
  campos <- c(
    COLETA = chaves$coleta,
    coleta_uuid = chaves$coleta_uuid,
    uuid_registro = chaves$uuid_registro,
    UC = chaves$uc,
    EA = chaves$ea,
    UA = chaves$ua,
    CICLO = chaves$ciclo,
    CAMPANHA = chaves$campanha,
    ANO = chaves$ano,
    "Data (data_hora)" = chaves$data_hora,
    "Ponto amostral" = chaves$ponto_amostral,
    "Ponto metro" = chaves$ponto_metro
  )
  for (nm in names(campos)) {
    col <- campos[[nm]]
    if (!(nm %in% names(audit))) audit[, (nm) := NA_character_]
    if (is.na(col) || !nzchar(col) || !(col %in% names(dt)) || !("linha_indice" %in% names(audit))) next
    idx <- suppressWarnings(as.integer(audit$linha_indice))
    ok <- !is.na(idx) & idx >= 1L & idx <= nrow(dt)
    vals <- rep(NA_character_, nrow(audit))
    vals[ok] <- as.character(dt[[col]][idx[ok]])
    antigos <- as.character(audit[[nm]])
    preservar <- !is.na(antigos) & nzchar(trimws(antigos))
    vals[preservar] <- antigos[preservar]
    data.table::set(audit, j = nm, value = vals)
  }
  audit[]
}



monitora_correcao_gravar_resumo_operacoes_atomicas <- function(audit, persistencia = data.table::data.table(), contexto = "pos_correcoes") {
  ### Resumo de uma linha por operação semântica. A auditoria detalhada continua
  ### célula a célula, mas este produto facilita validar se cada id_correcao foi
  ### roteado como unidade atômica e se persistiu no objeto/CSV final.
  audit <- data.table::as.data.table(audit)
  persistencia <- data.table::as.data.table(persistencia)
  if (!nrow(audit)) return(data.table::data.table())
  for (cc in c("id_correcao", "status", "atributo", "linha_indice", "mensagem")) if (!(cc %in% names(audit))) data.table::set(audit, j = cc, value = NA_character_)
  for (cc in c("id_correcao", "status_persistencia")) if (!(cc %in% names(persistencia))) data.table::set(persistencia, j = cc, value = NA_character_)
  classificar_tipo <- function(id) {
    id <- as.character(id)
    out <- rep("operacao_generica", length(id))
    out[grepl("^MVLOTE_", id)] <- "movimento_forma_vida_lote_atomico"
    out[grepl("^MOVFV_", id)] <- "movimento_forma_vida_atomico"
    out[grepl("^TRIDESC_", id)] <- "triagem_desconhecida_atomica"
    out[grepl("^TRIOUT", id)] <- "limpeza_outras_formas_atomica"
    out[grepl("^EXCCOL_", id)] <- "exclusao_coleta_atomica"
    out[grepl("^RECALC_SUPERIORES_XLSFORM$", id)] <- "recalculo_superiores_xlsform"
    out[grepl("^SYNC_ENCOSTAM_FINAL$", id)] <- "sincronizacao_final_encostam"
    out
  }
  resumo <- audit[, .(
    tipo_operacao = classificar_tipo(id_correcao[1L]),
    n_linhas_auditoria = .N,
    n_linhas_afetadas = data.table::uniqueN(suppressWarnings(as.integer(linha_indice)), na.rm = TRUE),
    n_atributos_afetados = data.table::uniqueN(as.character(atributo)[!is.na(atributo) & nzchar(as.character(atributo))]),
    status_aplicacao = if (any(grepl("^(falha|bloqueada)", as.character(status)))) "falha_ou_bloqueio" else if (any(as.character(status) %in% c("aplicada", "aplicada_atomica", "excluida_coleta"))) "aplicada" else "sem_alteracao",
    mensagens = monitora_correcao_colapsar_contexto_valores(mensagem, max_valores = 5L)
  ), by = id_correcao]
  if (nrow(persistencia) > 0L) {
    pers <- persistencia[, .(
      n_checagens_persistencia = .N,
      n_falhas_persistencia = sum(grepl("^falha", as.character(status_persistencia)), na.rm = TRUE),
      status_persistencia_operacao = if (any(grepl("^falha", as.character(status_persistencia)))) "falha" else "ok"
    ), by = id_correcao]
    resumo <- merge(resumo, pers, by = "id_correcao", all.x = TRUE)
  } else {
    resumo[, `:=`(n_checagens_persistencia = NA_integer_, n_falhas_persistencia = NA_integer_, status_persistencia_operacao = NA_character_)]
  }
  if (exists("MONITORA_LOG_DIR", inherits = TRUE) && exists("MONITORA_CORRECOES_DIR", inherits = TRUE)) {
    exec_id <- if (exists("MONITORA_EXEC_ID", inherits = TRUE)) MONITORA_EXEC_ID else format(Sys.time(), "%Y%m%d_%H%M%S")
    arq_log <- file.path(MONITORA_LOG_DIR, paste0("auditoria_operacoes_atomicas_resumo_", contexto, "_", exec_id, ".csv"))
    arq_ult <- file.path(MONITORA_CORRECOES_DIR, paste0("auditoria_operacoes_atomicas_resumo_", contexto, "_ultima_execucao.csv"))
    try(monitora_fwrite(resumo, arq_log, na = ""), silent = TRUE)
    try(monitora_fwrite(resumo, arq_ult, na = ""), silent = TRUE)
  }
  resumo[]
}

monitora_correcao_auditar_persistencia_operacoes <- function(dt, audit, chaves = monitora_correcao_colunas_chave(dt), coletas_excluidas = character(), contexto = "pos_correcoes", abortar = TRUE) {
  ### Confere se as operações registradas como aplicadas na auditoria realmente
  ### persistem no objeto final que será gravado/exportado. Esta trava evita o
  ### cenário perigoso em que a auditoria marca uma correção como aplicada, mas o
  ### registros_corrig.csv permanece com o valor antigo por uso de cópia temporária,
  ### linha_indice obsoleto ou reatribuição perdida.
  audit <- data.table::as.data.table(audit)
  dt <- monitora_dt_referenciar(dt)
  if (!nrow(audit)) return(data.table::data.table())
  for (cc in c("id_correcao", "status", "atributo", "linha_indice", "valor_depois", "COLETA", "coleta_uuid", "uuid_registro", "UC", "EA", "UA", "CICLO", "CAMPANHA", "ANO", "Data (data_hora)", "Ponto amostral", "Ponto metro")) {
    if (!(cc %in% names(audit))) data.table::set(audit, j = cc, value = NA_character_)
  }
  coletas_excluidas <- unique(as.character(coletas_excluidas))
  coletas_excluidas <- coletas_excluidas[!is.na(coletas_excluidas) & nzchar(trimws(coletas_excluidas))]
  indice <- monitora_correcao_criar_indice_linhas(dt, chaves)
  norm0 <- function(x) monitora_correcao_na_para_vazio(x)
  localizar_aud <- function(ii) {
    data.table::data.table(
      linha_indice = audit$linha_indice[ii],
      uuid_registro = audit$uuid_registro[ii],
      coleta_uuid = audit$coleta_uuid[ii],
      coleta = audit$COLETA[ii],
      UC = audit$UC[ii],
      EA = audit$EA[ii],
      UA = audit$UA[ii],
      CICLO = audit$CICLO[ii],
      CAMPANHA = audit$CAMPANHA[ii],
      ANO = audit$ANO[ii],
      `Data (data_hora)` = audit[["Data (data_hora)"]][ii],
      ponto_amostral = audit[["Ponto amostral"]][ii],
      ponto_metro = audit[["Ponto metro"]][ii],
      escopo_aplicacao = "ponto"
    )
  }
  out <- vector("list", 0L)
  kk <- 0L

  ### Primeiro valida exclusões por COLETA em lote, uma vez por COLETA.
  if (length(coletas_excluidas) > 0L && !is.na(chaves$coleta) && chaves$coleta %in% names(dt)) {
    for (co in coletas_excluidas) {
      n_rest <- sum(as.character(dt[[chaves$coleta]]) == co, na.rm = TRUE)
      kk <- kk + 1L
      out[[kk]] <- data.table::data.table(
        contexto = contexto,
        id_correcao = paste(unique(audit[COLETA == co & status == "excluida_coleta", id_correcao]), collapse = ";"),
        status_persistencia = ifelse(n_rest == 0L, "ok_exclusao_persistiu", "falha_exclusao_nao_persistiu"),
        mensagem = ifelse(n_rest == 0L, "COLETA excluída não possui vestígios no objeto final", paste0("COLETA excluída ainda possui ", n_rest, " linha(s) no objeto final")),
        atributo = chaves$coleta,
        COLETA = co,
        linha_indice_auditoria = NA_integer_,
        n_linhas_localizadas_final = as.integer(n_rest),
        valor_esperado = "<REGISTRO_REMOVIDO>",
        valor_final = ifelse(n_rest == 0L, NA_character_, co)
      )
    }
  }

  status_aplicados <- c("aplicada", "aplicada_atomica")
  rows <- which(as.character(audit$status) %in% status_aplicados)
  if (length(rows) > 0L) {
    for (ii in rows) {
      attr <- as.character(audit$atributo[ii])
      co <- as.character(audit$COLETA[ii])
      if (!is.na(co) && nzchar(trimws(co)) && co %chin% coletas_excluidas) next
      if (is.na(attr) || !nzchar(trimws(attr)) || startsWith(attr, "__")) next
      attr_dt <- monitora_correcao_resolver_atributo_auditoria(dt, attr)
      if (is.na(attr_dt) || !nzchar(trimws(attr_dt)) || !(attr_dt %in% names(dt))) {
        kk <- kk + 1L
        out[[kk]] <- data.table::data.table(
          contexto = contexto, id_correcao = as.character(audit$id_correcao[ii]), status_persistencia = "falha_atributo_ausente",
          mensagem = paste0("Atributo auditado não existe no objeto final, mesmo após resolução por nome normalizado: ", attr), atributo = attr, atributo_resolvido = NA_character_, COLETA = co,
          linha_indice_auditoria = suppressWarnings(as.integer(audit$linha_indice[ii])), n_linhas_localizadas_final = 0L,
          linhas_localizadas_final_indice = NA_character_,
          valor_esperado = as.character(audit$valor_depois[ii]), valor_final = NA_character_
        )
        next
      }
      alvo <- localizar_aud(ii)
      linhas <- monitora_correcao_localizar_linhas(dt, alvo, chaves, indice)
      linhas <- unique(as.integer(linhas))
      linhas <- linhas[!is.na(linhas) & linhas >= 1L & linhas <= nrow(dt)]
      esperado <- as.character(audit$valor_depois[ii])
      if (!length(linhas)) {
        kk <- kk + 1L
        out[[kk]] <- data.table::data.table(
          contexto = contexto, id_correcao = as.character(audit$id_correcao[ii]), status_persistencia = "falha_linha_nao_localizada",
          mensagem = "Linha auditada como aplicada não foi localizada no objeto final por chaves estáveis/contexto", atributo = attr, COLETA = co,
          linha_indice_auditoria = suppressWarnings(as.integer(audit$linha_indice[ii])), n_linhas_localizadas_final = 0L,
          linhas_localizadas_final_indice = NA_character_,
          valor_esperado = esperado, valor_final = NA_character_
        )
        next
      }
      finais <- as.character(dt[[attr_dt]][linhas])
      ok <- monitora_correcao_valores_equivalentes(finais, esperado, attr_dt, chaves)
      modo_comparacao <- ifelse(
        isTRUE(monitora_correcao_campo_multiselect_auditoria(attr_dt, chaves)),
        "tokens_multiselect",
        "literal"
      )
      status <- ifelse(all(ok), "ok_aplicacao_persistiu", "falha_valor_nao_persistiu")
      kk <- kk + 1L
      out[[kk]] <- data.table::data.table(
        contexto = contexto,
        id_correcao = as.character(audit$id_correcao[ii]),
        status_persistencia = status,
        mensagem = ifelse(identical(status, "ok_aplicacao_persistiu"), "Valor auditado persiste no objeto final", "Valor final diverge do valor_depois auditado"),
        modo_comparacao = modo_comparacao,
        atributo = attr,
        atributo_resolvido = attr_dt,
        COLETA = co,
        linha_indice_auditoria = suppressWarnings(as.integer(audit$linha_indice[ii])),
        n_linhas_localizadas_final = as.integer(length(linhas)),
        linhas_localizadas_final_indice = paste(linhas, collapse = ";"),
        valor_esperado = esperado,
        valor_final = paste(unique(finais), collapse = " | ")
      )
    }
  }
  res <- if (length(out)) data.table::rbindlist(out, fill = TRUE, use.names = TRUE) else data.table::data.table()
  if (nrow(res) > 0L) {
    ### A auditoria de persistência deve validar o estado final do produto, não
    ### valores intermediários de operações que foram corretamente sobrescritas por
    ### outra operação aplicada no mesmo alvo. Isto ocorre, por exemplo, quando a
    ### limpeza de "outra forma" harmoniza uma célula e, na sequência, um MVLOTE
    ### move a mesma forma para outra categoria. Se outra operação aplicada no
    ### mesmo alvo já confere com o valor final, a divergência intermediária é
    ### marcada como sobreposição compatível, sem bloquear a execução.
    for (cc in c("atributo_resolvido", "COLETA", "linha_indice_auditoria", "linhas_localizadas_final_indice", "status_persistencia")) {
      if (!(cc %in% names(res))) data.table::set(res, j = cc, value = NA_character_)
    }
    chave_res <- paste(
      as.character(res$COLETA),
      as.character(res$linha_indice_auditoria),
      as.character(res$atributo_resolvido),
      sep = "\r"
    )
    chaves_ok <- unique(chave_res[as.character(res$status_persistencia) == "ok_aplicacao_persistiu"])
    idx_sobreposta <- which(as.character(res$status_persistencia) == "falha_valor_nao_persistiu" & chave_res %chin% chaves_ok)
    if (length(idx_sobreposta) > 0L) {
      data.table::set(res, i = idx_sobreposta, j = "status_persistencia", value = "ok_sobreposta_por_correcao_final_compativel")
      data.table::set(res, i = idx_sobreposta, j = "mensagem", value = "Valor intermediário auditado foi sobrescrito por outra correção aplicada no mesmo alvo; o estado final confere com auditoria posterior")
    }

    ### Recalculos automáticos de campos superiores derivados do XLSForm podem
    ### registrar estados intermediários quando há múltiplas harmonizações no mesmo
    ### conjunto de linhas. Para o campo superior de categorias de forma de vida
    ### (**Encostam** / tipo_forma_vida), a trava robusta é semântica: o valor
    ### final deve ser idêntico ao que a própria função oficial de recálculo do
    ### script produziria a partir das listas inferiores finais. A validação evita
    ### depender de igualdade literal com valor_depois intermediário e evita
    ### depender apenas de linha_indice histórico após EXCCOL.
    eh_coluna_tipo_superior <- function(x) {
      x <- as.character(x)
      z <- monitora_correcao_normalizar_nome_coluna(x)
      z[is.na(z)] <- ""
      grepl("encostam.*vareta", z) |
        grepl("(^|_)tipo_forma_vida($|_)", z) |
        grepl("tipo.*forma.*vida", z)
    }
    tipo_col_persist <- NA_character_
    cand_tipo <- c(
      if (!is.null(chaves$tipo_forma_vida)) chaves$tipo_forma_vida else NA_character_,
      unique(as.character(res$atributo_resolvido[eh_coluna_tipo_superior(res$atributo_resolvido)])),
      unique(as.character(res$atributo[eh_coluna_tipo_superior(res$atributo)]))
    )
    cand_tipo <- unique(cand_tipo[!is.na(cand_tipo) & nzchar(trimws(cand_tipo))])
    if (length(cand_tipo) > 0L) {
      for (cc_tipo in cand_tipo) {
        cc_res <- monitora_correcao_resolver_atributo_auditoria(dt, cc_tipo)
        if (!is.na(cc_res) && nzchar(cc_res) && cc_res %in% names(dt)) {
          tipo_col_persist <- cc_res
          break
        }
      }
    }
    if (!is.na(tipo_col_persist) && nzchar(tipo_col_persist) && tipo_col_persist %in% names(dt)) {
      idx_recalc <- which(
        as.character(res$status_persistencia) == "falha_valor_nao_persistiu" &
          as.character(res$id_correcao) == "RECALC_SUPERIORES_XLSFORM" &
          (
            as.character(res$atributo_resolvido) == tipo_col_persist |
              eh_coluna_tipo_superior(res$atributo_resolvido) |
              eh_coluna_tipo_superior(res$atributo)
          )
      )
      if (length(idx_recalc) > 0L) {
        for (ii_recalc in idx_recalc) {
          linhas_txt <- as.character(res$linhas_localizadas_final_indice[ii_recalc])
          linhas_recalc <- suppressWarnings(as.integer(unlist(strsplit(linhas_txt, ";", fixed = TRUE), use.names = FALSE)))
          linhas_recalc <- unique(linhas_recalc[!is.na(linhas_recalc) & linhas_recalc >= 1L & linhas_recalc <= nrow(dt)])
          if (!length(linhas_recalc)) {
            li_recalc <- suppressWarnings(as.integer(res$linha_indice_auditoria[ii_recalc]))
            if (!is.na(li_recalc) && li_recalc >= 1L && li_recalc <= nrow(dt)) linhas_recalc <- li_recalc
          }
          if (!length(linhas_recalc)) next
          dt_recalc <- data.table::copy(dt)
          antes_recalc <- as.character(dt_recalc[[tipo_col_persist]][linhas_recalc])
          try(monitora_correcao_recalcular_tipo_forma_vida(dt_recalc, linhas_recalc), silent = TRUE)
          esperado_recalc <- as.character(dt_recalc[[tipo_col_persist]][linhas_recalc])
          final_recalc <- as.character(dt[[tipo_col_persist]][linhas_recalc])
          ok_recalc <- monitora_correcao_valores_equivalentes(
            final_recalc,
            esperado_recalc,
            tipo_col_persist,
            chaves
          )
          if (all(ok_recalc)) {
            data.table::set(res, i = ii_recalc, j = "status_persistencia", value = "ok_recalculo_superior_estado_final_consistente")
            data.table::set(res, i = ii_recalc, j = "mensagem", value = "Valor auditado intermediário divergiu, mas o campo superior final é idêntico ao recálculo oficial a partir das listas inferiores finais")
            data.table::set(res, i = ii_recalc, j = "modo_comparacao", value = "recalculo_oficial_tipo_forma_vida")
            data.table::set(res, i = ii_recalc, j = "valor_esperado", value = paste(unique(esperado_recalc), collapse = " | "))
            data.table::set(res, i = ii_recalc, j = "valor_final", value = paste(unique(final_recalc), collapse = " | "))
          } else {
            data.table::set(res, i = ii_recalc, j = "mensagem", value = paste0(
              "Valor final diverge do valor_depois auditado e também do recálculo oficial de tipo_forma_vida; antes_recalculo=",
              paste(unique(antes_recalc), collapse = " | "),
              "; esperado_recalculo=",
              paste(unique(esperado_recalc), collapse = " | "),
              "; final=",
              paste(unique(final_recalc), collapse = " | ")
            ))
            data.table::set(res, i = ii_recalc, j = "modo_comparacao", value = "falha_recalculo_oficial_tipo_forma_vida")
            data.table::set(res, i = ii_recalc, j = "valor_esperado", value = paste(unique(esperado_recalc), collapse = " | "))
            data.table::set(res, i = ii_recalc, j = "valor_final", value = paste(unique(final_recalc), collapse = " | "))
          }
        }
      }
    }
  }




    ### v2.6.1 --------------------------
    ### Auditoria de persistência com helpers nomeados e indexação segura.
    ### Corrige a colisão de nomes gerada por múltiplas funções locais chamadas
    ### `v2.5.4`, que fazia `linhas_estado` deixar de ser vetor inteiro e ser
    ### interpretado pelo data.table como i de join.

    monitora_persist_resolver_linhas_estado <- function(row_res, n_dt) {
      if (!is.data.frame(row_res) || !length(n_dt) || is.na(n_dt) || n_dt < 1L) return(integer(0))
      linhas_txt <- if ("linhas_localizadas_final_indice" %in% names(row_res)) {
        as.character(row_res$linhas_localizadas_final_indice[1L])
      } else NA_character_
      linhas <- suppressWarnings(as.integer(unlist(strsplit(linhas_txt, ";", fixed = TRUE), use.names = FALSE)))
      linhas <- unique(linhas[!is.na(linhas) & linhas >= 1L & linhas <= n_dt])
      if (!length(linhas) && "linha_indice_auditoria" %in% names(row_res)) {
        li <- suppressWarnings(as.integer(row_res$linha_indice_auditoria[1L]))
        if (!is.na(li) && li >= 1L && li <= n_dt) linhas <- li
      }
      as.integer(linhas)
    }

    monitora_persist_aplicar_normalizadores_estado <- function(dt_sub, linhas_sub, contexto_estado = "persistencia_estado_final_contratual") {
      old_publicacao_g_sim <- get0("MONITORA_PUBLICACAO_G_MODO_SIMULACAO_CONTRATO", ifnotfound = FALSE, inherits = TRUE)
      assign("MONITORA_PUBLICACAO_G_MODO_SIMULACAO_CONTRATO", TRUE, envir = .GlobalEnv)
      on.exit(assign("MONITORA_PUBLICACAO_G_MODO_SIMULACAO_CONTRATO", old_publicacao_g_sim, envir = .GlobalEnv), add = TRUE)
      dt_sub <- monitora_dt_referenciar(dt_sub)
      linhas_sub <- unique(as.integer(linhas_sub))
      linhas_sub <- linhas_sub[!is.na(linhas_sub) & linhas_sub >= 1L & linhas_sub <= nrow(dt_sub)]
      if (!length(linhas_sub)) return(invisible(dt_sub))

      meta_publicacao_f <- get0("MONITORA_META_XLSFORMS_CORRECOES", ifnotfound = NULL, inherits = TRUE)
      if (exists("monitora_correcao_preparar_schema_edicao_painel", mode = "function")) {
        try(monitora_correcao_preparar_schema_edicao_painel(dt_sub, meta_publicacao_f, contexto = paste0(contexto_estado, "_schema")), silent = TRUE)
      }
      if (exists("monitora_publicacao_c_sincronizar_materiais_botanicos", mode = "function")) {
        try(monitora_publicacao_c_sincronizar_materiais_botanicos(dt_sub, linhas_sub, contexto = paste0(contexto_estado, "_materiais_botanicos")), silent = TRUE)
      }
      if (exists("monitora_correcao_sincronizar_encostam_final", mode = "function")) {
        try(monitora_correcao_sincronizar_encostam_final(dt_sub, linhas_sub, contexto = paste0(contexto_estado, "_encostam_final")), silent = TRUE)
      } else if (exists("monitora_correcao_recalcular_tipo_forma_vida", mode = "function")) {
        try(monitora_correcao_recalcular_tipo_forma_vida(dt_sub, linhas_sub), silent = TRUE)
      }
      invisible(dt_sub)
    }

    monitora_persist_colunas_formas_estado <- function(dt_ref) {
      cats <- c("nativa", "exotica", "seca_morta")
      out_cols <- character()
      for (cat in cats) {
        cc <- tryCatch(monitora_correcao_coluna_forma_vida(dt_ref, cat), error = function(e) NA_character_)
        if (!is.na(cc) && nzchar(cc) && cc %in% names(dt_ref)) out_cols <- c(out_cols, cc)
      }
      unique(out_cols)
    }

    monitora_persist_colunas_contrato_estado <- function(dt_ref, atributo_resolvido = NA_character_, chaves_ref = monitora_correcao_colunas_chave(dt_ref)) {
      nms <- names(dt_ref)
      nms_norm <- tryCatch(
        vapply(nms, monitora_correcao_normalizar_nome_coluna, character(1)),
        error = function(e) tolower(trimws(nms))
      )
      padrao_contrato <- paste(
        c(
          "encostam", "tipo_forma_vida", "forma_vida_nativa", "forma_vida_exotica", "forma_vida_seca_morta",
          "forma_serrapilheira", "serrapilheira", "materiais_botanicos", "material_botanico", "fragmentos_botanicos",
          "material_inundado", "outra_forma_vida", "outras_formas", "samambaia", "orquidea", "cactacea", "bromelioide"
        ),
        collapse = "|"
      )
      cols_regex <- nms[grepl(padrao_contrato, nms_norm, perl = TRUE)]
      mat_col <- if (exists("monitora_publicacao_c_resolver_coluna_materiais_botanicos", mode = "function")) {
        tryCatch(monitora_publicacao_c_resolver_coluna_materiais_botanicos(dt_ref, criar = FALSE), error = function(e) NA_character_)
      } else NA_character_
      candidatos <- c(atributo_resolvido, chaves_ref$tipo_forma_vida, monitora_persist_colunas_formas_estado(dt_ref), mat_col, cols_regex)
      unique(candidatos[!is.na(candidatos) & nzchar(candidatos)])
    }

    monitora_persist_intersectar_colunas_estado <- function(cols, dt_a, dt_b) {
      cols <- unique(as.character(cols))
      cols <- cols[!is.na(cols) & nzchar(cols)]
      cols[cols %in% union(names(dt_a), names(dt_b))]
    }

    monitora_persist_extrair_coluna_estado <- function(dt_ref, col) {
      if (col %in% names(dt_ref)) as.character(dt_ref[[col]]) else rep(NA_character_, nrow(dt_ref))
    }

    monitora_persist_valores_equivalentes_estado <- function(final_vals, esperado_vals, col, chaves_ref) {
      ok <- tryCatch(
        monitora_correcao_valores_equivalentes(final_vals, esperado_vals, col, chaves_ref),
        error = function(e) monitora_correcao_na_para_vazio(final_vals) == monitora_correcao_na_para_vazio(esperado_vals)
      )
      isTRUE(all(ok, na.rm = FALSE))
    }

    monitora_persist_reclassificar_estado_contratual <- function(res, dt, chaves, contexto_estado = "persistencia_estado_final_contratual") {
      if (!nrow(res)) return(res)
      idx <- which(as.character(res$status_persistencia) == "falha_valor_nao_persistiu")
      if (!length(idx)) return(res)

      for (ii_estado in idx) {
        attr_estado <- as.character(res$atributo_resolvido[ii_estado])
        if (is.na(attr_estado) || !nzchar(attr_estado)) attr_estado <- as.character(res$atributo[ii_estado])
        attr_estado <- tryCatch(monitora_correcao_resolver_atributo_auditoria(dt, attr_estado), error = function(e) attr_estado)
        if (is.na(attr_estado) || !nzchar(attr_estado) || !(attr_estado %in% names(dt))) next

        linhas_estado <- monitora_persist_resolver_linhas_estado(res[ii_estado], nrow(dt))
        if (!is.integer(linhas_estado)) linhas_estado <- as.integer(linhas_estado)
        linhas_estado <- unique(linhas_estado[!is.na(linhas_estado) & linhas_estado >= 1L & linhas_estado <= nrow(dt)])
        if (!length(linhas_estado)) next

        dt_final <- data.table::copy(dt[linhas_estado])
        dt_esperado <- data.table::copy(dt[linhas_estado])
        esperado_raw <- as.character(res$valor_esperado[ii_estado])
        if (!length(esperado_raw) || all(is.na(esperado_raw))) esperado_raw <- NA_character_
        if (length(esperado_raw) != nrow(dt_esperado)) esperado_raw <- rep(esperado_raw[1L], nrow(dt_esperado))
        data.table::set(dt_esperado, i = seq_len(nrow(dt_esperado)), j = attr_estado, value = esperado_raw)

        linhas_sub <- seq_len(nrow(dt_esperado))
        monitora_persist_aplicar_normalizadores_estado(dt_esperado, linhas_sub, contexto_estado = paste0("persistencia_esperado_", contexto_estado))
        monitora_persist_aplicar_normalizadores_estado(dt_final, linhas_sub, contexto_estado = paste0("persistencia_final_", contexto_estado))

        chaves_sub <- monitora_correcao_colunas_chave(dt_final)
        cols_estado <- monitora_persist_intersectar_colunas_estado(
          monitora_persist_colunas_contrato_estado(dt_final, attr_estado, chaves_sub),
          dt_final,
          dt_esperado
        )
        if (!length(cols_estado)) cols_estado <- attr_estado

        falhas_cols <- character()
        for (cc_estado in cols_estado) {
          final_vals <- monitora_persist_extrair_coluna_estado(dt_final, cc_estado)
          esperado_vals <- monitora_persist_extrair_coluna_estado(dt_esperado, cc_estado)
          if (!monitora_persist_valores_equivalentes_estado(final_vals, esperado_vals, cc_estado, chaves_sub)) {
            falhas_cols <- c(falhas_cols, cc_estado)
          }
        }

        if (!length(falhas_cols)) {
          data.table::set(res, i = ii_estado, j = "status_persistencia", value = "ok_estado_final_contratual_consistente")
          data.table::set(res, i = ii_estado, j = "mensagem", value = "Valor auditado intermediário divergiu, mas o estado final real é equivalente ao estado final esperado após aplicação dos normalizadores contratuais")
          data.table::set(res, i = ii_estado, j = "modo_comparacao", value = "estado_final_contratual_normalizado")
          data.table::set(res, i = ii_estado, j = "valor_esperado", value = paste(
            vapply(cols_estado, function(cc) paste0(cc, "=", paste(unique(monitora_persist_extrair_coluna_estado(dt_esperado, cc)), collapse = " | ")), character(1)),
            collapse = "; "
          ))
          data.table::set(res, i = ii_estado, j = "valor_final", value = paste(
            vapply(cols_estado, function(cc) paste0(cc, "=", paste(unique(monitora_persist_extrair_coluna_estado(dt_final, cc)), collapse = " | ")), character(1)),
            collapse = "; "
          ))
        } else {
          data.table::set(res, i = ii_estado, j = "mensagem", value = paste0(
            "Valor final diverge do valor_depois auditado e também do estado final contratual normalizado; colunas divergentes=",
            paste(unique(falhas_cols), collapse = ";")
          ))
          data.table::set(res, i = ii_estado, j = "modo_comparacao", value = "falha_estado_final_contratual_normalizado")
        }
      }
      res
    }

    res <- monitora_persist_reclassificar_estado_contratual(res, dt, chaves, contexto_estado = contexto)

    ### v2.6.1: auditoria de persistência por efeito diagnóstico final --------
    ### A partir da run6, preview/modal e aplicação já convergem para o estado sem
    ### ocorrências impeditivas. A trava de persistência, porém, ainda comparava
    ### valores intermediários auditados com o objeto final depois de operações
    ### sobrepostas e normalizadores contratuais (TRIOUT -> PENDFV -> recálculos).
    ### Esta camada não substitui a auditoria célula-a-célula; ela apenas
    ### reclassifica divergências literais/posicionais de operações semânticas
    ### quando a própria triagem final de ocorrências impeditivas confirma que o
    ### efeito diagnóstico da sessão foi alcançado.
    monitora_persist_reclassificar_por_efeito_diagnostico_final <- function(res, dt, contexto_estado = "pos_aplicacao_objeto") {
      if (!nrow(res)) return(res)
      if (!("status_persistencia" %in% names(res))) return(res)
      idx_falha_compat <- which(as.character(res$status_persistencia) %in% c(
        "falha_valor_nao_persistiu",
        "falha_linha_nao_localizada"
      ))
      if (!length(idx_falha_compat)) return(res)

      ids <- as.character(res$id_correcao)
      ids[is.na(ids)] <- ""
      ### Só reclassificar famílias em que o critério correto é o desaparecimento
      ### da ocorrência diagnóstica, não igualdade literal do valor intermediário.
      idx_familias_semanticas <- idx_falha_compat[grepl(
        "^(TRIOUT|PENDFV|MVLOTE|TRIDESC|MOVFV|RECALC_SUPERIORES_XLSFORM|SYNC_ENCOSTAM_FINAL)",
        ids[idx_falha_compat]
      )]
      if (!length(idx_familias_semanticas)) return(res)

      efeito <- tryCatch({
        if (!exists("monitora_diag_rel_gerar_ocorrencias", mode = "function")) {
          stop("função monitora_diag_rel_gerar_ocorrencias indisponível")
        }
        base_tmp <- file.path(
          tempdir(),
          paste0(
            "monitora_persistencia_efeito_diagnostico_",
            gsub("[^A-Za-z0-9_]+", "_", as.character(contexto_estado)),
            "_", format(Sys.time(), "%Y%m%d%H%M%S")
          )
        )
        dir.create(base_tmp, recursive = TRUE, showWarnings = FALSE)
        diag <- suppressWarnings(suppressMessages(monitora_diag_rel_gerar_ocorrencias(
          dt,
          fase = "pos_painel",
          base_dir = base_tmp,
          coletas_triagem_por_tipo = NULL,
          triagem_painel_unificada = NULL,
          validar_contagens = FALSE
        )))
        resumo <- data.table::as.data.table(diag$resumo)
        if (!nrow(resumo) || !("severidade" %in% names(resumo)) || !("n_linhas" %in% names(resumo))) {
          stop("resumo diagnóstico final sem colunas esperadas")
        }
        imp <- resumo[as.character(severidade) == "impeditiva"]
        n_linhas_imp <- sum(suppressWarnings(as.integer(imp$n_linhas)), na.rm = TRUE)
        n_coletas_imp <- if ("n_coletas" %in% names(imp)) sum(suppressWarnings(as.integer(imp$n_coletas)), na.rm = TRUE) else NA_integer_
        list(ok = isTRUE(n_linhas_imp == 0L), n_linhas_imp = n_linhas_imp, n_coletas_imp = n_coletas_imp, resumo = resumo, erro = NA_character_)
      }, error = function(e) {
        list(ok = FALSE, n_linhas_imp = NA_integer_, n_coletas_imp = NA_integer_, resumo = data.table::data.table(), erro = conditionMessage(e))
      })

      if (isTRUE(efeito$ok)) {
        data.table::set(res, i = idx_familias_semanticas, j = "status_persistencia", value = "ok_persistiu_por_efeito_diagnostico_final")
        data.table::set(res, i = idx_familias_semanticas, j = "mensagem", value = paste0(
          "Valor auditado intermediário divergiu ou a linha histórica não foi localizada, mas a triagem diagnóstica final não encontrou ocorrências impeditivas remanescentes; persistência confirmada por efeito diagnóstico final em ",
          contexto_estado,
          "."
        ))
        if (!("modo_comparacao" %in% names(res))) data.table::set(res, j = "modo_comparacao", value = NA_character_)
        data.table::set(res, i = idx_familias_semanticas, j = "modo_comparacao", value = "efeito_diagnostico_final")
      } else {
        ### Se ainda há pendência impeditiva final, manter falha. Apenas enriquecer
        ### a mensagem para diferenciar falha real de impossibilidade de reclassificar.
        msg_extra <- if (!is.na(efeito$erro) && nzchar(efeito$erro)) {
          paste0(" Auditoria por efeito diagnóstico final indisponível: ", efeito$erro)
        } else {
          paste0(" Triagem diagnóstica final ainda indica ", efeito$n_linhas_imp, " linha(s) impeditiva(s).")
        }
        for (ii_msg in idx_familias_semanticas) {
          msg_atual <- as.character(res$mensagem[ii_msg])
          if (is.na(msg_atual)) msg_atual <- ""
          data.table::set(res, i = ii_msg, j = "mensagem", value = paste0(msg_atual, msg_extra))
        }
      }
      res
    }

    res <- monitora_persist_reclassificar_por_efeito_diagnostico_final(res, dt, contexto_estado = contexto)
    ### FIM v2.6.1 auditoria por efeito diagnóstico final ----------------------

  if (nrow(res) > 0L) {
    exec_id_pers <- if (exists("MONITORA_EXEC_ID", inherits = TRUE)) MONITORA_EXEC_ID else format(Sys.time(), "%Y%m%d_%H%M%S")
    arq_log <- file.path(MONITORA_LOG_DIR, paste0("auditoria_persistencia_correcoes_", contexto, "_", exec_id_pers, ".csv"))
    arq_ult <- file.path(MONITORA_CORRECOES_DIR, paste0("auditoria_persistencia_correcoes_", contexto, "_ultima_execucao.csv"))
    monitora_fwrite(res, arq_log, na = "")
    monitora_fwrite(res, arq_ult, na = "")
    monitora_correcao_gravar_resumo_operacoes_atomicas(audit, res, contexto = contexto)
    falhas <- res[grepl("^falha", status_persistencia)]
    if (nrow(falhas) > 0L) {
      modo_replay_nao_abortivo <- isTRUE(get0("MONITORA_REPLAY_DIAGNOSTICO_NAO_ABORTAR", ifnotfound = FALSE, inherits = TRUE)) &&
        isTRUE(get0("MONITORA_REAPLICAR_CORRECOES_ANTERIORES", ifnotfound = FALSE, inherits = TRUE)) &&
        (isTRUE(get0("MONITORA_REPLAY_SEMANTICO_EM_EXECUCAO", ifnotfound = FALSE, inherits = TRUE)) ||
           isTRUE(get0("MONITORA_CORRECOES_REAPLICADAS_PRE_PAINEL", ifnotfound = FALSE, inherits = TRUE)) ||
           exists("MONITORA_CORRECOES_REAPLICADAS_ARQUIVO", inherits = TRUE) ||
           exists("MONITORA_ARQUIVO_CORRECOES_CAMPOS_REAPLICADO", inherits = TRUE))
      nivel_persist <- if (isTRUE(modo_replay_nao_abortivo)) "AVISO" else "ERRO"
      acao_persist <- if (isTRUE(modo_replay_nao_abortivo)) {
        "diagnóstico não bloqueante ativo; execução continuará até o painel para coletar estado pós-replay"
      } else {
        "execução bloqueada; revisar auditoria_persistencia_correcoes_*"
      }
      monitora_log_registrar_evento(
        "persistencia_correcoes", nivel_persist, arq_log,
        paste0(nrow(falhas), " divergência(s) entre auditoria de correções e objeto final em ", contexto),
        acao_persist
      )
      if (isTRUE(abortar) && !isTRUE(modo_replay_nao_abortivo)) stop(paste0("Correções auditadas não persistiram em registros_corrig (", contexto, "). Ver ", basename(arq_ult), "."), call. = FALSE)
    } else {
      monitora_log_registrar_evento(
        "persistencia_correcoes", "INFO", arq_log,
        paste0(nrow(res), " checagem(ns) de persistência de correções confirmada(s) em ", contexto),
        "OK"
      )
    }
  }
  res[]
}

monitora_correcao_novo_id <- function(prefix = "CORR") {
  paste0(prefix, "_", format(Sys.time(), "%Y%m%d%H%M%S"), "_", sample.int(9999, 1))
}

monitora_correcao_assinatura_operacoes <- function(ops) {
  ops <- data.table::as.data.table(ops)
  if (!nrow(ops)) return(character(0))
  cols_sig <- c(
    "tipo_correcao", "escopo_aplicacao", "tipo_triagem", "escopo_diagnostico_mvlote",
    "categoria_base_diagnostica", "coleta", "coleta_uuid", "uuid_registro",
    "linha_indice", "linhas_alvo_serializadas", "ponto_amostral", "ponto_metro",
    "atributo_coluna_registros_corrig", "acao", "token_pai", "token_removido",
    "categoria_origem", "categoria_destino", "valor_original_esperado", "valor_novo",
    "forma_valida_escolhida", "habito_escolhido"
  )
  for (cc in cols_sig) if (!(cc %in% names(ops))) data.table::set(ops, j = cc, value = NA_character_)
  do.call(paste, c(lapply(cols_sig, function(cc) {
    z <- as.character(ops[[cc]])
    z[is.na(z)] <- ""
    trimws(tolower(z))
  }), sep = "\r"))
}

monitora_correcao_serial_linhas_canonico <- function(x) {
  li <- suppressWarnings(as.integer(monitora_correcao_parse_serial_generico(x)))
  li <- sort(unique(li[!is.na(li) & li > 0L]))
  if (!length(li)) return("")
  paste(li, collapse = ";")
}

monitora_correcao_primeiro_campo_existente <- function(dt, campos, padrao = NA_character_) {
  dt <- data.table::as.data.table(dt)
  for (cc in campos) {
    if (cc %in% names(dt)) {
      z <- as.character(dt[[cc]])
      z <- z[!is.na(z) & nzchar(trimws(z))]
      if (length(z)) return(z[1L])
    }
  }
  padrao
}

monitora_correcao_assinaturas_mvlote <- function(ops) {
  ops <- data.table::as.data.table(ops)
  if (!nrow(ops)) return(data.table::data.table(escopo = character(), solucao = character(), completa = character()))
  cols <- c(
    "tipo_correcao", "tipo_triagem", "escopo_diagnostico_mvlote", "categoria_base_diagnostica",
    "categoria_origem", "categoria_destino", "token_pai", "token_removido",
    "valor_original_esperado", "valor_novo", "forma_valida_escolhida", "habito_escolhido",
    "linhas_alvo_serializadas", "linha_indice", "coleta"
  )
  for (cc in cols) if (!(cc %in% names(ops))) data.table::set(ops, j = cc, value = NA_character_)
  canon_txt <- function(z) {
    z <- as.character(z)
    z[is.na(z)] <- ""
    trimws(tolower(z))
  }
  canon_forma <- function(z) {
    zz <- tryCatch(monitora_correcao_forma_canonica_lote(monitora_correcao_parse_serial_generico(z)), error = function(e) monitora_correcao_parse_serial_generico(z))
    zz <- unique(trimws(tolower(as.character(zz))))
    zz <- zz[!is.na(zz) & nzchar(zz)]
    if (!length(zz)) return("")
    paste(sort(zz), collapse = ";")
  }
  linhas_sig <- vapply(seq_len(nrow(ops)), function(i) {
    zz <- monitora_correcao_serial_linhas_canonico(ops$linhas_alvo_serializadas[i])
    if (!nzchar(zz)) zz <- monitora_correcao_serial_linhas_canonico(ops$linha_indice[i])
    zz
  }, character(1))
  token_sig <- vapply(seq_len(nrow(ops)), function(i) {
    canon_forma(c(ops$token_pai[i], ops$token_removido[i], ops$valor_original_esperado[i]))
  }, character(1))
  forma_dest <- vapply(seq_len(nrow(ops)), function(i) {
    canon_forma(c(ops$forma_valida_escolhida[i], ops$valor_novo[i]))
  }, character(1))
  tipo <- canon_txt(ops$tipo_triagem)
  tipo[!nzchar(tipo)] <- canon_txt(ops$escopo_diagnostico_mvlote)[!nzchar(tipo)]
  tipo[!nzchar(tipo)] <- "movimento_forma_vida_lote"
  cat_base <- canon_txt(ops$categoria_base_diagnostica)
  cat_base[!nzchar(cat_base)] <- canon_txt(ops$categoria_origem)[!nzchar(cat_base)]
  escopo <- paste(tipo, cat_base, canon_txt(ops$categoria_origem), token_sig, linhas_sig, sep = "\r")
  solucao <- paste(canon_txt(ops$categoria_destino), forma_dest, canon_txt(ops$habito_escolhido), sep = "\r")
  data.table::data.table(escopo = escopo, solucao = solucao, completa = paste(escopo, solucao, sep = "\r"))
}

monitora_correcao_status_mvlote_fatal <- function(status) {
  status <- unique(tolower(trimws(as.character(status))))
  status <- status[!is.na(status) & nzchar(status)]
  if (!length(status)) return(FALSE)
  nao_fatais <- c(
    "bloqueada_operacao_repetida_sem_efeito",
    "bloqueada_sem_ocorrencias_migraveis",
    "ignorada_operacao_repetida_sem_efeito",
    "ignorada_sem_efeito_estado_ja_corrigido",
    "substituida_por_operacao_posterior",
    "duplicada_exata_bloqueada",
    "sem_ocorrencias_migraveis_estado_ja_corrigido"
  )
  status_f <- setdiff(status, nao_fatais)
  if (!length(status_f)) return(FALSE)
  any(grepl("^(falha_|erro_|bloqueada_coluna_protegida|bloqueada_operacao_nula|falha_habito|falha_coluna|falha_lote|falha_n_linhas|falha_sem_linhas)", status_f))
}

monitora_correcao_normalizar_mvlote_sessao <- function(corr, contexto = "backend") {
  corr <- data.table::as.data.table(corr)
  audit <- data.table::data.table()
  if (!nrow(corr) || !exists("monitora_correcao_eh_operacao_movimento_forma_vida_lote", mode = "function")) {
    attr(corr, "auditoria_normalizacao_mvlote") <- audit
    return(corr[])
  }
  idx <- which(monitora_correcao_eh_operacao_movimento_forma_vida_lote(corr))
  if (length(idx) < 2L) {
    attr(corr, "auditoria_normalizacao_mvlote") <- audit
    return(corr[])
  }
  if (!("ordem_tmp" %in% names(corr))) corr[, ordem_tmp := seq_len(.N)]
  sig <- monitora_correcao_assinaturas_mvlote(corr[idx])
  tmp <- data.table::data.table(row_id = idx, ordem_norm = seq_along(idx), escopo = sig$escopo, solucao = sig$solucao, completa = sig$completa)
  tmp <- tmp[nzchar(escopo)]
  if (!nrow(tmp)) {
    attr(corr, "auditoria_normalizacao_mvlote") <- audit
    return(corr[])
  }
  tmp[, n_escopo := .N, by = escopo]
  repet <- tmp[n_escopo > 1L]
  if (!nrow(repet)) {
    attr(corr, "auditoria_normalizacao_mvlote") <- audit
    return(corr[])
  }
  keep <- repet[, .SD[which.max(ordem_norm)], by = escopo]$row_id
  drop <- setdiff(repet$row_id, keep)
  if (length(drop)) {
    audit <- data.table::rbindlist(lapply(drop, function(rr) {
      data.table::data.table(
        id_correcao = if ("id_correcao" %in% names(corr)) as.character(corr$id_correcao[rr]) else NA_character_,
        ordem_operacao = if ("ordem_operacao" %in% names(corr)) as.character(corr$ordem_operacao[rr]) else NA_character_,
        status = "substituida_por_operacao_posterior",
        mensagem = paste0("MVLOTE ", contexto, ": operação anterior substituída por operação posterior com o mesmo escopo diagnóstico de linhas."),
        atributo = "__mover_forma_vida_lote__",
        linha_indice = NA_integer_, valor_antes = NA_character_, valor_depois = NA_character_, arquivo_correcao = contexto
      )
    }), fill = TRUE, use.names = TRUE)
    corr <- corr[-drop]
  }
  attr(corr, "auditoria_normalizacao_mvlote") <- audit
  corr[]
}

monitora_correcao_criar_indice_linhas <- function(dt, chaves = monitora_correcao_colunas_chave(dt)) {
  ### Índice leve para reduzir revarreduras repetidas de registros_corrig durante
  ### lotes de correção. Mantém compatibilidade: quando o índice não existe,
  ### monitora_correcao_localizar_linhas() usa o caminho original por varredura.
  dt <- data.table::as.data.table(dt)
  indice <- new.env(parent = emptyenv())
  indice$n <- nrow(dt)
  indice$por_linha_indice <- seq_len(nrow(dt))
  criar_split <- function(col) {
    if (is.na(col) || !nzchar(col) || !(col %in% names(dt))) return(NULL)
    vals <- as.character(dt[[col]])
    ok <- !is.na(vals) & nzchar(trimws(vals))
    if (!any(ok)) return(NULL)
    split(which(ok), vals[ok], drop = TRUE)
  }
  indice$por_coleta_uuid <- criar_split(chaves$coleta_uuid)
  indice$por_coleta <- criar_split(chaves$coleta)
  indice$por_uuid_registro <- criar_split(chaves$uuid_registro)
  indice$por_ponto_amostral <- criar_split(chaves$ponto_amostral)
  indice
}

monitora_correcao_indice_obter <- function(indice, nome, valor) {
  if (is.null(indice) || is.null(nome) || !nzchar(nome) || monitora_correcao_vazio(valor)) return(integer(0))
  if (!exists(nome, envir = indice, inherits = FALSE)) return(integer(0))
  tab <- get(nome, envir = indice, inherits = FALSE)
  if (is.null(tab)) return(integer(0))
  valor <- as.character(valor)[1L]
  if (is.na(valor) || !nzchar(trimws(valor))) return(integer(0))
  out <- tab[[valor]]
  if (is.null(out)) integer(0) else as.integer(out)
}

monitora_correcao_localizar_linhas <- function(dt, corr, chaves = monitora_correcao_colunas_chave(dt), indice = NULL) {
  ### Localização segura de linhas para correções assistidas.
  ### A linha_indice é tratada apenas como fallback, pois exclusões, filtros e
  ### reordenações tornam índices numéricos frágeis entre o painel e a aplicação.
  ### A prioridade passa a ser: UUID do registro > UUID/ID da COLETA > chaves de
  ### contexto do ponto > linha_indice validado por contexto.
  n_dt <- nrow(dt)
  if (n_dt == 0L) return(integer(0))
  idx <- rep(TRUE, n_dt)
  escopo <- tolower(trimws(as.character(corr$escopo_aplicacao[1])))
  if (is.na(escopo) || !nzchar(escopo)) escopo <- "ponto"

  get1 <- function(nm) {
    if (!(nm %in% names(corr))) return(NA_character_)
    as.character(corr[[nm]][1L])
  }
  vazio <- function(x) monitora_correcao_vazio(x)
  restringir <- function(linhas, col, valor) {
    linhas <- as.integer(linhas)
    linhas <- linhas[!is.na(linhas) & linhas >= 1L & linhas <= n_dt]
    if (!length(linhas) || is.na(col) || !nzchar(col) || !(col %in% names(dt)) || vazio(valor)) return(linhas)
    linhas[as.character(dt[[col]][linhas]) == as.character(valor)]
  }
  filtrar_contexto_ponto <- function(linhas) {
    linhas <- restringir(linhas, chaves$ponto_amostral, get1("ponto_amostral"))
    linhas <- restringir(linhas, chaves$ponto_metro, get1("ponto_metro"))
    linhas
  }
  filtrar_contexto_basico <- function(linhas) {
    linhas <- restringir(linhas, chaves$uc, get1("UC"))
    linhas <- restringir(linhas, chaves$ea, get1("EA"))
    linhas <- restringir(linhas, chaves$ua, get1("UA"))
    linhas <- restringir(linhas, chaves$ciclo, get1("CICLO"))
    linhas <- restringir(linhas, chaves$campanha, get1("CAMPANHA"))
    linhas <- restringir(linhas, chaves$ano, get1("ANO"))
    linhas <- restringir(linhas, chaves$data_hora, get1("Data (data_hora)"))
    if (escopo %in% c("ponto", "coleta_ponto", "uuid_registro")) linhas <- filtrar_contexto_ponto(linhas)
    linhas
  }

  uuid_val <- get1("uuid_registro")
  if (!vazio(uuid_val) && !is.na(chaves$uuid_registro) && chaves$uuid_registro %in% names(dt)) {
    hit_uuid <- monitora_correcao_indice_obter(indice, "por_uuid_registro", uuid_val)
    if (!length(hit_uuid)) hit_uuid <- which(as.character(dt[[chaves$uuid_registro]]) == uuid_val)
    hit_uuid <- filtrar_contexto_basico(hit_uuid)
    if (length(hit_uuid) > 0L) return(as.integer(hit_uuid))
  }

  linhas_base <- integer(0)
  coleta_uuid_val <- get1("coleta_uuid")
  coleta_val <- get1("coleta")
  if (!vazio(coleta_uuid_val) && !is.na(chaves$coleta_uuid) && chaves$coleta_uuid %in% names(dt)) {
    linhas_base <- monitora_correcao_indice_obter(indice, "por_coleta_uuid", coleta_uuid_val)
    if (!length(linhas_base)) linhas_base <- which(as.character(dt[[chaves$coleta_uuid]]) == coleta_uuid_val)
  } else if (!vazio(coleta_val) && !is.na(chaves$coleta) && chaves$coleta %in% names(dt)) {
    linhas_base <- monitora_correcao_indice_obter(indice, "por_coleta", coleta_val)
    if (!length(linhas_base)) linhas_base <- which(as.character(dt[[chaves$coleta]]) == coleta_val)
  }
  if (length(linhas_base) > 0L) {
    linhas_base <- filtrar_contexto_basico(linhas_base)
    if (length(linhas_base) > 0L) return(as.integer(linhas_base))
  }

  if (!vazio(coleta_uuid_val) && !is.na(chaves$coleta_uuid) && chaves$coleta_uuid %in% names(dt)) idx <- idx & as.character(dt[[chaves$coleta_uuid]]) == coleta_uuid_val
  if (!vazio(coleta_val) && !is.na(chaves$coleta) && chaves$coleta %in% names(dt)) idx <- idx & as.character(dt[[chaves$coleta]]) == coleta_val
  idx_linhas <- which(idx)
  idx_linhas <- filtrar_contexto_basico(idx_linhas)
  if (length(idx_linhas) > 0L && (!vazio(coleta_uuid_val) || !vazio(coleta_val) || !vazio(get1("ponto_amostral")))) return(as.integer(idx_linhas))

  ### Fallback por linha_indice apenas se ainda não houver chave estável. Quando
  ### houver contexto suficiente, a linha é aceita somente se o contexto bater.
  if ("linha_indice" %in% names(corr)) {
    li <- suppressWarnings(as.integer(corr$linha_indice[1L]))
    if (!is.na(li) && li >= 1L && li <= n_dt) {
      li_ctx <- filtrar_contexto_basico(li)
      if (length(li_ctx) > 0L || all(vapply(c("UC", "EA", "UA", "CICLO", "CAMPANHA", "ANO", "Data (data_hora)", "ponto_amostral", "ponto_metro"), function(nm) vazio(get1(nm)), logical(1)))) return(li)
    }
  }

  integer(0)
}

monitora_correcao_aplicar_operacao <- function(valor_atual, acao, valor_novo, valor_original_esperado = NA_character_) {
  acao <- tolower(trimws(as.character(acao)))
  valor_novo <- if (is.na(valor_novo)) NA_character_ else as.character(valor_novo)
  valor_original_esperado <- if (is.na(valor_original_esperado)) NA_character_ else as.character(valor_original_esperado)
  if (acao %in% c("clear", "limpar")) return(rep(NA_character_, length(valor_atual)))
  if (acao %in% c("append_token", "adicionar_token")) return(vapply(valor_atual, monitora_correcao_append_token_valor, character(1), token = valor_novo))
  if (acao %in% c("remove_token", "remover_token")) {
    token_remover <- if (monitora_correcao_vazio(valor_novo)) valor_original_esperado else valor_novo
    return(vapply(valor_atual, monitora_correcao_remove_token_valor, character(1), token = token_remover))
  }
  if (acao %in% c("replace_token", "substituir_token")) return(vapply(valor_atual, monitora_correcao_replace_token_valor, character(1), token_antigo = valor_original_esperado, token_novo = valor_novo))
  rep(valor_novo, length(valor_atual))
}

### v2.6.1 ------------------------------------------
### Contrato transacional por tipo de operação:
### - update/substituir_valor e clear/limpar continuam sendo operações de célula inteira;
###   quando valor_original_esperado é informado, ele precisa coincidir com o valor completo atual.
### - append_token, remove_token e replace_token são operações tokenizadas; nelas,
###   valor_original_esperado pode ser token/subconjunto de tokens presente no campo,
###   sem exigir igualdade literal com a célula completa.
### - remove_token aceita o token a remover em valor_novo ou, se vazio, em valor_original_esperado.

monitora_publicacao_d_tokens_presentes_em_valor <- function(valor_atual, tokens_esperados) {
  alvo <- monitora_correcao_tokenizar(tokens_esperados)
  if (!length(alvo)) return(rep(TRUE, length(valor_atual)))
  vapply(
    valor_atual,
    function(v) all(alvo %in% monitora_correcao_tokenizar(v)),
    logical(1)
  )
}

monitora_publicacao_d_precondicao_valor_original <- function(valor_atual, acao, valor_novo, valor_original_esperado) {
  acao <- tolower(trimws(as.character(acao)[1L]))
  if (is.na(acao)) acao <- ""
  valor_novo <- if (length(valor_novo)) as.character(valor_novo[1L]) else NA_character_
  valor_original_esperado <- if (length(valor_original_esperado)) as.character(valor_original_esperado[1L]) else NA_character_
  if (monitora_correcao_vazio(valor_original_esperado) && !(acao %in% c("remove_token", "remover_token"))) {
    return(list(ok = TRUE, mensagem = "OK"))
  }

  valor_atual <- as.character(valor_atual)
  esperado_norm <- monitora_correcao_na_para_vazio(valor_original_esperado)
  atual_norm <- monitora_correcao_na_para_vazio(valor_atual)
  iguais <- atual_norm == esperado_norm

  if (acao %in% c("update", "substituir_valor", "clear", "limpar")) {
    if (all(iguais)) return(list(ok = TRUE, mensagem = "OK"))
    return(list(
      ok = FALSE,
      mensagem = paste0("valor_original_esperado não confere em ", sum(!iguais), " linha(s); operação de valor completo exige igualdade da célula inteira")
    ))
  }

  if (acao %in% c("replace_token", "substituir_token")) {
    tokens_alvo <- valor_original_esperado
    contem <- monitora_publicacao_d_tokens_presentes_em_valor(valor_atual, tokens_alvo)
    if (all(contem)) {
      if (all(iguais)) return(list(ok = TRUE, mensagem = "OK"))
      return(list(
        ok = TRUE,
        mensagem = paste0("OK; valor_original_esperado divergiu em ", sum(!iguais), " linha(s), mas o(s) token(s)-alvo de substituição estava(m) presente(s) em todas as linhas-alvo")
      ))
    }
    return(list(
      ok = FALSE,
      mensagem = paste0("valor_original_esperado não confere em ", sum(!iguais), " linha(s) e o(s) token(s)-alvo de substituição não estava(m) presente(s) em ", sum(!contem), " linha(s)")
    ))
  }

  if (acao %in% c("remove_token", "remover_token")) {
    tokens_alvo <- if (monitora_correcao_vazio(valor_novo)) valor_original_esperado else valor_novo
    contem <- monitora_publicacao_d_tokens_presentes_em_valor(valor_atual, tokens_alvo)
    if (all(contem)) {
      if (all(iguais)) return(list(ok = TRUE, mensagem = "OK"))
      return(list(
        ok = TRUE,
        mensagem = paste0("OK; valor_original_esperado divergiu em ", sum(!iguais), " linha(s), mas o(s) token(s)-alvo de remoção estava(m) presente(s) em todas as linhas-alvo")
      ))
    }
    return(list(
      ok = FALSE,
      mensagem = paste0("token(s)-alvo de remoção não estava(m) presente(s) em ", sum(!contem), " linha(s)")
    ))
  }

  if (acao %in% c("append_token", "adicionar_token")) {
    if (monitora_correcao_vazio(valor_original_esperado)) return(list(ok = TRUE, mensagem = "OK"))
    contem <- monitora_publicacao_d_tokens_presentes_em_valor(valor_atual, valor_original_esperado)
    if (all(iguais) || all(contem)) {
      if (all(iguais)) return(list(ok = TRUE, mensagem = "OK"))
      return(list(
        ok = TRUE,
        mensagem = paste0("OK; valor_original_esperado divergiu em ", sum(!iguais), " linha(s), mas estava contido como token/subconjunto em todas as linhas-alvo")
      ))
    }
    return(list(
      ok = FALSE,
      mensagem = paste0("valor_original_esperado não confere em ", sum(!iguais), " linha(s) e não está contido como token/subconjunto em ", sum(!contem), " linha(s)")
    ))
  }

  if (monitora_correcao_vazio(valor_original_esperado) || all(iguais)) {
    return(list(ok = TRUE, mensagem = "OK"))
  }
  list(ok = FALSE, mensagem = paste0("valor_original_esperado não confere em ", sum(!iguais), " linha(s)"))
}
### FIM v2.6.1 --------------------------------------


### v2.6.1 ----------------------------------
### Proteção transacional para erro de operação ambígua observado na v2.6.1.
### Caso real: o painel gravou acao=update para lista select_multiple de forma
### de vida, com valor_original_esperado="graminoide" e valor_novo="samambaia",
### enquanto a célula real era "serrapilheira graminoide". Como update é
### operação de célula inteira, a pré-condição falhou corretamente. Porém, para
### listas de tokens, esse padrão é inequivocamente uma substituição de token.
### A v2.6.1 reclassifica esse caso para replace_token antes da pré-validação,
### preservando update estrito quando valor_original_esperado for a célula
### inteira ou quando a coluna não for select_multiple/lista principal.

monitora_publicacao_s_coluna_select_multiple_tokenizada <- function(dt, col, dicionario = NULL) {
  col <- as.character(col)[1L]
  if (is.na(col) || !nzchar(col) || !(col %in% names(dt))) return(FALSE)

  papel <- tryCatch(monitora_correcao_papel_coluna_canonico(col), error = function(e) NA_character_)
  if (identical(papel, "lista_principal_forma_vida") || identical(papel, "campo_superior_tipo_forma_vida")) return(TRUE)

  dicionario_dt <- tryCatch(data.table::as.data.table(dicionario), error = function(e) data.table::data.table())
  if (nrow(dicionario_dt) && "atributo_coluna_registros_corrig" %in% names(dicionario_dt)) {
    info <- dicionario_dt[as.character(atributo_coluna_registros_corrig) == col]
    if (nrow(info)) {
      tipo <- if ("tipo_base_edicao" %in% names(info)) as.character(info$tipo_base_edicao[1L]) else NA_character_
      xls_tipo <- if ("xlsform_tipo" %in% names(info)) as.character(info$xlsform_tipo[1L]) else NA_character_
      if (identical(tipo, "select_multiple") || identical(xls_tipo, "select_multiple")) return(TRUE)
    }
  }

  vals <- as.character(dt[[col]])
  vals <- vals[!is.na(vals) & nzchar(trimws(vals))]
  if (!length(vals)) return(FALSE)
  mean(grepl("\\s+", vals)) >= 0.05
}

monitora_publicacao_s_operacao_update_tokenizada <- function(dt, corr_linha, chaves, dicionario = NULL, indice_linhas = NULL) {
  if (is.null(corr_linha) || !nrow(data.table::as.data.table(corr_linha))) return(FALSE)
  corr_linha <- data.table::as.data.table(corr_linha)[1L]

  acao <- if ("acao" %in% names(corr_linha)) monitora_correcao_acao_normalizar(corr_linha$acao[1L]) else ""
  if (!(acao %in% c("update", "substituir_valor"))) return(FALSE)

  esperado <- if ("valor_original_esperado" %in% names(corr_linha)) as.character(corr_linha$valor_original_esperado[1L]) else NA_character_
  novo <- if ("valor_novo" %in% names(corr_linha)) as.character(corr_linha$valor_novo[1L]) else NA_character_
  if (monitora_correcao_vazio(esperado) || monitora_correcao_vazio(novo)) return(FALSE)

  col <- tryCatch(monitora_correcao_resolver_coluna(dt, corr_linha$atributo_coluna_registros_corrig[1L], dicionario), error = function(e) NA_character_)
  if (is.na(col) || !nzchar(col) || !(col %in% names(dt))) return(FALSE)
  if (!isTRUE(monitora_publicacao_s_coluna_select_multiple_tokenizada(dt, col, dicionario))) return(FALSE)

  if (is.null(indice_linhas)) indice_linhas <- tryCatch(monitora_correcao_criar_indice_linhas(dt, chaves), error = function(e) NULL)
  linhas <- tryCatch(monitora_correcao_localizar_linhas(dt, corr_linha, chaves, indice_linhas), error = function(e) integer(0))
  linhas <- unique(as.integer(linhas))
  linhas <- linhas[!is.na(linhas) & linhas >= 1L & linhas <= nrow(dt)]
  if (!length(linhas)) return(FALSE)

  valor_atual <- as.character(dt[[col]][linhas])
  esperado_norm <- monitora_correcao_na_para_vazio(esperado)
  atual_norm <- monitora_correcao_na_para_vazio(valor_atual)

  ### Se esperado já é exatamente a célula inteira em todas as linhas, update é
  ### válido e deve permanecer update.
  if (all(atual_norm == esperado_norm)) return(FALSE)

  contem <- monitora_publicacao_d_tokens_presentes_em_valor(valor_atual, esperado)
  if (!all(contem)) return(FALSE)

  ### Exigir que o valor novo seja tokenizável e diferente do token antigo evita
  ### reclassificar indevidamente atualização textual livre.
  toks_novo <- monitora_correcao_tokenizar(novo)
  toks_esp <- monitora_correcao_tokenizar(esperado)
  if (!length(toks_novo) || !length(toks_esp)) return(FALSE)
  if (identical(paste(toks_novo, collapse = " "), paste(toks_esp, collapse = " "))) return(FALSE)

  TRUE
}

monitora_publicacao_s_reclassificar_updates_tokenizados <- function(dt, corr, chaves, dicionario = NULL, indice_linhas = NULL, arquivo_correcao = NA_character_) {
  corr <- data.table::as.data.table(data.table::copy(corr))
  audit <- data.table::data.table()
  if (!nrow(corr)) return(list(corr = corr, audit = audit, n = 0L))

  idx <- which(vapply(seq_len(nrow(corr)), function(ii) {
    isTRUE(monitora_publicacao_s_operacao_update_tokenizada(dt, corr[ii], chaves, dicionario, indice_linhas))
  }, logical(1L)))

  if (!length(idx)) return(list(corr = corr, audit = audit, n = 0L))

  audit <- data.table::data.table(
    id_correcao = corr$id_correcao[idx],
    ordem_operacao = corr$ordem_operacao[idx],
    status = "ok_acao_reclassificada_update_para_replace_token",
    mensagem = paste0(
      "v2.5.4: acao=update reclassificada para replace_token porque valor_original_esperado ",
      "não era a célula inteira, mas estava presente como token em lista select_multiple; update estrito preservado para células inteiras"
    ),
    atributo = corr$atributo_coluna_registros_corrig[idx],
    linha_indice = NA_integer_,
    valor_antes = corr$valor_original_esperado[idx],
    valor_depois = corr$valor_novo[idx],
    arquivo_correcao = arquivo_correcao
  )

  corr[idx, acao := "replace_token"]
  if ("mensagem_validacao" %in% names(corr)) {
    msg_ant <- as.character(corr$mensagem_validacao[idx])
    msg_ant[is.na(msg_ant) | msg_ant == "NA"] <- ""
    corr[idx, mensagem_validacao := trimws(paste(msg_ant, "v2.5.4: ação reclassificada de update para replace_token antes da aplicação."))]
  }

  list(corr = corr, audit = audit, n = length(idx))
}
### FIM v2.6.1 ------------------------------




### v2.6.1 --------------------------------------
### Harmonização contratual de serrapilheira/material botânico.
### Interpretação consolidada dos XLSForms:
### - ago/2022: serrapilheira apareceu nas listas inferiores nativa/exotica/seca_morta.
### - 2023/2024: serrapilheira passou a existir como token superior em tipo_forma_vida.
### - 2025: serrapilheira/material botânico é token superior em tipo_forma_vida e
###   possui atributo dependente específico forma_serrapilheira.
### Produto harmonizado: remover tokens de material das listas nativa/exotica/seca_morta,
### preencher o atributo de material botânico e garantir o token superior serrapilheira.

monitora_publicacao_c_tokens_materiais_botanicos <- function() {
  c("serrapilheira", "fragmentos_botanicos", "material_inundado")
}

monitora_publicacao_c_token_material_superior <- function() "serrapilheira"

monitora_publicacao_c_resolver_coluna_materiais_botanicos <- function(dt, criar = TRUE) {
  nms <- names(dt)
  candidatos <- c(
    "Materiais botânicos em decomposição no solo observados: (amostragem/registro)",
    "amostragem/registro/forma_serrapilheira",
    "forma_serrapilheira"
  )
  hit <- candidatos[candidatos %in% nms]
  if (length(hit)) return(hit[1L])
  nms_norm <- vapply(nms, monitora_correcao_normalizar_nome_coluna, character(1))
  padroes <- c("materiais_botanicos.*decomposicao", "forma_serrapilheira", "vida_serrapilheira")
  for (pp in padroes) {
    hit_idx <- which(grepl(pp, nms_norm, perl = TRUE))[1L]
    if (!is.na(hit_idx)) return(nms[hit_idx])
  }
  if (isTRUE(criar)) {
    novo <- "Materiais botânicos em decomposição no solo observados: (amostragem/registro)"
    data.table::set(dt, j = novo, value = NA_character_)
    return(novo)
  }
  NA_character_
}

monitora_publicacao_c_tokens_materiais_em_valor <- function(valor) {
  toks <- monitora_correcao_tokenizar(valor)
  if (!length(toks)) return(character(0))
  toks_norm <- vapply(toks, monitora_correcao_normalizar_nome_coluna, character(1))
  materiais <- monitora_publicacao_c_tokens_materiais_botanicos()
  out <- toks_norm[toks_norm %in% materiais]
  out <- out[!is.na(out) & nzchar(out)]
  unique(out)
}

monitora_publicacao_c_remover_materiais_de_valor <- function(valor) {
  toks <- monitora_correcao_tokenizar(valor)
  if (!length(toks)) return(NA_character_)
  toks_norm <- vapply(toks, monitora_correcao_normalizar_nome_coluna, character(1))
  keep <- !(toks_norm %in% monitora_publicacao_c_tokens_materiais_botanicos())
  out <- toks[keep]
  if (!length(out)) return(NA_character_)
  monitora_correcao_colapsar_tokens(out)
}

monitora_publicacao_c_sincronizar_materiais_botanicos <- function(dt, linhas = NULL, contexto = "materiais_botanicos_contrato") {
  dt <- monitora_dt_referenciar(dt)
  if (is.null(linhas)) linhas <- seq_len(nrow(dt))
  linhas <- unique(as.integer(linhas))
  linhas <- linhas[!is.na(linhas) & linhas >= 1L & linhas <= nrow(dt)]
  if (!length(linhas)) return(invisible(data.table::data.table()))

  chaves <- monitora_correcao_colunas_chave(dt)
  enc_col <- chaves$tipo_forma_vida
  mat_col <- monitora_publicacao_c_resolver_coluna_materiais_botanicos(dt, criar = TRUE)
  if (is.na(mat_col) || !nzchar(mat_col) || !(mat_col %in% names(dt))) return(invisible(data.table::data.table()))

  lower_cols <- c(
    nativa = tryCatch(monitora_correcao_coluna_forma_vida(dt, "nativa"), error = function(e) NA_character_),
    exotica = tryCatch(monitora_correcao_coluna_forma_vida(dt, "exotica"), error = function(e) NA_character_),
    seca_morta = tryCatch(monitora_correcao_coluna_forma_vida(dt, "seca_morta"), error = function(e) NA_character_)
  )
  lower_cols <- lower_cols[!is.na(lower_cols) & nzchar(lower_cols) & lower_cols %in% names(dt)]

  audit <- list()
  add_audit <- function(linha, atributo, antes, depois, motivo) {
    if (identical(monitora_correcao_na_para_vazio(antes), monitora_correcao_na_para_vazio(depois))) return(invisible(FALSE))
    audit[[length(audit) + 1L]] <<- data.table::data.table(
      contexto = contexto,
      linha_indice = as.integer(linha),
      atributo = atributo,
      valor_antes = as.character(antes),
      valor_depois = as.character(depois),
      motivo = motivo,
      timestamp = format(Sys.time(), "%Y-%m-%d %H:%M:%S")
    )
    invisible(TRUE)
  }

  for (lin in linhas) {
    tokens_mat <- monitora_publicacao_c_tokens_materiais_em_valor(dt[[mat_col]][lin])
    if (!is.na(enc_col) && nzchar(enc_col) && enc_col %in% names(dt)) {
      tokens_mat <- unique(c(tokens_mat, monitora_publicacao_c_tokens_materiais_em_valor(dt[[enc_col]][lin])))
    }

    if (length(lower_cols)) {
      for (cc in unname(lower_cols)) {
        val_lower <- as.character(dt[[cc]][lin])
        mat_lower <- monitora_publicacao_c_tokens_materiais_em_valor(val_lower)
        if (length(mat_lower)) {
          tokens_mat <- unique(c(tokens_mat, mat_lower))
          novo_lower <- monitora_publicacao_c_remover_materiais_de_valor(val_lower)
          add_audit(lin, cc, val_lower, novo_lower, "material_botanico_removido_de_lista_inferior")
          data.table::set(dt, i = lin, j = cc, value = novo_lower)
        }
      }
    }

    if (length(tokens_mat)) {
      antes_mat <- as.character(dt[[mat_col]][lin])
      novo_mat <- monitora_correcao_colapsar_tokens(unique(c(monitora_correcao_tokenizar(antes_mat), tokens_mat)))
      add_audit(lin, mat_col, antes_mat, novo_mat, "material_botanico_migrado_para_atributo_especifico")
      data.table::set(dt, i = lin, j = mat_col, value = novo_mat)
    }
  }

  aud <- if (length(audit)) data.table::rbindlist(audit, fill = TRUE, use.names = TRUE) else data.table::data.table()
  if (nrow(aud)) {
    out_dir <- get0("MONITORA_CORRECOES_DIR", ifnotfound = file.path("output", "correcoes_campos"), inherits = TRUE)
    dir.create(out_dir, recursive = TRUE, showWarnings = FALSE)
    arq <- file.path(out_dir, "auditoria_materiais_botanicos_contrato.csv")
    ant <- if (file.exists(arq)) tryCatch(data.table::fread(arq, encoding = "UTF-8", showProgress = FALSE, colClasses = "character"), error = function(e) NULL) else NULL
    if (!is.null(ant) && nrow(ant)) aud <- data.table::rbindlist(list(ant, aud), fill = TRUE, use.names = TRUE)
    try(monitora_fwrite(aud, arq, na = ""), silent = TRUE)
  }
  invisible(aud)
}

monitora_publicacao_c_normalizar_contratos_pre_exportacao <- function(dt, contexto = "pre_export") {
  dt <- monitora_dt_referenciar(dt)
  if (exists("monitora_publicacao_c_sincronizar_materiais_botanicos", mode = "function")) {
    try(monitora_publicacao_c_sincronizar_materiais_botanicos(dt, contexto = paste0(contexto, "_materiais_botanicos")), silent = TRUE)
  }
  if (exists("monitora_correcao_sincronizar_encostam_final", mode = "function")) {
    try(monitora_correcao_sincronizar_encostam_final(dt, contexto = paste0(contexto, "_encostam_final")), silent = TRUE)
  }
  invisible(dt)
}
### FIM v2.6.1 ----------------------------------

### v2.6.1 -----------------------------------------
### v2.6.1: correção robusta da materialização de registros_importados.csv com cabeçalhos duplicados.
### v2.6.1 -----------------------------
### Correção de fluxo: registros_importados.csv é produto bruto obrigatório e
### deve ser materializado logo após a concatenação dos CSVs lidos, antes de
### validações, harmonizações, deduplicações finais, painel ou registros_corrig.
### A ausência desse produto não deve bloquear a abertura do painel quando o
### script já avançou, mas a escrita inicial deve ser robusta inclusive com
### cabeçalhos duplicados herdados dos XLSForms históricos.

### Fechamento contratual em alta performance.
### Objetivo: garantir estado final de contrato sem reprocessar globalmente toda
### a base a cada edição incremental do painel.
###
### Estratégia:
### - normalização global apenas quando invariantes rápidas detectarem pendência
###   fora do escopo alterado ou quando a execução não for incremental;
### - em painel incremental, resolver apenas linhas/pontos afetados sempre que a
###   base já estiver contratualmente limpa;
### - auditoria detalhada somente de mudanças, nunca de conformidade;
### - append de auditoria, sem reler/regravar CSVs grandes;
### - simulações de persistência sem efeitos colaterais em disco.
###
### v2.6.1
### Regra de produto: registros_importados.csv é snapshot fiel da leitura/
### montagem dos arquivos de entrada antes de padronizações semânticas,
### harmonizações históricas, painel e correções. Nunca deve ser usado como
### alvo de normalização contratual nem reconstruído a partir de
### registros_corrig.csv. A normalização contratual é obrigatória apenas para
### registros_corrig.csv e registros_validados.csv.

monitora_publicacao_g_log <- function(..., nivel = "INFO") {
  msg <- paste0(..., collapse = "")
  if (exists("monitora_correcao_console_msg", mode = "function")) {
    try(monitora_correcao_console_msg("[v2.6.1] ", msg), silent = TRUE)
  } else {
    message("[v2.6.1] ", msg)
  }
  invisible(TRUE)
}

monitora_publicacao_g_modo_incremental <- function() {
  modo <- get0("MONITORA_MODO_EXECUCAO", ifnotfound = "", inherits = TRUE)
  grepl("painel_incremental|incremental_registros_corrig", as.character(modo), ignore.case = TRUE)
}

monitora_publicacao_g_token_regex <- function(tokens) {
  tokens <- unique(as.character(tokens))
  tokens <- tokens[!is.na(tokens) & nzchar(tokens)]
  tokens <- gsub("([\\^$.|?*+(){}\\[\\]\\\\])", "\\\\\\1", tokens, perl = TRUE)
  paste0("(^|\\s)(", paste(tokens, collapse = "|"), ")(?=\\s|$)")
}

monitora_publicacao_g_has_token_vec <- function(x, tokens) {
  x <- monitora_correcao_na_para_vazio(as.character(x))
  if (!length(x)) return(logical())
  rx <- monitora_publicacao_g_token_regex(tokens)
  grepl(rx, x, perl = TRUE)
}

monitora_publicacao_g_remover_tokens_materiais_vec <- function(x) {
  x0 <- as.character(x)
  rx <- monitora_publicacao_g_token_regex(monitora_publicacao_c_tokens_materiais_botanicos())
  out <- gsub(rx, " ", monitora_correcao_na_para_vazio(x0), perl = TRUE)
  out <- trimws(gsub("\\s+", " ", out, perl = TRUE))
  out[!nzchar(out)] <- NA_character_
  out
}

monitora_publicacao_g_append_tokens_materiais_valor <- function(valor_atual, valores_origem) {
  toks <- monitora_correcao_tokenizar(valor_atual)
  vals <- as.character(valores_origem)
  vals <- vals[!is.na(vals) & nzchar(vals)]
  if (length(vals)) {
    for (vv in vals) toks <- unique(c(toks, monitora_publicacao_c_tokens_materiais_em_valor(vv)))
  }
  toks <- unique(toks[!is.na(toks) & nzchar(toks)])
  if (!length(toks)) return(NA_character_)
  monitora_correcao_colapsar_tokens(toks)
}

monitora_publicacao_g_lower_cols <- function(dt) {
  cols <- c(
    nativa = tryCatch(monitora_correcao_coluna_forma_vida(dt, "nativa"), error = function(e) NA_character_),
    exotica = tryCatch(monitora_correcao_coluna_forma_vida(dt, "exotica"), error = function(e) NA_character_),
    seca_morta = tryCatch(monitora_correcao_coluna_forma_vida(dt, "seca_morta"), error = function(e) NA_character_)
  )
  cols[!is.na(cols) & nzchar(cols) & cols %in% names(dt)]
}

monitora_publicacao_g_append_auditoria <- function(aud, arquivo, resumo = NULL, arquivo_resumo = NULL) {
  if (!is.null(aud) && data.table::is.data.table(aud) && nrow(aud)) {
    dir.create(dirname(arquivo), recursive = TRUE, showWarnings = FALSE)
    existe <- file.exists(arquivo) && file.info(arquivo)$size > 0L
    data.table::fwrite(aud, arquivo, append = existe, col.names = !existe, na = "")
  }
  if (!is.null(resumo) && data.table::is.data.table(resumo) && nrow(resumo) && !is.null(arquivo_resumo)) {
    dir.create(dirname(arquivo_resumo), recursive = TRUE, showWarnings = FALSE)
    existe <- file.exists(arquivo_resumo) && file.info(arquivo_resumo)$size > 0L
    data.table::fwrite(resumo, arquivo_resumo, append = existe, col.names = !existe, na = "")
  }
  invisible(TRUE)
}

monitora_publicacao_g_linhas_afetadas_auditoria <- function(dt) {
  aud <- get0("MONITORA_AUDITORIA_CORRECOES_CAMPOS_ULTIMA", ifnotfound = NULL, inherits = TRUE)
  if (is.null(aud)) return(integer())
  aud <- tryCatch(data.table::as.data.table(aud), error = function(e) data.table::data.table())
  if (!nrow(aud)) return(integer())

  linhas <- integer()
  for (cc in c("linha_indice", "linha_indice_auditoria")) {
    if (cc %in% names(aud)) {
      z <- suppressWarnings(as.integer(aud[[cc]]))
      linhas <- c(linhas, z[!is.na(z)])
    }
  }
  if ("linhas_localizadas_final_indice" %in% names(aud)) {
    z <- as.character(aud$linhas_localizadas_final_indice)
    z <- z[!is.na(z) & nzchar(z)]
    if (length(z)) {
      linhas <- c(linhas, suppressWarnings(as.integer(unlist(strsplit(paste(z, collapse = ";"), ";", fixed = TRUE), use.names = FALSE))))
    }
  }
  linhas <- unique(linhas[!is.na(linhas) & linhas >= 1L & linhas <= nrow(dt)])
  if (!length(linhas)) return(integer())

  ### Expande para todas as linhas com a mesma chave de ponto quando possível.
  ch <- tryCatch(monitora_correcao_colunas_chave(dt), error = function(e) list())
  key_cols <- unique(c(
    unlist(ch[c("COLETA", "coleta", "ponto_amostral", "ponto_metro")], use.names = FALSE),
    intersect(c("COLETA", "ponto_amostral", "ponto_metro"), names(dt))
  ))
  key_cols <- key_cols[!is.na(key_cols) & nzchar(key_cols) & key_cols %in% names(dt)]
  if (length(key_cols) >= 2L && nrow(dt) > 0L) {
    tmp <- data.table::data.table(.v2.5.4 = seq_len(nrow(dt)))
    for (kc in key_cols) data.table::set(tmp, j = kc, value = as.character(dt[[kc]]))
    tmp_alvo <- unique(tmp[linhas, key_cols, with = FALSE])
    exp <- merge(tmp, tmp_alvo, by = key_cols, all = FALSE, sort = FALSE)
    if (".v2.5.4" %in% names(exp)) linhas <- unique(c(linhas, exp$.v2.5.4))
  }
  linhas <- unique(linhas[!is.na(linhas) & linhas >= 1L & linhas <= nrow(dt)])
  linhas
}

monitora_publicacao_g_checar_invariantes_contrato <- function(dt, linhas = NULL, contexto = "invariantes_contrato") {
  dt <- monitora_dt_referenciar(dt)
  if (is.null(linhas)) linhas <- seq_len(nrow(dt))
  linhas <- unique(as.integer(linhas))
  linhas <- linhas[!is.na(linhas) & linhas >= 1L & linhas <= nrow(dt)]
  if (!length(linhas)) {
    return(data.table::data.table(contexto = contexto, linhas_avaliadas = 0L, pendencias_total = 0L))
  }

  ch <- tryCatch(monitora_correcao_colunas_chave(dt), error = function(e) list(tipo_forma_vida = NA_character_))
  enc_col <- ch$tipo_forma_vida
  lower_cols <- monitora_publicacao_g_lower_cols(dt)
  mat_col <- tryCatch(monitora_publicacao_c_resolver_coluna_materiais_botanicos(dt, criar = FALSE), error = function(e) NA_character_)

  mat_em_inferiores <- 0L
  inferior_sem_superior <- 0L
  if (length(lower_cols)) {
    for (cat in names(lower_cols)) {
      cc <- unname(lower_cols[[cat]])
      vals <- dt[[cc]][linhas]
      mat_em_inferiores <- mat_em_inferiores + sum(monitora_publicacao_g_has_token_vec(vals, monitora_publicacao_c_tokens_materiais_botanicos()), na.rm = TRUE)
      if (!is.na(enc_col) && nzchar(enc_col) && enc_col %in% names(dt)) {
        has_lower <- !monitora_correcao_vazio_vec(vals)
        has_sup <- monitora_publicacao_g_has_token_vec(dt[[enc_col]][linhas], cat)
        inferior_sem_superior <- inferior_sem_superior + sum(has_lower & !has_sup, na.rm = TRUE)
      }
    }
  }

  solo_incompativel <- 0L
  material_sem_superior <- 0L
  if (!is.na(enc_col) && nzchar(enc_col) && enc_col %in% names(dt)) {
    enc_vals <- dt[[enc_col]][linhas]
    has_solo <- monitora_publicacao_g_has_token_vec(enc_vals, c("solo_nu", "solo_exposto", "solo", "rocha", "rochas"))
    has_contato <- monitora_publicacao_g_has_token_vec(enc_vals, c("nativa", "exotica", "seca_morta", "serrapilheira", "outra_forma_vida"))
    solo_incompativel <- sum(has_solo & has_contato, na.rm = TRUE)
    if (!is.na(mat_col) && nzchar(mat_col) && mat_col %in% names(dt)) {
      has_mat <- !monitora_correcao_vazio_vec(dt[[mat_col]][linhas])
      has_serrap <- monitora_publicacao_g_has_token_vec(enc_vals, monitora_publicacao_c_token_material_superior())
      material_sem_superior <- sum(has_mat & !has_serrap, na.rm = TRUE)
    }
  }

  data.table::data.table(
    contexto = contexto,
    linhas_avaliadas = length(linhas),
    materiais_em_listas_inferiores = as.integer(mat_em_inferiores),
    inferiores_sem_superior = as.integer(inferior_sem_superior),
    solo_nu_com_contato_real = as.integer(solo_incompativel),
    material_botanico_sem_superior = as.integer(material_sem_superior),
    pendencias_total = as.integer(mat_em_inferiores + inferior_sem_superior + solo_incompativel + material_sem_superior),
    timestamp = format(Sys.time(), "%Y-%m-%d %H:%M:%S")
  )
}

monitora_publicacao_g_definir_linhas_contrato <- function(dt, linhas = NULL, contexto = "pre_export") {
  dt <- monitora_dt_referenciar(dt)
  n <- nrow(dt)
  modo_inc <- monitora_publicacao_g_modo_incremental()
  linhas_arg <- if (!is.null(linhas)) unique(as.integer(linhas)) else integer()
  linhas_arg <- linhas_arg[!is.na(linhas_arg) & linhas_arg >= 1L & linhas_arg <= n]
  linhas_aud <- monitora_publicacao_g_linhas_afetadas_auditoria(dt)
  linhas_inc <- unique(c(linhas_arg, linhas_aud))

  ### Fora do modo incremental, a exportação completa mantém garantia global.
  if (!isTRUE(modo_inc)) {
    return(list(linhas = seq_len(n), escopo = "global_execucao_completa", motivo = "modo_nao_incremental"))
  }

  ### Checagem global barata: se ainda houver pendência contratual fora do escopo
  ### afetado, uma normalização global vetorizada é necessária uma única vez.
  inv_global <- monitora_publicacao_g_checar_invariantes_contrato(dt, linhas = NULL, contexto = paste0(contexto, "_pre_escopo_global"))
  pend <- suppressWarnings(as.integer(inv_global$pendencias_total[1L]))
  if (is.na(pend)) pend <- 0L
  if (pend > 0L) {
    return(list(linhas = seq_len(n), escopo = "global_invariantes_pendentes", motivo = paste0("pendencias_globais=", pend), invariantes = inv_global))
  }

  if (length(linhas_inc)) {
    return(list(linhas = linhas_inc, escopo = "incremental_linhas_afetadas", motivo = paste0("linhas_afetadas=", length(linhas_inc)), invariantes = inv_global))
  }

  ### Se não há linhas afetadas e a base está limpa, não normaliza nada.
  list(linhas = integer(), escopo = "incremental_sem_linhas_e_sem_pendencias", motivo = "nada_a_normalizar", invariantes = inv_global)
}

monitora_publicacao_c_sincronizar_materiais_botanicos <- function(dt,
                                                            linhas = NULL,
                                                            contexto = "materiais_botanicos_contrato",
                                                            gravar_auditoria = TRUE,
                                                            modo_simulacao = FALSE) {
  t0 <- proc.time()[["elapsed"]]
  dt <- monitora_dt_referenciar(dt)
  if (is.null(linhas)) linhas <- seq_len(nrow(dt))
  linhas <- unique(as.integer(linhas))
  linhas <- linhas[!is.na(linhas) & linhas >= 1L & linhas <= nrow(dt)]
  if (!length(linhas)) return(invisible(data.table::data.table()))

  gravar_auditoria <- isTRUE(gravar_auditoria) && !isTRUE(modo_simulacao) &&
    !isTRUE(get0("MONITORA_PUBLICACAO_G_MODO_SIMULACAO_CONTRATO", ifnotfound = FALSE, inherits = TRUE))

  chaves <- monitora_correcao_colunas_chave(dt)
  enc_col <- chaves$tipo_forma_vida
  mat_col <- monitora_publicacao_c_resolver_coluna_materiais_botanicos(dt, criar = TRUE)
  if (is.na(mat_col) || !nzchar(mat_col) || !(mat_col %in% names(dt))) return(invisible(data.table::data.table()))
  lower_cols <- monitora_publicacao_g_lower_cols(dt)

  audit_list <- list()
  add_audit_vec <- function(linhas_a, atributo, antes, depois, motivo) {
    mudou <- monitora_correcao_na_para_vazio(antes) != monitora_correcao_na_para_vazio(depois)
    if (!any(mudou, na.rm = TRUE)) return(invisible(FALSE))
    audit_list[[length(audit_list) + 1L]] <<- data.table::data.table(
      contexto = contexto,
      linha_indice = as.integer(linhas_a[mudou]),
      atributo = as.character(atributo),
      valor_antes = as.character(antes[mudou]),
      valor_depois = as.character(depois[mudou]),
      motivo = motivo,
      timestamp = format(Sys.time(), "%Y-%m-%d %H:%M:%S")
    )
    invisible(TRUE)
  }

  origens_por_linha <- vector("list", length(linhas))

  if (!is.na(enc_col) && nzchar(enc_col) && enc_col %in% names(dt)) {
    enc_vals <- as.character(dt[[enc_col]][linhas])
    idx_enc <- which(monitora_publicacao_g_has_token_vec(enc_vals, monitora_publicacao_c_tokens_materiais_botanicos()))
    if (length(idx_enc)) {
      for (jj in idx_enc) origens_por_linha[[jj]] <- c(origens_por_linha[[jj]], enc_vals[jj])
    }
  }

  mat_vals0 <- as.character(dt[[mat_col]][linhas])
  idx_mat0 <- which(monitora_publicacao_g_has_token_vec(mat_vals0, monitora_publicacao_c_tokens_materiais_botanicos()))
  if (length(idx_mat0)) {
    for (jj in idx_mat0) origens_por_linha[[jj]] <- c(origens_por_linha[[jj]], mat_vals0[jj])
  }

  if (length(lower_cols)) {
    for (cc in unname(lower_cols)) {
      vals <- as.character(dt[[cc]][linhas])
      has_mat <- monitora_publicacao_g_has_token_vec(vals, monitora_publicacao_c_tokens_materiais_botanicos())
      if (!any(has_mat, na.rm = TRUE)) next
      novo <- vals
      novo[has_mat] <- monitora_publicacao_g_remover_tokens_materiais_vec(vals[has_mat])
      add_audit_vec(linhas, cc, vals, novo, "material_botanico_removido_de_lista_inferior")
      data.table::set(dt, i = linhas[has_mat], j = cc, value = novo[has_mat])
      idx <- which(has_mat)
      for (jj in idx) origens_por_linha[[jj]] <- c(origens_por_linha[[jj]], vals[jj])
    }
  }

  idx_origem <- which(vapply(origens_por_linha, length, integer(1L)) > 0L)
  if (length(idx_origem)) {
    antes_mat <- as.character(dt[[mat_col]][linhas[idx_origem]])
    depois_mat <- vapply(seq_along(idx_origem), function(k) {
      jj <- idx_origem[k]
      monitora_publicacao_g_append_tokens_materiais_valor(antes_mat[k], origens_por_linha[[jj]])
    }, character(1L))
    mudou_mat <- monitora_correcao_na_para_vazio(antes_mat) != monitora_correcao_na_para_vazio(depois_mat)
    if (any(mudou_mat, na.rm = TRUE)) {
      add_audit_vec(linhas[idx_origem], mat_col, antes_mat, depois_mat, "material_botanico_migrado_para_atributo_especifico")
      data.table::set(dt, i = linhas[idx_origem][mudou_mat], j = mat_col, value = depois_mat[mudou_mat])
    }
  }

  aud <- if (length(audit_list)) data.table::rbindlist(audit_list, fill = TRUE, use.names = TRUE) else data.table::data.table()
  elapsed <- proc.time()[["elapsed"]] - t0
  resumo <- data.table::data.table(
    contexto = contexto,
    linhas_avaliadas = length(linhas),
    linhas_alteradas = if (nrow(aud)) data.table::uniqueN(aud$linha_indice) else 0L,
    acoes_auditadas = nrow(aud),
    tempo_s = round(elapsed, 3),
    escopo = if (length(linhas) == nrow(dt)) "global" else "incremental",
    timestamp = format(Sys.time(), "%Y-%m-%d %H:%M:%S")
  )

  if (isTRUE(gravar_auditoria)) {
    out_dir <- get0("MONITORA_CORRECOES_DIR", ifnotfound = file.path("output", "correcoes_campos"), inherits = TRUE)
    dir.create(out_dir, recursive = TRUE, showWarnings = FALSE)
    monitora_publicacao_g_append_auditoria(
      aud,
      file.path(out_dir, "auditoria_materiais_botanicos_contrato.csv"),
      resumo,
      file.path(out_dir, "auditoria_materiais_botanicos_contrato_resumo.csv")
    )
  }
  invisible(aud)
}


### v2.6.1 --------------------------------------------
### Selo leve de contrato para evitar fechamentos globais repetidos quando
### registros_corrig já foi saneado, fechado e não sofreu mutação contratual
### depois do último fechamento. A assinatura é propositalmente estrutural
### (linhas, colunas, nomes, resumo leve de conteúdo por coluna e contador
### dirty interno): não substitui auditoria completa, apenas impede chamadas
### redundantes dentro da mesma execução.
monitora_publicacao_z_assinatura_registros_corrig <- function(dt) {
  ### v2.6.1: assinatura intencionalmente barata. A integridade contra
  ### mutações semânticas depende das dirty flags/selo; recalcular uniqueN e
  ### nchar de todas as colunas a cada checagem anulava parte do ganho de
  ### performance do pipeline contratual.
  dt <- monitora_dt_referenciar(dt)
  cols <- names(dt)
  dirty_seq <- suppressWarnings(as.integer(get0("MONITORA_PUBLICACAO_Z_REGISTROS_CORRIG_DIRTY_SEQ", ifnotfound = 0L, inherits = TRUE)))
  if (is.na(dirty_seq)) dirty_seq <- 0L
  cols_chave <- intersect(c(".id", "COLETA", "UC", "EA", "UA", "ANO", "Data (data_hora)", "Horário (data_hora)"), cols)
  amostra <- vapply(cols_chave, function(cc) {
    x <- as.character(dt[[cc]])
    primeiro <- if (length(x)) x[1L] else ""
    ultimo <- if (length(x)) x[length(x)] else ""
    paste(cc, primeiro, ultimo, sep = "
")
  }, character(1L), USE.NAMES = FALSE)
  paste(
    as.integer(nrow(dt)),
    as.integer(ncol(dt)),
    paste(cols, collapse = ""),
    as.integer(dirty_seq),
    paste(amostra, collapse = ""),
    sep = "
"
  )
}

monitora_publicacao_z_marcar_registros_corrig_sujo <- function(motivo = "mutacao_registros_corrig",
                                                        linhas = NULL,
                                                        colunas = NULL,
                                                        coletas = NULL,
                                                        outras_formas = FALSE,
                                                        desconhecida = FALSE,
                                                        encostam = FALSE,
                                                        dependencias = FALSE,
                                                        registros_validados = TRUE) {
  seq_atual <- suppressWarnings(as.integer(get0("MONITORA_PUBLICACAO_Z_REGISTROS_CORRIG_DIRTY_SEQ", ifnotfound = 0L, inherits = TRUE)))
  if (is.na(seq_atual)) seq_atual <- 0L
  assign("MONITORA_PUBLICACAO_Z_REGISTROS_CORRIG_DIRTY_SEQ", seq_atual + 1L, envir = .GlobalEnv)
  assign("MONITORA_PUBLICACAO_Z_REGISTROS_CORRIG_DIRTY_MOTIVO", as.character(motivo)[1L], envir = .GlobalEnv)
  assign("MONITORA_REGISTROS_CORRIG_CONTRATO_OK", FALSE, envir = .GlobalEnv)
  if (exists("monitora_publicacao_ac_registrar_dirty", mode = "function")) {
    try(monitora_publicacao_ac_registrar_dirty(
      motivo = motivo,
      linhas = linhas,
      colunas = colunas,
      coletas = coletas,
      outras_formas = outras_formas,
      desconhecida = desconhecida,
      encostam = encostam,
      dependencias = dependencias,
      registros_validados = registros_validados
    ), silent = TRUE)
  }
  invisible(TRUE)
}

monitora_publicacao_z_gravar_selo_registros_corrig <- function(dt, contexto = "contrato_registros_corrig", invariantes = NULL) {
  assinatura <- monitora_publicacao_z_assinatura_registros_corrig(dt)
  assign("MONITORA_REGISTROS_CORRIG_CONTRATO_OK", TRUE, envir = .GlobalEnv)
  assign("MONITORA_REGISTROS_CORRIG_CONTRATO_ASSINATURA", assinatura, envir = .GlobalEnv)
  assign("MONITORA_REGISTROS_CORRIG_CONTRATO_CONTEXTO", as.character(contexto)[1L], envir = .GlobalEnv)
  assign("MONITORA_REGISTROS_CORRIG_CONTRATO_TIMESTAMP", format(Sys.time(), "%Y-%m-%d %H:%M:%S"), envir = .GlobalEnv)
  if (!is.null(invariantes)) assign("MONITORA_REGISTROS_CORRIG_CONTRATO_INVARIANTES", invariantes, envir = .GlobalEnv)
  invisible(TRUE)
}

monitora_publicacao_z_selo_registros_corrig_valido <- function(dt) {
  ok <- isTRUE(get0("MONITORA_REGISTROS_CORRIG_CONTRATO_OK", ifnotfound = FALSE, inherits = TRUE))
  if (!isTRUE(ok)) return(FALSE)
  assinatura_ant <- get0("MONITORA_REGISTROS_CORRIG_CONTRATO_ASSINATURA", ifnotfound = NA_character_, inherits = TRUE)
  assinatura_atual <- monitora_publicacao_z_assinatura_registros_corrig(dt)
  identical(as.character(assinatura_ant)[1L], as.character(assinatura_atual)[1L])
}
