### v2.6.1 ---------------------------
### Foco: ajuste parcial para a base v2.6.1, preservando contratos e ganhos
### válidos, e telemetria temporizado correto do bloco matriz/mapeamento.
monitora_publicacao_aj_cache_env <- function(nome = "matriz") {
  env_nome <- paste0("MONITORA_PUBLICACAO_AJ_CACHE_", gsub("[^A-Za-z0-9]+", "_", toupper(as.character(nome)[1L])))
  env <- get0(env_nome, ifnotfound = NULL, inherits = FALSE)
  if (!is.environment(env)) {
    env <- new.env(parent = emptyenv())
    assign(env_nome, env, envir = .GlobalEnv)
  }
  env
}

monitora_publicacao_aj_schema_sig <- function(schema) {
  if (!inherits(schema, "data.frame") || !nrow(schema)) return("schema_vazio")
  paste0(
    nrow(schema), ":",
    sum(nchar(names(schema)), na.rm = TRUE), ":",
    paste(names(schema), collapse = "\034"), ":",
    paste(as.character(schema$atributo), collapse = "\034"), ":",
    paste(as.character(schema$formato), collapse = "\034"), ":",
    paste(as.character(schema$largura), collapse = "\034")
  )
}

monitora_publicacao_aj_attrs_especiais_validados <- function() {
  c(
    "data_do_registro", "data_do_recebimento", "data_hora/data", "data_hora/hora",
    "coleta_uuid", "uuid", "amostragem/registro/uuid",
    "uc", "ea", "ua", "ciclo", "campanha", "validado", "controle_versao", "protocolo",
    "planilha_upload", "amostragem/num_placa", "amostragem/num_placa_formatado",
    "amostragem/registro/forma_vida_outros", "amostragem/registro/forma_serrapilheira",
    "amostragem/especie"
  )
}

monitora_publicacao_aj_plano_mapeamento_validados <- function(dt, schema) {
  if (!requireNamespace("data.table", quietly = TRUE)) stop("Pacote data.table é obrigatório.", call. = FALSE)
  dt <- data.table::as.data.table(dt)
  schema <- data.table::as.data.table(schema)
  env <- monitora_publicacao_aj_cache_env("plano_mapeamento")
  sig_dt <- if (exists("monitora_publicacao_ae_dt_names_sig", mode = "function")) {
    monitora_publicacao_ae_dt_names_sig(dt)
  } else {
    paste0(length(names(dt)), ":", sum(nchar(names(dt)), na.rm = TRUE), ":", paste(names(dt), collapse = "\034"))
  }
  sig_schema <- monitora_publicacao_aj_schema_sig(schema)
  chave <- paste0(sig_dt, "||", sig_schema)
  if (identical(get0("chave", envir = env, ifnotfound = NULL), chave)) {
    plano <- get0("plano", envir = env, ifnotfound = NULL)
    if (inherits(plano, "data.table")) return(data.table::copy(plano))
  }
  especiais <- monitora_publicacao_aj_attrs_especiais_validados()
  nms <- names(dt)
  plano <- data.table::copy(schema[, .(posicao, atributo, formato, largura, obrigatorio_valor)])
  plano[, `:=`(
    coluna_origem = NA_character_,
    estrategia_plano = "especial_ou_derivada"
  )]
  for (ii in seq_len(nrow(plano))) {
    att <- as.character(plano$atributo[ii])
    if (att %in% especiais) next
    col <- tryCatch(monitora_validados_resolver_coluna(nms, att), error = function(e) NA_character_)
    if (!is.na(col) && nzchar(col) && col %in% nms) {
      data.table::set(plano, i = ii, j = "coluna_origem", value = col)
      data.table::set(plano, i = ii, j = "estrategia_plano", value = "mapeada_direta_plano_publicacao")
    } else {
      data.table::set(plano, i = ii, j = "estrategia_plano", value = "opcional_sem_origem_vazio")
    }
  }
  assign("chave", chave, envir = env)
  assign("plano", data.table::copy(plano), envir = env)
  plano
}

### Guardar a função base e usar um wrapper por valores distintos. A semântica
### fica idêntica porque os valores únicos são formatados pela própria função
### original; apenas reduzimos trabalho quando há muita repetição.
if (exists("monitora_validados_formatar_valor", mode = "function") &&
    !exists("monitora_validados_formatar_valor_base_publicacao_aj", mode = "function")) {
  monitora_validados_formatar_valor_base_publicacao_aj <- monitora_validados_formatar_valor
  monitora_validados_formatar_valor <- function(x, formato = "texto", largura = NA_integer_) {
    n <- length(x)
    if (n < 512L) return(monitora_validados_formatar_valor_base_publicacao_aj(x, formato, largura))
    y0 <- monitora_validados_limpar_ausencia_saida(x)
    y0[is.na(y0)] <- ""
    u <- unique(y0)
    ### Se há muitos valores distintos, a vetorização original tende a ser mais barata.
    if (length(u) > max(512L, as.integer(n * 0.80))) {
      return(monitora_validados_formatar_valor_base_publicacao_aj(x, formato, largura))
    }
    fu <- monitora_validados_formatar_valor_base_publicacao_aj(u, formato, largura)
    fu[is.na(fu)] <- ""
    unname(fu[match(y0, u)])
  }
}

monitora_publicacao_aj_perf_matriz_env <- function() {
  env <- get0("MONITORA_PUBLICACAO_AJ_PERF_MATRIZ_ENV", ifnotfound = NULL, inherits = FALSE)
  if (!is.environment(env)) {
    env <- new.env(parent = emptyenv())
    assign("MONITORA_PUBLICACAO_AJ_PERF_MATRIZ_ENV", env, envir = .GlobalEnv)
  }
  env
}

monitora_publicacao_aj_perf_matriz_reset <- function() {
  env <- monitora_publicacao_aj_perf_matriz_env()
  rm(list = ls(envir = env, all.names = TRUE), envir = env)
  env$linhas <- list()
  invisible(env)
}

monitora_publicacao_aj_perf_matriz_add <- function(etapa,
                                             segundos,
                                             chamadas = 1L,
                                             n_atributos = 0L,
                                             n_celulas = 0L,
                                             n_valores_distintos = NA_integer_,
                                             detalhe = "") {
  env <- monitora_publicacao_aj_perf_matriz_env()
  if (is.null(env$linhas)) env$linhas <- list()
  k <- length(env$linhas) + 1L
  env$linhas[[k]] <- data.table::data.table(
    etapa = as.character(etapa)[1L],
    segundos = as.numeric(segundos)[1L],
    chamadas = as.integer(chamadas)[1L],
    n_atributos = as.integer(n_atributos)[1L],
    n_celulas = as.integer(n_celulas)[1L],
    n_valores_distintos = as.integer(n_valores_distintos)[1L],
    detalhe = as.character(detalhe)[1L]
  )
  invisible(NULL)
}

monitora_publicacao_aj_perf_matriz_time <- function(etapa, expr,
                                              chamadas = 1L,
                                              n_atributos = 0L,
                                              n_celulas = 0L,
                                              n_valores_distintos = NA_integer_,
                                              detalhe = "") {
  t0 <- proc.time()[["elapsed"]]
  val <- force(expr)
  monitora_publicacao_aj_perf_matriz_add(
    etapa = etapa,
    segundos = proc.time()[["elapsed"]] - t0,
    chamadas = chamadas,
    n_atributos = n_atributos,
    n_celulas = n_celulas,
    n_valores_distintos = n_valores_distintos,
    detalhe = detalhe
  )
  val
}

monitora_publicacao_aj_perf_matriz_gravar <- function(output_dir = get0("MONITORA_OUTPUT_DIR", ifnotfound = "output", inherits = TRUE),
                                                log_dir = get0("MONITORA_LOG_DIR", ifnotfound = "log", inherits = TRUE),
                                                exec_id = get0("MONITORA_EXEC_ID", ifnotfound = format(Sys.time(), "%Y%m%d_%H%M%S"), inherits = TRUE),
                                                resumo_extra = NULL) {
  env <- monitora_publicacao_aj_perf_matriz_env()
  linhas <- env$linhas
  aud <- if (length(linhas)) data.table::rbindlist(linhas, fill = TRUE) else data.table::data.table()
  if (nrow(aud)) {
    aud <- aud[, .(
      segundos = sum(segundos, na.rm = TRUE),
      chamadas = sum(chamadas, na.rm = TRUE),
      n_atributos = sum(n_atributos, na.rm = TRUE),
      n_celulas = sum(n_celulas, na.rm = TRUE),
      n_valores_distintos = if (all(is.na(n_valores_distintos))) NA_integer_ else sum(n_valores_distintos, na.rm = TRUE),
      detalhe = paste(unique(detalhe[nzchar(detalhe)]), collapse = " | ")
    ), by = etapa]
    data.table::setorder(aud, -segundos, etapa)
  }
  if (inherits(resumo_extra, "data.frame") && nrow(resumo_extra)) {
    resumo_extra <- data.table::as.data.table(resumo_extra)
    for (cc in setdiff(names(aud), names(resumo_extra))) resumo_extra[, (cc) := NA]
    for (cc in setdiff(names(resumo_extra), names(aud))) aud[, (cc) := NA]
    aud <- data.table::rbindlist(list(aud, resumo_extra), fill = TRUE, use.names = TRUE)
  }
  try({
    dir.create(output_dir, recursive = TRUE, showWarnings = FALSE)
    dir.create(log_dir, recursive = TRUE, showWarnings = FALSE)
    data.table::fwrite(aud, file.path(output_dir, "auditoria_performance_matriz_mapeamento_xlsform.csv"), sep = ",", quote = "auto", na = "")
    data.table::fwrite(aud, file.path(log_dir, paste0("auditoria_performance_matriz_mapeamento_xlsform_", exec_id, ".csv")), sep = ",", quote = "auto", na = "")
  }, silent = TRUE)
  invisible(aud)
}

monitora_publicacao_aj_constroi_matriz_validados <- function(registros_corrig,
                                                       schema,
                                                       somente_auditar_contrato_corrig = FALSE) {
  if (!requireNamespace("data.table", quietly = TRUE)) stop("Pacote data.table é obrigatório.", call. = FALSE)
  monitora_publicacao_aj_perf_matriz_reset()
  t_total <- proc.time()[["elapsed"]]

  dt <- data.table::as.data.table(registros_corrig)
  schema <- data.table::as.data.table(schema)
  cols <- schema$atributo
  n <- nrow(dt)

  plano <- monitora_publicacao_aj_perf_matriz_time(
    "matriz_plano_resolver",
    monitora_publicacao_aj_plano_mapeamento_validados(dt, schema),
    n_atributos = length(cols),
    detalhe = "resolve estratégia e coluna de origem dos atributos do template"
  )

  out <- monitora_publicacao_aj_perf_matriz_time(
    "matriz_alocar_saida",
    data.table::as.data.table(stats::setNames(rep(list(rep("", n)), length(cols)), cols)),
    n_atributos = length(cols),
    n_celulas = length(cols) * n,
    detalhe = "aloca matriz de saída com 129 atributos"
  )

  auditoria <- vector("list", length(cols))
  auditoria_leve <- isTRUE(somente_auditar_contrato_corrig) &&
    exists("monitora_publicacao_ae_auditoria_mapeamento_leve", mode = "function") &&
    isTRUE(monitora_publicacao_ae_auditoria_mapeamento_leve())

  cont <- list(
    n_linhas = n,
    n_atributos = length(cols),
    n_atributos_diretos = 0L,
    n_atributos_derivados = 0L,
    n_atributos_opcionais_sem_origem = 0L,
    n_chamadas_derivar_mapear_coluna = 0L,
    n_chamadas_formatar_valor = 0L,
    n_celulas_formatadas = 0L,
    n_valores_distintos_pos_formatacao = 0L,
    n_celulas_auditadas_mapeamento = 0L
  )

  progresso_matriz_parcial <- isTRUE(get0("MONITORA_PARAR_APOS_REGISTROS_CORRIG", ifnotfound = FALSE, inherits = TRUE))
  progresso_matriz_inicio <- if (isTRUE(progresso_matriz_parcial)) 6500L else 5000L
  progresso_matriz_fim <- if (isTRUE(progresso_matriz_parcial)) 9000L else 5015L
  if (exists("monitora_progresso_definir_valor", mode = "function")) {
    try(
      monitora_progresso_definir_valor(
        progresso_matriz_inicio,
        etapa = "contrato_xlsform_matriz_mapeamento",
        detalhe = paste0("0/", length(cols), " atributos do XLSForm; montando matriz contratual"),
        force = TRUE
      ),
      silent = TRUE
    )
  }

  for (ii in seq_along(cols)) {
    col_tpl <- cols[ii]
    if (exists("monitora_progresso_definir_valor", mode = "function") &&
        (ii == 1L || ii %% 5L == 0L || ii == length(cols))) {
      alvo_ii <- progresso_matriz_inicio + floor((progresso_matriz_fim - progresso_matriz_inicio) * ii / max(1L, length(cols)))
      detalhe_ii <- paste0(ii, "/", length(cols), " atributos do XLSForm; atributo=", col_tpl)
      try(
        monitora_progresso_definir_valor(
          alvo_ii,
          etapa = "contrato_xlsform_matriz_mapeamento",
          detalhe = detalhe_ii,
          force = ii == length(cols)
        ),
        silent = TRUE
      )
    }
    plano_ii <- plano[ii]
    formato_ii <- schema$formato[ii]
    largura_ii <- schema$largura[ii]

    if (identical(as.character(plano_ii$estrategia_plano), "mapeada_direta_plano_publicacao") &&
        !is.na(plano_ii$coluna_origem) && plano_ii$coluna_origem %in% names(dt)) {
      col_origem <- as.character(plano_ii$coluna_origem)
      x <- monitora_publicacao_aj_perf_matriz_time(
        "matriz_obter_vetores_diretos",
        dt[[col_origem]],
        n_atributos = 1L,
        n_celulas = n,
        detalhe = "obtém vetor de coluna direta já resolvida pelo plano"
      )
      cont$n_atributos_diretos <- cont$n_atributos_diretos + 1L
      estrategia_res <- "mapeada_direta_plano_publicacao"
    } else if (identical(as.character(plano_ii$estrategia_plano), "opcional_sem_origem_vazio")) {
      novo <- monitora_publicacao_aj_perf_matriz_time(
        "matriz_preencher_opcionais_sem_origem",
        rep("", n),
        n_atributos = 1L,
        n_celulas = n,
        detalhe = "preenche atributo sem coluna de origem com vazio efetivo"
      )
      col_origem <- NA_character_
      estrategia_res <- "opcional_sem_origem_vazio"
      cont$n_atributos_opcionais_sem_origem <- cont$n_atributos_opcionais_sem_origem + 1L
      data.table::set(out, j = col_tpl, value = novo)
      tem_valor <- FALSE
      n_dist <- if (isTRUE(auditoria_leve)) NA_integer_ else 0L
      exemplos <- if (isTRUE(auditoria_leve)) "[auditoria_leve_publicacao_aj; opcional sem origem]" else ""
      auditoria[[ii]] <- data.table::data.table(
        posicao = schema$posicao[ii], atributo = col_tpl,
        coluna_origem_registros_corrig = col_origem,
        estrategia = estrategia_res,
        status_mapeamento = "opcional_sem_origem_vazio",
        formato_esperado = formato_ii, largura = largura_ii, obrigatorio_valor = schema$obrigatorio_valor[ii],
        n_linhas_saida = n, n_vazios_saida = n, n_distintos_saida = n_dist,
        exemplos = exemplos,
        bloqueante = FALSE, motivo_bloqueio = ""
      )
      next
    } else {
      res <- monitora_publicacao_aj_perf_matriz_time(
        "matriz_derivar_vetores_especiais",
        monitora_validados_derivar_ou_mapear_coluna(dt, col_tpl, formato_ii, largura_ii),
        n_atributos = 1L,
        n_celulas = n,
        detalhe = "deriva ou mapeia atributo especial não direto"
      )
      x <- res$valor
      col_origem <- ifelse(is.null(res$coluna) || is.na(res$coluna) || !nzchar(res$coluna), NA_character_, as.character(res$coluna))
      estrategia_res <- if (is.null(res$estrategia) || is.na(res$estrategia) || !nzchar(as.character(res$estrategia)[1])) "mapeada" else as.character(res$estrategia)[1]
      cont$n_atributos_derivados <- cont$n_atributos_derivados + 1L
      cont$n_chamadas_derivar_mapear_coluna <- cont$n_chamadas_derivar_mapear_coluna + 1L
    }

    novo <- monitora_publicacao_aj_perf_matriz_time(
      "matriz_formatar_valores",
      monitora_validados_formatar_valor(x, formato_ii, largura_ii),
      n_atributos = 1L,
      n_celulas = length(x),
      n_valores_distintos = tryCatch(data.table::uniqueN(as.character(x)), error = function(e) NA_integer_),
      detalhe = "chama formatador contratual final do atributo"
    )
    cont$n_chamadas_formatar_valor <- cont$n_chamadas_formatar_valor + 1L
    cont$n_celulas_formatadas <- cont$n_celulas_formatadas + length(x)

    data.table::set(out, j = col_tpl, value = novo)

    aud_vals <- monitora_publicacao_aj_perf_matriz_time(
      "matriz_auditoria_vazios_status",
      {
        tem_valor <- any(nzchar(novo))
        n_vazios <- sum(!nzchar(novo))
        if (isTRUE(auditoria_leve)) {
          list(tem_valor = tem_valor, n_vazios = n_vazios, n_dist = NA_integer_, exemplos = "[auditoria_leve_publicacao_aj; exemplos calculados apenas em bloqueios]")
        } else {
          nz <- novo[nzchar(novo)]
          list(tem_valor = tem_valor, n_vazios = n_vazios, n_dist = data.table::uniqueN(nz), exemplos = paste(utils::head(unique(nz), 5L), collapse = " | "))
        }
      },
      n_atributos = 1L,
      n_celulas = length(novo),
      detalhe = "calcula status/vazios/exemplos da auditoria de mapeamento"
    )
    cont$n_celulas_auditadas_mapeamento <- cont$n_celulas_auditadas_mapeamento + length(novo)
    if (!is.na(aud_vals$n_dist)) cont$n_valores_distintos_pos_formatacao <- cont$n_valores_distintos_pos_formatacao + as.integer(aud_vals$n_dist)

    auditoria[[ii]] <- data.table::data.table(
      posicao = schema$posicao[ii], atributo = col_tpl,
      coluna_origem_registros_corrig = col_origem,
      estrategia = estrategia_res,
      status_mapeamento = if (aud_vals$tem_valor) estrategia_res else "opcional_sem_origem_vazio",
      formato_esperado = formato_ii, largura = largura_ii, obrigatorio_valor = schema$obrigatorio_valor[ii],
      n_linhas_saida = n, n_vazios_saida = aud_vals$n_vazios, n_distintos_saida = aud_vals$n_dist,
      exemplos = aud_vals$exemplos,
      bloqueante = FALSE, motivo_bloqueio = ""
    )
  }

  monitora_publicacao_aj_perf_matriz_time(
    "matriz_materializar_auditoria",
    {
      data.table::setcolorder(out, cols)
      auditoria_dt <- data.table::rbindlist(auditoria, fill = TRUE, use.names = TRUE)
    },
    n_atributos = length(cols),
    n_celulas = length(cols) * n,
    detalhe = "ordena matriz e materializa auditoria de mapeamento"
  )

  resumo_extra <- data.table::data.table(
    etapa = "matriz_contadores_totais",
    segundos = proc.time()[["elapsed"]] - t_total,
    chamadas = NA_integer_,
    n_atributos = cont$n_atributos,
    n_celulas = cont$n_atributos * cont$n_linhas,
    n_valores_distintos = cont$n_valores_distintos_pos_formatacao,
    detalhe = paste0(
      "n_linhas=", cont$n_linhas,
      "; n_atributos_diretos=", cont$n_atributos_diretos,
      "; n_atributos_derivados=", cont$n_atributos_derivados,
      "; n_atributos_opcionais_sem_origem=", cont$n_atributos_opcionais_sem_origem,
      "; n_chamadas_derivar_mapear_coluna=", cont$n_chamadas_derivar_mapear_coluna,
      "; n_chamadas_formatar_valor=", cont$n_chamadas_formatar_valor,
      "; n_celulas_formatadas=", cont$n_celulas_formatadas,
      "; n_celulas_auditadas_mapeamento=", cont$n_celulas_auditadas_mapeamento
    )
  )
  monitora_publicacao_aj_perf_matriz_gravar(resumo_extra = resumo_extra)

  list(out = out, auditoria = auditoria_dt)
}
### FIM v2.6.1 -----------------------

monitora_publicacao_g_gravar_selo_contrato <- function(dt, contexto, escopo, linhas_avaliadas, invariantes = NULL) {
  out_dir <- get0("MONITORA_CORRECOES_DIR", ifnotfound = file.path("output", "correcoes_campos"), inherits = TRUE)
  dir.create(out_dir, recursive = TRUE, showWarnings = FALSE)
  selo <- data.table::data.table(
    contexto = contexto,
    escopo = escopo,
    linhas_avaliadas = as.integer(linhas_avaliadas),
    n_linhas = nrow(dt),
    n_colunas = ncol(dt),
    modo_execucao = as.character(get0("MONITORA_MODO_EXECUCAO", ifnotfound = NA_character_, inherits = TRUE)),
    timestamp = format(Sys.time(), "%Y-%m-%d %H:%M:%S")
  )
  if (!is.null(invariantes) && data.table::is.data.table(invariantes) && nrow(invariantes)) {
    for (cc in setdiff(names(invariantes), c("contexto", "timestamp"))) {
      data.table::set(selo, j = paste0("invariante_", cc), value = as.character(invariantes[[cc]][1L]))
    }
  }
  arq <- file.path(out_dir, "selo_estado_final_contratual.csv")
  existe <- file.exists(arq) && file.info(arq)$size > 0L
  data.table::fwrite(selo, arq, append = existe, col.names = !existe, na = "")
  invisible(selo)
}

### v2.6.1
### Esta função é destinada a registros_corrig.csv e registros_validados.csv.
### Nunca chamar para registros_importados.csv, que deve permanecer como snapshot
### fiel dos arquivos de entrada lidos.
monitora_publicacao_c_normalizar_contratos_pre_exportacao <- function(dt, contexto = "pre_export", linhas = NULL, forcar_global = NULL) {
  t0 <- proc.time()[["elapsed"]]
  dt <- monitora_dt_referenciar(dt)
  esc <- monitora_publicacao_g_definir_linhas_contrato(dt, linhas = linhas, contexto = contexto)
  if (isTRUE(forcar_global)) {
    esc$linhas <- seq_len(nrow(dt)); esc$escopo <- "global_forcado"; esc$motivo <- "forcar_global=TRUE"
  }
  linhas_norm <- esc$linhas
  monitora_publicacao_g_log("fechamento contratual ", contexto, ": escopo=", esc$escopo, "; ", esc$motivo, "; linhas=", length(linhas_norm))

  if (length(linhas_norm)) {
    if (exists("monitora_publicacao_c_sincronizar_materiais_botanicos", mode = "function")) {
      monitora_publicacao_c_sincronizar_materiais_botanicos(
        dt,
        linhas = linhas_norm,
        contexto = paste0(contexto, "_materiais_botanicos"),
        gravar_auditoria = TRUE,
        modo_simulacao = FALSE
      )
    }
    if (exists("monitora_correcao_sincronizar_encostam_final", mode = "function")) {
      try(monitora_correcao_sincronizar_encostam_final(dt, linhas = linhas_norm, contexto = paste0(contexto, "_encostam_final")), silent = TRUE)
    }
  }

  inv_pos <- monitora_publicacao_g_checar_invariantes_contrato(dt, linhas = if (length(linhas_norm)) linhas_norm else integer(), contexto = paste0(contexto, "_pos"))
  out_dir <- get0("MONITORA_CORRECOES_DIR", ifnotfound = file.path("output", "correcoes_campos"), inherits = TRUE)
  dir.create(out_dir, recursive = TRUE, showWarnings = FALSE)
  arq_inv <- file.path(out_dir, "auditoria_invariantes_contrato_resumo.csv")
  existe <- file.exists(arq_inv) && file.info(arq_inv)$size > 0L
  data.table::fwrite(inv_pos, arq_inv, append = existe, col.names = !existe, na = "")
  monitora_publicacao_g_gravar_selo_contrato(dt, contexto, esc$escopo, length(linhas_norm), inv_pos)

  pend_pos <- suppressWarnings(as.integer(inv_pos$pendencias_total[1L]))
  if (is.na(pend_pos)) pend_pos <- 0L
  elapsed <- proc.time()[["elapsed"]] - t0
  monitora_publicacao_g_log("fechamento contratual ", contexto, " concluído em ", sprintf("%.3f", elapsed), "s; pendências no escopo=", pend_pos)
  if (pend_pos > 0L) {
    if (exists("monitora_publicacao_z_marcar_registros_corrig_sujo", mode = "function")) {
      monitora_publicacao_z_marcar_registros_corrig_sujo(paste0("pendencias_contrato_", contexto))
    }
    stop("Contrato final não resolvido no escopo de exportação; ver auditoria_invariantes_contrato_resumo.csv.", call. = FALSE)
  }
  if (exists("monitora_publicacao_z_gravar_selo_registros_corrig", mode = "function")) {
    monitora_publicacao_z_gravar_selo_registros_corrig(dt, contexto = contexto, invariantes = inv_pos)
  }
  invisible(dt)
}
### FIM v2.6.1 -------------------------------------


monitora_correcao_calcular_tipo_forma_vida_esperado <- function(dt, linhas = NULL, chaves = monitora_correcao_colunas_chave(dt)) {
  ### v2.6.1
  ### Calcula o valor esperado do campo superior de forma de vida a partir do
  ### estado FINAL do ponto, resolvendo automaticamente condicionantes do contrato.
  ### Regra central: solo_nu/solo exposto é mutuamente exclusivo com qualquer
  ### contato real com a vareta. Contato real inclui categorias derivadas das
  ### listas inferiores finais e quaisquer tokens superiores materiais/contratuais
  ### já presentes, como serrapilheira/material botânico ou outra forma válida.
  dt <- data.table::as.data.table(dt)
  if (is.null(linhas)) linhas <- seq_len(nrow(dt))
  linhas <- unique(as.integer(linhas))
  linhas <- linhas[!is.na(linhas) & linhas >= 1L & linhas <= nrow(dt)]
  if (!length(linhas)) return(character(0))
  tipo_col <- chaves$tipo_forma_vida
  if (is.na(tipo_col) || !nzchar(tipo_col) || !(tipo_col %in% names(dt))) return(rep(NA_character_, length(linhas)))

  parent_cols <- c(
    nativa = tryCatch(monitora_correcao_coluna_forma_vida(dt, "nativa"), error = function(e) NA_character_),
    exotica = tryCatch(monitora_correcao_coluna_forma_vida(dt, "exotica"), error = function(e) NA_character_),
    seca_morta = tryCatch(monitora_correcao_coluna_forma_vida(dt, "seca_morta"), error = function(e) NA_character_)
  )
  parent_cols <- parent_cols[!is.na(parent_cols) & nzchar(parent_cols) & parent_cols %in% names(dt)]
  material_col <- if (exists("monitora_publicacao_c_resolver_coluna_materiais_botanicos", mode = "function")) {
    tryCatch(monitora_publicacao_c_resolver_coluna_materiais_botanicos(dt, criar = FALSE), error = function(e) NA_character_)
  } else NA_character_

  antes <- as.character(dt[[tipo_col]][linhas])
  esperado <- rep(NA_character_, length(linhas))
  solo_tokens <- c("solo_nu", "solo_exposto", "solo", "rocha", "rochas")
  ausentes_tokens <- c("", "na", "nan", "null", "---")
  categorias_controladas <- c("nativa", "exotica", "seca_morta")
  preenchidas <- if (length(parent_cols)) lapply(parent_cols, function(cc) !monitora_correcao_vazio_vec(dt[[cc]][linhas])) else list()

  for (ii in seq_along(linhas)) {
    atual <- monitora_correcao_tokenizar(antes[ii])
    atual_norm <- monitora_correcao_limpar_texto(atual)
    remover_solo <- atual_norm %in% monitora_correcao_limpar_texto(solo_tokens)
    remover_categorias <- atual_norm %in% categorias_controladas
    remover_desconhecida_superior <- atual_norm %in% monitora_correcao_limpar_texto(tryCatch(monitora_correcao_tokens_desconhecida(), error = function(e) c("desconhecida", "desconhecido")))
    remover_ausentes <- atual_norm %in% ausentes_tokens | is.na(atual_norm) | !nzchar(atual_norm)
    outros_contatos <- atual[!(remover_solo | remover_categorias | remover_desconhecida_superior | remover_ausentes)]
    if (!is.na(material_col) && nzchar(material_col) && material_col %in% names(dt)) {
      mat_tokens <- monitora_publicacao_c_tokens_materiais_em_valor(dt[[material_col]][linhas[ii]])
      if (length(mat_tokens)) outros_contatos <- unique(c(outros_contatos, monitora_publicacao_c_token_material_superior()))
    }

    cats <- if (length(parent_cols)) names(parent_cols)[vapply(preenchidas, function(z) isTRUE(z[ii]), logical(1))] else character(0)
    contato_real <- unique(c(outros_contatos, cats))
    contato_real <- contato_real[!is.na(contato_real) & nzchar(trimws(contato_real))]

    if (length(contato_real)) {
      esperado[ii] <- monitora_correcao_colapsar_tokens(contato_real)
    } else {
      esperado[ii] <- "solo_nu"
    }
  }
  esperado
}

monitora_registros_corrig_auditar_encostam_derivado <- function(dt) {
  x <- data.table::as.data.table(data.table::copy(dt))
  n <- nrow(x)
  cols_out <- c(
    "tipo_pendencia", "severidade", "corrigivel_no_painel", "linha",
    "COLETA", "UC", "EA", "UA", "CICLO", "CAMPANHA",
    "coluna_encostam", "valor_atual", "valor_esperado",
    "tokens_atual", "tokens_esperado", "mensagem", "acao_sugerida"
  )
  vazio <- function() {
    out <- data.table::data.table(
      tipo_pendencia = character(),
      severidade = character(),
      corrigivel_no_painel = logical(),
      linha = integer(),
      COLETA = character(),
      UC = character(),
      EA = character(),
      UA = character(),
      CICLO = character(),
      CAMPANHA = character(),
      coluna_encostam = character(),
      valor_atual = character(),
      valor_esperado = character(),
      tokens_atual = character(),
      tokens_esperado = character(),
      mensagem = character(),
      acao_sugerida = character()
    )
    out[, ..cols_out]
  }
  if (!n) return(vazio())

  col_encostam <- NA_character_
  aliases_encostam <- c(
    "**Encostam** na vareta: (amostragem/registro)",
    "amostragem/registro/tipo_forma_vida",
    "tipo_forma_vida"
  )
  hit_alias <- aliases_encostam[aliases_encostam %in% names(x)]
  if (length(hit_alias)) {
    col_encostam <- hit_alias[1L]
  } else {
    ch <- tryCatch(monitora_correcao_colunas_chave(x), error = function(e) list(tipo_forma_vida = NA_character_))
    cand <- tryCatch(as.character(ch$tipo_forma_vida)[1L], error = function(e) NA_character_)
    if (!is.na(cand) && nzchar(cand) && cand %in% names(x)) col_encostam <- cand
  }

  pegar_contexto <- function(chave, padrao) {
    ch <- tryCatch(monitora_correcao_colunas_chave(x), error = function(e) list())
    cc <- tryCatch(as.character(ch[[chave]])[1L], error = function(e) NA_character_)
    if ((is.na(cc) || !nzchar(cc) || !(cc %in% names(x))) && padrao %in% names(x)) cc <- padrao
    if (!is.na(cc) && nzchar(cc) && cc %in% names(x)) as.character(x[[cc]]) else rep(NA_character_, n)
  }
  contexto <- data.table::data.table(
    COLETA = pegar_contexto("coleta", "COLETA"),
    UC = pegar_contexto("uc", "UC"),
    EA = pegar_contexto("ea", "EA"),
    UA = pegar_contexto("ua", "UA"),
    CICLO = pegar_contexto("ciclo", "CICLO"),
    CAMPANHA = pegar_contexto("campanha", "CAMPANHA")
  )

  if (is.na(col_encostam) || !nzchar(col_encostam) || !(col_encostam %in% names(x))) {
    out <- vazio()
    out <- data.table::rbindlist(list(out, data.table::data.table(
      tipo_pendencia = "encostam_coluna_nao_resolvida",
      severidade = "impeditiva",
      corrigivel_no_painel = FALSE,
      linha = NA_integer_,
      COLETA = NA_character_,
      UC = NA_character_,
      EA = NA_character_,
      UA = NA_character_,
      CICLO = NA_character_,
      CAMPANHA = NA_character_,
      coluna_encostam = NA_character_,
      valor_atual = NA_character_,
      valor_esperado = NA_character_,
      tokens_atual = NA_character_,
      tokens_esperado = NA_character_,
      mensagem = "Coluna Encostam/tipo_forma_vida nao resolvida na tabela.",
      acao_sugerida = "verificar_coluna_encostam"
    )), fill = TRUE, use.names = TRUE)
    return(out[, ..cols_out])
  }

  linhas <- seq_len(n)
  esperado <- tryCatch(
    monitora_correcao_calcular_tipo_forma_vida_esperado(x, linhas = linhas),
    error = function(e) rep(NA_character_, n)
  )
  atual <- as.character(x[[col_encostam]])
  tokens_lista <- function(v) {
    z <- tryCatch(monitora_correcao_tokenizar(v), error = function(e) character(0))
    z <- monitora_correcao_normalizar_nome_coluna(z)
    z[!is.na(z) & nzchar(z)]
  }
  toks_atual <- lapply(atual, tokens_lista)
  toks_esperado <- lapply(esperado, tokens_lista)
  colapsar <- function(z) {
    z <- unique(z[!is.na(z) & nzchar(z)])
    if (!length(z)) return(NA_character_)
    paste(z, collapse = " ")
  }
  atual_norm <- vapply(toks_atual, colapsar, character(1))
  esperado_norm <- vapply(toks_esperado, colapsar, character(1))
  atual_vazio <- monitora_correcao_vazio_vec(atual)
  esperado_vazio <- monitora_correcao_vazio_vec(esperado)

  tokens_controlados <- monitora_correcao_normalizar_nome_coluna(c(
    "nativa", "nativas", "nativo", "nativos",
    "exotica", "exoticas", "exotico", "exoticos",
    "seca_morta", "seca", "secas", "seco", "secos", "morta", "mortas", "morto", "mortos",
    "material_botanico", "serrapilheira", "fragmentos_botanicos", "material_inundado",
    "solo_nu", "solo_exposto", "solo", "rocha", "rochas"
  ))
  tokens_solo <- monitora_correcao_normalizar_nome_coluna(c("solo_nu", "solo_exposto", "solo", "rocha", "rochas"))
  tokens_desc <- monitora_correcao_normalizar_nome_coluna(tryCatch(monitora_correcao_tokens_desconhecida(), error = function(e) c("desconhecida", "desconhecido")))
  tokens_outra <- monitora_correcao_normalizar_nome_coluna(tryCatch(monitora_correcao_tokens_residuo_historico_outras_formas(), error = function(e) c("outra_forma_vida", "outras_formas_vida", "forma_vida_outros", "outra", "outro", "outras", "outros")))

  cols_inf <- unique(unlist(lapply(c("nativa", "exotica", "seca_morta"), function(cat) {
    cc <- tryCatch(monitora_correcao_colunas_forma_vida_categoria(x, cat), error = function(e) character(0))
    cc[cc %in% names(x)]
  }), use.names = FALSE))
  tem_inferior <- rep(FALSE, n)
  for (cc in cols_inf) {
    hit <- tryCatch(!monitora_correcao_vazio_vec(x[[cc]]), error = function(e) rep(FALSE, n))
    hit[is.na(hit)] <- FALSE
    tem_inferior <- tem_inferior | hit
  }

  pend <- list()
  adicionar <- function(tipo, idx, mensagem, acao = "recalcular_tipo_forma_vida", corrigivel = TRUE) {
    idx <- unique(as.integer(idx))
    idx <- idx[!is.na(idx) & idx >= 1L & idx <= n]
    if (!length(idx)) return(invisible(NULL))
    pend[[length(pend) + 1L]] <<- data.table::data.table(
      tipo_pendencia = tipo,
      severidade = "impeditiva",
      corrigivel_no_painel = isTRUE(corrigivel),
      linha = idx,
      COLETA = contexto$COLETA[idx],
      UC = contexto$UC[idx],
      EA = contexto$EA[idx],
      UA = contexto$UA[idx],
      CICLO = contexto$CICLO[idx],
      CAMPANHA = contexto$CAMPANHA[idx],
      coluna_encostam = col_encostam,
      valor_atual = atual[idx],
      valor_esperado = esperado[idx],
      tokens_atual = atual_norm[idx],
      tokens_esperado = esperado_norm[idx],
      mensagem = mensagem,
      acao_sugerida = acao
    )
    invisible(NULL)
  }

  difere <- !atual_vazio & !esperado_vazio & monitora_correcao_na_para_vazio(atual_norm) != monitora_correcao_na_para_vazio(esperado_norm)
  adicionar("encostam_desatualizado", which(difere), "Encostam/tipo_forma_vida difere do valor esperado derivado dos campos inferiores.")

  token_sem_inferior <- which(vapply(seq_len(n), function(i) length(setdiff(toks_atual[[i]], toks_esperado[[i]])) > 0L, logical(1)))
  adicionar("encostam_token_sem_inferior", token_sem_inferior, "Encostam contem token que nao aparece no valor esperado derivado dos inferiores.")

  inferior_sem_token <- which(vapply(seq_len(n), function(i) length(setdiff(toks_esperado[[i]], toks_atual[[i]])) > 0L, logical(1)))
  adicionar("encostam_inferior_sem_token", inferior_sem_token, "Valor esperado derivado dos inferiores contem token ausente em Encostam.")

  solo_conflito <- which(vapply(toks_atual, function(z) any(z %in% tokens_solo) && length(setdiff(z, tokens_solo)) > 0L, logical(1)))
  adicionar("encostam_solo_nu_conflitante", solo_conflito, "Encostam contem solo_nu/solo exposto junto com outra categoria.")

  desconhecidos <- which(vapply(toks_atual, function(z) {
    z <- setdiff(z, tokens_desc)
    z <- setdiff(z, tokens_outra)
    length(setdiff(z, tokens_controlados)) > 0L
  }, logical(1)))
  adicionar("encostam_token_desconhecido", desconhecidos, "Encostam contem token fora do conjunto controlado conhecido.")

  desc_superior_only <- which(vapply(toks_atual, function(z) length(z) > 0L && all(z %in% tokens_desc), logical(1)) & !tem_inferior)
  adicionar("encostam_desconhecida_superior_only", desc_superior_only, "Encostam contem somente desconhecida/desconhecido como superior, sem inferiores correspondentes.")

  outra <- which(vapply(seq_len(n), function(i) any(toks_atual[[i]] %in% tokens_outra) || any(toks_esperado[[i]] %in% tokens_outra), logical(1)))
  adicionar("encostam_outra_forma_vida", outra, "Encostam atual ou esperado contem token de outra forma de vida/outros fora do contrato.")

  # TODO Bloco futuro: encostam_vazio_apos_recalculo depende de uma fonte segura
  # para distinguir ponto sem interceptacao real de campo superior vazio indevido.

  if (!length(pend)) return(vazio())
  out <- data.table::rbindlist(pend, fill = TRUE, use.names = TRUE)
  data.table::setorder(out, linha, tipo_pendencia)
  out <- unique(out, by = c("tipo_pendencia", "linha"))
  out[, ..cols_out]
}

monitora_correcao_sincronizar_encostam_final <- function(dt,
                                                          linhas = NULL,
                                                          chaves = monitora_correcao_colunas_chave(dt),
                                                          contexto = "pos_correcoes") {
  ### Sincronização final obrigatória do campo superior Encostam/tipo_forma_vida.
  ###
  ### Justificativa operacional:
  ### - operações como TRIOUT, MVLOTE e recálculos intermediários podem tocar as
  ###   listas inferiores em momentos diferentes;
  ### - Encostam é campo derivado e não deve depender do último valor intermediário
  ###   auditado, mas sim do contrato final: categorias superiores coerentes com
  ###   as listas inferiores finais;
  ### - a aplicação é feita em bloco via data.table::set(), alterando apenas as
  ###   linhas efetivamente divergentes.
  dt <- monitora_dt_referenciar(dt)
  if (is.null(linhas)) linhas <- seq_len(nrow(dt))
  linhas <- unique(as.integer(linhas))
  linhas <- linhas[!is.na(linhas) & linhas >= 1L & linhas <= nrow(dt)]
  chaves <- monitora_correcao_colunas_chave(dt)
  if (exists("monitora_publicacao_c_sincronizar_materiais_botanicos", mode = "function")) {
    try(monitora_publicacao_c_sincronizar_materiais_botanicos(dt, linhas, contexto = paste0(contexto, "_materiais_botanicos")), silent = TRUE)
  }
  tipo_col <- chaves$tipo_forma_vida
  audit <- data.table::data.table()
  afetacoes <- data.table::data.table(linha_indice = integer(), atributo = character())
  if (!length(linhas) || is.na(tipo_col) || !nzchar(tipo_col) || !(tipo_col %in% names(dt))) {
    return(list(dt = dt, audit = audit, linhas = integer(), afetacoes = afetacoes))
  }
  antes <- as.character(dt[[tipo_col]][linhas])
  esperado <- monitora_correcao_calcular_tipo_forma_vida_esperado(dt, linhas, chaves)
  mudou <- monitora_correcao_na_para_vazio(antes) != monitora_correcao_na_para_vazio(esperado)
  linhas_mudou <- linhas[mudou]
  if (length(linhas_mudou) > 0L) {
    data.table::set(dt, i = linhas_mudou, j = tipo_col, value = esperado[mudou])
    audit <- data.table::data.table(
      id_correcao = "SYNC_ENCOSTAM_FINAL",
      ordem_operacao = NA_character_,
      status = "aplicada",
      mensagem = paste0(
        "Sincronização final obrigatória de Encostam/tipo_forma_vida a partir das listas inferiores finais; contexto=",
        contexto
      ),
      atributo = tipo_col,
      linha_indice = linhas_mudou,
      valor_antes = antes[mudou],
      valor_depois = esperado[mudou],
      arquivo_correcao = "sincronizacao_final_pos_correcoes"
    )
    afetacoes <- data.table::data.table(linha_indice = linhas_mudou, atributo = tipo_col)
  }
  list(dt = dt, audit = audit, linhas = linhas_mudou, afetacoes = afetacoes)
}

### v2.6.1: sanitização pré-painel de Encostam = desconhecida
### -------------------------------------------------------------------------
### Caso estrito e auditável: quando o campo superior Encostam/tipo_forma_vida
### contém exclusivamente o token desconhecida/desconhecido e as listas
### inferiores nativa/exótica/seca_morta estão vazias, o registro não tem
### categoria-base observável. Por decisão metodológica, "nativa" é usada como
### categoria técnica hospedeira para preservar a pendência como
### nativa/desconhecida no painel, sem inferir forma de vida válida. A ocorrência
### continua impeditiva até substituição assistida ou exclusão da COLETA.
monitora_correcao_sanitizar_encostam_desconhecida_para_nativa <- function(dt,
                                                                          chaves = monitora_correcao_colunas_chave(dt),
                                                                          output_dir = get0("MONITORA_OUTPUT_DIR", ifnotfound = tempdir(), inherits = TRUE),
                                                                          log_dir = get0("MONITORA_LOG_DIR", ifnotfound = tempdir(), inherits = TRUE),
                                                                          exec_id = get0("MONITORA_EXEC_ID", ifnotfound = format(Sys.time(), "%Y%m%d_%H%M%S"), inherits = TRUE),
                                                                          contexto = "pre_painel") {
  dt <- monitora_dt_referenciar(dt)
  audit <- data.table::data.table()
  afetacoes <- data.table::data.table(linha_indice = integer(), atributo = character())
  rel <- data.table::data.table()
  n <- nrow(dt)
  if (!n) return(list(dt = dt[], audit = audit, relatorio = rel, linhas = integer(), afetacoes = afetacoes))
  chaves <- tryCatch(monitora_correcao_colunas_chave(dt), error = function(e) chaves)
  tipo_col <- tryCatch(chaves$tipo_forma_vida, error = function(e) NA_character_)
  if (is.na(tipo_col) || !nzchar(as.character(tipo_col)[1L]) || !(as.character(tipo_col)[1L] %in% names(dt))) {
    return(list(dt = dt[], audit = audit, relatorio = rel, linhas = integer(), afetacoes = afetacoes))
  }
  tipo_col <- as.character(tipo_col)[1L]
  col_nat <- tryCatch(monitora_correcao_coluna_forma_vida(dt, "nativa"), error = function(e) NA_character_)
  if (is.na(col_nat) || !nzchar(as.character(col_nat)[1L]) || !(as.character(col_nat)[1L] %in% names(dt))) {
    return(list(dt = dt[], audit = audit, relatorio = rel, linhas = integer(), afetacoes = afetacoes))
  }
  col_nat <- as.character(col_nat)[1L]
  cols_inf <- unique(unlist(lapply(c("nativa", "exotica", "seca_morta"), function(cat) {
    cc <- tryCatch(monitora_correcao_colunas_forma_vida_categoria(dt, cat), error = function(e) character(0))
    cc[cc %in% names(dt)]
  }), use.names = FALSE))
  if (!length(cols_inf)) return(list(dt = dt[], audit = audit, relatorio = rel, linhas = integer(), afetacoes = afetacoes))

  toks_desc <- tryCatch(monitora_correcao_tokens_desconhecida(), error = function(e) c("desconhecida", "desconhecido"))
  toks_desc_norm <- unique(monitora_correcao_limpar_texto(toks_desc))
  tipo_vals <- as.character(dt[[tipo_col]])
  tokens_por_linha <- lapply(tipo_vals, function(v) {
    z <- tryCatch(monitora_correcao_tokenizar(v), error = function(e) character(0))
    z <- monitora_correcao_limpar_texto(z)
    z[!is.na(z) & nzchar(z)]
  })
  encostam_exclusivamente_desc <- vapply(tokens_por_linha, function(z) length(z) > 0L && all(z %in% toks_desc_norm), logical(1))
  inferior_vazia <- rep(TRUE, n)
  for (cc in cols_inf) {
    vv <- tryCatch(monitora_correcao_vazio_vec(dt[[cc]]), error = function(e) is.na(dt[[cc]]) | !nzchar(trimws(as.character(dt[[cc]]))))
    vv[is.na(vv)] <- TRUE
    inferior_vazia <- inferior_vazia & vv
  }
  linhas <- which(encostam_exclusivamente_desc & inferior_vazia)
  linhas <- unique(as.integer(linhas[!is.na(linhas) & linhas >= 1L & linhas <= n]))
  if (!length(linhas)) return(list(dt = dt[], audit = audit, relatorio = rel, linhas = integer(), afetacoes = afetacoes))

  pegar <- function(col) {
    if (!is.na(col) && nzchar(as.character(col)[1L]) && as.character(col)[1L] %in% names(dt)) as.character(dt[[as.character(col)[1L]]][linhas]) else rep(NA_character_, length(linhas))
  }
  antes_tipo <- as.character(dt[[tipo_col]][linhas])
  antes_nat <- as.character(dt[[col_nat]][linhas])
  depois_nat <- vapply(antes_nat, monitora_correcao_append_token_valor, character(1), token = "desconhecida")
  data.table::set(dt, i = linhas, j = col_nat, value = depois_nat)
  sync <- tryCatch(monitora_correcao_sincronizar_encostam_final(dt, linhas = linhas, chaves = chaves, contexto = paste0(contexto, "_encostam_desconhecida_para_nativa")), error = function(e) list(dt = dt, audit = data.table::data.table(), linhas = integer(), afetacoes = data.table::data.table()))
  dt <- data.table::as.data.table(sync$dt)
  depois_tipo <- as.character(dt[[tipo_col]][linhas])

  audit <- data.table::rbindlist(list(
    data.table::data.table(
      id_correcao = "SAN_DESC_SUP_PRE_PAINEL",
      ordem_operacao = NA_character_,
      status = "sanitizada_pre_painel",
      mensagem = paste0("Sanitização pré-painel auditável: Encostam exclusivamente desconhecida foi pré-tratado para Encostam=nativa e forma_vida_nativa=desconhecida; contexto=", contexto),
      atributo = col_nat,
      linha_indice = linhas,
      valor_antes = antes_nat,
      valor_depois = depois_nat,
      arquivo_correcao = "sanitizacao_encostam_desconhecida_para_nativa"
    ),
    if (!is.null(sync$audit) && data.table::is.data.table(sync$audit) && nrow(sync$audit)) sync$audit else data.table::data.table()
  ), fill = TRUE, use.names = TRUE)
  afetacoes <- data.table::rbindlist(list(
    data.table::data.table(linha_indice = linhas, atributo = col_nat),
    if (!is.null(sync$afetacoes) && data.table::is.data.table(sync$afetacoes) && nrow(sync$afetacoes)) sync$afetacoes else data.table::data.table()
  ), fill = TRUE, use.names = TRUE)
  ch <- tryCatch(monitora_correcao_colunas_chave(dt), error = function(e) chaves)
  rel <- data.table::data.table(
    contexto = contexto,
    acao = "encostam_desconhecida_superior_only_para_nativa_desconhecida",
    justificativa_tecnica = "Categoria técnica hospedeira para caso sem categoria-base; permanece ocorrência de Forma de vida desconhecida até correção assistida ou exclusão da COLETA.",
    linha_indice = linhas,
    COLETA = pegar(ch$coleta),
    UC = pegar(ch$uc),
    CICLO = pegar(ch$ciclo),
    CAMPANHA = pegar(ch$campanha),
    EA = pegar(ch$ea),
    UA = pegar(ch$ua),
    ANO = pegar(ch$ano),
    ponto_amostral = pegar(ch$ponto_amostral),
    ponto_metro = pegar(ch$ponto_metro),
    Encostam_original = antes_tipo,
    Encostam_final = depois_tipo,
    forma_vida_nativa_original = antes_nat,
    forma_vida_nativa_final = depois_nat
  )
  arqs <- unique(c(
    file.path(output_dir, "correcoes_campos", "relatorios_pre_painel", "sanitizacao_encostam_desconhecida_para_nativa.csv"),
    file.path(output_dir, "02_painel_correcoes", "relatorios_pre_painel", "sanitizacao_encostam_desconhecida_para_nativa.csv"),
    file.path(log_dir, paste0("sanitizacao_encostam_desconhecida_para_nativa_", exec_id, ".csv"))
  ))
  for (aa in arqs) {
    try({ dir.create(dirname(aa), recursive = TRUE, showWarnings = FALSE); monitora_fwrite(rel, aa, na = "") }, silent = TRUE)
  }
  if (exists("monitora_log_registrar_evento", mode = "function")) {
    monitora_log_registrar_evento(
      "painel_correcoes", "INFO", arqs[1L],
      paste0("Sanitização pré-painel Encostam=desconhecida superior-only aplicada em ", length(linhas), " linha(s); pendência preservada como nativa/desconhecida, com Encostam recalculado para nativa."),
      "relatório específico gerado; operação não infere forma válida nem resolve a pendência"
    )
  }
  list(dt = dt[], audit = audit[], relatorio = rel[], linhas = linhas, afetacoes = unique(afetacoes))
}

monitora_correcao_recalcular_tipo_forma_vida <- function(dt, linhas) {
  ### Recalcula tipo_forma_vida em bloco, evitando set() linha-a-linha.
  ### Mantém tokens materiais já existentes e atualiza apenas as categorias
  ### derivadas das listas principais de forma de vida.
  dt <- monitora_dt_referenciar(dt)
  chaves <- monitora_correcao_colunas_chave(dt)
  if (exists("monitora_publicacao_c_sincronizar_materiais_botanicos", mode = "function")) {
    try(monitora_publicacao_c_sincronizar_materiais_botanicos(dt, linhas, contexto = "recalculo_tipo_forma_vida_materiais_botanicos"), silent = TRUE)
  }
  tipo_col <- chaves$tipo_forma_vida
  linhas <- unique(as.integer(linhas))
  linhas <- linhas[!is.na(linhas) & linhas >= 1L & linhas <= nrow(dt)]
  if (is.na(tipo_col) || !(tipo_col %in% names(dt)) || length(linhas) == 0L) return(invisible(dt))
  antes <- as.character(dt[[tipo_col]][linhas])
  depois <- monitora_correcao_calcular_tipo_forma_vida_esperado(dt, linhas, chaves)
  mudou <- monitora_correcao_na_para_vazio(antes) != monitora_correcao_na_para_vazio(depois)
  if (any(mudou, na.rm = TRUE)) {
    data.table::set(dt, i = linhas[mudou], j = tipo_col, value = depois[mudou])
  }
  invisible(dt)
}



monitora_correcao_recalcular_superiores_vinculados <- function(dt, linhas, deps = NULL, dicionario = NULL, afetacoes = NULL) {
  ### Recalcula e harmoniza campos superiores vinculados por regras do XLSForm.
  ### Regra conservadora:
  ###   1. se um campo inferior dependente estiver preenchido, o token correspondente é garantido no campo superior;
  ###   2. o campo superior de classe geral (**Encostam** na vareta / tipo_forma_vida) é sempre recalculado
  ###      a partir das colunas pai de nativa, exótica e seca/morta;
  ###   3. remoções de tokens em campos intermediários continuam sendo feitas por operações explícitas
  ###      (por exemplo, movimento exótica -> nativa), evitando apagar informação válida de forma automática.
  dt <- data.table::as.data.table(dt)
  linhas <- unique(as.integer(linhas))
  linhas <- linhas[!is.na(linhas) & linhas >= 1L & linhas <= nrow(dt)]
  if (length(linhas) == 0L) return(data.table::data.table())
  audit <- data.table::data.table()
  deps <- if (is.null(deps)) data.table::data.table() else data.table::as.data.table(deps)
  if (nrow(deps) > 0L) {
    regras <- monitora_correcao_resolver_dependencias(dt, deps, dicionario, incluir_bloqueadas = TRUE)
    if (nrow(regras) > 0L) {
      bloqueadas <- regras[status_regra == "bloqueada_regra_xlsform_insegura"]
      if (nrow(bloqueadas)) {
        audit <- data.table::rbindlist(list(audit, data.table::data.table(
          id_correcao = "RECALC_SUPERIORES_XLSFORM",
          ordem_operacao = NA_character_,
          status = "bloqueada_regra_xlsform_insegura",
          mensagem = bloqueadas$mensagem_regra,
          atributo = bloqueadas$parent_col,
          linha_indice = NA_integer_,
          valor_antes = NA_character_,
          valor_depois = NA_character_,
          arquivo_correcao = "recalculo_automatico_pos_correcoes",
          parent_name = bloqueadas$parent_name,
          dependent_name = bloqueadas$dependent_name,
          token = bloqueadas$token
        )), fill = TRUE, use.names = TRUE)
      }
      deps_validas <- regras[status_regra == "ok"]
      if (nrow(deps_validas) > 0L) {
        deps_validas <- unique(deps_validas, by = c("parent_col", "token_norm", "dependent_col"))
        for (rr in seq_len(nrow(deps_validas))) {
          parent_col <- deps_validas$parent_col[rr]
          dep_col <- deps_validas$dependent_col[rr]
          token <- deps_validas$token[rr]
          if (is.na(parent_col) || is.na(dep_col)) next
          if (!(parent_col %in% names(dt)) || !(dep_col %in% names(dt))) next
          if (monitora_correcao_coluna_protegida(parent_col) || monitora_correcao_coluna_protegida(dep_col)) next
          idx_base <- linhas
          if (nrow(afetacoes) > 0L) {
            idx_base <- afetacoes[atributo == dep_col, linha_indice]
            idx_base <- unique(idx_base[!is.na(idx_base) & idx_base %in% linhas])
          }
          if (length(idx_base) == 0L) next
          idx <- idx_base[!monitora_correcao_vazio_vec(dt[[dep_col]][idx_base])]
          if (length(idx) == 0L) next
          antes <- as.character(dt[[parent_col]][idx])
          depois <- vapply(antes, monitora_correcao_append_token_valor, character(1), token = token)
          mudou <- monitora_correcao_na_para_vazio(antes) != monitora_correcao_na_para_vazio(depois)
          if (any(mudou)) {
            data.table::set(dt, i = idx[mudou], j = parent_col, value = depois[mudou])
            audit <- data.table::rbindlist(list(audit, data.table::data.table(
              id_correcao = "RECALC_SUPERIORES_XLSFORM",
              ordem_operacao = NA_character_,
              status = "aplicada",
              mensagem = paste0("Campo superior atualizado a partir de campo inferior vinculado pelo XLSForm: ", dep_col),
              atributo = parent_col,
              linha_indice = idx[mudou],
              valor_antes = antes[mudou],
              valor_depois = depois[mudou],
              arquivo_correcao = "recalculo_automatico_pos_correcoes"
            )), fill = TRUE, use.names = TRUE)
          }
        }
      }
    }
  }

  ### 2. Recalcular classe geral de forma de vida, inclusive removendo 'exotica'
  ### quando a coluna de formas exóticas ficou vazia após movimento/correção.
  chaves <- monitora_correcao_colunas_chave(dt)
  tipo_col <- chaves$tipo_forma_vida
  if (!is.na(tipo_col) && tipo_col %in% names(dt)) {
    antes_tipo <- as.character(dt[[tipo_col]][linhas])
    monitora_correcao_recalcular_tipo_forma_vida(dt, linhas)
    depois_tipo <- as.character(dt[[tipo_col]][linhas])
    mudou <- monitora_correcao_na_para_vazio(antes_tipo) != monitora_correcao_na_para_vazio(depois_tipo)
    if (any(mudou)) {
      audit <- data.table::rbindlist(list(audit, data.table::data.table(
        id_correcao = "RECALC_SUPERIORES_XLSFORM",
        ordem_operacao = NA_character_,
        status = "aplicada",
        mensagem = "Campo superior tipo_forma_vida recalculado a partir das categorias de forma de vida",
        atributo = tipo_col,
        linha_indice = linhas[mudou],
        valor_antes = antes_tipo[mudou],
        valor_depois = depois_tipo[mudou],
        arquivo_correcao = "recalculo_automatico_pos_correcoes"
      )), fill = TRUE, use.names = TRUE)
    }
  }
  audit[]
}


monitora_correcao_reforcar_movimentos_forma_vida <- function(dt, corr, chaves = monitora_correcao_colunas_chave(dt), dicionario = NULL) {
  ### Backstop semântico para movimentos entre categorias de forma de vida.
  ### A auditoria mostrou que, em alguns fluxos do painel, a operação remove_token
  ### podia não esvaziar a categoria de origem antes do recálculo do campo superior.
  ### Aqui a transação de movimento é interpretada semanticamente: token_pai deve sair
  ### da categoria_origem e entrar em categoria_destino nas linhas-alvo. Só depois o
  ### tipo_forma_vida é recalculado.
  dt <- data.table::as.data.table(dt)
  corr <- data.table::as.data.table(corr)
  if (nrow(corr) == 0L) {
    return(list(audit = data.table::data.table(), linhas = integer(), afetacoes = data.table::data.table(linha_indice = integer(), atributo = character())))
  }
  cols_need <- c("tipo_correcao", "id_correcao", "escopo_aplicacao", "coleta", "coleta_uuid", "uuid_registro", "ponto_amostral", "token_pai", "categoria_origem", "categoria_destino")
  for (cc in setdiff(cols_need, names(corr))) corr[, (cc) := NA_character_]
  mov <- corr[tolower(trimws(as.character(tipo_correcao))) %in% c("movimento_forma_vida_condicional", "movimento_forma_vida")]
  mov <- mov[!monitora_correcao_vazio(token_pai) & !monitora_correcao_vazio(categoria_origem) & !monitora_correcao_vazio(categoria_destino)]
  if (nrow(mov) == 0L) {
    return(list(audit = data.table::data.table(), linhas = integer(), afetacoes = data.table::data.table(linha_indice = integer(), atributo = character())))
  }
  mov <- unique(mov[, .(
    id_correcao,
    escopo_aplicacao,
    coleta,
    coleta_uuid,
    uuid_registro,
    ponto_amostral,
    token_pai,
    categoria_origem = tolower(trimws(as.character(categoria_origem))),
    categoria_destino = tolower(trimws(as.character(categoria_destino)))
  )])
  audit <- data.table::data.table()
  linhas_afetadas <- integer(0)
  afetacoes <- data.table::data.table(linha_indice = integer(), atributo = character())

  for (rr in seq_len(nrow(mov))) {
    linha_mov <- mov[rr]
    linhas <- monitora_correcao_localizar_linhas(dt, linha_mov, chaves)
    linhas <- unique(as.integer(linhas))
    linhas <- linhas[!is.na(linhas) & linhas >= 1L & linhas <= nrow(dt)]
    if (length(linhas) == 0L) next
    token <- as.character(linha_mov$token_pai[1])
    col_origem <- monitora_correcao_coluna_forma_vida(dt, linha_mov$categoria_origem[1])
    col_destino <- monitora_correcao_coluna_forma_vida(dt, linha_mov$categoria_destino[1])

    if (!is.na(col_origem) && col_origem %in% names(dt)) {
      antes <- as.character(dt[[col_origem]][linhas])
      depois <- vapply(antes, monitora_correcao_remove_token_valor, character(1), token = token)
      mudou <- monitora_correcao_na_para_vazio(antes) != monitora_correcao_na_para_vazio(depois)
      if (any(mudou)) {
        data.table::set(dt, i = linhas[mudou], j = col_origem, value = depois[mudou])
        linhas_afetadas <- unique(c(linhas_afetadas, linhas[mudou]))
        afetacoes <- data.table::rbindlist(list(afetacoes, data.table::data.table(linha_indice = linhas[mudou], atributo = col_origem)), fill = TRUE, use.names = TRUE)
        audit <- data.table::rbindlist(list(audit, data.table::data.table(
          id_correcao = linha_mov$id_correcao[1],
          ordem_operacao = NA_character_,
          status = "aplicada",
          mensagem = paste0("Backstop semântico do movimento: token removido da categoria de origem ", linha_mov$categoria_origem[1]),
          atributo = col_origem,
          linha_indice = linhas[mudou],
          valor_antes = antes[mudou],
          valor_depois = depois[mudou],
          arquivo_correcao = "reforco_semantico_movimento_forma_vida"
        )), fill = TRUE, use.names = TRUE)
      }
    }

    if (!is.na(col_destino) && col_destino %in% names(dt)) {
      antes <- as.character(dt[[col_destino]][linhas])
      depois <- vapply(antes, monitora_correcao_append_token_valor, character(1), token = token)
      mudou <- monitora_correcao_na_para_vazio(antes) != monitora_correcao_na_para_vazio(depois)
      if (any(mudou)) {
        data.table::set(dt, i = linhas[mudou], j = col_destino, value = depois[mudou])
        linhas_afetadas <- unique(c(linhas_afetadas, linhas[mudou]))
        afetacoes <- data.table::rbindlist(list(afetacoes, data.table::data.table(linha_indice = linhas[mudou], atributo = col_destino)), fill = TRUE, use.names = TRUE)
        audit <- data.table::rbindlist(list(audit, data.table::data.table(
          id_correcao = linha_mov$id_correcao[1],
          ordem_operacao = NA_character_,
          status = "aplicada",
          mensagem = paste0("Backstop semântico do movimento: token garantido na categoria de destino ", linha_mov$categoria_destino[1]),
          atributo = col_destino,
          linha_indice = linhas[mudou],
          valor_antes = antes[mudou],
          valor_depois = depois[mudou],
          arquivo_correcao = "reforco_semantico_movimento_forma_vida"
        )), fill = TRUE, use.names = TRUE)
      }
    }
  }
  list(audit = audit[], linhas = linhas_afetadas, afetacoes = afetacoes[])
}


### Limpeza atômica de outras formas de vida
### -------------------------------------------------------------------------
### Rotina transacional vetorizada para sanitizar resíduos históricos de
### outra(s) forma(s) de vida. Contrato atual:
### - tokens históricos de "outra" são removidos das listas antigas;
### - descritores livres inequívocos são convertidos para tokens atuais do
###   XLSForm 21FEV25 em forma_vida_outros;
### - descritores ambíguos, como briófita/briofita sem especificação, não são
###   convertidos automaticamente; são limpos como resíduo legado sem gerar token atual;
### - campos históricos de descritor/foto correlatos são limpos sempre que a
###   sanitização de outra forma de vida é aplicada;
### - após a remoção/conversão, **Encostam** é reconstruído a partir das listas
###   inferiores finais; se nenhuma categoria válida restar, recebe solo_nu.
monitora_correcao_tokens_outras_formas_vida <- function() {
  c("outra_forma_vida", "outras_formas_vida", "forma_vida_outros", "outra", "outro", "outras", "outros")
}

monitora_correcao_tokens_residuo_historico_outras_formas <- function() {
  ### Tokens que indicam resíduo histórico de "outra forma de vida" nas listas
  ### antigas. Não inclui forma_vida_outros: esse é o campo atual válido do
  ### XLSForm 21FEV25; valores como musgos/hepaticas/liquens/fungos nele são
  ### resultado esperado da sanitização e não devem manter a pendência ativa.
  c("outra_forma_vida", "outras_formas_vida", "outra", "outro", "outras", "outros")
}

monitora_correcao_tokens_tipo_validos_pos_limpeza_outras <- function() {
  ### Após remover "outra" das sublistas antigas, nativa/exotica/seca_morta só
  ### contam como categorias efetivas se os campos inferiores correspondentes
  ### permanecerem preenchidos. Aqui entram apenas categorias não inferíveis a
  ### partir dessas sublistas e que podem ser preservadas no campo superior.
  c("solo_nu", "serrapilheira", "fragmentos_botanicos", "material_inundado", "material_botanico")
}

monitora_correcao_contem_qualquer_token_vec <- function(x, tokens) {
  x <- as.character(x)
  if (!length(x)) return(logical(0))
  tokens <- unique(monitora_correcao_normalizar_nome_coluna(tokens))
  tokens <- tokens[!is.na(tokens) & nzchar(tokens)]
  if (!length(tokens)) return(rep(FALSE, length(x)))
  out <- rep(FALSE, length(x))
  for (tok in tokens) out <- out | monitora_correcao_token_presente_vec(x, tok)
  out
}

monitora_correcao_colapsar_lista_serializada <- function(x) {
  x <- unique(trimws(as.character(x)))
  x <- x[!is.na(x) & nzchar(x)]
  if (!length(x)) return(NA_character_)
  paste(x, collapse = "|")
}

monitora_correcao_parse_lista_serializada <- function(x) {
  x <- as.character(x)
  if (!length(x) || is.na(x[1L]) || !nzchar(trimws(x[1L]))) return(character(0))
  z <- unlist(strsplit(x[1L], "[|,;]+", perl = TRUE), use.names = FALSE)
  z <- trimws(z)
  unique(z[!is.na(z) & nzchar(z)])
}

monitora_correcao_normalizar_descritor_outra_forma <- function(x) {
  x <- as.character(x)
  x[is.na(x)] <- ""
  x <- tolower(x)
  x <- iconv(x, from = "", to = "ASCII//TRANSLIT")
  x[is.na(x)] <- ""
  x <- gsub("[^a-z0-9]+", " ", x, perl = TRUE)
  x <- gsub("\\s+", " ", x, perl = TRUE)
  trimws(x)
}

monitora_correcao_adicionar_tokens_valor <- function(valor, tokens) {
  tokens <- monitora_correcao_tokenizar(tokens)
  out <- valor
  if (!length(tokens)) return(out)
  for (tt in tokens) out <- monitora_correcao_append_token_valor(out, tt)
  out
}

monitora_correcao_classificar_descritor_outra_forma <- function(x) {
  x_chr <- as.character(x)
  vazio <- monitora_correcao_vazio_vec(x_chr)
  z <- monitora_correcao_normalizar_descritor_outra_forma(x_chr)
  token <- rep("", length(z))
  status <- rep("limpeza_descritor_legado_sem_conversao", length(z))
  status[vazio] <- "vazio"

  add_token <- function(cond, tok) {
    cond[is.na(cond)] <- FALSE
    if (!any(cond)) return(invisible(NULL))
    token[cond] <<- vapply(token[cond], monitora_correcao_adicionar_tokens_valor, character(1), tokens = tok)
    invisible(NULL)
  }

  ### Conversões inequívocas para tokens atuais do XLSForm 21FEV25.
  ### "m" é aceito apenas porque a regra se aplica exclusivamente a descritores
  ### históricos de outra forma de vida, onde o uso observado representa musgo.
  musgo <- z %in% c("m", "musgo", "musgos", "musg9", "mugo", "mugos") |
    grepl("(^| )musg[a-z0-9]*($| )", z, perl = TRUE) |
    grepl("(^| )mugo[s]?($| )", z, perl = TRUE) |
    grepl("(^| )lodo($| )", z, perl = TRUE)
  add_token(musgo, "musgos")

  hepatica <- grepl("(^| )hepatic[a-z]*($| )", z, perl = TRUE)
  add_token(hepatica, "hepaticas")

  antocero <- grepl("(^| )antocer[a-z]*($| )", z, perl = TRUE)
  add_token(antocero, "antoceros")

  liquen <- grepl("(^| )liquen[s]?($| )", z, perl = TRUE)
  add_token(liquen, "liquens")

  fungo <- grepl("(^| )(fungo[s]?|cogumelo[s]?)($| )", z, perl = TRUE)
  add_token(fungo, "fungos")

  convertido <- !vazio & nzchar(token)
  status[convertido] <- "convertido_para_token_atual_xlsform21"

  briofita <- !convertido & !vazio & (
    grepl("(^| )briofit[a-z]*($| )", z, perl = TRUE) |
      grepl("(^| )bryophyt[a-z]*($| )", z, perl = TRUE)
  )
  status[briofita] <- "limpeza_sem_conversao_briofita_termo_amplo"

  data.table::data.table(
    valor_original = x_chr,
    valor_normalizado = z,
    token_xlsform21 = data.table::fifelse(nzchar(token), token, NA_character_),
    status_sanitizacao = status
  )
}

monitora_correcao_colunas_limpeza_outras_formas <- function(dt, dicionario = NULL) {
  dt <- data.table::as.data.table(dt)
  nms <- names(dt)
  nms_norm <- monitora_correcao_normalizar_nome_coluna(nms)
  mapa <- monitora_correcao_mapa_colunas_canonicas(dt, contexto = "limpeza_outras_formas", gravar = FALSE)

  listas <- mapa[papel_coluna == "lista_principal_forma_vida" & categoria %in% c("nativa", "exotica", "seca_morta"), coluna_registros_corrig]
  listas <- unique(listas[!is.na(listas) & nzchar(listas) & listas %in% nms])

  resolver_dt <- function(vals) {
    vals <- unique(as.character(vals))
    vals <- vals[!is.na(vals) & nzchar(vals)]
    out <- character(0)
    for (vv in vals) {
      hit <- nms[nms == vv]
      if (length(hit)) out <- c(out, hit[1L])
      vv_norm <- monitora_correcao_normalizar_nome_coluna(vv)
      hit2 <- which(nms_norm == vv_norm)
      if (length(hit2)) out <- c(out, nms[hit2[1L]])
      col_res <- tryCatch(monitora_correcao_resolver_coluna(dt, vv, dicionario), error = function(e) NA_character_)
      if (!is.na(col_res) && nzchar(col_res) && col_res %in% nms) out <- c(out, col_res)
    }
    unique(out[out %in% nms])
  }

  descritores <- character(0)
  fotos <- character(0)
  forma_outros <- resolver_dt(c(
    "amostragem/registro/forma_vida_outros",
    "forma_vida_outros",
    "Outras plantas terrestres, líquens e/ou fungos​: (amostragem/registro)",
    "Outras plantas terrestres, líquens e/ou fungos: (amostragem/registro)"
  ))

  if (!is.null(dicionario) && nrow(data.table::as.data.table(dicionario)) > 0L) {
    d <- data.table::as.data.table(dicionario)
    for (cc in c("name", "caminho_registro", "label", "type", "list_name", "relevant")) if (!(cc %in% names(d))) d[, (cc) := NA_character_]
    d[, texto_busca := paste(name, caminho_registro, label, type, list_name, relevant, sep = " ")]
    d[, texto_norm := monitora_correcao_normalizar_nome_coluna(texto_busca)]
    d[, eh_outra_forma_historica := (
      grepl("forma_vida_(nativa|exotica|seca_morta)_outra", texto_norm) |
        (grepl("outr.*forma.*vida", texto_norm) & grepl("nativ|exotic|exotica|exotico|seca|morta", texto_norm))
    )]
    d[, eh_foto_outra_forma := eh_outra_forma_historica & grepl("foto|imagem|image|upload|arquivo|anexo|midia|media", texto_norm)]
    d[, eh_descritor_outra_forma := eh_outra_forma_historica &
        !grepl("especie|especies|outra_sp|_sp($|_)|foto|imagem|image|upload|arquivo|anexo|midia|media|plantas_terrestres|liquen|liquens|fungo|fungos", texto_norm)]
    if (any(d$eh_descritor_outra_forma, na.rm = TRUE)) {
      cand_vals <- unique(unlist(d[eh_descritor_outra_forma == TRUE, .(name, caminho_registro, label)], use.names = FALSE))
      descritores <- c(descritores, resolver_dt(cand_vals))
    }
    if (any(d$eh_foto_outra_forma, na.rm = TRUE)) {
      cand_vals <- unique(unlist(d[eh_foto_outra_forma == TRUE, .(name, caminho_registro, label)], use.names = FALSE))
      fotos <- c(fotos, resolver_dt(cand_vals))
    }
  }

  fallback_desc <- nms[(
    (grepl("outr.*forma.*vida", nms_norm) | grepl("forma_vida.*outr", nms_norm)) &
      grepl("nativ|exotic|exotica|exotico|seca|morta", nms_norm) &
      !grepl("especie|especies|outra_sp|_sp($|_)|foto|imagem|image|upload|arquivo|anexo|midia|media|plantas_terrestres|liquen|liquens|fungo|fungos", nms_norm)
  )]
  fallback_foto <- nms[(
    (grepl("outr.*forma.*vida", nms_norm) | grepl("forma_vida.*outr", nms_norm)) &
      grepl("nativ|exotic|exotica|exotico|seca|morta", nms_norm) &
      grepl("foto|imagem|image|upload|arquivo|anexo|midia|media", nms_norm) &
      !grepl("especie|especies|outra_sp|_sp($|_)", nms_norm)
  )]
  descritores <- unique(c(descritores, fallback_desc))
  descritores <- descritores[descritores %in% nms]
  fotos <- unique(c(fotos, fallback_foto))
  fotos <- fotos[fotos %in% nms]
  forma_outros <- unique(forma_outros[forma_outros %in% nms])

  tipo_cols <- mapa[papel_coluna == "campo_superior_tipo_forma_vida", coluna_registros_corrig]
  tipo_cols <- unique(tipo_cols[!is.na(tipo_cols) & nzchar(tipo_cols) & tipo_cols %in% nms])
  chaves <- monitora_correcao_colunas_chave(dt)
  tipo_update <- if (!is.na(chaves$tipo_forma_vida) && chaves$tipo_forma_vida %in% nms) chaves$tipo_forma_vida else if (length(tipo_cols)) tipo_cols[1L] else NA_character_

  data.table::rbindlist(list(
    data.table::data.table(classe = "lista_principal_forma_vida", coluna = listas, categoria = mapa[match(listas, coluna_registros_corrig), categoria], usar_para_escrita_solo_nu = FALSE),
    data.table::data.table(classe = "descritor_outra_forma_vida", coluna = descritores, categoria = NA_character_, usar_para_escrita_solo_nu = FALSE),
    data.table::data.table(classe = "foto_outra_forma_vida", coluna = fotos, categoria = NA_character_, usar_para_escrita_solo_nu = FALSE),
    data.table::data.table(classe = "campo_atual_forma_vida_outros", coluna = forma_outros, categoria = NA_character_, usar_para_escrita_solo_nu = FALSE),
    data.table::data.table(classe = "campo_superior_tipo_forma_vida", coluna = tipo_cols, categoria = NA_character_, usar_para_escrita_solo_nu = tipo_cols == tipo_update)
  ), fill = TRUE, use.names = TRUE)[!is.na(coluna) & nzchar(coluna)]
}

monitora_correcao_contar_residuos_outras_formas <- function(dt, linhas, cols_info) {
  dt <- data.table::as.data.table(dt)
  linhas <- unique(as.integer(linhas))
  linhas <- linhas[!is.na(linhas) & linhas >= 1L & linhas <= nrow(dt)]
  tokens_outra <- monitora_correcao_tokens_residuo_historico_outras_formas()
  listas <- cols_info[classe == "lista_principal_forma_vida" & coluna %in% names(dt), coluna]
  descritores <- cols_info[classe == "descritor_outra_forma_vida" & coluna %in% names(dt), coluna]
  fotos <- cols_info[classe == "foto_outra_forma_vida" & coluna %in% names(dt), coluna]
  if (!length(linhas)) {
    return(data.table::data.table(linhas_alvo = 0L, linhas_com_token_outra = 0L, celulas_com_token_outra = 0L, linhas_com_descritor = 0L, celulas_com_descritor = 0L, linhas_com_foto_historica = 0L, celulas_com_foto_historica = 0L, linhas_com_residuo_total = 0L))
  }
  flag_token <- rep(FALSE, length(linhas)); n_token <- 0L
  for (cc in listas) {
    hit <- monitora_correcao_contem_qualquer_token_vec(dt[[cc]][linhas], tokens_outra)
    flag_token <- flag_token | hit
    n_token <- n_token + sum(hit, na.rm = TRUE)
  }
  flag_desc <- rep(FALSE, length(linhas)); n_desc <- 0L
  for (cc in descritores) {
    hit <- !monitora_correcao_vazio_vec(dt[[cc]][linhas])
    flag_desc <- flag_desc | hit
    n_desc <- n_desc + sum(hit, na.rm = TRUE)
  }
  flag_foto <- rep(FALSE, length(linhas)); n_foto <- 0L
  for (cc in fotos) {
    hit <- !monitora_correcao_vazio_vec(dt[[cc]][linhas])
    flag_foto <- flag_foto | hit
    n_foto <- n_foto + sum(hit, na.rm = TRUE)
  }
  data.table::data.table(
    linhas_alvo = length(linhas),
    linhas_com_token_outra = sum(flag_token, na.rm = TRUE),
    celulas_com_token_outra = n_token,
    linhas_com_descritor = sum(flag_desc, na.rm = TRUE),
    celulas_com_descritor = n_desc,
    linhas_com_foto_historica = sum(flag_foto, na.rm = TRUE),
    celulas_com_foto_historica = n_foto,
    linhas_com_residuo_total = sum(flag_token | flag_desc | flag_foto, na.rm = TRUE)
  )
}

monitora_correcao_localizar_linhas_limpeza_outras_formas <- function(dt, linha_corr, chaves = monitora_correcao_colunas_chave(dt), indice = NULL) {
  dt <- data.table::as.data.table(dt)
  linha_corr <- data.table::as.data.table(linha_corr)
  esc <- if ("escopo_aplicacao" %in% names(linha_corr)) tolower(trimws(as.character(linha_corr$escopo_aplicacao[1L]))) else ""
  if (is.na(esc)) esc <- ""

  ### v2.6.1: TRIOUT é operação por ocorrência diagnóstica estável.
  ### Prioridade de resolução:
  ### 1) UUID(s) do registro;
  ### 2) chave composta de contexto (COLETA + ponto_amostral/ponto_metro, quando gravados);
  ### 3) COLETA como fallback legado;
  ### 4) linha_indice/linhas_alvo_serializadas apenas como último recurso validável.
  ### A posição da linha não pode ser a identidade primária, pois exclusões de
  ### COLETA deslocam o data.table antes de TRIOUT ser simulado/aplicado.
  parse_any <- function(cols) {
    vals <- character(0)
    for (cc in intersect(cols, names(linha_corr))) {
      vals <- c(vals, unlist(lapply(as.character(linha_corr[[cc]]), monitora_correcao_parse_serial_generico), use.names = FALSE))
    }
    vals <- unique(trimws(as.character(vals)))
    vals[!is.na(vals) & nzchar(vals)]
  }

  idx_uuid <- integer(0)
  if (!is.na(chaves$uuid_registro) && chaves$uuid_registro %in% names(dt)) {
    uu <- parse_any(c("uuid_registro", "uuid_registro_serializado", "uuids_registro"))
    if (length(uu)) idx_uuid <- which(trimws(as.character(dt[[chaves$uuid_registro]])) %chin% uu)
  }
  idx_uuid <- unique(as.integer(idx_uuid))
  idx_uuid <- idx_uuid[!is.na(idx_uuid) & idx_uuid >= 1L & idx_uuid <= nrow(dt)]
  if (length(idx_uuid)) return(idx_uuid)

  idx_ctx <- seq_len(nrow(dt))
  tem_ctx <- FALSE
  coletas <- parse_any(c("coleta", "COLETA", "coletas"))
  if (length(coletas) && !is.na(chaves$coleta) && chaves$coleta %in% names(dt)) {
    idx_ctx <- idx_ctx[as.character(dt[[chaves$coleta]][idx_ctx]) %chin% coletas]
    tem_ctx <- TRUE
  }
  uas <- parse_any(c("UA", "ua"))
  if (length(uas) && !is.na(chaves$ua) && chaves$ua %in% names(dt)) {
    idx_ctx <- idx_ctx[as.character(dt[[chaves$ua]][idx_ctx]) %chin% uas]
    tem_ctx <- TRUE
  }
  ciclos <- parse_any(c("CICLO", "ciclo"))
  if (length(ciclos) && !is.na(chaves$ciclo) && chaves$ciclo %in% names(dt)) {
    idx_ctx <- idx_ctx[as.character(dt[[chaves$ciclo]][idx_ctx]) %chin% ciclos]
    tem_ctx <- TRUE
  }
  campanhas <- parse_any(c("CAMPANHA", "campanha"))
  if (length(campanhas) && !is.na(chaves$campanha) && chaves$campanha %in% names(dt)) {
    idx_ctx <- idx_ctx[as.character(dt[[chaves$campanha]][idx_ctx]) %chin% campanhas]
    tem_ctx <- TRUE
  }
  anos <- parse_any(c("ANO", "ano"))
  if (length(anos) && !is.na(chaves$ano) && chaves$ano %in% names(dt)) {
    idx_ctx <- idx_ctx[as.character(dt[[chaves$ano]][idx_ctx]) %chin% anos]
    tem_ctx <- TRUE
  }
  pontos <- parse_any(c("ponto_amostral", "Ponto amostral", "ponto_amostral_serializado"))
  if (length(pontos) && !is.na(chaves$ponto_amostral) && chaves$ponto_amostral %in% names(dt)) {
    idx_ctx <- idx_ctx[as.character(dt[[chaves$ponto_amostral]][idx_ctx]) %chin% pontos]
    tem_ctx <- TRUE
  }
  metros <- parse_any(c("ponto_metro", "Ponto metro", "ponto_metro_serializado"))
  if (length(metros) && !is.na(chaves$ponto_metro) && chaves$ponto_metro %in% names(dt)) {
    idx_ctx <- idx_ctx[as.character(dt[[chaves$ponto_metro]][idx_ctx]) %chin% metros]
    tem_ctx <- TRUE
  }
  idx_ctx <- unique(as.integer(idx_ctx))
  idx_ctx <- idx_ctx[!is.na(idx_ctx) & idx_ctx >= 1L & idx_ctx <= nrow(dt)]
  if (isTRUE(tem_ctx) && length(idx_ctx)) return(idx_ctx)

  if (esc %in% c("lote_coletas", "coletas_filtradas", "multicoletas_atomico", "coleta_inteira")) {
    if (is.na(chaves$coleta) || !(chaves$coleta %in% names(dt))) return(integer(0))
    coletas <- parse_any(c("coleta", "COLETA", "coletas"))
    if (!length(coletas)) return(integer(0))
    idx <- which(as.character(dt[[chaves$coleta]]) %chin% coletas)
    pontos <- parse_any(c("ponto_amostral", "Ponto amostral"))
    if (length(pontos) && !is.na(chaves$ponto_amostral) && chaves$ponto_amostral %in% names(dt)) {
      idx <- idx[as.character(dt[[chaves$ponto_amostral]][idx]) %chin% pontos]
    }
    return(unique(as.integer(idx)))
  }

  parse_linhas_exp <- function() {
    vals <- character(0)
    for (cc in intersect(c("linhas_alvo_serializadas", "valor_original_esperado", "linha_indice"), names(linha_corr))) {
      vals <- c(vals, monitora_correcao_parse_serial_generico(linha_corr[[cc]][1L]))
    }
    idx <- suppressWarnings(as.integer(vals))
    unique(idx[!is.na(idx) & idx >= 1L & idx <= nrow(dt)])
  }
  idx_exp <- parse_linhas_exp()
  if (length(idx_exp)) return(idx_exp)

  unique(as.integer(monitora_correcao_localizar_linhas(dt, linha_corr, chaves, indice)))
}

monitora_correcao_aplicar_limpeza_outras_formas_atomica <- function(dt, linhas, id_correcao = NA_character_, arquivo_correcao = NA_character_, dicionario = NULL) {
  ### CRÍTICO: não usar as.data.table() aqui.
  ### Em alguns fluxos, as.data.table() pode operar sobre uma cópia/local; a auditoria
  ### fica correta, mas a alteração não persiste no objeto exportado. setDT()/referência
  ### preserva a alteração no mesmo data.table usado pelo fluxo principal.
  dt <- monitora_dt_referenciar(dt)
  linhas <- unique(as.integer(linhas))
  linhas <- linhas[!is.na(linhas) & linhas >= 1L & linhas <= nrow(dt)]
  audit <- data.table::data.table()
  afetacoes <- data.table::data.table(linha_indice = integer(), atributo = character())
  if (!length(linhas)) {
    ### v2.6.1: limpeza de outras formas deve ser idempotente.
    ### Escopo vazio pode ocorrer quando as COLETAS-alvo foram quarentenadas,
    ### excluídas na mesma sessão ou quando o lote filtrado não contém resíduo
    ### remanescente. Isso é sucesso auditável; pendências reais serão capturadas
    ### pela auditoria impeditiva pós-aplicação, sem abortar a aplicação aqui.
    return(list(audit = data.table::data.table(id_correcao = id_correcao, ordem_operacao = NA_character_, status = "ok_sem_linhas_alvo", mensagem = "Nenhuma linha-alvo localizada para limpeza atômica de outras formas de vida; operação tratada como idempotente e não bloqueante. Se houver resíduo remanescente, a auditoria impeditiva pós-painel registrará a pendência.", atributo = "__limpar_outras_formas_vida__", linha_indice = NA_integer_, valor_antes = NA_character_, valor_depois = NA_character_, arquivo_correcao = arquivo_correcao), linhas = integer(), afetacoes = afetacoes, falha = FALSE))
  }
  cols_info <- monitora_correcao_colunas_limpeza_outras_formas(dt, dicionario)
  listas <- cols_info[classe == "lista_principal_forma_vida" & coluna %in% names(dt), unique(coluna)]
  descritores <- cols_info[classe == "descritor_outra_forma_vida" & coluna %in% names(dt), unique(coluna)]
  fotos <- cols_info[classe == "foto_outra_forma_vida" & coluna %in% names(dt), unique(coluna)]
  forma_outros_col <- cols_info[classe == "campo_atual_forma_vida_outros" & coluna %in% names(dt), unique(coluna)]
  forma_outros_col <- if (length(forma_outros_col)) forma_outros_col[1L] else NA_character_
  if (is.na(forma_outros_col) || !nzchar(forma_outros_col)) {
    forma_outros_col <- "amostragem/registro/forma_vida_outros"
    if (!(forma_outros_col %in% names(dt))) data.table::set(dt, j = forma_outros_col, value = NA_character_)
    cols_info <- data.table::rbindlist(list(
      cols_info,
      data.table::data.table(classe = "campo_atual_forma_vida_outros", coluna = forma_outros_col, categoria = NA_character_, usar_para_escrita_solo_nu = FALSE)
    ), fill = TRUE, use.names = TRUE)
  }
  tipo_cols <- cols_info[classe == "campo_superior_tipo_forma_vida" & coluna %in% names(dt), unique(coluna)]
  tipo_update <- cols_info[classe == "campo_superior_tipo_forma_vida" & usar_para_escrita_solo_nu == TRUE & coluna %in% names(dt), coluna]
  tipo_update <- if (length(tipo_update)) tipo_update[1L] else NA_character_
  if (!length(listas) && !length(descritores) && !length(fotos)) {
    return(list(audit = data.table::data.table(id_correcao = id_correcao, ordem_operacao = NA_character_, status = "falha_sem_colunas", mensagem = "Nenhuma coluna de lista/descritor/foto histórica de outra forma de vida detectada", atributo = "__limpar_outras_formas_vida__", linha_indice = NA_integer_, valor_antes = NA_character_, valor_depois = NA_character_, arquivo_correcao = arquivo_correcao), linhas = integer(), afetacoes = afetacoes, falha = TRUE))
  }
  tokens_outra <- monitora_correcao_tokens_residuo_historico_outras_formas()
  remover_serial <- paste(tokens_outra, collapse = " ")
  registrar <- function(col, idx, antes, depois, mensagem, status = "aplicada") {
    idx <- as.integer(idx)
    mudou <- monitora_correcao_na_para_vazio(antes) != monitora_correcao_na_para_vazio(depois)
    if (!any(mudou, na.rm = TRUE)) return(invisible(NULL))
    idx2 <- idx[mudou]
    audit <<- data.table::rbindlist(list(audit, data.table::data.table(
      id_correcao = id_correcao,
      ordem_operacao = NA_character_,
      status = status,
      mensagem = mensagem,
      atributo = col,
      linha_indice = idx2,
      valor_antes = antes[mudou],
      valor_depois = depois[mudou],
      arquivo_correcao = arquivo_correcao
    )), fill = TRUE, use.names = TRUE)
    afetacoes <<- data.table::rbindlist(list(afetacoes, data.table::data.table(linha_indice = idx2, atributo = col)), fill = TRUE, use.names = TRUE)
  }
  registrar_evento <- function(col, idx, antes, depois, mensagem, status = "aplicada") {
    idx <- as.integer(idx)
    if (!length(idx)) return(invisible(NULL))
    audit <<- data.table::rbindlist(list(audit, data.table::data.table(
      id_correcao = id_correcao,
      ordem_operacao = NA_character_,
      status = status,
      mensagem = mensagem,
      atributo = col,
      linha_indice = idx,
      valor_antes = antes,
      valor_depois = depois,
      arquivo_correcao = arquivo_correcao
    )), fill = TRUE, use.names = TRUE)
    invisible(NULL)
  }

  resumo_antes <- monitora_correcao_contar_residuos_outras_formas(dt, linhas, cols_info)

  ### 1) Converter descritores inequívocos para o campo atual forma_vida_outros;
  ###    descritores sem equivalência inequívoca são limpos como resíduo legado,
  ###    sem gerar outra_forma_vida atual e sem bloquear a sanitização.
  for (cc in descritores) {
    antes <- as.character(dt[[cc]][linhas])
    cls <- monitora_correcao_classificar_descritor_outra_forma(antes)
    conv <- cls$status_sanitizacao == "convertido_para_token_atual_xlsform21"
    legado <- !conv & !monitora_correcao_vazio_vec(antes)
    campo_outros_ok <- !is.na(forma_outros_col) && forma_outros_col %in% names(dt)

    if (any(conv, na.rm = TRUE)) {
      if (campo_outros_ok) {
        idx_conv <- linhas[conv]
        antes_outros <- as.character(dt[[forma_outros_col]][idx_conv])
        depois_outros <- mapply(monitora_correcao_adicionar_tokens_valor, antes_outros, cls$token_xlsform21[conv], USE.NAMES = FALSE)
        data.table::set(dt, i = idx_conv, j = forma_outros_col, value = depois_outros)
        registrar(forma_outros_col, idx_conv, antes_outros, depois_outros, paste0("Limpeza atômica: descritor histórico de outra forma de vida convertido para token atual do XLSForm 21FEV25 a partir de ", cc))
      } else {
        registrar_evento("amostragem/registro/forma_vida_outros", linhas[conv], antes[conv], cls$token_xlsform21[conv], "Descritor histórico teria conversão inequívoca, mas campo atual forma_vida_outros não foi localizado", "falha_sem_campo_atual_forma_vida_outros")
      }
    }

    if (any(legado, na.rm = TRUE)) {
      registrar_evento(cc, linhas[legado], antes[legado], as.character(cls$status_sanitizacao[legado]), "Descritor histórico de outra forma de vida sem equivalência inequívoca no XLSForm 21FEV25; limpo como resíduo legado sem gerar token atual", "limpeza_descritor_legado_sem_conversao")
    }

    limpar <- ((conv & campo_outros_ok) | legado) & !monitora_correcao_vazio_vec(antes)
    if (any(limpar, na.rm = TRUE)) {
      depois <- antes
      depois[limpar] <- NA_character_
      data.table::set(dt, i = linhas[limpar], j = cc, value = NA_character_)
      registrar(cc, linhas, antes, depois, "Limpeza atômica: descritor textual histórico de outra forma de vida limpo; conversões inequívocas foram migradas e demais descritores foram removidos sem conversão")
    }
  }

  ### 2) Remover tokens históricos das listas antigas.
  for (cc in listas) {
    antes <- as.character(dt[[cc]][linhas])
    depois <- vapply(antes, monitora_correcao_remove_token_valor, character(1), token = remover_serial)
    mudou <- monitora_correcao_na_para_vazio(antes) != monitora_correcao_na_para_vazio(depois)
    if (any(mudou, na.rm = TRUE)) {
      data.table::set(dt, i = linhas[mudou], j = cc, value = depois[mudou])
      registrar(cc, linhas, antes, depois, "Limpeza atômica: token(s) histórico(s) de outra(s) forma(s) de vida removido(s) da lista principal")
    }
  }

  ### 3) Limpar fotos/imagens históricas correlatas, pois esses campos não fazem
  ###    parte do contrato atual do XLSForm 21FEV25.
  for (cc in fotos) {
    antes <- as.character(dt[[cc]][linhas])
    limpar <- !monitora_correcao_vazio_vec(antes)
    if (any(limpar, na.rm = TRUE)) {
      depois <- antes
      depois[limpar] <- NA_character_
      data.table::set(dt, i = linhas[limpar], j = cc, value = NA_character_)
      registrar(cc, linhas, antes, depois, "Limpeza atômica: foto/imagem histórica de outra forma de vida limpa por não integrar o XLSForm 21FEV25")
    }
  }

  ### 4) Reconstruir o campo superior a partir dos campos inferiores finais.
  if (!is.na(tipo_update) && tipo_update %in% names(dt)) {
    tipo_antes <- as.character(dt[[tipo_update]][linhas])
    n <- length(linhas)
    tipo_novo <- rep(NA_character_, n)
    append_vec <- function(cond, token) {
      cond[is.na(cond)] <- FALSE
      if (!any(cond)) return(invisible(NULL))
      tipo_novo[cond] <<- vapply(tipo_novo[cond], monitora_correcao_append_token_valor, character(1), token = token)
      invisible(NULL)
    }
    for (cat in c("nativa", "exotica", "seca_morta")) {
      cols_cat <- cols_info[classe == "lista_principal_forma_vida" & categoria == cat & coluna %in% names(dt), unique(coluna)]
      tem_cat <- rep(FALSE, n)
      for (cc in cols_cat) tem_cat <- tem_cat | !monitora_correcao_vazio_vec(dt[[cc]][linhas])
      append_vec(tem_cat, cat)
    }
    if (!is.na(forma_outros_col) && forma_outros_col %in% names(dt)) {
      append_vec(!monitora_correcao_vazio_vec(dt[[forma_outros_col]][linhas]), "outra_forma_vida")
    }
    for (tok in c("serrapilheira", "fragmentos_botanicos", "material_inundado", "material_botanico")) {
      append_vec(monitora_correcao_token_presente_vec(tipo_antes, tok), tok)
    }
    sem_categoria <- monitora_correcao_vazio_vec(tipo_novo)
    tipo_novo[sem_categoria] <- "solo_nu"
    data.table::set(dt, i = linhas, j = tipo_update, value = tipo_novo)
    registrar(tipo_update, linhas, tipo_antes, tipo_novo, "Limpeza atômica: campo superior de forma de vida recalculado após sanitização de outra forma de vida")
  } else {
    registrar_evento("tipo_forma_vida", linhas, rep(NA_character_, length(linhas)), rep(NA_character_, length(linhas)), "Campo superior tipo_forma_vida/Encostam não localizado para recálculo pós-sanitização", "falha_sem_tipo_forma_vida")
  }

  resumo_depois <- monitora_correcao_contar_residuos_outras_formas(dt, linhas, cols_info)
  n_pend <- sum(audit$status %in% c("falha_sem_campo_atual_forma_vida_outros", "falha_sem_tipo_forma_vida"), na.rm = TRUE)
  audit <- data.table::rbindlist(list(audit, data.table::data.table(
    id_correcao = id_correcao,
    ordem_operacao = NA_character_,
    status = ifelse(resumo_depois$linhas_com_residuo_total[1L] == 0L && n_pend == 0L, "auditoria_ok", "falha_residuo_pos_limpeza"),
    mensagem = paste0("Limpeza atômica outras formas: linhas_alvo=", length(linhas), "; residuos_antes=", resumo_antes$linhas_com_residuo_total[1L], "; residuos_depois=", resumo_depois$linhas_com_residuo_total[1L], "; pendencias_manuais=", n_pend, "; regra_solo_nu_pos_recalculo=ativa"),
    atributo = "__limpar_outras_formas_vida__",
    linha_indice = NA_integer_,
    valor_antes = as.character(resumo_antes$linhas_com_residuo_total[1L]),
    valor_depois = as.character(resumo_depois$linhas_com_residuo_total[1L]),
    arquivo_correcao = arquivo_correcao
  )), fill = TRUE, use.names = TRUE)
  list(audit = audit[], linhas = unique(afetacoes$linha_indice), afetacoes = afetacoes[], falha = any(grepl("^falha", as.character(audit$status))))
}

monitora_correcao_eh_operacao_limpeza_outras_formas <- function(corr) {
  corr <- data.table::as.data.table(corr)
  acao <- if ("acao" %in% names(corr)) tolower(trimws(as.character(corr$acao))) else rep("", nrow(corr))
  tipo <- if ("tipo_correcao" %in% names(corr)) tolower(trimws(as.character(corr$tipo_correcao))) else rep("", nrow(corr))
  acao %in% c("limpar_outras_formas_vida", "limpeza_outras_formas_vida_atomica") |
    tipo %in% c("triagem_limpeza_outras_formas_vida_atomica", "limpeza_outras_formas_vida_atomica")
}


### v2.6.1: contagem semântica global e aplicação vetorizada de operações
### -------------------------------------------------------------------------
### A fila do painel pode conter muitos itens auditáveis para uma única decisão
### do bolsista. As funções abaixo mantêm a rastreabilidade por item, mas aplicam
### a alteração por grupo semântico, evitando o gargalo observado quando 424
### itens auditáveis foram tratados como 424 operações.
monitora_correcao_contar_operacoes_semanticas <- function(correcoes) {
  if (is.null(correcoes)) return(0L)
  cc <- data.table::as.data.table(correcoes)
  if (!nrow(cc)) return(0L)
  if (!("id_correcao" %in% names(cc))) return(nrow(cc))
  ids <- trimws(as.character(cc$id_correcao))
  ids[is.na(ids) | !nzchar(ids)] <- paste0("__linha_", which(is.na(ids) | !nzchar(ids)))
  as.integer(data.table::uniqueN(ids))
}

monitora_correcao_eh_operacao_pendencia_sem_forma <- function(corr) {
  corr <- data.table::as.data.table(corr)
  tipo <- if ("tipo_correcao" %in% names(corr)) tolower(trimws(as.character(corr$tipo_correcao))) else rep("", nrow(corr))
  id <- if ("id_correcao" %in% names(corr)) toupper(trimws(as.character(corr$id_correcao))) else rep("", nrow(corr))
  esc <- if ("escopo_contextual_painel" %in% names(corr)) tolower(trimws(as.character(corr$escopo_contextual_painel))) else rep("", nrow(corr))
  tipo %in% c("pendencia_sem_forma_vida_lote", "pendencia_sem_forma_vida") |
    grepl("^PENDFV", id) |
    esc %in% c("linhas_pendentes_ocorrencia_diagnostica", "linhas_pendentes_ocorrencia")
}

monitora_correcao_primeiro_valor <- function(x) {
  x <- as.character(x)
  x <- x[!is.na(x) & nzchar(trimws(x))]
  if (!length(x)) return(NA_character_)
  x[1L]
}

monitora_correcao_inferir_categoria_pendfv <- function(grupo, atributo = NA_character_) {
  g <- data.table::as.data.table(grupo)
  vals <- character(0)
  for (cc in intersect(c("categoria_destino", "categoria_origem", "tipo_triagem", "ocorrencia_diagnostica_contextual"), names(g))) vals <- c(vals, as.character(g[[cc]]))
  vals <- c(vals, as.character(atributo))
  txt <- tolower(paste(vals, collapse = " "))
  if (grepl("seca_morta|seca.*morta|morta", txt, perl = TRUE)) return("seca_morta")
  if (grepl("exotic|exotica|exotico", txt, perl = TRUE)) return("exotica")
  if (grepl("nativ", txt, perl = TRUE)) return("nativa")
  NA_character_
}

monitora_correcao_linhas_pendfv_grupo <- function(dt, grupo, col, chaves = monitora_correcao_colunas_chave(dt)) {
  dt <- data.table::as.data.table(dt)
  grupo <- data.table::as.data.table(grupo)
  idx <- integer(0)
  if (!is.na(chaves$uuid_registro) && chaves$uuid_registro %in% names(dt) && "uuid_registro" %in% names(grupo)) {
    uu <- unique(trimws(as.character(grupo$uuid_registro)))
    uu <- uu[!is.na(uu) & nzchar(uu)]
    if (length(uu)) idx <- which(trimws(as.character(dt[[chaves$uuid_registro]])) %chin% uu)
  }
  ### v2.6.1 motor único: PENDFV também é ocorrência diagnóstica por linha.
  ### Se o painel gravou linha_indice/linhas_alvo_serializadas, essas linhas são
  ### preferidas ao escopo amplo de COLETAS. COLETA é apenas fallback legado.
  if (!length(idx)) {
    li_vals <- character(0)
    for (cc_li in intersect(c("linhas_alvo_serializadas", "linha_indice"), names(grupo))) {
      li_vals <- c(li_vals, unlist(lapply(as.character(grupo[[cc_li]]), monitora_correcao_parse_serial_generico), use.names = FALSE))
    }
    li <- suppressWarnings(as.integer(li_vals))
    li <- unique(li[!is.na(li) & li >= 1L & li <= nrow(dt)])
    if (length(li)) idx <- li
  }
  if (!length(idx) && !is.na(chaves$coleta) && chaves$coleta %in% names(dt) && "coleta" %in% names(grupo)) {
    coletas <- unique(unlist(lapply(as.character(grupo$coleta), monitora_correcao_parse_lista_serializada), use.names = FALSE))
    coletas <- coletas[!is.na(coletas) & nzchar(coletas)]
    if (length(coletas)) idx <- which(as.character(dt[[chaves$coleta]]) %chin% coletas)
    if (length(idx) && !is.na(chaves$ponto_amostral) && chaves$ponto_amostral %in% names(dt) && "ponto_amostral" %in% names(grupo)) {
      pontos <- unique(trimws(as.character(grupo$ponto_amostral)))
      pontos <- pontos[!is.na(pontos) & nzchar(pontos)]
      if (length(pontos)) idx <- idx[trimws(as.character(dt[[chaves$ponto_amostral]][idx])) %chin% pontos]
    }
  }
  idx <- unique(as.integer(idx))
  idx <- idx[!is.na(idx) & idx >= 1L & idx <= nrow(dt)]
  if (!length(idx) || is.na(col) || !(col %in% names(dt))) return(integer(0))
  categoria <- monitora_correcao_inferir_categoria_pendfv(grupo, col)
  vazio_destino <- monitora_correcao_vazio_vec(dt[[col]][idx])
  if (!is.na(categoria) && nzchar(categoria) && !is.na(chaves$tipo_forma_vida) && chaves$tipo_forma_vida %in% names(dt)) {
    tem_cat <- monitora_correcao_contem_qualquer_token_vec(dt[[chaves$tipo_forma_vida]][idx], categoria)
  } else {
    tem_cat <- rep(TRUE, length(idx))
  }
  idx[tem_cat & vazio_destino]
}

monitora_correcao_aplicar_pendencias_sem_forma_atomicas <- function(dt, corr, chaves = monitora_correcao_colunas_chave(dt), arquivo_correcao = NA_character_, dicionario = NULL, silencioso = FALSE, registrar_perf = TRUE) {
  dt <- monitora_dt_referenciar(dt)
  corr <- data.table::copy(data.table::as.data.table(corr))
  if (!nrow(corr)) return(list(dt = dt, corr = corr, audit = data.table::data.table(), linhas = integer(), afetacoes = data.table::data.table(linha_indice = integer(), atributo = character()), falha = FALSE, n_grupos = 0L))
  idx <- which(monitora_correcao_eh_operacao_pendencia_sem_forma(corr))
  if (!length(idx)) return(list(dt = dt, corr = corr, audit = data.table::data.table(), linhas = integer(), afetacoes = data.table::data.table(linha_indice = integer(), atributo = character()), falha = FALSE, n_grupos = 0L))
  if (!("id_correcao" %in% names(corr))) corr[, id_correcao := NA_character_]
  corr[, .grupo_pendfv_atom := data.table::fifelse(!is.na(id_correcao) & nzchar(as.character(id_correcao)), as.character(id_correcao), paste0("__linha_", seq_len(.N)))]
  grupos <- unique(corr[idx, .grupo_pendfv_atom])
  audit <- data.table::data.table()
  afetacoes <- data.table::data.table(linha_indice = integer(), atributo = character())
  linhas_total <- integer(0)
  falha <- FALSE
  n_total <- length(grupos)
  for (gg in seq_along(grupos)) {
    gid <- grupos[gg]
    grupo <- corr[.grupo_pendfv_atom == gid]
    attr_raw <- monitora_correcao_primeiro_valor(if ("atributo_coluna_registros_corrig" %in% names(grupo)) grupo$atributo_coluna_registros_corrig else NA_character_)
    col <- tryCatch(monitora_correcao_resolver_coluna(dt, attr_raw, dicionario), error = function(e) NA_character_)
    acao <- monitora_correcao_acao_normalizar(monitora_correcao_primeiro_valor(if ("acao" %in% names(grupo)) grupo$acao else "append_token"))
    valor <- monitora_correcao_primeiro_valor(if ("valor_novo" %in% names(grupo)) grupo$valor_novo else NA_character_)
    id_cor <- monitora_correcao_primeiro_valor(grupo$id_correcao)
    if (!isTRUE(silencioso) && exists("monitora_correcao_console_msg", mode = "function")) monitora_correcao_console_msg("Aplicando operação semântica PENDFV ", gg, "/", n_total, ": atributo=", attr_raw, "; token=", valor, ".")
    linhas <- monitora_correcao_linhas_pendfv_grupo(dt, grupo, col, chaves)
    if (is.na(col) || !(col %in% names(dt))) {
      falha <- TRUE
      audit <- data.table::rbindlist(list(audit, data.table::data.table(id_correcao = id_cor, ordem_operacao = NA_character_, status = "falha_coluna_pendencia_sem_forma", mensagem = paste0("Coluna de forma de vida não localizada para operação contextual: ", attr_raw), atributo = attr_raw, linha_indice = NA_integer_, valor_antes = NA_character_, valor_depois = NA_character_, arquivo_correcao = arquivo_correcao)), fill = TRUE, use.names = TRUE)
      next
    }
    if (!length(linhas)) {
      audit <- data.table::rbindlist(list(audit, data.table::data.table(id_correcao = id_cor, ordem_operacao = NA_character_, status = "ok_sem_linhas_pendentes", mensagem = "Operação contextual sem efeito: nenhuma linha pendente sem forma permaneceu no estado corrente", atributo = col, linha_indice = NA_integer_, valor_antes = NA_character_, valor_depois = NA_character_, arquivo_correcao = arquivo_correcao)), fill = TRUE, use.names = TRUE)
      next
    }
    antes <- as.character(dt[[col]][linhas])
    novo <- monitora_correcao_aplicar_operacao(antes, acao, valor, NA_character_)
    mudou <- monitora_correcao_na_para_vazio(antes) != monitora_correcao_na_para_vazio(novo)
    if (any(mudou, na.rm = TRUE)) {
      data.table::set(dt, i = linhas[mudou], j = col, value = novo[mudou])
      linhas_mudou <- linhas[mudou]
      linhas_total <- unique(c(linhas_total, linhas_mudou))
      afetacoes <- data.table::rbindlist(list(afetacoes, data.table::data.table(linha_indice = linhas_mudou, atributo = col)), fill = TRUE, use.names = TRUE)
      audit <- data.table::rbindlist(list(audit, data.table::data.table(id_correcao = id_cor, ordem_operacao = NA_character_, status = "aplicada", mensagem = paste0("Correção contextual vetorizada de pendência sem forma: ", length(linhas_mudou), " linha(s) alterada(s) em uma operação semântica"), atributo = col, linha_indice = linhas_mudou, valor_antes = antes[mudou], valor_depois = novo[mudou], arquivo_correcao = arquivo_correcao)), fill = TRUE, use.names = TRUE)
    } else {
      audit <- data.table::rbindlist(list(audit, data.table::data.table(id_correcao = id_cor, ordem_operacao = NA_character_, status = "ignorada_sem_alteracao", mensagem = "Operação contextual sem efeito: valores finais já correspondiam ao token solicitado", atributo = col, linha_indice = linhas, valor_antes = antes, valor_depois = novo, arquivo_correcao = arquivo_correcao)), fill = TRUE, use.names = TRUE)
    }
    if (isTRUE(registrar_perf) && exists("monitora_perf_registrar_checkpoint", mode = "function")) {
      try(monitora_perf_registrar_checkpoint(paste0("painel_correcoes_pendfv_", gg, "_de_", n_total), paste0("operação contextual PENDFV ", gg, "/", n_total, " aplicada"), dt), silent = TRUE)
    }
  }
  corr_out <- corr[!(.grupo_pendfv_atom %in% grupos)]
  corr_out[, .grupo_pendfv_atom := NULL]
  corr[, .grupo_pendfv_atom := NULL]
  list(dt = dt[], corr = corr_out[], audit = audit[], linhas = linhas_total, afetacoes = unique(afetacoes), falha = falha, n_grupos = length(grupos))
}

monitora_correcao_linhas_residuo_outras_formas <- function(dt, linhas, cols_info) {
  dt <- data.table::as.data.table(dt)
  linhas <- unique(as.integer(linhas)); linhas <- linhas[!is.na(linhas) & linhas >= 1L & linhas <= nrow(dt)]
  if (!length(linhas)) return(integer(0))
  tokens_outra <- monitora_correcao_tokens_residuo_historico_outras_formas()
  listas <- cols_info[classe == "lista_principal_forma_vida" & coluna %in% names(dt), coluna]
  descritores <- cols_info[classe == "descritor_outra_forma_vida" & coluna %in% names(dt), coluna]
  fotos <- cols_info[classe == "foto_outra_forma_vida" & coluna %in% names(dt), coluna]
  flag <- rep(FALSE, length(linhas))
  for (cc in listas) flag <- flag | monitora_correcao_contem_qualquer_token_vec(dt[[cc]][linhas], tokens_outra)
  for (cc in descritores) flag <- flag | !monitora_correcao_vazio_vec(dt[[cc]][linhas])
  for (cc in fotos) flag <- flag | !monitora_correcao_vazio_vec(dt[[cc]][linhas])
  linhas[flag]
}

monitora_correcao_linhas_escopo_operacao_outras_estado_corrente <- function(dt, grupo, chaves = monitora_correcao_colunas_chave(dt), indice = NULL) {
  dt <- data.table::as.data.table(dt)
  grupo <- data.table::as.data.table(grupo)

  ### v2.6.1: TRIOUT atômico e vetorizado, com COLETA como filtro
  ### operacional estável. A operação de limpeza de outras formas não deve
  ### depender de linha_indice depois que outras operações podem deslocar o
  ### data.table, nem precisa expandir uma aplicação por item. O fluxo seguro é:
  ### 1) resolver o universo corrente por COLETA/chaves estáveis do próprio
  ###    grupo TRIOUT;
  ### 2) dentro desse universo, o aplicador vetorizado atua somente nas linhas
  ###    que ainda tenham resíduo real de outra forma;
  ### 3) linha_indice/linhas_alvo_serializadas permanecem apenas como fallback
  ###    legado para arquivos antigos sem COLETA/contexto.
  parse_any <- function(cols) {
    vals <- character(0)
    for (cc in intersect(cols, names(grupo))) {
      vals <- c(vals, unlist(lapply(as.character(grupo[[cc]]), monitora_correcao_parse_serial_generico), use.names = FALSE))
    }
    vals <- unique(trimws(as.character(vals)))
    vals <- vals[!is.na(vals) & nzchar(vals) & !(toupper(vals) %in% c("NA", "NAN", "NULL"))]
    vals
  }

  idx_filtro <- seq_len(nrow(dt))
  tem_filtro_estavel <- FALSE

  coletas <- parse_any(c("coleta", "COLETA", "coletas"))
  if (length(coletas) && !is.na(chaves$coleta) && chaves$coleta %in% names(dt)) {
    idx_filtro <- idx_filtro[as.character(dt[[chaves$coleta]][idx_filtro]) %chin% coletas]
    tem_filtro_estavel <- TRUE
  }

  ### Ponto/metro só restringem quando a operação é inequivocamente de um único
  ### ponto. Em operações agrupadas, listas serializadas de pontos e metros não
  ### carregam pareamento seguro; usar interseção de vetores pode errar o alvo.
  pontos <- parse_any(c("ponto_amostral", "Ponto amostral", "ponto_amostral_serializado"))
  metros <- parse_any(c("ponto_metro", "Ponto metro", "ponto_metro_serializado"))
  if (length(coletas) <= 1L && length(pontos) == 1L && !is.na(chaves$ponto_amostral) && chaves$ponto_amostral %in% names(dt)) {
    idx_filtro <- idx_filtro[as.character(dt[[chaves$ponto_amostral]][idx_filtro]) %chin% pontos]
    tem_filtro_estavel <- TRUE
    if (length(metros) == 1L && !is.na(chaves$ponto_metro) && chaves$ponto_metro %in% names(dt)) {
      idx_filtro <- idx_filtro[as.character(dt[[chaves$ponto_metro]][idx_filtro]) %chin% metros]
    }
  }

  ### UUIDs continuam aceitos, mas apenas quando há UUID real. Não deixar o
  ### literal "NA" bloquear o fallback estável por COLETA.
  uuids <- parse_any(c("uuid_registro", "uuid_registro_serializado", "uuids_registro"))
  if (length(uuids) && !is.na(chaves$uuid_registro) && chaves$uuid_registro %in% names(dt)) {
    idx_uuid <- which(trimws(as.character(dt[[chaves$uuid_registro]])) %chin% uuids)
    idx_uuid <- as.integer(idx_uuid[!is.na(idx_uuid) & idx_uuid >= 1L & idx_uuid <= nrow(dt)])
    if (length(idx_uuid)) {
      if (isTRUE(tem_filtro_estavel)) idx_filtro <- intersect(idx_filtro, idx_uuid) else idx_filtro <- idx_uuid
      tem_filtro_estavel <- TRUE
    }
  }

  idx_filtro <- unique(as.integer(idx_filtro))
  idx_filtro <- idx_filtro[!is.na(idx_filtro) & idx_filtro >= 1L & idx_filtro <= nrow(dt)]
  if (isTRUE(tem_filtro_estavel) && length(idx_filtro)) return(idx_filtro)

  ### Fallback: aplicar resolução linha a linha antiga somente quando a operação
  ### não traz COLETA/contexto estável. Isso preserva compatibilidade com
  ### correcoes_campos legados, mas evita que posição antiga domine a run atual.
  idx <- unique(unlist(lapply(seq_len(nrow(grupo)), function(ii) monitora_correcao_localizar_linhas_limpeza_outras_formas(dt, grupo[ii], chaves, indice)), use.names = FALSE))
  idx <- as.integer(idx); idx <- idx[!is.na(idx) & idx >= 1L & idx <= nrow(dt)]
  if (length(idx)) return(unique(idx))

  integer(0)
}

monitora_correcao_aplicar_limpezas_outras_formas_estado_corrente <- function(dt, corr, chaves = monitora_correcao_colunas_chave(dt), indice = NULL, arquivo_correcao = NA_character_, dicionario = NULL, silencioso = FALSE, registrar_perf = TRUE) {
  dt <- monitora_dt_referenciar(dt)
  corr <- data.table::copy(data.table::as.data.table(corr))
  if (!nrow(corr)) return(list(dt = dt, corr = corr, audit = data.table::data.table(), linhas = integer(), afetacoes = data.table::data.table(linha_indice = integer(), atributo = character()), falha = FALSE, n_grupos = 0L))
  idx <- which(monitora_correcao_eh_operacao_limpeza_outras_formas(corr))
  if (!length(idx)) return(list(dt = dt, corr = corr, audit = data.table::data.table(), linhas = integer(), afetacoes = data.table::data.table(linha_indice = integer(), atributo = character()), falha = FALSE, n_grupos = 0L))
  if (!("id_correcao" %in% names(corr))) corr[, id_correcao := NA_character_]
  corr[, .grupo_triout_atom := data.table::fifelse(!is.na(id_correcao) & nzchar(as.character(id_correcao)), as.character(id_correcao), paste0("__linha_", seq_len(.N)))]
  grupos <- unique(corr[idx, .grupo_triout_atom])
  audit <- data.table::data.table()
  linhas_total <- integer(0)
  afetacoes <- data.table::data.table(linha_indice = integer(), atributo = character())
  falha <- FALSE
  cols_info <- monitora_correcao_colunas_limpeza_outras_formas(dt, dicionario)
  n_total <- length(grupos)
  for (gg in seq_along(grupos)) {
    gid <- grupos[gg]
    grupo <- corr[.grupo_triout_atom == gid]
    id_cor <- monitora_correcao_primeiro_valor(grupo$id_correcao)
    linhas_escopo <- monitora_correcao_linhas_escopo_operacao_outras_estado_corrente(dt, grupo, chaves, indice)
    linhas_residuo <- monitora_correcao_linhas_residuo_outras_formas(dt, linhas_escopo, cols_info)
    if (!isTRUE(silencioso) && exists("monitora_correcao_console_msg", mode = "function")) monitora_correcao_console_msg("Aplicando operação semântica TRIOUT ", gg, "/", n_total, ": escopo=", length(linhas_escopo), " linha(s); resíduos=", length(linhas_residuo), ".")
    if (!length(linhas_residuo)) {
      audit <- data.table::rbindlist(list(audit, data.table::data.table(id_correcao = id_cor, ordem_operacao = NA_character_, status = "ok_sem_residuo_no_estado_corrente", mensagem = paste0("Limpeza de outras formas sem ação: nenhum resíduo remanescente no estado corrente do escopo (", length(linhas_escopo), " linha(s))."), atributo = "__limpar_outras_formas_vida__", linha_indice = NA_integer_, valor_antes = NA_character_, valor_depois = NA_character_, arquivo_correcao = arquivo_correcao)), fill = TRUE, use.names = TRUE)
      next
    }
    res <- monitora_correcao_aplicar_limpeza_outras_formas_atomica(dt, linhas_residuo, id_correcao = id_cor, arquivo_correcao = arquivo_correcao, dicionario = dicionario)
    if (nrow(res$audit)) audit <- data.table::rbindlist(list(audit, res$audit), fill = TRUE, use.names = TRUE)
    if (length(res$linhas)) linhas_total <- unique(c(linhas_total, res$linhas))
    if (nrow(res$afetacoes)) afetacoes <- data.table::rbindlist(list(afetacoes, res$afetacoes), fill = TRUE, use.names = TRUE)
    linhas_residuo_pos <- monitora_correcao_linhas_residuo_outras_formas(dt, linhas_escopo, monitora_correcao_colunas_limpeza_outras_formas(dt, dicionario))
    if (length(linhas_residuo_pos)) {
      falha <- TRUE
      audit <- data.table::rbindlist(list(audit, data.table::data.table(id_correcao = id_cor, ordem_operacao = NA_character_, status = "falha_residuo_pos_limpeza_estado_corrente", mensagem = paste0("Limpeza de outras formas deixou ", length(linhas_residuo_pos), " linha(s) com resíduo no estado corrente."), atributo = "__limpar_outras_formas_vida__", linha_indice = linhas_residuo_pos, valor_antes = NA_character_, valor_depois = NA_character_, arquivo_correcao = arquivo_correcao)), fill = TRUE, use.names = TRUE)
    }
    if (isTRUE(registrar_perf) && exists("monitora_perf_registrar_checkpoint", mode = "function")) {
      try(monitora_perf_registrar_checkpoint(paste0("painel_correcoes_triout_", gg, "_de_", n_total), paste0("operação TRIOUT ", gg, "/", n_total, " aplicada no estado corrente"), dt), silent = TRUE)
    }
  }
  corr_out <- corr[!(.grupo_triout_atom %in% grupos)]
  corr_out[, .grupo_triout_atom := NULL]
  corr[, .grupo_triout_atom := NULL]
  list(dt = dt[], corr = corr_out[], audit = audit[], linhas = linhas_total, afetacoes = unique(afetacoes), falha = falha, n_grupos = length(grupos))
}


monitora_correcao_auditar_persistencia_limpeza_outras_formas <- function(dt,
                                                                         arquivo_correcao = MONITORA_ARQUIVO_CORRECOES_CAMPOS,
                                                                         dicionario = NULL,
                                                                         contexto = "persistencia_limpeza_outras_formas",
                                                                         abortar = TRUE) {
  if (!file.exists(arquivo_correcao)) return(invisible(data.table::data.table()))
  dt <- monitora_dt_referenciar(dt)
  corr <- tryCatch(
    data.table::fread(arquivo_correcao, encoding = "UTF-8", na.strings = c("", "NA"), colClasses = "character"),
    error = function(e) data.table::data.table()
  )
  if (nrow(corr) == 0L) return(invisible(data.table::data.table()))
  template <- monitora_correcao_template()
  for (cc in setdiff(names(template), names(corr))) corr[, (cc) := NA_character_]
  data.table::setDT(corr)
  idx_limpeza <- which(monitora_correcao_eh_operacao_limpeza_outras_formas(corr))
  if (!length(idx_limpeza)) return(invisible(data.table::data.table()))

  chaves <- monitora_correcao_colunas_chave(dt)
  indice_linhas <- monitora_correcao_criar_indice_linhas(dt, chaves)
  linhas <- unique(unlist(lapply(idx_limpeza, function(ii) {
    monitora_correcao_localizar_linhas_limpeza_outras_formas(dt, corr[ii], chaves, indice_linhas)
  }), use.names = FALSE))
  linhas <- as.integer(linhas)
  linhas <- linhas[!is.na(linhas) & linhas >= 1L & linhas <= nrow(dt)]

  cols_info <- monitora_correcao_colunas_limpeza_outras_formas(dt, dicionario)
  resumo <- monitora_correcao_contar_residuos_outras_formas(dt, linhas, cols_info)
  resumo[, `:=`(
    contexto = contexto,
    n_operacoes_limpeza = length(idx_limpeza),
    n_linhas_escopo = length(linhas),
    n_colunas_lista_principal = cols_info[classe == "lista_principal_forma_vida", uniqueN(coluna)],
    n_colunas_descritor_outra = cols_info[classe == "descritor_outra_forma_vida", uniqueN(coluna)],
    arquivo_correcao = arquivo_correcao
  )]

  arq_ult <- file.path(MONITORA_CORRECOES_DIR, paste0("auditoria_persistencia_limpeza_outras_formas_", contexto, "_ultima_execucao.csv"))
  arq_log <- file.path(MONITORA_LOG_DIR, paste0("auditoria_persistencia_limpeza_outras_formas_", contexto, "_", MONITORA_EXEC_ID, ".csv"))
  monitora_fwrite(resumo, arq_ult, na = "")
  monitora_fwrite(resumo, arq_log, na = "")

  msg <- paste0(
    "Persistência limpeza outras formas [", contexto, "]: linhas_escopo=", length(linhas),
    "; residuos=", resumo$linhas_com_residuo_total[1L],
    "; tokens=", resumo$celulas_com_token_outra[1L],
    "; descritores=", resumo$celulas_com_descritor[1L]
  )
  monitora_log_registrar_evento(
    "limpeza_outras_formas_persistencia",
    ifelse(resumo$linhas_com_residuo_total[1L] > 0L, "ERRO", "INFO"),
    arq_ult,
    msg,
    "auditoria obrigatória após aplicação atômica e antes da exportação final"
  )
  if (exists("monitora_correcao_console_msg", mode = "function")) monitora_correcao_console_msg(msg)

  if (isTRUE(abortar) && resumo$linhas_com_residuo_total[1L] > 0L) {
    stop(paste0(
      "Falha de persistência na limpeza atômica de outra(s) forma(s) de vida [", contexto, "]: ",
      resumo$linhas_com_residuo_total[1L], " linha(s) ainda com resíduo no escopo limpo. Ver ", arq_ult
    ), call. = FALSE)
  }
  invisible(resumo[])
}



monitora_correcao_acao_normalizar <- function(acao) {
  acao <- tolower(trimws(as.character(acao)[1L]))
  if (is.na(acao)) acao <- ""
  data.table::fcase(
    acao %in% c("update", "substituir_valor"), "update",
    acao %in% c("clear", "limpar", "limpar_valor"), "clear",
    acao %in% c("append_token", "adicionar_token"), "append_token",
    acao %in% c("remove_token", "remover_token"), "remove_token",
    acao %in% c("replace_token", "substituir_token"), "replace_token",
    acao %in% c("recalcular_tipo_forma_vida", "atualizar_tipo_forma_vida"), "recalcular_tipo_forma_vida",
    default = acao
  )
}

monitora_correcao_acoes_rotulos <- function() {
  c(
    "Substituir valor" = "update",
    "Limpar valor" = "clear",
    "Adicionar token" = "append_token",
    "Remover token" = "remove_token",
    "Substituir token" = "replace_token",
    "Recalcular Encostam/tipo_forma_vida" = "recalcular_tipo_forma_vida"
  )
}

monitora_correcao_split_serial <- function(x) {
  x <- as.character(x)[1L]
  if (is.na(x) || !nzchar(trimws(x))) return(character(0))
  unique(strsplit(x, "\\s*;\\s*", perl = TRUE)[[1]])
}

monitora_correcao_serializar_acoes <- function(x) {
  x <- unique(as.character(x))
  x <- x[!is.na(x) & nzchar(trimws(x))]
  paste(x, collapse = ";")
}

monitora_correcao_xlsform_meta_atual <- function(meta_xls = NULL) {
  if (!is.null(meta_xls) && is.list(meta_xls)) return(meta_xls)
  if (exists("MONITORA_META_XLSFORMS_CORRECOES", inherits = TRUE)) {
    meta <- get("MONITORA_META_XLSFORMS_CORRECOES", inherits = TRUE)
    if (is.list(meta)) return(meta)
  }
  if (exists("monitora_correcao_xlsforms_embutidos", mode = "function")) return(monitora_correcao_xlsforms_embutidos_cache_publicacao_ae())
  list(campos = data.table::data.table(), opcoes = data.table::data.table(), dependencias = data.table::data.table())
}

monitora_correcao_ultima_versao_xlsform <- function(campos) {
  campos <- data.table::as.data.table(campos)
  if (!nrow(campos) || !("arquivo_xlsform" %in% names(campos))) return(NA_character_)
  arqs <- unique(as.character(campos$arquivo_xlsform))
  arqs <- arqs[!is.na(arqs) & nzchar(arqs)]
  if (!length(arqs)) return(NA_character_)
  hit_21 <- arqs[grepl("21FEV25", arqs, ignore.case = TRUE)]
  if (length(hit_21)) return(hit_21[1L])
  arqs[order(arqs, decreasing = TRUE)][1L]
}

monitora_correcao_choices_xlsform <- function(list_name, meta_xls = NULL, preferir_ultima = TRUE) {
  list_name <- as.character(list_name)[1L]
  if (is.na(list_name) || !nzchar(trimws(list_name))) return(character(0))
  meta <- monitora_correcao_xlsform_meta_atual(meta_xls)
  op <- if (!is.null(meta$opcoes)) data.table::as.data.table(meta$opcoes) else data.table::data.table()
  if (!nrow(op)) return(character(0))
  for (cc in c("arquivo_xlsform", "list_name", "name")) if (!(cc %in% names(op))) op[, (cc) := NA_character_]
  lista_alvo <- list_name
  op <- op[list_name == lista_alvo & !is.na(name) & nzchar(as.character(name))]
  if (!nrow(op)) return(character(0))
  if (isTRUE(preferir_ultima)) {
    arq <- monitora_correcao_ultima_versao_xlsform(op)
    if (!is.na(arq) && nzchar(arq)) {
      op2 <- op[arquivo_xlsform == arq]
      if (nrow(op2)) op <- op2
    }
  }
  choices <- unique(as.character(op$name))
  choices <- choices[!is.na(choices) & nzchar(trimws(choices))]
  if (length(choices) <= 2L && all(choices %in% c("num_key", "label"))) return(character(0))
  choices
}

monitora_correcao_tokens_valor <- function(valor) {
  valor <- as.character(valor)[1L]
  if (is.na(valor) || !nzchar(trimws(valor))) return(character(0))
  toks <- unlist(strsplit(gsub("[|;,]+", " ", valor, perl = TRUE), "\\s+", perl = TRUE), use.names = FALSE)
  unique(toks[!is.na(toks) & nzchar(trimws(toks))])
}

monitora_correcao_tipo_campo_inferir <- function(col, papel, tipo_xls = NA_character_, tipo_inferido = NA_character_, list_name = NA_character_, chaves = NULL) {
  col <- as.character(col)[1L]
  papel <- as.character(papel)[1L]
  tipo_xls <- as.character(tipo_xls)[1L]
  tipo_inferido <- as.character(tipo_inferido)[1L]
  list_name <- as.character(list_name)[1L]
  base <- NA_character_
  if (!is.na(tipo_xls) && nzchar(trimws(tipo_xls))) base <- monitora_correcao_tipo_xlsform(tipo_xls)$tipo_base[1L]
  if (is.na(base) || !nzchar(base)) {
    ti <- tolower(trimws(tipo_inferido))
    if (grepl("select_multiple", ti)) base <- "select_multiple"
    else if (grepl("select_one", ti)) base <- "select_one"
    else if (grepl("decimal", ti)) base <- "decimal"
    else if (grepl("inteiro|integer", ti)) base <- "integer"
    else if (grepl("hora|time", ti)) base <- "time"
    else if (grepl("data|date", ti)) base <- "date"
    else if (grepl("uuid", ti)) base <- "uuid"
    else base <- "text"
  }
  cn <- monitora_correcao_normalizar_nome_coluna(col)
  if (!is.null(chaves) && !is.na(chaves$data_hora) && identical(col, chaves$data_hora)) base <- "date"
  if (cn %in% c("data_data_hora", "data_hora_data") || grepl("(^|_)data(_|$).*hora|data_hora", cn)) base <- "date"
  if (grepl("hora", cn) && !grepl("data", cn)) base <- "time"
  if (identical(papel, "campo_superior_tipo_forma_vida")) base <- "select_multiple"
  if (identical(papel, "lista_principal_forma_vida")) base <- "select_multiple"
  if (identical(papel, "atributo_dependente_habito") && (is.na(list_name) || !nzchar(list_name))) base <- "select_one"
  base
}


