monitora_painel_admin_harmonizar_colunas <- function(d) {
  if (is.null(d)) return(data.table::data.table())
  d <- data.table::as.data.table(d)
  cols_texto <- intersect(monitora_painel_admin_colunas_texto(), names(d))
  for (cc in cols_texto) {
    if (!is.character(d[[cc]])) data.table::set(d, j = cc, value = as.character(d[[cc]]))
  }
  for (cc in intersect(c("atende_template_sismonitora", "required_bool", "painel_template_2025_editavel", "protegido", "painel_editavel"), names(d))) {
    if (!is.logical(d[[cc]])) data.table::set(d, j = cc, value = as.logical(d[[cc]]))
  }
  for (cc in intersect(c("ordem_template_sismonitora"), names(d))) {
    if (!is.integer(d[[cc]])) data.table::set(d, j = cc, value = as.integer(d[[cc]]))
  }
  d[]
}

monitora_painel_admin_controlados_aplicar_contrato <- function(d) {
  if (is.null(d)) d <- data.table::data.table()
  d <- data.table::as.data.table(d)
  admin <- monitora_painel_admin_controlados_sismonitora_2025()
  admin <- admin[
    vapply(atributo_coluna_registros_corrig, monitora_painel_atributo_editavel_sismonitora_2025, logical(1))
  ]
  admin <- monitora_painel_admin_harmonizar_colunas(admin)
  if (!nrow(admin)) return(d)

  for (cc in setdiff(names(admin), names(d))) {
    if (cc %in% monitora_painel_admin_colunas_texto()) {
      d[, (cc) := NA_character_]
    } else if (cc %in% c("atende_template_sismonitora", "required_bool", "painel_template_2025_editavel", "protegido", "painel_editavel")) {
      d[, (cc) := NA]
      data.table::set(d, j = cc, value = as.logical(d[[cc]]))
    } else if (cc %in% c("ordem_template_sismonitora")) {
      d[, (cc) := NA_integer_]
    } else {
      d[, (cc) := NA_character_]
    }
  }
  for (cc in setdiff(names(d), names(admin))) admin[, (cc) := NA_character_]
  d <- monitora_painel_admin_harmonizar_colunas(d)
  admin <- monitora_painel_admin_harmonizar_colunas(admin)

  faltam <- setdiff(as.character(admin$atributo_coluna_registros_corrig), as.character(d$atributo_coluna_registros_corrig))
  if (length(faltam)) {
    d <- data.table::rbindlist(list(d, admin[atributo_coluna_registros_corrig %in% faltam]), fill = TRUE, use.names = TRUE)
    d <- monitora_painel_admin_harmonizar_colunas(d)
  }
  for (ii in seq_len(nrow(admin))) {
    cc_admin <- admin$atributo_coluna_registros_corrig[ii]
    jj <- which(as.character(d$atributo_coluna_registros_corrig) == cc_admin)
    if (!length(jj)) next
    jj <- jj[1L]
    for (nm in names(admin)) {
      if (!(nm %in% names(d))) next
      valor_admin <- admin[[nm]][ii]
      ## Preservar o tipo da coluna já existente em d para evitar coerções
      ## silenciosas/logicamente erradas ao sobrepor metadados sintéticos.
      if (is.integer(d[[nm]])) {
        valor_admin <- suppressWarnings(as.integer(valor_admin))
      } else if (is.numeric(d[[nm]])) {
        valor_admin <- suppressWarnings(as.numeric(valor_admin))
      } else if (is.logical(d[[nm]])) {
        valor_admin <- suppressWarnings(as.logical(valor_admin))
      } else if (is.character(d[[nm]])) {
        valor_admin <- as.character(valor_admin)
      }
      data.table::set(d, i = jj, j = nm, value = valor_admin)
    }
  }
  monitora_painel_admin_harmonizar_colunas(d)
}

monitora_painel_normalizar_atributo_template_sismonitora_2025 <- function(x) {
  x <- trimws(tolower(as.character(x)))
  x[is.na(x)] <- ""
  x <- gsub("\\", "/", x, fixed = TRUE)
  x <- gsub("/+", "/", x, perl = TRUE)
  x
}

monitora_painel_atributo_editavel_sismonitora_2025 <- function(x) {
  x <- as.character(x)
  edit <- monitora_painel_normalizar_atributo_template_sismonitora_2025(monitora_painel_atributos_editaveis_sismonitora_2025())
  out <- rep(FALSE, length(x))
  for (ii in seq_along(x)) {
    xx <- x[ii]
    if (is.na(xx) || !nzchar(trimws(xx))) next
    partes <- unique(trimws(unlist(strsplit(as.character(xx), "[|;]", perl = TRUE), use.names = FALSE)))
    partes <- partes[!is.na(partes) & nzchar(partes)]
    cand <- monitora_painel_normalizar_atributo_template_sismonitora_2025(partes)
    cand <- unique(c(cand, monitora_correcao_normalizar_nome_coluna(partes)))
    out[ii] <- any(cand %in% edit)
  }
  out
}

monitora_painel_atributo_template_por_coluna_sismonitora_2025 <- function(col) {
  z <- monitora_correcao_normalizar_nome_coluna(col)
  tpl <- monitora_painel_template_sismonitora_2025()
  tpl[, atributo_norm := monitora_correcao_normalizar_nome_coluna(atributo)]
  hit <- tpl[atributo_norm %in% z | basename(atributo) %in% col | atributo %in% col]
  if (nrow(hit)) return(as.character(hit$atributo[1L]))
  NA_character_
}


monitora_correcao_aliases_admin_sismonitora <- function(col) {
  z <- monitora_correcao_normalizar_nome_coluna(as.character(col)[1L])
  if (is.na(z) || !nzchar(z)) return(character(0))
  mapa <- list(
    uc = c("uc", "UC"),
    ea = c("ea", "EA", "estacao_amostral", "Estação Amostral", "estacao amostral"),
    ua = c("ua", "UA", "unidade_amostral", "Unidade Amostral", "unidade amostral"),
    ciclo = c("ciclo", "CICLO", "Ciclo"),
    campanha = c("campanha", "CAMPANHA", "Campanha"),
    validado = c("validado", "VALIDADO", "Validado"),
    validador = c("validador", "VALIDADOR", "Validador"),
    data_validacao = c("data_validacao", "DATA_VALIDACAO", "Data da validação", "data da validacao", "data validacao"),
    obs_validacao = c("obs_validacao", "OBS_VALIDACAO", "Observações da validação", "observacoes da validacao", "obs validacao")
  )
  alvo <- NULL
  for (nm in names(mapa)) {
    cand_norm <- monitora_correcao_normalizar_nome_coluna(c(nm, mapa[[nm]]))
    if (z %in% cand_norm) { alvo <- nm; break }
  }
  if (is.null(alvo)) return(character(0))
  unique(c(alvo, mapa[[alvo]]))
}

monitora_correcao_coluna_real_admin_sismonitora <- function(dt, col) {
  if (is.null(dt) || is.null(col) || is.na(col) || !nzchar(as.character(col)[1L])) return(NA_character_)
  nms <- names(dt)
  if (!length(nms)) return(NA_character_)
  aliases <- monitora_correcao_aliases_admin_sismonitora(col)
  if (!length(aliases)) return(NA_character_)
  aliases_norm <- monitora_correcao_normalizar_nome_coluna(aliases)
  nms_norm <- monitora_correcao_normalizar_nome_coluna(nms)
  idx <- which(nms %in% aliases | tolower(nms) %in% tolower(aliases) | nms_norm %in% aliases_norm)
  if (!length(idx)) return(NA_character_)
  ### Preferir a coluna real já preenchida na base carregada. Isso evita criar/usar
  ### uma coluna sintética vazia (ex.: ua) quando o registros_corrig atual traz o
  ### mesmo atributo com alias operacional (ex.: UA). Não insere valores reais no script.
  tem_valor <- vapply(idx, function(ii) {
    vals <- tryCatch(as.character(dt[[nms[ii]]]), error = function(e) character(0))
    vals <- vals[!is.na(vals) & nzchar(trimws(vals))]
    length(vals) > 0L
  }, logical(1))
  if (any(tem_valor)) return(nms[idx[which(tem_valor)[1L]]])
  nms[idx[1L]]
}

monitora_registros_corrig_contrato_mestre_2025 <- function() {
  ### Contrato mestre declarativo de registros_corrig. Esta função apenas monta
  ### metadados a partir do template 2025 e das listas de edição já versionadas;
  ### ela não altera painel, exportação nem materialização.
  if (!requireNamespace("data.table", quietly = TRUE)) {
    stop("Pacote data.table é obrigatório.", call. = FALSE)
  }

  normalizar <- function(x) {
    if (exists("monitora_correcao_normalizar_nome_coluna", mode = "function")) {
      return(monitora_correcao_normalizar_nome_coluna(x))
    }
    x <- trimws(tolower(as.character(x)))
    x[is.na(x)] <- ""
    x <- iconv(x, from = "", to = "ASCII//TRANSLIT")
    x[is.na(x)] <- ""
    gsub("[^a-z0-9]+", "_", x, perl = TRUE)
  }
  colapsar <- function(x) {
    x <- unique(trimws(as.character(x)))
    x <- x[!is.na(x) & nzchar(x)]
    paste(x, collapse = "|")
  }

  tpl <- data.table::as.data.table(monitora_painel_template_sismonitora_2025())
  editaveis <- as.character(monitora_painel_atributos_editaveis_sismonitora_2025())
  edit_norm <- unique(normalizar(editaveis))
  bloqueados <- if (exists("monitora_painel_atributos_bloqueados_sismonitora_2025", mode = "function")) {
    as.character(monitora_painel_atributos_bloqueados_sismonitora_2025())
  } else {
    character(0)
  }
  bloqueados_norm <- unique(normalizar(bloqueados))

  admin <- if (exists("monitora_painel_admin_controlados_sismonitora_2025", mode = "function")) {
    tryCatch(data.table::as.data.table(monitora_painel_admin_controlados_sismonitora_2025()), error = function(e) data.table::data.table())
  } else {
    data.table::data.table()
  }
  if (!nrow(admin)) admin <- data.table::data.table(atributo_coluna_registros_corrig = character())
  for (cc in c("atributo_coluna_registros_corrig", "xlsform_tipo", "xlsform_tipo_base", "xlsform_list_name", "acoes_permitidas")) {
    if (!(cc %in% names(admin))) admin[, (cc) := NA_character_]
  }
  admin[, atributo_norm := normalizar(atributo_coluna_registros_corrig)]

  tipo_parse <- function(tipo, list_name = "") {
    tipo <- as.character(tipo)[1L]
    list_name <- as.character(list_name)[1L]
    if (is.na(tipo)) tipo <- ""
    if (is.na(list_name)) list_name <- ""
    out <- tryCatch(
      if (exists("monitora_correcao_tipo_xlsform", mode = "function")) monitora_correcao_tipo_xlsform(tipo) else NULL,
      error = function(e) NULL
    )
    if (is.data.frame(out) && nrow(out)) {
      base <- as.character(out$tipo_base[1L])
      lista <- as.character(out$list_name[1L])
    } else {
      tipo_low <- tolower(trimws(tipo))
      base <- if (grepl("^select_multiple", tipo_low)) "select_multiple" else if (grepl("^select_one", tipo_low)) "select_one" else if (grepl("^calculate", tipo_low)) "calculate" else if (grepl("^hidden", tipo_low)) "hidden" else if (grepl("^date$", tipo_low)) "date" else if (grepl("^time$", tipo_low)) "time" else if (grepl("^decimal$", tipo_low)) "decimal" else if (grepl("^integer$", tipo_low)) "integer" else if (grepl("^geopoint$", tipo_low)) "geopoint" else if (grepl("^image$", tipo_low)) "image" else if (grepl("^metadata", tipo_low)) "metadata" else "text"
      lista <- sub("^select_(one|multiple)\\s+", "", tipo_low, perl = TRUE)
      if (identical(lista, tipo_low)) lista <- ""
    }
    if (is.na(base) || !nzchar(base)) base <- "text"
    if ((is.na(lista) || !nzchar(lista)) && nzchar(list_name)) lista <- list_name
    list(tipo_base = base, list_name = ifelse(is.na(lista), "", lista))
  }

  aliases_admin <- function(atributo) {
    aliases <- tryCatch(
      if (exists("monitora_correcao_aliases_admin_sismonitora", mode = "function")) monitora_correcao_aliases_admin_sismonitora(atributo) else character(0),
      error = function(e) character(0)
    )
    if (!length(aliases)) {
      z <- normalizar(atributo)
      aliases <- switch(
        z,
        uc = c("uc", "UC"),
        ea = c("ea", "EA", "estacao_amostral", "Estação Amostral", "estacao amostral"),
        ua = c("ua", "UA", "unidade_amostral", "Unidade Amostral", "unidade amostral"),
        ciclo = c("ciclo", "CICLO", "Ciclo"),
        campanha = c("campanha", "CAMPANHA", "Campanha"),
        character(0)
      )
    }
    unique(c(atributo, aliases))
  }

  linhas <- vector("list", nrow(tpl))
  for (ii in seq_len(nrow(tpl))) {
    att <- as.character(tpl$atributo[ii])
    att_norm <- normalizar(att)
    admin_hit <- admin[atributo_norm == att_norm]
    tipo <- as.character(tpl$tipo_template[ii])
    lista <- as.character(tpl$list_name_template[ii])
    if (nrow(admin_hit)) {
      if (!is.na(admin_hit$xlsform_tipo[1L]) && nzchar(admin_hit$xlsform_tipo[1L])) tipo <- admin_hit$xlsform_tipo[1L]
      if (!is.na(admin_hit$xlsform_list_name[1L]) && nzchar(admin_hit$xlsform_list_name[1L])) lista <- admin_hit$xlsform_list_name[1L]
    }
    tipo_info <- tipo_parse(tipo, lista)
    if (nrow(admin_hit) && !is.na(admin_hit$xlsform_tipo_base[1L]) && nzchar(admin_hit$xlsform_tipo_base[1L])) {
      tipo_info$tipo_base <- as.character(admin_hit$xlsform_tipo_base[1L])
    }
    excecao_calculate_editavel <- identical(att, "amostragem/num_placa_formatado")
    if (isTRUE(excecao_calculate_editavel)) {
      tipo_info$tipo_base <- "text"
      tipo_info$list_name <- ""
    }

    painel_101 <- att_norm %in% edit_norm
    protegido <- att_norm %in% bloqueados_norm ||
      isTRUE(tryCatch(exists("monitora_correcao_coluna_protegida", mode = "function") && any(monitora_correcao_coluna_protegida(att)), error = function(e) FALSE))
    editavel <- isTRUE(painel_101) && !isTRUE(protegido)
    obrig <- tolower(trimws(as.character(tpl$required_template[ii]))) %in% c("yes", "true", "1", "sim", "required")

    acao <- ""
    if (isTRUE(editavel)) {
      if (nrow(admin_hit) && !is.na(admin_hit$acoes_permitidas[1L]) && nzchar(admin_hit$acoes_permitidas[1L])) {
        acao <- as.character(admin_hit$acoes_permitidas[1L])
      } else if (identical(att, "amostragem/registro/tipo_forma_vida")) {
        acao <- "recalcular_tipo_forma_vida"
      } else if (identical(tipo_info$tipo_base, "select_multiple")) {
        acao <- "append_token;remove_token;replace_token"
      } else if (tipo_info$tipo_base %in% c("select_one", "text", "note", "date", "datetime", "time", "integer", "decimal", "geopoint")) {
        acao <- "update;clear"
      }
      if (tipo_info$tipo_base %in% c("calculate", "hidden", "metadata")) {
        editavel <- FALSE
        acao <- ""
      }
    }

    aliases <- unique(c(
      att,
      sub("^.*/", "", att),
      aliases_admin(att),
      if (att_norm %in% c("uc", "ea", "ua", "ciclo", "campanha")) aliases_admin(att_norm) else character(0)
    ))
    aliases <- aliases[!is.na(aliases) & nzchar(aliases)]

    origem <- c("template_xlsform_2025")
    if (nrow(admin_hit)) origem <- c(origem, "atributo_administrativo_controlado")
    if (isTRUE(painel_101)) origem <- c(origem, "painel_101")
    if (isTRUE(excecao_calculate_editavel)) origem <- c(origem, "excecao_calculate_editavel_num_placa_formatado")

    dominio <- if (nzchar(tipo_info$list_name)) {
      paste0("xlsform:", tipo_info$list_name)
    } else if (tipo_info$tipo_base %in% c("calculate", "hidden", "metadata")) {
      tipo_info$tipo_base
    } else {
      "livre"
    }

    linhas[[ii]] <- data.table::data.table(
      atributo_canonico = att,
      coluna_materializada = att,
      aliases_aceitos = colapsar(aliases),
      origem_contrato = colapsar(origem),
      ordem_template = suppressWarnings(as.integer(tpl$posicao[ii])),
      painel_101 = isTRUE(painel_101),
      editavel_painel = isTRUE(editavel),
      protegido = isTRUE(protegido),
      tipo_base = tipo_info$tipo_base,
      dominio_tipo = dominio,
      list_name = tipo_info$list_name,
      obrigatorio_registros_corrig = isTRUE(obrig),
      obrigatorio_registros_validados = isTRUE(obrig),
      acao_painel = acao,
      validacao_materializacao = if (isTRUE(protegido)) {
        "protegido; nao editar no painel"
      } else if (isTRUE(excecao_calculate_editavel)) {
        "excecao explicita: num_placa_formatado e editavel com validacao de formato; materializacao posterior continua controlada"
      } else if (isTRUE(editavel)) {
        "validar dominio/formato antes de materializar registros_corrig"
      } else if (tipo_info$tipo_base %in% c("calculate", "hidden", "metadata")) {
        "derivado/metadata; materializar por regra controlada"
      } else {
        "materializar conforme template 2025"
      }
    )
  }

  out <- data.table::rbindlist(linhas, fill = TRUE, use.names = TRUE)
  data.table::setorder(out, ordem_template, atributo_canonico)
  out[]
}

monitora_registros_corrig_auditar_atributos_101 <- function(dt, contrato = NULL) {
  ### Auditoria autônoma dos 101 atributos editáveis. Não altera dt, não grava
  ### arquivos e não é chamada pelo painel/materialização neste bloco.
  if (!requireNamespace("data.table", quietly = TRUE)) {
    stop("Pacote data.table é obrigatório.", call. = FALSE)
  }
  if (!inherits(dt, c("data.frame", "data.table"))) {
    stop("Auditoria de atributos 101 exige data.frame/data.table.", call. = FALSE)
  }
  x <- data.table::as.data.table(data.table::copy(dt))
  if (is.null(contrato)) contrato <- monitora_registros_corrig_contrato_mestre_2025()
  contrato <- data.table::as.data.table(data.table::copy(contrato))

  cols_contrato <- c(
    "atributo_canonico", "coluna_materializada", "aliases_aceitos",
    "painel_101", "editavel_painel", "tipo_base", "list_name"
  )
  faltantes <- setdiff(cols_contrato, names(contrato))
  if (length(faltantes)) {
    stop("Contrato 101 sem coluna(s) obrigatória(s): ", paste(faltantes, collapse = ", "), call. = FALSE)
  }

  normalizar <- function(v) {
    if (exists("monitora_correcao_normalizar_nome_coluna", mode = "function")) {
      return(monitora_correcao_normalizar_nome_coluna(v))
    }
    v <- trimws(tolower(as.character(v)))
    v[is.na(v)] <- ""
    v <- iconv(v, from = "", to = "ASCII//TRANSLIT")
    v[is.na(v)] <- ""
    gsub("[^a-z0-9]+", "_", v, perl = TRUE)
  }
  vazio <- function(v) {
    if (exists("monitora_correcao_vazio_vec", mode = "function")) {
      out <- tryCatch(monitora_correcao_vazio_vec(v), error = function(e) NULL)
      if (!is.null(out)) {
        out[is.na(out)] <- TRUE
        return(out)
      }
    }
    z <- trimws(as.character(v))
    is.na(v) | is.na(z) | !nzchar(z) | tolower(z) %in% c("na", "nan", "null") |
      grepl("^[[:space:]]*[-–—−]+[[:space:]]*$", z, perl = TRUE)
  }
  split_aliases <- function(...) {
    vals <- unlist(list(...), use.names = FALSE)
    vals <- unlist(strsplit(as.character(vals), "[|;]", perl = TRUE), use.names = FALSE)
    vals <- unique(trimws(vals))
    vals[!is.na(vals) & nzchar(vals)]
  }
  nms <- names(x)
  nms_norm <- normalizar(nms)
  resolver_cols <- function(aliases) {
    aliases <- split_aliases(aliases)
    aliases_norm <- normalizar(aliases)
    idx <- which(nms %in% aliases | tolower(nms) %in% tolower(aliases) | nms_norm %in% aliases_norm)
    unique(nms[idx])
  }
  valor_linha <- function(col, i) {
    if (is.na(col) || !nzchar(col) || !(col %in% names(x)) || is.na(i) || i < 1L || i > nrow(x)) return("")
    z <- as.character(x[[col]][i])
    if (is.na(z)) "" else z
  }
  primeiro_valor_alias <- function(aliases, i) {
    cols <- resolver_cols(aliases)
    if (!length(cols)) return("")
    vals <- vapply(cols, valor_linha, character(1), i = i)
    vals[is.na(vals)] <- ""
    hit <- vals[!vazio(vals)]
    if (length(hit)) hit[1L] else ""
  }
  contexto_linha <- function(i) {
    aliases_ctx <- list(
      COLETA = c("COLETA", "coleta"),
      UC = c("UC", "uc"),
      EA = c("EA", "ea", "estacao_amostral", "estação amostral"),
      UA = c("UA", "ua", "unidade_amostral", "unidade amostral"),
      CICLO = c("CICLO", "Ciclo", "ciclo"),
      CAMPANHA = c("CAMPANHA", "Campanha", "campanha")
    )
    as.list(vapply(aliases_ctx, primeiro_valor_alias, character(1), i = i))
  }
  saida_vazia <- function() {
    data.table::data.table(
      tipo_pendencia = character(),
      severidade = character(),
      corrigivel_no_painel = logical(),
      atributo_canonico = character(),
      coluna_materializada = character(),
      aliases_aceitos = character(),
      linha = integer(),
      COLETA = character(),
      UC = character(),
      EA = character(),
      UA = character(),
      CICLO = character(),
      CAMPANHA = character(),
      valor_atual = character(),
      valor_esperado = character(),
      mensagem = character(),
      acao_sugerida = character()
    )
  }
  pendencias <- list()
  add <- function(tipo_pendencia, severidade, corrigivel_no_painel, row, linha, valor_atual, valor_esperado, mensagem, acao_sugerida) {
    ctx <- contexto_linha(linha)
    pendencias[[length(pendencias) + 1L]] <<- data.table::data.table(
      tipo_pendencia = as.character(tipo_pendencia)[1L],
      severidade = as.character(severidade)[1L],
      corrigivel_no_painel = isTRUE(corrigivel_no_painel),
      atributo_canonico = as.character(row$atributo_canonico)[1L],
      coluna_materializada = as.character(row$coluna_materializada)[1L],
      aliases_aceitos = as.character(row$aliases_aceitos)[1L],
      linha = suppressWarnings(as.integer(linha))[1L],
      COLETA = ctx$COLETA,
      UC = ctx$UC,
      EA = ctx$EA,
      UA = ctx$UA,
      CICLO = ctx$CICLO,
      CAMPANHA = ctx$CAMPANHA,
      valor_atual = as.character(valor_atual)[1L],
      valor_esperado = as.character(valor_esperado)[1L],
      mensagem = as.character(mensagem)[1L],
      acao_sugerida = as.character(acao_sugerida)[1L]
    )
    invisible(TRUE)
  }

  validar_formato <- function(v, tipo_base) {
    z <- trimws(as.character(v))
    z[is.na(z)] <- ""
    ok <- rep(TRUE, length(z))
    idx <- nzchar(z)
    if (!any(idx)) return(ok)
    if (identical(tipo_base, "date")) {
      ok[idx] <- grepl("^[0-9]{4}-[0-9]{2}-[0-9]{2}$", z[idx], perl = TRUE) &
        !is.na(as.Date(z[idx], format = "%Y-%m-%d"))
      ok[idx] <- ok[idx] & format(as.Date(z[idx], format = "%Y-%m-%d"), "%Y-%m-%d") == z[idx]
    } else if (identical(tipo_base, "time")) {
      ok[idx] <- grepl("^([01][0-9]|2[0-3]):[0-5][0-9](:[0-5][0-9](\\.[0-9]+)?(Z|[+-][0-9]{2}:[0-9]{2})?)?$", z[idx], perl = TRUE)
    } else if (identical(tipo_base, "datetime")) {
      ok[idx] <- grepl("^[0-9]{4}-[0-9]{2}-[0-9]{2}[ T]([01][0-9]|2[0-3]):[0-5][0-9]:[0-5][0-9](\\.[0-9]+)?(Z|[+-][0-9]{2}:[0-9]{2})?$", z[idx], perl = TRUE)
      datas_dt <- sub("[ T].*$", "", z[idx], perl = TRUE)
      ok[idx] <- ok[idx] & !is.na(as.Date(datas_dt, format = "%Y-%m-%d")) &
        format(as.Date(datas_dt, format = "%Y-%m-%d"), "%Y-%m-%d") == datas_dt
    } else if (identical(tipo_base, "integer")) {
      ok[idx] <- grepl("^-?[0-9]+$", z[idx], perl = TRUE)
    } else if (identical(tipo_base, "decimal")) {
      ok[idx] <- grepl("^-?[0-9]+(\\.[0-9]+)?$", z[idx], perl = TRUE) &
        is.finite(suppressWarnings(as.numeric(z[idx])))
    }
    ok[is.na(ok)] <- FALSE
    ok
  }
  choices_seguras <- function(list_name) {
    list_name <- as.character(list_name)[1L]
    if (is.na(list_name) || !nzchar(trimws(list_name))) return(character(0))
    choices <- character(0)
    if (exists("monitora_validados_xlsform21_choices", mode = "function")) {
      choices <- tryCatch(monitora_validados_xlsform21_choices(list_name), error = function(e) character(0))
    }
    if (!length(choices) && exists("monitora_correcao_choices_xlsform", mode = "function")) {
      choices <- tryCatch(monitora_correcao_choices_xlsform(list_name, meta_xls = NULL), error = function(e) character(0))
    }
    if (identical(list_name, "form_veg") && length(choices)) {
      choices <- c(choices, "Campestre", "campestre", "Savânica", "savanica")
    }
    unique(as.character(choices[!is.na(choices) & nzchar(choices)]))
  }
  tokens_select_multiple <- function(v) {
    if (exists("monitora_correcao_tokens_valor", mode = "function")) {
      return(tryCatch(monitora_correcao_tokens_valor(v), error = function(e) character(0)))
    }
    toks <- unlist(strsplit(gsub("[|;,]+", " ", as.character(v), perl = TRUE), "\\s+", perl = TRUE), use.names = FALSE)
    unique(toks[!is.na(toks) & nzchar(toks)])
  }

  contrato_101 <- contrato[painel_101 == TRUE]
  if (!nrow(contrato_101)) return(saida_vazia())
  for (ii in seq_len(nrow(contrato_101))) {
    row <- contrato_101[ii]
    aliases <- split_aliases(row$coluna_materializada, row$atributo_canonico, row$aliases_aceitos)
    cols_presentes <- resolver_cols(aliases)
    col_principal <- as.character(row$coluna_materializada)[1L]
    col_resolvida <- if (col_principal %in% cols_presentes) col_principal else if (length(cols_presentes)) cols_presentes[1L] else NA_character_

    if (!length(cols_presentes)) {
      add(
        "atributo_101_nao_resolvido", "impeditiva", FALSE, row, NA_integer_, "",
        paste(aliases, collapse = " | "),
        "Atributo 101 sem coluna materializada e sem alias presente em registros_corrig.",
        "Mapear/materializar o atributo antes de considerar registros_corrig final."
      )
      next
    }

    if (length(cols_presentes) >= 2L && nrow(x)) {
      vals_mat <- as.data.frame(x[, ..cols_presentes], stringsAsFactors = FALSE)
      for (linha in seq_len(nrow(x))) {
        vals <- trimws(as.character(unlist(vals_mat[linha, ], use.names = TRUE)))
        names(vals) <- cols_presentes
        vals <- vals[!vazio(vals)]
        if (length(unique(vals)) > 1L) {
          add(
            "atributo_101_alias_conflitante", "impeditiva", isTRUE(row$editavel_painel), row, linha,
            paste(paste(names(vals), vals, sep = "="), collapse = " | "),
            "aliases com o mesmo valor",
            "Há aliases do mesmo atributo com valores não vazios diferentes na mesma linha.",
            "Escolher e persistir um único valor coerente para o atributo."
          )
        }
      }
    }

    cad_tipo <- switch(
      normalizar(row$atributo_canonico)[1L],
      uc = "cadastro_uc_ausente_ou_invalida",
      ea = "cadastro_ea_ausente_ou_invalida",
      ua = "cadastro_ua_ausente_ou_invalida",
      ciclo = "cadastro_ciclo_ausente_ou_invalido",
      campanha = "cadastro_campanha_ausente_ou_invalida",
      NA_character_
    )
    if (!is.na(cad_tipo) && nrow(x)) {
      for (linha in seq_len(nrow(x))) {
        vals <- vapply(cols_presentes, valor_linha, character(1), i = linha)
        if (!any(!vazio(vals))) {
          add(
            cad_tipo, "impeditiva", isTRUE(row$editavel_painel), row, linha,
            "", "valor cadastral preenchido",
            "Atributo cadastral principal ausente/vazio nos aliases resolvidos. TODO: validar domínio cadastral quando houver fonte segura.",
            "Preencher valor cadastral correto a partir da documentação da coleta."
          )
        }
      }
    }

    tipo_base <- as.character(row$tipo_base)[1L]
    if (tipo_base %in% c("date", "time", "datetime", "integer", "decimal") && !is.na(col_resolvida) && nrow(x)) {
      vals <- as.character(x[[col_resolvida]])
      ok <- validar_formato(vals, tipo_base)
      idx_bad <- which(!vazio(vals) & !ok)
      for (linha in idx_bad) {
        add(
          "atributo_101_formato_invalido", "impeditiva", isTRUE(row$editavel_painel), row, linha,
          vals[linha], tipo_base,
          paste0("Valor incompatível com formato seguro do tipo ", tipo_base, "."),
          "Corrigir o valor para o formato contratual; a auditoria não tenta corrigir automaticamente."
        )
      }
    }

    if (tipo_base %in% c("select_one", "select_multiple") && is.na(cad_tipo) && !is.na(col_resolvida) && nrow(x)) {
      escolhas <- choices_seguras(row$list_name)
      ### TODO bloco posterior: ampliar validação de domínio dos 101 com fonte
      ### mestre explícita quando a lista XLSForm não estiver carregada. Sem
      ### choices seguras, esta auditoria não gera falso positivo de domínio.
      if (length(escolhas)) {
        vals <- as.character(x[[col_resolvida]])
        for (linha in which(!vazio(vals))) {
          tokens <- if (identical(tipo_base, "select_multiple")) tokens_select_multiple(vals[linha]) else trimws(vals[linha])
          invalidos <- setdiff(tokens, escolhas)
          if (length(invalidos)) {
            add(
              "atributo_101_valor_fora_dominio", "impeditiva", isTRUE(row$editavel_painel), row, linha,
              vals[linha], paste(utils::head(escolhas, 20L), collapse = " | "),
              paste0("Valor/token fora do domínio XLSForm seguro: ", paste(invalidos, collapse = " | "), "."),
              "Substituir por token presente no domínio XLSForm carregado."
            )
          }
        }
      }
    }
  }

  ### TODO bloco posterior: edicao_nao_persistida e dirty_flag_pendente dependem
  ### de trilha/log/estado reativo do painel; não são inferidos desta tabela.
  if (!length(pendencias)) return(saida_vazia())
  out <- data.table::rbindlist(pendencias, fill = TRUE, use.names = TRUE)
  data.table::setcolorder(out, names(saida_vazia()))
  out[]
}

monitora_registros_corrig_contrato_dropdown_painel_101 <- function(contrato = NULL) {
  if (!requireNamespace("data.table", quietly = TRUE)) {
    stop("Pacote data.table é obrigatório.", call. = FALSE)
  }
  if (is.null(contrato)) contrato <- monitora_registros_corrig_contrato_mestre_2025()
  contrato <- data.table::as.data.table(data.table::copy(contrato))
  obrigatorias <- c("atributo_canonico", "coluna_materializada", "ordem_template", "painel_101", "editavel_painel", "protegido", "tipo_base", "acao_painel")
  faltantes <- setdiff(obrigatorias, names(contrato))
  if (length(faltantes)) {
    stop("Contrato mestre sem coluna(s) obrigatoria(s) para dropdown: ", paste(faltantes, collapse = ", "), call. = FALSE)
  }
  out <- contrato[painel_101 == TRUE & editavel_painel == TRUE & protegido != TRUE]
  data.table::setorder(out, ordem_template, atributo_canonico)
  if (nrow(out) != 101L) {
    stop("Dropdown contratual do painel deve conter exatamente 101 atributos; encontrado ", nrow(out), ".", call. = FALSE)
  }
  calc_update <- out[tipo_base %in% c("calculate", "hidden", "metadata") & grepl("(^|;)update(;|$)|(^|;)clear(;|$)", acao_painel, perl = TRUE)]
  if (nrow(calc_update)) {
    stop("Atributos calculate/hidden/metadata nao podem usar update/clear no dropdown: ", paste(calc_update$atributo_canonico, collapse = ", "), call. = FALSE)
  }
  out[]
}

monitora_registros_corrig_contrato_edicao_painel_101 <- function(contrato_edicao, contrato_dropdown_painel_101) {
  if (!requireNamespace("data.table", quietly = TRUE)) {
    stop("Pacote data.table é obrigatório.", call. = FALSE)
  }
  original <- data.table::as.data.table(data.table::copy(contrato_edicao))
  contrato <- data.table::as.data.table(data.table::copy(contrato_dropdown_painel_101))
  obrigatorias <- c("coluna_materializada", "tipo_base", "list_name", "obrigatorio_registros_corrig", "ordem_template", "atributo_canonico", "origem_contrato", "acao_painel")
  faltantes <- setdiff(obrigatorias, names(contrato))
  if (length(faltantes)) {
    stop("Contrato dropdown sem coluna(s) obrigatoria(s): ", paste(faltantes, collapse = ", "), call. = FALSE)
  }
  tipo_base <- as.character(contrato$tipo_base)
  list_name <- as.character(contrato$list_name)
  list_name[is.na(list_name)] <- ""
  xlsform_tipo <- tipo_base
  idx_lista <- tipo_base %in% c("select_one", "select_multiple") & nzchar(trimws(list_name))
  xlsform_tipo[idx_lista] <- paste(tipo_base[idx_lista], list_name[idx_lista])
  novo <- data.table::data.table(
    atributo_coluna_registros_corrig = as.character(contrato$coluna_materializada),
    tipo_base_edicao = tipo_base,
    xlsform_tipo = xlsform_tipo,
    xlsform_list_name = list_name,
    papel_coluna = "",
    categoria_coluna = "",
    required_bool = as.logical(contrato$obrigatorio_registros_corrig),
    atende_template_sismonitora = TRUE,
    ordem_template_sismonitora = as.integer(contrato$ordem_template),
    atributos_template_sismonitora = as.character(contrato$atributo_canonico),
    posicoes_template_sismonitora = as.character(contrato$ordem_template),
    estrategias_template_sismonitora = as.character(contrato$origem_contrato),
    painel_editavel = TRUE,
    painel_motivo_bloqueio = "",
    acoes_permitidas = as.character(contrato$acao_painel)
  )
  if (!nrow(original)) return(novo[])
  for (cc in setdiff(names(novo), names(original))) original[, (cc) := NA]
  for (cc in setdiff(names(original), names(novo))) novo[, (cc) := NA]
  original[, atributo_coluna_registros_corrig := as.character(atributo_coluna_registros_corrig)]
  novo[, atributo_coluna_registros_corrig := as.character(atributo_coluna_registros_corrig)]
  fora_101 <- original[!(atributo_coluna_registros_corrig %in% novo$atributo_coluna_registros_corrig)]
  sobrepostos <- merge(
    original[atributo_coluna_registros_corrig %in% novo$atributo_coluna_registros_corrig],
    novo,
    by = "atributo_coluna_registros_corrig",
    all.y = TRUE,
    suffixes = c(".orig", ".novo"),
    sort = FALSE
  )
  preferir_original <- function(orig, novo) {
    orig_chr <- as.character(orig)
    usar_orig <- !is.na(orig_chr) & nzchar(trimws(orig_chr))
    out <- novo
    out[usar_orig] <- orig[usar_orig]
    out
  }
  combinados <- data.table::data.table(atributo_coluna_registros_corrig = sobrepostos$atributo_coluna_registros_corrig)
  for (cc in setdiff(names(novo), "atributo_coluna_registros_corrig")) {
    orig_nm <- paste0(cc, ".orig")
    novo_nm <- paste0(cc, ".novo")
    if (cc %in% c("atende_template_sismonitora", "ordem_template_sismonitora", "atributos_template_sismonitora", "posicoes_template_sismonitora", "estrategias_template_sismonitora", "painel_editavel", "painel_motivo_bloqueio", "acoes_permitidas")) {
      combinados[, (cc) := sobrepostos[[novo_nm]]]
    } else if (orig_nm %in% names(sobrepostos)) {
      combinados[, (cc) := preferir_original(sobrepostos[[orig_nm]], sobrepostos[[novo_nm]])]
    } else {
      combinados[, (cc) := sobrepostos[[novo_nm]]]
    }
  }
  tipo_final <- as.character(combinados$tipo_base_edicao)
  lista_final <- as.character(combinados$xlsform_list_name)
  lista_final[is.na(lista_final)] <- ""
  tipo_xls_final <- as.character(combinados$xlsform_tipo)
  precisa_lista <- tipo_final %in% c("select_one", "select_multiple") & nzchar(trimws(lista_final))
  tipo_xls_final[precisa_lista] <- paste(tipo_final[precisa_lista], lista_final[precisa_lista])
  combinados[, xlsform_tipo := tipo_xls_final]
  data.table::rbindlist(list(fora_101, combinados), fill = TRUE, use.names = TRUE)
}

monitora_correcao_coluna_real_admin_ou_col <- function(dt, col) {
  hit <- tryCatch(monitora_correcao_coluna_real_admin_sismonitora(dt, col), error = function(e) NA_character_)
  if (!is.na(hit) && nzchar(hit)) hit else as.character(col)[1L]
}

monitora_correcao_campo_dominio_dinamico_sismonitora <- function(col, list_name = NA_character_) {
  vals <- unique(tolower(trimws(as.character(c(col, list_name)))))
  vals <- vals[!is.na(vals) & nzchar(vals)]
  norms <- unique(monitora_correcao_normalizar_nome_coluna(vals))
  any(norms %in% c("uc", "ea", "ua", "estacao_amostral", "unidade_amostral", "ciclo", "campanha", "validado"))
}

monitora_correcao_choices_dominio_dinamico_sismonitora <- function(dt, col) {
  if (is.null(dt) || is.na(col) || !nzchar(col)) return(character(0))
  col_real <- monitora_correcao_coluna_real_admin_ou_col(dt, col)
  if (is.na(col_real) || !nzchar(col_real) || !(col_real %in% names(dt))) return(character(0))
  vals <- unique(trimws(as.character(dt[[col_real]])))
  vals <- vals[!is.na(vals) & nzchar(vals)]
  vals <- sort(vals)
  ### validado é domínio administrativo simples; se a base ainda não tiver valor
  ### observado, oferece opções contratuais genéricas, sem copiar valores reais.
  if (!length(vals) && monitora_correcao_normalizar_nome_coluna(col) %in% c("validado")) {
    vals <- c("nao", "sim")
  }
  vals
}

monitora_correcao_validar_dominio_dinamico_sismonitora <- function(dt, col, tipo_base, list_name, valor, acao) {
  acao <- monitora_correcao_acao_normalizar(acao)
  if (!identical(as.character(tipo_base)[1L], "select_one")) return(list(aplicou = FALSE, ok = TRUE, status = "ok", mensagem = "não é domínio dinâmico"))
  if (!isTRUE(monitora_correcao_campo_dominio_dinamico_sismonitora(col, list_name))) return(list(aplicou = FALSE, ok = TRUE, status = "ok", mensagem = "não é domínio dinâmico"))
  if (acao %in% c("clear", "recalcular_tipo_forma_vida")) return(list(aplicou = TRUE, ok = TRUE, status = "ok", mensagem = "ação sem valor novo"))
  valor <- trimws(as.character(valor)[1L])
  if (is.na(valor) || !nzchar(valor)) return(list(aplicou = TRUE, ok = FALSE, status = "bloqueada_valor_vazio", mensagem = "valor novo vazio para domínio dinâmico"))
  escolhas <- monitora_correcao_choices_dominio_dinamico_sismonitora(dt, col)
  if (!length(escolhas)) return(list(aplicou = TRUE, ok = FALSE, status = "bloqueada_dominio_dinamico_ausente", mensagem = paste0("Correção bloqueada: não há valores observados para o domínio dinâmico do atributo '", col, "' nesta execução.")))
  if (!(valor %in% escolhas)) {
    msg <- paste0("Valor fora do domínio dinâmico observado para '", col, "'. Use um valor já presente na base desta execução.")
    return(list(aplicou = TRUE, ok = FALSE, status = "bloqueada_dominio_dinamico", mensagem = msg))
  }
  list(aplicou = TRUE, ok = TRUE, status = "ok", mensagem = "domínio dinâmico compatível")
}

monitora_correcao_validar_atributo_especifico_sismonitora_2025 <- function(col, valor, acao) {
  acao <- monitora_correcao_acao_normalizar(acao)
  if (acao %in% c("clear", "recalcular_tipo_forma_vida")) return(list(ok = TRUE, status = "ok", mensagem = "sem valor novo"))
  col_norm <- monitora_correcao_normalizar_nome_coluna(col)
  valor <- trimws(as.character(valor)[1L])
  if (is.na(valor)) valor <- ""
  if (col_norm %in% c("amostragem_num_placa", "num_placa")) {
    if (!grepl("^\\d{1,4}$", valor, perl = TRUE)) {
      return(list(ok = FALSE, status = "bloqueada_formato_num_placa", mensagem = "Número da plaqueta inválido: use apenas 1 a 4 dígitos."))
    }
  }
  if (col_norm %in% c("amostragem_num_placa_formatado", "num_placa_formatado")) {
    if (!grepl("^\\d{4}$", valor, perl = TRUE)) {
      return(list(ok = FALSE, status = "bloqueada_formato_num_placa_formatado", mensagem = "Número da plaqueta formatado inválido: use exatamente 4 dígitos, com zeros à esquerda quando necessário."))
    }
  }
  list(ok = TRUE, status = "ok", mensagem = "validação específica compatível")
}
### FIM v2.6.1 -------------------------------------------------------------

monitora_correcao_contrato_edicao <- function(dt, meta_xls = NULL, dicionario = NULL) {
  dt <- data.table::as.data.table(dt)
  meta_xls <- monitora_correcao_xlsform_meta_atual(meta_xls)
  chaves <- monitora_correcao_colunas_chave(dt)
  dicionario_invalido <- is.null(dicionario) || !nrow(data.table::as.data.table(dicionario)) || !("atributo_coluna_registros_corrig" %in% names(data.table::as.data.table(dicionario)))
  if (!isTRUE(dicionario_invalido)) {
    dd_tmp <- data.table::as.data.table(dicionario)
    dicionario_invalido <- all(is.na(dd_tmp$atributo_coluna_registros_corrig) | !nzchar(as.character(dd_tmp$atributo_coluna_registros_corrig)))
  }
  if (isTRUE(dicionario_invalido)) {
    dicionario <- monitora_correcao_dicionario_atributos(dt, meta_xls)
  }
  d <- data.table::as.data.table(data.table::copy(dicionario))
  if (!nrow(d)) {
    d <- data.table::data.table(atributo_coluna_registros_corrig = names(dt))
  }
  for (cc in c("atributo_coluna_registros_corrig", "xlsform_tipo", "tipo_valor_inferido", "papel_coluna", "categoria_coluna", "xlsform_name", "xlsform_list_name", "xlsform_required")) {
    if (!(cc %in% names(d))) d[, (cc) := NA_character_]
  }

  tipo_parse <- monitora_correcao_tipo_xlsform(d$xlsform_tipo)
  d[, xlsform_tipo_base := tipo_parse$tipo_base]
  d[, xlsform_list_name_calc := tipo_parse$list_name]
  d[is.na(xlsform_list_name) | !nzchar(xlsform_list_name), xlsform_list_name := xlsform_list_name_calc]
  d[papel_coluna == "lista_principal_forma_vida" & !is.na(categoria_coluna) & nzchar(categoria_coluna), xlsform_list_name := paste0("forma_vida_", categoria_coluna)]
  d[papel_coluna == "campo_superior_tipo_forma_vida", xlsform_list_name := "tipo_forma_vida"]
  d[papel_coluna == "atributo_dependente_habito" & (is.na(xlsform_list_name) | !nzchar(xlsform_list_name)), xlsform_list_name := "habito_forma_vida"]
  d[, tipo_base_edicao := mapply(
    monitora_correcao_tipo_campo_inferir,
    atributo_coluna_registros_corrig,
    papel_coluna,
    xlsform_tipo,
    tipo_valor_inferido,
    xlsform_list_name,
    MoreArgs = list(chaves = chaves),
    SIMPLIFY = TRUE,
    USE.NAMES = FALSE
  )]
  d[, protegido := monitora_correcao_coluna_protegida(atributo_coluna_registros_corrig)]
  d[, required_bool := tolower(trimws(as.character(xlsform_required))) %in% c("yes", "true", "1", "sim", "required")]

  if (exists("monitora_correcao_anotar_contrato_template_sismonitora", mode = "function")) {
    d <- monitora_correcao_anotar_contrato_template_sismonitora(d, dt)
  } else {
    d[, atende_template_sismonitora := FALSE]
    d[, atributos_template_sismonitora := ""]
    d[, posicoes_template_sismonitora := ""]
    d[, estrategias_template_sismonitora := ""]
    d[, ordem_template_sismonitora := 999999L]
  }
  for (cc in c("atende_template_sismonitora", "ordem_template_sismonitora", "atributos_template_sismonitora", "posicoes_template_sismonitora", "estrategias_template_sismonitora")) {
    if (!(cc %in% names(d))) d[, (cc) := if (identical(cc, "atende_template_sismonitora")) FALSE else if (identical(cc, "ordem_template_sismonitora")) 999999L else ""]
  }

  d[, painel_template_2025_editavel := monitora_painel_atributo_editavel_sismonitora_2025(atributos_template_sismonitora)]
  d[is.na(painel_template_2025_editavel) | painel_template_2025_editavel == FALSE,
    painel_template_2025_editavel := monitora_painel_atributo_editavel_sismonitora_2025(atributo_coluna_registros_corrig)]
  d[is.na(painel_template_2025_editavel), painel_template_2025_editavel := FALSE]

  ### Exceção deliberada v2.6.1: os dois campos de plaqueta podem ser corrigidos
  ### pelos bolsistas com validação de formato e auditoria, embora um deles seja
  ### derivado no XLSForm.
  d[monitora_correcao_normalizar_nome_coluna(atributo_coluna_registros_corrig) %in% c("amostragem_num_placa_formatado", "num_placa_formatado"),
    `:=`(protegido = FALSE, tipo_base_edicao = "text", xlsform_tipo = "text", xlsform_list_name = "")]
  d[monitora_painel_atributo_editavel_sismonitora_2025(atributos_template_sismonitora) & grepl("num_placa_formatado$", atributos_template_sismonitora),
    `:=`(protegido = FALSE, tipo_base_edicao = "text", xlsform_tipo = "text", xlsform_list_name = "")]

  ### Exceção cirúrgica v2.6.1: metadados administrativos autorizados pelo
  ### contrato do template exportado. A exceção é aplicada no contrato central,
  ### antes dos bloqueios, para que a UI, a validação e a aplicação persistente
  ### usem exatamente a mesma regra.
  if (exists("monitora_painel_admin_controlados_aplicar_contrato", mode = "function")) {
    d <- monitora_painel_admin_controlados_aplicar_contrato(d)
  }

  d[, motivo_bloqueio_edicao := NA_character_]
  d[atende_template_sismonitora != TRUE, motivo_bloqueio_edicao := "fora do contrato do template SISMONITORA/XLSForm 2025"]
  d[painel_template_2025_editavel != TRUE & is.na(motivo_bloqueio_edicao), motivo_bloqueio_edicao := "atributo fora da whitelist de edição do painel v2.6.1"]
  d[protegido == TRUE & is.na(motivo_bloqueio_edicao), motivo_bloqueio_edicao := "coluna estrutural, chave operacional ou derivada protegida"]
  d[tipo_base_edicao %in% c("calculate", "hidden", "start", "end", "deviceid", "phonenumber", "barcode", "acknowledge", "rank", "range", "file") & is.na(motivo_bloqueio_edicao), motivo_bloqueio_edicao := paste0("tipo XLSForm não editável diretamente: ", tipo_base_edicao)]
  d[papel_coluna %in% c("imagem_foto") & is.na(motivo_bloqueio_edicao), motivo_bloqueio_edicao := "imagem/foto não deve ser substituída livremente no painel"]
  d[tipo_base_edicao == "uuid" & is.na(motivo_bloqueio_edicao), motivo_bloqueio_edicao := "UUID não deve ser editado diretamente"]

  d[, acoes_permitidas := ""]
  d[is.na(motivo_bloqueio_edicao) & papel_coluna == "campo_superior_tipo_forma_vida", acoes_permitidas := "recalcular_tipo_forma_vida"]
  d[is.na(motivo_bloqueio_edicao) & tipo_base_edicao == "select_multiple" & papel_coluna != "campo_superior_tipo_forma_vida", acoes_permitidas := "append_token;remove_token;replace_token"]
  d[is.na(motivo_bloqueio_edicao) & tipo_base_edicao == "select_one", acoes_permitidas := "update;clear"]
  d[is.na(motivo_bloqueio_edicao) & tipo_base_edicao %in% c("text", "note"), acoes_permitidas := "update;clear"]
  d[is.na(motivo_bloqueio_edicao) & tipo_base_edicao %in% c("date", "datetime", "time", "integer", "decimal", "geopoint"), acoes_permitidas := "update;clear"]
  d[required_bool == TRUE, acoes_permitidas := gsub("(^|;)clear(;|$)", "\\1", acoes_permitidas, perl = TRUE)]
  d[, acoes_permitidas := gsub(";+", ";", gsub("^;|;$", "", acoes_permitidas))]
  d[, painel_editavel := painel_template_2025_editavel == TRUE & atende_template_sismonitora == TRUE & !protegido & nzchar(acoes_permitidas)]
  d[, painel_motivo_bloqueio := data.table::fifelse(painel_editavel, "", data.table::fifelse(!is.na(motivo_bloqueio_edicao), motivo_bloqueio_edicao, "sem ação permitida para edição direta"))]

  d[, .(
    atributo_coluna_registros_corrig,
    tipo_base_edicao,
    xlsform_tipo,
    xlsform_list_name,
    papel_coluna,
    categoria_coluna,
    required_bool,
    atende_template_sismonitora,
    ordem_template_sismonitora,
    atributos_template_sismonitora,
    posicoes_template_sismonitora,
    estrategias_template_sismonitora,
    painel_editavel,
    painel_motivo_bloqueio,
    acoes_permitidas
  )]
}


### publicação: restringe atributos do painel aos campos de registros_corrig que
### constam no template SISMONITORA/XLSForm 2025 usado como contrato de atributos.
### O painel continua operando sobre registros_corrig, mas só lista atributos
### que aparecem como coluna de origem na matriz de herança para os 129 atributos
### do contrato final. Campos técnicos, auxiliares, diagnósticos ou legados que
### não constam nesse template ficam bloqueados para edição livre.
monitora_correcao_colunas_template_sismonitora <- function(dt, schema = NULL) {
  if (!requireNamespace("data.table", quietly = TRUE)) stop("Pacote data.table é obrigatório.", call. = FALSE)
  dt <- data.table::as.data.table(dt)
  tpl <- monitora_painel_template_sismonitora_2025()
  if (is.null(schema)) {
    schema <- if (exists("monitora_validados_schema_embutido", mode = "function")) monitora_validados_schema_embutido() else data.table::data.table()
  }
  schema <- data.table::as.data.table(schema)
  if (!nrow(schema) || !("atributo" %in% names(schema))) schema <- data.table::data.table(atributo = character())
  for (cc in c("posicao", "atributo", "formato", "obrigatorio_valor", "nivel")) {
    if (!(cc %in% names(schema))) schema[, (cc) := NA_character_]
  }
  schema[, atributo := as.character(atributo)]
  schema <- schema[!is.na(atributo) & nzchar(trimws(atributo))]
  schema <- schema[!duplicated(atributo)]

  ### v2.6.1: o contrato do painel segue a estrutura de 129 atributos do template
  ### de exportação SISMONITORA 2025. A matriz abaixo contém apenas metadados
  ### estruturais e não contém nenhum valor real de arquivo de dados.
  schema <- merge(
    tpl,
    schema[, .(atributo, formato_schema = formato, obrigatorio_valor_schema = obrigatorio_valor, nivel_schema = nivel)],
    by = "atributo",
    all.x = TRUE,
    sort = FALSE
  )
  data.table::setorder(schema, posicao)
  schema[, formato := formato_schema]
  schema[is.na(formato) | !nzchar(as.character(formato)), formato := tipo_template]
  schema[, obrigatorio_valor := obrigatorio_valor_schema]
  schema[is.na(obrigatorio_valor) | !nzchar(as.character(obrigatorio_valor)), obrigatorio_valor := required_template]
  schema[, nivel := nivel_schema]
  schema[is.na(nivel) | !nzchar(as.character(nivel)), nivel := sub("/[^/]+$", "", atributo)]

  meta <- tryCatch(monitora_correcao_xlsform_meta_atual(NULL), error = function(e) NULL)
  campos <- if (!is.null(meta) && !is.null(meta$campos)) data.table::as.data.table(meta$campos) else data.table::data.table()
  if (nrow(campos)) {
    for (cc in c("name", "type", "label", "caminho_registro", "list_name", "arquivo_xlsform")) {
      if (!(cc %in% names(campos))) campos[, (cc) := NA_character_]
    }
    campos[, name_chr := as.character(name)]
    campos[, type_chr := as.character(type)]
    campos[, label_chr := as.character(label)]
    campos[, caminho_chr := as.character(caminho_registro)]
    campos[, list_chr := as.character(list_name)]
    arq_atual <- tryCatch(monitora_correcao_ultima_versao_xlsform(campos), error = function(e) NA_character_)
    if (!is.na(arq_atual) && nzchar(arq_atual) && "arquivo_xlsform" %in% names(campos)) {
      campos_atual <- campos[arquivo_xlsform == arq_atual]
      if (nrow(campos_atual)) campos <- campos_atual
    }
  }

  nms <- names(dt)
  nms_norm <- monitora_correcao_normalizar_nome_coluna(nms)
  rows <- vector("list", nrow(schema))
  for (ii in seq_len(nrow(schema))) {
    att <- as.character(schema$atributo[ii])
    if (!isTRUE(schema$painel_editavel_template[ii])) next
    att_final <- sub("^.*/", "", att)
    pos_raw <- schema$posicao[ii]
    pos_num <- suppressWarnings(as.integer(pos_raw))
    if (is.na(pos_num)) pos_num <- ii

    hit <- data.table::data.table()
    if (nrow(campos)) {
      hit <- campos[caminho_chr == att | name_chr == att | name_chr == att_final]
      if (!nrow(hit)) {
        pad <- paste0("(^|/)", gsub("([][{}()+*^$|\\?.])", "\\\\\\1", att_final, perl = TRUE), "$")
        hit <- campos[grepl(pad, caminho_chr, ignore.case = TRUE)]
      }
    }

    nome_xls <- if (nrow(hit)) as.character(hit$name_chr[1L]) else att_final
    lab_xls <- if (nrow(hit)) as.character(hit$label_chr[1L]) else ""
    tipo_xls <- if (nrow(hit)) as.character(hit$type_chr[1L]) else as.character(schema$formato[ii])
    list_xls <- if (nrow(hit)) as.character(hit$list_chr[1L]) else as.character(schema$list_name_template[ii])
    tipo_hit <- tryCatch(monitora_correcao_tipo_xlsform(tipo_xls), error = function(e) data.table::data.table(tipo_base = "text", list_name = ""))
    tipo_base <- as.character(tipo_hit$tipo_base[1L])
    if (is.na(tipo_base) || !nzchar(tipo_base)) tipo_base <- "text"
    if (is.na(list_xls) || !nzchar(list_xls)) list_xls <- as.character(tipo_hit$list_name[1L])

    if (att %in% c("amostragem/num_placa_formatado")) {
      tipo_xls <- "text"
      tipo_base <- "text"
      list_xls <- ""
    }

    parent <- sub("/[^/]+$", "", att)
    lab_limpo <- trimws(gsub("\\s+", " ", gsub("\\u200b", "", lab_xls)))
    lab_sem_dois <- sub(":$", "", lab_limpo)
    candidatos <- unique(c(
      att, att_final, nome_xls,
      if (identical(att, "uc")) c("UC", "uc") else character(0),
      if (identical(att, "ea")) c("EA", "ea", "estacao_amostral", "estação amostral") else character(0),
      if (identical(att, "ua")) c("UA", "ua", "unidade_amostral", "unidade amostral") else character(0),
      if (nzchar(lab_limpo)) lab_limpo else character(0),
      if (nzchar(lab_sem_dois)) lab_sem_dois else character(0),
      if (nzchar(lab_limpo) && nzchar(parent)) paste0(lab_limpo, " (", parent, ")") else character(0),
      if (nzchar(lab_sem_dois) && nzchar(parent)) paste0(lab_sem_dois, ": (", parent, ")") else character(0),
      if (nzchar(lab_sem_dois) && nzchar(parent)) paste0(lab_sem_dois, " (", parent, ")") else character(0)
    ))
    candidatos <- candidatos[!is.na(candidatos) & nzchar(candidatos)]

    col <- NA_character_
    col_res <- tryCatch(monitora_validados_resolver_coluna(nms, att), error = function(e) NA_character_)
    if (!is.na(col_res) && nzchar(col_res) && col_res %in% nms) col <- col_res
    if (is.na(col) || !nzchar(col)) {
      hit_exato <- candidatos[candidatos %in% nms]
      if (length(hit_exato)) col <- hit_exato[1L]
    }
    if (is.na(col) || !nzchar(col)) {
      cand_norm <- monitora_correcao_normalizar_nome_coluna(candidatos)
      idx <- match(TRUE, nms_norm %in% cand_norm)
      if (!is.na(idx)) col <- nms[idx]
    }
    if (is.na(col) || !nzchar(col)) col <- att

    protegido <- isTRUE(monitora_correcao_coluna_protegida(col)) || isTRUE(monitora_correcao_coluna_protegida(att))
    if (isTRUE(protegido)) next
    if (grepl("foto|imagem|image", att, ignore.case = TRUE)) next
    if (tolower(tipo_base) %in% c("hidden", "start", "end", "deviceid", "phonenumber", "barcode", "acknowledge", "rank", "range", "file", "image", "audio", "video", "uuid")) next
    if (tolower(tipo_base) == "calculate" && !identical(att, "amostragem/num_placa_formatado")) next

    rows[[ii]] <- data.table::data.table(
      atributo_coluna_registros_corrig = as.character(col),
      atende_template_sismonitora = TRUE,
      ordem_template_sismonitora = as.integer(pos_num),
      atributos_template_sismonitora = as.character(att),
      posicoes_template_sismonitora = as.character(pos_raw),
      estrategias_template_sismonitora = data.table::fifelse(col %in% nms, "coluna_existente_registros_corrig", "coluna_contratual_criada_pre_painel"),
      xlsform_name = nome_xls,
      xlsform_label = lab_xls,
      xlsform_tipo = tipo_xls,
      xlsform_tipo_base = tipo_base,
      xlsform_list_name = list_xls
    )
  }
  h <- data.table::rbindlist(rows, fill = TRUE, use.names = TRUE)
  if (!nrow(h)) {
    return(data.table::data.table(
      atributo_coluna_registros_corrig = character(), atende_template_sismonitora = logical(),
      ordem_template_sismonitora = integer(), atributos_template_sismonitora = character(),
      posicoes_template_sismonitora = character(), estrategias_template_sismonitora = character()
    ))
  }
  ### Garante que os metadados editáveis do template exportado entrem também no
  ### contrato global, não apenas na UI. Isso evita bloqueio posterior quando as
  ### correções salvas pelo painel são validadas e aplicadas aos produtos.
  if (exists("monitora_painel_admin_controlados_aplicar_contrato", mode = "function")) {
    h <- monitora_painel_admin_controlados_aplicar_contrato(h)
  }
  h <- h[!duplicated(atributo_coluna_registros_corrig)]
  data.table::setorder(h, ordem_template_sismonitora, atributo_coluna_registros_corrig)
  h[]
}

monitora_correcao_anotar_contrato_template_sismonitora <- function(d, dt) {
  if (!requireNamespace("data.table", quietly = TRUE)) stop("Pacote data.table é obrigatório.", call. = FALSE)
  d <- data.table::as.data.table(data.table::copy(d))
  if (!("atributo_coluna_registros_corrig" %in% names(d))) return(d)
  heranca <- tryCatch(monitora_correcao_colunas_template_sismonitora(dt), error = function(e) data.table::data.table())
  cols_h <- c("atende_template_sismonitora", "ordem_template_sismonitora", "atributos_template_sismonitora", "posicoes_template_sismonitora", "estrategias_template_sismonitora")
  cols_h_existentes <- intersect(cols_h, names(d))
  if (length(cols_h_existentes)) d[, (cols_h_existentes) := NULL]
  if (nrow(heranca)) {
    cols_h_merge <- c("atributo_coluna_registros_corrig", cols_h)
    d <- merge(d, heranca[, ..cols_h_merge], by = "atributo_coluna_registros_corrig", all.x = TRUE, sort = FALSE)
  } else {
    d[, atende_template_sismonitora := FALSE]
    d[, atributos_template_sismonitora := ""]
    d[, posicoes_template_sismonitora := ""]
    d[, estrategias_template_sismonitora := ""]
  }
  for (cc in c("atende_template_sismonitora", "ordem_template_sismonitora", "atributos_template_sismonitora", "posicoes_template_sismonitora", "estrategias_template_sismonitora")) {
    if (!(cc %in% names(d))) d[, (cc) := if (identical(cc, "atende_template_sismonitora")) FALSE else if (identical(cc, "ordem_template_sismonitora")) NA_integer_ else ""]
  }
  d[is.na(atende_template_sismonitora), atende_template_sismonitora := FALSE]
  d[is.na(ordem_template_sismonitora), ordem_template_sismonitora := 999999L]
  for (cc in c("atributos_template_sismonitora", "posicoes_template_sismonitora", "estrategias_template_sismonitora")) {
    d[is.na(get(cc)), (cc) := ""]
  }
  d[]
}


monitora_correcao_colapsar_opcoes_msg <- function(opcoes, max_n = 35L) {
  opcoes <- unique(trimws(as.character(opcoes)))
  opcoes <- opcoes[!is.na(opcoes) & nzchar(opcoes)]
  if (!length(opcoes)) return("sem opções enumeradas no contrato")
  opcoes <- sort(opcoes)
  txt <- paste(utils::head(opcoes, max_n), collapse = ", ")
  if (length(opcoes) > max_n) txt <- paste0(txt, " ... [", length(opcoes), " opções no contrato]")
  txt
}

monitora_correcao_sugerir_opcoes_msg <- function(invalidos, opcoes, max_n = 5L) {
  invalidos <- unique(trimws(as.character(invalidos)))
  invalidos <- invalidos[!is.na(invalidos) & nzchar(invalidos)]
  opcoes <- unique(trimws(as.character(opcoes)))
  opcoes <- opcoes[!is.na(opcoes) & nzchar(opcoes)]
  if (!length(invalidos) || !length(opcoes)) return("")
  out <- character(0)
  for (inv in invalidos) {
    dd <- utils::adist(tolower(inv), tolower(opcoes))
    ord <- order(as.numeric(dd[1, ]), opcoes)
    cand <- opcoes[ord]
    cand <- cand[seq_len(min(max_n, length(cand)))]
    out <- c(out, paste0("Para '", inv, "', opções próximas: ", paste(cand, collapse = ", ")))
  }
  paste(out, collapse = "; ")
}

monitora_correcao_exemplos_formato_msg <- function(tipo_base) {
  tipo_base <- as.character(tipo_base)[1L]
  if (is.na(tipo_base)) tipo_base <- ""
  if (tipo_base == "date") {
    return("Exemplo válido: 2025-05-23. Use exatamente YYYY-MM-DD; espaços, pontos, barras, texto e datas parciais são bloqueados.")
  }
  if (tipo_base == "datetime") {
    return("Exemplo válido: 2025-05-23T15:40:00-03:00. Use datetime ISO; espaços extras, pontos soltos, barras e texto são bloqueados.")
  }
  if (tipo_base == "time") {
    return("Exemplos válidos: 15:40; 15:40:00; 15:40:00.000-03:00. Use apenas caracteres do contrato de hora.")
  }
  if (tipo_base == "integer") return("Exemplo válido: 101. Use apenas número inteiro, sem texto adicional.")
  if (tipo_base == "decimal") return("Exemplo válido: 3.33. Use número decimal com ponto, sem vírgula, texto ou espaços.")
  if (tipo_base == "geopoint") {
    return("Exemplos válidos: -7.7267858 -63.7942423; -7.7267858 -63.7942423 88.8; -7.7267858 -63.7942423 88.8 3.33. Latitude e longitude são obrigatórias; altitude e acurácia são opcionais.")
  }
  if (tipo_base %in% c("select_one", "select_multiple")) return("Use exatamente os tokens definidos no contrato XLSForm vigente.")
  "Preencha conforme o tipo do campo no contrato XLSForm."
}

monitora_correcao_validar_formato_valor <- function(valor, tipo_base, acao, list_name = NA_character_, meta_xls = NULL, valor_original = NA_character_) {
  acao <- monitora_correcao_acao_normalizar(acao)
  tipo_base <- as.character(tipo_base)[1L]
  valor <- as.character(valor)[1L]
  valor_original <- as.character(valor_original)[1L]
  if (is.na(valor)) valor <- ""
  if (is.na(valor_original)) valor_original <- ""
  if (acao %in% c("clear", "recalcular_tipo_forma_vida")) return(list(ok = TRUE, status = "ok", mensagem = "formato compatível"))
  if (tipo_base %in% c("select_one", "select_multiple")) {
    escolhas <- monitora_correcao_choices_xlsform(list_name, meta_xls)
    if (!length(escolhas)) {
      return(list(ok = FALSE, status = "bloqueada_dominio_xlsform_ausente", mensagem = paste0("Correção bloqueada: o atributo usa lista XLSForm, mas o domínio de tokens não foi carregado para list_name='", list_name, "'.")))
    }
    if (tipo_base == "select_multiple" && acao %in% c("update", "substituir_valor", "clear", "limpar")) {
      return(list(ok = FALSE, status = "bloqueada_lista_tokens_sem_substituir_valor", mensagem = "Atributos de lista de tokens não aceitam substituir ou limpar o valor inteiro. Use Adicionar token, Remover token ou Substituir token."))
    }
    valor_validar <- valor
    if (acao %in% c("remove_token", "remover_token") && !nzchar(trimws(valor_validar))) valor_validar <- valor_original
    if (!nzchar(trimws(valor_validar))) {
      return(list(ok = FALSE, status = "bloqueada_valor_vazio", mensagem = "Informe o token/valor da operação. Em lista de tokens, use operação tokenizada; não substitua o valor inteiro do campo."))
    }
    if (tipo_base == "select_multiple" && acao %in% c("remove_token", "remover_token")) {
      return(list(ok = TRUE, status = "ok", mensagem = "remoção de token validada quanto à presença pela pré-condição operacional"))
    }
    toks <- if (tipo_base == "select_multiple") monitora_correcao_tokens_valor(valor_validar) else valor_validar
    invalidos <- setdiff(toks, escolhas)
    if (length(invalidos)) {
      opcoes_msg <- monitora_correcao_colapsar_opcoes_msg(escolhas)
      sugestoes_msg <- monitora_correcao_sugerir_opcoes_msg(invalidos, escolhas)
      msg <- paste0(
        "Valor/token fora do domínio XLSForm da lista '", list_name, "'. ",
        "Token(s) inválido(s): ", paste(invalidos, collapse = ", "), ". ",
        "Opções válidas: ", opcoes_msg, "."
      )
      if (nzchar(sugestoes_msg)) msg <- paste0(msg, " ", sugestoes_msg, ".")
      return(list(ok = FALSE, status = "bloqueada_dominio_xlsform", mensagem = msg))
    }
    return(list(ok = TRUE, status = "ok", mensagem = "domínio XLSForm compatível"))
  }
  if (!nzchar(trimws(valor))) return(list(ok = FALSE, status = "bloqueada_valor_vazio", mensagem = "valor novo vazio; use Limpar valor quando a ausência for permitida"))
  if (tipo_base == "date") {
    vv <- as.character(valor)[1L]
    ok <- grepl("^\\d{4}-\\d{2}-\\d{2}$", vv, perl = TRUE)
    if (!ok) return(list(ok = FALSE, status = "bloqueada_formato_data", mensagem = paste("Data inválida: use exatamente YYYY-MM-DD. Qualquer caractere fora desse contrato é bloqueado no painel.", monitora_correcao_exemplos_formato_msg(tipo_base))))
    d <- suppressWarnings(as.Date(vv, format = "%Y-%m-%d"))
    if (is.na(d) || !identical(format(d, "%Y-%m-%d"), vv)) return(list(ok = FALSE, status = "bloqueada_formato_data", mensagem = paste("Data inexistente ou fora do contrato YYYY-MM-DD.", monitora_correcao_exemplos_formato_msg(tipo_base))))
    return(list(ok = TRUE, status = "ok", mensagem = "data válida no contrato YYYY-MM-DD"))
  }
  if (tipo_base == "datetime") {
    vv <- as.character(valor)[1L]
    ok <- grepl("^\\d{4}-\\d{2}-\\d{2}[T ]([01]\\d|2[0-3]):[0-5]\\d(:[0-5]\\d(\\.\\d{1,3})?)?([+-]([01]\\d|2[0-3]):?[0-5]\\d|Z)?$", vv, perl = TRUE)
    if (!ok) return(list(ok = FALSE, status = "bloqueada_formato_datetime", mensagem = paste("Datetime inválido: use formato ISO compatível com o contrato, sem caracteres extras.", monitora_correcao_exemplos_formato_msg(tipo_base))))
    return(list(ok = TRUE, status = "ok", mensagem = "datetime válido no contrato ISO"))
  }
  if (tipo_base == "time") {
    vv <- as.character(valor)[1L]
    ok <- grepl("^([01]\\d|2[0-3]):[0-5]\\d(:[0-5]\\d(\\.\\d{1,3})?)?([+-]([01]\\d|2[0-3]):?[0-5]\\d|Z)?$", vv, perl = TRUE)
    if (!ok) return(list(ok = FALSE, status = "bloqueada_formato_hora", mensagem = paste("Hora inválida: somente caracteres do contrato de hora são aceitos.", monitora_correcao_exemplos_formato_msg(tipo_base))))
    return(list(ok = TRUE, status = "ok", mensagem = "hora válida"))
  }
  if (tipo_base == "integer") {
    vv <- as.character(valor)[1L]
    ok <- grepl("^-?\\d+$", vv, perl = TRUE)
    if (!ok) return(list(ok = FALSE, status = "bloqueada_formato_inteiro", mensagem = paste("Valor deve ser inteiro e conter apenas caracteres do contrato numérico inteiro.", monitora_correcao_exemplos_formato_msg(tipo_base))))
    return(list(ok = TRUE, status = "ok", mensagem = "inteiro válido"))
  }
  if (tipo_base == "decimal") {
    vv <- as.character(valor)[1L]
    ok <- grepl("^-?\\d+(\\.\\d+)?$", vv, perl = TRUE)
    if (!ok) return(list(ok = FALSE, status = "bloqueada_formato_decimal", mensagem = paste("Valor deve ser decimal com ponto e conter apenas caracteres do contrato numérico decimal.", monitora_correcao_exemplos_formato_msg(tipo_base))))
    num <- suppressWarnings(as.numeric(vv))
    if (!is.finite(num)) return(list(ok = FALSE, status = "bloqueada_formato_decimal", mensagem = paste("Valor decimal fora de faixa ou inválido.", monitora_correcao_exemplos_formato_msg(tipo_base))))
    return(list(ok = TRUE, status = "ok", mensagem = "decimal válido"))
  }
  if (tipo_base == "geopoint") {
    vv <- as.character(valor)[1L]
    num_re <- "[-+]?\\d+(?:\\.\\d+)?"
    ok <- grepl(paste0("^", num_re, "\\s+", num_re, "(?:\\s+", num_re, "){0,2}$"), vv, perl = TRUE)
    if (!ok) return(list(ok = FALSE, status = "bloqueada_formato_geopoint", mensagem = paste("Coordenada inválida: use apenas 2 a 4 números separados por espaço, com ponto decimal.", monitora_correcao_exemplos_formato_msg(tipo_base))))
    nums <- as.numeric(strsplit(vv, "\\s+", perl = TRUE)[[1L]])
    if (length(nums) < 2L || length(nums) > 4L || any(!is.finite(nums))) return(list(ok = FALSE, status = "bloqueada_formato_geopoint", mensagem = paste("Coordenada incompleta ou inválida.", monitora_correcao_exemplos_formato_msg(tipo_base))))
    if (nums[1L] < -90 || nums[1L] > 90 || nums[2L] < -180 || nums[2L] > 180) return(list(ok = FALSE, status = "bloqueada_formato_geopoint", mensagem = paste("Latitude/longitude fora de faixa.", monitora_correcao_exemplos_formato_msg(tipo_base))))
    return(list(ok = TRUE, status = "ok", mensagem = "geopoint válido"))
  }
  list(ok = TRUE, status = "ok", mensagem = "texto compatível")
}

monitora_correcao_validar_contrato_edicao <- function(dt, col, acao, valor_novo, corr_linha = NULL, dicionario = NULL, meta_xls = NULL) {
  col <- as.character(col)[1L]
  acao_norm <- monitora_correcao_acao_normalizar(acao)

  ### v2.6.1 alias_admin_persistencia_fix:
  ### A UI e o replay podem entregar a coluna física (ex.: "UA", "EA", "CICLO", "CAMPANHA"),
  ### enquanto o contrato SISMONITORA 2025 é canônico em minúsculas ("ua", "ea", "ciclo", "campanha").
  ### Antes, a validação encontrava a linha física bloqueada do dicionário e parava ali,
  ### sem consultar a exceção controlada canônica. Resultado: a operação era gravada,
  ### mas auditada como bloqueada_regra_xlsform_insegura e não persistia.
  ### A correção abaixo não destrava campos genericamente: ela só prefere o contrato
  ### canônico editável quando o atributo físico pertence aos aliases administrativos
  ### explicitamente autorizados em monitora_correcao_aliases_admin_sismonitora().
  col_real_admin <- tryCatch(monitora_correcao_coluna_real_admin_sismonitora(dt, col), error = function(e) NA_character_)
  if (!is.na(col_real_admin) && nzchar(col_real_admin) && col_real_admin %in% names(dt)) {
    col <- col_real_admin
  }

  if (is.na(col) || !nzchar(col) || !(col %in% names(dt))) return(list(ok = FALSE, status = "falha", mensagem = "coluna de destino inexistente"))
  contrato <- monitora_correcao_contrato_edicao(dt, meta_xls, dicionario)

  info_direta <- contrato[atributo_coluna_registros_corrig == col]
  alvo_norm <- unique(monitora_correcao_normalizar_nome_coluna(c(col, monitora_correcao_aliases_admin_sismonitora(col))))
  alvo_norm <- alvo_norm[!is.na(alvo_norm) & nzchar(alvo_norm)]
  info_alias <- if (length(alvo_norm)) contrato[monitora_correcao_normalizar_nome_coluna(atributo_coluna_registros_corrig) %in% alvo_norm] else data.table::data.table()

  info <- info_direta
  if (!nrow(info)) {
    info <- info_alias
  } else if (nrow(info_alias)) {
    info_alias_ok <- info_alias[painel_editavel %in% TRUE]
    if (!isTRUE(info$painel_editavel[1L]) && nrow(info_alias_ok)) {
      info <- info_alias_ok[1L]
    }
  }
  if (!nrow(info)) return(list(ok = FALSE, status = "bloqueada_contrato_ausente", mensagem = paste0("atributo sem contrato de edição: ", col)))
  info <- info[1L]
  if (!isTRUE(info$painel_editavel)) {
    return(list(ok = FALSE, status = "bloqueada_regra_xlsform_insegura", mensagem = paste0("edição bloqueada para '", col, "': ", info$painel_motivo_bloqueio)))
  }
  acoes <- monitora_correcao_split_serial(info$acoes_permitidas)
  if (!(acao_norm %in% acoes)) {
    return(list(ok = FALSE, status = "bloqueada_acao_incompativel", mensagem = paste0("ação '", acao_norm, "' não permitida para '", col, "' (tipo=", info$tipo_base_edicao, "; ações permitidas=", paste(acoes, collapse = ", "), ")")))
  }
  valor_original <- if (!is.null(corr_linha) && "valor_original_esperado" %in% names(corr_linha)) as.character(corr_linha$valor_original_esperado[1L]) else NA_character_

  valid_dinamico <- monitora_correcao_validar_dominio_dinamico_sismonitora(dt, col, info$tipo_base_edicao, info$xlsform_list_name, valor_novo, acao_norm)
  if (isTRUE(valid_dinamico$aplicou)) {
    if (!isTRUE(valid_dinamico$ok)) return(valid_dinamico[c("ok", "status", "mensagem")])
    valid_formato <- list(ok = TRUE, status = "ok", mensagem = valid_dinamico$mensagem)
  } else {
    valid_formato <- monitora_correcao_validar_formato_valor(valor_novo, info$tipo_base_edicao, acao_norm, info$xlsform_list_name, meta_xls, valor_original)
    if (!isTRUE(valid_formato$ok)) return(valid_formato)
  }
  valid_especifica <- monitora_correcao_validar_atributo_especifico_sismonitora_2025(col, valor_novo, acao_norm)
  if (!isTRUE(valid_especifica$ok)) return(valid_especifica)
  valid_formato
}

monitora_correcao_validar_destino_operacao <- function(dt, col, acao, valor_novo, corr_linha, dicionario = NULL, meta_xls = NULL) {
  col_real_admin <- tryCatch(monitora_correcao_coluna_real_admin_sismonitora(dt, col), error = function(e) NA_character_)
  if (!is.na(col_real_admin) && nzchar(col_real_admin) && col_real_admin %in% names(dt)) col <- col_real_admin
  if (is.na(col) || !nzchar(col) || !(col %in% names(dt))) {
    return(list(ok = FALSE, status = "falha", mensagem = "coluna de destino inexistente"))
  }
  valid_contrato <- monitora_correcao_validar_contrato_edicao(dt, col, acao, valor_novo, corr_linha, dicionario = dicionario, meta_xls = meta_xls)
  if (!isTRUE(valid_contrato$ok)) return(valid_contrato)
  papel <- monitora_correcao_papel_coluna_canonico(col)
  acao <- monitora_correcao_acao_normalizar(acao)
  valor <- as.character(valor_novo)[1L]
  valor_norm_tokens <- monitora_correcao_normalizar_nome_coluna(monitora_correcao_tokenizar(valor))
  forma_tokens <- setdiff(monitora_correcao_tokens_forma_vida_catalogo(), c("outra", "outros", "desconhecida"))
  forma_tokens_norm <- monitora_correcao_normalizar_nome_coluna(forma_tokens)
  habitos_norm <- monitora_correcao_normalizar_nome_coluna(monitora_correcao_tokens_habito_catalogo())
  token_pai <- if ("token_pai" %in% names(corr_linha)) as.character(corr_linha$token_pai[1L]) else NA_character_
  forma_escolhida <- if ("forma_valida_escolhida" %in% names(corr_linha)) as.character(corr_linha$forma_valida_escolhida[1L]) else NA_character_
  categoria_destino <- if ("categoria_destino" %in% names(corr_linha)) as.character(corr_linha$categoria_destino[1L]) else NA_character_
  tipo_corr <- if ("tipo_correcao" %in% names(corr_linha)) as.character(corr_linha$tipo_correcao[1L]) else ""

  grava_forma <- length(intersect(valor_norm_tokens, forma_tokens_norm)) > 0L
  if (acao %in% c("append_token", "adicionar_token") && monitora_correcao_normalizar_nome_coluna(forma_escolhida) %in% forma_tokens_norm) grava_forma <- TRUE
  grava_habito <- length(intersect(valor_norm_tokens, habitos_norm)) > 0L

  if (acao %in% c("append_token", "adicionar_token", "update", "substituir_valor") && isTRUE(grava_forma) && papel %in% c("especie_nome_popular", "atributo_dependente_habito")) {
    return(list(ok = FALSE, status = "bloqueada_destino_semantico", mensagem = paste0("token de forma de vida não pode ser gravado em coluna com papel ", papel, ": ", col)))
  }
  if (acao %in% c("append_token", "adicionar_token") && isTRUE(grava_forma) && !identical(papel, "lista_principal_forma_vida") && categoria_destino %in% c("nativa", "exotica", "seca_morta")) {
    return(list(ok = FALSE, status = "bloqueada_destino_semantico", mensagem = paste0("adição de forma de vida exige lista principal; papel encontrado=", papel, ": ", col)))
  }
  if (isTRUE(grava_habito) && !identical(papel, "atributo_dependente_habito")) {
    return(list(ok = FALSE, status = "bloqueada_destino_semantico", mensagem = paste0("hábito/atributo dependente exige coluna de hábito; papel encontrado=", papel, ": ", col)))
  }
  if (identical(papel, "lista_principal_forma_vida") && isTRUE(grava_habito)) {
    return(list(ok = FALSE, status = "bloqueada_destino_semantico", mensagem = "hábito não pode ser gravado em lista principal de forma de vida"))
  }
  list(ok = TRUE, status = "ok", mensagem = "destino semanticamente compatível")
}


monitora_correcao_atributo_lote_multicoletas_seguro <- function(dt, col, chaves = monitora_correcao_colunas_chave(dt)) {
  col <- as.character(col)[1L]
  if (is.na(col) || !nzchar(col) || !(col %in% names(dt))) {
    return(list(ok = FALSE, status = "falha", mensagem = "atributo inexistente para lote de COLETAS"))
  }
  if (monitora_correcao_coluna_protegida(col)) {
    return(list(ok = FALSE, status = "bloqueada_coluna_protegida", mensagem = paste0("coluna estrutural/protegida não pode ser alterada em lote: ", col)))
  }
  papel <- monitora_correcao_papel_coluna_canonico(col)
  if (identical(papel, "lista_principal_forma_vida")) {
    return(list(ok = TRUE, status = "ok_lista_principal_forma_vida", mensagem = paste0("lista principal de forma de vida elegível para operação tokenizada/contextual: ", col)))
  }
  if (papel %in% c("atributo_dependente_habito", "especie_nome_popular", "campo_superior_tipo_forma_vida")) {
    return(list(ok = FALSE, status = "bloqueada_destino_semantico", mensagem = paste0("atributo com papel '", papel, "' não é elegível para lote de COLETAS: ", col)))
  }
  col_norm <- monitora_correcao_normalizar_nome_coluna(col)
  padroes_bloqueio <- c("ponto_amostral", "ponto_metro", "tipo_forma_vida", "forma_vida", "especie", "especies", "exotica", "nativa", "seca_morta", "encostam", "vareta")
  if (any(grepl(paste(padroes_bloqueio, collapse = "|"), col_norm, perl = TRUE))) {
    return(list(ok = FALSE, status = "bloqueada_destino_semantico", mensagem = paste0("atributo parece ser de nível do ponto/forma de vida e foi bloqueado para lote de COLETAS: ", col)))
  }
  list(ok = TRUE, status = "ok", mensagem = "atributo elegível para lote de COLETAS")
}

monitora_correcao_valores_uniformes_linhas <- function(dt, linhas, col) {
  linhas <- unique(as.integer(linhas))
  linhas <- linhas[!is.na(linhas) & linhas >= 1L & linhas <= nrow(dt)]
  if (!length(linhas) || is.na(col) || !(col %in% names(dt))) {
    return(list(ok = FALSE, n_valores = NA_integer_, valor_resumo = NA_character_))
  }
  vals <- as.character(dt[[col]][linhas])
  vals_norm <- monitora_correcao_na_para_vazio(vals)
  vals_norm[is.na(vals_norm)] <- ""
  vals_unicos_norm <- unique(trimws(vals_norm))
  vals_unicos_norm <- vals_unicos_norm[!is.na(vals_unicos_norm)]
  vals_unicos_orig <- unique(vals)
  valor_resumo <- monitora_correcao_colapsar_contexto_valores(vals_unicos_orig)
  list(ok = length(vals_unicos_norm) <= 1L, n_valores = length(vals_unicos_norm), valor_resumo = valor_resumo)
}



monitora_correcao_acao_exclusao_coleta <- function(acao, tipo_correcao = "") {
  acao <- tolower(trimws(as.character(acao)[1L]))
  tipo_correcao <- tolower(trimws(as.character(tipo_correcao)[1L]))
  if (is.na(acao)) acao <- ""
  if (is.na(tipo_correcao)) tipo_correcao <- ""
  acao %in% c("excluir_coleta", "delete_coleta", "delete_collection", "excluir_registros_coleta") ||
    grepl("exclusao_coleta", tipo_correcao, fixed = TRUE) ||
    grepl("excluir_coleta", tipo_correcao, fixed = TRUE)
}

monitora_correcao_prevalidar_operacao <- function(dt, linha_corr, chaves, dicionario = NULL, indice = NULL) {
  col_req <- as.character(linha_corr$atributo_coluna_registros_corrig[1])
  col <- monitora_correcao_resolver_coluna(dt, col_req, dicionario)
  acao <- tolower(trimws(as.character(linha_corr$acao[1])))
  linhas <- monitora_correcao_localizar_linhas(dt, linha_corr, chaves, indice)
  n_esperado <- suppressWarnings(as.integer(linha_corr$n_linhas_esperado[1]))
  status <- "ok"; msg <- "OK"
  tipo_corr <- if ("tipo_correcao" %in% names(linha_corr)) tolower(trimws(as.character(linha_corr$tipo_correcao[1]))) else ""
  if (is.na(tipo_corr)) tipo_corr <- ""
  if (isTRUE(monitora_correcao_acao_exclusao_coleta(acao, tipo_corr))) {
    escopo_corr <- if ("escopo_aplicacao" %in% names(linha_corr)) tolower(trimws(as.character(linha_corr$escopo_aplicacao[1]))) else ""
    if (is.na(escopo_corr)) escopo_corr <- ""
    if (!identical(escopo_corr, "coleta_inteira")) {
      status <- "bloqueada_exclusao_coleta"; msg <- "exclusão de COLETA exige escopo_aplicacao='coleta_inteira'"
    } else if (is.na(chaves$coleta) || !(chaves$coleta %in% names(dt))) {
      status <- "falha"; msg <- "Coluna de COLETA não localizada; exclusão bloqueada"
    } else if (length(linhas) == 0L) {
      status <- "falha"; msg <- "Nenhuma linha-alvo localizada para exclusão da COLETA"
    } else if (!is.na(n_esperado) && n_esperado > 0L && length(linhas) != n_esperado) {
      status <- "falha"; msg <- paste0("n_linhas_alvo=", length(linhas), " diferente de n_linhas_esperado=", n_esperado, " para exclusão da COLETA")
    }
    return(data.table::data.table(status_prevalidacao = status, mensagem_prevalidacao = msg, atributo_resolvido = chaves$coleta, n_linhas = length(linhas)))
  }
  if (acao %in% c("recalcular_tipo_forma_vida", "atualizar_tipo_forma_vida")) {
    if (length(linhas) == 0L) {
      status <- "falha"; msg <- "Nenhuma linha-alvo localizada para recalcular tipo_forma_vida"
    } else if (is.na(chaves$tipo_forma_vida) || !(chaves$tipo_forma_vida %in% names(dt))) {
      status <- "falha"; msg <- "Coluna tipo_forma_vida/Encostam não localizada para recálculo"
    }
    return(data.table::data.table(status_prevalidacao = status, mensagem_prevalidacao = msg, atributo_resolvido = chaves$tipo_forma_vida, n_linhas = length(linhas)))
  }
  if (!is.na(col) && col %in% names(dt) && monitora_correcao_coluna_protegida(col)) {
    status <- "bloqueada_coluna_protegida"; msg <- paste0("Correção bloqueada: coluna estrutural/protegida não pode ser alterada: ", col)
  } else if (monitora_correcao_coluna_protegida(col_req)) {
    status <- "bloqueada_coluna_protegida"; msg <- paste0("Correção bloqueada: atributo solicitado é coluna estrutural/protegida: ", col_req)
  } else if (is.na(col) || !(col %in% names(dt))) {
    status <- "falha"; msg <- paste0("Coluna não encontrada: ", col_req)
  } else if (length(linhas) == 0L) {
    status <- "falha"; msg <- "Nenhuma linha-alvo localizada"
  } else if (!is.na(n_esperado) && n_esperado > 0L && length(linhas) != n_esperado) {
    status <- "falha"; msg <- paste0("n_linhas_alvo=", length(linhas), " diferente de n_linhas_esperado=", n_esperado)
  } else {
    if (grepl("lote_multicoletas", tipo_corr, fixed = TRUE)) {
      escopo_corr <- if ("escopo_aplicacao" %in% names(linha_corr)) tolower(trimws(as.character(linha_corr$escopo_aplicacao[1]))) else ""
      if (is.na(escopo_corr)) escopo_corr <- ""
      if (!identical(escopo_corr, "coleta_inteira")) {
        status <- "bloqueada_lote_multicoletas"; msg <- "lote de COLETAS exige escopo_aplicacao='coleta_inteira'"
      } else if (!(acao %in% c("update", "substituir_valor", "clear", "limpar"))) {
        status <- "bloqueada_lote_multicoletas"; msg <- "lote de COLETAS permite apenas substituir valor ou limpar valor"
      } else {
        valid_lote <- monitora_correcao_atributo_lote_multicoletas_seguro(dt, col, chaves)
        if (!isTRUE(valid_lote$ok)) {
          status <- valid_lote$status; msg <- valid_lote$mensagem
        } else {
          unif <- monitora_correcao_valores_uniformes_linhas(dt, linhas, col)
          if (!isTRUE(unif$ok)) {
            status <- "bloqueada_lote_multicoletas"
            msg <- paste0("atributo não é uniforme nas linhas-alvo da coleta; n_valores_atuais=", unif$n_valores, "; valor_resumo=", unif$valor_resumo)
          }
        }
      }
    }
    valid_dest <- if (identical(status, "ok")) monitora_correcao_validar_destino_operacao(dt, col, acao, linha_corr$valor_novo[1], linha_corr, dicionario) else list(ok = FALSE, status = status, mensagem = msg)
    if (!isTRUE(valid_dest$ok)) {
      status <- valid_dest$status; msg <- valid_dest$mensagem
    } else {
      valor_atual <- as.character(dt[[col]][linhas])
      esperado <- linha_corr$valor_original_esperado[1]
      precond <- monitora_publicacao_d_precondicao_valor_original(valor_atual, acao, linha_corr$valor_novo[1], esperado)
      if (!isTRUE(precond$ok)) {
        status <- "falha"
        msg <- precond$mensagem
      } else if (!identical(precond$mensagem, "OK")) {
        msg <- precond$mensagem
      }
    }
  }
  data.table::data.table(status_prevalidacao = status, mensagem_prevalidacao = msg, atributo_resolvido = col, n_linhas = length(linhas))
}


monitora_correcao_comparar_auditoria_semantica_pre_pos <- function(pre, pos, contexto = "correcoes") {
  pre <- data.table::as.data.table(pre)
  pos <- data.table::as.data.table(pos)
  chave_cols <- c("tipo_achado", "coluna", "linha_indice", "valor")
  for (cc in chave_cols) {
    if (!(cc %in% names(pre))) pre[, (cc) := NA_character_]
    if (!(cc %in% names(pos))) pos[, (cc) := NA_character_]
  }
  if ("linha_indice" %in% names(pre)) pre[, linha_indice := as.integer(linha_indice)]
  if ("linha_indice" %in% names(pos)) pos[, linha_indice := as.integer(linha_indice)]
  pre_key <- unique(pre[, ..chave_cols])
  pos_key <- unique(pos[, ..chave_cols])
  pre_key[, achado_pre := TRUE]
  pos_key[, achado_pos := TRUE]
  comp <- merge(pre_key, pos_key, by = chave_cols, all = TRUE)
  comp[is.na(achado_pre), achado_pre := FALSE]
  comp[is.na(achado_pos), achado_pos := FALSE]
  comp[, classificacao := data.table::fcase(
    achado_pre == FALSE & achado_pos == TRUE, "erro_introduzido_pela_correcao",
    achado_pre == TRUE & achado_pos == TRUE, "erro_pre_existente_mantido",
    achado_pre == TRUE & achado_pos == FALSE, "erro_pre_existente_corrigido",
    default = "sem_classificacao"
  )]
  arq <- file.path(if (exists("MONITORA_CORRECOES_DIR", inherits = TRUE)) get("MONITORA_CORRECOES_DIR", inherits = TRUE) else file.path("output", "correcoes_campos"), paste0("auditoria_semantica_papeis_colunas_pre_pos_", contexto, ".csv"))
  dir.create(dirname(arq), recursive = TRUE, showWarnings = FALSE)
  try(monitora_fwrite(comp, arq, na = ""), silent = TRUE)
  try(monitora_fwrite(comp, file.path(dirname(arq), "auditoria_semantica_papeis_colunas_pre_pos_ultima_execucao.csv"), na = ""), silent = TRUE)
  comp[]
}

monitora_correcao_auditar_lotes_multicoletas <- function(dt, corr, linhas_list, chaves, arquivo_correcao = NA_character_) {
  corr <- data.table::as.data.table(corr)
  if (!nrow(corr)) return(data.table::data.table())
  tipo <- if ("tipo_correcao" %in% names(corr)) tolower(trimws(as.character(corr$tipo_correcao))) else rep("", nrow(corr))
  idx_lote <- which(grepl("lote_multicoletas", tipo, fixed = TRUE))
  if (!length(idx_lote)) return(data.table::data.table())
  pegar <- function(ii, nm) if (nm %in% names(corr)) as.character(corr[[nm]][ii]) else NA_character_
  out <- vector("list", length(idx_lote))
  for (kk in seq_along(idx_lote)) {
    ii <- idx_lote[kk]
    linhas <- if (length(linhas_list) >= ii) as.integer(linhas_list[[ii]]) else integer(0)
    linhas <- linhas[!is.na(linhas) & linhas >= 1L & linhas <= nrow(dt)]
    col <- pegar(ii, "atributo_coluna_registros_corrig")
    unif <- if (col %in% names(dt)) monitora_correcao_valores_uniformes_linhas(dt, linhas, col) else list(ok = FALSE, n_valores = NA_integer_, valor_resumo = NA_character_)
    n_exp <- suppressWarnings(as.integer(pegar(ii, "n_linhas_esperado")))
    out[[kk]] <- data.table::data.table(
      id_correcao = pegar(ii, "id_correcao"),
      ordem_operacao = suppressWarnings(as.integer(pegar(ii, "ordem_operacao"))),
      tipo_correcao = pegar(ii, "tipo_correcao"),
      escopo_aplicacao = pegar(ii, "escopo_aplicacao"),
      coleta = pegar(ii, "coleta"),
      coleta_uuid = pegar(ii, "coleta_uuid"),
      UC = pegar(ii, "UC"),
      EA = pegar(ii, "EA"),
      UA = pegar(ii, "UA"),
      CICLO = pegar(ii, "CICLO"),
      CAMPANHA = pegar(ii, "CAMPANHA"),
      ANO = pegar(ii, "ANO"),
      `Data (data_hora)` = pegar(ii, "Data (data_hora)"),
      atributo_coluna_registros_corrig = col,
      acao = pegar(ii, "acao"),
      valor_original_esperado = pegar(ii, "valor_original_esperado"),
      valor_novo = pegar(ii, "valor_novo"),
      n_linhas_esperado = n_exp,
      n_linhas_alvo_localizadas = length(linhas),
      n_valores_atuais_no_atributo = unif$n_valores,
      atributo_uniforme_na_coleta = isTRUE(unif$ok),
      valor_atual_resumo = unif$valor_resumo,
      status_pre_auditoria_lote = ifelse(isTRUE(unif$ok) && !is.na(n_exp) && length(linhas) == n_exp, "ok", "revisar"),
      arquivo_correcao = arquivo_correcao
    )
  }
  aud <- data.table::rbindlist(out, fill = TRUE, use.names = TRUE)
  if (nrow(aud) > 0L) {
    saida <- file.path(MONITORA_LOG_DIR, paste0("auditoria_correcoes_campos_lote_multicoletas_", MONITORA_EXEC_ID, ".csv"))
    monitora_fwrite(aud, saida, na = "")
    monitora_fwrite(aud, file.path(MONITORA_CORRECOES_DIR, "auditoria_correcoes_campos_lote_multicoletas_ultima_execucao.csv"), na = "")
    nivel <- if (any(aud$status_pre_auditoria_lote != "ok", na.rm = TRUE)) "AVISO" else "INFO"
    monitora_log_registrar_evento(
      "correcoes_campos_lote_multicoletas", nivel, saida,
      paste0(nrow(aud), " operação(ões) de lote multicoletas pré-auditada(s)"),
      "uma operação por COLETA; alterações linha a linha continuam na auditoria principal"
    )
  }
  aud[]
}


### Movimento atômico em lote de formas de vida
### -------------------------------------------------------------------------
### Operação semântica para mover uma ou mais formas de vida entre listas
### nativa/exótica/seca-morta em várias COLETAS. O lote é validado antes de
### qualquer escrita. Ocorrências ambíguas são separadas, mantidas sem
### alteração e relatadas; as demais ocorrências migráveis seguem no lote.
monitora_correcao_eh_operacao_movimento_forma_vida_lote <- function(corr) {
  corr <- data.table::as.data.table(corr)
  if (!nrow(corr)) return(logical(0))
  idc <- if ("id_correcao" %in% names(corr)) trimws(as.character(corr$id_correcao)) else rep("", nrow(corr))
  tipo <- if ("tipo_correcao" %in% names(corr)) tolower(trimws(as.character(corr$tipo_correcao))) else rep("", nrow(corr))
  acao <- if ("acao" %in% names(corr)) tolower(trimws(as.character(corr$acao))) else rep("", nrow(corr))
  atributo <- if ("atributo_coluna_registros_corrig" %in% names(corr)) tolower(trimws(as.character(corr$atributo_coluna_registros_corrig))) else rep("", nrow(corr))
  grepl("^MVLOTE_", idc) |
    tipo %in% c("movimento_forma_vida_lote_atomico", "movimento_lote_forma_vida_atomico") |
    acao %in% c("mover_forma_vida_lote", "movimento_forma_vida_lote_atomico") |
    atributo %in% c("__mover_forma_vida_lote__", "__movimento_forma_vida_lote__")
}

monitora_correcao_forma_canonica_lote <- function(x) {
  x <- as.character(x)
  if (!length(x)) return(character(0))
  z <- tryCatch(monitora_relatorio_exoticas_normalizar_token(x), error = function(e) monitora_correcao_normalizar_nome_coluna(x))
  z <- monitora_correcao_normalizar_nome_coluna(z)
  z[z == "liana"] <- "lianas"
  z[z == "ervas_bromelioides"] <- "bromelioide"
  z[z == "erva_bromelioide"] <- "bromelioide"
  z[z == "bromelia"] <- "bromelioide"
  z[z == "bromelias"] <- "bromelioide"
  z[z == "cacto"] <- "cactacea"
  z[z == "cactos"] <- "cactacea"
  z[z == "orquideas"] <- "orquidea"
  z[z == "samambaias"] <- "samambaia"
  z <- unique(z[!is.na(z) & nzchar(z)])
  z
}

monitora_correcao_localizar_linhas_movimento_lote <- function(dt, linha_lote, chaves = monitora_correcao_colunas_chave(dt)) {
  dt <- data.table::as.data.table(dt)
  linha_lote <- data.table::as.data.table(linha_lote)
  if (!nrow(dt) || !nrow(linha_lote)) return(integer(0))

  ### v2.6.1: quando o MVLOTE representa a correção semântica de
  ### "desconhecida" em uma categoria-base, as linhas serializadas da
  ### sessão anterior não são estáveis entre versões/reruns. Nesse caso,
  ### o replay deve reconstruir o escopo por COLETA no estado corrente; a
  ### filtragem fina da ocorrência desconhecida é feita depois por
  ### monitora_correcao_linhas_desconhecida_categoria_base().
  mv_desc_vals <- character(0)
  for (cc_mv in intersect(c("escopo_diagnostico_mvlote", "categoria_base_diagnostica", "token_pai", "token_removido", "valor_original_esperado"), names(linha_lote))) {
    mv_desc_vals <- c(mv_desc_vals, as.character(linha_lote[[cc_mv]][1L]))
  }
  mv_desc_norm <- tryCatch(monitora_correcao_limpar_texto(mv_desc_vals), error = function(e) tolower(trimws(mv_desc_vals)))
  mv_desc_semantica <- any(mv_desc_norm %in% c("forma_vida_desconhecida_categoria_base", "forma_vida_desconhecida", "desconhecida", "desconhecido"), na.rm = TRUE)
  if (isTRUE(mv_desc_semantica) && !is.na(chaves$coleta) && chaves$coleta %in% names(dt) && "coleta" %in% names(linha_lote)) {
    coletas_desc <- monitora_correcao_parse_lista_serializada(linha_lote$coleta[1L])
    coletas_desc <- unique(as.character(coletas_desc))
    coletas_desc <- coletas_desc[!is.na(coletas_desc) & nzchar(trimws(coletas_desc))]
    if (length(coletas_desc)) {
      idx_coletas_desc <- which(as.character(dt[[chaves$coleta]]) %chin% coletas_desc)
      idx_coletas_desc <- unique(as.integer(idx_coletas_desc))
      if (length(idx_coletas_desc)) return(idx_coletas_desc)
    }
  }

  ### v2.6.1 diagnóstico: MVLOTE pode carregar um escopo diagnóstico já
  ### calculado pelo painel (ex.: nativa/desconhecida -> nativa/samambaia).
  ### Nesse caso, o alvo correto são as linhas diagnósticas serializadas, não
  ### as 101 linhas de cada COLETA do lote. Isto evita comparar 8*101 linhas
  ### contra o total real da ocorrência de desconhecida na categoria-base.
  linhas_serial <- integer(0)
  if ("linhas_alvo_serializadas" %in% names(linha_lote)) {
    linhas_serial <- suppressWarnings(as.integer(monitora_correcao_parse_serial_generico(linha_lote$linhas_alvo_serializadas[1L])))
  }
  if (!length(linhas_serial) && "linha_indice" %in% names(linha_lote)) {
    linhas_serial <- suppressWarnings(as.integer(monitora_correcao_parse_serial_generico(linha_lote$linha_indice[1L])))
  }
  linhas_serial <- unique(linhas_serial[!is.na(linhas_serial) & linhas_serial >= 1L & linhas_serial <= nrow(dt)])
  if (length(linhas_serial)) return(linhas_serial)

  if (is.na(chaves$coleta) || !(chaves$coleta %in% names(dt))) return(integer(0))
  coletas <- if ("coleta" %in% names(linha_lote)) monitora_correcao_parse_lista_serializada(linha_lote$coleta[1L]) else character(0)
  coletas <- unique(as.character(coletas))
  coletas <- coletas[!is.na(coletas) & nzchar(trimws(coletas))]
  if (!length(coletas)) return(integer(0))
  which(as.character(dt[[chaves$coleta]]) %chin% coletas)
}

monitora_correcao_dependentes_nao_migraveis_lote <- function(dt, linhas, origem, formas, dicionario = NULL) {
  dt <- data.table::as.data.table(dt)
  linhas <- unique(as.integer(linhas))
  linhas <- linhas[!is.na(linhas) & linhas >= 1L & linhas <= nrow(dt)]
  if (!length(linhas) || !length(formas)) return(data.table::data.table())
  out <- list()
  for (forma in formas) {
    deps <- tryCatch(monitora_correcao_colunas_dependentes_por_token(dt, origem, forma, dicionario), error = function(e) character(0))
    if (!length(deps)) next
    deps <- unique(deps[deps %in% names(dt)])
    if (!length(deps)) next
    nao_hab <- deps[!vapply(deps, function(cc) monitora_correcao_coluna_habito_segura(dt, cc, origem, forma), logical(1))]
    if (!length(nao_hab)) next
    for (dep in nao_hab) {
      vals <- as.character(dt[[dep]][linhas])
      preench <- !monitora_correcao_vazio_vec(vals)
      if (any(preench, na.rm = TRUE)) {
        out[[length(out) + 1L]] <- data.table::data.table(
          forma = forma,
          categoria_origem = origem,
          coluna_dependente = dep,
          n_linhas_com_valor = sum(preench, na.rm = TRUE),
          exemplo_valor = monitora_correcao_colapsar_contexto_valores(vals[preench], max_valores = 3L)
        )
      }
    }
  }
  if (length(out)) data.table::rbindlist(out, fill = TRUE, use.names = TRUE) else data.table::data.table()
}


monitora_correcao_valor_marcador_outra_especie <- function(x) {
  x <- as.character(x)
  if (!length(x)) return(logical(0))
  z <- monitora_correcao_normalizar_nome_coluna(x)
  z <- trimws(z)
  !monitora_correcao_vazio_vec(x) & grepl("(^|_)outra(_|$)|(^|_)outro(_|$)|outra_especie|outro_especie|outra_sp|outro_sp", z)
}

monitora_correcao_resolver_dependente_destino_lote <- function(dt, origem, destino, forma, coluna_origem, dicionario = NULL) {
  dt <- data.table::as.data.table(dt)
  if (monitora_correcao_vazio(coluna_origem) || !(coluna_origem %in% names(dt))) return(NA_character_)
  mapa <- tryCatch(monitora_correcao_mapa_colunas_canonicas(dt), error = function(e) data.table::data.table())
  if (!nrow(mapa)) return(NA_character_)
  src <- mapa[coluna_registros_corrig == coluna_origem]
  if (!nrow(src)) return(NA_character_)
  papel <- src$papel_coluna[1L]
  if (!papel %in% c("especie_nome_popular", "outro")) return(NA_character_)
  cand <- tryCatch(monitora_correcao_colunas_dependentes_por_token(dt, destino, forma, dicionario), error = function(e) character(0))
  cand <- unique(cand[cand %in% names(dt)])
  cand <- cand[!vapply(cand, function(cc) monitora_correcao_coluna_habito_segura(dt, cc, destino, forma), logical(1))]
  if (!length(cand)) return(NA_character_)
  meta <- mapa[coluna_registros_corrig %in% cand & papel_coluna == papel]
  if (!nrow(meta)) meta <- mapa[coluna_registros_corrig %in% cand]
  if (!nrow(meta)) return(NA_character_)
  src_norm <- src$coluna_norm[1L]
  src_outra <- grepl("outra|outro", src_norm)
  meta[, score := 0L]
  meta[grepl("outra|outro", coluna_norm) == src_outra, score := score + 100L]
  meta[papel_coluna == papel, score := score + 50L]
  meta[categoria == destino, score := score + 20L]
  meta[grepl("especie|nome_popular|outra|outro", coluna_norm), score := score + 10L]
  data.table::setorder(meta, -score, coluna_registros_corrig)
  top_score <- meta$score[1L]
  top <- meta[score == top_score]
  if (nrow(top) != 1L) return(NA_character_)
  top$coluna_registros_corrig[1L]
}

monitora_correcao_planejar_migracao_dependentes_lote <- function(dt, linhas, origem, destino, formas_efetivas, presenca, dicionario = NULL) {
  dt <- data.table::as.data.table(dt)
  plano <- data.table::data.table(
    forma = character(),
    linha_indice = integer(),
    atributo = character(),
    valor_antes = character(),
    valor_depois = character(),
    mensagem = character()
  )
  bloqueios <- data.table::data.table(
    forma = character(),
    linha_indice = integer(),
    coluna_dependente = character(),
    motivo = character(),
    exemplo_valor = character()
  )
  if (!length(linhas) || !length(formas_efetivas)) return(list(plano = plano, bloqueios = bloqueios))
  for (forma in formas_efetivas) {
    rows_f <- linhas[presenca[[forma]]]
    rows_f <- rows_f[!is.na(rows_f) & rows_f >= 1L & rows_f <= nrow(dt)]
    if (!length(rows_f)) next
    deps_src <- tryCatch(monitora_correcao_colunas_dependentes_por_token(dt, origem, forma, dicionario), error = function(e) character(0))
    deps_src <- unique(deps_src[deps_src %in% names(dt)])
    deps_src <- deps_src[!vapply(deps_src, function(cc) monitora_correcao_coluna_habito_segura(dt, cc, origem, forma), logical(1))]
    if (!length(deps_src)) next

    vals_por_dep <- lapply(deps_src, function(dep) as.character(dt[[dep]][rows_f]))
    names(vals_por_dep) <- deps_src
    for (k in seq_along(rows_f)) {
      rr <- rows_f[k]
      vals_linha <- vapply(vals_por_dep, function(v) v[k], character(1))
      preench <- !monitora_correcao_vazio_vec(vals_linha)
      if (!any(preench, na.rm = TRUE)) next
      vals_preench <- vals_linha[preench]
      marcadores <- monitora_correcao_valor_marcador_outra_especie(vals_preench)
      ha_valor_textual <- any(!marcadores, na.rm = TRUE)

      for (dep in names(vals_linha)[preench]) {
        val_src <- vals_linha[[dep]]
        if (monitora_correcao_vazio(val_src)) next
        if (isTRUE(monitora_correcao_valor_marcador_outra_especie(val_src))) {
          if (!isTRUE(ha_valor_textual)) {
            bloqueios <- data.table::rbindlist(list(
              bloqueios,
              data.table::data.table(
                forma = forma,
                linha_indice = as.integer(rr),
                coluna_dependente = dep,
                motivo = "marcador 'outra espécie' preenchido sem campo textual migrável na mesma linha",
                exemplo_valor = as.character(val_src)
              )
            ), fill = TRUE, use.names = TRUE)
          } else {
            plano <- data.table::rbindlist(list(
              plano,
              data.table::data.table(
                forma = forma,
                linha_indice = as.integer(rr),
                atributo = dep,
                valor_antes = as.character(val_src),
                valor_depois = NA_character_,
                mensagem = "Movimento em lote: marcador de outra espécie limpo após migração do texto associado"
              )
            ), fill = TRUE, use.names = TRUE)
          }
          next
        }

        dep_dst <- monitora_correcao_resolver_dependente_destino_lote(dt, origem, destino, forma, dep, dicionario)
        if (monitora_correcao_vazio(dep_dst) || !(dep_dst %in% names(dt))) {
          bloqueios <- data.table::rbindlist(list(
            bloqueios,
            data.table::data.table(
              forma = forma,
              linha_indice = as.integer(rr),
              coluna_dependente = dep,
              motivo = "coluna de destino correspondente não localizada com segurança",
              exemplo_valor = as.character(val_src)
            )
          ), fill = TRUE, use.names = TRUE)
          next
        }
        val_dst <- as.character(dt[[dep_dst]][rr])
        if (!monitora_correcao_vazio(val_dst) && !identical(monitora_correcao_na_para_vazio(val_dst), monitora_correcao_na_para_vazio(val_src))) {
          bloqueios <- data.table::rbindlist(list(
            bloqueios,
            data.table::data.table(
              forma = forma,
              linha_indice = as.integer(rr),
              coluna_dependente = dep_dst,
              motivo = "destino já preenchido com valor diferente",
              exemplo_valor = paste0("origem=", val_src, " | destino=", val_dst)
            )
          ), fill = TRUE, use.names = TRUE)
          next
        }
        if (monitora_correcao_na_para_vazio(val_dst) != monitora_correcao_na_para_vazio(val_src)) {
          plano <- data.table::rbindlist(list(
            plano,
            data.table::data.table(
              forma = forma,
              linha_indice = as.integer(rr),
              atributo = dep_dst,
              valor_antes = as.character(val_dst),
              valor_depois = as.character(val_src),
              mensagem = "Movimento em lote: espécie/outro dependente migrado para destino"
            )
          ), fill = TRUE, use.names = TRUE)
        }
        plano <- data.table::rbindlist(list(
          plano,
          data.table::data.table(
            forma = forma,
            linha_indice = as.integer(rr),
            atributo = dep,
            valor_antes = as.character(val_src),
            valor_depois = NA_character_,
            mensagem = "Movimento em lote: espécie/outro dependente limpo na origem após migração"
          )
        ), fill = TRUE, use.names = TRUE)
      }
    }
  }
  if (nrow(plano)) {
    plano_cmp <- plano[, .(valores = list(unique(monitora_correcao_na_para_vazio(valor_depois))), n_valores = data.table::uniqueN(monitora_correcao_na_para_vazio(valor_depois))), by = .(linha_indice, atributo)]
    conflito <- plano_cmp[n_valores > 1L]
    if (nrow(conflito)) {
      bloqueios <- data.table::rbindlist(list(
        bloqueios,
        conflito[, data.table::data.table(
          forma = NA_character_,
          linha_indice = as.integer(linha_indice),
          coluna_dependente = atributo,
          motivo = "plano de migração gerou mais de um valor final para a mesma célula",
          exemplo_valor = vapply(valores, function(v) paste(v, collapse = " | "), character(1))
        )]
      ), fill = TRUE, use.names = TRUE)
    }
  }
  list(plano = plano[], bloqueios = bloqueios[])
}


monitora_correcao_anexar_contexto_ambiguidades_mvlote <- function(dt, ambiguidades, id_correcao = NA_character_, origem = NA_character_, destino = NA_character_, chaves = monitora_correcao_colunas_chave(dt)) {
  dt <- data.table::as.data.table(dt)
  ambiguidades <- data.table::as.data.table(ambiguidades)
  if (!nrow(ambiguidades)) return(ambiguidades[])
  for (cc in c("forma", "linha_indice", "coluna_dependente", "motivo", "exemplo_valor")) if (!(cc %in% names(ambiguidades))) data.table::set(ambiguidades, j = cc, value = NA_character_)
  pegar <- function(col, idx) {
    if (is.na(col) || !nzchar(col) || !(col %in% names(dt))) return(rep(NA_character_, length(idx)))
    ok <- !is.na(idx) & idx >= 1L & idx <= nrow(dt)
    out <- rep(NA_character_, length(idx))
    out[ok] <- as.character(dt[[col]][idx[ok]])
    out
  }
  idx <- suppressWarnings(as.integer(ambiguidades$linha_indice))
  data.table::data.table(
    id_correcao = id_correcao,
    status = "ambigua_mantida_sem_migracao",
    categoria_origem = origem,
    categoria_destino = destino,
    forma = as.character(ambiguidades$forma),
    COLETA = pegar(chaves$coleta, idx),
    EA = pegar(chaves$ea, idx),
    UA = pegar(chaves$ua, idx),
    CICLO = pegar(chaves$ciclo, idx),
    CAMPANHA = pegar(chaves$campanha, idx),
    ANO = pegar(chaves$ano, idx),
    `Data (data_hora)` = pegar(chaves$data_hora, idx),
    ponto_amostral = pegar(chaves$ponto_amostral, idx),
    ponto_metro = pegar(chaves$ponto_metro, idx),
    linha_indice = idx,
    coluna_dependente = as.character(ambiguidades$coluna_dependente),
    motivo_ambiguidade = as.character(ambiguidades$motivo),
    valor_observado = as.character(ambiguidades$exemplo_valor),
    acao_adotada = "ocorrencia_ambigua_mantida_sem_alteracao; demais ocorrencias migraveis do lote continuam processadas"
  )[]
}

monitora_correcao_gravar_relatorio_ambiguidades_mvlote <- function(relatorio, contexto = "movimento_lote_forma_vida") {
  relatorio <- data.table::as.data.table(relatorio)
  if (!nrow(relatorio)) return(invisible(relatorio))
  exec_id <- if (exists("MONITORA_EXEC_ID", inherits = TRUE)) MONITORA_EXEC_ID else format(Sys.time(), "%Y%m%d_%H%M%S")
  arqs <- character(0)
  if (exists("MONITORA_LOG_DIR", inherits = TRUE)) {
    arqs <- c(arqs, file.path(MONITORA_LOG_DIR, paste0("relatorio_ambiguidades_", contexto, "_", exec_id, ".csv")))
  }
  if (exists("MONITORA_CORRECOES_DIR", inherits = TRUE)) {
    arqs <- c(arqs, file.path(MONITORA_CORRECOES_DIR, paste0("relatorio_ambiguidades_", contexto, "_ultima_execucao.csv")))
  }
  for (aa in arqs) {
    old <- data.table::data.table()
    if (file.exists(aa)) old <- tryCatch(data.table::fread(aa, encoding = "UTF-8", showProgress = FALSE), error = function(e) data.table::data.table())
    out <- data.table::rbindlist(list(old, relatorio), fill = TRUE, use.names = TRUE)
    out <- unique(out)
    try(monitora_fwrite(out, aa, na = ""), silent = TRUE)
  }
  if (exists("monitora_log_registrar_evento", mode = "function")) {
    monitora_log_registrar_evento(
      "movimento_lote_forma_vida_ambiguidades", "AVISO",
      if (length(arqs)) arqs[1L] else NA_character_,
      paste0(nrow(relatorio), " ocorrência(s) ambígua(s) mantida(s) sem migração no movimento em lote de formas de vida"),
      "demais ocorrências migráveis do lote foram preservadas para aplicação atômica"
    )
  }
  invisible(relatorio)
}

monitora_correcao_filtrar_presenca_mvlote <- function(presenca, linhas, ambiguidades) {
  presenca <- presenca
  ambiguidades <- data.table::as.data.table(ambiguidades)
  if (!length(presenca) || !nrow(ambiguidades)) return(presenca)
  for (rr in seq_len(nrow(ambiguidades))) {
    forma <- as.character(ambiguidades$forma[rr])
    idx_linha <- suppressWarnings(as.integer(ambiguidades$linha_indice[rr]))
    if (is.na(forma) || !nzchar(forma) || !(forma %in% names(presenca)) || is.na(idx_linha)) next
    pos <- which(as.integer(linhas) == idx_linha)
    if (length(pos)) presenca[[forma]][pos] <- FALSE
  }
  presenca
}

monitora_correcao_formas_efetivas_presenca <- function(presenca) {
  if (!length(presenca)) return(character(0))
  names(presenca)[vapply(presenca, function(x) any(isTRUE(x) | (is.logical(x) & x), na.rm = TRUE), logical(1))]
}



### Sanitização de dependentes históricos/atuais de forma de vida desconhecida
### -------------------------------------------------------------------------
### Contrato: fotos, imagens, uploads, anexos e descritores de "desconhecida"
### só são relevantes enquanto a sublista correspondente contém o token
### desconhecida. Quando o token é removido por movimento/triagem assistida,
### todos os dependentes da categoria devem ser limpos, independentemente da
### versão/fonte do XLSForm que originou a coluna.
monitora_correcao_tokens_desconhecida <- function() {
  c("desconhecida", "desconhecido", "indeterminada", "indeterminado", "nao_identificada", "nao_identificado", "não_identificada", "não_identificado")
}

monitora_correcao_categoria_variantes_norm <- function(categoria) {
  categoria <- tolower(trimws(as.character(categoria)[1L]))
  switch(
    categoria,
    nativa = c("nativa", "nativo", "planta_nativa", "plantas_nativas"),
    exotica = c("exotica", "exotico", "exoticas", "exoticos", "planta_exotica", "plantas_exoticas"),
    seca_morta = c("seca_morta", "seca", "morta", "seca_ou_morta", "seca_e_morta", "planta_seca", "planta_morta", "seca_morta"),
    character(0)
  )
}

monitora_correcao_colunas_desconhecida_por_categoria <- function(dt, categoria, dicionario = NULL) {
  dt <- data.table::as.data.table(dt)
  nms <- names(dt)
  nms_norm <- monitora_correcao_normalizar_nome_coluna(nms)
  cat_norms <- monitora_correcao_categoria_variantes_norm(categoria)
  cat_norms <- unique(monitora_correcao_normalizar_nome_coluna(cat_norms))
  tem_cat <- function(z) {
    if (!length(cat_norms)) return(rep(FALSE, length(z)))
    out <- rep(FALSE, length(z))
    for (cc in cat_norms) out <- out | grepl(cc, z, fixed = TRUE)
    out
  }
  eh_dep <- function(z) {
    grepl("desconhecid|indeterminad|nao_identific|nao identific|não_identific|não identific", z, perl = TRUE) &
      tem_cat(z) &
      grepl("foto|imagem|image|upload|arquivo|anexo|midia|media|descr|descricao|descritor|observ|obs", z, perl = TRUE) &
      !grepl("especie|especies|outra_sp|_sp($|_)", z, perl = TRUE)
  }

  resolver_dt <- function(vals) {
    vals <- unique(as.character(vals))
    vals <- vals[!is.na(vals) & nzchar(vals)]
    out <- character(0)
    for (vv in vals) {
      hit <- nms[nms == vv]
      if (length(hit)) out <- c(out, hit)
      vv_norm <- monitora_correcao_normalizar_nome_coluna(vv)
      hit2 <- which(nms_norm == vv_norm)
      if (length(hit2)) out <- c(out, nms[hit2])
      col_res <- tryCatch(monitora_correcao_resolver_coluna(dt, vv, dicionario), error = function(e) NA_character_)
      if (!is.na(col_res) && nzchar(col_res) && col_res %in% nms) out <- c(out, col_res)
    }
    unique(out[out %in% nms])
  }

  canon <- character(0)
  base <- paste0("foto_forma_vida_", categoria, "_desconhecida")
  if (identical(categoria, "seca_morta")) base <- "foto_forma_vida_seca_morta_desconhecida"
  canon <- c(
    base, paste0(base, "02"), paste0(base, "03"),
    paste0("amostragem/registro/", base), paste0("amostragem/registro/", base, "02"), paste0("amostragem/registro/", base, "03")
  )
  cols <- resolver_dt(canon)

  if (!is.null(dicionario) && nrow(data.table::as.data.table(dicionario)) > 0L) {
    d <- data.table::as.data.table(dicionario)
    for (cc in c("name", "caminho_registro", "label", "type", "list_name", "relevant")) if (!(cc %in% names(d))) d[, (cc) := NA_character_]
    d[, texto_busca := paste(name, caminho_registro, label, type, list_name, relevant, sep = " ")]
    d[, texto_norm := monitora_correcao_normalizar_nome_coluna(texto_busca)]
    d[, dep_desconhecida := eh_dep(texto_norm)]
    if (any(d$dep_desconhecida, na.rm = TRUE)) {
      cand_vals <- unique(unlist(d[dep_desconhecida == TRUE, .(name, caminho_registro, label)], use.names = FALSE))
      cols <- c(cols, resolver_dt(cand_vals))
    }
  }

  fallback <- nms[eh_dep(nms_norm)]
  cols <- unique(c(cols, fallback))
  cols <- cols[cols %in% nms]
  if (!length(cols)) {
    return(data.table::data.table(categoria = character(), coluna = character(), tipo_dependente = character(), origem_resolucao = character()))
  }
  tipo <- ifelse(grepl("foto|imagem|image", monitora_correcao_normalizar_nome_coluna(cols), perl = TRUE), "foto_imagem",
                 ifelse(grepl("upload|arquivo|anexo|midia|media", monitora_correcao_normalizar_nome_coluna(cols), perl = TRUE), "arquivo_midia", "descritor_obs"))
  data.table::data.table(
    categoria = categoria,
    coluna = cols,
    tipo_dependente = tipo,
    origem_resolucao = "xlsform_embutido_alias_label_fallback_normalizado"
  )[]
}

monitora_correcao_auditoria_desconhecida_vazia <- function() {
  data.table::data.table(
    id_correcao = character(), ordem_operacao = character(), status = character(), mensagem = character(),
    atributo = character(), linha_indice = integer(), valor_antes = character(), valor_depois = character(),
    arquivo_correcao = character(), categoria = character(), tipo_dependente = character(), origem_resolucao = character()
  )
}

monitora_correcao_sanitizar_dependentes_desconhecida <- function(dt, linhas = NULL, categorias = c("nativa", "exotica", "seca_morta"), id_correcao = NA_character_, ordem_operacao = NA_character_, arquivo_correcao = NA_character_, dicionario = NULL, registrar_preservadas = TRUE) {
  dt <- monitora_dt_referenciar(dt)
  if (is.null(linhas)) linhas <- seq_len(nrow(dt))
  linhas <- unique(as.integer(linhas))
  linhas <- linhas[!is.na(linhas) & linhas >= 1L & linhas <= nrow(dt)]
  audit <- monitora_correcao_auditoria_desconhecida_vazia()
  afetacoes <- data.table::data.table(linha_indice = integer(), atributo = character())
  if (!length(linhas)) return(list(dt = dt[], audit = audit, afetacoes = afetacoes, falha = FALSE))
  tokens_desc <- monitora_correcao_tokens_desconhecida()

  for (cat in categorias) {
    col_lista <- tryCatch(monitora_correcao_coluna_forma_vida(dt, cat), error = function(e) NA_character_)
    if (is.na(col_lista) || !(col_lista %in% names(dt))) next
    lista_vals <- as.character(dt[[col_lista]][linhas])
    tem_desc <- monitora_correcao_contem_qualquer_token_vec(lista_vals, tokens_desc)
    cols_dep <- monitora_correcao_colunas_desconhecida_por_categoria(dt, cat, dicionario)
    if (!nrow(cols_dep)) next
    for (ii in seq_len(nrow(cols_dep))) {
      dep_col <- cols_dep$coluna[ii]
      if (!(dep_col %in% names(dt)) || monitora_correcao_coluna_protegida(dep_col)) next
      antes <- as.character(dt[[dep_col]][linhas])
      preenchido <- !monitora_correcao_vazio_vec(antes)
      limpar <- preenchido & !tem_desc
      preservar <- preenchido & tem_desc
      if (any(limpar, na.rm = TRUE)) {
        idx <- linhas[limpar]
        depois <- rep(NA_character_, length(idx))
        data.table::set(dt, i = idx, j = dep_col, value = depois)
        audit <- data.table::rbindlist(list(audit, data.table::data.table(
          id_correcao = as.character(id_correcao),
          ordem_operacao = as.character(ordem_operacao),
          status = paste0(cols_dep$tipo_dependente[ii], "_desconhecida_limpa_token_removido"),
          mensagem = paste0("Dependente histórico/atual de forma de vida desconhecida limpo porque a categoria ", cat, " não contém mais o token desconhecida"),
          atributo = dep_col,
          linha_indice = idx,
          valor_antes = antes[limpar],
          valor_depois = depois,
          arquivo_correcao = as.character(arquivo_correcao),
          categoria = cat,
          tipo_dependente = cols_dep$tipo_dependente[ii],
          origem_resolucao = cols_dep$origem_resolucao[ii]
        )), fill = TRUE, use.names = TRUE)
        afetacoes <- data.table::rbindlist(list(afetacoes, data.table::data.table(linha_indice = idx, atributo = dep_col)), fill = TRUE, use.names = TRUE)
      }
      if (isTRUE(registrar_preservadas) && any(preservar, na.rm = TRUE)) {
        idxp <- linhas[preservar]
        audit <- data.table::rbindlist(list(audit, data.table::data.table(
          id_correcao = as.character(id_correcao),
          ordem_operacao = as.character(ordem_operacao),
          status = paste0(cols_dep$tipo_dependente[ii], "_desconhecida_preservada_token_ainda_presente"),
          mensagem = paste0("Dependente de forma de vida desconhecida preservado porque a categoria ", cat, " ainda contém o token desconhecida"),
          atributo = dep_col,
          linha_indice = idxp,
          valor_antes = antes[preservar],
          valor_depois = antes[preservar],
          arquivo_correcao = as.character(arquivo_correcao),
          categoria = cat,
          tipo_dependente = cols_dep$tipo_dependente[ii],
          origem_resolucao = cols_dep$origem_resolucao[ii]
        )), fill = TRUE, use.names = TRUE)
      }
    }
  }
  list(dt = dt[], audit = audit[], afetacoes = unique(afetacoes), falha = FALSE)
}

monitora_correcao_gravar_auditoria_sanitizacao_desconhecida <- function(audit) {
  audit <- data.table::as.data.table(audit)
  if (!nrow(audit)) return(invisible(audit))
  exec_id <- if (exists("MONITORA_EXEC_ID", inherits = TRUE)) MONITORA_EXEC_ID else format(Sys.time(), "%Y%m%d_%H%M%S")
  arqs <- character(0)
  if (exists("MONITORA_LOG_DIR", inherits = TRUE)) arqs <- c(arqs, file.path(MONITORA_LOG_DIR, paste0("auditoria_sanitizacao_forma_vida_desconhecida_", exec_id, ".csv")))
  if (exists("MONITORA_CORRECOES_DIR", inherits = TRUE)) arqs <- c(arqs, file.path(MONITORA_CORRECOES_DIR, "auditoria_sanitizacao_forma_vida_desconhecida_ultima_execucao.csv"))
  for (aa in arqs) try(monitora_fwrite(audit, aa, na = ""), silent = TRUE)
  invisible(audit)
}

monitora_correcao_aplicar_movimento_forma_vida_lote_atomico <- function(dt, linha_lote, chaves = monitora_correcao_colunas_chave(dt), indice = NULL, arquivo_correcao = NA_character_, dicionario = NULL, gravar_relatorio_ambiguidades = TRUE) {
  dt <- monitora_dt_referenciar(dt)
  linha_lote <- data.table::as.data.table(linha_lote)
  if (!nrow(linha_lote)) return(list(dt = dt[], audit = data.table::data.table(), linhas = integer(), afetacoes = data.table::data.table(linha_indice = integer(), atributo = character()), falha = FALSE))
  id_cor <- if ("id_correcao" %in% names(linha_lote)) as.character(linha_lote$id_correcao[1L]) else NA_character_
  ordem <- if ("ordem_operacao" %in% names(linha_lote)) linha_lote$ordem_operacao[1L] else NA_character_
  falhar <- function(status, msg, atributo = "__mover_forma_vida_lote__", extra = data.table::data.table()) {
    audit <- data.table::data.table(id_correcao = id_cor, ordem_operacao = ordem, status = status, mensagem = paste0("Movimento atômico em lote bloqueado: ", msg), atributo = atributo, linha_indice = NA_integer_, valor_antes = NA_character_, valor_depois = NA_character_, arquivo_correcao = arquivo_correcao)
    if (nrow(extra)) audit <- data.table::rbindlist(list(audit, extra), fill = TRUE, use.names = TRUE)
    list(dt = dt[], audit = audit[], linhas = integer(), afetacoes = data.table::data.table(linha_indice = integer(), atributo = character()), falha = TRUE)
  }
  origem <- if ("categoria_origem" %in% names(linha_lote)) tolower(trimws(as.character(linha_lote$categoria_origem[1L]))) else NA_character_
  destino <- if ("categoria_destino" %in% names(linha_lote)) tolower(trimws(as.character(linha_lote$categoria_destino[1L]))) else NA_character_
  if (monitora_correcao_vazio(origem) || monitora_correcao_vazio(destino) || !origem %in% c("nativa", "exotica", "seca_morta") || !destino %in% c("nativa", "exotica", "seca_morta")) {
    return(falhar("falha_lote_categoria", "origem/destino ausentes ou inválidos"))
  }
  if (identical(origem, destino)) return(falhar("falha_lote_origem_destino_iguais", "origem e destino são iguais"))
  col_origem <- tryCatch(monitora_correcao_coluna_forma_vida(dt, origem), error = function(e) NA_character_)
  col_destino <- tryCatch(monitora_correcao_coluna_forma_vida(dt, destino), error = function(e) NA_character_)
  if (is.na(col_origem) || !(col_origem %in% names(dt))) return(falhar("falha_coluna_origem", paste0("coluna de origem não localizada para ", origem)))
  if (is.na(col_destino) || !(col_destino %in% names(dt))) return(falhar("falha_coluna_destino", paste0("coluna de destino não localizada para ", destino)))
  if (monitora_correcao_coluna_protegida(col_origem) || monitora_correcao_coluna_protegida(col_destino)) return(falhar("bloqueada_coluna_protegida", "origem ou destino é coluna protegida"))

  linhas <- unique(as.integer(monitora_correcao_localizar_linhas_movimento_lote(dt, linha_lote, chaves)))
  linhas <- linhas[!is.na(linhas) & linhas >= 1L & linhas <= nrow(dt)]
  n_esperado <- if ("n_linhas_esperado" %in% names(linha_lote)) suppressWarnings(as.integer(linha_lote$n_linhas_esperado[1L])) else NA_integer_
  if (!length(linhas)) return(falhar("falha_sem_linhas", "nenhuma linha-alvo localizada nas COLETAS do lote"))
  if (!is.na(n_esperado) && n_esperado > 0L && length(linhas) != n_esperado) return(falhar("falha_n_linhas", paste0("n_linhas_alvo=", length(linhas), " diferente de n_linhas_esperado=", n_esperado)))

  formas_raw <- character(0)
  if ("token_pai" %in% names(linha_lote)) formas_raw <- c(formas_raw, monitora_correcao_parse_lista_serializada(linha_lote$token_pai[1L]))
  if (!length(formas_raw) && "valor_novo" %in% names(linha_lote)) formas_raw <- c(formas_raw, monitora_correcao_parse_lista_serializada(linha_lote$valor_novo[1L]))
  formas_raw <- unique(trimws(as.character(formas_raw)))
  formas_raw <- formas_raw[!is.na(formas_raw) & nzchar(formas_raw)]
  mover_todas <- any(formas_raw %in% c("__todas__", "todas", "todos", "all"))
  origem_vals <- as.character(dt[[col_origem]][linhas])
  if (isTRUE(mover_todas)) {
    formas <- unique(unlist(lapply(origem_vals, monitora_correcao_tokenizar), use.names = FALSE))
  } else {
    formas <- formas_raw
  }
  formas <- monitora_correcao_forma_canonica_lote(formas)
  formas <- setdiff(formas, c("", "na", "nan", "null", "desconhecida", "desconhecido", "outra", "outro", "outras", "outros", "outra_forma_vida", "forma_vida_outros", "nativa", "exotica", "seca", "morta", "seca_morta", "solo_nu", "serrapilheira", "fragmentos_botanicos", "material_inundado"))
  formas <- unique(formas[!is.na(formas) & nzchar(formas)])
  if (!length(formas)) return(falhar("falha_lote_sem_formas", "nenhuma forma de vida válida informada ou encontrada na origem"))

  presenca <- list()
  for (forma in formas) {
    toks <- unique(c(forma, monitora_correcao_sinonimos_forma(forma)))
    hit <- rep(FALSE, length(linhas))
    for (tok in toks) hit <- hit | monitora_correcao_token_presente_vec(origem_vals, tok)
    if (any(hit, na.rm = TRUE)) presenca[[forma]] <- hit
  }
  formas_efetivas <- names(presenca)
  if (!length(formas_efetivas)) return(falhar("bloqueada_operacao_repetida_sem_efeito", "nenhuma das formas selecionadas está presente na origem; possível operação repetida ou seleção incompatível"))

  ambiguidades_mvlote <- data.table::data.table()
  presenca_aplicavel <- presenca

  plano_dep_res <- monitora_correcao_planejar_migracao_dependentes_lote(
    dt = dt,
    linhas = linhas,
    origem = origem,
    destino = destino,
    formas_efetivas = formas_efetivas,
    presenca = presenca_aplicavel,
    dicionario = dicionario
  )
  plano_dep <- plano_dep_res$plano
  bloqueios_dep <- plano_dep_res$bloqueios
  if (nrow(bloqueios_dep)) {
    ambiguidades_mvlote <- data.table::rbindlist(list(
      ambiguidades_mvlote,
      monitora_correcao_anexar_contexto_ambiguidades_mvlote(dt, bloqueios_dep, id_cor, origem, destino, chaves)
    ), fill = TRUE, use.names = TRUE)
    presenca_aplicavel <- monitora_correcao_filtrar_presenca_mvlote(presenca_aplicavel, linhas, bloqueios_dep)
    formas_efetivas <- monitora_correcao_formas_efetivas_presenca(presenca_aplicavel)
    if (length(formas_efetivas)) {
      plano_dep_res <- monitora_correcao_planejar_migracao_dependentes_lote(
        dt = dt,
        linhas = linhas,
        origem = origem,
        destino = destino,
        formas_efetivas = formas_efetivas,
        presenca = presenca_aplicavel,
        dicionario = dicionario
      )
      plano_dep <- plano_dep_res$plano
      bloqueios_dep <- plano_dep_res$bloqueios
      if (nrow(bloqueios_dep)) {
        ambiguidades_mvlote <- data.table::rbindlist(list(
          ambiguidades_mvlote,
          monitora_correcao_anexar_contexto_ambiguidades_mvlote(dt, bloqueios_dep, id_cor, origem, destino, chaves)
        ), fill = TRUE, use.names = TRUE)
        presenca_aplicavel <- monitora_correcao_filtrar_presenca_mvlote(presenca_aplicavel, linhas, bloqueios_dep)
        formas_efetivas <- monitora_correcao_formas_efetivas_presenca(presenca_aplicavel)
        plano_dep_res <- monitora_correcao_planejar_migracao_dependentes_lote(
          dt = dt,
          linhas = linhas,
          origem = origem,
          destino = destino,
          formas_efetivas = formas_efetivas,
          presenca = presenca_aplicavel,
          dicionario = dicionario
        )
        plano_dep <- plano_dep_res$plano
      }
    }
  }
  if (!length(formas_efetivas)) {
    if (nrow(ambiguidades_mvlote) && isTRUE(gravar_relatorio_ambiguidades)) monitora_correcao_gravar_relatorio_ambiguidades_mvlote(ambiguidades_mvlote)
    extra <- if (nrow(ambiguidades_mvlote)) ambiguidades_mvlote[, data.table::data.table(
      id_correcao = id_cor,
      ordem_operacao = ordem,
      status = "ambigua_mantida_sem_migracao",
      mensagem = paste0("Ocorrência ambígua mantida sem migração: forma=", forma, "; coluna=", coluna_dependente, "; motivo=", motivo_ambiguidade),
      atributo = coluna_dependente,
      linha_indice = as.integer(linha_indice),
      valor_antes = valor_observado,
      valor_depois = valor_observado,
      arquivo_correcao = arquivo_correcao
    )] else data.table::data.table()
    return(falhar("bloqueada_sem_ocorrencias_migraveis", "todas as ocorrências do lote eram ambíguas; nenhuma alteração foi aplicada", extra = extra))
  }

  final_origem <- origem_vals
  final_destino <- as.character(dt[[col_destino]][linhas])
  for (forma in formas_efetivas) {
    toks <- unique(c(forma, monitora_correcao_sinonimos_forma(forma)))
    idx_f <- which(presenca_aplicavel[[forma]])
    if (length(idx_f)) {
      for (tok in toks) final_origem[idx_f] <- vapply(final_origem[idx_f], monitora_correcao_remove_token_valor, character(1), token = tok)
      final_destino[idx_f] <- vapply(final_destino[idx_f], monitora_correcao_append_token_valor, character(1), token = forma)
    }
  }

  habito_padrao <- if ("habito_escolhido" %in% names(linha_lote)) trimws(as.character(linha_lote$habito_escolhido[1L])) else ""
  if (is.na(habito_padrao)) habito_padrao <- ""
  habitos_validos <- c("terrestre", "epifita", "rupicola")
  plano_hab <- data.table::data.table(linha_indice = integer(), atributo = character(), valor_antes = character(), valor_depois = character(), mensagem = character())
  bloqueios_hab <- list()
  formas_cond <- intersect(formas_efetivas, c("bromelioide", "erva_bromelioide", "cactacea", "orquidea", "samambaia"))
  for (forma in formas_cond) {
    rows_f <- linhas[presenca_aplicavel[[forma]]]
    for (rr in rows_f) {
      dep_origem <- tryCatch(monitora_correcao_resolver_coluna_habito(dt, origem, forma, dicionario, linha = rr, meta_xls = NULL), error = function(e) NA_character_)
      dep_destino <- tryCatch(monitora_correcao_resolver_coluna_habito(dt, destino, forma, dicionario, linha = rr, meta_xls = NULL), error = function(e) NA_character_)
      if (!monitora_correcao_coluna_habito_segura(dt, dep_destino, destino, forma) || identical(dep_destino, col_destino)) {
        bloqueios_hab[[length(bloqueios_hab) + 1L]] <- data.table::data.table(forma = forma, linha_indice = rr, atributo = dep_destino, motivo = paste0("coluna de hábito do destino não localizada com segurança para ", forma))
        next
      }
      origem_segura <- monitora_correcao_coluna_habito_segura(dt, dep_origem, origem, forma) && !identical(dep_origem, col_origem)
      valor_origem_hab <- if (isTRUE(origem_segura)) as.character(dt[[dep_origem]][rr]) else NA_character_
      valor_dest_hab <- as.character(dt[[dep_destino]][rr])
      candidato <- if (!monitora_correcao_vazio(valor_origem_hab)) valor_origem_hab else habito_padrao
      candidato <- trimws(as.character(candidato))
      if (is.na(candidato) || !nzchar(candidato) || !(candidato %in% habitos_validos)) {
        bloqueios_hab[[length(bloqueios_hab) + 1L]] <- data.table::data.table(forma = forma, linha_indice = rr, atributo = dep_destino, motivo = paste0("hábito obrigatório ausente para ", forma, "; informe hábito padrão ou preencha a origem"))
        next
      }
      if (!monitora_correcao_vazio(valor_dest_hab) && !identical(monitora_correcao_na_para_vazio(valor_dest_hab), monitora_correcao_na_para_vazio(candidato))) {
        bloqueios_hab[[length(bloqueios_hab) + 1L]] <- data.table::data.table(forma = forma, linha_indice = rr, atributo = dep_destino, motivo = paste0("hábito de destino já preenchido com valor diferente para ", forma))
        next
      }
      if (monitora_correcao_na_para_vazio(valor_dest_hab) != monitora_correcao_na_para_vazio(candidato)) {
        plano_hab <- data.table::rbindlist(list(plano_hab, data.table::data.table(linha_indice = rr, atributo = dep_destino, valor_antes = valor_dest_hab, valor_depois = candidato, mensagem = "Movimento em lote: hábito obrigatório copiado/preenchido no destino")), fill = TRUE, use.names = TRUE)
      }
      if (isTRUE(origem_segura) && !monitora_correcao_vazio(valor_origem_hab)) {
        plano_hab <- data.table::rbindlist(list(plano_hab, data.table::data.table(linha_indice = rr, atributo = dep_origem, valor_antes = valor_origem_hab, valor_depois = NA_character_, mensagem = "Movimento em lote: hábito/dependente da origem limpo após migração")), fill = TRUE, use.names = TRUE)
      }
    }
  }
  if (length(bloqueios_hab)) {
    bb <- data.table::rbindlist(bloqueios_hab, fill = TRUE, use.names = TRUE)
    bb_rep <- data.table::data.table(
      forma = as.character(bb$forma),
      linha_indice = as.integer(bb$linha_indice),
      coluna_dependente = as.character(bb$atributo),
      motivo = as.character(bb$motivo),
      exemplo_valor = NA_character_
    )
    ambiguidades_mvlote <- data.table::rbindlist(list(
      ambiguidades_mvlote,
      monitora_correcao_anexar_contexto_ambiguidades_mvlote(dt, bb_rep, id_cor, origem, destino, chaves)
    ), fill = TRUE, use.names = TRUE)
    ### Restaura os tokens principais nas ocorrências com hábito ambíguo para que
    ### elas permaneçam intactas; demais ocorrências migráveis seguem no lote.
    for (rr in seq_len(nrow(bb_rep))) {
      forma_bb <- as.character(bb_rep$forma[rr])
      linha_bb <- suppressWarnings(as.integer(bb_rep$linha_indice[rr]))
      pos <- which(as.integer(linhas) == linha_bb)
      if (length(pos) && forma_bb %in% names(presenca_aplicavel)) {
        presenca_aplicavel[[forma_bb]][pos] <- FALSE
        final_origem[pos] <- origem_vals[pos]
        final_destino[pos] <- as.character(dt[[col_destino]][linhas[pos]])
      }
    }
    formas_efetivas <- monitora_correcao_formas_efetivas_presenca(presenca_aplicavel)
    if (nrow(plano_dep) && "forma" %in% names(plano_dep)) {
      pares_bloq <- unique(bb_rep[, .(forma = as.character(forma), linha_indice = as.integer(linha_indice))])
      plano_dep <- merge(
        plano_dep,
        pares_bloq[, .bloq := TRUE],
        by = c("forma", "linha_indice"),
        all.x = TRUE,
        sort = FALSE
      )
      plano_dep <- plano_dep[is.na(.bloq)]
      plano_dep[, .bloq := NULL]
    }
    if (!length(formas_efetivas)) {
      if (nrow(ambiguidades_mvlote) && isTRUE(gravar_relatorio_ambiguidades)) monitora_correcao_gravar_relatorio_ambiguidades_mvlote(ambiguidades_mvlote)
      extra <- ambiguidades_mvlote[, data.table::data.table(id_correcao = id_cor, ordem_operacao = ordem, status = "ambigua_mantida_sem_migracao", mensagem = paste0("Ocorrência ambígua mantida sem migração: forma=", forma, "; motivo=", motivo_ambiguidade), atributo = coluna_dependente, linha_indice = as.integer(linha_indice), valor_antes = valor_observado, valor_depois = valor_observado, arquivo_correcao = arquivo_correcao)]
      return(falhar("bloqueada_sem_ocorrencias_migraveis", "todas as ocorrências do lote eram ambíguas; nenhuma alteração foi aplicada", extra = extra))
    }
  }

  registrar <- function(status, msg, atributo, idx, antes, depois) {
    data.table::data.table(id_correcao = id_cor, ordem_operacao = ordem, status = status, mensagem = msg, atributo = atributo, linha_indice = as.integer(idx), valor_antes = as.character(antes), valor_depois = as.character(depois), arquivo_correcao = arquivo_correcao)
  }
  audit <- data.table::data.table(); afetacoes <- data.table::data.table(linha_indice = integer(), atributo = character())
  mudou_origem <- monitora_correcao_na_para_vazio(origem_vals) != monitora_correcao_na_para_vazio(final_origem)
  mudou_destino <- monitora_correcao_na_para_vazio(as.character(dt[[col_destino]][linhas])) != monitora_correcao_na_para_vazio(final_destino)
  if (any(mudou_origem, na.rm = TRUE)) {
    data.table::set(dt, i = linhas[mudou_origem], j = col_origem, value = final_origem[mudou_origem])
    audit <- data.table::rbindlist(list(audit, registrar("aplicada_atomica", "Movimento em lote: token(s) removido(s) da categoria de origem", col_origem, linhas[mudou_origem], origem_vals[mudou_origem], final_origem[mudou_origem])), fill = TRUE, use.names = TRUE)
    afetacoes <- data.table::rbindlist(list(afetacoes, data.table::data.table(linha_indice = linhas[mudou_origem], atributo = col_origem)), fill = TRUE, use.names = TRUE)
  }
  if (any(mudou_destino, na.rm = TRUE)) {
    antes_destino <- as.character(dt[[col_destino]][linhas])
    data.table::set(dt, i = linhas[mudou_destino], j = col_destino, value = final_destino[mudou_destino])
    audit <- data.table::rbindlist(list(audit, registrar("aplicada_atomica", "Movimento em lote: forma(s) garantida(s) na categoria de destino", col_destino, linhas[mudou_destino], antes_destino[mudou_destino], final_destino[mudou_destino])), fill = TRUE, use.names = TRUE)
    afetacoes <- data.table::rbindlist(list(afetacoes, data.table::data.table(linha_indice = linhas[mudou_destino], atributo = col_destino)), fill = TRUE, use.names = TRUE)
  }
  if (nrow(plano_hab)) {
    plano_hab <- unique(plano_hab, by = c("linha_indice", "atributo", "valor_depois"))
    for (cc in unique(plano_hab$atributo)) {
      z <- plano_hab[atributo == cc]
      data.table::set(dt, i = z$linha_indice, j = cc, value = z$valor_depois)
      audit <- data.table::rbindlist(list(audit, registrar("aplicada_atomica", z$mensagem, cc, z$linha_indice, z$valor_antes, z$valor_depois)), fill = TRUE, use.names = TRUE)
      afetacoes <- data.table::rbindlist(list(afetacoes, data.table::data.table(linha_indice = z$linha_indice, atributo = cc)), fill = TRUE, use.names = TRUE)
    }
  }
  if (nrow(plano_dep)) {
    plano_dep <- unique(plano_dep, by = c("linha_indice", "atributo", "valor_depois"))
    for (cc in unique(plano_dep$atributo)) {
      z <- plano_dep[atributo == cc]
      data.table::set(dt, i = z$linha_indice, j = cc, value = z$valor_depois)
      audit <- data.table::rbindlist(list(audit, registrar("aplicada_atomica", z$mensagem, cc, z$linha_indice, z$valor_antes, z$valor_depois)), fill = TRUE, use.names = TRUE)
      afetacoes <- data.table::rbindlist(list(afetacoes, data.table::data.table(linha_indice = z$linha_indice, atributo = cc)), fill = TRUE, use.names = TRUE)
    }
  }
  tipo_col <- chaves$tipo_forma_vida
  if (!is.na(tipo_col) && tipo_col %in% names(dt)) {
    antes_tipo <- as.character(dt[[tipo_col]][linhas])
    monitora_correcao_recalcular_tipo_forma_vida(dt, linhas)
    depois_tipo <- as.character(dt[[tipo_col]][linhas])
    mudou_tipo <- monitora_correcao_na_para_vazio(antes_tipo) != monitora_correcao_na_para_vazio(depois_tipo)
    if (any(mudou_tipo, na.rm = TRUE)) {
      audit <- data.table::rbindlist(list(audit, registrar("aplicada_atomica", "Movimento em lote: tipo_forma_vida recalculado após origem/destino", tipo_col, linhas[mudou_tipo], antes_tipo[mudou_tipo], depois_tipo[mudou_tipo])), fill = TRUE, use.names = TRUE)
      afetacoes <- data.table::rbindlist(list(afetacoes, data.table::data.table(linha_indice = linhas[mudou_tipo], atributo = tipo_col)), fill = TRUE, use.names = TRUE)
    }
  }
  if (!nrow(audit)) {
    audit <- registrar("ignorada_operacao_repetida_sem_efeito", "Movimento em lote ignorado: origem, destino e dependentes já estavam coerentes", "__mover_forma_vida_lote__", linhas, NA_character_, NA_character_)
    return(list(dt = dt[], audit = audit[], linhas = linhas, afetacoes = data.table::data.table(linha_indice = integer(), atributo = character()), falha = FALSE))
  }
  if (nrow(ambiguidades_mvlote)) {
    if (isTRUE(gravar_relatorio_ambiguidades)) monitora_correcao_gravar_relatorio_ambiguidades_mvlote(ambiguidades_mvlote)
    audit_amb <- ambiguidades_mvlote[, data.table::data.table(
      id_correcao = id_cor,
      ordem_operacao = ordem,
      status = "ambigua_mantida_sem_migracao",
      mensagem = paste0("Movimento em lote: ocorrência ambígua mantida sem migração; forma=", forma, "; motivo=", motivo_ambiguidade),
      atributo = coluna_dependente,
      linha_indice = as.integer(linha_indice),
      valor_antes = valor_observado,
      valor_depois = valor_observado,
      arquivo_correcao = arquivo_correcao,
      COLETA = COLETA,
      EA = EA,
      UA = UA,
      CICLO = CICLO,
      CAMPANHA = CAMPANHA,
      ANO = ANO,
      `Data (data_hora)` = `Data (data_hora)`,
      `Ponto amostral` = ponto_amostral,
      `Ponto metro` = ponto_metro
    )]
    audit <- data.table::rbindlist(list(audit, audit_amb), fill = TRUE, use.names = TRUE)
  }
  audit[, formas_movidas := monitora_correcao_colapsar_lista_serializada(formas_efetivas)]
  list(dt = dt[], audit = audit[], linhas = unique(linhas), afetacoes = unique(afetacoes), falha = FALSE)
}

monitora_correcao_aplicar_movimentos_forma_vida_lote_atomicos <- function(dt, corr, chaves = monitora_correcao_colunas_chave(dt), indice = NULL, arquivo_correcao = NA_character_, dicionario = NULL) {
  dt <- monitora_dt_referenciar(dt)
  corr <- data.table::copy(data.table::as.data.table(corr))
  if (!nrow(corr)) return(list(dt = dt[], corr = corr, audit = data.table::data.table(), linhas = integer(), afetacoes = data.table::data.table(linha_indice = integer(), atributo = character()), falha = FALSE, n_grupos = 0L))
  if (!("ordem_tmp" %in% names(corr))) corr[, ordem_tmp := seq_len(.N)]
  corr <- monitora_correcao_normalizar_mvlote_sessao(corr, contexto = arquivo_correcao)
  audit_norm_mvlote <- attr(corr, "auditoria_normalizacao_mvlote")
  if (is.null(audit_norm_mvlote)) audit_norm_mvlote <- data.table::data.table()
  if (!("id_correcao" %in% names(corr))) corr[, id_correcao := NA_character_]
  data.table::set(corr, j = ".grupo_mvlote_atom", value = data.table::fifelse(!is.na(corr$id_correcao) & nzchar(as.character(corr$id_correcao)), as.character(corr$id_correcao), paste0("__linha_", corr$ordem_tmp)))
  idx <- which(monitora_correcao_eh_operacao_movimento_forma_vida_lote(corr))
  if (!length(idx)) {
    if (".grupo_mvlote_atom" %in% names(corr)) corr[, .grupo_mvlote_atom := NULL]
    return(list(dt = dt[], corr = corr, audit = audit_norm_mvlote, linhas = integer(), afetacoes = data.table::data.table(linha_indice = integer(), atributo = character()), falha = FALSE, n_grupos = 0L))
  }
  grupos <- unique(corr[idx, .grupo_mvlote_atom])
  audit <- data.table::as.data.table(audit_norm_mvlote); linhas <- integer(); afetacoes <- data.table::data.table(linha_indice = integer(), atributo = character()); falha <- FALSE
  for (gid in grupos) {
    grp <- corr[.grupo_mvlote_atom == gid]
    linha <- data.table::copy(grp[1L])
    if ("tipo_correcao" %in% names(linha)) linha[, tipo_correcao := "movimento_forma_vida_lote_atomico"]
    if ("acao" %in% names(linha)) linha[, acao := "mover_forma_vida_lote"]
    if ("atributo_coluna_registros_corrig" %in% names(linha)) linha[, atributo_coluna_registros_corrig := "__mover_forma_vida_lote__"]
    res <- monitora_correcao_aplicar_movimento_forma_vida_lote_atomico(dt, linha, chaves, indice, arquivo_correcao, dicionario, gravar_relatorio_ambiguidades = TRUE)
    dt <- res$dt
    if (nrow(res$audit)) audit <- data.table::rbindlist(list(audit, res$audit), fill = TRUE, use.names = TRUE)
    if (length(res$linhas)) linhas <- unique(c(linhas, res$linhas))
    if (nrow(res$afetacoes)) afetacoes <- data.table::rbindlist(list(afetacoes, res$afetacoes), fill = TRUE, use.names = TRUE)
    status_res <- if (!is.null(res$audit) && data.table::is.data.table(res$audit) && "status" %in% names(res$audit)) res$audit$status else character(0)
    falha_res <- isTRUE(res$falha) && isTRUE(monitora_correcao_status_mvlote_fatal(status_res))
    falha <- isTRUE(falha) || isTRUE(falha_res)
  }
  corr_out <- corr[!(.grupo_mvlote_atom %in% grupos)]
  corr_out[, .grupo_mvlote_atom := NULL]
  corr[, .grupo_mvlote_atom := NULL]
  list(dt = dt[], corr = corr_out[], audit = audit[], linhas = linhas, afetacoes = unique(afetacoes), falha = falha, n_grupos = length(grupos))
}

### v2.6.1: MVLOTE generalizado (movimento entre categorias e substituição intralista)
### -------------------------------------------------------------------------
### Esta definição substitui a versão anterior por busca dinâmica em runtime.
### Permite origem==destino quando a forma de origem difere da forma de destino
### (ex.: nativa/desconhecida -> nativa/samambaia), mantendo bloqueio apenas para
### operação realmente nula. A auditoria continua linha-a-linha; a aplicação é
### vetorizada por operação semântica.
monitora_correcao_aplicar_movimento_forma_vida_lote_atomico <- function(dt, linha_lote, chaves = monitora_correcao_colunas_chave(dt), indice = NULL, arquivo_correcao = NA_character_, dicionario = NULL, gravar_relatorio_ambiguidades = TRUE) {
  dt <- monitora_dt_referenciar(dt)
  linha_lote <- data.table::as.data.table(linha_lote)
  vazio_res <- list(dt = dt[], audit = data.table::data.table(), linhas = integer(), afetacoes = data.table::data.table(linha_indice = integer(), atributo = character()), falha = FALSE)
  if (!nrow(linha_lote)) return(vazio_res)
  id_cor <- if ("id_correcao" %in% names(linha_lote)) as.character(linha_lote$id_correcao[1L]) else NA_character_
  ordem <- if ("ordem_operacao" %in% names(linha_lote)) linha_lote$ordem_operacao[1L] else NA_character_
  falhar <- function(status, msg, atributo = "__mover_forma_vida_lote__", extra = data.table::data.table()) {
    audit <- data.table::data.table(id_correcao = id_cor, ordem_operacao = ordem, status = status, mensagem = paste0("Movimento/substituição atômica em lote bloqueado: ", msg), atributo = atributo, linha_indice = NA_integer_, valor_antes = NA_character_, valor_depois = NA_character_, arquivo_correcao = arquivo_correcao)
    if (nrow(extra)) audit <- data.table::rbindlist(list(audit, extra), fill = TRUE, use.names = TRUE)
    list(dt = dt[], audit = audit[], linhas = integer(), afetacoes = data.table::data.table(linha_indice = integer(), atributo = character()), falha = TRUE)
  }
  informar <- function(status, msg, atributo = "__mover_forma_vida_lote__", linhas_info = integer()) {
    audit <- data.table::data.table(
      id_correcao = id_cor, ordem_operacao = ordem, status = status,
      mensagem = paste0("Movimento/substituição atômica em lote sem alteração fatal: ", msg),
      atributo = atributo, linha_indice = if (length(linhas_info)) as.integer(linhas_info) else NA_integer_,
      valor_antes = NA_character_, valor_depois = NA_character_, arquivo_correcao = arquivo_correcao
    )
    list(dt = dt[], audit = audit[], linhas = unique(as.integer(linhas_info)), afetacoes = data.table::data.table(linha_indice = integer(), atributo = character()), falha = FALSE)
  }
  origem <- if ("categoria_origem" %in% names(linha_lote)) tolower(trimws(as.character(linha_lote$categoria_origem[1L]))) else NA_character_
  destino <- if ("categoria_destino" %in% names(linha_lote)) tolower(trimws(as.character(linha_lote$categoria_destino[1L]))) else NA_character_
  cats <- c("nativa", "exotica", "seca_morta")
  if (monitora_correcao_vazio(origem) || monitora_correcao_vazio(destino) || !origem %in% cats || !destino %in% cats) {
    return(falhar("falha_lote_categoria", "origem/destino ausentes ou inválidos"))
  }
  mv_desc_vals <- character(0)
  for (cc_mv in intersect(c("escopo_diagnostico_mvlote", "categoria_base_diagnostica", "token_pai", "token_removido", "valor_original_esperado"), names(linha_lote))) {
    mv_desc_vals <- c(mv_desc_vals, as.character(linha_lote[[cc_mv]][1L]))
  }
  mv_desc_norm <- tryCatch(monitora_correcao_limpar_texto(mv_desc_vals), error = function(e) tolower(trimws(mv_desc_vals)))
  mv_lote_desconhecida_semantica <- any(mv_desc_norm %in% c("forma_vida_desconhecida_categoria_base", "forma_vida_desconhecida", "desconhecida", "desconhecido"), na.rm = TRUE)

  col_origem <- tryCatch(monitora_correcao_coluna_forma_vida(dt, origem), error = function(e) NA_character_)
  col_destino <- tryCatch(monitora_correcao_coluna_forma_vida(dt, destino), error = function(e) NA_character_)
  if (is.na(col_origem) || !(col_origem %in% names(dt))) return(falhar("falha_coluna_origem", paste0("coluna de origem não localizada para ", origem)))
  if (is.na(col_destino) || !(col_destino %in% names(dt))) return(falhar("falha_coluna_destino", paste0("coluna de destino não localizada para ", destino)))
  if (monitora_correcao_coluna_protegida(col_origem) || monitora_correcao_coluna_protegida(col_destino)) return(falhar("bloqueada_coluna_protegida", "origem ou destino é coluna protegida"))

  linhas <- unique(as.integer(monitora_correcao_localizar_linhas_movimento_lote(dt, linha_lote, chaves)))
  linhas <- linhas[!is.na(linhas) & linhas >= 1L & linhas <= nrow(dt)]
  n_esperado <- if ("n_linhas_esperado" %in% names(linha_lote)) suppressWarnings(as.integer(linha_lote$n_linhas_esperado[1L])) else NA_integer_
  if (!length(linhas)) return(falhar("falha_sem_linhas", "nenhuma linha-alvo diagnóstica localizada para o movimento em lote"))
  if (!is.na(n_esperado) && n_esperado > 0L && length(linhas) != n_esperado && !isTRUE(mv_lote_desconhecida_semantica)) {
    return(falhar("falha_n_linhas", paste0("n_linhas_alvo=", length(linhas), " diferente de n_linhas_esperado=", n_esperado, "; o MVLOTE deve usar as linhas diagnósticas serializadas, não a COLETA inteira")))
  }

  parse_vals <- function(...) {
    vals <- character(0)
    for (x in list(...)) vals <- c(vals, monitora_correcao_parse_serial_generico(x))
    vals <- unique(trimws(as.character(vals)))
    vals[!is.na(vals) & nzchar(vals)]
  }
  formas_raw <- parse_vals(if ("token_pai" %in% names(linha_lote)) linha_lote$token_pai[1L] else NA_character_, if ("valor_original_esperado" %in% names(linha_lote)) linha_lote$valor_original_esperado[1L] else NA_character_, if ("token_removido" %in% names(linha_lote)) linha_lote$token_removido[1L] else NA_character_)
  mover_todas <- any(tolower(formas_raw) %in% c("__todas__", "todas", "todos", "all"))
  origem_vals <- as.character(dt[[col_origem]][linhas])
  if (isTRUE(mover_todas)) {
    formas_origem <- unique(unlist(lapply(origem_vals, monitora_correcao_tokenizar), use.names = FALSE))
  } else {
    formas_origem <- formas_raw
  }
  formas_origem <- monitora_correcao_forma_canonica_lote(formas_origem)
  formas_origem <- unique(formas_origem[!is.na(formas_origem) & nzchar(formas_origem)])
  formas_origem <- setdiff(formas_origem, c("", "na", "nan", "null", "outra", "outro", "outras", "outros", "outra_forma_vida", "forma_vida_outros", "nativa", "exotica", "seca", "morta", "seca_morta", "solo_nu", "serrapilheira", "fragmentos_botanicos", "material_inundado"))
  if (!length(formas_origem)) return(falhar("falha_lote_sem_formas", "nenhuma forma de vida de origem válida informada ou encontrada"))

  forma_destino <- parse_vals(if ("forma_valida_escolhida" %in% names(linha_lote)) linha_lote$forma_valida_escolhida[1L] else NA_character_, if ("valor_novo" %in% names(linha_lote)) linha_lote$valor_novo[1L] else NA_character_)
  forma_destino <- monitora_correcao_forma_canonica_lote(forma_destino)
  forma_destino <- unique(forma_destino[!is.na(forma_destino) & nzchar(forma_destino) & !forma_destino %in% c("__todas__", "todas", "todos", "all")])
  if (!length(forma_destino)) {
    ### Compatibilidade com movimento antigo: se não houver forma de destino explícita,
    ### preserva os próprios tokens migrados como destino.
    forma_destino <- formas_origem
  }
  forma_destino <- forma_destino[1L]
  if (identical(origem, destino) && length(formas_origem) == 1L && identical(monitora_correcao_limpar_texto(formas_origem[1L]), monitora_correcao_limpar_texto(forma_destino))) {
    return(falhar("bloqueada_operacao_nula", "origem e destino são a mesma categoria e a mesma forma de vida; nada seria alterado"))
  }

  tokens_de_forma <- function(forma) {
    if (monitora_correcao_limpar_texto(forma) %in% c("desconhecida", "desconhecido")) return(unique(c("desconhecida", "desconhecido")))
    unique(c(forma, monitora_correcao_sinonimos_forma(forma)))
  }
  presenca <- list()
  for (forma in formas_origem) {
    toks <- tokens_de_forma(forma)
    hit <- rep(FALSE, length(linhas))
    if (monitora_correcao_limpar_texto(forma) %in% c("desconhecida", "desconhecido")) {
      ### MVLOTE de desconhecida usa linhas diagnósticas calculadas no painel.
      ### Essas linhas podem ser identificadas por dependentes/fotos de desconhecida,
      ### mesmo quando o token literal não aparece na lista principal; portanto, se
      ### linhas_alvo_serializadas chegou até aqui, ela já é o alvo correto.
      linhas_desc_cat <- tryCatch(monitora_correcao_linhas_desconhecida_categoria_base(dt, origem, linhas, dicionario = dicionario), error = function(e) integer(0))
      if (length(linhas_desc_cat)) {
        hit <- linhas %in% linhas_desc_cat
      } else if ("linhas_alvo_serializadas" %in% names(linha_lote) && nzchar(trimws(as.character(linha_lote$linhas_alvo_serializadas[1L])))) {
        ### linhas_alvo_serializadas define o universo candidato, mas não autoriza
        ### aplicação cega: no estado corrente, a ocorrência diagnóstica ainda deve
        ### ter desconhecida na categoria-base indicada. Se uma operação anterior já
        ### corrigiu a linha, o MVLOTE vira no-op auditado, não falha fatal.
        hit <- monitora_correcao_contem_qualquer_token_vec(origem_vals, tokens_de_forma(forma))
        hit[is.na(hit)] <- FALSE
      }
    } else {
      for (tok in toks) hit <- hit | monitora_correcao_token_presente_vec(origem_vals, tok)
    }
    if (any(hit, na.rm = TRUE)) presenca[[forma]] <- hit
  }
  if (!length(presenca)) return(informar("ignorada_sem_efeito_estado_ja_corrigido", "nenhuma das formas de origem selecionadas permanece no estado corrente para a categoria-base escolhida", linhas))
  linhas_migraveis <- rep(FALSE, length(linhas))
  for (hh in presenca) linhas_migraveis <- linhas_migraveis | hh
  linhas_alvo <- linhas[linhas_migraveis]
  if (!length(linhas_alvo)) return(informar("sem_ocorrencias_migraveis_estado_ja_corrigido", "nenhuma ocorrência migrável restou no estado corrente; provável operação substituída ou já aplicada", linhas))

  final_origem <- origem_vals
  final_destino <- as.character(dt[[col_destino]][linhas])
  for (forma in names(presenca)) {
    idx_f <- which(presenca[[forma]])
    if (!length(idx_f)) next
    for (tok in tokens_de_forma(forma)) final_origem[idx_f] <- vapply(final_origem[idx_f], monitora_correcao_remove_token_valor, character(1), token = tok)
    final_destino[idx_f] <- vapply(final_destino[idx_f], monitora_correcao_append_token_valor, character(1), token = forma_destino)
  }
  ### Se origem e destino são a mesma lista, aplicar substituição no mesmo vetor.
  if (identical(col_origem, col_destino)) {
    final_mesma <- origem_vals
    for (forma in names(presenca)) {
      idx_f <- which(presenca[[forma]])
      for (tok in tokens_de_forma(forma)) final_mesma[idx_f] <- vapply(final_mesma[idx_f], monitora_correcao_remove_token_valor, character(1), token = tok)
      final_mesma[idx_f] <- vapply(final_mesma[idx_f], monitora_correcao_append_token_valor, character(1), token = forma_destino)
    }
    final_origem <- final_mesma
    final_destino <- final_mesma
  }

  registrar <- function(status, msg, atributo, idx, antes, depois) {
    data.table::data.table(id_correcao = id_cor, ordem_operacao = ordem, status = status, mensagem = msg, atributo = atributo, linha_indice = as.integer(idx), valor_antes = as.character(antes), valor_depois = as.character(depois), arquivo_correcao = arquivo_correcao)
  }
  audit <- data.table::data.table(); afetacoes <- data.table::data.table(linha_indice = integer(), atributo = character())
  mudou_origem <- monitora_correcao_na_para_vazio(origem_vals) != monitora_correcao_na_para_vazio(final_origem)
  antes_destino <- as.character(dt[[col_destino]][linhas])
  mudou_destino <- monitora_correcao_na_para_vazio(antes_destino) != monitora_correcao_na_para_vazio(final_destino)
  if (identical(col_origem, col_destino)) mudou_destino <- rep(FALSE, length(mudou_destino))

  if (any(mudou_origem, na.rm = TRUE)) {
    data.table::set(dt, i = linhas[mudou_origem], j = col_origem, value = final_origem[mudou_origem])
    audit <- data.table::rbindlist(list(audit, registrar("aplicada_atomica", if (identical(origem, destino)) "Substituição intralista em lote: forma de origem removida e forma de destino garantida" else "Movimento em lote: token(s) removido(s) da categoria de origem", col_origem, linhas[mudou_origem], origem_vals[mudou_origem], final_origem[mudou_origem])), fill = TRUE, use.names = TRUE)
    afetacoes <- data.table::rbindlist(list(afetacoes, data.table::data.table(linha_indice = linhas[mudou_origem], atributo = col_origem)), fill = TRUE, use.names = TRUE)
  }
  if (any(mudou_destino, na.rm = TRUE)) {
    data.table::set(dt, i = linhas[mudou_destino], j = col_destino, value = final_destino[mudou_destino])
    audit <- data.table::rbindlist(list(audit, registrar("aplicada_atomica", "Movimento em lote: forma de destino garantida na categoria de destino", col_destino, linhas[mudou_destino], antes_destino[mudou_destino], final_destino[mudou_destino])), fill = TRUE, use.names = TRUE)
    afetacoes <- data.table::rbindlist(list(afetacoes, data.table::data.table(linha_indice = linhas[mudou_destino], atributo = col_destino)), fill = TRUE, use.names = TRUE)
  }

  habito_destino <- if ("habito_escolhido" %in% names(linha_lote)) trimws(as.character(linha_lote$habito_escolhido[1L])) else ""
  if (is.na(habito_destino)) habito_destino <- ""
  forma_exige_habito <- monitora_correcao_limpar_texto(forma_destino) %in% c("bromelioide", "erva_bromelioide", "cactacea", "orquidea", "samambaia")
  if (isTRUE(forma_exige_habito)) {
    if (!nzchar(habito_destino) || !(habito_destino %in% c("terrestre", "epifita", "rupicola"))) return(falhar("falha_habito_obrigatorio", paste0("forma de destino '", forma_destino, "' exige hábito terrestre/epifita/rupicola")))
    dep_destino <- tryCatch(monitora_correcao_resolver_coluna_habito(dt, destino, forma_destino, dicionario, linha = linhas_alvo[1L], meta_xls = NULL), error = function(e) NA_character_)
    if (!monitora_correcao_coluna_habito_segura(dt, dep_destino, destino, forma_destino) || identical(dep_destino, col_destino)) return(falhar("falha_coluna_habito_destino", "coluna de hábito segura não localizada para o destino"))
    antes_h <- as.character(dt[[dep_destino]][linhas_alvo])
    depois_h <- rep(habito_destino, length(linhas_alvo))
    mudou_h <- monitora_correcao_na_para_vazio(antes_h) != monitora_correcao_na_para_vazio(depois_h)
    if (any(mudou_h, na.rm = TRUE)) {
      data.table::set(dt, i = linhas_alvo[mudou_h], j = dep_destino, value = depois_h[mudou_h])
      audit <- data.table::rbindlist(list(audit, registrar("aplicada_atomica", "Movimento/substituição em lote: hábito obrigatório preenchido no destino", dep_destino, linhas_alvo[mudou_h], antes_h[mudou_h], depois_h[mudou_h])), fill = TRUE, use.names = TRUE)
      afetacoes <- data.table::rbindlist(list(afetacoes, data.table::data.table(linha_indice = linhas_alvo[mudou_h], atributo = dep_destino)), fill = TRUE, use.names = TRUE)
    }
  } else if (nzchar(habito_destino)) {
    return(falhar("falha_habito_indevido", paste0("hábito informado para forma que não exige hábito: ", forma_destino)))
  }

  if (any(monitora_correcao_limpar_texto(formas_origem) %in% c("desconhecida", "desconhecido"))) {
    res_desc_dep <- monitora_correcao_sanitizar_dependentes_desconhecida(
      dt, linhas = linhas_alvo, categorias = c("nativa", "exotica", "seca_morta"), id_correcao = id_cor,
      ordem_operacao = ordem, arquivo_correcao = arquivo_correcao, dicionario = dicionario, registrar_preservadas = TRUE
    )
    dt <- res_desc_dep$dt
    if (nrow(res_desc_dep$audit)) audit <- data.table::rbindlist(list(audit, res_desc_dep$audit), fill = TRUE, use.names = TRUE)
    if (nrow(res_desc_dep$afetacoes)) afetacoes <- data.table::rbindlist(list(afetacoes, res_desc_dep$afetacoes), fill = TRUE, use.names = TRUE)
  }
  tipo_col <- chaves$tipo_forma_vida
  if (!is.na(tipo_col) && tipo_col %in% names(dt)) {
    antes_tipo <- as.character(dt[[tipo_col]][linhas_alvo])
    monitora_correcao_recalcular_tipo_forma_vida(dt, linhas_alvo)
    depois_tipo <- as.character(dt[[tipo_col]][linhas_alvo])
    mudou_tipo <- monitora_correcao_na_para_vazio(antes_tipo) != monitora_correcao_na_para_vazio(depois_tipo)
    if (any(mudou_tipo, na.rm = TRUE)) {
      audit <- data.table::rbindlist(list(audit, registrar("aplicada_atomica", "Movimento/substituição em lote: tipo_forma_vida recalculado", tipo_col, linhas_alvo[mudou_tipo], antes_tipo[mudou_tipo], depois_tipo[mudou_tipo])), fill = TRUE, use.names = TRUE)
      afetacoes <- data.table::rbindlist(list(afetacoes, data.table::data.table(linha_indice = linhas_alvo[mudou_tipo], atributo = tipo_col)), fill = TRUE, use.names = TRUE)
    }
  }
  if (!nrow(audit)) return(informar("ignorada_operacao_repetida_sem_efeito", "estado final já estava coerente; nenhuma alteração necessária", linhas_info = linhas_alvo))
  audit[, formas_origem := monitora_correcao_colapsar_lista_serializada(formas_origem)]
  audit[, forma_destino := forma_destino]
  audit[, modo_movimento := ifelse(identical(origem, destino), "substituicao_intralista", "movimento_entre_categorias")]
  list(dt = dt[], audit = audit[], linhas = unique(linhas_alvo), afetacoes = unique(afetacoes), falha = FALSE)
}


### Movimento atômico de forma de vida
### -------------------------------------------------------------------------
### Movimento de forma de vida altera origem, destino, dependentes e campo
### superior. Aqui o grupo é tratado como transação semântica: ou o conjunto
### validado é aplicado, ou nada é aplicado.
monitora_correcao_eh_operacao_movimento_forma_vida <- function(corr) {
  corr <- data.table::as.data.table(corr)
  if (!nrow(corr)) return(logical(0))
  tipo <- if ("tipo_correcao" %in% names(corr)) tolower(trimws(as.character(corr$tipo_correcao))) else rep("", nrow(corr))
  acao <- if ("acao" %in% names(corr)) tolower(trimws(as.character(corr$acao))) else rep("", nrow(corr))
  atributo <- if ("atributo_coluna_registros_corrig" %in% names(corr)) tolower(trimws(as.character(corr$atributo_coluna_registros_corrig))) else rep("", nrow(corr))
  tipo %in% c("movimento_forma_vida_atomico", "movimento_forma_vida_condicional", "movimento_forma_vida") |
    acao %in% c("mover_forma_vida", "movimento_forma_vida_atomico") |
    atributo %in% c("__mover_forma_vida__", "__movimento_forma_vida__")
}

monitora_correcao_compactar_movimento_forma_vida_atomico <- function(grupo) {
  grupo <- data.table::as.data.table(grupo)
  if (!nrow(grupo)) return(grupo)
  if ("ordem_operacao" %in% names(grupo)) {
    grupo[, .ordem_atom_tmp := suppressWarnings(as.integer(ordem_operacao))]
    data.table::setorder(grupo, .ordem_atom_tmp, na.last = TRUE)
    grupo[, .ordem_atom_tmp := NULL]
  }
  pegar_primeiro <- function(col, default = NA_character_) {
    if (!(col %in% names(grupo))) return(default)
    vals <- as.character(grupo[[col]])
    vals <- vals[!is.na(vals) & nzchar(trimws(vals))]
    if (length(vals)) vals[1L] else default
  }
  linha <- data.table::copy(grupo[1L])
  if ("acao" %in% names(linha)) linha[, acao := "mover_forma_vida"]
  if ("tipo_correcao" %in% names(linha)) linha[, tipo_correcao := "movimento_forma_vida_atomico"]
  if ("atributo_coluna_registros_corrig" %in% names(linha)) linha[, atributo_coluna_registros_corrig := "__mover_forma_vida__"]
  if ("ordem_operacao" %in% names(linha)) {
    ord_vals <- suppressWarnings(as.integer(grupo$ordem_operacao))
    ord_vals <- ord_vals[!is.na(ord_vals) & is.finite(ord_vals)]
    linha[, ordem_operacao := if (length(ord_vals)) min(ord_vals) else NA_integer_]
  }
  if ("valor_novo" %in% names(linha)) {
    destino <- pegar_primeiro("valor_novo", pegar_primeiro("token_pai"))
    if (all(c("acao", "valor_novo") %in% names(grupo))) {
      vals_append <- unique(as.character(grupo[tolower(trimws(as.character(acao))) %in% c("append_token", "adicionar_token", "mover_forma_vida"), valor_novo]))
      vals_append <- vals_append[!is.na(vals_append) & nzchar(trimws(vals_append))]
      if (length(vals_append)) destino <- vals_append[1L]
    }
    linha[, valor_novo := destino]
  }
  tokens_remover <- character(0)
  if (all(c("acao", "valor_novo") %in% names(grupo))) {
    tokens_remover <- c(tokens_remover, as.character(grupo[tolower(trimws(as.character(acao))) %in% c("remove_token", "remover_token"), valor_novo]))
  }
  if ("token_removido" %in% names(grupo)) tokens_remover <- c(tokens_remover, monitora_correcao_parse_lista_serializada(pegar_primeiro("token_removido")))
  if ("token_pai" %in% names(grupo)) tokens_remover <- c(tokens_remover, as.character(grupo$token_pai))
  tokens_remover <- unique(trimws(tokens_remover))
  tokens_remover <- tokens_remover[!is.na(tokens_remover) & nzchar(tokens_remover)]
  if ("token_removido" %in% names(linha)) linha[, token_removido := monitora_correcao_colapsar_lista_serializada(tokens_remover)]
  if ("token_pai" %in% names(linha) && monitora_correcao_vazio(linha$token_pai[1L])) linha[, token_pai := pegar_primeiro("valor_novo")]
  if ("categoria_origem" %in% names(linha) && monitora_correcao_vazio(linha$categoria_origem[1L])) linha[, categoria_origem := pegar_primeiro("categoria_origem")]
  if ("categoria_destino" %in% names(linha) && monitora_correcao_vazio(linha$categoria_destino[1L])) linha[, categoria_destino := pegar_primeiro("categoria_destino")]
  if ("habito_escolhido" %in% names(linha)) {
    hab <- pegar_primeiro("habito_escolhido")
    if (monitora_correcao_vazio(hab) && all(c("acao", "valor_novo") %in% names(grupo))) {
      cand <- as.character(grupo[tolower(trimws(as.character(acao))) %in% c("update", "substituir_valor"), valor_novo])
      cand <- cand[!is.na(cand) & nzchar(trimws(cand)) & cand %in% c("terrestre", "epifita", "rupicola")]
      if (length(cand)) hab <- cand[1L]
    }
    linha[, habito_escolhido := hab]
  }
  linha[]
}

monitora_correcao_aplicar_movimento_forma_vida_atomico <- function(dt, linha_mov, chaves = monitora_correcao_colunas_chave(dt), indice = NULL, arquivo_correcao = NA_character_, dicionario = NULL) {
  dt <- monitora_dt_referenciar(dt)
  linha_mov <- data.table::as.data.table(linha_mov)
  if (!nrow(linha_mov)) return(list(dt = dt[], audit = data.table::data.table(), linhas = integer(), afetacoes = data.table::data.table(linha_indice = integer(), atributo = character()), falha = FALSE))
  id_cor <- if ("id_correcao" %in% names(linha_mov)) as.character(linha_mov$id_correcao[1L]) else NA_character_
  ordem <- if ("ordem_operacao" %in% names(linha_mov)) linha_mov$ordem_operacao[1L] else NA_character_
  falhar <- function(status, msg, atributo = "__mover_forma_vida__") {
    list(
      dt = dt[],
      audit = data.table::data.table(id_correcao = id_cor, ordem_operacao = ordem, status = status, mensagem = paste0("Movimento atômico de forma de vida bloqueado: ", msg), atributo = atributo, linha_indice = NA_integer_, valor_antes = NA_character_, valor_depois = NA_character_, arquivo_correcao = arquivo_correcao),
      linhas = integer(),
      afetacoes = data.table::data.table(linha_indice = integer(), atributo = character()),
      falha = TRUE
    )
  }
  origem <- if ("categoria_origem" %in% names(linha_mov)) tolower(trimws(as.character(linha_mov$categoria_origem[1L]))) else NA_character_
  destino <- if ("categoria_destino" %in% names(linha_mov)) tolower(trimws(as.character(linha_mov$categoria_destino[1L]))) else NA_character_
  forma_destino <- if ("valor_novo" %in% names(linha_mov)) trimws(as.character(linha_mov$valor_novo[1L])) else NA_character_
  token_pai <- if ("token_pai" %in% names(linha_mov)) trimws(as.character(linha_mov$token_pai[1L])) else NA_character_
  if (monitora_correcao_vazio(forma_destino)) forma_destino <- token_pai
  if (monitora_correcao_vazio(token_pai)) token_pai <- forma_destino
  if (monitora_correcao_vazio(origem) || monitora_correcao_vazio(destino) || monitora_correcao_vazio(forma_destino)) return(falhar("falha_movimento_atomico_incompleto", "categoria de origem/destino ou forma de vida não informada"))
  col_origem <- tryCatch(monitora_correcao_coluna_forma_vida(dt, origem), error = function(e) NA_character_)
  col_destino <- tryCatch(monitora_correcao_coluna_forma_vida(dt, destino), error = function(e) NA_character_)
  if (is.na(col_origem) || !(col_origem %in% names(dt))) return(falhar("falha_coluna_origem", paste0("coluna de origem não localizada para ", origem)))
  if (is.na(col_destino) || !(col_destino %in% names(dt))) return(falhar("falha_coluna_destino", paste0("coluna de destino não localizada para ", destino)))
  if (monitora_correcao_coluna_protegida(col_origem) || monitora_correcao_coluna_protegida(col_destino)) return(falhar("bloqueada_coluna_protegida", "origem ou destino é coluna protegida"))

  linhas <- unique(as.integer(monitora_correcao_localizar_linhas(dt, linha_mov, chaves, indice)))
  linhas <- linhas[!is.na(linhas) & linhas >= 1L & linhas <= nrow(dt)]
  n_esperado <- if ("n_linhas_esperado" %in% names(linha_mov)) suppressWarnings(as.integer(linha_mov$n_linhas_esperado[1L])) else NA_integer_
  if (!length(linhas)) return(falhar("falha_sem_linhas", "nenhuma linha-alvo localizada"))
  if (!is.na(n_esperado) && n_esperado > 0L && length(linhas) != n_esperado) return(falhar("falha_n_linhas", paste0("n_linhas_alvo=", length(linhas), " diferente de n_linhas_esperado=", n_esperado)))

  tokens_remover <- character(0)
  if ("token_removido" %in% names(linha_mov)) tokens_remover <- c(tokens_remover, monitora_correcao_parse_lista_serializada(linha_mov$token_removido[1L]))
  if ("valor_original_esperado" %in% names(linha_mov)) tokens_remover <- c(tokens_remover, monitora_correcao_tokenizar(linha_mov$valor_original_esperado[1L]))
  tokens_remover <- c(tokens_remover, token_pai, forma_destino)
  tokens_remover <- unique(monitora_correcao_limpar_texto(tokens_remover))
  tokens_remover <- tokens_remover[!is.na(tokens_remover) & nzchar(tokens_remover)]
  if (!length(tokens_remover)) tokens_remover <- forma_destino

  registrar <- function(status, msg, atributo, idx, antes, depois) {
    data.table::data.table(id_correcao = id_cor, ordem_operacao = ordem, status = status, mensagem = msg, atributo = atributo, linha_indice = as.integer(idx), valor_antes = as.character(antes), valor_depois = as.character(depois), arquivo_correcao = arquivo_correcao)
  }
  audit <- data.table::data.table()
  linhas_afetadas <- integer()
  afetacoes <- data.table::data.table(linha_indice = integer(), atributo = character())

  antes_origem <- as.character(dt[[col_origem]][linhas])
  depois_origem <- antes_origem
  for (tok in tokens_remover) depois_origem <- vapply(depois_origem, monitora_correcao_remove_token_valor, character(1), token = tok)
  esperado <- if ("valor_original_esperado" %in% names(linha_mov)) linha_mov$valor_original_esperado[1L] else NA_character_
  if (!monitora_correcao_vazio(esperado)) {
    iguais <- monitora_correcao_na_para_vazio(antes_origem) == monitora_correcao_na_para_vazio(esperado)
    contem_algum <- Reduce(`|`, lapply(tokens_remover, function(tok) monitora_correcao_token_presente_vec(antes_origem, tok)))
    if (!all(iguais) && !all(contem_algum)) return(falhar("falha_precondicao_origem", "valor_original_esperado divergiu e token-alvo não estava presente em todas as linhas-alvo", col_origem))
  }
  mudou_origem <- monitora_correcao_na_para_vazio(antes_origem) != monitora_correcao_na_para_vazio(depois_origem)

  antes_destino <- as.character(dt[[col_destino]][linhas])
  depois_destino <- vapply(antes_destino, monitora_correcao_append_token_valor, character(1), token = forma_destino)
  mudou_destino <- monitora_correcao_na_para_vazio(antes_destino) != monitora_correcao_na_para_vazio(depois_destino)

  deps_origem_cols <- character(0)
  deps <- if (exists("MONITORA_DEPENDENCIAS_CORRECOES", inherits = TRUE)) get("MONITORA_DEPENDENCIAS_CORRECOES", inherits = TRUE) else NULL
  if (!is.null(deps) && nrow(data.table::as.data.table(deps)) > 0L) {
    deps_dt <- data.table::as.data.table(deps)
    if (all(c("parent_name", "token", "dependent_name") %in% names(deps_dt))) {
      deps_mov <- deps_dt[parent_name == paste0("forma_vida_", origem) & token %in% tokens_remover]
      if (nrow(deps_mov) > 0L) deps_origem_cols <- unique(vapply(deps_mov$dependent_name, function(nn) monitora_correcao_resolver_coluna(dt, nn, dicionario), character(1)))
    }
  }
  if (!length(deps_origem_cols)) deps_origem_cols <- unique(unlist(lapply(tokens_remover, function(tok) monitora_correcao_colunas_dependentes_por_token(dt, origem, tok, dicionario)), use.names = FALSE))
  deps_origem_cols <- unique(deps_origem_cols[!is.na(deps_origem_cols) & deps_origem_cols %in% names(dt) & !monitora_correcao_coluna_protegida(deps_origem_cols)])
  deps_origem_cols <- setdiff(deps_origem_cols, c(col_origem, col_destino))
  atualizacoes_deps <- list()
  for (dep_col in deps_origem_cols) {
    antes_dep <- as.character(dt[[dep_col]][linhas])
    limpar <- !monitora_correcao_vazio_vec(antes_dep)
    if (any(limpar, na.rm = TRUE)) atualizacoes_deps[[dep_col]] <- list(idx = linhas[limpar], antes = antes_dep[limpar], depois = rep(NA_character_, sum(limpar, na.rm = TRUE)))
  }

  habito <- if ("habito_escolhido" %in% names(linha_mov)) trimws(as.character(linha_mov$habito_escolhido[1L])) else ""
  if (is.na(habito)) habito <- ""
  forma_exige_habito <- monitora_correcao_limpar_texto(forma_destino) %in% c("bromelioide", "erva_bromelioide", "cactacea", "orquidea", "samambaia")
  dep_destino <- if ("campo_dependente_preenchido" %in% names(linha_mov)) trimws(as.character(linha_mov$campo_dependente_preenchido[1L])) else NA_character_
  if (is.na(dep_destino) || !nzchar(dep_destino) || !(dep_destino %in% names(dt))) dep_destino <- tryCatch(monitora_correcao_resolver_coluna_habito(dt, destino, forma_destino, dicionario, linha = linhas[1L], meta_xls = NULL), error = function(e) NA_character_)
  atualizacao_habito <- NULL
  if (isTRUE(forma_exige_habito)) {
    if (!nzchar(habito) || !(habito %in% c("terrestre", "epifita", "rupicola"))) return(falhar("falha_habito_obrigatorio", paste0("forma '", forma_destino, "' exige hábito terrestre/epifita/rupicola")))
    if (!monitora_correcao_coluna_habito_segura(dt, dep_destino, destino, forma_destino) || identical(dep_destino, col_destino)) return(falhar("falha_coluna_habito_destino", "coluna de hábito segura não localizada para o destino"))
    antes_hab <- as.character(dt[[dep_destino]][linhas])
    depois_hab <- rep(habito, length(linhas))
    mudou_hab <- monitora_correcao_na_para_vazio(antes_hab) != monitora_correcao_na_para_vazio(depois_hab)
    if (any(mudou_hab, na.rm = TRUE)) atualizacao_habito <- list(col = dep_destino, idx = linhas[mudou_hab], antes = antes_hab[mudou_hab], depois = depois_hab[mudou_hab])
  } else if (nzchar(habito)) {
    return(falhar("falha_habito_indevido", paste0("hábito informado para forma que não exige hábito: ", forma_destino)))
  }

  if (any(mudou_origem, na.rm = TRUE)) {
    data.table::set(dt, i = linhas[mudou_origem], j = col_origem, value = depois_origem[mudou_origem])
    audit <- data.table::rbindlist(list(audit, registrar("aplicada_atomica", "Movimento atômico: token(s) removido(s) da categoria de origem", col_origem, linhas[mudou_origem], antes_origem[mudou_origem], depois_origem[mudou_origem])), fill = TRUE, use.names = TRUE)
    linhas_afetadas <- unique(c(linhas_afetadas, linhas[mudou_origem])); afetacoes <- data.table::rbindlist(list(afetacoes, data.table::data.table(linha_indice = linhas[mudou_origem], atributo = col_origem)), fill = TRUE, use.names = TRUE)
  }
  if (any(mudou_destino, na.rm = TRUE)) {
    data.table::set(dt, i = linhas[mudou_destino], j = col_destino, value = depois_destino[mudou_destino])
    audit <- data.table::rbindlist(list(audit, registrar("aplicada_atomica", "Movimento atômico: forma garantida na categoria de destino", col_destino, linhas[mudou_destino], antes_destino[mudou_destino], depois_destino[mudou_destino])), fill = TRUE, use.names = TRUE)
    linhas_afetadas <- unique(c(linhas_afetadas, linhas[mudou_destino])); afetacoes <- data.table::rbindlist(list(afetacoes, data.table::data.table(linha_indice = linhas[mudou_destino], atributo = col_destino)), fill = TRUE, use.names = TRUE)
  }
  for (dep_col in names(atualizacoes_deps)) {
    zz <- atualizacoes_deps[[dep_col]]
    data.table::set(dt, i = zz$idx, j = dep_col, value = zz$depois)
    audit <- data.table::rbindlist(list(audit, registrar("aplicada_atomica", "Movimento atômico: campo inferior/dependente da origem limpo", dep_col, zz$idx, zz$antes, zz$depois)), fill = TRUE, use.names = TRUE)
    linhas_afetadas <- unique(c(linhas_afetadas, zz$idx)); afetacoes <- data.table::rbindlist(list(afetacoes, data.table::data.table(linha_indice = zz$idx, atributo = dep_col)), fill = TRUE, use.names = TRUE)
  }
  if (!is.null(atualizacao_habito)) {
    data.table::set(dt, i = atualizacao_habito$idx, j = atualizacao_habito$col, value = atualizacao_habito$depois)
    audit <- data.table::rbindlist(list(audit, registrar("aplicada_atomica", "Movimento atômico: hábito obrigatório preenchido no destino", atualizacao_habito$col, atualizacao_habito$idx, atualizacao_habito$antes, atualizacao_habito$depois)), fill = TRUE, use.names = TRUE)
    linhas_afetadas <- unique(c(linhas_afetadas, atualizacao_habito$idx)); afetacoes <- data.table::rbindlist(list(afetacoes, data.table::data.table(linha_indice = atualizacao_habito$idx, atributo = atualizacao_habito$col)), fill = TRUE, use.names = TRUE)
  }
  if (any(monitora_correcao_normalizar_nome_coluna(tokens_remover) %in% monitora_correcao_normalizar_nome_coluna(monitora_correcao_tokens_desconhecida()))) {
    res_desc_dep <- monitora_correcao_sanitizar_dependentes_desconhecida(
      dt,
      linhas = linhas,
      categorias = c(origem, destino),
      id_correcao = id_cor,
      ordem_operacao = ordem,
      arquivo_correcao = arquivo_correcao,
      dicionario = dicionario,
      registrar_preservadas = TRUE
    )
    dt <- res_desc_dep$dt
    if (nrow(res_desc_dep$audit)) audit <- data.table::rbindlist(list(audit, res_desc_dep$audit), fill = TRUE, use.names = TRUE)
    if (nrow(res_desc_dep$afetacoes)) afetacoes <- data.table::rbindlist(list(afetacoes, res_desc_dep$afetacoes), fill = TRUE, use.names = TRUE)
    if (nrow(res_desc_dep$afetacoes)) linhas_afetadas <- unique(c(linhas_afetadas, res_desc_dep$afetacoes$linha_indice))
  }
  tipo_col <- chaves$tipo_forma_vida
  if (!is.na(tipo_col) && tipo_col %in% names(dt)) {
    antes_tipo <- as.character(dt[[tipo_col]][linhas])
    monitora_correcao_recalcular_tipo_forma_vida(dt, linhas)
    depois_tipo <- as.character(dt[[tipo_col]][linhas])
    mudou_tipo <- monitora_correcao_na_para_vazio(antes_tipo) != monitora_correcao_na_para_vazio(depois_tipo)
    if (any(mudou_tipo, na.rm = TRUE)) {
      audit <- data.table::rbindlist(list(audit, registrar("aplicada_atomica", "Movimento atômico: tipo_forma_vida recalculado após origem/destino", tipo_col, linhas[mudou_tipo], antes_tipo[mudou_tipo], depois_tipo[mudou_tipo])), fill = TRUE, use.names = TRUE)
      linhas_afetadas <- unique(c(linhas_afetadas, linhas[mudou_tipo])); afetacoes <- data.table::rbindlist(list(afetacoes, data.table::data.table(linha_indice = linhas[mudou_tipo], atributo = tipo_col)), fill = TRUE, use.names = TRUE)
    }
  }
  if (!nrow(audit)) {
    audit <- registrar("bloqueada_operacao_repetida_sem_efeito", "Movimento atômico bloqueado: operação repetida ou sem efeito; origem, destino, dependentes e tipo_forma_vida já estavam coerentes antes da aplicação", "__mover_forma_vida__", linhas, NA_character_, NA_character_)
    return(list(dt = dt[], audit = audit[], linhas = linhas, afetacoes = data.table::data.table(linha_indice = integer(), atributo = character()), falha = TRUE))
  }
  list(dt = dt[], audit = audit[], linhas = unique(c(linhas, linhas_afetadas)), afetacoes = unique(afetacoes), falha = FALSE)
}

monitora_correcao_aplicar_movimentos_forma_vida_atomicos <- function(dt, corr, chaves = monitora_correcao_colunas_chave(dt), indice = NULL, arquivo_correcao = NA_character_, dicionario = NULL) {
  dt <- monitora_dt_referenciar(dt)
  corr <- data.table::as.data.table(corr)
  if (!nrow(corr)) return(list(dt = dt[], corr = corr, audit = data.table::data.table(), linhas = integer(), afetacoes = data.table::data.table(linha_indice = integer(), atributo = character()), falha = FALSE, n_grupos = 0L))
  if (!("ordem_tmp" %in% names(corr))) corr[, ordem_tmp := seq_len(.N)]
  if (!("id_correcao" %in% names(corr))) corr[, id_correcao := NA_character_]
  corr[, .grupo_mov_atom := fifelse(!is.na(id_correcao) & nzchar(as.character(id_correcao)), as.character(id_correcao), paste0("__linha_", ordem_tmp))]
  idx_mov <- which(monitora_correcao_eh_operacao_movimento_forma_vida(corr))
  if (!length(idx_mov)) {
    corr[, .grupo_mov_atom := NULL]
    return(list(dt = dt[], corr = corr, audit = data.table::data.table(), linhas = integer(), afetacoes = data.table::data.table(linha_indice = integer(), atributo = character()), falha = FALSE, n_grupos = 0L))
  }
  grupos <- unique(corr[idx_mov, .grupo_mov_atom])
  audit <- data.table::data.table(); linhas <- integer(); afetacoes <- data.table::data.table(linha_indice = integer(), atributo = character()); falha <- FALSE
  for (gid in grupos) {
    grp <- corr[.grupo_mov_atom == gid]
    linha_atom <- monitora_correcao_compactar_movimento_forma_vida_atomico(grp)
    res <- monitora_correcao_aplicar_movimento_forma_vida_atomico(dt, linha_atom, chaves, indice, arquivo_correcao, dicionario)
    dt <- res$dt
    if (nrow(res$audit)) audit <- data.table::rbindlist(list(audit, res$audit), fill = TRUE, use.names = TRUE)
    if (length(res$linhas)) linhas <- unique(c(linhas, res$linhas))
    if (nrow(res$afetacoes)) afetacoes <- data.table::rbindlist(list(afetacoes, res$afetacoes), fill = TRUE, use.names = TRUE)
    falha <- isTRUE(falha) || isTRUE(res$falha)
  }
  corr_out <- corr[!(.grupo_mov_atom %in% grupos)]
  corr_out[, .grupo_mov_atom := NULL]
  corr[, .grupo_mov_atom := NULL]
  list(dt = dt[], corr = corr_out[], audit = audit[], linhas = linhas, afetacoes = unique(afetacoes), falha = falha, n_grupos = length(grupos))
}


### Substituição atômica de forma de vida desconhecida
### -------------------------------------------------------------------------
### A triagem de "desconhecida" altera potencialmente várias células: remove
### token(s) históricos de listas principais, garante a forma válida na lista de
### destino, preenche hábito obrigatório quando aplicável e recalcula o campo
### superior. O bloco abaixo trata tudo como uma transação semântica única.
monitora_correcao_eh_operacao_triagem_desconhecida <- function(corr) {
  corr <- data.table::as.data.table(corr)
  if (!nrow(corr)) return(logical(0))
  idc <- if ("id_correcao" %in% names(corr)) trimws(as.character(corr$id_correcao)) else rep("", nrow(corr))
  tipo <- if ("tipo_correcao" %in% names(corr)) tolower(trimws(as.character(corr$tipo_correcao))) else rep("", nrow(corr))
  acao <- if ("acao" %in% names(corr)) tolower(trimws(as.character(corr$acao))) else rep("", nrow(corr))
  atributo <- if ("atributo_coluna_registros_corrig" %in% names(corr)) tolower(trimws(as.character(corr$atributo_coluna_registros_corrig))) else rep("", nrow(corr))
  grepl("^TRIDESC_", idc) |
    tipo %in% c("triagem_substituir_desconhecida", "triagem_substituir_desconhecida_atomica") |
    acao %in% c("substituir_desconhecida", "substituir_forma_desconhecida") |
    atributo %in% c("__substituir_desconhecida__", "__triagem_desconhecida__")
}

monitora_correcao_compactar_triagem_desconhecida_atomica <- function(grupo) {
  grupo <- data.table::as.data.table(grupo)
  if (!nrow(grupo)) return(grupo)
  if ("ordem_operacao" %in% names(grupo)) {
    grupo[, .ordem_tridesc_tmp := suppressWarnings(as.integer(ordem_operacao))]
    data.table::setorder(grupo, .ordem_tridesc_tmp, na.last = TRUE)
    grupo[, .ordem_tridesc_tmp := NULL]
  }
  pegar_primeiro <- function(col, default = NA_character_) {
    if (!(col %in% names(grupo))) return(default)
    vals <- as.character(grupo[[col]])
    vals <- vals[!is.na(vals) & nzchar(trimws(vals))]
    if (length(vals)) vals[1L] else default
  }
  linha <- data.table::copy(grupo[1L])
  if ("tipo_correcao" %in% names(linha)) linha[, tipo_correcao := "triagem_substituir_desconhecida_atomica"]
  if ("acao" %in% names(linha)) linha[, acao := "substituir_desconhecida"]
  if ("atributo_coluna_registros_corrig" %in% names(linha)) linha[, atributo_coluna_registros_corrig := "__substituir_desconhecida__"]
  if ("ordem_operacao" %in% names(linha)) {
    ord_vals <- suppressWarnings(as.integer(grupo$ordem_operacao))
    ord_vals <- ord_vals[!is.na(ord_vals) & is.finite(ord_vals)]
    linha[, ordem_operacao := if (length(ord_vals)) min(ord_vals) else NA_integer_]
  }

  acao_grupo <- if ("acao" %in% names(grupo)) tolower(trimws(as.character(grupo$acao))) else rep("", nrow(grupo))
  attr_grupo <- if ("atributo_coluna_registros_corrig" %in% names(grupo)) as.character(grupo$atributo_coluna_registros_corrig) else rep(NA_character_, nrow(grupo))
  valor_novo_grupo <- if ("valor_novo" %in% names(grupo)) as.character(grupo$valor_novo) else rep(NA_character_, nrow(grupo))
  valor_orig_grupo <- if ("valor_original_esperado" %in% names(grupo)) as.character(grupo$valor_original_esperado) else rep(NA_character_, nrow(grupo))

  tokens <- character(0)
  if ("token_removido" %in% names(grupo)) tokens <- c(tokens, unlist(lapply(as.character(grupo$token_removido), monitora_correcao_parse_lista_serializada), use.names = FALSE))
  if (all(c("acao", "valor_novo") %in% names(grupo))) tokens <- c(tokens, as.character(grupo[tolower(trimws(as.character(acao))) %in% c("remove_token", "remover_token"), valor_novo]))
  if ("token_pai" %in% names(grupo)) tokens <- c(tokens, as.character(grupo$token_pai))
  tokens <- unique(monitora_correcao_limpar_texto(tokens))
  tokens <- tokens[!is.na(tokens) & nzchar(tokens)]
  tokens_norm <- monitora_correcao_normalizar_nome_coluna(tokens)
  if (!length(tokens)) tokens <- c("desconhecida", "indeterminada", "nao_identificada", "não_identificada")
  if (!length(tokens_norm)) tokens_norm <- monitora_correcao_normalizar_nome_coluna(tokens)

  forma <- pegar_primeiro("forma_valida_escolhida")
  if (monitora_correcao_vazio(forma) && all(c("acao", "valor_novo") %in% names(grupo))) {
    idx_append <- acao_grupo %in% c("append_token", "adicionar_token", "substituir_desconhecida")
    vals_append <- valor_novo_grupo[idx_append]
    vals_append <- vals_append[!is.na(vals_append) & nzchar(trimws(vals_append))]
    if (length(vals_append)) {
      tokens_append <- unlist(lapply(vals_append, monitora_correcao_tokenizar), use.names = FALSE)
      tokens_old <- unlist(lapply(valor_orig_grupo, monitora_correcao_tokenizar), use.names = FALSE)
      old_norm <- monitora_correcao_normalizar_nome_coluna(tokens_old)
      cand_norm <- monitora_correcao_normalizar_nome_coluna(tokens_append)
      catalogo <- monitora_correcao_normalizar_nome_coluna(monitora_correcao_tokens_forma_vida_catalogo())
      habitos <- monitora_correcao_normalizar_nome_coluna(monitora_correcao_tokens_habito_catalogo())
      keep <- cand_norm %in% catalogo & !(cand_norm %in% unique(c(old_norm, tokens_norm, habitos, "desconhecida", "indeterminada", "nao_identificada")))
      if (any(keep, na.rm = TRUE)) {
        forma <- tokens_append[which(keep)[1L]]
      } else if (length(vals_append) == 1L && length(monitora_correcao_tokenizar(vals_append[1L])) == 1L) {
        forma <- vals_append[1L]
      }
    }
  }
  if (monitora_correcao_vazio(forma)) forma <- pegar_primeiro("valor_novo")
  forma <- monitora_correcao_limpar_texto(forma)
  if ("forma_valida_escolhida" %in% names(linha)) linha[, forma_valida_escolhida := forma]
  if ("valor_novo" %in% names(linha)) linha[, valor_novo := forma]

  destino <- pegar_primeiro("lista_destino", pegar_primeiro("categoria_destino"))
  if (monitora_correcao_vazio(destino) && all(c("acao", "categoria_destino") %in% names(grupo))) {
    vals_dest <- unique(as.character(grupo[tolower(trimws(as.character(acao))) %in% c("append_token", "adicionar_token", "substituir_desconhecida"), categoria_destino]))
    vals_dest <- vals_dest[!is.na(vals_dest) & nzchar(trimws(vals_dest))]
    if (length(vals_dest)) destino <- vals_dest[1L]
  }
  if (monitora_correcao_vazio(destino)) {
    idx_append <- acao_grupo %in% c("append_token", "adicionar_token", "substituir_desconhecida")
    cats <- monitora_correcao_categoria_coluna_canonica(attr_grupo[idx_append])
    cats <- cats[!is.na(cats) & nzchar(cats)]
    if (length(cats)) destino <- cats[1L]
  }
  if ("lista_destino" %in% names(linha)) linha[, lista_destino := destino]
  if ("categoria_destino" %in% names(linha)) linha[, categoria_destino := destino]
  if ("categoria_origem" %in% names(linha)) linha[, categoria_origem := "desconhecida"]

  tokens <- unique(monitora_correcao_limpar_texto(tokens))
  tokens <- tokens[!is.na(tokens) & nzchar(tokens) & !(monitora_correcao_normalizar_nome_coluna(tokens) %in% monitora_correcao_normalizar_nome_coluna(c(forma, destino)))]
  if (!length(tokens)) tokens <- c("desconhecida", "indeterminada", "nao_identificada", "não_identificada")
  if ("token_removido" %in% names(linha)) linha[, token_removido := monitora_correcao_colapsar_lista_serializada(tokens)]
  if ("token_pai" %in% names(linha)) linha[, token_pai := monitora_correcao_colapsar_tokens(tokens)]

  hab <- pegar_primeiro("habito_escolhido")
  if (monitora_correcao_vazio(hab) && all(c("acao", "valor_novo") %in% names(grupo))) {
    cand <- valor_novo_grupo[acao_grupo %in% c("update", "substituir_valor")]
    cand <- cand[!is.na(cand) & nzchar(trimws(cand)) & cand %in% c("terrestre", "epifita", "rupicola")]
    if (length(cand)) hab <- cand[1L]
  }
  if ("habito_escolhido" %in% names(linha)) linha[, habito_escolhido := hab]

  dep <- pegar_primeiro("campo_dependente_preenchido")
  if (monitora_correcao_vazio(dep)) {
    idx_hab <- acao_grupo %in% c("update", "substituir_valor") & valor_novo_grupo %in% c("terrestre", "epifita", "rupicola")
    cand_dep <- attr_grupo[idx_hab]
    cand_dep <- cand_dep[!is.na(cand_dep) & nzchar(trimws(cand_dep))]
    if (length(cand_dep)) dep <- cand_dep[1L]
  }
  if ("campo_dependente_preenchido" %in% names(linha)) linha[, campo_dependente_preenchido := dep]
  linha[]
}

monitora_correcao_aplicar_triagem_desconhecida_atomica <- function(dt, linha_tri, chaves = monitora_correcao_colunas_chave(dt), indice = NULL, arquivo_correcao = NA_character_, dicionario = NULL) {
  dt <- monitora_dt_referenciar(dt)
  linha_tri <- data.table::as.data.table(linha_tri)
  if (!nrow(linha_tri)) return(list(dt = dt[], audit = data.table::data.table(), linhas = integer(), afetacoes = data.table::data.table(linha_indice = integer(), atributo = character()), falha = FALSE))
  id_cor <- if ("id_correcao" %in% names(linha_tri)) as.character(linha_tri$id_correcao[1L]) else NA_character_
  ordem <- if ("ordem_operacao" %in% names(linha_tri)) linha_tri$ordem_operacao[1L] else NA_character_
  falhar <- function(status, msg, atributo = "__substituir_desconhecida__") {
    list(
      dt = dt[],
      audit = data.table::data.table(id_correcao = id_cor, ordem_operacao = ordem, status = status, mensagem = paste0("Substituição atômica de desconhecida bloqueada: ", msg), atributo = atributo, linha_indice = NA_integer_, valor_antes = NA_character_, valor_depois = NA_character_, arquivo_correcao = arquivo_correcao),
      linhas = integer(),
      afetacoes = data.table::data.table(linha_indice = integer(), atributo = character()),
      falha = TRUE
    )
  }
  forma <- if ("forma_valida_escolhida" %in% names(linha_tri)) trimws(as.character(linha_tri$forma_valida_escolhida[1L])) else NA_character_
  if (monitora_correcao_vazio(forma) && "valor_novo" %in% names(linha_tri)) forma <- trimws(as.character(linha_tri$valor_novo[1L]))
  destino <- if ("lista_destino" %in% names(linha_tri)) trimws(as.character(linha_tri$lista_destino[1L])) else NA_character_
  if (monitora_correcao_vazio(destino) && "categoria_destino" %in% names(linha_tri)) destino <- trimws(as.character(linha_tri$categoria_destino[1L]))
  tokens_remover <- character(0)
  if ("token_removido" %in% names(linha_tri)) tokens_remover <- c(tokens_remover, monitora_correcao_parse_lista_serializada(linha_tri$token_removido[1L]))
  if ("token_pai" %in% names(linha_tri)) tokens_remover <- c(tokens_remover, monitora_correcao_tokenizar(linha_tri$token_pai[1L]))
  tokens_remover <- unique(monitora_correcao_limpar_texto(tokens_remover))
  tokens_remover <- tokens_remover[!is.na(tokens_remover) & nzchar(tokens_remover) & !(tokens_remover %in% monitora_correcao_limpar_texto(c(forma, destino)))]
  if (!length(tokens_remover)) tokens_remover <- c("desconhecida", "indeterminada", "nao_identificada", "não_identificada")
  if (monitora_correcao_vazio(forma) || monitora_correcao_vazio(destino)) return(falhar("falha_triagem_incompleta", "forma válida ou lista de destino não informada"))
  col_destino <- tryCatch(monitora_correcao_coluna_forma_vida(dt, destino), error = function(e) NA_character_)
  if (is.na(col_destino) || !(col_destino %in% names(dt))) return(falhar("falha_coluna_destino", paste0("coluna de destino não localizada para ", destino)))
  if (monitora_correcao_coluna_protegida(col_destino)) return(falhar("bloqueada_coluna_protegida", "destino é coluna protegida"))
  valid_dest <- monitora_correcao_validar_destino_operacao(dt, col_destino, "append_token", forma, linha_tri)
  if (!isTRUE(valid_dest$ok)) return(falhar(valid_dest$status, valid_dest$mensagem, col_destino))

  linhas <- unique(as.integer(monitora_correcao_linhas_triagem_desconhecida_lote(dt, linha_tri, chaves, indice)))
  linhas <- linhas[!is.na(linhas) & linhas >= 1L & linhas <= nrow(dt)]
  n_esperado <- if ("n_linhas_esperado" %in% names(linha_tri)) suppressWarnings(as.integer(linha_tri$n_linhas_esperado[1L])) else NA_integer_
  if (!length(linhas)) return(falhar("falha_sem_linhas", "nenhuma linha-alvo localizada"))
  if (!is.na(n_esperado) && n_esperado > 0L && length(linhas) != n_esperado) return(falhar("falha_n_linhas", paste0("n_linhas_alvo=", length(linhas), " diferente de n_linhas_esperado=", n_esperado)))

  categorias <- c("nativa", "exotica", "seca_morta")
  cols_origem <- unique(vapply(categorias, function(cat) tryCatch(monitora_correcao_coluna_forma_vida(dt, cat), error = function(e) NA_character_), character(1)))
  cols_origem <- cols_origem[!is.na(cols_origem) & cols_origem %in% names(dt) & !monitora_correcao_coluna_protegida(cols_origem)]
  registrar <- function(status, msg, atributo, idx, antes, depois) {
    data.table::data.table(id_correcao = id_cor, ordem_operacao = ordem, status = status, mensagem = msg, atributo = atributo, linha_indice = as.integer(idx), valor_antes = as.character(antes), valor_depois = as.character(depois), arquivo_correcao = arquivo_correcao)
  }
  audit <- data.table::data.table()
  linhas_afetadas <- integer()
  afetacoes <- data.table::data.table(linha_indice = integer(), atributo = character())

  atualizacoes_colunas <- list()
  token_presente_algum <- FALSE
  cols_plano <- unique(c(cols_origem, col_destino))
  cols_plano <- cols_plano[!is.na(cols_plano) & cols_plano %in% names(dt)]
  for (cc in cols_plano) {
    antes <- as.character(dt[[cc]][linhas])
    depois <- antes
    remove_nesta_coluna <- cc %in% cols_origem
    adiciona_nesta_coluna <- identical(cc, col_destino)
    if (isTRUE(remove_nesta_coluna)) {
      presente <- Reduce(`|`, lapply(tokens_remover, function(tok) monitora_correcao_token_presente_vec(depois, tok)))
      token_presente_algum <- isTRUE(token_presente_algum) || any(presente, na.rm = TRUE)
      for (tok in tokens_remover) depois <- vapply(depois, monitora_correcao_remove_token_valor, character(1), token = tok)
    }
    if (isTRUE(adiciona_nesta_coluna)) {
      depois <- vapply(depois, monitora_correcao_append_token_valor, character(1), token = forma)
    }
    mudou <- monitora_correcao_na_para_vazio(antes) != monitora_correcao_na_para_vazio(depois)
    if (any(mudou, na.rm = TRUE)) {
      msg <- if (isTRUE(remove_nesta_coluna) && isTRUE(adiciona_nesta_coluna)) {
        "Substituição atômica: desconhecida removida e forma válida garantida na mesma lista"
      } else if (isTRUE(remove_nesta_coluna)) {
        "Substituição atômica: token(s) de desconhecida removido(s) da origem"
      } else {
        "Substituição atômica: forma válida garantida na lista de destino"
      }
      atualizacoes_colunas[[cc]] <- list(idx = linhas[mudou], antes = antes[mudou], depois = depois[mudou], mensagem = msg)
    }
  }

  habito <- if ("habito_escolhido" %in% names(linha_tri)) trimws(as.character(linha_tri$habito_escolhido[1L])) else ""
  if (is.na(habito)) habito <- ""
  forma_exige_habito <- monitora_correcao_limpar_texto(forma) %in% c("bromelioide", "erva_bromelioide", "cactacea", "orquidea", "samambaia")
  dep_destino <- if ("campo_dependente_preenchido" %in% names(linha_tri)) trimws(as.character(linha_tri$campo_dependente_preenchido[1L])) else NA_character_
  if (is.na(dep_destino) || !nzchar(dep_destino) || !(dep_destino %in% names(dt))) dep_destino <- tryCatch(monitora_correcao_resolver_coluna_habito(dt, destino, forma, dicionario, linha = linhas[1L], meta_xls = NULL), error = function(e) NA_character_)
  atualizacao_habito <- NULL
  if (isTRUE(forma_exige_habito)) {
    if (!nzchar(habito) || !(habito %in% c("terrestre", "epifita", "rupicola"))) return(falhar("falha_habito_obrigatorio", paste0("forma '", forma, "' exige hábito terrestre/epifita/rupicola")))
    if (!monitora_correcao_coluna_habito_segura(dt, dep_destino, destino, forma) || identical(dep_destino, col_destino)) return(falhar("falha_coluna_habito_destino", "coluna de hábito segura não localizada para o destino"))
    antes_hab <- as.character(dt[[dep_destino]][linhas])
    depois_hab <- rep(habito, length(linhas))
    mudou_hab <- monitora_correcao_na_para_vazio(antes_hab) != monitora_correcao_na_para_vazio(depois_hab)
    if (any(mudou_hab, na.rm = TRUE)) atualizacao_habito <- list(col = dep_destino, idx = linhas[mudou_hab], antes = antes_hab[mudou_hab], depois = depois_hab[mudou_hab])
  } else if (nzchar(habito)) {
    return(falhar("falha_habito_indevido", paste0("hábito informado para forma que não exige hábito: ", forma)))
  }

  for (cc in names(atualizacoes_colunas)) {
    zz <- atualizacoes_colunas[[cc]]
    data.table::set(dt, i = zz$idx, j = cc, value = zz$depois)
    audit <- data.table::rbindlist(list(audit, registrar("aplicada_atomica", zz$mensagem, cc, zz$idx, zz$antes, zz$depois)), fill = TRUE, use.names = TRUE)
    linhas_afetadas <- unique(c(linhas_afetadas, zz$idx)); afetacoes <- data.table::rbindlist(list(afetacoes, data.table::data.table(linha_indice = zz$idx, atributo = cc)), fill = TRUE, use.names = TRUE)
  }
  if (!is.null(atualizacao_habito)) {
    data.table::set(dt, i = atualizacao_habito$idx, j = atualizacao_habito$col, value = atualizacao_habito$depois)
    audit <- data.table::rbindlist(list(audit, registrar("aplicada_atomica", "Substituição atômica: hábito obrigatório preenchido", atualizacao_habito$col, atualizacao_habito$idx, atualizacao_habito$antes, atualizacao_habito$depois)), fill = TRUE, use.names = TRUE)
    linhas_afetadas <- unique(c(linhas_afetadas, atualizacao_habito$idx)); afetacoes <- data.table::rbindlist(list(afetacoes, data.table::data.table(linha_indice = atualizacao_habito$idx, atributo = atualizacao_habito$col)), fill = TRUE, use.names = TRUE)
  }
  if (any(monitora_correcao_normalizar_nome_coluna(tokens_remover) %in% monitora_correcao_normalizar_nome_coluna(monitora_correcao_tokens_desconhecida()))) {
    res_desc_dep <- monitora_correcao_sanitizar_dependentes_desconhecida(
      dt,
      linhas = linhas,
      categorias = c("nativa", "exotica", "seca_morta"),
      id_correcao = id_cor,
      ordem_operacao = ordem,
      arquivo_correcao = arquivo_correcao,
      dicionario = dicionario,
      registrar_preservadas = TRUE
    )
    dt <- res_desc_dep$dt
    if (nrow(res_desc_dep$audit)) audit <- data.table::rbindlist(list(audit, res_desc_dep$audit), fill = TRUE, use.names = TRUE)
    if (nrow(res_desc_dep$afetacoes)) afetacoes <- data.table::rbindlist(list(afetacoes, res_desc_dep$afetacoes), fill = TRUE, use.names = TRUE)
    if (nrow(res_desc_dep$afetacoes)) linhas_afetadas <- unique(c(linhas_afetadas, res_desc_dep$afetacoes$linha_indice))
  }
  tipo_col <- chaves$tipo_forma_vida
  if (!is.na(tipo_col) && tipo_col %in% names(dt)) {
    antes_tipo <- as.character(dt[[tipo_col]][linhas])
    monitora_correcao_recalcular_tipo_forma_vida(dt, linhas)
    depois_tipo <- as.character(dt[[tipo_col]][linhas])
    mudou_tipo <- monitora_correcao_na_para_vazio(antes_tipo) != monitora_correcao_na_para_vazio(depois_tipo)
    if (any(mudou_tipo, na.rm = TRUE)) {
      audit <- data.table::rbindlist(list(audit, registrar("aplicada_atomica", "Substituição atômica: tipo_forma_vida recalculado após triagem", tipo_col, linhas[mudou_tipo], antes_tipo[mudou_tipo], depois_tipo[mudou_tipo])), fill = TRUE, use.names = TRUE)
      linhas_afetadas <- unique(c(linhas_afetadas, linhas[mudou_tipo])); afetacoes <- data.table::rbindlist(list(afetacoes, data.table::data.table(linha_indice = linhas[mudou_tipo], atributo = tipo_col)), fill = TRUE, use.names = TRUE)
    }
  }
  if (!isTRUE(token_presente_algum)) {
    audit <- data.table::rbindlist(list(audit, registrar("aviso_sem_token_origem_atomica", "Substituição atômica: token(s) de desconhecida não estavam mais presentes; forma de destino/hábito/tipo foram harmonizados", "__substituir_desconhecida__", linhas, NA_character_, forma)), fill = TRUE, use.names = TRUE)
  }
  if (!nrow(audit)) {
    audit <- registrar("bloqueada_operacao_repetida_sem_efeito", "Substituição atômica bloqueada: operação repetida ou sem efeito; origem, destino, hábito e tipo_forma_vida já estavam coerentes antes da aplicação", "__substituir_desconhecida__", linhas, NA_character_, NA_character_)
    return(list(dt = dt[], audit = audit[], linhas = linhas, afetacoes = data.table::data.table(linha_indice = integer(), atributo = character()), falha = TRUE))
  }
  list(dt = dt[], audit = audit[], linhas = unique(c(linhas, linhas_afetadas)), afetacoes = unique(afetacoes), falha = FALSE)
}

monitora_correcao_aplicar_triagens_desconhecida_atomicas <- function(dt, corr, chaves = monitora_correcao_colunas_chave(dt), indice = NULL, arquivo_correcao = NA_character_, dicionario = NULL) {
  dt <- monitora_dt_referenciar(dt)
  corr <- data.table::as.data.table(corr)
  if (!nrow(corr)) return(list(dt = dt[], corr = corr, audit = data.table::data.table(), linhas = integer(), afetacoes = data.table::data.table(linha_indice = integer(), atributo = character()), falha = FALSE, n_grupos = 0L))
  if (!("ordem_tmp" %in% names(corr))) corr[, ordem_tmp := seq_len(.N)]
  if (!("id_correcao" %in% names(corr))) corr[, id_correcao := NA_character_]
  corr[, .grupo_tridesc_atom := fifelse(!is.na(id_correcao) & nzchar(as.character(id_correcao)), as.character(id_correcao), paste0("__linha_", ordem_tmp))]
  idx_tri <- which(monitora_correcao_eh_operacao_triagem_desconhecida(corr))
  if (!length(idx_tri)) {
    corr[, .grupo_tridesc_atom := NULL]
    return(list(dt = dt[], corr = corr, audit = data.table::data.table(), linhas = integer(), afetacoes = data.table::data.table(linha_indice = integer(), atributo = character()), falha = FALSE, n_grupos = 0L))
  }
  grupos <- unique(corr[idx_tri, .grupo_tridesc_atom])
  audit <- data.table::data.table(); linhas <- integer(); afetacoes <- data.table::data.table(linha_indice = integer(), atributo = character()); falha <- FALSE
  for (gid in grupos) {
    grp <- corr[.grupo_tridesc_atom == gid]
    linha_atom <- monitora_correcao_compactar_triagem_desconhecida_atomica(grp)
    res <- monitora_correcao_aplicar_triagem_desconhecida_atomica(dt, linha_atom, chaves, indice, arquivo_correcao, dicionario)
    dt <- res$dt
    if (nrow(res$audit)) audit <- data.table::rbindlist(list(audit, res$audit), fill = TRUE, use.names = TRUE)
    if (length(res$linhas)) linhas <- unique(c(linhas, res$linhas))
    if (nrow(res$afetacoes)) afetacoes <- data.table::rbindlist(list(afetacoes, res$afetacoes), fill = TRUE, use.names = TRUE)
    falha <- isTRUE(falha) || isTRUE(res$falha)
  }
  corr_out <- corr[!(.grupo_tridesc_atom %in% grupos)]
  corr_out[, .grupo_tridesc_atom := NULL]
  corr[, .grupo_tridesc_atom := NULL]

  list(dt = dt[], corr = corr_out[], audit = audit[], linhas = linhas, afetacoes = unique(afetacoes), falha = falha, n_grupos = length(grupos))
}

### v2.6.1: transação semântica agrupada para operações do painel
### -------------------------------------------------------------------------
### O painel pode gerar muitos itens auditáveis para uma única decisão do
### bolsista. A partir daqui, a regra é: a fila guarda operações semânticas
### agrupadas; os itens por linha ficam apenas na auditoria expandida; a
### aplicação usa máscaras vetorizadas por grupos semânticos.
monitora_correcao_parse_serial_generico <- function(x) {
  x <- as.character(x)
  x <- x[!is.na(x) & nzchar(trimws(x))]
  if (!length(x)) return(character(0))
  vals <- unlist(strsplit(paste(x, collapse = "|"), "\\s*(\\||;|,)\\s*"), use.names = FALSE)
  vals <- unique(trimws(as.character(vals)))
  vals[!is.na(vals) & nzchar(vals)]
}


monitora_correcao_linhas_desconhecida_sem_categoria_base <- function(dt, linhas_base = NULL, chaves = monitora_correcao_colunas_chave(dt)) {
  dt <- data.table::as.data.table(dt)
  n <- nrow(dt)
  if (!n) return(integer(0))
  if (is.null(linhas_base)) linhas_base <- seq_len(n)
  linhas_base <- unique(as.integer(linhas_base))
  linhas_base <- linhas_base[!is.na(linhas_base) & linhas_base >= 1L & linhas_base <= n]
  if (!length(linhas_base)) return(integer(0))
  tipo_col <- tryCatch(chaves$tipo_forma_vida, error = function(e) NA_character_)
  if (is.na(tipo_col) || !nzchar(as.character(tipo_col)[1L]) || !(as.character(tipo_col)[1L] %in% names(dt))) {
    cand <- grep("encostam|tipo_forma_vida", names(dt), ignore.case = TRUE, value = TRUE)
    tipo_col <- if (length(cand)) cand[1L] else NA_character_
  }
  if (is.na(tipo_col) || !(tipo_col %in% names(dt))) return(integer(0))
  tipo <- as.character(dt[[tipo_col]][linhas_base])
  toks_desc <- tryCatch(monitora_correcao_tokens_desconhecida(), error = function(e) c("desconhecida", "desconhecido", "indeterminada", "nao_identificada", "não_identificada"))
  tem_desc_sup <- tryCatch(monitora_correcao_contem_qualquer_token_vec(tipo, toks_desc), error = function(e) rep(FALSE, length(linhas_base)))
  tem_desc_sup[is.na(tem_desc_sup)] <- FALSE
  toks_base <- c("nativa", "nativas", "nativo", "nativos", "exotica", "exoticas", "exotico", "exoticos", "seca_morta", "seca", "secas", "seco", "secos", "morta", "mortas", "morto", "mortos", "solo_nu", "solo", "serrapilheira", "outras_plantas_terrestres", "forma_vida_outros")
  tem_base_sup <- tryCatch(monitora_correcao_contem_qualquer_token_vec(tipo, toks_base), error = function(e) rep(FALSE, length(linhas_base)))
  tem_base_sup[is.na(tem_base_sup)] <- FALSE
  tem_inferior <- rep(FALSE, length(linhas_base))
  for (cat_desc in c("nativa", "exotica", "seca_morta")) {
    cols_d <- tryCatch(monitora_correcao_colunas_forma_vida_categoria(dt, cat_desc), error = function(e) character(0))
    cols_d <- cols_d[cols_d %in% names(dt)]
    for (cc in cols_d) {
      hit <- tryCatch(!monitora_correcao_vazio_vec(dt[[cc]][linhas_base]), error = function(e) rep(FALSE, length(linhas_base)))
      hit[is.na(hit)] <- FALSE
      tem_inferior <- tem_inferior | hit
    }
  }
  cols_outros <- grep("forma_vida_outros|outras_plantas_terrestres|forma_serrapilheira", names(dt), ignore.case = TRUE, value = TRUE)
  for (cc in unique(cols_outros)) {
    hit <- tryCatch(!monitora_correcao_vazio_vec(dt[[cc]][linhas_base]), error = function(e) rep(FALSE, length(linhas_base)))
    hit[is.na(hit)] <- FALSE
    tem_inferior <- tem_inferior | hit
  }
  linhas_base[tem_desc_sup & !tem_base_sup & !tem_inferior]
}

monitora_correcao_linhas_desconhecida_dados <- function(dt, linhas_base = NULL, chaves = monitora_correcao_colunas_chave(dt), dicionario = NULL) {
  dt <- data.table::as.data.table(dt)
  n <- nrow(dt)
  if (!n) return(integer(0))
  if (is.null(linhas_base)) linhas_base <- seq_len(n)
  linhas_base <- unique(as.integer(linhas_base))
  linhas_base <- linhas_base[!is.na(linhas_base) & linhas_base >= 1L & linhas_base <= n]
  if (!length(linhas_base)) return(integer(0))
  toks_desc <- tryCatch(monitora_correcao_tokens_desconhecida(), error = function(e) c("desconhecida", "desconhecido", "indeterminada", "nao_identificada", "não_identificada"))
  hit_total <- rep(FALSE, length(linhas_base))
  for (cat_desc in c("nativa", "exotica", "seca_morta")) {
    col_princ <- tryCatch(monitora_correcao_coluna_forma_vida(dt, cat_desc), error = function(e) NA_character_)
    if (!is.na(col_princ) && col_princ %in% names(dt)) {
      h <- tryCatch(monitora_correcao_contem_qualquer_token_vec(dt[[col_princ]][linhas_base], toks_desc), error = function(e) rep(FALSE, length(linhas_base)))
      h[is.na(h)] <- FALSE
      hit_total <- hit_total | h
    }
    dep <- tryCatch(monitora_correcao_colunas_desconhecida_por_categoria(dt, cat_desc, dicionario), error = function(e) data.table::data.table())
    if (nrow(dep)) {
      for (cc in unique(as.character(dep$coluna[dep$coluna %in% names(dt)]))) {
        h <- tryCatch(!monitora_correcao_vazio_vec(dt[[cc]][linhas_base]), error = function(e) rep(FALSE, length(linhas_base)))
        h[is.na(h)] <- FALSE
        hit_total <- hit_total | h
      }
    }
  }
  idx_superior_only <- tryCatch(monitora_correcao_linhas_desconhecida_sem_categoria_base(dt, linhas_base, chaves = chaves), error = function(e) integer(0))
  if (length(idx_superior_only)) hit_total <- hit_total | (linhas_base %in% idx_superior_only)
  linhas_base[hit_total]
}

monitora_correcao_linhas_desconhecida_categoria_base <- function(dt, categoria, linhas_base = NULL, dicionario = NULL) {
  dt <- data.table::as.data.table(dt)
  n <- nrow(dt)
  if (!n) return(integer(0))
  if (is.null(linhas_base)) linhas_base <- seq_len(n)
  linhas_base <- unique(as.integer(linhas_base))
  linhas_base <- linhas_base[!is.na(linhas_base) & linhas_base >= 1L & linhas_base <= n]
  if (!length(linhas_base)) return(integer(0))
  categoria <- tolower(trimws(as.character(categoria)[1L]))
  if (!(categoria %in% c("nativa", "exotica", "seca_morta"))) return(integer(0))
  toks_desc <- tryCatch(monitora_correcao_tokens_desconhecida(), error = function(e) c("desconhecida", "desconhecido"))
  hit_total <- rep(FALSE, length(linhas_base))
  col_princ <- tryCatch(monitora_correcao_coluna_forma_vida(dt, categoria), error = function(e) NA_character_)
  if (!is.na(col_princ) && col_princ %in% names(dt)) {
    h <- tryCatch(monitora_correcao_contem_qualquer_token_vec(dt[[col_princ]][linhas_base], toks_desc), error = function(e) rep(FALSE, length(linhas_base)))
    h[is.na(h)] <- FALSE
    hit_total <- hit_total | h
  }
  dep <- tryCatch(monitora_correcao_colunas_desconhecida_por_categoria(dt, categoria, dicionario), error = function(e) data.table::data.table())
  if (nrow(dep)) {
    for (cc in unique(as.character(dep$coluna[dep$coluna %in% names(dt)]))) {
      h <- tryCatch(!monitora_correcao_vazio_vec(dt[[cc]][linhas_base]), error = function(e) rep(FALSE, length(linhas_base)))
      h[is.na(h)] <- FALSE
      hit_total <- hit_total | h
    }
  }
  linhas_base[hit_total]
}

monitora_correcao_linhas_triagem_desconhecida_lote <- function(dt, linha_tri, chaves = monitora_correcao_colunas_chave(dt), indice = NULL) {
  dt <- data.table::as.data.table(dt)
  linha_tri <- data.table::as.data.table(linha_tri)
  n <- nrow(dt)
  if (!n || !nrow(linha_tri)) return(integer(0))
  # 1) IDs estáveis de registro, quando gravados como lista serializada.
  uuid_cols <- intersect(c("uuid_registro", "uuid_registro_serializado", "uuids_registro"), names(linha_tri))
  uu <- character(0)
  for (cc in uuid_cols) uu <- c(uu, monitora_correcao_parse_serial_generico(linha_tri[[cc]][1L]))
  uu <- unique(uu[!is.na(uu) & nzchar(uu)])
  if (length(uu) && !is.na(chaves$uuid_registro) && chaves$uuid_registro %in% names(dt)) {
    idx <- which(trimws(as.character(dt[[chaves$uuid_registro]])) %chin% uu)
    idx <- unique(as.integer(idx))
    if (length(idx)) return(idx)
  }
  # 2) Índices gravados apenas para prévia/aplicação na mesma sessão.
  lin_cols <- intersect(c("linhas_alvo_serializadas", "linha_indice", "linhas_alvo"), names(linha_tri))
  li <- integer(0)
  for (cc in lin_cols) {
    z <- suppressWarnings(as.integer(monitora_correcao_parse_serial_generico(linha_tri[[cc]][1L])))
    li <- c(li, z)
  }
  li <- unique(li[!is.na(li) & li >= 1L & li <= n])
  if (length(li)) return(li)
  # 3) Escopo por COLETA, sempre reavaliando a ocorrência de desconhecida.
  coletas <- character(0)
  if ("coleta" %in% names(linha_tri)) coletas <- c(coletas, monitora_correcao_parse_serial_generico(linha_tri$coleta[1L]))
  if ("coletas" %in% names(linha_tri)) coletas <- c(coletas, monitora_correcao_parse_serial_generico(linha_tri$coletas[1L]))
  coletas <- unique(coletas[!is.na(coletas) & nzchar(coletas)])
  if (length(coletas) && !is.na(chaves$coleta) && chaves$coleta %in% names(dt)) {
    idx_base <- which(as.character(dt[[chaves$coleta]]) %chin% coletas)
    idx_desc <- monitora_correcao_linhas_desconhecida_dados(dt, idx_base, chaves = chaves, dicionario = NULL)
    if (length(idx_desc)) return(idx_desc)
  }
  # 4) Fallback para a regra histórica.
  unique(as.integer(monitora_correcao_localizar_linhas(dt, linha_tri, chaves, indice)))
}


monitora_correcao_classificar_tipo_operacao <- function(corr) {
  corr <- data.table::as.data.table(corr)
  if (!nrow(corr)) return(character(0))
  getc <- function(nm) if (nm %in% names(corr)) as.character(corr[[nm]]) else rep("", nrow(corr))
  idc <- toupper(trimws(getc("id_correcao")))
  tipo <- tolower(trimws(getc("tipo_correcao")))
  acao <- tolower(trimws(getc("acao")))
  attr <- tolower(trimws(getc("atributo_coluna_registros_corrig")))
  out <- rep("operacao_generica", nrow(corr))
  out[grepl("^EXCCOL", idc) | tipo %in% c("exclusao_coletas_filtradas", "exclusao_coleta_atomica") | acao %in% c("excluir_coleta", "exclusao_coleta")] <- "exclusao_coleta_atomica"
  out[grepl("^PENDFV", idc) | tipo %in% c("pendencia_sem_forma_vida_lote", "pendencia_sem_forma_vida") | attr %in% c("__pendencia_sem_forma_vida__")] <- "pendencia_sem_forma_vida_lote"
  out[grepl("^TRIOUT", idc) | tipo %in% c("triagem_limpeza_outras_formas_vida_atomica", "limpeza_outras_formas_vida_atomica") | acao %in% c("limpar_outras_formas_vida", "limpeza_outras_formas_vida_atomica")] <- "limpeza_outras_formas_atomica"
  out[grepl("^TRIDESC", idc) | tipo %in% c("triagem_substituir_desconhecida", "triagem_substituir_desconhecida_atomica") | acao %in% c("substituir_desconhecida", "substituir_forma_desconhecida") | attr %in% c("__substituir_desconhecida__", "__triagem_desconhecida__")] <- "triagem_desconhecida_atomica"
  out[grepl("^MVLOTE", idc) | tipo %in% c("movimento_forma_vida_lote_atomico", "movimento_forma_vida_lote") | acao %in% c("mover_forma_vida_lote", "movimento_forma_vida_lote_atomico") | attr %in% c("__mover_forma_vida_lote__", "__movimento_forma_vida_lote__")] <- "movimento_forma_vida_lote_atomico"
  out[grepl("^MOVFV", idc) | tipo %in% c("movimento_forma_vida_atomico", "movimento_forma_vida_condicional", "movimento_forma_vida") | acao %in% c("mover_forma_vida", "movimento_forma_vida_atomico") | attr %in% c("__mover_forma_vida__", "__movimento_forma_vida__")] <- "movimento_forma_vida_atomico"
  out[grepl("^RECALC_SUPERIORES_XLSFORM$", idc)] <- "recalculo_superiores_xlsform"
  out[grepl("^SYNC_ENCOSTAM_FINAL$", idc)] <- "sincronizacao_final_encostam"
  out
}

monitora_correcao_chave_semantica_operacao <- function(corr) {
  corr <- data.table::as.data.table(corr)
  n <- nrow(corr)
  if (!n) return(character(0))
  getc <- function(nm) if (nm %in% names(corr)) as.character(corr[[nm]]) else rep("", n)
  fam <- monitora_correcao_classificar_tipo_operacao(corr)
  campos <- list(
    familia = fam,
    tipo = getc("tipo_correcao"), acao = getc("acao"),
    atributo = getc("atributo_coluna_registros_corrig"),
    categoria_origem = getc("categoria_origem"), categoria_destino = getc("categoria_destino"),
    lista_destino = getc("lista_destino"), token_pai = getc("token_pai"), token_removido = getc("token_removido"),
    valor_novo = getc("valor_novo"), forma = getc("forma_valida_escolhida"), habito = getc("habito_escolhido"),
    campo_dep = getc("campo_dependente_preenchido"), escopo = getc("escopo_aplicacao"), motivo = getc("motivo")
  )
  mat <- data.frame(lapply(campos, function(v) { v <- tolower(trimws(as.character(v))); v[is.na(v)] <- ""; v }), check.names = FALSE)
  apply(mat, 1L, paste, collapse = "\r")
}

monitora_correcao_agrupar_operacoes_semanticas <- function(ops) {
  ops <- data.table::as.data.table(ops)
  if (!nrow(ops)) return(ops)
  for (cc in c("id_correcao", "uuid_registro", "linha_indice", "coleta", "ponto_amostral", "n_linhas_esperado", "n_linhas_alvo", "motivo")) if (!(cc %in% names(ops))) data.table::set(ops, j = cc, value = NA_character_)
  key <- monitora_correcao_chave_semantica_operacao(ops)
  fam <- monitora_correcao_classificar_tipo_operacao(ops)
  idx_grp <- which(fam %in% c("triagem_desconhecida_atomica", "pendencia_sem_forma_vida", "limpeza_outras_formas_atomica", "movimento_forma_vida_lote", "movimento_forma_vida_atomico"))
  if (!length(idx_grp)) return(ops[])
  ops[, .semkey_agrupar := key]
  out <- list()
  # mantém operações não agrupáveis como estão
  if (length(setdiff(seq_len(nrow(ops)), idx_grp))) out[[length(out)+1L]] <- ops[setdiff(seq_len(nrow(ops)), idx_grp)]
  for (kk in unique(ops$.semkey_agrupar[idx_grp])) {
    g <- data.table::copy(ops[.semkey_agrupar == kk])
    if (nrow(g) == 1L) {
      g[, .semkey_agrupar := NULL]
      out[[length(out)+1L]] <- g
      next
    }
    linha <- data.table::copy(g[1L])
    uu <- unique(monitora_correcao_parse_serial_generico(g$uuid_registro))
    li <- suppressWarnings(as.integer(monitora_correcao_parse_serial_generico(g$linha_indice)))
    li <- unique(li[!is.na(li)])
    co <- unique(monitora_correcao_parse_serial_generico(g$coleta))
    pt <- unique(monitora_correcao_parse_serial_generico(g$ponto_amostral))
    pm <- if ("ponto_metro" %in% names(g)) unique(monitora_correcao_parse_serial_generico(g$ponto_metro)) else character(0)
    if (length(uu)) linha[, uuid_registro := monitora_correcao_colapsar_lista_serializada(uu)]
    if (length(li)) linha[, linhas_alvo_serializadas := monitora_correcao_colapsar_lista_serializada(as.character(li))]
    if (length(co)) linha[, coleta := monitora_correcao_colapsar_lista_serializada(co)]
    if (length(pt)) linha[, ponto_amostral := monitora_correcao_colapsar_lista_serializada(pt)]
    if (length(pm)) linha[, ponto_metro := monitora_correcao_colapsar_lista_serializada(pm)]
    if ("Ponto amostral" %in% names(linha) && length(pt)) linha[, `Ponto amostral` := monitora_correcao_colapsar_lista_serializada(pt)]
    if ("Ponto metro" %in% names(linha) && length(pm)) linha[, `Ponto metro` := monitora_correcao_colapsar_lista_serializada(pm)]
    linha[, `:=`(
      n_linhas_esperado = ifelse(length(uu) > 0L, length(uu), ifelse(length(li) > 0L, length(li), nrow(g))),
      n_linhas_alvo = ifelse(length(uu) > 0L, length(uu), ifelse(length(li) > 0L, length(li), nrow(g))),
      n_itens_auditaveis = nrow(g),
      operacao_semantica_agrupada = TRUE,
      motivo = paste0(as.character(motivo[1L]), " [", nrow(g), " item(ns) auditável(is) agrupado(s) em uma operação semântica]")
    )]
    linha[, .semkey_agrupar := NULL]
    out[[length(out)+1L]] <- linha
  }
  data.table::rbindlist(out, fill = TRUE, use.names = TRUE)
}

monitora_correcao_contar_operacoes_semanticas <- function(correcoes) {
  if (is.null(correcoes)) return(0L)
  cc <- data.table::as.data.table(correcoes)
  if (!nrow(cc)) return(0L)
  cc2 <- tryCatch(monitora_correcao_agrupar_operacoes_semanticas(cc), error = function(e) cc)
  if (!("id_correcao" %in% names(cc2))) return(nrow(cc2))
  ids <- trimws(as.character(cc2$id_correcao))
  ids[is.na(ids) | !nzchar(ids)] <- paste0("__linha_", which(is.na(ids) | !nzchar(ids)))
  as.integer(data.table::uniqueN(ids))
}

monitora_correcao_aplicar_triagens_desconhecida_atomicas <- function(dt, corr, chaves = monitora_correcao_colunas_chave(dt), indice = NULL, arquivo_correcao = NA_character_, dicionario = NULL) {
  dt <- monitora_dt_referenciar(dt)
  corr <- data.table::as.data.table(corr)
  if (!nrow(corr)) return(list(dt = dt[], corr = corr, audit = data.table::data.table(), linhas = integer(), afetacoes = data.table::data.table(linha_indice = integer(), atributo = character()), falha = FALSE, n_grupos = 0L))
  if (!("ordem_tmp" %in% names(corr))) corr[, ordem_tmp := seq_len(.N)]
  if (!("id_correcao" %in% names(corr))) corr[, id_correcao := NA_character_]
  idx_tri <- which(monitora_correcao_eh_operacao_triagem_desconhecida(corr))
  if (!length(idx_tri)) return(list(dt = dt[], corr = corr, audit = data.table::data.table(), linhas = integer(), afetacoes = data.table::data.table(linha_indice = integer(), atributo = character()), falha = FALSE, n_grupos = 0L))
  corr_tri <- data.table::copy(corr[idx_tri])
  corr_tri <- monitora_correcao_agrupar_operacoes_semanticas(corr_tri)
  grupos <- if ("id_correcao" %in% names(corr_tri)) unique(as.character(corr_tri$id_correcao)) else paste0("__linha_", seq_len(nrow(corr_tri)))
  audit <- data.table::data.table(); linhas <- integer(); afetacoes <- data.table::data.table(linha_indice = integer(), atributo = character()); falha <- FALSE
  for (gg in seq_along(grupos)) {
    gid <- grupos[gg]
    grp <- corr_tri[as.character(id_correcao) == gid]
    if (!nrow(grp)) grp <- corr_tri[gg]
    if (exists("monitora_correcao_console_msg", mode = "function")) {
      forma_msg <- if ("forma_valida_escolhida" %in% names(grp)) as.character(grp$forma_valida_escolhida[1L]) else as.character(grp$valor_novo[1L])
      dest_msg <- if ("categoria_destino" %in% names(grp)) as.character(grp$categoria_destino[1L]) else NA_character_
      monitora_correcao_console_msg("Aplicando operação semântica TRIDESC ", gg, "/", length(grupos), ": destino=", dest_msg, "; forma=", forma_msg, ".")
    }
    linha_atom <- monitora_correcao_compactar_triagem_desconhecida_atomica(grp)
    # A compactação antiga preserva o primeiro item; estes campos reintroduzem o escopo completo.
    for (cc in intersect(c("uuid_registro", "linhas_alvo_serializadas", "coleta", "ponto_amostral", "n_linhas_esperado", "n_linhas_alvo", "n_itens_auditaveis"), names(grp))) {
      if (cc %in% names(linha_atom)) data.table::set(linha_atom, j = cc, value = grp[[cc]][1L]) else linha_atom[, (cc) := grp[[cc]][1L]]
    }
    res <- monitora_correcao_aplicar_triagem_desconhecida_atomica(dt, linha_atom, chaves, indice, arquivo_correcao, dicionario)
    dt <- res$dt
    if (nrow(res$audit)) audit <- data.table::rbindlist(list(audit, res$audit), fill = TRUE, use.names = TRUE)
    if (length(res$linhas)) linhas <- unique(c(linhas, res$linhas))
    if (nrow(res$afetacoes)) afetacoes <- data.table::rbindlist(list(afetacoes, res$afetacoes), fill = TRUE, use.names = TRUE)
    falha <- isTRUE(falha) || isTRUE(res$falha)
  }
  # remove do plano todas as operações de desconhecida originais, processadas pela transação agrupada
  corr_out <- corr[-idx_tri]
  list(dt = dt[], corr = corr_out[], audit = audit[], linhas = linhas, afetacoes = unique(afetacoes), falha = falha, n_grupos = length(grupos))
}

### Exclusão atômica de COLETAS
### -------------------------------------------------------------------------
### Aplica grupos de exclusão de COLETAS em lote: pré-valida todas as COLETAS
### do grupo, registra auditoria no estado pré-exclusão e remove as linhas em
### uma única operação data.table, evitando reconstruir índices a cada COLETA.
monitora_correcao_aplicar_exclusoes_coleta_atomicas <- function(dt, corr, chaves = monitora_correcao_colunas_chave(dt), indice = NULL, arquivo_correcao = NA_character_) {
  dt <- monitora_dt_referenciar(dt)
  corr <- data.table::as.data.table(corr)
  if (!nrow(corr)) return(list(dt = dt, corr = corr, audit = data.table::data.table(), coletas = character(), linhas_removidas = integer(), falha = FALSE, n_grupos = 0L))
  if (!("ordem_tmp" %in% names(corr))) corr[, ordem_tmp := seq_len(.N)]
  if (!("id_correcao" %in% names(corr))) corr[, id_correcao := NA_character_]
  acao_vec <- if ("acao" %in% names(corr)) as.character(corr$acao) else rep("", nrow(corr))
  tipo_vec <- if ("tipo_correcao" %in% names(corr)) as.character(corr$tipo_correcao) else rep("", nrow(corr))
  idx_exc <- which(mapply(monitora_correcao_acao_exclusao_coleta, acao_vec, tipo_vec))
  if (!length(idx_exc)) return(list(dt = dt, corr = corr, audit = data.table::data.table(), coletas = character(), linhas_removidas = integer(), falha = FALSE, n_grupos = 0L))
  corr[, .grupo_exc_atom := fifelse(!is.na(id_correcao) & nzchar(as.character(id_correcao)), as.character(id_correcao), paste0("__linha_", ordem_tmp))]
  grupos <- unique(corr[idx_exc, .grupo_exc_atom])
  audit <- data.table::data.table()
  linhas_remover_total <- integer()
  coletas_removidas <- character()
  falha <- FALSE
  grupos_processados <- character()
  for (gid in grupos) {
    grp <- corr[.grupo_exc_atom == gid]
    invalid <- data.table::data.table()
    linhas_por_op <- vector("list", nrow(grp))
    for (ii in seq_len(nrow(grp))) {
      linha_corr <- grp[ii]
      escopo_corr <- if ("escopo_aplicacao" %in% names(linha_corr)) tolower(trimws(as.character(linha_corr$escopo_aplicacao[1L]))) else ""
      linhas <- monitora_correcao_localizar_linhas(dt, linha_corr, chaves, indice)
      linhas <- unique(as.integer(linhas))
      linhas <- linhas[!is.na(linhas) & linhas >= 1L & linhas <= nrow(dt)]
      linhas_por_op[[ii]] <- linhas
      n_esperado <- suppressWarnings(as.integer(linha_corr$n_linhas_esperado[1L]))
      status <- "ok"; msg <- "OK"
      if (!identical(escopo_corr, "coleta_inteira")) {
        status <- "bloqueada_exclusao_coleta"; msg <- "exclusão de COLETA exige escopo_aplicacao='coleta_inteira'"
      } else if (is.na(chaves$coleta) || !(chaves$coleta %in% names(dt))) {
        status <- "falha"; msg <- "Coluna de COLETA não localizada; exclusão bloqueada"
      } else if (length(linhas) == 0L) {
        status <- "falha"; msg <- "Nenhuma linha-alvo localizada para exclusão da COLETA"
      } else if (!is.na(n_esperado) && n_esperado > 0L && length(linhas) != n_esperado) {
        status <- "falha"; msg <- paste0("n_linhas_alvo=", length(linhas), " diferente de n_linhas_esperado=", n_esperado, " para exclusão da COLETA")
      }
      if (!identical(status, "ok")) {
        invalid <- data.table::rbindlist(list(invalid, data.table::data.table(
          id_correcao = linha_corr$id_correcao[1L],
          ordem_operacao = linha_corr$ordem_operacao[1L],
          status = status,
          mensagem = paste0("Grupo de exclusão bloqueado atomicamente: ", msg),
          atributo = if (!is.na(chaves$coleta)) chaves$coleta else linha_corr$atributo_coluna_registros_corrig[1L],
          linha_indice = NA_integer_,
          valor_antes = NA_character_,
          valor_depois = NA_character_,
          arquivo_correcao = arquivo_correcao
        )), fill = TRUE, use.names = TRUE)
      }
    }
    grupos_processados <- unique(c(grupos_processados, gid))
    if (nrow(invalid) > 0L) {
      audit <- data.table::rbindlist(list(audit, invalid), fill = TRUE, use.names = TRUE)
      falha <- TRUE
      next
    }
    for (ii in seq_len(nrow(grp))) {
      linha_corr <- grp[ii]
      linhas <- linhas_por_op[[ii]]
      coleta_val <- if ("coleta" %in% names(linha_corr)) as.character(linha_corr$coleta[1L]) else NA_character_
      audit_del <- data.table::data.table(
        id_correcao = linha_corr$id_correcao[1L],
        ordem_operacao = linha_corr$ordem_operacao[1L],
        status = "excluida_coleta",
        mensagem = paste0("Exclusão atômica de COLETA: ", length(linhas), " registro(s) removido(s) em lote"),
        atributo = chaves$coleta,
        linha_indice = linhas,
        valor_antes = if (!is.na(chaves$coleta) && chaves$coleta %in% names(dt)) as.character(dt[[chaves$coleta]][linhas]) else NA_character_,
        valor_depois = "<REGISTRO_REMOVIDO>",
        arquivo_correcao = arquivo_correcao
      )
      audit_del <- monitora_correcao_anexar_contexto_auditoria(audit_del, dt, chaves)
      audit <- data.table::rbindlist(list(audit, audit_del), fill = TRUE, use.names = TRUE)
      linhas_remover_total <- unique(c(linhas_remover_total, linhas))
      if (!is.na(coleta_val) && nzchar(trimws(coleta_val))) coletas_removidas <- unique(c(coletas_removidas, coleta_val))
    }
  }
  linhas_remover_total <- sort(unique(linhas_remover_total))
  linhas_remover_total <- linhas_remover_total[!is.na(linhas_remover_total) & linhas_remover_total >= 1L & linhas_remover_total <= nrow(dt)]
  if (length(linhas_remover_total) > 0L) dt <- dt[-linhas_remover_total]
  corr_out <- corr[!(.grupo_exc_atom %in% grupos_processados)]
  corr_out[, .grupo_exc_atom := NULL]
  corr[, .grupo_exc_atom := NULL]
  list(dt = dt[], corr = corr_out[], audit = audit[], coletas = coletas_removidas, linhas_removidas = linhas_remover_total, falha = falha, n_grupos = length(grupos_processados))
}


### v2.6.1 -----------------------------------------------------------------
### Replay semântico em nova execução: o arquivo de correções é uma trilha de
### intenção, não um vetor de posições. Este bloco corrige três pontos críticos:
### 1) PENDFV agrupado não pode parar nos poucos UUIDs que ainda batem; deve
###    reconstruir o escopo corrente por COLETA e filtrar pendências reais.
### 2) EXCCOL em replay não deve falhar quando a COLETA já não existe no input
###    corrente; isso é estado já materializado/ausente, não erro fatal.
### 3) MVLOTE de desconhecida não deve depender de linha_indice antigo; deve
###    reaplicar a intenção "desconhecida -> forma válida/destino" sobre as
###    ocorrências diagnósticas atuais da categoria-base no escopo de COLETAS.

monitora_replay_v263_parse_lista <- function(x) {
  if (is.null(x)) return(character(0))
  x <- as.character(x)
  x <- x[!is.na(x)]
  if (!length(x)) return(character(0))
  vals <- unlist(strsplit(x, "[|;\n\r]+", perl = TRUE), use.names = FALSE)
  vals <- trimws(as.character(vals))
  vals <- vals[!is.na(vals) & nzchar(vals)]
  vals <- vals[!(toupper(vals) %in% c("NA", "NAN", "NULL", "NONE", "---"))]
  unique(vals)
}

monitora_replay_v263_parse_colunas <- function(tab, cols) {
  tab <- data.table::as.data.table(tab)
  vals <- character(0)
  for (cc in intersect(cols, names(tab))) {
    vals <- c(vals, unlist(lapply(as.character(tab[[cc]]), monitora_replay_v263_parse_lista), use.names = FALSE))
  }
  vals <- trimws(as.character(vals))
  vals <- vals[!is.na(vals) & nzchar(vals)]
  unique(vals)
}

monitora_replay_v263_filtrar_valores <- function(dt, linhas, col, vals) {
  dt <- data.table::as.data.table(dt)
  linhas <- unique(as.integer(linhas))
  linhas <- linhas[!is.na(linhas) & linhas >= 1L & linhas <= nrow(dt)]
  vals <- unique(trimws(as.character(vals)))
  vals <- vals[!is.na(vals) & nzchar(vals)]
  if (!length(linhas) || is.na(col) || !nzchar(col) || !(col %in% names(dt)) || !length(vals)) return(linhas)
  linhas[trimws(as.character(dt[[col]][linhas])) %chin% vals]
}

monitora_correcao_linhas_pendfv_grupo <- function(dt, grupo, col, chaves = monitora_correcao_colunas_chave(dt)) {
  dt <- data.table::as.data.table(dt)
  grupo <- data.table::as.data.table(grupo)
  if (!nrow(dt) || !nrow(grupo) || is.na(col) || !(col %in% names(dt))) return(integer(0))

  ### Escopo preferencial para replay: COLETA(s) + estado diagnóstico corrente.
  ### Isso evita perder a maior parte de um lote quando apenas alguns UUIDs da
  ### rodada antiga ainda batem no input reprocessado.
  idx <- integer(0)
  coletas <- monitora_replay_v263_parse_colunas(grupo, c("coleta", "COLETA", "coletas", "coletas_alvo", "coletas_lote"))
  if (length(coletas) && !is.na(chaves$coleta) && chaves$coleta %in% names(dt)) {
    idx <- which(trimws(as.character(dt[[chaves$coleta]])) %chin% coletas)
  }

  ### UUIDs continuam úteis para arquivos não agrupados, mas são união, não
  ### condição de parada. Em grupos grandes eles costumam ser incompletos.
  uuids <- monitora_replay_v263_parse_colunas(grupo, c("uuid_registro", "uuid_registro_serializado", "uuids_registro"))
  if (length(uuids) && !is.na(chaves$uuid_registro) && chaves$uuid_registro %in% names(dt)) {
    idx_uuid <- which(trimws(as.character(dt[[chaves$uuid_registro]])) %chin% uuids)
    idx <- unique(c(idx, idx_uuid))
  }

  ### Fallback por linha antiga apenas se não houver escopo estável.
  if (!length(idx) && !length(coletas) && !length(uuids)) {
    li <- suppressWarnings(as.integer(monitora_replay_v263_parse_colunas(grupo, c("linhas_alvo_serializadas", "linha_indice", "linhas_alvo"))))
    li <- unique(li[!is.na(li) & li >= 1L & li <= nrow(dt)])
    if (length(li)) idx <- li
  }

  idx <- unique(as.integer(idx))
  idx <- idx[!is.na(idx) & idx >= 1L & idx <= nrow(dt)]
  if (!length(idx)) return(integer(0))

  categoria <- monitora_correcao_inferir_categoria_pendfv(grupo, col)
  vazio_destino <- monitora_correcao_vazio_vec(dt[[col]][idx])
  if (!is.na(categoria) && nzchar(categoria) && !is.na(chaves$tipo_forma_vida) && chaves$tipo_forma_vida %in% names(dt)) {
    tem_cat <- monitora_correcao_contem_qualquer_token_vec(dt[[chaves$tipo_forma_vida]][idx], categoria)
  } else {
    tem_cat <- rep(TRUE, length(idx))
  }
  idx[tem_cat & vazio_destino]
}

monitora_correcao_aplicar_exclusoes_coleta_atomicas <- function(dt, corr, chaves = monitora_correcao_colunas_chave(dt), indice = NULL, arquivo_correcao = NA_character_) {
  dt <- monitora_dt_referenciar(dt)
  corr <- data.table::as.data.table(corr)
  if (!nrow(corr)) return(list(dt = dt, corr = corr, audit = data.table::data.table(), coletas = character(), linhas_removidas = integer(), falha = FALSE, n_grupos = 0L))
  if (!("ordem_tmp" %in% names(corr))) corr[, ordem_tmp := seq_len(.N)]
  if (!("id_correcao" %in% names(corr))) corr[, id_correcao := NA_character_]
  acao_vec <- if ("acao" %in% names(corr)) as.character(corr$acao) else rep("", nrow(corr))
  tipo_vec <- if ("tipo_correcao" %in% names(corr)) as.character(corr$tipo_correcao) else rep("", nrow(corr))
  idx_exc <- which(mapply(monitora_correcao_acao_exclusao_coleta, acao_vec, tipo_vec))
  if (!length(idx_exc)) return(list(dt = dt, corr = corr, audit = data.table::data.table(), coletas = character(), linhas_removidas = integer(), falha = FALSE, n_grupos = 0L))

  corr[, .grupo_exc_atom := data.table::fifelse(!is.na(id_correcao) & nzchar(as.character(id_correcao)), as.character(id_correcao), paste0("__linha_", ordem_tmp))]
  grupos <- unique(corr[idx_exc, .grupo_exc_atom])
  audit <- data.table::data.table()
  linhas_remover_total <- integer()
  coletas_removidas <- character()
  grupos_processados <- character()
  falha <- FALSE

  for (gid in grupos) {
    grp <- corr[.grupo_exc_atom == gid]
    grupos_processados <- unique(c(grupos_processados, gid))
    coletas_grp <- monitora_replay_v263_parse_colunas(grp, c("coleta", "COLETA", "coletas", "coletas_alvo"))
    if (is.na(chaves$coleta) || !(chaves$coleta %in% names(dt))) {
      falha <- TRUE
      audit <- data.table::rbindlist(list(audit, data.table::data.table(
        id_correcao = grp$id_correcao[1L], ordem_operacao = NA_character_,
        status = "falha_coluna_coleta_exclusao", mensagem = "Coluna de COLETA não localizada; exclusão bloqueada",
        atributo = "COLETA", linha_indice = NA_integer_, valor_antes = NA_character_, valor_depois = NA_character_, arquivo_correcao = arquivo_correcao
      )), fill = TRUE, use.names = TRUE)
      next
    }
    if (!length(coletas_grp)) {
      falha <- TRUE
      audit <- data.table::rbindlist(list(audit, data.table::data.table(
        id_correcao = grp$id_correcao[1L], ordem_operacao = NA_character_,
        status = "falha_sem_coleta_exclusao", mensagem = "Operação de exclusão sem COLETA identificável",
        atributo = chaves$coleta, linha_indice = NA_integer_, valor_antes = NA_character_, valor_depois = NA_character_, arquivo_correcao = arquivo_correcao
      )), fill = TRUE, use.names = TRUE)
      next
    }

    for (co in coletas_grp) {
      linhas <- which(trimws(as.character(dt[[chaves$coleta]])) == trimws(as.character(co)))
      linhas <- unique(as.integer(linhas))
      linhas <- linhas[!is.na(linhas) & linhas >= 1L & linhas <= nrow(dt)]
      if (!length(linhas)) {
        audit <- data.table::rbindlist(list(audit, data.table::data.table(
          id_correcao = grp$id_correcao[1L], ordem_operacao = NA_character_,
          status = "ok_coleta_ausente_estado_corrente",
          mensagem = "Exclusão em replay sem ação: COLETA não existe no input/estado corrente ou já foi removida anteriormente",
          atributo = chaves$coleta, linha_indice = NA_integer_, valor_antes = as.character(co),
          valor_depois = "<COLETA_AUSENTE_ESTADO_CORRENTE>", arquivo_correcao = arquivo_correcao
        )), fill = TRUE, use.names = TRUE)
        next
      }
      audit_del <- data.table::data.table(
        id_correcao = grp$id_correcao[1L],
        ordem_operacao = NA_character_,
        status = "excluida_coleta",
        mensagem = paste0("Exclusão atômica/replay de COLETA: ", length(linhas), " registro(s) removido(s)"),
        atributo = chaves$coleta,
        linha_indice = linhas,
        valor_antes = as.character(dt[[chaves$coleta]][linhas]),
        valor_depois = "<REGISTRO_REMOVIDO>",
        arquivo_correcao = arquivo_correcao
      )
      audit_del <- monitora_correcao_anexar_contexto_auditoria(audit_del, dt, chaves)
      audit <- data.table::rbindlist(list(audit, audit_del), fill = TRUE, use.names = TRUE)
      linhas_remover_total <- unique(c(linhas_remover_total, linhas))
      coletas_removidas <- unique(c(coletas_removidas, as.character(co)))
    }
  }

  linhas_remover_total <- sort(unique(as.integer(linhas_remover_total)))
  linhas_remover_total <- linhas_remover_total[!is.na(linhas_remover_total) & linhas_remover_total >= 1L & linhas_remover_total <= nrow(dt)]
  if (length(linhas_remover_total) > 0L) dt <- dt[-linhas_remover_total]
  corr_out <- corr[!(.grupo_exc_atom %in% grupos_processados)]
  corr_out[, .grupo_exc_atom := NULL]
  corr[, .grupo_exc_atom := NULL]
  list(dt = dt[], corr = corr_out[], audit = audit[], coletas = coletas_removidas, linhas_removidas = linhas_remover_total, falha = falha, n_grupos = length(grupos_processados))
}

monitora_correcao_localizar_linhas_movimento_lote <- function(dt, linha_lote, chaves = monitora_correcao_colunas_chave(dt)) {
  dt <- data.table::as.data.table(dt)
  linha_lote <- data.table::as.data.table(linha_lote)
  if (!nrow(dt) || !nrow(linha_lote)) return(integer(0))

  mv_desc_vals <- character(0)
  for (cc_mv in intersect(c("escopo_diagnostico_mvlote", "categoria_base_diagnostica", "token_pai", "token_removido", "valor_original_esperado"), names(linha_lote))) {
    mv_desc_vals <- c(mv_desc_vals, as.character(linha_lote[[cc_mv]][1L]))
  }
  mv_desc_norm <- tryCatch(monitora_correcao_limpar_texto(mv_desc_vals), error = function(e) tolower(trimws(mv_desc_vals)))
  mv_desc_semantica <- any(mv_desc_norm %in% c("forma_vida_desconhecida_categoria_base", "forma_vida_desconhecida", "desconhecida", "desconhecido"), na.rm = TRUE)

  coletas <- monitora_replay_v263_parse_colunas(linha_lote, c("coleta", "COLETA", "coletas", "coletas_alvo"))
  if (length(coletas) && !is.na(chaves$coleta) && chaves$coleta %in% names(dt)) {
    idx <- which(trimws(as.character(dt[[chaves$coleta]])) %chin% coletas)
    idx <- unique(as.integer(idx))
    idx <- idx[!is.na(idx) & idx >= 1L & idx <= nrow(dt)]
    if (length(idx)) return(idx)
  }

  ### Somente arquivos legados sem COLETA podem cair para linha_indice.
  linhas_serial <- integer(0)
  if (!isTRUE(mv_desc_semantica)) {
    linhas_serial <- suppressWarnings(as.integer(monitora_replay_v263_parse_colunas(linha_lote, c("linhas_alvo_serializadas", "linha_indice", "linhas_alvo"))))
    linhas_serial <- unique(linhas_serial[!is.na(linhas_serial) & linhas_serial >= 1L & linhas_serial <= nrow(dt)])
    if (length(linhas_serial)) return(linhas_serial)
  }

  integer(0)
}

monitora_correcao_aplicar_movimento_forma_vida_lote_atomico__v262 <- monitora_correcao_aplicar_movimento_forma_vida_lote_atomico

monitora_correcao_aplicar_movimento_forma_vida_lote_atomico <- function(dt, linha_lote, chaves = monitora_correcao_colunas_chave(dt), indice = NULL, arquivo_correcao = NA_character_, dicionario = NULL, gravar_relatorio_ambiguidades = TRUE) {
  dt <- monitora_dt_referenciar(dt)
  linha_lote <- data.table::as.data.table(linha_lote)
  if (!nrow(linha_lote)) return(list(dt = dt[], audit = data.table::data.table(), linhas = integer(), afetacoes = data.table::data.table(linha_indice = integer(), atributo = character()), falha = FALSE))

  mv_desc_vals <- character(0)
  for (cc_mv in intersect(c("escopo_diagnostico_mvlote", "categoria_base_diagnostica", "token_pai", "token_removido", "valor_original_esperado"), names(linha_lote))) {
    mv_desc_vals <- c(mv_desc_vals, as.character(linha_lote[[cc_mv]][1L]))
  }
  mv_desc_norm <- tryCatch(monitora_correcao_limpar_texto(mv_desc_vals), error = function(e) tolower(trimws(mv_desc_vals)))
  mv_desc_semantica <- any(mv_desc_norm %in% c("forma_vida_desconhecida_categoria_base", "forma_vida_desconhecida", "desconhecida", "desconhecido"), na.rm = TRUE)
  if (!isTRUE(mv_desc_semantica)) {
    return(monitora_correcao_aplicar_movimento_forma_vida_lote_atomico__v262(dt, linha_lote, chaves, indice, arquivo_correcao, dicionario, gravar_relatorio_ambiguidades))
  }

  id_cor <- if ("id_correcao" %in% names(linha_lote)) as.character(linha_lote$id_correcao[1L]) else NA_character_
  ordem <- if ("ordem_operacao" %in% names(linha_lote)) linha_lote$ordem_operacao[1L] else NA_character_
  registrar <- function(status, msg, atributo, idx, antes, depois) {
    data.table::data.table(
      id_correcao = id_cor, ordem_operacao = ordem, status = status, mensagem = msg,
      atributo = atributo, linha_indice = as.integer(idx), valor_antes = as.character(antes),
      valor_depois = as.character(depois), arquivo_correcao = arquivo_correcao
    )
  }
  nofatal <- function(status, msg, linhas_info = integer()) {
    list(
      dt = dt[],
      audit = registrar(status, paste0("Replay MVLOTE desconhecida sem alteração fatal: ", msg), "__mover_forma_vida_lote__", if (length(linhas_info)) linhas_info else NA_integer_, NA_character_, NA_character_),
      linhas = unique(as.integer(linhas_info)),
      afetacoes = data.table::data.table(linha_indice = integer(), atributo = character()),
      falha = FALSE
    )
  }
  falhar <- function(status, msg) {
    list(
      dt = dt[],
      audit = registrar(status, paste0("Replay MVLOTE desconhecida bloqueado: ", msg), "__mover_forma_vida_lote__", NA_integer_, NA_character_, NA_character_),
      linhas = integer(),
      afetacoes = data.table::data.table(linha_indice = integer(), atributo = character()),
      falha = TRUE
    )
  }

  origem <- if ("categoria_origem" %in% names(linha_lote)) tolower(trimws(as.character(linha_lote$categoria_origem[1L]))) else NA_character_
  destino <- if ("categoria_destino" %in% names(linha_lote)) tolower(trimws(as.character(linha_lote$categoria_destino[1L]))) else NA_character_
  cats <- c("nativa", "exotica", "seca_morta")
  if (monitora_correcao_vazio(origem) || !(origem %in% cats)) return(falhar("falha_categoria_origem", "categoria de origem ausente/inválida"))
  if (monitora_correcao_vazio(destino) || !(destino %in% cats)) destino <- origem

  col_origem <- tryCatch(monitora_correcao_coluna_forma_vida(dt, origem), error = function(e) NA_character_)
  col_destino <- tryCatch(monitora_correcao_coluna_forma_vida(dt, destino), error = function(e) NA_character_)
  if (is.na(col_origem) || !(col_origem %in% names(dt))) return(falhar("falha_coluna_origem", paste0("coluna de origem não localizada para ", origem)))
  if (is.na(col_destino) || !(col_destino %in% names(dt))) return(falhar("falha_coluna_destino", paste0("coluna de destino não localizada para ", destino)))

  forma_destino <- monitora_replay_v263_parse_colunas(linha_lote, c("forma_valida_escolhida", "valor_novo", "forma_destino_lote"))
  forma_destino <- forma_destino[!tolower(forma_destino) %in% c("__todas__", "todas", "todos", "all", "desconhecida", "desconhecido")]
  forma_destino <- tryCatch(monitora_correcao_forma_canonica_lote(forma_destino), error = function(e) forma_destino)
  forma_destino <- unique(forma_destino[!is.na(forma_destino) & nzchar(forma_destino)])
  if (!length(forma_destino)) return(falhar("falha_forma_destino", "forma válida de destino não informada"))
  forma_destino <- forma_destino[1L]

  linhas_base <- monitora_correcao_localizar_linhas_movimento_lote(dt, linha_lote, chaves)
  linhas_base <- unique(as.integer(linhas_base))
  linhas_base <- linhas_base[!is.na(linhas_base) & linhas_base >= 1L & linhas_base <= nrow(dt)]
  if (!length(linhas_base)) return(nofatal("ok_sem_escopo_corrente", "nenhuma COLETA/linha do escopo foi localizada no estado corrente"))

  linhas_alvo <- tryCatch(monitora_correcao_linhas_desconhecida_categoria_base(dt, origem, linhas_base, dicionario = dicionario), error = function(e) integer(0))
  linhas_alvo <- unique(as.integer(linhas_alvo))
  linhas_alvo <- linhas_alvo[!is.na(linhas_alvo) & linhas_alvo >= 1L & linhas_alvo <= nrow(dt)]
  if (!length(linhas_alvo)) {
    ### v2.6.1: em algumas runs de replay o MVLOTE de "desconhecida"
    ### é executado antes da sanitização que transforma Encostam=desconhecida
    ### superior-only em categoria-base nativa + forma_vida_nativa=desconhecida.
    ### Nesse intervalo, a intenção semântica do bolsista só está visível no
    ### campo superior Encostam/tipo_forma_vida. Portanto, antes de declarar
    ### "sem efeito", reconstruímos o alvo por COLETA + ponto/métro da operação
    ### e presença de desconhecida superior-only no estado corrente.
    linhas_sup <- tryCatch(monitora_correcao_linhas_desconhecida_sem_categoria_base(dt, linhas_base, chaves), error = function(e) integer(0))
    linhas_sup <- unique(as.integer(linhas_sup))
    linhas_sup <- linhas_sup[!is.na(linhas_sup) & linhas_sup >= 1L & linhas_sup <= nrow(dt)]
    if (length(linhas_sup)) {
      pa_vals <- tryCatch(monitora_replay_v263_parse_colunas(linha_lote, c("ponto_amostral", "Ponto amostral")), error = function(e) character(0))
      pm_vals <- tryCatch(monitora_replay_v263_parse_colunas(linha_lote, c("ponto_metro", "Ponto metro")), error = function(e) character(0))
      pa_vals <- unique(trimws(as.character(pa_vals)))
      pm_vals <- unique(trimws(as.character(pm_vals)))
      pa_vals <- pa_vals[!is.na(pa_vals) & nzchar(pa_vals) & !grepl("^multiplos\\(", pa_vals, ignore.case = TRUE)]
      pm_vals <- pm_vals[!is.na(pm_vals) & nzchar(pm_vals) & !grepl("^multiplos\\(", pm_vals, ignore.case = TRUE)]
      if (length(pa_vals) && !is.na(chaves$ponto_amostral) && chaves$ponto_amostral %in% names(dt)) {
        linhas_sup <- linhas_sup[trimws(as.character(dt[[chaves$ponto_amostral]][linhas_sup])) %chin% pa_vals]
      }
      if (length(pm_vals) && !is.na(chaves$ponto_metro) && chaves$ponto_metro %in% names(dt)) {
        linhas_sup <- linhas_sup[trimws(as.character(dt[[chaves$ponto_metro]][linhas_sup])) %chin% pm_vals]
      }
    }
    if (length(linhas_sup)) {
      linhas_alvo <- unique(as.integer(linhas_sup))
      ### A auditoria detalhada será registrada nos blocos de aplicação abaixo,
      ### quando o valor efetivamente mudar.
    } else {
      return(nofatal("ok_sem_desconhecida_estado_corrente", paste0("nenhuma ocorrência de desconhecida permaneceu em ", origem, " no escopo corrente"), linhas_base))
    }
  }

  audit <- data.table::data.table()
  afetacoes <- data.table::data.table(linha_indice = integer(), atributo = character())
  tokens_desc <- unique(c("desconhecida", "desconhecido", tryCatch(monitora_correcao_tokens_desconhecida(), error = function(e) character(0))))

  if (identical(col_origem, col_destino)) {
    antes <- as.character(dt[[col_origem]][linhas_alvo])
    depois <- antes
    for (tok in tokens_desc) depois <- vapply(depois, monitora_correcao_remove_token_valor, character(1), token = tok)
    depois <- vapply(depois, monitora_correcao_append_token_valor, character(1), token = forma_destino)
    mudou <- monitora_correcao_na_para_vazio(antes) != monitora_correcao_na_para_vazio(depois)
    if (any(mudou, na.rm = TRUE)) {
      data.table::set(dt, i = linhas_alvo[mudou], j = col_origem, value = depois[mudou])
      audit <- data.table::rbindlist(list(audit, registrar("aplicada_atomica", "Replay MVLOTE: desconhecida substituída por forma válida na mesma categoria", col_origem, linhas_alvo[mudou], antes[mudou], depois[mudou])), fill = TRUE, use.names = TRUE)
      afetacoes <- data.table::rbindlist(list(afetacoes, data.table::data.table(linha_indice = linhas_alvo[mudou], atributo = col_origem)), fill = TRUE, use.names = TRUE)
    }
  } else {
    antes_o <- as.character(dt[[col_origem]][linhas_alvo])
    depois_o <- antes_o
    for (tok in tokens_desc) depois_o <- vapply(depois_o, monitora_correcao_remove_token_valor, character(1), token = tok)
    mudou_o <- monitora_correcao_na_para_vazio(antes_o) != monitora_correcao_na_para_vazio(depois_o)
    if (any(mudou_o, na.rm = TRUE)) {
      data.table::set(dt, i = linhas_alvo[mudou_o], j = col_origem, value = depois_o[mudou_o])
      audit <- data.table::rbindlist(list(audit, registrar("aplicada_atomica", "Replay MVLOTE: desconhecida removida da categoria-base de origem", col_origem, linhas_alvo[mudou_o], antes_o[mudou_o], depois_o[mudou_o])), fill = TRUE, use.names = TRUE)
      afetacoes <- data.table::rbindlist(list(afetacoes, data.table::data.table(linha_indice = linhas_alvo[mudou_o], atributo = col_origem)), fill = TRUE, use.names = TRUE)
    }
    antes_d <- as.character(dt[[col_destino]][linhas_alvo])
    depois_d <- vapply(antes_d, monitora_correcao_append_token_valor, character(1), token = forma_destino)
    mudou_d <- monitora_correcao_na_para_vazio(antes_d) != monitora_correcao_na_para_vazio(depois_d)
    if (any(mudou_d, na.rm = TRUE)) {
      data.table::set(dt, i = linhas_alvo[mudou_d], j = col_destino, value = depois_d[mudou_d])
      audit <- data.table::rbindlist(list(audit, registrar("aplicada_atomica", "Replay MVLOTE: forma válida garantida na categoria de destino", col_destino, linhas_alvo[mudou_d], antes_d[mudou_d], depois_d[mudou_d])), fill = TRUE, use.names = TRUE)
      afetacoes <- data.table::rbindlist(list(afetacoes, data.table::data.table(linha_indice = linhas_alvo[mudou_d], atributo = col_destino)), fill = TRUE, use.names = TRUE)
    }
  }

  res_desc_dep <- tryCatch(monitora_correcao_sanitizar_dependentes_desconhecida(
    dt, linhas = linhas_alvo, categorias = c("nativa", "exotica", "seca_morta"), id_correcao = id_cor,
    ordem_operacao = ordem, arquivo_correcao = arquivo_correcao, dicionario = dicionario, registrar_preservadas = TRUE
  ), error = function(e) NULL)
  if (is.list(res_desc_dep)) {
    dt <- res_desc_dep$dt
    if (data.table::is.data.table(res_desc_dep$audit) && nrow(res_desc_dep$audit)) audit <- data.table::rbindlist(list(audit, res_desc_dep$audit), fill = TRUE, use.names = TRUE)
    if (data.table::is.data.table(res_desc_dep$afetacoes) && nrow(res_desc_dep$afetacoes)) afetacoes <- data.table::rbindlist(list(afetacoes, res_desc_dep$afetacoes), fill = TRUE, use.names = TRUE)
  }

  tipo_col <- chaves$tipo_forma_vida
  if (!is.na(tipo_col) && tipo_col %in% names(dt)) {
    antes_tipo <- as.character(dt[[tipo_col]][linhas_alvo])
    try(monitora_correcao_recalcular_tipo_forma_vida(dt, linhas_alvo), silent = TRUE)
    depois_tipo <- as.character(dt[[tipo_col]][linhas_alvo])
    mudou_tipo <- monitora_correcao_na_para_vazio(antes_tipo) != monitora_correcao_na_para_vazio(depois_tipo)
    if (any(mudou_tipo, na.rm = TRUE)) {
      audit <- data.table::rbindlist(list(audit, registrar("aplicada_atomica", "Replay MVLOTE: Encostam/tipo_forma_vida recalculado após substituição de desconhecida", tipo_col, linhas_alvo[mudou_tipo], antes_tipo[mudou_tipo], depois_tipo[mudou_tipo])), fill = TRUE, use.names = TRUE)
      afetacoes <- data.table::rbindlist(list(afetacoes, data.table::data.table(linha_indice = linhas_alvo[mudou_tipo], atributo = tipo_col)), fill = TRUE, use.names = TRUE)
    }
  }

  if (!nrow(audit)) return(nofatal("ok_estado_final_ja_coerente", "as linhas-alvo já estavam coerentes após avaliação semântica", linhas_alvo))
  audit[, formas_origem := "desconhecida"]
  audit[, forma_destino := forma_destino]
  audit[, modo_movimento := ifelse(identical(origem, destino), "substituicao_intralista_replay", "movimento_entre_categorias_replay")]
  list(dt = dt[], audit = audit[], linhas = unique(linhas_alvo), afetacoes = unique(afetacoes), falha = FALSE)
}
### FIM v2.6.1 -------------------------------------------------------------






### v2.6.1 ---------------------------------
### v2.6.1: reforço para limpeza sem alvo em sessão com exclusões dominantes.
### Orquestração pós-painel de operações que interagem entre si.
### Regra central: exclusão de COLETAS é operação dominante na sessão.
### Operações modificadoras cujo alvo foi removido por uma exclusão da mesma
### sessão não representam falha de aplicação; devem ser auditadas como
### subsumidas por exclusão e não bloquear a entrega de registros_corrig.
monitora_publicacao_q_parse_coletas_operacao <- function(linha_corr) {
  if (is.null(linha_corr) || !nrow(data.table::as.data.table(linha_corr))) return(character(0))
  linha_corr <- data.table::as.data.table(linha_corr)
  cols <- intersect(
    c("coleta", "COLETA", "coletas", "coletas_alvo", "coletas_lote", "coletas_selecionadas"),
    names(linha_corr)
  )
  vals <- character(0)
  for (cc in cols) {
    vals <- c(vals, monitora_correcao_parse_lista_serializada(linha_corr[[cc]][1L]))
  }
  vals <- unique(trimws(as.character(vals)))
  vals[!is.na(vals) & nzchar(vals)]
}

monitora_publicacao_q_coletas_exclusao_dominante <- function(corr) {
  corr <- data.table::as.data.table(corr)
  if (!nrow(corr)) return(character(0))
  acao_vec <- if ("acao" %in% names(corr)) as.character(corr$acao) else rep("", nrow(corr))
  tipo_vec <- if ("tipo_correcao" %in% names(corr)) as.character(corr$tipo_correcao) else rep("", nrow(corr))
  idx <- which(mapply(monitora_correcao_acao_exclusao_coleta, acao_vec, tipo_vec))
  if (!length(idx)) return(character(0))
  out <- unique(unlist(lapply(idx, function(ii) monitora_publicacao_q_parse_coletas_operacao(corr[ii])), use.names = FALSE))
  out <- unique(trimws(as.character(out)))
  out[!is.na(out) & nzchar(out)]
}

monitora_publicacao_q_operacao_totalmente_subsumida_por_exclusao <- function(linha_corr, coletas_excluidas) {
  coletas_excluidas <- unique(trimws(as.character(coletas_excluidas)))
  coletas_excluidas <- coletas_excluidas[!is.na(coletas_excluidas) & nzchar(coletas_excluidas)]
  if (!length(coletas_excluidas)) return(FALSE)
  coletas_op <- monitora_publicacao_q_parse_coletas_operacao(linha_corr)
  length(coletas_op) > 0L && all(coletas_op %chin% coletas_excluidas)
}

monitora_publicacao_q_filtrar_linhas_exclusao_dominante <- function(dt, linhas, chaves, coletas_excluidas) {
  linhas <- unique(as.integer(linhas))
  linhas <- linhas[!is.na(linhas) & linhas >= 1L & linhas <= nrow(dt)]
  coletas_excluidas <- unique(trimws(as.character(coletas_excluidas)))
  coletas_excluidas <- coletas_excluidas[!is.na(coletas_excluidas) & nzchar(coletas_excluidas)]
  if (!length(linhas) || !length(coletas_excluidas) || is.na(chaves$coleta) || !(chaves$coleta %in% names(dt))) {
    return(list(linhas = linhas, linhas_subsumidas = integer(0), coletas_subsumidas = character(0)))
  }
  coleta_linha <- trimws(as.character(dt[[chaves$coleta]][linhas]))
  subs <- coleta_linha %chin% coletas_excluidas
  list(
    linhas = linhas[!subs],
    linhas_subsumidas = linhas[subs],
    coletas_subsumidas = unique(coleta_linha[subs & !is.na(coleta_linha) & nzchar(coleta_linha)])
  )
}

monitora_publicacao_q_auditoria_subsumida_por_exclusao <- function(linha_corr,
                                                             arquivo_correcao = NA_character_,
                                                             atributo = NA_character_,
                                                             status = "ok_subsumida_por_exclusao",
                                                             n_linhas_alvo_original = NA_integer_,
                                                             n_linhas_subsumidas = NA_integer_,
                                                             n_linhas_aplicadas = 0L,
                                                             coletas_subsumidas = character(0),
                                                             mensagem_extra = NA_character_) {
  linha_corr <- data.table::as.data.table(linha_corr)
  if (is.na(atributo) || !nzchar(as.character(atributo))) {
    atributo <- if ("atributo_coluna_registros_corrig" %in% names(linha_corr)) as.character(linha_corr$atributo_coluna_registros_corrig[1L]) else NA_character_
  }
  coletas_subsumidas <- unique(trimws(as.character(coletas_subsumidas)))
  coletas_subsumidas <- coletas_subsumidas[!is.na(coletas_subsumidas) & nzchar(coletas_subsumidas)]
  msg <- paste0(
    "Operação não aplicada porque seu alvo foi removido por exclusão de COLETA na mesma sessão; ",
    "n_linhas_alvo_original=", ifelse(is.na(n_linhas_alvo_original), "NA", as.character(n_linhas_alvo_original)),
    "; n_linhas_subsumidas=", ifelse(is.na(n_linhas_subsumidas), "NA", as.character(n_linhas_subsumidas)),
    "; n_linhas_aplicadas=", ifelse(is.na(n_linhas_aplicadas), "NA", as.character(n_linhas_aplicadas)),
    if (length(coletas_subsumidas)) paste0("; coletas_subsumidas=", paste(coletas_subsumidas, collapse = "|")) else ""
  )
  if (!is.na(mensagem_extra) && nzchar(as.character(mensagem_extra))) msg <- paste0(msg, "; ", mensagem_extra)
  data.table::data.table(
    id_correcao = if ("id_correcao" %in% names(linha_corr)) linha_corr$id_correcao[1L] else NA_character_,
    ordem_operacao = if ("ordem_operacao" %in% names(linha_corr)) linha_corr$ordem_operacao[1L] else NA_character_,
    status = status,
    mensagem = msg,
    atributo = atributo,
    linha_indice = NA_integer_,
    valor_antes = NA_character_,
    valor_depois = "<ALVO_REMOVIDO_POR_EXCLUSAO_COLETA>",
    arquivo_correcao = arquivo_correcao
  )
}
### FIM v2.6.1 -----------------------------

monitora_correcao_arquivo_ler_defensivo <- function(arquivo_correcao) {
  if (is.null(arquivo_correcao) || !file.exists(arquivo_correcao)) return(data.table::data.table())
  tryCatch(
    data.table::fread(arquivo_correcao, encoding = "UTF-8", na.strings = c("", "NA"), colClasses = "character", showProgress = FALSE),
    error = function(e) data.table::data.table()
  )
}

monitora_correcao_norm_nome_campo <- function(x) {
  x <- tolower(trimws(as.character(x)))
  x <- iconv(x, to = "ASCII//TRANSLIT", sub = "")
  gsub("[^a-z0-9]+", "_", x)
}

monitora_correcao_operacoes_alteram_data_hora <- function(corr) {
  if (is.null(corr)) return(FALSE)
  corr <- data.table::as.data.table(corr)
  if (!nrow(corr)) return(FALSE)
  cols_busca <- intersect(
    c("atributo_coluna_registros_corrig", "atributo", "coluna", "campo", "campo_alvo", "acao", "tipo_correcao"),
    names(corr)
  )
  if (!length(cols_busca)) return(FALSE)
  txt <- unique(unlist(lapply(cols_busca, function(cc) as.character(corr[[cc]])), use.names = FALSE))
  txt <- txt[!is.na(txt) & nzchar(trimws(txt))]
  if (!length(txt)) return(FALSE)
  n <- monitora_correcao_norm_nome_campo(txt)
  padroes_data <- c(
    "^data_data_hora$", "^data_hora_data$", "^data_hora$", "^data$",
    "^amostragem_registro_data$", "^data_do_registro$"
  )
  any(vapply(padroes_data, function(p) any(grepl(p, n, perl = TRUE)), logical(1L))) ||
    any(grepl("data_hora|data_data_hora|data_hora_data|amostragem_registro_data", n, perl = TRUE))
}

monitora_correcao_arquivo_altera_data_hora <- function(arquivo_correcao = NULL, corr = NULL) {
  if (is.null(corr)) corr <- monitora_correcao_arquivo_ler_defensivo(arquivo_correcao)
  monitora_correcao_operacoes_alteram_data_hora(corr)
}

monitora_correcao_operacoes_afetam_relatorios_suporte <- function(corr) {
  if (is.null(corr)) return(FALSE)
  corr <- data.table::as.data.table(corr)
  if (!nrow(corr)) return(FALSE)
  cols_busca <- intersect(
    c("tipo_correcao", "acao", "atributo_coluna_registros_corrig", "atributo", "categoria_origem", "categoria_destino", "tipo_triagem", "token_removido", "forma_valida_escolhida", "lista_destino", "campo_dependente_preenchido"),
    names(corr)
  )
  if (!length(cols_busca)) return(FALSE)
  txt <- unique(unlist(lapply(cols_busca, function(cc) as.character(corr[[cc]])), use.names = FALSE))
  txt <- txt[!is.na(txt) & nzchar(trimws(txt))]
  if (!length(txt)) return(FALSE)
  n <- monitora_correcao_norm_nome_campo(txt)
  any(grepl("exotica|nativa|desconhecida|outra|forma|vida|habito|especie|encostam|tipo_forma_vida|mv|mvlote|limpeza", n, perl = TRUE))
}

monitora_correcao_arquivo_afeta_relatorios_suporte <- function(arquivo_correcao = NULL, corr = NULL) {
  if (is.null(corr)) corr <- monitora_correcao_arquivo_ler_defensivo(arquivo_correcao)
  monitora_correcao_operacoes_afetam_relatorios_suporte(corr)
}

monitora_recalcular_derivados_data_hora_se_necessario <- function(dt, arquivo_correcao = NULL, corr = NULL, contexto = "pos_correcoes_assistidas", forcar = FALSE) {
  deve <- isTRUE(forcar) || !isTRUE(get0("MONITORA_OPCAO_PULAR_RECALCULO_DATA_HORA_SEM_ALTERACAO", ifnotfound = "S", inherits = TRUE) == "S") ||
    monitora_correcao_arquivo_altera_data_hora(arquivo_correcao, corr)
  if (isTRUE(deve)) {
    out <- monitora_recalcular_derivados_data_hora(dt, contexto = contexto)
    assign("MONITORA_RECALC_DATA_HORA_EXECUTADO_ULTIMO", TRUE, envir = .GlobalEnv)
    if (isTRUE(get0("MONITORA_OPCAO_CHECKPOINTS_GRANULARES_CORRECOES", ifnotfound = "S", inherits = TRUE) == "S") && exists("monitora_perf_registrar_checkpoint", mode = "function")) {
      monitora_perf_registrar_checkpoint("recalculo_data_hora_pos_correcoes", "DATA_MONITORA_PARSEADA e ANO recalculados porque Data (data_hora) foi alterada", out)
    }
    return(out)
  }
  assign("MONITORA_RECALC_DATA_HORA_EXECUTADO_ULTIMO", FALSE, envir = .GlobalEnv)
  if (exists("monitora_log_registrar_evento", mode = "function")) {
    monitora_log_registrar_evento("datas", "INFO", if (is.null(arquivo_correcao)) NA_character_ else arquivo_correcao, paste0("Recálculo de DATA_MONITORA_PARSEADA/ANO pulado em ", contexto, ": nenhuma correção de Data (data_hora) detectada"), "derivados preservados")
  }
  if (isTRUE(get0("MONITORA_OPCAO_CHECKPOINTS_GRANULARES_CORRECOES", ifnotfound = "S", inherits = TRUE) == "S") && exists("monitora_perf_registrar_checkpoint", mode = "function")) {
    monitora_perf_registrar_checkpoint("recalculo_data_hora_pos_correcoes_pulado", "recálculo de data/hora pulado por ausência de alteração em Data (data_hora)", dt)
  }
  dt[]
}


monitora_correcao_aplicar_plano_atomico_sessao <- function(dt,
                                                           corr,
                                                           chaves = monitora_correcao_colunas_chave(dt),
                                                           dicionario = NULL,
                                                           arquivo_correcao = "preview_painel_motor_unico",
                                                           aplicar_exclusoes = TRUE,
                                                           silencioso = TRUE,
                                                           registrar_perf = FALSE) {
  ### v2.6.1: motor único de preview/modal/aplicação lógica.
  ### A ordem replica o backend real: MVLOTE/TRIDESC, sanitizações vinculadas,
  ### PENDFV/TRIOUT por ocorrência diagnóstica, exclusões de COLETA e só então
  ### operações genéricas restantes.
  ### Assim a janela modal não pode divergir do que será aplicado ao salvar.
  dt <- monitora_dt_referenciar(dt)
  corr <- data.table::copy(data.table::as.data.table(corr))
  audit <- data.table::data.table()
  afetacoes <- data.table::data.table(linha_indice = integer(), atributo = character())
  linhas_semantica_alvo <- integer(0)
  linhas_afetadas_vinculos <- integer(0)
  falha <- FALSE
  if (!nrow(corr)) return(list(dt = dt[], corr = corr[], audit = audit, linhas = integer(), afetacoes = afetacoes, falha = FALSE))
  template <- tryCatch(monitora_correcao_template(), error = function(e) data.table::data.table())
  for (cc in setdiff(names(template), names(corr))) data.table::set(corr, j = cc, value = NA_character_)
  if (!("ordem_tmp" %in% names(corr))) corr[, ordem_tmp := seq_len(.N)]
  sig_corr <- tryCatch(monitora_correcao_assinatura_operacoes(corr), error = function(e) rep(NA_character_, nrow(corr)))
  if (length(sig_corr) == nrow(corr)) corr <- corr[!duplicated(sig_corr)]
  corr[, ordem_tmp := seq_len(.N)]
  indice_linhas <- tryCatch(monitora_correcao_criar_indice_linhas(dt, chaves), error = function(e) NULL)

  add_res <- function(res) {
    if (is.list(res) && "dt" %in% names(res)) dt <<- res$dt
    if (is.list(res) && !is.null(res$audit) && data.table::is.data.table(res$audit) && nrow(res$audit)) audit <<- data.table::rbindlist(list(audit, res$audit), fill = TRUE, use.names = TRUE)
    if (is.list(res) && !is.null(res$afetacoes) && data.table::is.data.table(res$afetacoes) && nrow(res$afetacoes)) afetacoes <<- data.table::rbindlist(list(afetacoes, res$afetacoes), fill = TRUE, use.names = TRUE)
    if (is.list(res) && length(res$linhas)) {
      linhas_semantica_alvo <<- unique(c(linhas_semantica_alvo, as.integer(res$linhas)))
      linhas_afetadas_vinculos <<- unique(c(linhas_afetadas_vinculos, as.integer(res$linhas)))
    }
    if (is.list(res) && isTRUE(res$falha)) falha <<- TRUE
    invisible(TRUE)
  }

  if (nrow(corr)) {
    res_mvlote <- monitora_correcao_aplicar_movimentos_forma_vida_lote_atomicos(dt, corr, chaves = chaves, indice = indice_linhas, arquivo_correcao = arquivo_correcao, dicionario = dicionario)
    add_res(res_mvlote)
    if (is.list(res_mvlote) && "corr" %in% names(res_mvlote)) corr <- data.table::copy(data.table::as.data.table(res_mvlote$corr))
    if (nrow(corr)) corr[, ordem_tmp := seq_len(.N)]
    indice_linhas <- tryCatch(monitora_correcao_criar_indice_linhas(dt, chaves), error = function(e) NULL)
  }

  if (nrow(corr)) {
    res_mov <- monitora_correcao_aplicar_movimentos_forma_vida_atomicos(dt, corr, chaves = chaves, indice = indice_linhas, arquivo_correcao = arquivo_correcao, dicionario = dicionario)
    add_res(res_mov)
    if (is.list(res_mov) && "corr" %in% names(res_mov)) corr <- data.table::copy(data.table::as.data.table(res_mov$corr))
    if (nrow(corr)) corr[, ordem_tmp := seq_len(.N)]
    indice_linhas <- tryCatch(monitora_correcao_criar_indice_linhas(dt, chaves), error = function(e) NULL)
  }

  if (nrow(corr)) {
    res_desc <- monitora_correcao_aplicar_triagens_desconhecida_atomicas(dt, corr, chaves = chaves, indice = indice_linhas, arquivo_correcao = arquivo_correcao, dicionario = dicionario)
    add_res(res_desc)
    if (is.list(res_desc) && "corr" %in% names(res_desc)) corr <- data.table::copy(data.table::as.data.table(res_desc$corr))
    if (nrow(corr)) corr[, ordem_tmp := seq_len(.N)]
    indice_linhas <- tryCatch(monitora_correcao_criar_indice_linhas(dt, chaves), error = function(e) NULL)
  }

  linhas_desc_alvo <- unique(c(linhas_semantica_alvo, linhas_afetadas_vinculos))
  linhas_desc_alvo <- linhas_desc_alvo[!is.na(linhas_desc_alvo) & linhas_desc_alvo >= 1L & linhas_desc_alvo <= nrow(dt)]
  if (length(linhas_desc_alvo)) {
    res_desc_cons <- tryCatch(monitora_correcao_sanitizar_dependentes_desconhecida(dt, linhas = linhas_desc_alvo, categorias = c("nativa", "exotica", "seca_morta"), id_correcao = "__PREVIEW_SANITIZACAO_DESCONHECIDA_POS_OPERACOES__", ordem_operacao = NA_character_, arquivo_correcao = arquivo_correcao, dicionario = dicionario, registrar_preservadas = FALSE), error = function(e) NULL)
    if (is.list(res_desc_cons)) add_res(res_desc_cons)
  }



  ### TRIOUT precisa anteceder PENDFV: a limpeza/conversão de outras formas
  ### pode preencher/normalizar listas inferiores e, portanto, resolver parte
  ### das pendências "sem forma". Se PENDFV roda antes, cria conflito e auditoria
  ### intermediária falsa.
  if (nrow(corr)) {
    res_triout_pre <- monitora_correcao_aplicar_limpezas_outras_formas_estado_corrente(dt, corr, chaves = chaves, indice = indice_linhas, arquivo_correcao = arquivo_correcao, dicionario = dicionario, silencioso = silencioso, registrar_perf = registrar_perf)
    add_res(res_triout_pre)
    if (is.list(res_triout_pre) && "corr" %in% names(res_triout_pre)) corr <- data.table::copy(data.table::as.data.table(res_triout_pre$corr))
    if (nrow(corr)) corr[, ordem_tmp := seq_len(.N)]
    indice_linhas <- tryCatch(monitora_correcao_criar_indice_linhas(dt, chaves), error = function(e) NULL)
  }

  if (nrow(corr)) {
    res_pend <- monitora_correcao_aplicar_pendencias_sem_forma_atomicas(dt, corr, chaves = chaves, arquivo_correcao = arquivo_correcao, dicionario = dicionario, silencioso = silencioso, registrar_perf = registrar_perf)
    add_res(res_pend)
    if (is.list(res_pend) && "corr" %in% names(res_pend)) corr <- data.table::copy(data.table::as.data.table(res_pend$corr))
    if (nrow(corr)) corr[, ordem_tmp := seq_len(.N)]
    indice_linhas <- tryCatch(monitora_correcao_criar_indice_linhas(dt, chaves), error = function(e) NULL)
  }

  if (nrow(corr)) {
    res_triout <- monitora_correcao_aplicar_limpezas_outras_formas_estado_corrente(dt, corr, chaves = chaves, indice = indice_linhas, arquivo_correcao = arquivo_correcao, dicionario = dicionario, silencioso = silencioso, registrar_perf = registrar_perf)
    add_res(res_triout)
    if (is.list(res_triout) && "corr" %in% names(res_triout)) corr <- data.table::copy(data.table::as.data.table(res_triout$corr))
    if (nrow(corr)) corr[, ordem_tmp := seq_len(.N)]
    indice_linhas <- tryCatch(monitora_correcao_criar_indice_linhas(dt, chaves), error = function(e) NULL)
  }

  if (isTRUE(aplicar_exclusoes) && nrow(corr)) {
    res_exc <- monitora_correcao_aplicar_exclusoes_coleta_atomicas(dt, corr, chaves = chaves, indice = indice_linhas, arquivo_correcao = arquivo_correcao)
    add_res(res_exc)
    if (is.list(res_exc) && "corr" %in% names(res_exc)) corr <- data.table::copy(data.table::as.data.table(res_exc$corr))
    if (nrow(corr)) corr[, ordem_tmp := seq_len(.N)]
    linhas_semantica_alvo <- linhas_semantica_alvo[linhas_semantica_alvo <= nrow(dt)]
    linhas_afetadas_vinculos <- linhas_afetadas_vinculos[linhas_afetadas_vinculos <= nrow(dt)]
    indice_linhas <- tryCatch(monitora_correcao_criar_indice_linhas(dt, chaves), error = function(e) NULL)
  }

  if (nrow(corr)) {
    for (ii in seq_len(nrow(corr))) {
      ac <- tolower(trimws(as.character(corr$acao[ii])))
      tipo <- if ("tipo_correcao" %in% names(corr)) as.character(corr$tipo_correcao[ii]) else ""
      if (ac %in% c("excluir_coleta", "exclusao_coleta")) next
      if (grepl("limpar_outras_formas_vida", tipo) || ac %in% c("limpar_outras_formas_vida", "limpar_outras_formas")) next
      if (grepl("pendencia_sem_forma_vida|movimento_forma_vida|triagem_substituir_desconhecida", tipo)) next
      attr <- as.character(corr$atributo_coluna_registros_corrig[ii])
      if (is.na(attr) || !nzchar(attr) || !(attr %in% names(dt))) next
      lin <- tryCatch(monitora_correcao_localizar_linhas(dt, corr[ii], chaves, indice_linhas), error = function(e) integer(0))
      lin <- unique(as.integer(lin[!is.na(lin) & lin >= 1L & lin <= nrow(dt)]))
      if (!length(lin)) next
      novo <- tryCatch(monitora_correcao_aplicar_operacao(dt[[attr]][lin], ac, corr$valor_novo[ii], corr$valor_original_esperado[ii]), error = function(e) dt[[attr]][lin])
      data.table::set(dt, i = lin, j = attr, value = novo)
      linhas_semantica_alvo <- unique(c(linhas_semantica_alvo, lin))
      afetacoes <- data.table::rbindlist(list(afetacoes, data.table::data.table(linha_indice = lin, atributo = attr)), fill = TRUE, use.names = TRUE)
    }
  }
  list(dt = dt[], corr = corr[], audit = audit[], linhas = unique(linhas_semantica_alvo), afetacoes = unique(afetacoes), falha = falha)
}

monitora_correcao_aplicar_arquivo <- function(dt, arquivo_correcao = MONITORA_ARQUIVO_CORRECOES_CAMPOS, dicionario = NULL) {
  if (!file.exists(arquivo_correcao)) {
    monitora_log_registrar_evento("correcoes_campos", "INFO", arquivo_correcao, "Arquivo de correções não encontrado; nenhuma correção aplicada", "opcional")
    return(dt)
  }
  dt <- monitora_dt_referenciar(dt)
  meta_schema_publicacao_b <- list(campos = if (!is.null(dicionario)) data.table::as.data.table(dicionario) else data.table::data.table(), dependencias = get0("MONITORA_DEPENDENCIAS_CORRECOES", ifnotfound = data.table::data.table(), inherits = TRUE))
  dt <- monitora_correcao_preparar_schema_edicao_painel(dt, meta_schema_publicacao_b, contexto = "pre_aplicacao_arquivo_correcoes")
  corr <- tryCatch(data.table::fread(arquivo_correcao, encoding = "UTF-8", na.strings = c("", "NA"), colClasses = "character"), error = function(e) data.table::data.table())
  if (nrow(corr) == 0) {
    monitora_log_registrar_evento("correcoes_campos", "AVISO", arquivo_correcao, "Arquivo de correções vazio ou ilegível", "nenhuma correção aplicada")
    return(dt)
  }
  template <- monitora_correcao_template()
  for (cc in setdiff(names(template), names(corr))) corr[, (cc) := NA_character_]
  data.table::setDT(corr)
  corr[, ordem_tmp := seq_len(.N)]
  sig_corr_original <- monitora_correcao_assinatura_operacoes(corr)
  manter_corr <- !duplicated(sig_corr_original)
  n_corr_dup <- sum(!manter_corr)
  if (n_corr_dup > 0L) {
    corr <- corr[manter_corr]
    monitora_log_registrar_evento(
      "correcoes_campos", "AVISO", arquivo_correcao,
      paste0(n_corr_dup, " operação(ões) duplicada(s) removida(s) antes da aplicação"),
      "deduplicação defensiva por assinatura semântica"
    )
  }
  corr[, ordem_tmp := seq_len(.N)]
  n_sem_plano <- tryCatch(monitora_correcao_contar_operacoes_semanticas(corr), error = function(e) nrow(corr))
  if (exists("monitora_correcao_console_msg", mode = "function")) {
    monitora_correcao_console_msg("Plano de aplicação das correções: ", n_sem_plano, " operação(ões) semântica(s), ", nrow(corr), " item(ns) auditável(is). Aplicação será agrupada por operações atômicas quando possível.")
  }
  snapshot_colunas_protegidas_antes <- monitora_correcao_snapshot_colunas_protegidas(dt)
  chaves <- monitora_correcao_colunas_chave(dt)
  indice_linhas <- monitora_correcao_criar_indice_linhas(dt, chaves)
  auditoria_semantica_pre <- data.table::data.table()
  linhas_semantica_alvo <- integer(0)
  auditoria_semantica_completa <- isTRUE(if (exists("MONITORA_AUDITORIA_SEMANTICA_CORRECOES_COMPLETA", inherits = TRUE)) get("MONITORA_AUDITORIA_SEMANTICA_CORRECOES_COMPLETA", inherits = TRUE) else FALSE)
  audit <- data.table::data.table()
  linhas_afetadas_vinculos <- integer(0)
  afetacoes_vinculos <- data.table::data.table(linha_indice = integer(), atributo = character())
  coletas_excluidas_aplicadas <- character(0)
  coletas_exclusao_dominante_sessao <- monitora_publicacao_q_coletas_exclusao_dominante(corr)
  if (length(coletas_exclusao_dominante_sessao) > 0L) {
    monitora_log_registrar_evento(
      "correcoes_campos",
      "INFO",
      arquivo_correcao,
      paste0("v2.5.4: exclusões dominantes detectadas na sessão: ", length(coletas_exclusao_dominante_sessao), " COLETA(s)"),
      "operações modificadoras totalmente cobertas por essas exclusões serão auditadas como subsumidas, não como falha"
    )
  }

  ### v2.6.1: limpeza de outras formas (TRIOUT) é normalização de base.
  ### Deve rodar antes de PENDFV e antes das exclusões, sempre recalculando
  ### resíduos no estado corrente por filtro estável de COLETA/contexto.
  falha_limpeza_outras_formas <- FALSE

  ### Movimentos em lote de forma de vida: aplicar como transações atômicas
  ### antes da pré-validação célula-a-célula. O lote é uma operação semântica
  ### única para várias COLETAS e uma ou mais formas de vida.
  falha_movimento_forma_vida_lote <- FALSE
  if (nrow(corr) > 0L) {
    res_mvlote_atom <- monitora_correcao_aplicar_movimentos_forma_vida_lote_atomicos(
      dt,
      corr,
      chaves = chaves,
      indice = indice_linhas,
      arquivo_correcao = arquivo_correcao,
      dicionario = dicionario
    )
    dt <- res_mvlote_atom$dt
    if (nrow(res_mvlote_atom$audit) > 0L) audit <- data.table::rbindlist(list(audit, res_mvlote_atom$audit), fill = TRUE, use.names = TRUE)
    if (length(res_mvlote_atom$linhas) > 0L) {
      linhas_semantica_alvo <- unique(c(linhas_semantica_alvo, res_mvlote_atom$linhas))
      linhas_afetadas_vinculos <- unique(c(linhas_afetadas_vinculos, res_mvlote_atom$linhas))
    }
    if (nrow(res_mvlote_atom$afetacoes) > 0L) afetacoes_vinculos <- data.table::rbindlist(list(afetacoes_vinculos, res_mvlote_atom$afetacoes), fill = TRUE, use.names = TRUE)
    falha_movimento_forma_vida_lote <- isTRUE(res_mvlote_atom$falha)
    if (isTRUE(res_mvlote_atom$n_grupos > 0L)) {
      corr <- res_mvlote_atom$corr
      corr[, ordem_tmp := seq_len(.N)]
      indice_linhas <- monitora_correcao_criar_indice_linhas(dt, chaves)
      monitora_log_registrar_evento(
        "correcoes_campos",
        ifelse(isTRUE(falha_movimento_forma_vida_lote), "ERRO", "INFO"),
        arquivo_correcao,
        paste0(res_mvlote_atom$n_grupos, " grupo(s) de movimento em lote de forma de vida processado(s) atomicamente"),
        "movimento semântico multicoletas aplicado sem expansão célula-a-célula"
      )
    }
  }

  if (isTRUE(falha_movimento_forma_vida_lote)) {
    if (nrow(audit) > 0) {
      audit <- monitora_correcao_anexar_contexto_auditoria(audit, dt, chaves)
      saida_audit <- file.path(MONITORA_LOG_DIR, paste0("auditoria_correcoes_campos_", MONITORA_EXEC_ID, ".csv"))
      monitora_fwrite(audit, saida_audit, na = "")
      monitora_fwrite(audit, file.path(MONITORA_CORRECOES_DIR, "auditoria_correcoes_campos_ultima_execucao.csv"), na = "")
    }
    stop("Movimento atômico em lote de forma de vida falhou; ver auditoria_correcoes_campos_ultima_execucao.csv", call. = FALSE)
  }

  ### Movimentos de forma de vida: aplicar como transações atômicas antes da
  ### pré-validação célula-a-célula. Isso cobre tanto as novas operações
  ### movimento_forma_vida_atomico quanto grupos legados MOVFV expandidos em
  ### remove_token/append_token/clear/recalcular_tipo_forma_vida.
  falha_movimento_forma_vida <- FALSE
  if (nrow(corr) > 0L) {
    res_mov_atom <- monitora_correcao_aplicar_movimentos_forma_vida_atomicos(
      dt,
      corr,
      chaves = chaves,
      indice = indice_linhas,
      arquivo_correcao = arquivo_correcao,
      dicionario = dicionario
    )
    dt <- res_mov_atom$dt
    if (nrow(res_mov_atom$audit) > 0L) audit <- data.table::rbindlist(list(audit, res_mov_atom$audit), fill = TRUE, use.names = TRUE)
    if (length(res_mov_atom$linhas) > 0L) {
      linhas_semantica_alvo <- unique(c(linhas_semantica_alvo, res_mov_atom$linhas))
      linhas_afetadas_vinculos <- unique(c(linhas_afetadas_vinculos, res_mov_atom$linhas))
    }
    if (nrow(res_mov_atom$afetacoes) > 0L) afetacoes_vinculos <- data.table::rbindlist(list(afetacoes_vinculos, res_mov_atom$afetacoes), fill = TRUE, use.names = TRUE)
    falha_movimento_forma_vida <- isTRUE(res_mov_atom$falha)
    if (isTRUE(res_mov_atom$n_grupos > 0L)) {
      corr <- res_mov_atom$corr
      corr[, ordem_tmp := seq_len(.N)]
      indice_linhas <- monitora_correcao_criar_indice_linhas(dt, chaves)
      monitora_log_registrar_evento(
        "correcoes_campos",
        ifelse(isTRUE(falha_movimento_forma_vida), "ERRO", "INFO"),
        arquivo_correcao,
        paste0(res_mov_atom$n_grupos, " grupo(s) de movimento de forma de vida processado(s) atomicamente"),
        "movimento semântico aplicado sem expansão célula-a-célula"
      )
    }
  }

  if (isTRUE(falha_movimento_forma_vida)) {
    if (nrow(audit) > 0) {
      audit <- monitora_correcao_anexar_contexto_auditoria(audit, dt, chaves)
      saida_audit <- file.path(MONITORA_LOG_DIR, paste0("auditoria_correcoes_campos_", MONITORA_EXEC_ID, ".csv"))
      monitora_fwrite(audit, saida_audit, na = "")
      monitora_fwrite(audit, file.path(MONITORA_CORRECOES_DIR, "auditoria_correcoes_campos_ultima_execucao.csv"), na = "")
    }
    stop("Movimento atômico de forma de vida falhou; ver auditoria_correcoes_campos_ultima_execucao.csv", call. = FALSE)
  }

  ### Substituição de forma de vida desconhecida: processar como transação
  ### atômica antes da validação célula-a-célula. Isso impede aplicação parcial
  ### do grupo TRIDESC quando a remoção do token antigo fica sem efeito, mas a
  ### adição da forma válida e o recálculo seriam executados separadamente.
  falha_triagem_desconhecida <- FALSE
  if (nrow(corr) > 0L) {
    res_tridesc_atom <- monitora_correcao_aplicar_triagens_desconhecida_atomicas(
      dt,
      corr,
      chaves = chaves,
      indice = indice_linhas,
      arquivo_correcao = arquivo_correcao,
      dicionario = dicionario
    )
    dt <- res_tridesc_atom$dt
    if (nrow(res_tridesc_atom$audit) > 0L) audit <- data.table::rbindlist(list(audit, res_tridesc_atom$audit), fill = TRUE, use.names = TRUE)
    if (length(res_tridesc_atom$linhas) > 0L) {
      linhas_semantica_alvo <- unique(c(linhas_semantica_alvo, res_tridesc_atom$linhas))
      linhas_afetadas_vinculos <- unique(c(linhas_afetadas_vinculos, res_tridesc_atom$linhas))
    }
    if (nrow(res_tridesc_atom$afetacoes) > 0L) afetacoes_vinculos <- data.table::rbindlist(list(afetacoes_vinculos, res_tridesc_atom$afetacoes), fill = TRUE, use.names = TRUE)
    falha_triagem_desconhecida <- isTRUE(res_tridesc_atom$falha)
    if (isTRUE(res_tridesc_atom$n_grupos > 0L)) {
      corr <- res_tridesc_atom$corr
      corr[, ordem_tmp := seq_len(.N)]
      indice_linhas <- monitora_correcao_criar_indice_linhas(dt, chaves)
      monitora_log_registrar_evento(
        "correcoes_campos",
        ifelse(isTRUE(falha_triagem_desconhecida), "ERRO", "INFO"),
        arquivo_correcao,
        paste0(res_tridesc_atom$n_grupos, " grupo(s) de triagem de desconhecida processado(s) atomicamente"),
        "substituição semântica aplicada sem expansão célula-a-célula"
      )
    }
  }

  if (isTRUE(falha_triagem_desconhecida)) {
    if (nrow(audit) > 0) {
      audit <- monitora_correcao_anexar_contexto_auditoria(audit, dt, chaves)
      saida_audit <- file.path(MONITORA_LOG_DIR, paste0("auditoria_correcoes_campos_", MONITORA_EXEC_ID, ".csv"))
      monitora_fwrite(audit, saida_audit, na = "")
      monitora_fwrite(audit, file.path(MONITORA_CORRECOES_DIR, "auditoria_correcoes_campos_ultima_execucao.csv"), na = "")
    }
    stop("Substituição atômica de desconhecida falhou; ver auditoria_correcoes_campos_ultima_execucao.csv", call. = FALSE)
  }

  ### Consistência pós-sanitização/triagem: dependentes históricos de forma de
  ### vida desconhecida só podem permanecer preenchidos quando a sublista da
  ### categoria correspondente ainda contém o token desconhecida.
  linhas_desc_alvo <- unique(c(linhas_semantica_alvo, linhas_afetadas_vinculos))
  linhas_desc_alvo <- linhas_desc_alvo[!is.na(linhas_desc_alvo) & linhas_desc_alvo >= 1L & linhas_desc_alvo <= nrow(dt)]
  if (length(linhas_desc_alvo)) {
    res_desc_cons <- monitora_correcao_sanitizar_dependentes_desconhecida(
      dt,
      linhas = linhas_desc_alvo,
      categorias = c("nativa", "exotica", "seca_morta"),
      id_correcao = "__SANITIZACAO_DESCONHECIDA_POS_CORRECOES__",
      ordem_operacao = NA_character_,
      arquivo_correcao = arquivo_correcao,
      dicionario = dicionario,
      registrar_preservadas = TRUE
    )
    dt <- res_desc_cons$dt
    if (nrow(res_desc_cons$audit)) {
      monitora_correcao_gravar_auditoria_sanitizacao_desconhecida(res_desc_cons$audit)
      audit <- data.table::rbindlist(list(audit, res_desc_cons$audit), fill = TRUE, use.names = TRUE)
    }
    if (nrow(res_desc_cons$afetacoes)) {
      afetacoes_vinculos <- data.table::rbindlist(list(afetacoes_vinculos, res_desc_cons$afetacoes), fill = TRUE, use.names = TRUE)
      linhas_afetadas_vinculos <- unique(c(linhas_afetadas_vinculos, res_desc_cons$afetacoes$linha_indice))
      linhas_semantica_alvo <- unique(c(linhas_semantica_alvo, res_desc_cons$afetacoes$linha_indice))
    }
  }

  ### Antes de remover linhas, fixa o contexto estável das alterações já
  ### auditadas. Assim a auditoria não passa a apontar para linhas deslocadas
  ### após exclusões de COLETA.
  if (nrow(audit) > 0L) audit <- monitora_correcao_anexar_contexto_auditoria(audit, dt, chaves)



  ### TRIOUT antes de PENDFV: a sanitização/conversão de outras formas é
  ### normalização de base e deve ocorrer antes de preencher pendências sem forma.
  ### Mantém aplicação atômica e vetorizada; o backend posterior de TRIOUT ficará
  ### sem operações restantes quando esta etapa consumir o grupo.
  if (nrow(corr) > 0L) {
    res_triout_pre_pendfv <- monitora_correcao_aplicar_limpezas_outras_formas_estado_corrente(
      dt,
      corr,
      chaves = chaves,
      indice = indice_linhas,
      arquivo_correcao = arquivo_correcao,
      dicionario = dicionario
    )
    dt <- res_triout_pre_pendfv$dt
    if (nrow(res_triout_pre_pendfv$audit) > 0L) audit <- data.table::rbindlist(list(audit, res_triout_pre_pendfv$audit), fill = TRUE, use.names = TRUE)
    if (length(res_triout_pre_pendfv$linhas) > 0L) {
      linhas_semantica_alvo <- unique(c(linhas_semantica_alvo, res_triout_pre_pendfv$linhas))
      linhas_afetadas_vinculos <- unique(c(linhas_afetadas_vinculos, res_triout_pre_pendfv$linhas))
    }
    if (nrow(res_triout_pre_pendfv$afetacoes) > 0L) afetacoes_vinculos <- data.table::rbindlist(list(afetacoes_vinculos, res_triout_pre_pendfv$afetacoes), fill = TRUE, use.names = TRUE)
    falha_limpeza_outras_formas <- isTRUE(res_triout_pre_pendfv$falha)
    if (isTRUE(res_triout_pre_pendfv$n_grupos > 0L)) {
      corr <- res_triout_pre_pendfv$corr
      if (nrow(corr) > 0L) corr[, ordem_tmp := seq_len(.N)]
      indice_linhas <- monitora_correcao_criar_indice_linhas(dt, chaves)
      monitora_log_registrar_evento(
        "correcoes_campos",
        ifelse(isTRUE(falha_limpeza_outras_formas), "ERRO", "INFO"),
        arquivo_correcao,
        paste0(res_triout_pre_pendfv$n_grupos, " operação(ões) semântica(s) TRIOUT processada(s) antes de PENDFV; ", length(res_triout_pre_pendfv$linhas), " linha(s) alterada(s)"),
        "TRIOUT vetorizado por filtro estável de COLETA; evita conflito com pendências sem forma"
      )
    }
  }

  if (isTRUE(falha_limpeza_outras_formas)) {
    if (nrow(audit) > 0) {
      audit <- monitora_correcao_anexar_contexto_auditoria(audit, dt, chaves)
      saida_audit <- file.path(MONITORA_LOG_DIR, paste0("auditoria_correcoes_campos_", MONITORA_EXEC_ID, ".csv"))
      monitora_fwrite(audit, saida_audit, na = "")
      monitora_fwrite(audit, file.path(MONITORA_CORRECOES_DIR, "auditoria_correcoes_campos_ultima_execucao.csv"), na = "")
    }
    stop("Limpeza atômica de outras formas de vida falhou antes de PENDFV; ver auditoria_correcoes_campos_ultima_execucao.csv", call. = FALSE)
  }

  ### Correções contextuais de pendências sem forma de vida (PENDFV).
  ### Aplicação vetorizada por id_correcao: cada decisão do painel é uma operação
  ### semântica; os itens auditáveis são usados apenas para rastreabilidade.
  falha_pendencia_sem_forma <- FALSE
  if (nrow(corr) > 0L) {
    res_pendfv_atom <- monitora_correcao_aplicar_pendencias_sem_forma_atomicas(
      dt,
      corr,
      chaves = chaves,
      arquivo_correcao = arquivo_correcao,
      dicionario = dicionario
    )
    dt <- res_pendfv_atom$dt
    if (nrow(res_pendfv_atom$audit) > 0L) audit <- data.table::rbindlist(list(audit, res_pendfv_atom$audit), fill = TRUE, use.names = TRUE)
    if (length(res_pendfv_atom$linhas) > 0L) {
      linhas_semantica_alvo <- unique(c(linhas_semantica_alvo, res_pendfv_atom$linhas))
      linhas_afetadas_vinculos <- unique(c(linhas_afetadas_vinculos, res_pendfv_atom$linhas))
    }
    if (nrow(res_pendfv_atom$afetacoes) > 0L) afetacoes_vinculos <- data.table::rbindlist(list(afetacoes_vinculos, res_pendfv_atom$afetacoes), fill = TRUE, use.names = TRUE)
    falha_pendencia_sem_forma <- isTRUE(res_pendfv_atom$falha)
    if (isTRUE(res_pendfv_atom$n_grupos > 0L)) {
      corr <- res_pendfv_atom$corr
      if (nrow(corr) > 0L) corr[, ordem_tmp := seq_len(.N)]
      indice_linhas <- monitora_correcao_criar_indice_linhas(dt, chaves)
      monitora_log_registrar_evento(
        "correcoes_campos",
        ifelse(isTRUE(falha_pendencia_sem_forma), "ERRO", "INFO"),
        arquivo_correcao,
        paste0(res_pendfv_atom$n_grupos, " operação(ões) semântica(s) PENDFV processada(s) vetorialmente; ", length(res_pendfv_atom$linhas), " linha(s) alterada(s)"),
        "itens auditáveis preservados; aplicação agrupada por id_correcao"
      )
    }
  }

  if (isTRUE(falha_pendencia_sem_forma)) {
    if (nrow(audit) > 0) {
      audit <- monitora_correcao_anexar_contexto_auditoria(audit, dt, chaves)
      saida_audit <- file.path(MONITORA_LOG_DIR, paste0("auditoria_correcoes_campos_", MONITORA_EXEC_ID, ".csv"))
      monitora_fwrite(audit, saida_audit, na = "")
      monitora_fwrite(audit, file.path(MONITORA_CORRECOES_DIR, "auditoria_correcoes_campos_ultima_execucao.csv"), na = "")
    }
    stop("Correção contextual de pendências sem forma de vida falhou; ver auditoria_correcoes_campos_ultima_execucao.csv", call. = FALSE)
  }

  ### Limpeza de outras formas de vida (TRIOUT) no estado corrente.
  ### Operação por ocorrência diagnóstica aplicada antes das exclusões de COLETA,
  ### usando UUID/chave composta; linha_indice é apenas fallback auditável.
  if (nrow(corr) > 0L) {
    res_triout_atom <- monitora_correcao_aplicar_limpezas_outras_formas_estado_corrente(
      dt,
      corr,
      chaves = chaves,
      indice = indice_linhas,
      arquivo_correcao = arquivo_correcao,
      dicionario = dicionario
    )
    dt <- res_triout_atom$dt
    if (nrow(res_triout_atom$audit) > 0L) audit <- data.table::rbindlist(list(audit, res_triout_atom$audit), fill = TRUE, use.names = TRUE)
    if (length(res_triout_atom$linhas) > 0L) {
      linhas_semantica_alvo <- unique(c(linhas_semantica_alvo, res_triout_atom$linhas))
      linhas_afetadas_vinculos <- unique(c(linhas_afetadas_vinculos, res_triout_atom$linhas))
    }
    if (nrow(res_triout_atom$afetacoes) > 0L) afetacoes_vinculos <- data.table::rbindlist(list(afetacoes_vinculos, res_triout_atom$afetacoes), fill = TRUE, use.names = TRUE)
    falha_limpeza_outras_formas <- isTRUE(res_triout_atom$falha)
    if (isTRUE(res_triout_atom$n_grupos > 0L)) {
      corr <- res_triout_atom$corr
      if (nrow(corr) > 0L) corr[, ordem_tmp := seq_len(.N)]
      indice_linhas <- monitora_correcao_criar_indice_linhas(dt, chaves)
      monitora_log_registrar_evento(
        "correcoes_campos",
        ifelse(isTRUE(falha_limpeza_outras_formas), "ERRO", "INFO"),
        arquivo_correcao,
        paste0(res_triout_atom$n_grupos, " operação(ões) semântica(s) TRIOUT processada(s) no estado corrente; ", length(res_triout_atom$linhas), " linha(s) alterada(s)"),
        "alvo por UUID/chave composta aplicado antes de exclusões; sem índices antigos"
      )
    }
  }

  if (isTRUE(falha_limpeza_outras_formas)) {
    if (nrow(audit) > 0) {
      audit <- monitora_correcao_anexar_contexto_auditoria(audit, dt, chaves)
      saida_audit <- file.path(MONITORA_LOG_DIR, paste0("auditoria_correcoes_campos_", MONITORA_EXEC_ID, ".csv"))
      monitora_fwrite(audit, saida_audit, na = "")
      monitora_fwrite(audit, file.path(MONITORA_CORRECOES_DIR, "auditoria_correcoes_campos_ultima_execucao.csv"), na = "")
    }
    stop("Limpeza atômica de outras formas de vida falhou na auditoria pós-aplicação; ver auditoria_correcoes_campos_ultima_execucao.csv", call. = FALSE)
  }

  ### Exclusões de COLETAS: aplicar grupos em lote, com auditoria pré-exclusão
  ### e uma única remoção vetorizada. Isso evita reconstruir o índice após cada
  ### COLETA e reduz risco de inconsistência por deslocamento de linha.
  if (nrow(corr) > 0L) {
    res_exc_atom <- monitora_correcao_aplicar_exclusoes_coleta_atomicas(
      dt,
      corr,
      chaves = chaves,
      indice = indice_linhas,
      arquivo_correcao = arquivo_correcao
    )
    dt <- res_exc_atom$dt
    if (nrow(res_exc_atom$audit) > 0L) audit <- data.table::rbindlist(list(audit, res_exc_atom$audit), fill = TRUE, use.names = TRUE)
    if (length(res_exc_atom$coletas) > 0L) coletas_excluidas_aplicadas <- unique(c(coletas_excluidas_aplicadas, res_exc_atom$coletas))
    if (isTRUE(res_exc_atom$n_grupos > 0L)) {
      corr <- res_exc_atom$corr
      corr[, ordem_tmp := seq_len(.N)]
      indice_linhas <- monitora_correcao_criar_indice_linhas(dt, chaves)
      linhas_semantica_alvo <- linhas_semantica_alvo[linhas_semantica_alvo <= nrow(dt)]
      monitora_log_registrar_evento(
        "correcoes_campos",
        ifelse(isTRUE(res_exc_atom$falha), "AVISO", "INFO"),
        arquivo_correcao,
        paste0(res_exc_atom$n_grupos, " grupo(s) de exclusão de COLETAS processado(s) atomicamente; ", length(res_exc_atom$linhas_removidas), " linha(s) removida(s)"),
        "exclusão em lote por data.table; índice reconstruído uma única vez"
      )
    }
  }

  if (nrow(corr) > 0L && length(coletas_excluidas_aplicadas) > 0L) {
    idx_subsumidas_publicacao_q <- which(vapply(seq_len(nrow(corr)), function(ii) {
      monitora_publicacao_q_operacao_totalmente_subsumida_por_exclusao(corr[ii], coletas_excluidas_aplicadas)
    }, logical(1L)))
    if (length(idx_subsumidas_publicacao_q) > 0L) {
      audit_sub_gen <- data.table::rbindlist(lapply(idx_subsumidas_publicacao_q, function(ii) {
        monitora_publicacao_q_auditoria_subsumida_por_exclusao(
          corr[ii],
          arquivo_correcao = arquivo_correcao,
          atributo = if ("atributo_coluna_registros_corrig" %in% names(corr)) corr$atributo_coluna_registros_corrig[ii] else NA_character_,
          status = "ok_subsumida_por_exclusao",
          n_linhas_alvo_original = suppressWarnings(as.integer(corr$n_linhas_esperado[ii])),
          n_linhas_subsumidas = suppressWarnings(as.integer(corr$n_linhas_esperado[ii])),
          n_linhas_aplicadas = 0L,
          coletas_subsumidas = monitora_publicacao_q_parse_coletas_operacao(corr[ii]),
          mensagem_extra = "v2.5.4: operação modificadora removida do plano porque suas COLETAS já foram excluídas"
        )
      }), fill = TRUE, use.names = TRUE)
      audit <- data.table::rbindlist(list(audit, audit_sub_gen), fill = TRUE, use.names = TRUE)
      corr <- corr[-idx_subsumidas_publicacao_q]
      if (nrow(corr) > 0L) corr[, ordem_tmp := seq_len(.N)]
      monitora_log_registrar_evento(
        "correcoes_campos",
        "INFO",
        arquivo_correcao,
        paste0("v2.5.4: ", length(idx_subsumidas_publicacao_q), " operação(ões) modificadora(s) subsumida(s) por exclusão dominante e removida(s) do plano de aplicação"),
        "orquestrador de operações atômicas"
      )
    }
  }

  if (nrow(corr) > 0L) {
    if (!("id_correcao" %in% names(corr))) corr[, id_correcao := NA_character_]
    corr[, grupo_correcao := fifelse(!is.na(id_correcao) & nzchar(as.character(id_correcao)), as.character(id_correcao), paste0("__linha_", ordem_tmp))]
  ### v2.6.1: reclassificar operações ambíguas de token antes da pré-validação
  ### transacional. Isso evita que um update em lista select_multiple com
  ### valor_original_esperado parcial ("graminoide") bloqueie um grupo cuja
  ### intenção operacional é substituir token ("graminoide" -> "samambaia").
  res_publicacao_s_token <- monitora_publicacao_s_reclassificar_updates_tokenizados(
    dt,
    corr,
    chaves,
    dicionario = dicionario,
    indice_linhas = indice_linhas,
    arquivo_correcao = arquivo_correcao
  )
  corr <- res_publicacao_s_token$corr
  if (nrow(res_publicacao_s_token$audit) > 0L) {
    audit <- data.table::rbindlist(list(audit, res_publicacao_s_token$audit), fill = TRUE, use.names = TRUE)
    monitora_log_registrar_evento(
      "correcoes_campos",
      "INFO",
      arquivo_correcao,
      paste0("v2.5.4: ", res_publicacao_s_token$n, " operação(ões) update reclassificada(s) para replace_token antes da pré-validação"),
      "preserva update estrito para valor completo e corrige operações tokenizadas ambíguas em select_multiple"
    )
  }

  pre_list <- vector("list", nrow(corr))
  for (pp in seq_len(nrow(corr))) {
    pre <- monitora_correcao_prevalidar_operacao(dt, corr[pp], chaves, dicionario, indice_linhas)
    pre[, ordem_tmp := corr$ordem_tmp[pp]]
    pre[, grupo_correcao := corr$grupo_correcao[pp]]
    pre_list[[pp]] <- pre
  }
  prevalidacao <- data.table::rbindlist(pre_list, fill = TRUE, use.names = TRUE)
  grupos_invalidos <- unique(prevalidacao[status_prevalidacao != "ok", grupo_correcao])
  grupos_invalidos <- grupos_invalidos[!is.na(grupos_invalidos) & nzchar(grupos_invalidos)]
  if (length(grupos_invalidos)) {
    corr_invalidas <- prevalidacao[grupo_correcao %in% grupos_invalidos]
    corr_invalidas <- merge(corr, corr_invalidas, by = "ordem_tmp", all.y = TRUE, sort = FALSE)
    audit_bloq <- corr_invalidas[, .(
      id_correcao = id_correcao,
      ordem_operacao = ordem_operacao,
      status = fifelse(status_prevalidacao == "ok", "bloqueada_grupo_incompleto", status_prevalidacao),
      mensagem = paste0("Grupo de correção bloqueado transacionalmente: ", mensagem_prevalidacao),
      atributo = atributo_coluna_registros_corrig,
      linha_indice = NA_integer_,
      valor_antes = NA_character_,
      valor_depois = NA_character_,
      arquivo_correcao = arquivo_correcao
    )]
    audit <- data.table::rbindlist(list(audit, audit_bloq), fill = TRUE, use.names = TRUE)
    corr <- corr[!(grupo_correcao %in% grupos_invalidos)]
    if (nrow(corr) == 0L) {
      if (nrow(audit) > 0) {
        audit <- monitora_correcao_anexar_contexto_auditoria(audit, dt, chaves)
        saida_audit <- file.path(MONITORA_LOG_DIR, paste0("auditoria_correcoes_campos_", MONITORA_EXEC_ID, ".csv"))
        monitora_fwrite(audit, saida_audit, na = "")
        monitora_fwrite(audit, file.path(MONITORA_CORRECOES_DIR, "auditoria_correcoes_campos_ultima_execucao.csv"), na = "")
        monitora_log_registrar_evento("correcoes_campos", "AVISO", saida_audit, paste0(nrow(audit), " operação(ões) bloqueada(s) por validação transacional"), "nenhuma correção aplicada")
      }
      return(dt[])
    }
  }

  }

  if (nrow(corr) > 0L) {
    linhas_list <- vector("list", nrow(corr))
    for (pp2 in seq_len(nrow(corr))) {
      linhas_list[[pp2]] <- tryCatch(monitora_correcao_localizar_linhas(dt, corr[pp2], chaves, indice_linhas), error = function(e) integer(0))
    }
    linhas_semantica_alvo_generica <- unique(as.integer(unlist(linhas_list, use.names = FALSE)))
    linhas_semantica_alvo_generica <- linhas_semantica_alvo_generica[!is.na(linhas_semantica_alvo_generica) & linhas_semantica_alvo_generica >= 1L & linhas_semantica_alvo_generica <= nrow(dt)]
    ### Não sobrescrever alvos semânticos acumulados por operações atômicas.
    ### Linhas de MVLOTE ambíguas devem ser avaliadas de forma coerente no pré e no pós-teste, pois
    ### podiam ser removidas do pré-teste quando ainda havia correções genéricas
    ### remanescentes. Isso gerava falso "erro introduzido" para valores que
    ### foram mantidos intocados, como marcadores "Outra espécie..." em linhas
    ### ambíguas preservadas para revisão.
    linhas_semantica_alvo <- unique(c(linhas_semantica_alvo, linhas_semantica_alvo_generica))
    try(monitora_correcao_auditar_lotes_multicoletas(dt, corr, linhas_list, chaves, arquivo_correcao), silent = TRUE)
  }
  contexto_semantica_pre <- paste0("pre_correcoes_", if (exists("MONITORA_EXEC_ID", inherits = TRUE)) MONITORA_EXEC_ID else format(Sys.time(), "%Y%m%d_%H%M%S"))
  auditoria_semantica_pre <- monitora_correcao_auditar_papeis_colunas_semantica(
    dt,
    contexto = contexto_semantica_pre,
    abortar = FALSE,
    linhas = if (isTRUE(auditoria_semantica_completa)) NULL else linhas_semantica_alvo
  )

  for (rr in seq_len(nrow(corr))) {
    linha_corr <- corr[rr]
    col <- monitora_correcao_resolver_coluna(dt, linha_corr$atributo_coluna_registros_corrig[1], dicionario)
    acao <- tolower(trimws(as.character(linha_corr$acao[1])))
    linhas <- monitora_correcao_localizar_linhas(dt, linha_corr, chaves, indice_linhas)
    n_esperado <- suppressWarnings(as.integer(linha_corr$n_linhas_esperado[1]))
    status <- "aplicada"
    msg <- "OK"
    tipo_corr <- if ("tipo_correcao" %in% names(linha_corr)) tolower(trimws(as.character(linha_corr$tipo_correcao[1]))) else ""
    if (is.na(tipo_corr)) tipo_corr <- ""

    if (isTRUE(monitora_correcao_acao_exclusao_coleta(acao, tipo_corr))) {
      linhas <- monitora_correcao_localizar_linhas(dt, linha_corr, chaves, monitora_correcao_criar_indice_linhas(dt, chaves))
      if (length(linhas) == 0L) {
        status <- "falha"; msg <- "Nenhuma linha-alvo localizada para exclusão da COLETA"
      } else if (!is.na(n_esperado) && n_esperado > 0L && length(linhas) != n_esperado) {
        status <- "falha"; msg <- paste0("n_linhas_alvo=", length(linhas), " diferente de n_linhas_esperado=", n_esperado, " para exclusão da COLETA")
      } else {
        audit_del <- data.table::data.table(
          id_correcao = linha_corr$id_correcao[1],
          ordem_operacao = linha_corr$ordem_operacao[1],
          status = "excluida_coleta",
          mensagem = paste0("COLETA excluída integralmente por correção auditável; ", length(linhas), " registro(s) removido(s)"),
          atributo = chaves$coleta,
          linha_indice = linhas,
          valor_antes = if (!is.na(chaves$coleta) && chaves$coleta %in% names(dt)) as.character(dt[[chaves$coleta]][linhas]) else NA_character_,
          valor_depois = "<REGISTRO_REMOVIDO>",
          arquivo_correcao = arquivo_correcao
        )
        audit_del <- monitora_correcao_anexar_contexto_auditoria(audit_del, dt, chaves)
        audit <- data.table::rbindlist(list(audit, audit_del), fill = TRUE, use.names = TRUE)
        coleta_excluida_val <- if ("coleta" %in% names(linha_corr)) as.character(linha_corr$coleta[1L]) else NA_character_
        if (!is.na(coleta_excluida_val) && nzchar(trimws(coleta_excluida_val))) {
          coletas_excluidas_aplicadas <- unique(c(coletas_excluidas_aplicadas, coleta_excluida_val))
        }
        dt <- dt[-linhas]
        indice_linhas <- monitora_correcao_criar_indice_linhas(dt, chaves)
        linhas_semantica_alvo <- linhas_semantica_alvo[linhas_semantica_alvo <= nrow(dt)]
      }
      if (!identical(status, "aplicada")) {
        audit <- data.table::rbindlist(list(audit, data.table::data.table(
          id_correcao = linha_corr$id_correcao[1], ordem_operacao = linha_corr$ordem_operacao[1],
          status = status, mensagem = msg, atributo = linha_corr$atributo_coluna_registros_corrig[1],
          linha_indice = NA_integer_, valor_antes = NA_character_, valor_depois = NA_character_,
          arquivo_correcao = arquivo_correcao
        )), fill = TRUE, use.names = TRUE)
      }
      next
    }

    if (acao %in% c("recalcular_tipo_forma_vida", "atualizar_tipo_forma_vida")) {
      if (length(linhas) == 0) {
        status <- "falha"; msg <- "Nenhuma linha-alvo localizada para recalcular tipo_forma_vida"
      } else {
        antes_tipo <- if (!is.na(chaves$tipo_forma_vida) && chaves$tipo_forma_vida %in% names(dt)) as.character(dt[[chaves$tipo_forma_vida]][linhas]) else NA_character_
        monitora_correcao_recalcular_tipo_forma_vida(dt, linhas)
        depois_tipo <- if (!is.na(chaves$tipo_forma_vida) && chaves$tipo_forma_vida %in% names(dt)) as.character(dt[[chaves$tipo_forma_vida]][linhas]) else NA_character_
        linhas_afetadas_vinculos <- unique(c(linhas_afetadas_vinculos, linhas))
        if (!is.na(chaves$tipo_forma_vida) && chaves$tipo_forma_vida %in% names(dt)) {
          afetacoes_vinculos <- data.table::rbindlist(list(afetacoes_vinculos, data.table::data.table(linha_indice = linhas, atributo = chaves$tipo_forma_vida)), fill = TRUE, use.names = TRUE)
        }
        audit <- data.table::rbindlist(list(audit, data.table::data.table(
          id_correcao = linha_corr$id_correcao[1], ordem_operacao = linha_corr$ordem_operacao[1],
          status = status, mensagem = msg, atributo = chaves$tipo_forma_vida,
          linha_indice = linhas, valor_antes = antes_tipo, valor_depois = depois_tipo,
          arquivo_correcao = arquivo_correcao
        )), fill = TRUE, use.names = TRUE)
      }
      next
    }

    if (!is.na(col) && col %in% names(dt) && monitora_correcao_coluna_protegida(col)) {
      status <- "bloqueada_coluna_protegida"
      msg <- paste0("Correção bloqueada: coluna estrutural/protegida não pode ser alterada: ", col)
    } else if (monitora_correcao_coluna_protegida(linha_corr$atributo_coluna_registros_corrig[1])) {
      status <- "bloqueada_coluna_protegida"
      msg <- paste0("Correção bloqueada: atributo solicitado é coluna estrutural/protegida: ", linha_corr$atributo_coluna_registros_corrig[1])
    } else if (is.na(col) || !(col %in% names(dt))) {
      status <- "falha"; msg <- paste0("Coluna não encontrada: ", linha_corr$atributo_coluna_registros_corrig[1])
    } else if (length(linhas) == 0) {
      status <- "falha"; msg <- "Nenhuma linha-alvo localizada"
    } else if (!is.na(n_esperado) && n_esperado > 0L && length(linhas) != n_esperado) {
      status <- "falha"; msg <- paste0("n_linhas_alvo=", length(linhas), " diferente de n_linhas_esperado=", n_esperado)
    } else {
      valid_dest <- monitora_correcao_validar_destino_operacao(dt, col, acao, linha_corr$valor_novo[1], linha_corr, dicionario)
      if (!isTRUE(valid_dest$ok)) {
        status <- valid_dest$status
        msg <- valid_dest$mensagem
      }
      valor_atual <- as.character(dt[[col]][linhas])
      esperado <- linha_corr$valor_original_esperado[1]
      precond <- monitora_publicacao_d_precondicao_valor_original(valor_atual, acao, linha_corr$valor_novo[1], esperado)
      if (!isTRUE(precond$ok)) {
        status <- "falha"
        msg <- precond$mensagem
      } else if (!identical(precond$mensagem, "OK")) {
        msg <- precond$mensagem
      }
      if (identical(status, "aplicada")) {
        novo <- monitora_correcao_aplicar_operacao(valor_atual, acao, linha_corr$valor_novo[1], esperado)
        mudou <- monitora_correcao_na_para_vazio(valor_atual) != monitora_correcao_na_para_vazio(novo)
        if (any(mudou, na.rm = TRUE)) {
          data.table::set(dt, i = linhas[mudou], j = col, value = novo[mudou])
          linhas_afetadas_vinculos <- unique(c(linhas_afetadas_vinculos, linhas[mudou]))
          afetacoes_vinculos <- data.table::rbindlist(list(afetacoes_vinculos, data.table::data.table(linha_indice = linhas[mudou], atributo = col)), fill = TRUE, use.names = TRUE)
          audit <- data.table::rbindlist(list(audit, data.table::data.table(
            id_correcao = linha_corr$id_correcao[1], ordem_operacao = linha_corr$ordem_operacao[1],
            status = status, mensagem = msg, atributo = col,
            linha_indice = linhas[mudou], valor_antes = valor_atual[mudou], valor_depois = novo[mudou],
            arquivo_correcao = arquivo_correcao
          )), fill = TRUE, use.names = TRUE)
        } else {
          audit <- data.table::rbindlist(list(audit, data.table::data.table(
            id_correcao = linha_corr$id_correcao[1], ordem_operacao = linha_corr$ordem_operacao[1],
            status = "ignorada_sem_alteracao", mensagem = "Operação sem efeito: valor final igual ao valor inicial", atributo = col,
            linha_indice = linhas, valor_antes = valor_atual, valor_depois = novo,
            arquivo_correcao = arquivo_correcao
          )), fill = TRUE, use.names = TRUE)
        }
      }
    }
    if (!identical(status, "aplicada")) {
      audit <- data.table::rbindlist(list(audit, data.table::data.table(
        id_correcao = linha_corr$id_correcao[1], ordem_operacao = linha_corr$ordem_operacao[1],
        status = status, mensagem = msg, atributo = linha_corr$atributo_coluna_registros_corrig[1],
        linha_indice = NA_integer_, valor_antes = NA_character_, valor_depois = NA_character_,
        arquivo_correcao = arquivo_correcao
      )), fill = TRUE, use.names = TRUE)
    }
  }

  if (length(coletas_excluidas_aplicadas) > 0L && !is.na(chaves$coleta) && chaves$coleta %in% names(dt)) {
    coletas_excluidas_aplicadas <- unique(coletas_excluidas_aplicadas[!is.na(coletas_excluidas_aplicadas) & nzchar(trimws(coletas_excluidas_aplicadas))])
    if (length(coletas_excluidas_aplicadas) > 0L) {
      idx_vestigios <- which(as.character(dt[[chaves$coleta]]) %chin% coletas_excluidas_aplicadas)
      if (length(idx_vestigios) > 0L) {
        vestigios <- dt[idx_vestigios, .(
          linha_indice_pos_correcoes = idx_vestigios,
          COLETA = as.character(get(chaves$coleta))
        )]
        exec_id_vest <- if (exists("MONITORA_EXEC_ID", inherits = TRUE)) MONITORA_EXEC_ID else format(Sys.time(), "%Y%m%d_%H%M%S")
        arq_vest_log <- file.path(MONITORA_LOG_DIR, paste0("auditoria_exclusao_coletas_vestigios_", exec_id_vest, ".csv"))
        arq_vest_ult <- file.path(MONITORA_CORRECOES_DIR, "auditoria_exclusao_coletas_vestigios_ultima_execucao.csv")
        monitora_fwrite(vestigios, arq_vest_log, na = "")
        monitora_fwrite(vestigios, arq_vest_ult, na = "")
        monitora_log_registrar_evento(
          "exclusao_coletas", "ERRO", arq_vest_log,
          paste0(length(idx_vestigios), " vestígio(s) de COLETA excluída permaneceram em registros_corrig"),
          "execução bloqueada; revisar auditoria de vestígios"
        )
        stop("Exclusão de COLETAS falhou: ainda há linhas das COLETAS excluídas em registros_corrig. Ver auditoria_exclusao_coletas_vestigios_ultima_execucao.csv", call. = FALSE)
      } else {
        monitora_log_registrar_evento(
          "exclusao_coletas", "INFO", NA_character_,
          paste0(length(coletas_excluidas_aplicadas), " COLETA(s) excluída(s) sem vestígios em registros_corrig"),
          "OK"
        )
      }
    }
  }

  reforco_movimentos <- monitora_correcao_reforcar_movimentos_forma_vida(dt, corr, chaves, dicionario)
  if (nrow(reforco_movimentos$audit) > 0L) {
    audit <- data.table::rbindlist(list(audit, reforco_movimentos$audit), fill = TRUE, use.names = TRUE)
    linhas_afetadas_vinculos <- unique(c(linhas_afetadas_vinculos, reforco_movimentos$linhas))
    afetacoes_vinculos <- data.table::rbindlist(list(afetacoes_vinculos, reforco_movimentos$afetacoes), fill = TRUE, use.names = TRUE)
    monitora_log_registrar_evento(
      "correcoes_campos",
      "INFO",
      NA_character_,
      paste0(nrow(reforco_movimentos$audit), " reforço(s) semântico(s) aplicado(s) em movimentos de forma de vida"),
      "movimentos interpretados antes do recálculo de campos superiores"
    )
  }

  if (length(linhas_afetadas_vinculos) > 0L) {
    deps_vinculos <- if (exists("MONITORA_DEPENDENCIAS_CORRECOES", inherits = TRUE)) get("MONITORA_DEPENDENCIAS_CORRECOES", inherits = TRUE) else NULL
    audit_vinculos <- monitora_correcao_recalcular_superiores_vinculados(dt, linhas_afetadas_vinculos, deps_vinculos, dicionario, afetacoes_vinculos)
    if (nrow(audit_vinculos) > 0L) {
      audit <- data.table::rbindlist(list(audit, audit_vinculos), fill = TRUE, use.names = TRUE)
      monitora_log_registrar_evento(
        "correcoes_campos",
        "INFO",
        NA_character_,
        paste0(nrow(audit_vinculos), " atualização(ões) automática(s) de campos superiores vinculados ao XLSForm"),
        "campos superiores recalculados após correções"
      )
    }
  }


  ### Contrato final obrigatório para Encostam/tipo_forma_vida.
  ### A auditoria de persistência mostrou que recálculos intermediários podiam deixar
  ### tokens superiores antigos em algumas linhas. A sincronização abaixo roda
  ### depois de todas as operações assistidas e antes da auditoria de persistência,
  ### garantindo que o campo superior derive do estado final das listas inferiores.
  linhas_sync_final <- unique(as.integer(c(
    linhas_afetadas_vinculos,
    linhas_semantica_alvo,
    if (nrow(audit) > 0L && "linha_indice" %in% names(audit)) suppressWarnings(as.integer(audit$linha_indice)) else integer(0)
  )))
  linhas_sync_final <- linhas_sync_final[!is.na(linhas_sync_final) & linhas_sync_final >= 1L & linhas_sync_final <= nrow(dt)]
  sync_encostam_final <- monitora_correcao_sincronizar_encostam_final(
    dt,
    linhas = linhas_sync_final,
    chaves = chaves,
    contexto = "pos_aplicacao_objeto"
  )
  dt <- sync_encostam_final$dt
  if (nrow(sync_encostam_final$audit) > 0L) {
    audit <- data.table::rbindlist(list(audit, sync_encostam_final$audit), fill = TRUE, use.names = TRUE)
    linhas_afetadas_vinculos <- unique(c(linhas_afetadas_vinculos, sync_encostam_final$linhas))
    afetacoes_vinculos <- data.table::rbindlist(list(afetacoes_vinculos, sync_encostam_final$afetacoes), fill = TRUE, use.names = TRUE)
    monitora_log_registrar_evento(
      "correcoes_campos",
      "INFO",
      NA_character_,
      paste0(nrow(sync_encostam_final$audit), " sincronização(ões) final(is) de Encostam/tipo_forma_vida aplicada(s)"),
      "campo superior harmonizado pelo contrato derivado das listas inferiores finais"
    )
  }

  if (isTRUE(get0("MONITORA_OPCAO_CHECKPOINTS_GRANULARES_CORRECOES", ifnotfound = "S", inherits = TRUE) == "S") && exists("monitora_perf_registrar_checkpoint", mode = "function")) {
    monitora_perf_registrar_checkpoint("painel_correcoes_operacoes_atomicas_pre_recalculo_data", "operações atômicas de correção de campos aplicadas; antes de derivados de data/hora", dt)
  }
  dt <- monitora_recalcular_derivados_data_hora_se_necessario(
    dt,
    corr = corr,
    contexto = "pos_aplicacao_arquivo_correcoes",
    forcar = FALSE
  )
  chaves <- monitora_correcao_colunas_chave(dt)

  if (nrow(audit) > 0) {
    audit <- monitora_correcao_anexar_contexto_auditoria(audit, dt, chaves)
    MONITORA_AUDITORIA_CORRECOES_CAMPOS_ULTIMA <<- data.table::copy(audit)
    MONITORA_COLETAS_EXCLUIDAS_CORRECOES_ULTIMA <<- unique(coletas_excluidas_aplicadas)
    abortar_persistencia_objeto <- TRUE
    if (isTRUE(get0("MONITORA_REPLAY_DIAGNOSTICO_NAO_ABORTAR", ifnotfound = FALSE, inherits = TRUE)) &&
        isTRUE(get0("MONITORA_REAPLICAR_CORRECOES_ANTERIORES", ifnotfound = FALSE, inherits = TRUE)) &&
        (isTRUE(get0("MONITORA_REPLAY_SEMANTICO_EM_EXECUCAO", ifnotfound = FALSE, inherits = TRUE)) ||
           exists("MONITORA_ARQUIVO_CORRECOES_CAMPOS_REAPLICADO", inherits = TRUE))) {
      abortar_persistencia_objeto <- FALSE
    }
    monitora_correcao_auditar_persistencia_operacoes(
      dt,
      audit,
      chaves = chaves,
      coletas_excluidas = coletas_excluidas_aplicadas,
      contexto = "pos_aplicacao_objeto",
      abortar = abortar_persistencia_objeto
    )
    saida_audit <- file.path(MONITORA_LOG_DIR, paste0("auditoria_correcoes_campos_", MONITORA_EXEC_ID, ".csv"))
    monitora_fwrite(audit, saida_audit, na = "")
    monitora_fwrite(audit, file.path(MONITORA_CORRECOES_DIR, "auditoria_correcoes_campos_ultima_execucao.csv"), na = "")
    nivel_audit <- if (any(grepl("^(falha|bloqueada)", as.character(audit$status)) | audit$status %in% c("excluida_coleta"), na.rm = TRUE)) "AVISO" else "INFO"
    monitora_log_registrar_evento("correcoes_campos", nivel_audit, saida_audit, paste0(nrow(audit), " linha(s) de auditoria de correções"), "verificar falhas/bloqueios antes de liberar produtos")
  }

  ### Trava final de integridade: qualquer alteração em coluna estrutural aborta a execução.
  contexto_integridade <- paste0("pos_correcoes_", if (exists("MONITORA_EXEC_ID", inherits = TRUE)) MONITORA_EXEC_ID else format(Sys.time(), "%Y%m%d_%H%M%S"))
  monitora_correcao_auditar_colunas_protegidas(
    snapshot_colunas_protegidas_antes,
    dt,
    contexto = contexto_integridade,
    abortar = TRUE
  )
  monitora_correcao_mapa_colunas_canonicas(dt, contexto = contexto_integridade, gravar = TRUE)
  linhas_semantica_pos <- unique(as.integer(c(linhas_semantica_alvo, linhas_afetadas_vinculos)))
  linhas_semantica_pos <- linhas_semantica_pos[!is.na(linhas_semantica_pos) & linhas_semantica_pos >= 1L & linhas_semantica_pos <= nrow(dt)]
  auditoria_semantica_pos <- monitora_correcao_auditar_papeis_colunas_semantica(
    dt,
    contexto = contexto_integridade,
    abortar = FALSE,
    linhas = if (isTRUE(auditoria_semantica_completa)) NULL else linhas_semantica_pos
  )
  auditoria_semantica_pre_pos <- monitora_correcao_comparar_auditoria_semantica_pre_pos(auditoria_semantica_pre, auditoria_semantica_pos, contexto = contexto_integridade)
  erros_introduzidos <- auditoria_semantica_pre_pos[classificacao == "erro_introduzido_pela_correcao"]
  if (nrow(erros_introduzidos) > 0L) {
    monitora_log_registrar_evento("auditoria_semantica_papeis", "ERRO", NA_character_, paste0(nrow(erros_introduzidos), " erro(s) semântico(s) introduzido(s) por correção"), "execução bloqueada; revisar auditoria_semantica_papeis_colunas_pre_pos_ultima_execucao.csv")
    stop(paste0("Integridade semântica violada: ", nrow(erros_introduzidos), " erro(s) introduzido(s) por correção. Ver auditoria_semantica_papeis_colunas_pre_pos_ultima_execucao.csv"), call. = FALSE)
  }
  dt[]
}

### v2.6.1 - trilha semântica e reaplicação de correções anteriores ---------
monitora_correcao_arquivo_tem_operacoes <- function(arquivo) {
  if (is.na(arquivo) || !nzchar(as.character(arquivo)[1]) || !file.exists(arquivo)) return(FALSE)
  info <- tryCatch(file.info(arquivo), error = function(e) NULL)
  if (is.null(info) || is.na(info$size[1]) || info$size[1] <= 0) return(FALSE)
  x <- tryCatch(data.table::fread(arquivo, nrows = 2L, encoding = "UTF-8", na.strings = c("", "NA"), colClasses = "character"), error = function(e) data.table::data.table())
  nrow(x) > 0L
}

monitora_correcao_ler_operacoes_semanticas <- function(arquivo) {
  if (!monitora_correcao_arquivo_tem_operacoes(arquivo)) return(data.table::data.table())
  corr <- tryCatch(data.table::fread(arquivo, encoding = "UTF-8", na.strings = c("", "NA"), colClasses = "character"), error = function(e) data.table::data.table())
  if (!nrow(corr)) return(data.table::data.table())
  template <- monitora_correcao_template()
  for (cc in setdiff(names(template), names(corr))) corr[, (cc) := NA_character_]
  data.table::setDT(corr)
  corr[]
}

monitora_correcao_hash_texto <- function(x) {
  x <- paste(as.character(x), collapse = "|")
  if (requireNamespace("digest", quietly = TRUE)) return(digest::digest(x, algo = "sha256"))
  paste0("hash_indisponivel_", nchar(x), "_", sum(utf8ToInt(enc2utf8(x)), na.rm = TRUE))
}

monitora_correcao_assinatura_linha_semantica <- function(corr) {
  corr <- data.table::as.data.table(corr)
  if (!nrow(corr)) return(character())
  campos <- intersect(
    c("id_correcao", "tipo_correcao", "ordem_operacao", "escopo_aplicacao", "coleta", "UC", "EA", "UA", "CICLO", "CAMPANHA", "ANO", "Ponto amostral", "Ponto metro", "uuid_registro", "atributo_coluna_registros_corrig", "acao", "token_pai", "categoria_origem", "categoria_destino", "tipo_triagem", "token_removido", "forma_valida_escolhida", "lista_destino", "campo_dependente_preenchido", "habito_escolhido", "valor_original_esperado", "valor_novo", "motivo"),
    names(corr)
  )
  if (!length(campos)) return(rep(NA_character_, nrow(corr)))
  apply(as.data.frame(corr[, ..campos]), 1L, monitora_correcao_hash_texto)
}

monitora_correcao_gravar_trilha_semantica <- function(corr,
                                                      arquivo_origem = NA_character_,
                                                      fase = "sessao_painel",
                                                      status = "registrada",
                                                      contexto = "") {
  if (!isTRUE(get0("MONITORA_GRAVAR_TRILHA_SEMANTICA_CORRECOES", ifnotfound = TRUE, inherits = TRUE))) return(invisible(data.table::data.table()))
  corr <- data.table::as.data.table(corr)
  if (!nrow(corr)) return(invisible(data.table::data.table()))
  template <- monitora_correcao_template()
  for (cc in setdiff(names(template), names(corr))) corr[, (cc) := NA_character_]
  corr[, trilha_schema := "correcoes_semanticas_v1"]
  corr[, script_versao_replay := "2.6.1"]
  corr[, exec_id_registro := get0("MONITORA_EXEC_ID", ifnotfound = format(Sys.time(), "%Y%m%d_%H%M%S"), inherits = TRUE)]
  corr[, fase_trilha := as.character(fase)]
  corr[, status_trilha := as.character(status)]
  corr[, contexto_trilha := as.character(contexto)]
  corr[, arquivo_origem_trilha := as.character(arquivo_origem)[1]]
  corr[, data_hora_trilha := format(Sys.time(), "%Y-%m-%d %H:%M:%S %z")]
  corr[, hash_operacao_semantica := monitora_correcao_assinatura_linha_semantica(.SD)]
  corr_dir <- get0("MONITORA_CORRECOES_DIR", ifnotfound = file.path(get0("MONITORA_OUTPUT_DIR", ifnotfound = "output", inherits = TRUE), "correcoes_campos"), inherits = TRUE)
  dir.create(corr_dir, showWarnings = FALSE, recursive = TRUE)
  exec_id <- get0("MONITORA_EXEC_ID", ifnotfound = format(Sys.time(), "%Y%m%d_%H%M%S"), inherits = TRUE)
  arq_exec <- file.path(corr_dir, paste0("correcoes_semanticas_", fase, "_", exec_id, ".csv"))
  arq_ultima <- file.path(corr_dir, "correcoes_semanticas_ultima_execucao.csv")
  arq_consolidada <- file.path(corr_dir, "correcoes_semanticas_consolidada.csv")
  try(monitora_fwrite(corr, arq_exec, na = ""), silent = TRUE)
  try(monitora_fwrite(corr, arq_ultima, na = ""), silent = TRUE)
  if (file.exists(arq_consolidada)) {
    old <- tryCatch(data.table::fread(arq_consolidada, encoding = "UTF-8", na.strings = c("", "NA"), colClasses = "character"), error = function(e) data.table::data.table())
    comb <- data.table::rbindlist(list(old, corr), fill = TRUE, use.names = TRUE)
    if ("hash_operacao_semantica" %in% names(comb)) comb <- comb[!duplicated(hash_operacao_semantica)]
  } else {
    comb <- corr
  }
  try(monitora_fwrite(comb, arq_consolidada, na = ""), silent = TRUE)
  if (exists("monitora_log_registrar_evento", mode = "function", inherits = TRUE)) {
    monitora_log_registrar_evento("trilha_semantica_correcoes", "INFO", arq_exec, paste0(nrow(corr), " item(ns) auditável(is) registrados na trilha semântica de correções"), "use correcoes_semanticas_consolidada.csv para replay em versões futuras")
  }
  invisible(corr[])
}

monitora_correcao_preparar_arquivo_sessao_pos_replay <- function() {
  corr_dir <- get0("MONITORA_CORRECOES_DIR", ifnotfound = file.path(get0("MONITORA_OUTPUT_DIR", ifnotfound = "output", inherits = TRUE), "correcoes_campos"), inherits = TRUE)
  dir.create(corr_dir, showWarnings = FALSE, recursive = TRUE)
  exec_id <- get0("MONITORA_EXEC_ID", ifnotfound = format(Sys.time(), "%Y%m%d_%H%M%S"), inherits = TRUE)
  arq <- file.path(corr_dir, paste0("correcoes_campos_sessao_", exec_id, ".csv"))
  try(unlink(arq), silent = TRUE)
  MONITORA_ARQUIVO_CORRECOES_CAMPOS <<- arq
  MONITORA_CORRECOES_ARQUIVO_EXISTE <<- FALSE
  arq
}

monitora_correcao_reaplicar_arquivo_semantico <- function(dt,
                                                          arquivo,
                                                          dicionario = NULL,
                                                          contexto = "pre_painel") {
  ### v2.6.1: marcar replay semântico antes da auditoria interna de persistência.
  ### A própria função audita persistência antes de retornar; portanto o marcador
  ### precisa existir antes de chamar monitora_correcao_aplicar_operacoes().
  MONITORA_REPLAY_SEMANTICO_EM_EXECUCAO <<- TRUE
  MONITORA_ARQUIVO_CORRECOES_CAMPOS_REAPLICADO <<- arquivo
  on.exit({
    MONITORA_REPLAY_SEMANTICO_EM_EXECUCAO <<- FALSE
  }, add = TRUE)
  if (!monitora_correcao_arquivo_tem_operacoes(arquivo)) {
    if (exists("monitora_log_registrar_evento", mode = "function", inherits = TRUE)) {
      monitora_log_registrar_evento("reaplicacao_correcoes", "INFO", arquivo, "Arquivo de correções anteriores não encontrado, vazio ou sem operações", "replay ignorado")
    }
    return(dt)
  }
  corr <- monitora_correcao_ler_operacoes_semanticas(arquivo)
  n_sem <- tryCatch(monitora_correcao_contar_operacoes_semanticas(corr), error = function(e) nrow(corr))
  if (exists("monitora_correcao_console_msg", mode = "function", inherits = TRUE)) {
    monitora_correcao_console_msg("Reaplicando correções semânticas anteriores antes do painel: ", n_sem, " operação(ões) semântica(s), arquivo=", arquivo, ".")
  }
  monitora_correcao_gravar_trilha_semantica(corr, arquivo_origem = arquivo, fase = "replay_pre_painel", status = "planejada", contexto = contexto)
  dt2 <- monitora_correcao_aplicar_arquivo(dt, arquivo, dicionario = dicionario)
  MONITORA_CORRECOES_REAPLICADAS_ARQUIVO <<- arquivo
  MONITORA_CORRECOES_REAPLICADAS_N_ITENS <<- nrow(corr)
  MONITORA_CORRECOES_REAPLICADAS_N_OPERACOES_SEMANTICAS <<- n_sem
  MONITORA_CORRECOES_REAPLICADAS_PRE_PAINEL <<- TRUE
  aud <- data.table::data.table(
    data_hora = format(Sys.time(), "%Y-%m-%d %H:%M:%S %z"),
    exec_id = get0("MONITORA_EXEC_ID", ifnotfound = NA_character_, inherits = TRUE),
    contexto = contexto,
    arquivo_reaplicado = arquivo,
    n_itens_auditaveis = nrow(corr),
    n_operacoes_semanticas = n_sem,
    observacao = "Correções anteriores reaplicadas antes dos relatórios pré-painel e antes da abertura do Shiny. O arquivo de sessão atual foi separado para evitar reaplicação duplicada."
  )
  corr_dir <- get0("MONITORA_CORRECOES_DIR", ifnotfound = file.path(get0("MONITORA_OUTPUT_DIR", ifnotfound = "output", inherits = TRUE), "correcoes_campos"), inherits = TRUE)
  log_dir <- get0("MONITORA_LOG_DIR", ifnotfound = "log", inherits = TRUE)
  dir.create(corr_dir, showWarnings = FALSE, recursive = TRUE)
  dir.create(log_dir, showWarnings = FALSE, recursive = TRUE)
  try(monitora_fwrite(aud, file.path(corr_dir, "auditoria_reaplicacao_correcoes_anteriores_ultima_execucao.csv"), na = ""), silent = TRUE)
  try(monitora_fwrite(aud, file.path(log_dir, paste0("auditoria_reaplicacao_correcoes_anteriores_", get0("MONITORA_EXEC_ID", ifnotfound = format(Sys.time(), "%Y%m%d_%H%M%S"), inherits = TRUE), ".csv")), na = ""), silent = TRUE)
  if (exists("monitora_log_registrar_evento", mode = "function", inherits = TRUE)) {
    monitora_log_registrar_evento("reaplicacao_correcoes", "INFO", arquivo, paste0(n_sem, " operação(ões) semântica(s) anteriores reaplicadas antes do painel"), "diagnósticos pré-painel e contadores devem refletir o estado reaplicado")
  }
  dt2[]
}


### v2.6.1 - replay semântico estável e comparação por oráculo ----------------
### O oráculo é somente uma referência de validação. Nenhum arquivo da pasta do
### oráculo é usado como entrada operacional do pipeline. O resultado esperado é
### que o input bruto + correcoes_semanticas.csv reproduza o estado corrigido da
### run-oráculo, ignorando apenas metadados legitimamente dependentes do caminho
### local de execução, como MONITORA_CAMINHO_ARQUIVO_ENTRADA.

monitora_oraculo_fwrite <- function(x, path) {
  dir.create(dirname(path), showWarnings = FALSE, recursive = TRUE)
  if (exists("monitora_fwrite", mode = "function", inherits = TRUE)) {
    monitora_fwrite(x, path, na = "")
  } else {
    data.table::fwrite(x, path, na = "")
  }
  invisible(path)
}

monitora_oraculo_ler_csv <- function(path) {
  if (!nzchar(path) || !file.exists(path)) return(data.table::data.table())
  tryCatch(
    data.table::fread(path, encoding = "UTF-8", na.strings = c("", "NA"), colClasses = "character", showProgress = FALSE),
    error = function(e) data.table::data.table(.erro_leitura = conditionMessage(e), .arquivo = path)
  )
}

monitora_oraculo_dir_resolver <- function() {
  if (!isTRUE(get0("MONITORA_COMPARAR_REPLAY_COM_ORACULO", ifnotfound = FALSE, inherits = TRUE))) return("")
  dir_cfg <- trimws(as.character(get0("MONITORA_DIR_RUN_ORACULO", ifnotfound = "", inherits = TRUE))[1])
  candidatos <- c(
    dir_cfg,
    file.path(get0("MONITORA_INPUT_DIR", ifnotfound = "input", inherits = TRUE), "oraculo_replay"),
    file.path(get0("MONITORA_INPUT_DIR", ifnotfound = "input", inherits = TRUE), "referencia_replay"),
    file.path(get0("MONITORA_INPUT_DIR", ifnotfound = "input", inherits = TRUE), "diagnostico_run_referencia")
  )
  candidatos <- unique(candidatos[nzchar(candidatos)])
  candidatos[file.exists(candidatos) & file.info(candidatos)$isdir][1] %||% ""
}

monitora_oraculo_localizar <- function(subcaminhos) {
  base <- monitora_oraculo_dir_resolver()
  if (!nzchar(base)) return("")
  candidatos <- file.path(base, subcaminhos)
  candidatos <- candidatos[file.exists(candidatos)]
  if (length(candidatos)) normalizePath(candidatos[1], winslash = "/", mustWork = FALSE) else ""
}

monitora_oraculo_key <- function(dt, preferir_uuid = TRUE) {
  if (!is.data.table(dt)) dt <- data.table::as.data.table(dt)
  candidatos <- c("COLETA", "UC", "EA", "UA", "CICLO", "CAMPANHA", "ANO", "Data (data_hora)", "ponto_amostral", "ponto_metro")
  if (isTRUE(preferir_uuid)) candidatos <- c(candidatos, "uuid_registro")
  cols <- candidatos[candidatos %in% names(dt)]
  if (!length(cols)) return(sprintf("linha_%08d", seq_len(nrow(dt))))
  vals <- lapply(cols, function(cc) {
    x <- as.character(dt[[cc]])
    x[is.na(x)] <- ""
    trimws(x)
  })
  do.call(paste, c(vals, sep = "||"))
}

monitora_oraculo_comparar_registros_corrig <- function(dt_atual, fase = "pos_replay_pre_painel") {
  if (!isTRUE(get0("MONITORA_COMPARAR_REPLAY_COM_ORACULO", ifnotfound = FALSE, inherits = TRUE))) return(invisible(NULL))
  arq_ref <- monitora_oraculo_localizar(c(
    "output_01_produtos_dados/registros_corrig.csv",
    "output/01_produtos_dados/registros_corrig.csv",
    "01_produtos_dados/registros_corrig.csv",
    "registros_corrig.csv"
  ))
  out_dir <- file.path(get0("MONITORA_CORRECOES_DIR", ifnotfound = file.path(get0("MONITORA_OUTPUT_DIR", ifnotfound = "output", inherits = TRUE), "02_painel_correcoes"), inherits = TRUE), "diagnostico_oraculo_replay")
  dir.create(out_dir, showWarnings = FALSE, recursive = TRUE)
  exec_id <- get0("MONITORA_EXEC_ID", ifnotfound = format(Sys.time(), "%Y%m%d_%H%M%S"), inherits = TRUE)
  resumo_base <- data.table::data.table(
    data_hora = format(Sys.time(), "%Y-%m-%d %H:%M:%S %z"),
    exec_id = exec_id,
    fase = fase,
    oraculo_dir = monitora_oraculo_dir_resolver(),
    arquivo_oraculo_registros_corrig = arq_ref,
    status = if (nzchar(arq_ref)) "oraculo_encontrado" else "oraculo_nao_encontrado"
  )
  if (!nzchar(arq_ref)) {
    monitora_oraculo_fwrite(resumo_base, file.path(out_dir, paste0("oraculo_registros_corrig_resumo_", fase, ".csv")))
    return(invisible(resumo_base))
  }
  ref <- monitora_oraculo_ler_csv(arq_ref)
  cur <- data.table::as.data.table(data.table::copy(dt_atual))
  for (cc in names(ref)) ref[[cc]] <- as.character(ref[[cc]])
  for (cc in names(cur)) cur[[cc]] <- as.character(cur[[cc]])
  col_ref <- names(ref); col_cur <- names(cur); col_comuns <- intersect(col_ref, col_cur)
  resumo <- data.table::copy(resumo_base)
  resumo[, `:=`(
    n_linhas_oraculo = nrow(ref),
    n_linhas_atual = nrow(cur),
    n_colunas_oraculo = length(col_ref),
    n_colunas_atual = length(col_cur),
    n_colunas_comuns = length(col_comuns),
    n_colunas_so_oraculo = length(setdiff(col_ref, col_cur)),
    n_colunas_so_atual = length(setdiff(col_cur, col_ref))
  )]
  diagnostico_colunas <- data.table::rbindlist(list(
    data.table::data.table(tipo = "coluna_so_oraculo", coluna = setdiff(col_ref, col_cur)),
    data.table::data.table(tipo = "coluna_so_atual", coluna = setdiff(col_cur, col_ref)),
    data.table::data.table(tipo = "coluna_comum", coluna = col_comuns)
  ), fill = TRUE)
  monitora_oraculo_fwrite(diagnostico_colunas, file.path(out_dir, paste0("oraculo_registros_corrig_colunas_", fase, ".csv")))
  key_ref <- monitora_oraculo_key(ref); key_cur <- monitora_oraculo_key(cur)
  ref[, .chave_oraculo_replay := key_ref]
  cur[, .chave_oraculo_replay := key_cur]
  dup_ref <- ref[, .N, by = .chave_oraculo_replay][N > 1]
  dup_cur <- cur[, .N, by = .chave_oraculo_replay][N > 1]
  keys_ref <- unique(ref$.chave_oraculo_replay); keys_cur <- unique(cur$.chave_oraculo_replay)
  somente_ref <- setdiff(keys_ref, keys_cur)
  somente_cur <- setdiff(keys_cur, keys_ref)
  comum <- intersect(keys_ref, keys_cur)
  resumo[, `:=`(
    n_chaves_oraculo = length(keys_ref),
    n_chaves_atual = length(keys_cur),
    n_chaves_comuns = length(comum),
    n_chaves_so_oraculo = length(somente_ref),
    n_chaves_so_atual = length(somente_cur),
    n_chaves_duplicadas_oraculo = nrow(dup_ref),
    n_chaves_duplicadas_atual = nrow(dup_cur)
  )]
  amostra_chaves <- data.table::rbindlist(list(
    data.table::data.table(tipo = "chave_so_oraculo", chave = head(somente_ref, 5000)),
    data.table::data.table(tipo = "chave_so_atual", chave = head(somente_cur, 5000))
  ), fill = TRUE)
  monitora_oraculo_fwrite(amostra_chaves, file.path(out_dir, paste0("oraculo_registros_corrig_chaves_diferentes_", fase, ".csv")))
  cols_ignorar_padrao <- grep("^(linha_|arquivo_|data_hora_auditoria|exec_id$|\\.chave_oraculo_replay$)", col_comuns, value = TRUE)
  cols_ignorar_config <- as.character(get0("MONITORA_ORACULO_COLUNAS_IGNORAR", ifnotfound = character(0), inherits = TRUE))
  cols_ignorar_config <- cols_ignorar_config[!is.na(cols_ignorar_config) & nzchar(cols_ignorar_config)]
  cols_ignorar <- unique(c(cols_ignorar_padrao, intersect(cols_ignorar_config, col_comuns)))
  cols_cmp <- setdiff(col_comuns, cols_ignorar)
  ref_u <- ref[!duplicated(.chave_oraculo_replay) & .chave_oraculo_replay %in% comum]
  cur_u <- cur[!duplicated(.chave_oraculo_replay) & .chave_oraculo_replay %in% comum]
  data.table::setkey(ref_u, .chave_oraculo_replay)
  data.table::setkey(cur_u, .chave_oraculo_replay)
  ref_u <- ref_u[comum]
  cur_u <- cur_u[comum]
  dif_cols <- data.table::data.table()
  dif_cells <- data.table::data.table()
  if (length(cols_cmp) && length(comum)) {
    dif_list <- vector("list", length(cols_cmp))
    names(dif_list) <- cols_cmp
    sample_list <- list(); si <- 0L
    for (cc in cols_cmp) {
      a <- ref_u[[cc]]; b <- cur_u[[cc]]
      a[is.na(a)] <- ""; b[is.na(b)] <- ""
      idx <- which(a != b)
      dif_list[[cc]] <- data.table::data.table(coluna = cc, n_diferencas = length(idx), n_chaves_comparadas = length(comum))
      if (length(idx) && si < 5000L) {
        take <- head(idx, min(length(idx), 5000L - si))
        sample_list[[length(sample_list) + 1L]] <- data.table::data.table(
          chave = ref_u$.chave_oraculo_replay[take], coluna = cc, valor_oraculo = a[take], valor_atual = b[take]
        )
        si <- si + length(take)
      }
    }
    dif_cols <- data.table::rbindlist(dif_list, fill = TRUE)
    dif_cols <- dif_cols[order(-n_diferencas, coluna)]
    dif_cells <- if (length(sample_list)) data.table::rbindlist(sample_list, fill = TRUE) else data.table::data.table()
  }
  resumo[, n_colunas_com_diferencas_valor := if (nrow(dif_cols)) sum(dif_cols$n_diferencas > 0, na.rm = TRUE) else 0L]
  resumo[, n_celulas_diferentes_amostradas := nrow(dif_cells)]
  resumo[, colunas_ignoradas_na_comparacao := paste(cols_ignorar, collapse = " | ")]
  resumo[, status_convergencia := ifelse(
    n_chaves_so_oraculo == 0 & n_chaves_so_atual == 0 & n_colunas_so_oraculo == 0 & n_colunas_so_atual == 0 & n_colunas_com_diferencas_valor == 0,
    "convergente_com_oraculo", "divergente_do_oraculo"
  )]
  resumo[, replay_equivalente_ao_oraculo := ifelse(status_convergencia == "convergente_com_oraculo", "SIM", "NAO")]
  resumo[, interpretacao := ifelse(
    replay_equivalente_ao_oraculo == "SIM",
    "O input bruto somado à trilha semântica reproduziu o registros_corrig da run-oráculo; diferenças de caminho local foram ignoradas quando configuradas.",
    "O replay semântico ainda diverge do oráculo; consultar chaves, colunas e amostras de células divergentes."
  )]
  selo_oraculo <- resumo[, .(
    data_hora, exec_id, fase, replay_equivalente_ao_oraculo, status_convergencia,
    n_linhas_oraculo, n_linhas_atual, n_chaves_so_oraculo, n_chaves_so_atual,
    n_colunas_so_oraculo, n_colunas_so_atual, n_colunas_com_diferencas_valor,
    colunas_ignoradas_na_comparacao, interpretacao
  )]
  monitora_oraculo_fwrite(resumo, file.path(out_dir, paste0("oraculo_registros_corrig_resumo_", fase, ".csv")))
  monitora_oraculo_fwrite(selo_oraculo, file.path(out_dir, paste0("oraculo_replay_selo_convergencia_", fase, ".csv")))
  monitora_oraculo_fwrite(dif_cols, file.path(out_dir, paste0("oraculo_registros_corrig_diferencas_por_coluna_", fase, ".csv")))
  monitora_oraculo_fwrite(dif_cells, file.path(out_dir, paste0("oraculo_registros_corrig_amostra_celulas_diferentes_", fase, ".csv")))
  if (exists("monitora_log_registrar_evento", mode = "function", inherits = TRUE)) {
    nivel <- if (identical(resumo$status_convergencia[1], "convergente_com_oraculo")) "INFO" else "AVISO"
    monitora_log_registrar_evento("oraculo_replay", nivel, file.path(out_dir, paste0("oraculo_registros_corrig_resumo_", fase, ".csv")), paste0("Comparação do registros_corrig pós-replay com oráculo: ", resumo$status_convergencia[1]), "não usa o oráculo como entrada; apenas audita a convergência")
  }
  if (isTRUE(get0("MONITORA_REPLAY_ORACULO_ABORTAR_DIVERGENCIA", ifnotfound = FALSE, inherits = TRUE)) && !identical(resumo$status_convergencia[1], "convergente_com_oraculo")) {
    stop("Replay semântico divergiu do oráculo em registros_corrig. Ver output/02_painel_correcoes/diagnostico_oraculo_replay/.", call. = FALSE)
  }
  invisible(resumo[])
}

monitora_oraculo_resumo_ocorrencias_localizar <- function(fase_oraculo = "pos_painel") {
  nome <- paste0("resumo_ocorrencias_diagnosticas_", fase_oraculo, ".csv")
  monitora_oraculo_localizar(c(
    file.path("output_correcoes_campos", "ocorrencias_diagnosticas", fase_oraculo, nome),
    file.path("output_correcoes_campos", "relatorios_pos_painel", "ocorrencias_diagnosticas", nome),
    file.path("output_correcoes_campos", "relatorios_pos_correcoes", "ocorrencias_diagnosticas", nome),
    file.path("output_02_painel_correcoes", "ocorrencias_diagnosticas", fase_oraculo, nome),
    file.path("output_02_painel_correcoes", "relatorios_pos_painel", "ocorrencias_diagnosticas", nome),
    file.path("output_02_painel_correcoes", "relatorios_pos_correcoes", "ocorrencias_diagnosticas", nome),
    file.path("output/02_painel_correcoes", "ocorrencias_diagnosticas", fase_oraculo, nome),
    file.path("output/02_painel_correcoes", "relatorios_pos_painel", "ocorrencias_diagnosticas", nome),
    file.path("output/02_painel_correcoes", "relatorios_pos_correcoes", "ocorrencias_diagnosticas", nome),
    nome
  ))
}

monitora_oraculo_comparar_resumo_ocorrencias <- function(fase_atual = "pre_painel", fase_oraculo = "pos_painel") {
  if (!isTRUE(get0("MONITORA_COMPARAR_REPLAY_COM_ORACULO", ifnotfound = FALSE, inherits = TRUE))) return(invisible(NULL))
  out_dir <- file.path(get0("MONITORA_CORRECOES_DIR", ifnotfound = file.path(get0("MONITORA_OUTPUT_DIR", ifnotfound = "output", inherits = TRUE), "02_painel_correcoes"), inherits = TRUE), "diagnostico_oraculo_replay")
  dir.create(out_dir, showWarnings = FALSE, recursive = TRUE)
  arq_ref <- monitora_oraculo_resumo_ocorrencias_localizar(fase_oraculo)
  nome_atual <- paste0("resumo_ocorrencias_diagnosticas_", fase_atual, ".csv")
  candidatos_atual <- c(
    file.path(get0("MONITORA_CORRECOES_DIR", ifnotfound = "output/02_painel_correcoes", inherits = TRUE), "ocorrencias_diagnosticas", fase_atual, nome_atual),
    file.path(get0("MONITORA_CORRECOES_DIR", ifnotfound = "output/02_painel_correcoes", inherits = TRUE), "relatorios_pre_painel", "ocorrencias_diagnosticas", nome_atual),
    file.path(get0("MONITORA_OUTPUT_DIR", ifnotfound = "output", inherits = TRUE), "02_painel_correcoes", "ocorrencias_diagnosticas", fase_atual, nome_atual),
    file.path(get0("MONITORA_OUTPUT_DIR", ifnotfound = "output", inherits = TRUE), "02_painel_correcoes", "relatorios_pre_painel", "ocorrencias_diagnosticas", nome_atual)
  )
  arq_atual <- candidatos_atual[file.exists(candidatos_atual)][1] %||% ""
  resumo <- data.table::data.table(
    data_hora = format(Sys.time(), "%Y-%m-%d %H:%M:%S %z"),
    exec_id = get0("MONITORA_EXEC_ID", ifnotfound = NA_character_, inherits = TRUE),
    fase_atual = fase_atual,
    fase_oraculo = fase_oraculo,
    arquivo_atual = arq_atual,
    arquivo_oraculo = arq_ref,
    status = if (nzchar(arq_atual) && nzchar(arq_ref)) "arquivos_encontrados" else "arquivo_ausente"
  )
  if (!nzchar(arq_atual) || !nzchar(arq_ref)) {
    monitora_oraculo_fwrite(resumo, file.path(out_dir, paste0("oraculo_ocorrencias_resumo_", fase_atual, "_vs_", fase_oraculo, ".csv")))
    return(invisible(resumo))
  }
  atual <- monitora_oraculo_ler_csv(arq_atual)
  ref <- monitora_oraculo_ler_csv(arq_ref)
  key <- intersect(c("tipo_ocorrencia", "rotulo_ocorrencia", "severidade"), intersect(names(atual), names(ref)))
  if (!length(key)) key <- intersect(names(atual), names(ref))[1]
  for (cc in names(atual)) atual[[cc]] <- as.character(atual[[cc]])
  for (cc in names(ref)) ref[[cc]] <- as.character(ref[[cc]])
  atual[, .origem_comparacao := "atual"]
  ref[, .origem_comparacao := "oraculo"]
  cmp <- merge(
    ref[, c(key, intersect(c("n_linhas", "n_coletas"), names(ref))), with = FALSE],
    atual[, c(key, intersect(c("n_linhas", "n_coletas"), names(atual))), with = FALSE],
    by = key, all = TRUE, suffixes = c("_oraculo", "_atual")
  )
  for (cc in grep("^n_(linhas|coletas)_", names(cmp), value = TRUE)) cmp[[cc]] <- suppressWarnings(as.integer(cmp[[cc]]))
  if (all(c("n_linhas_oraculo", "n_linhas_atual") %in% names(cmp))) cmp[, dif_n_linhas := n_linhas_atual - n_linhas_oraculo]
  if (all(c("n_coletas_oraculo", "n_coletas_atual") %in% names(cmp))) cmp[, dif_n_coletas := n_coletas_atual - n_coletas_oraculo]
  cmp[, status_convergencia := ifelse((is.na(dif_n_linhas) | dif_n_linhas == 0) & (is.na(dif_n_coletas) | dif_n_coletas == 0), "convergente", "divergente")]
  resumo[, `:=`(
    n_ocorrencias_comparadas = nrow(cmp),
    n_ocorrencias_divergentes = sum(cmp$status_convergencia == "divergente", na.rm = TRUE),
    status_convergencia = ifelse(sum(cmp$status_convergencia == "divergente", na.rm = TRUE) == 0, "convergente_com_oraculo", "divergente_do_oraculo")
  )]
  resumo[, ocorrencias_equivalentes_ao_oraculo := ifelse(status_convergencia == "convergente_com_oraculo", "SIM", "NAO")]
  resumo[, interpretacao := ifelse(
    ocorrencias_equivalentes_ao_oraculo == "SIM",
    "As ocorrências diagnósticas da nova run, após replay, convergiram com a fase comparada da run-oráculo.",
    "Há diferenças entre ocorrências diagnósticas da nova run e da run-oráculo; consultar comparativo por tipo."
  )]
  arq_cmp <- file.path(out_dir, paste0("oraculo_ocorrencias_comparativo_", fase_atual, "_vs_", fase_oraculo, ".csv"))
  arq_res <- file.path(out_dir, paste0("oraculo_ocorrencias_resumo_", fase_atual, "_vs_", fase_oraculo, ".csv"))
  arq_selo <- file.path(out_dir, paste0("oraculo_ocorrencias_selo_convergencia_", fase_atual, "_vs_", fase_oraculo, ".csv"))
  monitora_oraculo_fwrite(cmp, arq_cmp)
  monitora_oraculo_fwrite(resumo, arq_res)
  monitora_oraculo_fwrite(resumo[, .(data_hora, exec_id, fase_atual, fase_oraculo, ocorrencias_equivalentes_ao_oraculo, status_convergencia, n_ocorrencias_comparadas, n_ocorrencias_divergentes, interpretacao)], arq_selo)
  if (exists("monitora_log_registrar_evento", mode = "function", inherits = TRUE)) {
    nivel <- if (identical(resumo$status_convergencia[1], "convergente_com_oraculo")) "INFO" else "AVISO"
    monitora_log_registrar_evento("oraculo_replay_ocorrencias", nivel, arq_res, paste0("Comparação de ocorrências diagnósticas: ", resumo$status_convergencia[1]), "esperado: pre_painel pós-replay igual ao pos_painel da run-oráculo")
  }
  invisible(resumo[])
}


monitora_correcao_corrigir_ponto_metro <- function(dt) {
  if (!isTRUE(MONITORA_CORRIGIR_PONTO_METRO_AUTOMATICO)) return(dt)
  dt <- monitora_dt_referenciar(dt)
  chaves <- monitora_correcao_colunas_chave(dt)
  if (is.na(chaves$ponto_amostral) || is.na(chaves$ponto_metro)) return(dt)
  if (!(chaves$ponto_amostral %in% names(dt)) || !(chaves$ponto_metro %in% names(dt))) return(dt)
  ponto <- suppressWarnings(as.numeric(gsub(",", ".", as.character(dt[[chaves$ponto_amostral]]))))
  metro_atual <- suppressWarnings(as.numeric(gsub(",", ".", as.character(dt[[chaves$ponto_metro]]))))
  metro_esperado <- (ponto - 1) / 2
  corrigir <- !is.na(ponto) & ponto >= 1 & ponto <= 101 & !is.na(metro_atual) & abs(metro_atual - metro_esperado) > 1e-9
  if (any(corrigir)) {
    aud <- data.table::data.table(
      linha_indice = which(corrigir),
      ponto_amostral = as.character(dt[[chaves$ponto_amostral]][corrigir]),
      ponto_metro_antes = as.character(dt[[chaves$ponto_metro]][corrigir]),
      ponto_metro_depois = as.character(metro_esperado[corrigir])
    )
    monitora_fwrite(aud, file.path(MONITORA_LOG_DIR, paste0("auditoria_correcao_ponto_metro_", MONITORA_EXEC_ID, ".csv")), na = "")
    data.table::set(dt, i = which(corrigir), j = chaves$ponto_metro, value = as.character(metro_esperado[corrigir]))
    monitora_log_registrar_evento("correcao_ponto_metro", "AVISO", NA_character_, paste0(sum(corrigir), " valor(es) de ponto_metro corrigidos por ponto_amostral"), "ver auditoria_correcao_ponto_metro")
  } else {
    monitora_log_registrar_evento("correcao_ponto_metro", "INFO", NA_character_, "Nenhuma inconformidade detectada", "ponto_metro validado por ponto_amostral")
  }
  dt[]
}

monitora_correcao_validar_dependencias <- function(dt, deps, dicionario = NULL) {
  if (!isTRUE(MONITORA_VALIDAR_CONDICIONAIS_CORRECOES)) return(data.table::data.table())
  if (is.null(deps) || nrow(deps) == 0) return(data.table::data.table())
  dt <- data.table::as.data.table(dt)

  deps_dt <- data.table::as.data.table(deps)
  regras_brutas <- deps_dt[!is.na(parent_name) & nzchar(parent_name) & !is.na(token) & nzchar(token) & !is.na(dependent_name) & nzchar(dependent_name)]
  n_regras_brutas <- nrow(regras_brutas)
  regras_unicas <- unique(regras_brutas, by = c("parent_name", "token", "dependent_name", "fonte"))
  n_regras_unicas <- nrow(regras_unicas)
  if (n_regras_brutas > 0L) {
    monitora_fwrite(regras_brutas, file.path(MONITORA_LOG_DIR, paste0("auditoria_dependencias_condicionais_regras_brutas_", MONITORA_EXEC_ID, ".csv")), na = "")
    monitora_fwrite(regras_brutas, file.path(MONITORA_CORRECOES_DIR, "auditoria_dependencias_condicionais_regras_brutas_ultima_execucao.csv"), na = "")
    monitora_fwrite(regras_unicas, file.path(MONITORA_LOG_DIR, paste0("auditoria_dependencias_condicionais_regras_unicas_", MONITORA_EXEC_ID, ".csv")), na = "")
    monitora_fwrite(regras_unicas, file.path(MONITORA_CORRECOES_DIR, "auditoria_dependencias_condicionais_regras_unicas_ultima_execucao.csv"), na = "")
  }

  regras_todas <- monitora_correcao_resolver_dependencias(dt, deps, dicionario, incluir_bloqueadas = TRUE)
  if (nrow(regras_todas) > 0L) {
    arq_regras <- file.path(MONITORA_LOG_DIR, paste0("auditoria_dependencias_condicionais_regras_resolvidas_", MONITORA_EXEC_ID, ".csv"))
    monitora_fwrite(regras_todas, arq_regras, na = "")
    monitora_fwrite(regras_todas, file.path(MONITORA_CORRECOES_DIR, "auditoria_dependencias_condicionais_regras_resolvidas_ultima_execucao.csv"), na = "")
  }
  regras <- regras_todas[status_regra == "ok"]
  n_deps <- nrow(regras)
  n_ignoradas <- nrow(regras_todas[status_regra != "ok"])
  monitora_correcao_console_msg(
    "Iniciando validação de dependências condicionais: ",
    n_regras_brutas, " regra(s) bruta(s) extraída(s) do(s) XLSForm(s); ",
    n_regras_unicas, " regra(s) única(s) por parent/token/dependent/fonte; ",
    nrow(regras_todas), " regra(s) resolvida(s)/classificada(s); ",
    n_deps, " regra(s) validadas linha-a-linha; ",
    n_ignoradas, " regra(s) documentadas mas ignoradas/bloqueadas/sem coluna resolvida."
  )
  if (n_deps == 0L) {
    monitora_log_registrar_evento(
      "dependencias_condicionais", "INFO", NA_character_,
      paste0("Nenhuma regra condicional acionável para validação linha-a-linha; regras_brutas=", n_regras_brutas, "; regras_unicas=", n_regras_unicas, "; regras_resolvidas=", nrow(regras_todas)),
      "OK; consultar auditoria_dependencias_condicionais_regras_resolvidas_* para universo completo"
    )
    return(data.table::data.table())
  }

  out <- vector("list", n_deps)
  parent_cache <- new.env(parent = emptyenv())
  vazio_cache <- new.env(parent = emptyenv())

  for (ii in seq_len(n_deps)) {
    if (ii == 1L || ii == n_deps || ii %% 25L == 0L) {
      monitora_correcao_console_msg("Validação de dependências condicionais: regra ", ii, "/", n_deps, ".")
    }

    parent_col <- regras$parent_col[ii]
    dep_col <- regras$dependent_col[ii]
    token <- regras$token[ii]
    if (is.na(parent_col) || is.na(dep_col) || !(parent_col %in% names(dt)) || !(dep_col %in% names(dt))) next
    if (monitora_correcao_coluna_protegida(parent_col) || monitora_correcao_coluna_protegida(dep_col)) next

    chave_parent <- paste(parent_col, token, sep = "\r")
    if (exists(chave_parent, envir = parent_cache, inherits = FALSE)) {
      ativo <- get(chave_parent, envir = parent_cache, inherits = FALSE)
    } else {
      ativo <- monitora_correcao_token_presente_vec(dt[[parent_col]], token)
      assign(chave_parent, ativo, envir = parent_cache)
    }

    if (exists(dep_col, envir = vazio_cache, inherits = FALSE)) {
      vazio_dep <- get(dep_col, envir = vazio_cache, inherits = FALSE)
    } else {
      vazio_dep <- monitora_correcao_vazio_vec(dt[[dep_col]])
      assign(dep_col, vazio_dep, envir = vazio_cache)
    }

    falha <- which(ativo & vazio_dep)
    if (length(falha) > 0) {
      out[[ii]] <- data.table::data.table(
        parent_col = parent_col,
        token = token,
        dependent_col = dep_col,
        severidade = regras$severidade[ii],
        n_falhas = length(falha),
        linhas_exemplo = paste(utils::head(falha, 20), collapse = ";"),
        fonte = regras$fonte[ii]
      )
    }
  }

  out <- out[!vapply(out, is.null, logical(1))]
  res <- if (length(out) > 0) data.table::rbindlist(out, fill = TRUE, use.names = TRUE) else data.table::data.table()
  if (nrow(res) > 0) {
    res <- unique(res, by = c("parent_col", "token", "dependent_col"))
    data.table::setorderv(res, c("severidade", "parent_col", "token", "dependent_col"))
    arq <- file.path(MONITORA_LOG_DIR, paste0("auditoria_dependencias_condicionais_", MONITORA_EXEC_ID, ".csv"))
    monitora_fwrite(res, arq, na = "")
    n_crit <- sum(res$severidade == "critica_forma_vida", na.rm = TRUE)
    nivel <- if (n_crit > 0L) "AVISO" else "INFO"
    monitora_log_registrar_evento(
      "dependencias_condicionais", nivel, arq,
      paste0(
        nrow(res), " regra(s) com pendências condicionais consolidadas; críticas=", n_crit,
        "; informativas=", nrow(res) - n_crit,
        "; regras_brutas_xlsform=", n_regras_brutas,
        "; regras_unicas_xlsform=", n_regras_unicas,
        "; regras_resolvidas=", nrow(regras_todas),
        "; regras_validadas_linha_a_linha=", n_deps,
        "; regras_documentadas_nao_validadas=", n_ignoradas
      ),
      "corrigir críticas antes de validar; consultar auditoria_dependencias_condicionais_regras_resolvidas_* para universo completo"
    )
  } else {
    monitora_log_registrar_evento("dependencias_condicionais", "INFO", NA_character_, "Nenhuma pendência condicional detectada nas regras mapeadas", "OK")
  }
  monitora_correcao_console_msg("Validação de dependências condicionais concluída: ", nrow(res), " pendência(s) consolidada(s).")
  res
}

monitora_correcao_resumo_coleta <- function(dt, coleta_valor, chaves = monitora_correcao_colunas_chave(dt)) {
  if (is.na(chaves$coleta) || !(chaves$coleta %in% names(dt))) return(data.table::data.table())
  dt[as.character(get(chaves$coleta)) == as.character(coleta_valor)]
}

