monitora_correcao_limpar_cache_mapa_colunas_publicacao_b <- function() {
  cache_env <- tryCatch(get(".MONITORA_MAPA_COLUNAS_CANONICAS_CACHE", inherits = TRUE), error = function(e) NULL)
