### publicação: contrato global do seletor de atributos do painel.
### A lista de atributos editáveis do bolsista não deve depender da COLETA,
### do ponto selecionado nem de valores já preenchidos. Ela deve refletir o
### template SISMONITORA/XLSForm 2025 usado como contrato de atributos, criando
### colunas vazias em registros_corrig quando um atributo contratual opcional
### ainda não apareceu nos dados da execução.
monitora_correcao_attrs_template_sismonitora_editaveis <- function(meta_xls = NULL) {
  if (!requireNamespace("data.table", quietly = TRUE)) stop("Pacote data.table é obrigatório.", call. = FALSE)
  if (!exists("monitora_validados_schema_embutido", mode = "function")) return(data.table::data.table())
  schema <- tryCatch(monitora_validados_schema_embutido(), error = function(e) NULL)
  if (is.null(schema)) return(data.table::data.table())
  schema <- data.table::as.data.table(schema)
  if (!nrow(schema) || !("atributo" %in% names(schema))) return(data.table::data.table())

  meta <- tryCatch(monitora_correcao_xlsform_meta_atual(meta_xls), error = function(e) NULL)
  campos <- if (!is.null(meta) && !is.null(meta$campos)) data.table::as.data.table(meta$campos) else data.table::data.table()
  if (nrow(campos)) {
    for (cc in c("name", "type", "label", "caminho_registro", "list_name", "arquivo_xlsform")) {
      if (!(cc %in% names(campos))) data.table::set(campos, j = cc, value = NA_character_)
    }
    campos[, name_chr := as.character(name)]
    campos[, type_chr := as.character(type)]
    campos[, label_chr := as.character(label)]
    campos[, caminho_chr := as.character(caminho_registro)]
    arq_atual <- tryCatch(monitora_correcao_ultima_versao_xlsform(campos), error = function(e) NA_character_)
    if (!is.na(arq_atual) && nzchar(arq_atual) && "arquivo_xlsform" %in% names(campos)) {
      campos_atual <- campos[arquivo_xlsform == arq_atual]
      if (nrow(campos_atual)) campos <- campos_atual
    }
  }

  out <- data.table::copy(schema[, .(posicao, atributo, formato, obrigatorio_valor, nivel)])
  out[, atributo := as.character(atributo)]
  out <- out[!is.na(atributo) & nzchar(trimws(atributo))]
  if (!nrow(out)) return(out)
  out[, atributo_final := sub("^.*/", "", atributo)]
  out[, xlsform_name := NA_character_]
  out[, xlsform_label := NA_character_]
  out[, xlsform_tipo := NA_character_]
  out[, xlsform_tipo_base := NA_character_]
  out[, xlsform_list_name := NA_character_]

  if (nrow(campos)) {
    for (ii in seq_len(nrow(out))) {
      att <- out$atributo[ii]
      att_final <- out$atributo_final[ii]
      hit <- campos[caminho_chr == att | name_chr == att | name_chr == att_final]
      if (!nrow(hit)) {
        hit <- campos[grepl(paste0("(^|/)", gsub("([][{}()+*^$|\\\\?.])", "\\\\\\1", att_final, perl = TRUE), "$"), caminho_chr, ignore.case = TRUE)]
      }
      if (nrow(hit)) {
        tipo_hit <- monitora_correcao_tipo_xlsform(hit$type_chr[1L])
        data.table::set(out, i = ii, j = "xlsform_name", value = hit$name_chr[1L])
        data.table::set(out, i = ii, j = "xlsform_label", value = hit$label_chr[1L])
        data.table::set(out, i = ii, j = "xlsform_tipo", value = hit$type_chr[1L])
        data.table::set(out, i = ii, j = "xlsform_tipo_base", value = tipo_hit$tipo_base[1L])
        data.table::set(out, i = ii, j = "xlsform_list_name", value = tipo_hit$list_name[1L])
      }
    }
  }

  out[is.na(xlsform_tipo_base) | !nzchar(xlsform_tipo_base), xlsform_tipo_base := data.table::fifelse(
    grepl("uuid", atributo, ignore.case = TRUE), "uuid",
    data.table::fifelse(grepl("foto|imagem|image", atributo, ignore.case = TRUE), "file", "text")
  )]
  tipos_bloqueados <- c(
    "calculate", "hidden", "start", "end", "deviceid", "phonenumber",
    "barcode", "acknowledge", "rank", "range", "file", "image", "audio", "video"
  )
  out[, protegido_template := monitora_correcao_coluna_protegida(atributo) | monitora_correcao_coluna_protegida(atributo_final) |
        grepl("(^|/)uuid$|foto|imagem|image", atributo, ignore.case = TRUE)]
  out <- out[protegido_template != TRUE & !(tolower(xlsform_tipo_base) %in% tipos_bloqueados)]
  out[]
}

monitora_correcao_preparar_schema_edicao_painel <- function(dt, meta_xls = NULL, contexto = "pre_painel") {
  if (is.null(dt)) return(data.table::data.table())
  if (!data.table::is.data.table(dt)) data.table::setDT(dt)

  meta <- monitora_correcao_xlsform_meta_atual(meta_xls)
  campos <- if (!is.null(meta$campos)) data.table::as.data.table(meta$campos) else data.table::data.table()
  deps <- tryCatch(
    monitora_correcao_unificar_dependencias(if (!is.null(meta$dependencias)) meta$dependencias else data.table::data.table()),
    error = function(e) data.table::data.table()
  )

  formas_cond <- c("bromelioide", "cactacea", "orquidea", "samambaia")
  categorias <- c("nativa", "exotica", "seca_morta")
  nomes_padrao <- as.vector(outer(paste0("forma_vida_", categorias, "_"), formas_cond, paste0))

  cols_meta <- character(0)
  if (nrow(campos)) {
    for (cc in c("name", "type", "tipo_base", "list_name", "required", "arquivo_xlsform")) {
      if (!(cc %in% names(campos))) data.table::set(campos, j = cc, value = NA_character_)
    }
    campos[, name_chr := as.character(name)]
    campos[, type_chr := tolower(trimws(as.character(type)))]
    campos[, list_chr := as.character(list_name)]
    arq_atual <- tryCatch(monitora_correcao_ultima_versao_xlsform(campos), error = function(e) NA_character_)
    campos_alvo <- campos[name_chr %in% nomes_padrao | list_chr %in% nomes_padrao]
    if (!is.na(arq_atual) && nzchar(arq_atual)) {
      campos_atual <- campos_alvo[arquivo_xlsform == arq_atual]
      if (nrow(campos_atual)) campos_alvo <- campos_atual
    }
    cols_meta <- unique(campos_alvo[grepl("select_one|text", type_chr), name_chr])
  }

  cols_deps <- character(0)
  if (nrow(deps)) {
    for (cc in c("parent_name", "token", "dependent_name")) if (!(cc %in% names(deps))) data.table::set(deps, j = cc, value = NA_character_)
    deps[, dependent_chr := as.character(dependent_name)]
    deps[, dependent_norm := monitora_correcao_normalizar_nome_coluna(dependent_chr)]
    deps[, token_norm := monitora_correcao_limpar_texto(token)]
    cols_deps <- unique(deps[token_norm %in% formas_cond & grepl("^forma_vida_(nativa|exotica|seca_morta)_(bromelioide|cactacea|orquidea|samambaia)$", dependent_norm), dependent_chr])
  }

  cols_template <- character(0)
  if (exists("monitora_correcao_attrs_template_sismonitora_editaveis", mode = "function") &&
      exists("monitora_validados_resolver_coluna", mode = "function")) {
    attrs_template <- tryCatch(monitora_correcao_attrs_template_sismonitora_editaveis(meta_xls), error = function(e) data.table::data.table())
    if (nrow(attrs_template) && "atributo" %in% names(attrs_template)) {
      nms_atuais <- names(dt)
      cols_template <- vapply(as.character(attrs_template$atributo), function(att) {
        col_existente <- tryCatch(monitora_validados_resolver_coluna(nms_atuais, att), error = function(e) NA_character_)
        if (!is.na(col_existente) && nzchar(col_existente) && col_existente %in% nms_atuais) return(NA_character_)
        att
      }, character(1), USE.NAMES = FALSE)
      ### publicação: garantia explícita dos campos de material botânico e outras formas
      ### atuais do XLSForm 2025. Eles devem existir no painel mesmo que a execução
      ### atual não tenha valores preenchidos nem coluna herdada do CSV bruto.
      cols_template <- unique(c(
        cols_template,
        "amostragem/registro/forma_serrapilheira",
        "amostragem/registro/forma_vida_outros",
        if (exists("monitora_painel_admin_controlados_sismonitora_2025", mode = "function"))
          as.character(monitora_painel_admin_controlados_sismonitora_2025()$atributo_coluna_registros_corrig)
        else character(0)
      ))
      cols_template <- cols_template[!is.na(cols_template) & nzchar(cols_template)]
    }
  }

  cols_criar <- unique(c(cols_meta, cols_deps, nomes_padrao, cols_template))
  cols_criar <- cols_criar[!is.na(cols_criar) & nzchar(trimws(cols_criar))]
  cols_criar <- cols_criar[!monitora_correcao_coluna_protegida(cols_criar)]
  cols_criar <- cols_criar[!cols_criar %in% names(dt)]

  if (length(cols_criar)) {
    data.table::setalloccol(dt, ncol(dt) + length(cols_criar) + 16L)
    for (cc in cols_criar) data.table::set(dt, j = cc, value = NA_character_)
    monitora_correcao_limpar_cache_mapa_colunas_publicacao_b()
  }

  cols_cond <- intersect(unique(c(cols_meta, cols_deps, nomes_padrao)), names(dt))
  for (cc in cols_cond) {
    if (!is.character(dt[[cc]])) data.table::set(dt, j = cc, value = as.character(dt[[cc]]))
  }

  aud <- data.table::data.table(
    contexto = as.character(contexto),
    coluna = cols_criar,
    status = if (length(cols_criar)) "criada_pre_painel" else character(),
    tipo = if (length(cols_criar)) "character" else character(),
    origem = if (length(cols_criar)) ifelse(cols_criar %in% cols_template, "template_sismonitora_xlsform_2025", "v2.5.4") else character(),
    timestamp = if (length(cols_criar)) format(Sys.time(), "%Y-%m-%d %H:%M:%S") else character()
  )
  arq <- file.path(monitora_publicacao_b_correcoes_dir(), "auditoria_schema_pre_painel_colunas_criadas.csv")
  dir.create(dirname(arq), recursive = TRUE, showWarnings = FALSE)
  if (nrow(aud)) {
    try({
      ant <- if (file.exists(arq)) data.table::fread(arq, encoding = "UTF-8", showProgress = FALSE) else data.table::data.table()
      monitora_fwrite(data.table::rbindlist(list(ant, aud), fill = TRUE, use.names = TRUE), arq, na = "")
    }, silent = TRUE)
    if (exists("monitora_log_registrar_evento", mode = "function")) {
      monitora_log_registrar_evento(
        "schema_pre_painel", "INFO", arq,
        paste0(length(cols_criar), " coluna(s) condicional(is) criada(s) antes da edição/aplicação"),
        "schema preparado por referência com data.table::set"
      )
    }
  }
  dt[]
}

monitora_registros_importados_garantir_pre_painel <- function(dt, contexto = "pre_painel") {
  ativo <- isTRUE(get0("MONITORA_GERAR_REGISTROS_IMPORTADOS_PRE_PAINEL", ifnotfound = FALSE, inherits = TRUE)) ||
    isTRUE(get0("MONITORA_ABRIR_PAINEL_CORRECOES", ifnotfound = FALSE, inherits = TRUE))
  if (!isTRUE(ativo)) return(invisible(FALSE))

  output_dir <- monitora_publicacao_b_output_dir()
  log_dir <- monitora_publicacao_b_log_dir()
  exec_id <- monitora_publicacao_b_exec_id()
  dir.create(output_dir, recursive = TRUE, showWarnings = FALSE)
  dir.create(log_dir, recursive = TRUE, showWarnings = FALSE)
  caminho_canonico <- if (exists("monitora_produtos_path_canonico", mode = "function")) {
    monitora_produtos_path_canonico("registros_importados.csv", output_dir)
  } else file.path(output_dir, "01_produtos_dados", "registros_importados.csv")
  caminho_bruto_canonico <- if (exists("monitora_produtos_path_canonico", mode = "function")) {
    monitora_produtos_path_canonico("registros_importados_bruto.csv", output_dir)
  } else file.path(output_dir, "01_produtos_dados", "registros_importados_bruto.csv")
  caminho_legado <- file.path(output_dir, "registros_importados.csv")
  caminho_bruto_legado <- file.path(output_dir, "registros_importados_bruto.csv")
  caminho <- caminho_canonico
  caminho_bruto <- caminho_bruto_canonico
  if ((!file.exists(caminho) || !isTRUE(file.info(caminho)$size > 0)) && file.exists(caminho_legado)) caminho <- caminho_legado
  if ((!file.exists(caminho_bruto) || !isTRUE(file.info(caminho_bruto)$size > 0)) && file.exists(caminho_bruto_legado)) caminho_bruto <- caminho_bruto_legado

  if (file.exists(caminho) && isTRUE(file.info(caminho)$size > 0)) {
    if (exists("monitora_log_registrar_evento", mode = "function")) {
      monitora_log_registrar_evento("registros_importados_pre_painel", "INFO", caminho, "registros_importados.csv saneado já existia antes do painel no destino canônico/compatível", contexto)
    }
    return(invisible(TRUE))
  }

  ### publicação: neste ponto não reconstruir o produto saneado se ele estiver ausente,
  ### pois o objeto já pode ter sofrido transformações adicionais. A ausência não
  ### bloqueia o painel, mas é registrada para auditoria.
  msg <- paste0(
    "registros_importados.csv saneado ausente antes do painel. O arquivo deveria ter sido ",
    "materializado após consolidação inicial de colunas/aliases e antes do painel. O painel ",
    "não será bloqueado, mas esta execução deve ser auditada porque o produto de comparação ",
    "não foi entregue. Produto bruto esperado em: ", basename(caminho_bruto), "."
  )
  warning(msg, call. = FALSE)
  if (exists("monitora_log_registrar_evento", mode = "function")) {
    monitora_log_registrar_evento("registros_importados_pre_painel_ausente", "WARN", caminho, msg, contexto)
  }
  invisible(FALSE)
}
### FIM v2.6.1 ----------------------------------------------





### Auditoria/quarentena pré-painel de completude de 101 pontos ---------------
### COLETAS incompletas não são corrigíveis no painel: o bolsista não pode
### criar pontos amostrais ausentes com todos os atributos. A rotina abaixo roda
### antes do painel, gera relatórios específicos e remove essas COLETAS do
### universo editável. Se a incompletude for erro de importação/tokenização, a
### correção deve ser no script/processamento; se existir na fonte, a COLETA deve
### permanecer quarentenada ou ser excluída em fluxo próprio.
monitora_pre_painel_quarentenar_coletas_incompletas <- function(dt,
                                                               output_dir = get0("MONITORA_OUTPUT_DIR", ifnotfound = "output", inherits = TRUE),
                                                               log_dir = get0("MONITORA_LOG_DIR", ifnotfound = "log", inherits = TRUE),
                                                               exec_id = get0("MONITORA_EXEC_ID", ifnotfound = format(Sys.time(), "%Y%m%d_%H%M%S"), inherits = TRUE),
                                                               contexto = "pre_painel") {
  if (!requireNamespace("data.table", quietly = TRUE)) return(list(dt = dt, auditoria = data.frame(), quarentenadas = character(0)))
  d <- data.table::as.data.table(dt)
  n <- nrow(d)
  dir_comp <- file.path(output_dir, "03_auditorias", "completude")
  dir_painel <- file.path(output_dir, "correcoes_campos", "relatorios_pre_painel", "completude")
  dir.create(dir_comp, recursive = TRUE, showWarnings = FALSE)
  dir.create(dir_painel, recursive = TRUE, showWarnings = FALSE)
  dir.create(log_dir, recursive = TRUE, showWarnings = FALSE)
  fw <- function(x, file) {
    x <- data.table::as.data.table(x)
    dir.create(dirname(file), recursive = TRUE, showWarnings = FALSE)
    data.table::fwrite(x, file, na = "")
    invisible(file)
  }
  empty_aud <- data.table::data.table(
    contexto = character(), COLETA = character(), UC = character(), EA = character(), UA = character(), CICLO = character(), CAMPANHA = character(), ANO = character(),
    n_linhas = integer(), n_pontos_validos = integer(), n_pontos_distintos = integer(), n_pontos_duplicados = integer(), n_pontos_fora_1_101 = integer(),
    pontos_ausentes = character(), pontos_duplicados = character(), pontos_fora_exemplo = character(), completa_101 = logical(), acao_recomendada = character()
  )
  if (!n) return(list(dt = d, auditoria = empty_aud, quarentenadas = character(0)))
  ch <- tryCatch(monitora_correcao_colunas_chave(d), error = function(e) list())
  col_ok <- function(col) !is.null(col) && length(col) && !is.na(as.character(col)[1L]) && nzchar(as.character(col)[1L]) && as.character(col)[1L] %in% names(d)
  if (!col_ok(ch$coleta) || !col_ok(ch$ponto_amostral)) {
    aud <- empty_aud
    fw(aud, file.path(dir_comp, "auditoria_completude_101_pontos_por_coleta_pre_painel.csv"))
    fw(aud, file.path(dir_painel, "auditoria_completude_101_pontos_por_coleta_pre_painel.csv"))
    return(list(dt = d, auditoria = aud, quarentenadas = character(0)))
  }
  getv <- function(nm) {
    cc <- ch[[nm]]
    if (col_ok(cc)) as.character(d[[as.character(cc)[1L]]]) else rep(NA_character_, n)
  }
  ponto_chr <- as.character(d[[as.character(ch$ponto_amostral)[1L]]])
  ponto_num <- suppressWarnings(as.integer(gsub(",", ".", ponto_chr)))
  aux <- data.table::data.table(
    linha_indice = seq_len(n),
    COLETA = as.character(d[[as.character(ch$coleta)[1L]]]),
    UC = getv("uc"), EA = getv("ea"), UA = getv("ua"), CICLO = getv("ciclo"), CAMPANHA = getv("campanha"), ANO = getv("ano"),
    ponto = ponto_num, ponto_original = ponto_chr
  )
  aux <- aux[!is.na(COLETA) & nzchar(COLETA)]
  if (!nrow(aux)) {
    fw(empty_aud, file.path(dir_comp, "auditoria_completude_101_pontos_por_coleta_pre_painel.csv"))
    fw(empty_aud, file.path(dir_painel, "auditoria_completude_101_pontos_por_coleta_pre_painel.csv"))
    return(list(dt = d, auditoria = empty_aud, quarentenadas = character(0)))
  }
  by_cols <- c("COLETA", "UC", "EA", "UA", "CICLO", "CAMPANHA", "ANO")
  aud <- aux[, {
    p_valid <- ponto[!is.na(ponto) & ponto >= 1L & ponto <= 101L]
    tab <- table(p_valid)
    dup <- as.integer(names(tab)[tab > 1L])
    miss <- setdiff(1:101, sort(unique(p_valid)))
    fora <- ponto_original[is.na(ponto) | ponto < 1L | ponto > 101L]
    data.table::data.table(
      n_linhas = .N,
      n_pontos_validos = length(p_valid),
      n_pontos_distintos = data.table::uniqueN(p_valid),
      n_pontos_duplicados = length(dup),
      n_pontos_fora_1_101 = length(fora),
      pontos_ausentes = paste(miss, collapse = " | "),
      pontos_duplicados = paste(sort(dup), collapse = " | "),
      pontos_fora_exemplo = paste(utils::head(unique(fora), 20L), collapse = " | ")
    )
  }, by = by_cols]
  aud[, contexto := contexto]
  aud[, completa_101 := n_linhas == 101L & n_pontos_distintos == 101L & n_pontos_duplicados == 0L & n_pontos_fora_1_101 == 0L]
  aud[, acao_recomendada := ifelse(completa_101,
    "COLETA atende à completude de 101 pontos e pode entrar no painel.",
    "COLETA não atende à completude de 101 pontos. Não é corrigível por criação manual de ponto no painel; investigar importação/tokenização ou manter/excluir a COLETA em fluxo próprio."
  )]
  data.table::setcolorder(aud, c("contexto", by_cols, "n_linhas", "n_pontos_validos", "n_pontos_distintos", "n_pontos_duplicados", "n_pontos_fora_1_101", "pontos_ausentes", "pontos_duplicados", "pontos_fora_exemplo", "completa_101", "acao_recomendada"))
  bad <- sort(unique(as.character(aud[completa_101 == FALSE, COLETA])))
  bad <- bad[!is.na(bad) & nzchar(bad)]
  quar <- aud[COLETA %in% bad]
  regs_quar <- if (length(bad)) d[as.character(d[[as.character(ch$coleta)[1L]]]) %chin% bad] else d[0]
  fw(aud, file.path(dir_comp, "auditoria_completude_101_pontos_por_coleta_pre_painel.csv"))
  fw(quar, file.path(dir_comp, "coletas_quarentenadas_por_incompletude_pre_painel.csv"))
  fw(regs_quar, file.path(dir_comp, "registros_quarentenados_por_incompletude_pre_painel.csv"))
  fw(aud, file.path(dir_painel, "auditoria_completude_101_pontos_por_coleta_pre_painel.csv"))
  fw(quar, file.path(dir_painel, "coletas_quarentenadas_por_incompletude_pre_painel.csv"))
  try(fw(aud, file.path(log_dir, paste0("auditoria_completude_101_pontos_por_coleta_pre_painel_", exec_id, ".csv"))), silent = TRUE)
  if (length(bad)) {
    d2 <- d[!(as.character(d[[as.character(ch$coleta)[1L]]]) %chin% bad)]
    msg <- paste0("Completude pré-painel: ", length(bad), " COLETA(s) quarentenada(s) por não atenderem a 101 pontos; removidas do painel. Relatório: ", file.path(dir_comp, "coletas_quarentenadas_por_incompletude_pre_painel.csv"))
    if (exists("monitora_correcao_console_msg", mode = "function")) monitora_correcao_console_msg(msg) else message(msg)
    if (exists("monitora_log_registrar_evento", mode = "function")) monitora_log_registrar_evento("completude_pre_painel", "AVISO", file.path(dir_comp, "coletas_quarentenadas_por_incompletude_pre_painel.csv"), msg, "COLETAS incompletas fora do painel")
    return(list(dt = d2, auditoria = aud, quarentenadas = bad, registros_quarentenados = regs_quar))
  }
  msg <- "Completude pré-painel: todas as COLETAS avaliadas atendem a 101 pontos."
  if (exists("monitora_correcao_console_msg", mode = "function")) monitora_correcao_console_msg(msg) else message(msg)
  list(dt = d, auditoria = aud, quarentenadas = character(0), registros_quarentenados = regs_quar)
}

### Relatórios diagnósticos de ocorrências do painel ------------------------
### Gera relatórios operacionais pré/pós-painel para todas as ocorrências
### diagnósticas exibidas no filtro. Esta rotina é independente dos relatórios
### históricos de apoio e grava somente arquivos regulares dentro de
### ocorrencias_diagnosticas/, evitando interferência na comparação MD5 antiga.
monitora_diag_rel_gerar_ocorrencias <- function(dt,
                                                fase = c("pre_painel", "pos_painel"),
                                                base_dir = NULL,
                                                coletas_triagem_por_tipo = NULL,
                                                triagem_painel_unificada = NULL,
                                                validar_contagens = TRUE) {
  fase <- as.character(fase)[1L]
  if (!requireNamespace("data.table", quietly = TRUE)) stop("Pacote data.table é obrigatório para relatórios diagnósticos.", call. = FALSE)
  dt <- data.table::as.data.table(dt)
  n <- nrow(dt)
  if (is.null(base_dir)) {
    corr_dir <- get0("MONITORA_CORRECOES_DIR", ifnotfound = file.path(get0("MONITORA_OUTPUT_DIR", ifnotfound = "output", inherits = TRUE), "correcoes_campos"), inherits = TRUE)
    pasta_fase <- if (grepl("^pre", fase)) "relatorios_pre_painel" else "relatorios_pos_painel"
    base_dir <- file.path(corr_dir, pasta_fase, "ocorrencias_diagnosticas")
  }
  dir.create(base_dir, recursive = TRUE, showWarnings = FALSE)

  write_dt <- function(x, arquivo) {
    x <- data.table::as.data.table(x)
    dir.create(dirname(arquivo), recursive = TRUE, showWarnings = FALSE)
    tryCatch(
      data.table::fwrite(x, arquivo, na = ""),
      error = function(e) utils::write.csv(as.data.frame(x), arquivo, row.names = FALSE, na = "", fileEncoding = "UTF-8")
    )
    invisible(arquivo)
  }

  empty_rel <- function() {
    data.table::data.table(
      etapa = character(), tipo_ocorrencia = character(), rotulo_ocorrencia = character(), severidade = character(),
      linha_indice = integer(), COLETA = character(), UC = character(), EA = character(), UA = character(), CICLO = character(), CAMPANHA = character(), ANO = character(),
      `Data (data_hora)` = character(), PROTOCOLO = character(), num_placa_formatado = character(), ponto_amostral = character(), ponto_metro = character(), Encostam = character(),
      campo_superior = character(), token_problematico = character(), campo_forma_vida_esperado = character(), valor_forma_vida_atual = character(),
      campos_dependentes_preenchidos = character(), acao_recomendada = character()
    )
  }

  catalogo <- data.table::data.table(
    tipo_ocorrencia = c(
      "uas_duplicadas_mesmo_ano", "ponto_sem_interceptacao", "nativa_sem_forma_vida", "exotica_sem_forma_vida", "seca_morta_sem_forma_vida", "outra_forma_vida", "forma_vida_desconhecida", "forma_vida_exotica_sem_especie", "forma_vida_exotica_com_especie"
    ),
    rotulo_ocorrencia = c(
      "UAs duplicadas no mesmo ano", "Ponto amostral sem interceptação", "Nativa sem forma de vida", "Exótica sem forma de vida", "Seca ou morta sem forma de vida", "Outra forma de vida", "Forma de vida desconhecida", "Revisão: forma de vida exótica sem espécie", "Revisão: forma de vida exótica com espécie"
    ),
    severidade = c(rep("impeditiva", 7L), rep("revisao", 2L)),
    arquivo = c(
      paste0("registros_ua_duplicada_mesmo_ano_", fase, ".csv"),
      paste0("registros_ponto_sem_interceptacao_", fase, ".csv"),
      paste0("registros_nativa_sem_forma_vida_", fase, ".csv"),
      paste0("registros_exotica_sem_forma_vida_", fase, ".csv"),
      paste0("registros_seca_morta_sem_forma_vida_", fase, ".csv"),
      paste0("registros_outra_forma_vida_", fase, ".csv"),
      paste0("registros_forma_vida_desconhecida_", fase, ".csv"),
      paste0("registros_forma_vida_exotica_sem_especie_", fase, ".csv"),
      paste0("registros_forma_vida_exotica_com_especie_", fase, ".csv")
    )
  )

  chaves <- tryCatch(monitora_correcao_colunas_chave(dt), error = function(e) list())
  col_ok <- function(col) !is.null(col) && length(col) && !is.na(as.character(col)[1L]) && nzchar(as.character(col)[1L]) && as.character(col)[1L] %in% names(dt)
  get_col <- function(col) {
    if (!col_ok(col)) return(rep(NA_character_, n))
    as.character(dt[[as.character(col)[1L]]])
  }
  primeira_col <- function(nomes = character(), regex = character()) {
    out <- tryCatch(monitora_correcao_primeira_coluna(dt, nomes, regex), error = function(e) NA_character_)
    if (col_ok(out)) as.character(out)[1L] else NA_character_
  }
  col_data <- chaves[["data_hora"]]
  col_prot <- primeira_col(c("PROTOCOLO", "protocolo"), c("^protocolo$"))
  col_placa <- primeira_col(c("num_placa_formatado", "amostragem/num_placa_formatado", "Número da placa", "numero_placa", "num_placa"), c("num.*placa", "numero.*placa", "placa"))
  tipo_col <- chaves[["tipo_forma_vida"]]
  tipo_val <- get_col(tipo_col)
  coleta <- get_col(chaves[["coleta"]])

  vec_ch <- function(nm) get_col(chaves[[nm]])
  vazio <- function(x) {
    out <- tryCatch(monitora_correcao_vazio_vec(x), error = function(e) is.na(x) | !nzchar(trimws(as.character(x))))
    out[is.na(out)] <- TRUE
    out
  }
  tem_token <- function(tokens) {
    if (!n) return(logical(0))
    out <- tryCatch(monitora_relatorio_exoticas_tem_token(tipo_val, tokens), error = function(e) rep(FALSE, n))
    out[is.na(out)] <- FALSE
    out
  }
  cols_categoria <- function(categoria) {
    cols <- tryCatch(monitora_correcao_colunas_forma_vida_categoria(dt, categoria), error = function(e) character(0))
    unique(cols[!is.na(cols) & nzchar(cols) & cols %in% names(dt)])
  }
  tem_forma_categoria <- function(categoria) {
    cols <- cols_categoria(categoria)
    if (!length(cols)) return(rep(FALSE, n))
    out <- rep(FALSE, n)
    for (cc in cols) out <- out | !vazio(dt[[cc]])
    out[is.na(out)] <- FALSE
    out
  }
  collapse_cols_linha <- function(cols, idx) {
    cols <- unique(cols[!is.na(cols) & nzchar(cols) & cols %in% names(dt)])
    if (!length(cols) || !length(idx)) return(rep("", length(idx)))
    vapply(idx, function(ii) {
      vals <- vapply(cols, function(cc) {
        vv <- as.character(dt[[cc]][ii]); if (is.na(vv) || !nzchar(trimws(vv))) return(NA_character_)
        paste0(cc, " = ", vv)
      }, character(1))
      vals <- vals[!is.na(vals) & nzchar(vals)]
      paste(vals, collapse = " | ")
    }, character(1))
  }
  dependentes_categoria <- function(categoria, idx, excluir = character()) {
    if (!length(idx)) return(character(0))
    z <- tryCatch(monitora_correcao_normalizar_nome_coluna(names(dt)), error = function(e) tolower(names(dt)))
    cat_pat <- switch(categoria, nativa = "nativ", exotica = "exotic|exotica|exotico", seca_morta = "seca|morta", outras = "outra|outro|forma_vida_outros", "")
    if (!nzchar(cat_pat)) return(rep("", length(idx)))
    cols <- names(dt)[grepl(cat_pat, z)]
    cols <- setdiff(cols, excluir)
    cols <- cols[!grepl("^(monitora_|DATA_MONITORA|HASH_|hash_|arquivo_|origem_)", cols)]
    if (length(cols) > 30L) cols <- cols[seq_len(30L)]
    collapse_cols_linha(cols, idx)
  }

  add_rows <- function(tipo_ocorrencia, mask = NULL, idx = NULL, token = NA_character_, campo_forma = NA_character_, valor_forma = NULL, dependentes = NULL, acao = "") {
    tipo_key <- as.character(tipo_ocorrencia)[1L]
    cat_row <- catalogo[catalogo$tipo_ocorrencia == tipo_key]
    if (!nrow(cat_row)) return(empty_rel())
    if (is.null(idx)) {
      mask <- as.logical(mask); mask[is.na(mask)] <- FALSE
      if (length(mask) != n) mask <- rep(FALSE, n)
      idx <- which(mask)
    }
    idx <- unique(as.integer(idx[!is.na(idx) & idx >= 1L & idx <= n]))
    if (!length(idx)) return(empty_rel())
    if (is.null(valor_forma)) valor_forma <- rep("", length(idx))
    if (length(valor_forma) == 1L) valor_forma <- rep(as.character(valor_forma), length(idx))
    if (is.null(dependentes)) dependentes <- rep("", length(idx))
    if (length(dependentes) == 1L) dependentes <- rep(as.character(dependentes), length(idx))
    data.table::data.table(
      etapa = fase,
      tipo_ocorrencia = tipo_key,
      rotulo_ocorrencia = cat_row$rotulo_ocorrencia[1L],
      severidade = cat_row$severidade[1L],
      linha_indice = idx,
      COLETA = coleta[idx],
      UC = vec_ch("uc")[idx],
      EA = vec_ch("ea")[idx],
      UA = vec_ch("ua")[idx],
      CICLO = vec_ch("ciclo")[idx],
      CAMPANHA = vec_ch("campanha")[idx],
      ANO = vec_ch("ano")[idx],
      `Data (data_hora)` = get_col(col_data)[idx],
      PROTOCOLO = get_col(col_prot)[idx],
      num_placa_formatado = get_col(col_placa)[idx],
      ponto_amostral = vec_ch("ponto_amostral")[idx],
      ponto_metro = vec_ch("ponto_metro")[idx],
      Encostam = tipo_val[idx],
      campo_superior = ifelse(col_ok(tipo_col), as.character(tipo_col)[1L], ""),
      token_problematico = as.character(token)[1L],
      campo_forma_vida_esperado = as.character(campo_forma)[1L],
      valor_forma_vida_atual = as.character(valor_forma),
      campos_dependentes_preenchidos = as.character(dependentes),
      acao_recomendada = acao
    )
  }

  rels <- list()

  if (n && all(vapply(list(vec_ch("uc"), vec_ch("ua"), vec_ch("ano"), coleta), function(x) any(!is.na(x) & nzchar(x)), logical(1)))) {
    aux <- data.table::data.table(linha_indice = seq_len(n), UC = vec_ch("uc"), UA = vec_ch("ua"), ANO = vec_ch("ano"), COLETA = coleta)
    aux <- aux[!is.na(UC) & nzchar(UC) & !is.na(UA) & nzchar(UA) & !is.na(ANO) & nzchar(ANO) & !is.na(COLETA) & nzchar(COLETA)]
    if (nrow(aux)) {
      grupos <- aux[, .(n_coletas = data.table::uniqueN(COLETA)), by = .(UC, UA, ANO)][n_coletas > 1L]
      idx_dup <- if (nrow(grupos)) aux[grupos, on = .(UC, UA, ANO), linha_indice] else integer(0)
      rels[["uas_duplicadas_mesmo_ano"]] <- add_rows("uas_duplicadas_mesmo_ano", idx = idx_dup, token = "UC+UA+ANO", campo_forma = "UC+UA+ANO+COLETA", acao = "Resolver no painel por exclusão de COLETA excedente, correção de UA/ANO quando houver erro documental ou outra modificação auditável.")
    }
  }


  rels[["ponto_sem_interceptacao"]] <- add_rows("ponto_sem_interceptacao", mask = vazio(tipo_val), token = "Encostam vazio", campo_forma = ifelse(col_ok(tipo_col), as.character(tipo_col)[1L], ""), acao = "Conferir o registro original; se não houver interceptação registrada de forma válida, excluir a COLETA.")

  cols_nat <- cols_categoria("nativa")
  cols_exo <- cols_categoria("exotica")
  cols_sec <- cols_categoria("seca_morta")
  idx_nat <- which(tem_token(c("nativa", "nativas", "nativo", "nativos")) & !tem_forma_categoria("nativa"))
  rels[["nativa_sem_forma_vida"]] <- add_rows("nativa_sem_forma_vida", idx = idx_nat, token = "nativa", campo_forma = paste(cols_nat, collapse = " | "), valor_forma = collapse_cols_linha(cols_nat, idx_nat), dependentes = dependentes_categoria("nativa", idx_nat, cols_nat), acao = "Conferir a planilha original. Se a forma de vida constar na planilha, preencher o campo inferior correspondente; se não foi registrada em campo, excluir a COLETA.")

  idx_exo <- which(tem_token(c("exotica", "exoticas", "exotico", "exoticos")) & !tem_forma_categoria("exotica"))
  rels[["exotica_sem_forma_vida"]] <- add_rows("exotica_sem_forma_vida", idx = idx_exo, token = "exotica", campo_forma = paste(cols_exo, collapse = " | "), valor_forma = collapse_cols_linha(cols_exo, idx_exo), dependentes = dependentes_categoria("exotica", idx_exo, cols_exo), acao = "Conferir a planilha original. Se a forma de vida constar na planilha, preencher o campo inferior correspondente; se não foi registrada em campo, excluir a COLETA.")

  idx_sec <- which(tem_token(c("seca_morta", "seca", "secas", "seco", "secos", "morta", "mortas", "morto", "mortos")) & !tem_forma_categoria("seca_morta"))
  rels[["seca_morta_sem_forma_vida"]] <- add_rows("seca_morta_sem_forma_vida", idx = idx_sec, token = "seca_morta/seca/morta", campo_forma = paste(cols_sec, collapse = " | "), valor_forma = collapse_cols_linha(cols_sec, idx_sec), dependentes = dependentes_categoria("seca_morta", idx_sec, cols_sec), acao = "Conferir a planilha original. Se a forma de vida constar na planilha, preencher o campo inferior correspondente; se não foi registrada em campo, excluir a COLETA.")

  mask_outra <- rep(FALSE, n); cols_outra_hit <- character(0)
  cols_info <- tryCatch(monitora_correcao_colunas_limpeza_outras_formas(dt, NULL), error = function(e) data.table::data.table())
  if (nrow(cols_info)) {
    tokens_outra <- tryCatch(monitora_correcao_tokens_residuo_historico_outras_formas(), error = function(e) c("outra_forma_vida", "outras_formas_vida", "outra", "outro", "outras", "outros"))
    listas <- cols_info[classe == "lista_principal_forma_vida" & coluna %in% names(dt), unique(coluna)]
    descritores <- cols_info[classe == "descritor_outra_forma_vida" & coluna %in% names(dt), unique(coluna)]
    fotos <- cols_info[classe == "foto_outra_forma_vida" & coluna %in% names(dt), unique(coluna)]
    for (cc in listas) {
      hit <- tryCatch(monitora_correcao_contem_qualquer_token_vec(dt[[cc]], tokens_outra), error = function(e) rep(FALSE, n)); hit[is.na(hit)] <- FALSE
      if (any(hit)) cols_outra_hit <- unique(c(cols_outra_hit, cc))
      mask_outra <- mask_outra | hit
    }
    for (cc in unique(c(descritores, fotos))) {
      hit <- !vazio(dt[[cc]]); hit[is.na(hit)] <- FALSE
      if (any(hit)) cols_outra_hit <- unique(c(cols_outra_hit, cc))
      mask_outra <- mask_outra | hit
    }
  }
  idx_outra <- which(mask_outra)
  rels[["outra_forma_vida"]] <- add_rows("outra_forma_vida", idx = idx_outra, token = "outra_forma_vida/outra/outros", campo_forma = paste(cols_outra_hit, collapse = " | "), valor_forma = collapse_cols_linha(cols_outra_hit, idx_outra), dependentes = dependentes_categoria("outras", idx_outra, cols_outra_hit), acao = "Aplicar a sanitização assistida no painel ou corrigir manualmente; se a pendência permanecer, registros_corrig.csv será checkpoint pendente e registros_validados.csv ficará bloqueado.")

  ### Forma de vida desconhecida: ocorrência diagnóstica restaurada. Inclui
  ### tokens explícitos nas listas principais e dependentes de desconhecida
  ### preenchidos sem/independentemente do token, para antecipar bloqueios de
  ### registros_validados.csv e permitir substituição assistida no painel.
  mask_desc <- rep(FALSE, n); cols_desc_hit <- character(0)
  toks_desc <- tryCatch(monitora_correcao_tokens_desconhecida(), error = function(e) c("desconhecida", "desconhecido"))
  for (cat_desc in c("nativa", "exotica", "seca_morta")) {
    cols_desc_lista <- cols_categoria(cat_desc)
    for (cc in cols_desc_lista) {
      hit <- tryCatch(monitora_correcao_contem_qualquer_token_vec(dt[[cc]], toks_desc), error = function(e) rep(FALSE, n)); hit[is.na(hit)] <- FALSE
      if (any(hit)) cols_desc_hit <- unique(c(cols_desc_hit, cc))
      mask_desc <- mask_desc | hit
    }
    cols_dep_desc <- tryCatch(monitora_correcao_colunas_desconhecida_por_categoria(dt, cat_desc, NULL), error = function(e) data.table::data.table())
    if (nrow(cols_dep_desc)) {
      for (cc in unique(cols_dep_desc$coluna[cols_dep_desc$coluna %in% names(dt)])) {
        hit <- !vazio(dt[[cc]]); hit[is.na(hit)] <- FALSE
        if (any(hit)) cols_desc_hit <- unique(c(cols_desc_hit, cc))
        mask_desc <- mask_desc | hit
      }
    }
  }
  idx_desc_superior_only <- tryCatch(monitora_correcao_linhas_desconhecida_sem_categoria_base(dt, seq_len(n), chaves = chaves), error = function(e) integer(0))
  if (length(idx_desc_superior_only)) {
    mask_desc[idx_desc_superior_only] <- TRUE
    cols_desc_hit <- unique(c(cols_desc_hit, if (col_ok(tipo_col)) as.character(tipo_col)[1L] else "Encostam"))
  }
  idx_desc <- which(mask_desc)
  rels[["forma_vida_desconhecida"]] <- add_rows("forma_vida_desconhecida", idx = idx_desc, token = "desconhecida/desconhecido/dependente_desconhecida/encostam_superior_only", campo_forma = paste(cols_desc_hit, collapse = " | "), valor_forma = collapse_cols_linha(cols_desc_hit, idx_desc), dependentes = dependentes_categoria("nativa", idx_desc, character(0)), acao = "Usar a operação assistida 'Substituir desconhecida(s) por forma válida'. Encostam=desconhecida superior-only é erro grave de input; antes do painel é pré-tratado automaticamente para Encostam=nativa e forma_vida_nativa=desconhecida, chegando ao painel como pendência impeditiva nativa/desconhecida até substituição assistida ou exclusão da COLETA.")


  ### Ocorrências de revisão exótica: recomputadas linha-a-linha, inclusive no pós-painel.
  idx_sem_sp <- integer(0); idx_com_sp <- integer(0)
  tri_ex <- tryCatch(data.table::as.data.table(triagem_painel_unificada), error = function(e) data.table::data.table())
  if (nrow(tri_ex) && "linha_filtro" %in% names(tri_ex) && "status_vinculo" %in% names(tri_ex)) {
    ### Pré-painel: usar a mesma fonte lógica da triagem exibida no painel,
    ### para as contagens dos relatórios baterem exatamente com os filtros.
    idx_sem_sp <- unique(as.integer(tri_ex[status_vinculo == "exotica_com_forma_sem_sp_vinculada", linha_filtro]))
    idx_com_sp <- unique(as.integer(tri_ex[status_vinculo == "exotica_com_forma_e_sp_vinculada", linha_filtro]))
  } else if (exists("monitora_relatorio_exoticas_detectar_colunas_forma", mode = "function") && exists("monitora_relatorio_exoticas_detectar_colunas_especies", mode = "function")) {
    ### Pós-painel: recomputar linha-a-linha quando a triagem pré-painel já não
    ### representa a base mutada por correções/exclusões.
    forma_cols_ex <- tryCatch(monitora_relatorio_exoticas_detectar_colunas_forma(dt), error = function(e) character(0))
    especie_cols_ex <- tryCatch(monitora_relatorio_exoticas_detectar_colunas_especies(dt), error = function(e) character(0))
    tem_token_ex <- tem_token(c("exotica", "exoticas", "exotico", "exoticos"))
    tem_forma_ex <- if (length(forma_cols_ex)) Reduce(`|`, lapply(forma_cols_ex, function(cc) tryCatch(monitora_relatorio_exoticas_tem_valor(dt[[cc]]), error = function(e) rep(FALSE, n)))) else rep(FALSE, n)
    vinc <- tryCatch(monitora_relatorio_exoticas_especies_vinculadas_por_linha(dt, forma_cols_ex, especie_cols_ex), error = function(e) list(tem = rep(FALSE, n)))
    tem_sp_vinc <- as.logical(vinc$tem); tem_sp_vinc[is.na(tem_sp_vinc)] <- FALSE
    idx_sem_sp <- which(tem_token_ex & tem_forma_ex & !tem_sp_vinc)
    idx_com_sp <- which(tem_token_ex & tem_forma_ex & tem_sp_vinc)
  }
  idx_sem_sp <- idx_sem_sp[!is.na(idx_sem_sp) & idx_sem_sp >= 1L & idx_sem_sp <= n]
  idx_com_sp <- idx_com_sp[!is.na(idx_com_sp) & idx_com_sp >= 1L & idx_com_sp <= n]
  rels[["forma_vida_exotica_sem_especie"]] <- add_rows("forma_vida_exotica_sem_especie", idx = idx_sem_sp, token = "exotica_com_forma_sem_sp_vinculada", campo_forma = paste(cols_exo, collapse = " | "), valor_forma = collapse_cols_linha(cols_exo, idx_sem_sp), dependentes = dependentes_categoria("exotica", idx_sem_sp, cols_exo), acao = "Revisar espécie exótica vinculada à forma de vida. Ocorrência de revisão; não bloqueia sozinha registros_corrig.csv.")
  rels[["forma_vida_exotica_com_especie"]] <- add_rows("forma_vida_exotica_com_especie", idx = idx_com_sp, token = "exotica_com_forma_e_sp_vinculada", campo_forma = paste(cols_exo, collapse = " | "), valor_forma = collapse_cols_linha(cols_exo, idx_com_sp), dependentes = dependentes_categoria("exotica", idx_com_sp, cols_exo), acao = "Revisar consistência taxonômica da espécie exótica vinculada. Ocorrência informativa/revisão.")

  for (tp in catalogo$tipo_ocorrencia) if (is.null(rels[[tp]])) rels[[tp]] <- empty_rel()
  todos <- data.table::rbindlist(rels[catalogo$tipo_ocorrencia], fill = TRUE, use.names = TRUE)
  if (nrow(todos)) {
    todos[, COLETA := as.character(COLETA)]
    todos <- unique(todos, by = c("tipo_ocorrencia", "linha_indice"))
    data.table::setorder(todos, severidade, tipo_ocorrencia, UC, UA, ANO, COLETA, ponto_amostral, ponto_metro, linha_indice)
  }

  for (ii in seq_len(nrow(catalogo))) {
    tp <- catalogo$tipo_ocorrencia[ii]
    arq <- file.path(base_dir, catalogo$arquivo[ii])
    x <- if (nrow(todos)) todos[tipo_ocorrencia == tp] else empty_rel()
    write_dt(x, arq)
  }
  write_dt(todos, file.path(base_dir, paste0("registros_ocorrencias_diagnosticas_", fase, ".csv")))

  resumo <- if (nrow(todos)) {
    todos[, .(
      n_linhas = .N,
      n_coletas = data.table::uniqueN(COLETA[!is.na(COLETA) & nzchar(COLETA)]),
      coletas_exemplo = paste(utils::head(unique(COLETA[!is.na(COLETA) & nzchar(COLETA)]), 30L), collapse = " | ")
    ), by = .(etapa, severidade, tipo_ocorrencia, rotulo_ocorrencia)]
  } else {
    data.table::data.table(etapa = character(), severidade = character(), tipo_ocorrencia = character(), rotulo_ocorrencia = character(), n_linhas = integer(), n_coletas = integer(), coletas_exemplo = character())
  }
  resumo_all <- merge(catalogo[, .(tipo_ocorrencia, rotulo_ocorrencia, severidade)], resumo, by = c("tipo_ocorrencia", "rotulo_ocorrencia", "severidade"), all.x = TRUE)
  resumo_all[is.na(etapa), etapa := fase]
  resumo_all[is.na(n_linhas), n_linhas := 0L]
  resumo_all[is.na(n_coletas), n_coletas := 0L]
  resumo_all[is.na(coletas_exemplo), coletas_exemplo := ""]
  data.table::setcolorder(resumo_all, c("etapa", "severidade", "tipo_ocorrencia", "rotulo_ocorrencia", "n_linhas", "n_coletas", "coletas_exemplo"))
  data.table::setorder(resumo_all, severidade, tipo_ocorrencia)

  write_dt(resumo_all[severidade == "impeditiva"], file.path(base_dir, paste0("resumo_ocorrencias_impeditivas_", fase, ".csv")))
  write_dt(resumo_all, file.path(base_dir, paste0("resumo_ocorrencias_diagnosticas_", fase, ".csv")))

  indice <- catalogo[, .(etapa = fase, tipo_ocorrencia, rotulo_ocorrencia, severidade, arquivo, caminho = file.path(base_dir, arquivo))]
  indice <- resumo_all[indice, on = .(tipo_ocorrencia, rotulo_ocorrencia, severidade)]
  indice[, arquivo_existe := file.exists(caminho)]
  data.table::setcolorder(indice, c("etapa", "severidade", "tipo_ocorrencia", "rotulo_ocorrencia", "arquivo", "caminho", "arquivo_existe", "n_linhas", "n_coletas", "coletas_exemplo"))
  write_dt(indice, file.path(base_dir, "indice_relatorios_ocorrencias_diagnosticas.csv"))

  validacao <- data.table::data.table()
  if (isTRUE(validar_contagens) && is.list(coletas_triagem_por_tipo)) {
    validacao <- data.table::rbindlist(lapply(intersect(names(coletas_triagem_por_tipo), catalogo$tipo_ocorrencia), function(tp) {
      exp <- coletas_triagem_por_tipo[[tp]]
      exp <- unique(as.character(exp)); exp <- exp[!is.na(exp) & nzchar(exp)]
      obs <- if (nrow(todos)) unique(as.character(todos[tipo_ocorrencia == tp, COLETA])) else character(0)
      obs <- obs[!is.na(obs) & nzchar(obs)]
      data.table::data.table(
        etapa = fase,
        tipo_ocorrencia = tp,
        n_coletas_triagem_painel = length(exp),
        n_coletas_relatorio = length(obs),
        consistente = identical(sort(exp), sort(obs)),
        coletas_na_triagem_nao_relatorio = paste(setdiff(sort(exp), sort(obs)), collapse = " | "),
        coletas_no_relatorio_nao_triagem = paste(setdiff(sort(obs), sort(exp)), collapse = " | ")
      )
    }), fill = TRUE)
    write_dt(validacao, file.path(base_dir, paste0("validacao_contagens_triagem_vs_relatorios_", fase, ".csv")))
  }

  n_csv <- length(list.files(base_dir, pattern = "\\.csv$", full.names = TRUE, recursive = FALSE))
  n_tipos_com_ocorrencia <- sum(resumo_all$n_coletas > 0L, na.rm = TRUE)
  soma_imp <- sum(resumo_all[severidade == "impeditiva", n_coletas], na.rm = TRUE)
  msg <- paste0("Relatórios de ocorrências diagnósticas [", fase, "] gerados em ", base_dir, "; arquivos_csv=", n_csv, "; tipos_com_ocorrencia=", n_tipos_com_ocorrencia, "; soma coletas impeditivas por tipo=", soma_imp, ".")
  if (exists("monitora_correcao_console_msg", mode = "function")) monitora_correcao_console_msg(msg) else message(msg)
  if (nrow(validacao) && any(!validacao$consistente, na.rm = TRUE)) {
    msg2 <- paste0("AVISO: contagens dos relatórios diagnósticos divergem da triagem do painel em ", sum(!validacao$consistente, na.rm = TRUE), " tipo(s). Ver validacao_contagens_triagem_vs_relatorios_", fase, ".csv.")
    if (exists("monitora_correcao_console_msg", mode = "function")) monitora_correcao_console_msg(msg2) else warning(msg2, call. = FALSE)
  }
  invisible(list(diretorio = base_dir, indice = indice, resumo = resumo_all, registros = todos, validacao = validacao))
}

monitora_correcao_painel <- function(dt, meta_xls = NULL, arquivo_saida = MONITORA_ARQUIVO_CORRECOES_CAMPOS) {
  monitora_correcao_carregar_dependencias_painel()
  dt <- data.table::as.data.table(dt)
  dt <- monitora_correcao_preparar_schema_edicao_painel(dt, meta_xls, contexto = "pre_painel_shiny")
  chaves <- monitora_correcao_colunas_chave(dt)
  dict <- monitora_correcao_dicionario_atributos(dt, meta_xls)
  contrato_edicao <- monitora_correcao_contrato_edicao(dt, meta_xls, dict)
  if (!("painel_editavel" %in% names(dict)) && "atributo_coluna_registros_corrig" %in% names(dict) && nrow(contrato_edicao)) {
    dict <- merge(dict, contrato_edicao[, .(atributo_coluna_registros_corrig, tipo_base_edicao, painel_editavel, painel_motivo_bloqueio, acoes_permitidas)], by = "atributo_coluna_registros_corrig", all.x = TRUE, sort = FALSE)
  }
  if ("atributo_coluna_registros_corrig" %in% names(dict) && "painel_editavel" %in% names(dict)) {
    dict <- dict[painel_editavel %in% TRUE]
  } else if ("atributo_coluna_registros_corrig" %in% names(dict)) {
    dict <- dict[!monitora_correcao_coluna_protegida(atributo_coluna_registros_corrig)]
  }
  ### publicação: a lista do seletor deve seguir o contrato global do template
  ### SISMONITORA/XLSForm 2025 e a ordem do template, não a ordem caótica das
  ### colunas de registros_corrig nem a presença de valores na coleta filtrada.
  if (exists("monitora_correcao_colunas_template_sismonitora", mode = "function")) {
    dict_template <- tryCatch(monitora_correcao_colunas_template_sismonitora(dt), error = function(e) data.table::data.table())
    if (nrow(dict_template) && "atributo_coluna_registros_corrig" %in% names(dict_template)) {
      ### Garante fisicamente no objeto os campos contratuais ainda ausentes.
      cols_criar_tpl <- setdiff(as.character(dict_template$atributo_coluna_registros_corrig), names(dt))
      cols_criar_tpl <- cols_criar_tpl[!is.na(cols_criar_tpl) & nzchar(cols_criar_tpl) & !monitora_correcao_coluna_protegida(cols_criar_tpl)]
      if (length(cols_criar_tpl)) {
        data.table::setalloccol(dt, ncol(dt) + length(cols_criar_tpl) + 16L)
        for (cc_tpl in cols_criar_tpl) data.table::set(dt, j = cc_tpl, value = NA_character_)
        monitora_correcao_limpar_cache_mapa_colunas_publicacao_b()
      }
      dict <- merge(dict_template, dict, by = "atributo_coluna_registros_corrig", all.x = TRUE, sort = FALSE, suffixes = c("", ".dict"))
      ### Preserva metadados XLSForm trazidos diretamente do template quando o
      ### dicionário base não os resolveu por nome de coluna.
      for (cc_tpl in c("xlsform_name", "xlsform_label", "xlsform_tipo", "xlsform_tipo_base", "xlsform_list_name")) {
        cc_dict <- paste0(cc_tpl, ".dict")
        if (cc_dict %in% names(dict)) {
          if (!(cc_tpl %in% names(dict))) dict[, (cc_tpl) := NA_character_]
          dict[is.na(get(cc_tpl)) | !nzchar(as.character(get(cc_tpl))), (cc_tpl) := get(cc_dict)]
          dict[, (cc_dict) := NULL]
        }
      }
      contrato_edicao <- monitora_correcao_contrato_edicao(dt, meta_xls, dict)
      cols_contrato_painel <- intersect(
        c("atributo_coluna_registros_corrig", "tipo_base_edicao", "painel_editavel", "painel_motivo_bloqueio", "acoes_permitidas", "atende_template_sismonitora", "ordem_template_sismonitora", "atributos_template_sismonitora", "posicoes_template_sismonitora", "estrategias_template_sismonitora"),
        names(contrato_edicao)
      )
      if (length(cols_contrato_painel) > 1L) {
        cols_drop <- setdiff(cols_contrato_painel, "atributo_coluna_registros_corrig")
        cols_drop <- intersect(cols_drop, names(dict))
        if (length(cols_drop)) dict[, (cols_drop) := NULL]
        dict <- merge(dict, contrato_edicao[, ..cols_contrato_painel], by = "atributo_coluna_registros_corrig", all.x = TRUE, sort = FALSE)
      }
      if ("painel_editavel" %in% names(dict)) dict <- dict[painel_editavel %in% TRUE]
      if ("atende_template_sismonitora" %in% names(dict)) dict <- dict[atende_template_sismonitora %in% TRUE]
      if (!("ordem_template_sismonitora" %in% names(dict))) dict[, ordem_template_sismonitora := 999999L]
      dict[is.na(ordem_template_sismonitora), ordem_template_sismonitora := 999999L]
      data.table::setorder(dict, ordem_template_sismonitora, atributo_coluna_registros_corrig)
    }
  }

  ### v2.6.1: força atributos administrativos/editáveis do template exportado
  ### SISMONITORA 2025 que não necessariamente aparecem como perguntas comuns do
  ### XLSForm bruto. A lista abaixo contém apenas nomes estruturais do template,
  ### sem valores reais de qualquer arquivo de dados. Os domínios de ciclo,
  ### campanha, UC, EA, UA e validado são lidos dinamicamente da execução.
  atributos_admin_forcados <- data.table::data.table(
    atributo_coluna_registros_corrig = c("ciclo", "campanha", "ea", "ua", "validado", "validador", "data_validacao", "obs_validacao"),
    xlsform_label = c("Ciclo", "Campanha", "EA", "UA", "Validado", "Validador", "Data da validação", "Observações da validação"),
    xlsform_tipo = c("select_one ciclo", "select_one campanha", "select_one ea", "select_one ua", "select_one validado", "text", "date", "text"),
    tipo_base_edicao = c("select_one", "select_one", "select_one", "select_one", "select_one", "text", "date", "text"),
    xlsform_list_name = c("ciclo", "campanha", "ea", "ua", "validado", "", "", ""),
    papel_coluna = c("metadado_template_sismonitora", "metadado_template_sismonitora", "metadado_template_sismonitora", "metadado_template_sismonitora", "metadado_template_sismonitora", "metadado_template_sismonitora", "metadado_template_sismonitora", "metadado_template_sismonitora"),
    categoria_coluna = "",
    required_bool = FALSE,
    atende_template_sismonitora = TRUE,
    ordem_template_sismonitora = c(7L, 8L, 9L, 10L, 12L, 13L, 14L, 15L),
    atributos_template_sismonitora = c("ciclo", "campanha", "ea", "ua", "validado", "validador", "data_validacao", "obs_validacao"),
    posicoes_template_sismonitora = as.character(c(7L, 8L, 9L, 10L, 12L, 13L, 14L, 15L)),
    estrategias_template_sismonitora = "forcado_metadado_template_exportado",
    painel_editavel = TRUE,
    painel_motivo_bloqueio = "",
    acoes_permitidas = c("update;clear", "update;clear", "update;clear", "update;clear", "update;clear", "update;clear", "update;clear", "update;clear")
  )
  atributos_admin_forcados <- atributos_admin_forcados[
    vapply(atributo_coluna_registros_corrig, monitora_painel_atributo_editavel_sismonitora_2025, logical(1))
  ]
  if (nrow(atributos_admin_forcados)) {
    cols_criar_admin <- as.character(atributos_admin_forcados$atributo_coluna_registros_corrig)
    cols_criar_admin <- cols_criar_admin[vapply(cols_criar_admin, function(cc) {
      hit <- tryCatch(monitora_correcao_coluna_real_admin_sismonitora(dt, cc), error = function(e) NA_character_)
      is.na(hit) || !nzchar(hit)
    }, logical(1))]
    cols_criar_admin <- setdiff(cols_criar_admin, names(dt))
    cols_criar_admin <- cols_criar_admin[!is.na(cols_criar_admin) & nzchar(cols_criar_admin) & !monitora_correcao_coluna_protegida(cols_criar_admin)]
    if (length(cols_criar_admin)) {
      data.table::setalloccol(dt, ncol(dt) + length(cols_criar_admin) + 16L)
      for (cc_admin in cols_criar_admin) data.table::set(dt, j = cc_admin, value = NA_character_)
      monitora_correcao_limpar_cache_mapa_colunas_publicacao_b()
    }
    if (!nrow(dict)) {
      dict <- data.table::copy(atributos_admin_forcados)
    } else {
      for (cc_admin in setdiff(names(atributos_admin_forcados), names(dict))) dict[, (cc_admin) := NA_character_]
      for (cc_admin in setdiff(names(dict), names(atributos_admin_forcados))) atributos_admin_forcados[, (cc_admin) := NA_character_]
      dict <- monitora_painel_admin_harmonizar_colunas(dict)
      atributos_admin_forcados <- monitora_painel_admin_harmonizar_colunas(atributos_admin_forcados)
      faltam_admin_dict <- setdiff(as.character(atributos_admin_forcados$atributo_coluna_registros_corrig), as.character(dict$atributo_coluna_registros_corrig))
      if (length(faltam_admin_dict)) {
        dict <- data.table::rbindlist(list(dict, atributos_admin_forcados[atributo_coluna_registros_corrig %in% faltam_admin_dict]), fill = TRUE, use.names = TRUE)
      }
      for (ii_admin in seq_len(nrow(atributos_admin_forcados))) {
        cc_admin <- atributos_admin_forcados$atributo_coluna_registros_corrig[ii_admin]
        jj_admin <- which(as.character(dict$atributo_coluna_registros_corrig) == cc_admin)
        if (!length(jj_admin)) next
        jj_admin <- jj_admin[1L]
        for (nm_admin in names(atributos_admin_forcados)) {
          val_admin <- atributos_admin_forcados[[nm_admin]][ii_admin]
          if (!(nm_admin %in% names(dict))) next
          vazio_admin <- is.na(dict[[nm_admin]][jj_admin]) || !nzchar(as.character(dict[[nm_admin]][jj_admin]))
          if (isTRUE(vazio_admin) || nm_admin %in% c("painel_editavel", "painel_motivo_bloqueio", "acoes_permitidas", "atende_template_sismonitora", "ordem_template_sismonitora", "atributos_template_sismonitora", "posicoes_template_sismonitora", "estrategias_template_sismonitora", "tipo_base_edicao", "xlsform_tipo", "xlsform_list_name", "xlsform_label")) {
            data.table::set(dict, i = jj_admin, j = nm_admin, value = val_admin)
          }
        }
      }
    }
    if (!nrow(contrato_edicao)) {
      contrato_edicao <- data.table::copy(atributos_admin_forcados)
    } else {
      for (cc_admin in setdiff(names(atributos_admin_forcados), names(contrato_edicao))) contrato_edicao[, (cc_admin) := NA_character_]
      for (cc_admin in setdiff(names(contrato_edicao), names(atributos_admin_forcados))) atributos_admin_forcados[, (cc_admin) := NA_character_]
      contrato_edicao <- monitora_painel_admin_harmonizar_colunas(contrato_edicao)
      atributos_admin_forcados <- monitora_painel_admin_harmonizar_colunas(atributos_admin_forcados)
      faltam_admin_contrato <- setdiff(as.character(atributos_admin_forcados$atributo_coluna_registros_corrig), as.character(contrato_edicao$atributo_coluna_registros_corrig))
      if (length(faltam_admin_contrato)) {
        contrato_edicao <- data.table::rbindlist(list(contrato_edicao, atributos_admin_forcados[atributo_coluna_registros_corrig %in% faltam_admin_contrato]), fill = TRUE, use.names = TRUE)
      }
      for (ii_admin in seq_len(nrow(atributos_admin_forcados))) {
        cc_admin <- atributos_admin_forcados$atributo_coluna_registros_corrig[ii_admin]
        jj_admin <- which(as.character(contrato_edicao$atributo_coluna_registros_corrig) == cc_admin)
        if (!length(jj_admin)) next
        jj_admin <- jj_admin[1L]
        for (nm_admin in names(atributos_admin_forcados)) {
          if (!(nm_admin %in% names(contrato_edicao))) next
          data.table::set(contrato_edicao, i = jj_admin, j = nm_admin, value = atributos_admin_forcados[[nm_admin]][ii_admin])
        }
      }
    }
    if ("painel_editavel" %in% names(dict)) dict <- dict[painel_editavel %in% TRUE]
    if (!("ordem_template_sismonitora" %in% names(dict))) dict[, ordem_template_sismonitora := 999999L]
    dict[is.na(ordem_template_sismonitora), ordem_template_sismonitora := 999999L]
    data.table::setorder(dict, ordem_template_sismonitora, atributo_coluna_registros_corrig)
  }

  if (!nrow(dict)) stop("Nenhum atributo editável seguro foi identificado para o painel de correções.", call. = FALSE)
  mapa_colunas_painel <- monitora_correcao_mapa_colunas_canonicas(dt, meta_xls, contexto = paste0("painel_", if (exists("MONITORA_EXEC_ID", inherits = TRUE)) get("MONITORA_EXEC_ID", inherits = TRUE) else format(Sys.time(), "%Y%m%d_%H%M%S")), gravar = TRUE)
  deps <- monitora_correcao_unificar_dependencias(if (!is.null(meta_xls)) meta_xls$dependencias else data.table::data.table())

  monitora_painel_valor <- function(x) {
    if (is.null(x) || length(x) == 0L) return("")
    z <- as.character(x)
    z <- z[!is.na(z) & nzchar(trimws(z))]
    if (!length(z)) return("")
    paste(unique(z), collapse = " | ")
  }
  monitora_painel_valores_coluna <- function(x, col) {
    if (is.na(col) || !col %in% names(x)) return(character(0))
    vals <- unique(as.character(x[[col]]))
    vals <- vals[!is.na(vals) & nzchar(trimws(vals))]
    sort(vals)
  }
  monitora_painel_choices <- function(rotulo_todos, vals) {
    vals <- vals[!is.na(vals) & nzchar(trimws(vals))]
    vals <- sort(unique(as.character(vals)))
    stats::setNames(c("", vals), c(rotulo_todos, vals))
  }
  monitora_painel_choices_obrigatorio <- function(rotulo_vazio, vals) {
    vals <- vals[!is.na(vals) & nzchar(trimws(vals))]
    vals <- sort(unique(as.character(vals)))
    if (length(vals) == 0L) return(stats::setNames("", rotulo_vazio))
    stats::setNames(vals, vals)
  }
  monitora_painel_acoes_atributo <- function(atributo) {
    info <- contrato_edicao[atributo_coluna_registros_corrig == as.character(atributo)[1L]]
    if (!nrow(info)) return(stats::setNames(character(0), character(0)))
    acoes <- monitora_correcao_split_serial(info$acoes_permitidas[1L])
    rot <- monitora_correcao_acoes_rotulos()
    rot <- rot[unname(rot) %in% acoes]
    if (!length(rot)) stats::setNames(character(0), character(0)) else rot
  }

  monitora_painel_limpar_html_rotulo <- function(x) {
    x <- as.character(x)
    x[is.na(x)] <- ""
    x <- gsub("<[^>]+>", "", x, perl = TRUE)
    x <- gsub("&nbsp;", " ", x, fixed = TRUE)
    x <- gsub("&lt;", "<", x, fixed = TRUE)
    x <- gsub("&gt;", ">", x, fixed = TRUE)
    x <- gsub("&amp;", "&", x, fixed = TRUE)
    trimws(gsub("\\s+", " ", gsub("\u200b", "", x), perl = TRUE))
  }

  monitora_painel_choices_atributos_template <- function(d) {
    d <- data.table::as.data.table(data.table::copy(d))
    if ("ordem_template_sismonitora" %in% names(d)) {
      d[is.na(ordem_template_sismonitora), ordem_template_sismonitora := 999999L]
      data.table::setorder(d, ordem_template_sismonitora, atributo_coluna_registros_corrig)
    }
    vals <- as.character(d$atributo_coluna_registros_corrig)
    labels_base <- vals
    if ("xlsform_label" %in% names(d)) {
      lab <- monitora_painel_limpar_html_rotulo(d$xlsform_label)
      labels_base <- ifelse(nzchar(lab), paste0(lab, " (", vals, ")"), labels_base)
    }
    labels <- labels_base
    if ("atributos_template_sismonitora" %in% names(d)) {
      tpl <- as.character(d$atributos_template_sismonitora)
      tpl[is.na(tpl)] <- ""
      labels <- ifelse(nzchar(tpl), paste0(labels_base, "  →  ", tpl), labels_base)
    }
    ### Termos auxiliares explícitos ajudam a busca do selectize por expressões
    ### naturais usadas pelos bolsistas e pelo contrato do XLSForm 2025.
    extras <- rep("", length(vals))
    extras[vals %in% c("amostragem/registro/forma_serrapilheira", "forma_serrapilheira")] <- " material botanico materiais botanicos decomposicao solo serrapilheira fragmentos botanicos material inundado"
    extras[vals %in% c("amostragem/registro/forma_vida_outros", "forma_vida_outros")] <- " outras plantas terrestres liquens fungos musgos hepaticas antoceros"
    labels <- monitora_painel_limpar_html_rotulo(paste0(labels, extras))
    stats::setNames(vals, labels)
  }
  monitora_painel_choices_atributos_contrato_mestre <- function(d) {
    d <- data.table::as.data.table(data.table::copy(d))
    d <- d[order(ordem_template, atributo_canonico)]
    vals <- as.character(d$coluna_materializada)
    rotulo_base <- sub("^.*/", "", as.character(d$atributo_canonico))
    rotulo_base <- gsub("_", " ", rotulo_base, fixed = TRUE)
    rotulo_base <- tools::toTitleCase(rotulo_base)
    labels <- paste0(rotulo_base, " (", as.character(d$atributo_canonico), ")")
    extras <- rep("", length(vals))
    extras[as.character(d$atributo_canonico) %in% c("amostragem/registro/forma_serrapilheira", "forma_serrapilheira")] <- " material botanico materiais botanicos decomposicao solo serrapilheira fragmentos botanicos material inundado"
    extras[as.character(d$atributo_canonico) %in% c("amostragem/registro/forma_vida_outros", "forma_vida_outros")] <- " outras plantas terrestres liquens fungos musgos hepaticas antoceros"
    labels <- monitora_painel_limpar_html_rotulo(paste0(labels, extras))
    stats::setNames(vals, labels)
  }
  contrato_dropdown_painel_101 <- monitora_registros_corrig_contrato_dropdown_painel_101()
  contrato_edicao <- monitora_registros_corrig_contrato_edicao_painel_101(contrato_edicao, contrato_dropdown_painel_101)
  escolhas_atributos_painel <- monitora_painel_choices_atributos_contrato_mestre(contrato_dropdown_painel_101)
  if (exists("monitora_correcao_console_msg", mode = "function")) {
    alvos_tpl <- c("ciclo", "campanha", "ea", "ua", "validado", "validador", "data_validacao", "obs_validacao", "UA", "amostragem/num_placa", "amostragem/num_placa_formatado", "amostragem/registro/forma_serrapilheira", "amostragem/registro/forma_vida_outros", "forma_serrapilheira", "forma_vida_outros")
    presentes_tpl <- intersect(alvos_tpl, unname(escolhas_atributos_painel))
    monitora_correcao_console_msg(
      "Seletor de atributos do painel: ", length(escolhas_atributos_painel),
      " atributo(s) contratuais exibidos em ordem do template SISMONITORA/XLSForm 2025; alvos v2.6.1 presentes=",
      paste(presentes_tpl, collapse = " | ")
    )
  }
  monitora_painel_choices_valor_atributo <- function(atributo, acao = NULL, incluir_observados = FALSE) {
    info <- monitora_painel_info_contrato_atributo(atributo)
    escolhas <- unique(as.character(info$escolhas))
    escolhas <- escolhas[!is.na(escolhas) & nzchar(trimws(escolhas))]
    if (!length(escolhas) && isTRUE(monitora_correcao_campo_dominio_dinamico_sismonitora(info$col, info$list_name))) {
      escolhas <- monitora_correcao_choices_dominio_dinamico_sismonitora(dt, info$col)
    }
    if (isTRUE(incluir_observados) && !is.na(info$col) && nzchar(info$col) && info$col %in% names(dt)) {
      obs <- unique(unlist(lapply(as.character(dt[[info$col]]), monitora_correcao_tokens_valor), use.names = FALSE))
      obs <- obs[!is.na(obs) & nzchar(trimws(obs))]
      escolhas <- unique(c(escolhas, obs))
    }
    stats::setNames(escolhas, escolhas)
  }

  monitora_painel_widget_valor_atributo <- function(atributo, acao = NULL) {
    info <- monitora_painel_info_contrato_atributo(atributo)
    tipo <- as.character(info$tipo)[1L]
    acao_norm <- monitora_correcao_acao_normalizar(acao)
    if (is.na(tipo) || !nzchar(tipo)) tipo <- "text"
    if (acao_norm %in% c("clear", "recalcular_tipo_forma_vida")) return("sem_valor_novo")
    if (tipo == "select_one") return("selectize_unico")
    if (tipo == "select_multiple") return("selectize_tokens")
    if (tipo == "date") return("date")
    if (tipo %in% c("integer", "decimal")) return("numeric")
    if (tipo %in% c("time", "datetime", "geopoint")) return("texto_formatado")
    "texto_livre"
  }

  monitora_painel_gravar_auditoria_controle_atributos <- function() {
    aud <- data.table::as.data.table(data.table::copy(contrato_edicao))
    if (!nrow(aud)) return(invisible(FALSE))
    if ("atende_template_sismonitora" %in% names(aud)) aud <- aud[atende_template_sismonitora %in% TRUE]
    if ("painel_editavel" %in% names(aud)) aud <- aud[painel_editavel %in% TRUE]
    if (!nrow(aud)) return(invisible(FALSE))
    aud[, n_opcoes_xlsform := vapply(xlsform_list_name, function(ll) length(monitora_correcao_choices_xlsform(ll, meta_xls)), integer(1))]
    aud[, n_opcoes_dominio_dinamico := vapply(atributo_coluna_registros_corrig, function(cc) length(monitora_correcao_choices_dominio_dinamico_sismonitora(dt, cc)), integer(1))]
    aud[, widget_valor := vapply(atributo_coluna_registros_corrig, function(aa) monitora_painel_widget_valor_atributo(aa, "update"), character(1))]
    aud[tipo_base_edicao == "select_multiple", widget_valor := "selectize_tokens"]
    aud[tipo_base_edicao == "select_one", widget_valor := "selectize_unico"]
    aud[, status_controle := "ok"]
    aud[tipo_base_edicao %in% c("select_one", "select_multiple") & (n_opcoes_xlsform + n_opcoes_dominio_dinamico) < 1L, status_controle := "bloqueado_sem_dominio_xlsform_ou_dinamico"]
    aud[tipo_base_edicao == "select_multiple" & grepl("(^|;)update(;|$)|(^|;)clear(;|$)", acoes_permitidas, perl = TRUE), status_controle := "erro_lista_tokens_com_operacao_valor_total"]
    aud[, timestamp := format(Sys.time(), "%Y-%m-%d %H:%M:%S")]
    cols <- intersect(c(
      "timestamp", "atributo_coluna_registros_corrig", "ordem_template_sismonitora", "atributos_template_sismonitora",
      "tipo_base_edicao", "xlsform_tipo", "xlsform_list_name", "n_opcoes_xlsform", "n_opcoes_dominio_dinamico", "acoes_permitidas",
      "widget_valor", "status_controle", "painel_motivo_bloqueio"
    ), names(aud))
    arq <- file.path(monitora_publicacao_b_output_dir(), "auditoria_painel_controle_atributos.csv")
    dir.create(dirname(arq), recursive = TRUE, showWarnings = FALSE)
    try(monitora_fwrite(aud[, ..cols], arq, na = ""), silent = TRUE)
    if (exists("monitora_correcao_console_msg", mode = "function")) {
      tab <- aud[, .N, by = status_controle]
      monitora_correcao_console_msg("Auditoria de controle de atributos do painel gravada: ", arq, "; ", paste(paste0(tab$status_controle, "=", tab$N), collapse = "; "))
    }
    invisible(TRUE)
  }
  monitora_painel_validar_entrada <- function(atributo, acao, valor_novo, valor_original = NA_character_) {
    col <- monitora_correcao_resolver_coluna(dt, atributo, dict)
    fake <- data.table::data.table(valor_original_esperado = valor_original)
    monitora_correcao_validar_destino_operacao(dt, col, acao, valor_novo, fake, dict, meta_xls)
  }
  monitora_painel_coluna_ok <- function(col, x = dt) {
    !is.na(col) && nzchar(col) && col %in% names(x)
  }
  monitora_painel_n_coletas <- function(x) {
    if (!monitora_painel_coluna_ok(chaves$coleta, x)) return(NA_integer_)
    data.table::uniqueN(as.character(x[[chaves$coleta]]))
  }
  monitora_painel_coleta_unica <- function(x) {
    if (!monitora_painel_coluna_ok(chaves$coleta, x)) return(NA_character_)
    vals <- unique(as.character(x[[chaves$coleta]]))
    vals <- vals[!is.na(vals) & nzchar(vals)]
    if (length(vals) == 1L) vals[1] else NA_character_
  }

  valores_uc <- monitora_painel_valores_coluna(dt, chaves$uc)
  valores_ea <- monitora_painel_valores_coluna(dt, chaves$ea)
  valores_ano <- monitora_painel_valores_coluna(dt, chaves$ano)
  valores_ciclo <- monitora_painel_valores_coluna(dt, chaves$ciclo)
  valores_campanha <- monitora_painel_valores_coluna(dt, chaves$campanha)
  valores_ua <- monitora_painel_valores_coluna(dt, chaves$ua)
  valores_coleta <- monitora_painel_valores_coluna(dt, chaves$coleta)
  coleta_inicial <- ""
  col_forma_exotica <- monitora_correcao_coluna_forma_vida(dt, "exotica")
  cols_forma_exotica <- monitora_correcao_colunas_forma_vida_categoria(dt, "exotica")

  ### Regras assistidas da triagem unificada
  ### - exóticas: movimento controlado exótica -> nativa;
  ### - desconhecidas: substituição por forma de vida válida do XLSForm atual,
  ###   mantendo ou mudando a lista de destino;
  ### - outras formas de vida: remoção do token histórico e registro de solo_nu
  ###   quando a remoção deixaria o ponto sem nenhuma categoria tocando a vareta.
  MONITORA_TRIAGEM_TOKENS_DESCONHECIDOS <- c("desconhecida", "desconhecido")
  MONITORA_TRIAGEM_TOKENS_OUTRAS <- c("outra_forma_vida", "outras_formas_vida", "forma_vida_outros", "outra", "outro", "outras", "outros")
  MONITORA_TRIAGEM_TOKENS_INVALIDOS <- unique(c(MONITORA_TRIAGEM_TOKENS_DESCONHECIDOS, MONITORA_TRIAGEM_TOKENS_OUTRAS))
  MONITORA_TRIAGEM_CATEGORIAS_FORMA <- c("nativa", "exotica", "seca_morta")
  ### Apenas estas formas possuem atributo dependente de hábito no fluxo operacional.
  ### Todas as demais formas de vida devem ignorar/bloquear qualquer hábito selecionado.
  ### Os tokens canônicos abaixo são os names do XLSForm mais recente embutido
  ### (21FEV25/2025): bromelioide, cactacea, orquidea e samambaia.
  MONITORA_TRIAGEM_FORMAS_CONDICIONAIS <- c("bromelioide", "cactacea", "orquidea", "samambaia")
  MONITORA_TRIAGEM_ALIASES_FORMAS_CONDICIONAIS <- list(
    bromelioide = c("bromelioide", "bromelioides", "erva_bromelioide", "erva_bromelioides", "ervas_bromelioides", "bromelia", "bromelias", "bromeliacea", "bromeliaceas"),
    cactacea = c("cactacea", "cactaceas", "cacto", "cactos"),
    orquidea = c("orquidea", "orquideas"),
    samambaia = c("samambaia", "samambaias")
  )
  monitora_painel_canonizar_forma_habito <- function(forma) {
    z <- monitora_relatorio_exoticas_normalizar_token(as.character(forma)[1L])
    if (is.na(z) || !nzchar(z)) return("")
    for (canon in names(MONITORA_TRIAGEM_ALIASES_FORMAS_CONDICIONAIS)) {
      aliases <- monitora_relatorio_exoticas_normalizar_token(MONITORA_TRIAGEM_ALIASES_FORMAS_CONDICIONAIS[[canon]])
      if (z %in% aliases) return(canon)
    }
    z
  }
  MONITORA_TRIAGEM_HABITO_CHOICES <- c("(não informado)" = "", "terrestre" = "terrestre", "epifita" = "epifita", "rupicola" = "rupicola")
  MONITORA_TRIAGEM_HABITO_NAO_APLICA_CHOICES <- c("(não se aplica a esta forma de vida)" = "")
  monitora_painel_forma_exige_habito <- function(forma) {
    forma <- monitora_painel_canonizar_forma_habito(forma)
    !is.na(forma) && nzchar(forma) && forma %in% MONITORA_TRIAGEM_FORMAS_CONDICIONAIS
  }

  monitora_painel_split_barra <- function(x) {
    x <- as.character(x)
    if (!length(x) || is.na(x[1]) || !nzchar(trimws(x[1]))) return(character(0))
    z <- unlist(strsplit(x[1], "\\s*\\|\\s*", perl = TRUE), use.names = FALSE)
    z <- trimws(z)
    unique(z[!is.na(z) & nzchar(z)])
  }

  monitora_painel_split_tokens_triagem <- function(x) {
    x <- as.character(x)
    if (!length(x) || is.na(x[1]) || !nzchar(trimws(x[1]))) return(character(0))
    z <- unlist(strsplit(x[1], "\\s*;\\s*", perl = TRUE), use.names = FALSE)
    z <- monitora_relatorio_exoticas_normalizar_token(z)
    unique(z[!is.na(z) & nzchar(z)])
  }

  monitora_painel_categoria_por_coluna_forma <- function(col) {
    if (is.na(col) || !nzchar(col)) return(NA_character_)
    r <- mapa_colunas_painel[coluna_registros_corrig == col]
    if (nrow(r) && identical(r$papel_coluna[1L], "lista_principal_forma_vida")) return(r$categoria[1L])
    NA_character_
  }

  monitora_painel_coluna_forma_categoria <- function(categoria, x = dt) {
    categoria <- as.character(categoria)[1]
    if (!categoria %in% MONITORA_TRIAGEM_CATEGORIAS_FORMA) return(NA_character_)
    col <- monitora_correcao_coluna_forma_vida(x, categoria)
    if (is.na(col) || !(col %in% names(x))) return(NA_character_)
    if (!monitora_correcao_coluna_principal_segura(x, col, categoria)) return(NA_character_)
    col
  }

  monitora_painel_formas_validas_choices_categoria <- function(categoria) {
    categoria <- as.character(categoria)[1]
    lista <- paste0("forma_vida_", categoria)
    op <- if (!is.null(meta_xls) && !is.null(meta_xls$opcoes)) data.table::as.data.table(meta_xls$opcoes) else data.table::data.table()
    if (nrow(op) && all(c("list_name", "name", "label") %in% names(op))) {
      op[, arquivo_xlsform_chr := if ("arquivo_xlsform" %in% names(op)) as.character(arquivo_xlsform) else ""]
      cand <- op[list_name == lista]
      if (nrow(cand)) {
        ### Preferir explicitamente o XLSForm mais recente embutido; cair para
        ### qualquer versão histórica se necessário.
        cand_atual <- cand[grepl("21FEV25|2025", arquivo_xlsform_chr, ignore.case = TRUE)]
        if (nrow(cand_atual)) cand <- cand_atual
        cand[, token_norm := monitora_relatorio_exoticas_normalizar_token(name)]
        cand <- cand[!is.na(token_norm) & nzchar(token_norm) & !(token_norm %in% MONITORA_TRIAGEM_TOKENS_INVALIDOS)]
        if (nrow(cand)) {
          cand <- unique(cand[, .(name = token_norm, label = as.character(label))], by = "name")
          cand[, rotulo := ifelse(!is.na(label) & nzchar(label), paste0(name, " — ", label), name)]
          vals <- as.character(cand$name)
          labs <- as.character(cand$rotulo)
          o <- order(vals)
          return(stats::setNames(vals[o], labs[o]))
        }
      }
    }
    vals <- sort(setdiff(c(
      "bromelioide", "erva_bromelioide", "cactacea", "orquidea", "samambaia",
      "arbusto_acima", "arbusto_abaixo", "arvore_acima", "arvore_abaixo",
      "graminoide", "erva_nao_graminoide", "bambu", "lianas", "palmeira"
    ), MONITORA_TRIAGEM_TOKENS_INVALIDOS))
    stats::setNames(vals, vals)
  }

  formas_validas_por_categoria <- list(
    nativa = monitora_painel_formas_validas_choices_categoria("nativa"),
    exotica = monitora_painel_formas_validas_choices_categoria("exotica"),
    seca_morta = monitora_painel_formas_validas_choices_categoria("seca_morta")
  )

  monitora_painel_info_contrato_atributo <- function(atributo) {
    col <- monitora_correcao_resolver_coluna(dt, atributo, dict)
    if (is.na(col) || !nzchar(col)) col <- as.character(atributo)[1L]
    info <- contrato_edicao[atributo_coluna_registros_corrig == col]
    if (!nrow(info)) {
      ### Quando o seletor usa o nome contratual (ua) mas a base carregada possui
      ### alias operacional real (UA), usar o contrato do nome selecionado e manter
      ### col como a coluna real. Isso libera a UI e garante persistência no objeto certo.
      alvo_norm <- unique(monitora_correcao_normalizar_nome_coluna(c(atributo, col, monitora_correcao_aliases_admin_sismonitora(atributo))))
      alvo_norm <- alvo_norm[!is.na(alvo_norm) & nzchar(alvo_norm)]
      info <- contrato_edicao[monitora_correcao_normalizar_nome_coluna(atributo_coluna_registros_corrig) %in% alvo_norm]
    }
    if (!nrow(info)) return(list(col = col, tipo = NA_character_, list_name = NA_character_, papel = NA_character_, categoria = NA_character_, escolhas = character(0)))
    info <- info[1L]
    escolhas <- monitora_correcao_choices_xlsform(info$xlsform_list_name, meta_xls)
    if (!length(escolhas) && isTRUE(monitora_correcao_campo_dominio_dinamico_sismonitora(col, info$xlsform_list_name))) {
      escolhas <- monitora_correcao_choices_dominio_dinamico_sismonitora(dt, col)
    }
    list(
      col = col,
      tipo = as.character(info$tipo_base_edicao[1L]),
      list_name = as.character(info$xlsform_list_name[1L]),
      papel = as.character(info$papel_coluna[1L]),
      categoria = as.character(info$categoria_coluna[1L]),
      escolhas = escolhas
    )
  }

  try(monitora_painel_gravar_auditoria_controle_atributos(), silent = TRUE)

  monitora_painel_detalhar_forma_vida_contratual <- function(atributo, acao, valor_novo) {
    info <- monitora_painel_info_contrato_atributo(atributo)
    acao_norm <- monitora_correcao_acao_normalizar(acao)
    if (!identical(info$papel, "lista_principal_forma_vida") || !(acao_norm %in% c("append_token", "adicionar_token", "update", "replace_token"))) {
      return(list(eh = FALSE, categoria = NA_character_, tokens = character(0), tokens_invalidos = character(0), exige_habito = character(0), info = info))
    }
    categoria <- info$categoria
    if (is.na(categoria) || !nzchar(categoria)) categoria <- monitora_painel_categoria_por_coluna_forma(info$col)
    tokens <- monitora_correcao_tokenizar(valor_novo)
    tokens <- unique(vapply(tokens, monitora_painel_canonizar_forma_habito, character(1)))
    tokens <- tokens[!is.na(tokens) & nzchar(tokens)]
    validos <- unname(formas_validas_por_categoria[[categoria]])
    validos_norm <- unique(vapply(validos, monitora_painel_canonizar_forma_habito, character(1)))
    invalidos <- setdiff(tokens, validos_norm)
    exige <- tokens[vapply(tokens, monitora_painel_forma_exige_habito, logical(1))]
    list(eh = TRUE, categoria = categoria, tokens = tokens, tokens_invalidos = invalidos, exige_habito = exige, info = info, validos = validos_norm)
  }

  monitora_painel_mensagem_contrato_entrada <- function(atributo, acao, valor_novo) {
    info <- monitora_painel_info_contrato_atributo(atributo)
    partes <- c(
      paste0("Tipo XLSForm inferido: ", ifelse(is.na(info$tipo) || !nzchar(info$tipo), "não identificado", info$tipo)),
      paste0("Papel da coluna: ", ifelse(is.na(info$papel) || !nzchar(info$papel), "não identificado", info$papel))
    )
    if (!is.na(info$list_name) && nzchar(info$list_name)) partes <- c(partes, paste0("Lista XLSForm: ", info$list_name))
    if (length(info$escolhas)) partes <- c(partes, paste0("Opções válidas: ", monitora_correcao_colapsar_opcoes_msg(info$escolhas, 20L)))
    exemplos <- monitora_correcao_exemplos_formato_msg(info$tipo)
    if (nzchar(exemplos)) partes <- c(partes, exemplos)
    det <- monitora_painel_detalhar_forma_vida_contratual(atributo, acao, valor_novo)
    if (isTRUE(det$eh) && length(det$exige_habito)) {
      partes <- c(partes, paste0("Forma(s) de vida com hábito obrigatório detectada(s): ", paste(det$exige_habito, collapse = ", "), ". Selecione o hábito na mesma operação."))
    }
    paste(partes, collapse = " | ")
  }

  monitora_painel_expandir_operacao_contratual <- function(op_base, x, linhas, atributo, acao, valor_novo, habito_val, n_esperado, n_alvo) {
    det <- monitora_painel_detalhar_forma_vida_contratual(atributo, acao, valor_novo)
    if (!isTRUE(det$eh)) return(list(ok = TRUE, ops = op_base, mensagem = ""))
    if (length(det$tokens_invalidos)) {
      msg <- paste0("Token(s) inválido(s) para lista de forma de vida ", det$categoria, ": ", paste(det$tokens_invalidos, collapse = ", "), ". Opções válidas: ", monitora_correcao_colapsar_opcoes_msg(det$validos), ".")
      return(list(ok = FALSE, mensagem = msg, ops = data.table::data.table()))
    }
    extras <- list()
    ordem <- suppressWarnings(max(as.integer(op_base$ordem_operacao), na.rm = TRUE))
    if (!is.finite(ordem)) ordem <- 1L
    habito_val <- monitora_painel_valor(habito_val)
    if (length(det$exige_habito) && !nzchar(habito_val)) {
      return(list(ok = FALSE, mensagem = paste0("A forma de vida '", paste(det$exige_habito, collapse = ", "), "' exige hábito. Selecione uma opção válida: terrestre, epifita ou rupicola."), ops = data.table::data.table()))
    }
    if (length(det$exige_habito)) {
      if (!habito_val %in% unname(MONITORA_TRIAGEM_HABITO_CHOICES) || !nzchar(habito_val)) {
        return(list(ok = FALSE, mensagem = "Hábito inválido. Opções válidas: terrestre, epifita, rupicola.", ops = data.table::data.table()))
      }
      for (ff in det$exige_habito) {
        dep_col <- tryCatch(monitora_correcao_resolver_coluna_habito(x, det$categoria, ff, if (!is.null(meta_xls)) meta_xls$campos else NULL, linha = if (length(linhas)) linhas[1L] else NA_integer_, meta_xls = meta_xls), error = function(e) NA_character_)
        if (!monitora_correcao_coluna_habito_segura(x, dep_col, det$categoria, ff) || identical(dep_col, det$info$col)) {
          return(list(ok = FALSE, mensagem = paste0("Não foi localizada coluna segura de hábito para '", ff, "' na categoria ", det$categoria, ". Correção bloqueada para evitar preenchimento em coluna errada."), ops = data.table::data.table()))
        }
        ordem <- ordem + 1L
        val_orig <- if (dep_col %in% names(x) && length(linhas)) unique(as.character(x[[dep_col]][linhas])) else NA_character_
        val_orig <- val_orig[!is.na(val_orig) & nzchar(trimws(val_orig))]
        val_orig <- if (length(val_orig) == 1L) val_orig[1L] else NA_character_
        op_h <- monitora_correcao_criar_operacao(
          id = as.character(op_base$id_correcao[1L]), responsavel = as.character(op_base$responsavel[1L]), tipo = "correcao_contratual_xlsform_habito", ordem = ordem,
          escopo = as.character(op_base$escopo_aplicacao[1L]), coleta = as.character(op_base$coleta[1L]), coleta_uuid = as.character(op_base$coleta_uuid[1L]),
          atributo = dep_col, acao = "update", valor_original = val_orig, valor_novo = habito_val,
          n_esperado = n_esperado, n_alvo = n_alvo, motivo = paste0(as.character(op_base$motivo[1L]), " [ação composta: hábito obrigatório pelo contrato XLSForm]"),
          token_pai = ff, categoria_destino = det$categoria, forma_valida_escolhida = ff, lista_destino = det$categoria,
          campo_dependente_preenchido = dep_col, habito_escolhido = habito_val
        )
        op_h <- monitora_correcao_anexar_contexto_operacao(op_h, x, linhas, chaves)
        extras[[length(extras) + 1L]] <- op_h
      }
    }
    tipo_col <- chaves$tipo_forma_vida
    if (!is.na(tipo_col) && nzchar(tipo_col) && tipo_col %in% names(x)) {
      ordem <- ordem + 1L
      val_orig_tipo <- if (length(linhas)) unique(as.character(x[[tipo_col]][linhas])) else NA_character_
      val_orig_tipo <- val_orig_tipo[!is.na(val_orig_tipo) & nzchar(trimws(val_orig_tipo))]
      val_orig_tipo <- if (length(val_orig_tipo) == 1L) val_orig_tipo[1L] else NA_character_
      op_t <- monitora_correcao_criar_operacao(
        id = as.character(op_base$id_correcao[1L]), responsavel = as.character(op_base$responsavel[1L]), tipo = "correcao_contratual_xlsform_encostam", ordem = ordem,
        escopo = as.character(op_base$escopo_aplicacao[1L]), coleta = as.character(op_base$coleta[1L]), coleta_uuid = as.character(op_base$coleta_uuid[1L]),
        atributo = tipo_col, acao = "recalcular_tipo_forma_vida", valor_original = val_orig_tipo, valor_novo = NA_character_,
        n_esperado = n_esperado, n_alvo = n_alvo, motivo = paste0(as.character(op_base$motivo[1L]), " [ação composta: recálculo de Encostam/tipo_forma_vida pelo contrato XLSForm]"),
        token_pai = det$categoria, categoria_destino = det$categoria, lista_destino = det$categoria
      )
      op_t <- monitora_correcao_anexar_contexto_operacao(op_t, x, linhas, chaves)
      extras[[length(extras) + 1L]] <- op_t
    }
    ops <- data.table::rbindlist(c(list(op_base), extras), fill = TRUE, use.names = TRUE)
    msg <- if (nrow(ops) > nrow(op_base)) paste0("Operação composta pelo contrato XLSForm: ", nrow(ops), " ação(ões) atômica(s), incluindo atualização de Encostam e hábito quando obrigatório.") else ""
    list(ok = TRUE, ops = ops, mensagem = msg)
  }

  ### Performance: não tokenizar todos os registros na abertura do painel apenas
  ### para montar opções do movimento assistido. A lista fixa cobre os tokens
  ### operacionais esperados; tokens diagnósticos observados na triagem unificada
  ### são reaproveitados porque essa tabela já foi montada antes da abertura do
  ### painel.
  formas_exoticas_observadas <- character(0)
  formas_diagnosticas_mv <- character(0)
  if (exists("triagem_painel_unificada", inherits = FALSE)) {
    tri_mv <- tryCatch(data.table::as.data.table(triagem_painel_unificada), error = function(e) data.table::data.table())
    if (nrow(tri_mv) && all(c("tipo_triagem", "token_detectado") %in% names(tri_mv))) {
      tok_mv <- tri_mv[tipo_triagem %in% c("forma_vida_desconhecida", "outras_formas_vida"), token_detectado]
      formas_diagnosticas_mv <- unique(unlist(lapply(tok_mv, monitora_painel_split_tokens_triagem), use.names = FALSE))
      formas_diagnosticas_mv <- formas_diagnosticas_mv[!is.na(formas_diagnosticas_mv) & nzchar(formas_diagnosticas_mv)]
    }
  }
  formas_diagnosticas_mv <- setdiff(formas_diagnosticas_mv, MONITORA_TRIAGEM_TOKENS_OUTRAS)

  monitora_painel_montar_choices_formas_mv <- function() {
    ### Lista do movimento assistido apresentada por LABEL do XLSForm mais
    ### recente (21FEV25/2025). Os names atuais e históricos ficam vinculados
    ### internamente ao label/canônico, mas não são exibidos como opções ao
    ### usuário. A lista é restrita às formas de vida das listas
    ### forma_vida_nativa, forma_vida_exotica e forma_vida_seca_morta; portanto
    ### não inclui atributos de Encostam na vareta, como serrapilheira,
    ### fragmentos_botanicos ou material_inundado, nem forma_vida_outros.
    op <- if (!is.null(meta_xls) && !is.null(meta_xls$opcoes)) data.table::as.data.table(meta_xls$opcoes) else data.table::data.table()
    listas_forma <- paste0("forma_vida_", MONITORA_TRIAGEM_CATEGORIAS_FORMA)
    tokens_excluir_mv <- unique(c(
      MONITORA_TRIAGEM_TOKENS_OUTRAS,
      "serrapilheira", "fragmentos_botanicos", "material_inundado",
      "solo_nu", "nativa", "exotica", "seca", "morta", "seca_morta"
    ))

    fallback_atual <- data.table::data.table(
      token_representativo = c(
        "graminoide", "erva_nao_graminoide", "arbusto_abaixo", "arbusto_acima",
        "arvore_abaixo", "arvore_acima", "bambu", "bromelioide", "cactacea",
        "lianas", "ervas_de_passarinho", "orquidea", "palmeira", "samambaia",
        "canela_de_ema", "desconhecida"
      ),
      label_exibicao = c(
        "Erva graminoide (gramíneas, ciperáceas e juncáceas)",
        "Erva não graminoide",
        "Arbusto tocando a vareta a uma altura inferior a 50cm",
        "Arbusto tocando a vareta a uma altura igual ou superior a 50cm",
        "Árvore com diâmetro do tronco menor que 5cm a 30cm do solo (D30)",
        "Árvore com diâmetro do tronco igual ou maior que 5cm a 30cm do solo (D30)",
        "Bambu ou taquara",
        "Erva bromelioide (bromeliáceas, apiáceas, eriocauláceas)",
        "Cacto",
        "Liana, cipó ou trepadeira",
        "Erva-de-passarinho (hemiparasita)",
        "Orquídea",
        "Palmeira",
        "Samambaia",
        "Velósia (Velloziaceae)",
        "Forma de vida desconhecida"
      ),
      ordem = seq_len(16L)
    )
    fallback_atual[, tokens_historicos := token_representativo]

    out <- fallback_atual
    if (nrow(op) && all(c("list_name", "name", "label") %in% names(op))) {
      op[, arquivo_xlsform_chr := if ("arquivo_xlsform" %in% names(op)) as.character(arquivo_xlsform) else ""]
      cand <- op[list_name %in% listas_forma]
      if (nrow(cand)) {
        cand[, token_norm := monitora_relatorio_exoticas_normalizar_token(name)]
        cand[, label_chr := trimws(as.character(label))]
        cand[is.na(label_chr) | !nzchar(label_chr), label_chr := token_norm]
        cand[, label_key := monitora_correcao_normalizar_nome_coluna(label_chr)]
        cand[, atual := grepl("21FEV25|2025", arquivo_xlsform_chr, ignore.case = TRUE)]
        cand <- cand[!is.na(token_norm) & nzchar(token_norm)]
        cand <- cand[!(token_norm %in% tokens_excluir_mv)]

        cand_atual <- cand[atual == TRUE]
        if (nrow(cand_atual)) {
          cand_atual[, ordem_atual := seq_len(.N)]
          ### Usar os names e labels do XLSForm mais recente como canônicos.
          atuais <- unique(cand_atual[, .(
            token_representativo = token_norm,
            label_exibicao = label_chr,
            label_key = label_key,
            ordem = ordem_atual
          )], by = "token_representativo")

          hist <- atuais[, {
            toks <- cand[token_norm == .BY$token_representativo | label_key == .BY$label_key, token_norm]
            toks <- sort(unique(c(toks, .BY$token_representativo)))
            list(tokens_historicos = paste(toks, collapse = "|"))
          }, by = .(token_representativo, label_exibicao, label_key, ordem)]
          out <- hist[, .(token_representativo, label_exibicao, tokens_historicos, ordem)]
        } else if (nrow(cand)) {
          ### Fallback raro: se o XLSForm mais recente não estiver nos metadados,
          ### usar somente tokens observados nas listas forma_vida_* históricas,
          ### sem incluir atributos de Encostam/forma_vida_outros.
          cand[, ordem_hist := seq_len(.N)]
          out <- unique(cand[, .(
            token_representativo = token_norm,
            label_exibicao = label_chr,
            tokens_historicos = token_norm,
            ordem = ordem_hist
          )], by = "token_representativo")
        }
      }
    }

    ### Consolidar explicitamente aliases históricos de desconhecida em uma
    ### única opção operacional com o label atual.
    if (nrow(out)) {
      out[token_representativo %in% MONITORA_TRIAGEM_TOKENS_DESCONHECIDOS | grepl("desconhecid", monitora_correcao_normalizar_nome_coluna(label_exibicao)),
          `:=`(
            token_representativo = "desconhecida",
            label_exibicao = "Forma de vida desconhecida",
            tokens_historicos = paste(sort(unique(MONITORA_TRIAGEM_TOKENS_DESCONHECIDOS)), collapse = "|")
          )]
      out <- out[!(token_representativo %in% tokens_excluir_mv)]
      data.table::setorder(out, ordem, label_exibicao, token_representativo)
      out <- unique(out, by = "token_representativo")
    }

    choices <- stats::setNames(as.character(out$token_representativo), as.character(out$label_exibicao))
    tokens_historicos <- stats::setNames(strsplit(as.character(out$tokens_historicos), "|", fixed = TRUE), as.character(out$token_representativo))
    token_para_representativo <- stats::setNames(as.character(out$token_representativo), as.character(out$token_representativo))
    for (ii in seq_len(nrow(out))) {
      toks <- unlist(strsplit(as.character(out$tokens_historicos[ii]), "|", fixed = TRUE), use.names = FALSE)
      toks <- unique(monitora_relatorio_exoticas_normalizar_token(toks))
      toks <- toks[!is.na(toks) & nzchar(toks)]
      if (length(toks)) token_para_representativo[toks] <- as.character(out$token_representativo[ii])
    }
    list(choices = choices, tokens_historicos = tokens_historicos, token_para_representativo = token_para_representativo)
  }

  formas_mv_choices_info <- monitora_painel_montar_choices_formas_mv()
  formas_mv_choices <- formas_mv_choices_info$choices
  formas_mv_tokens_historicos <- formas_mv_choices_info$tokens_historicos
  formas_mv_token_para_representativo <- formas_mv_choices_info$token_para_representativo

  monitora_painel_forma_representativa_mv <- function(forma) {
    forma <- monitora_relatorio_exoticas_normalizar_token(monitora_painel_valor(forma))
    if (!nzchar(forma)) return("")
    z <- formas_mv_token_para_representativo[[forma]]
    if (is.null(z) || !length(z) || is.na(z)) return(forma)
    as.character(z)[1L]
  }

  monitora_painel_forma_tokens_historicos_mv <- function(forma) {
    forma <- monitora_painel_forma_representativa_mv(forma)
    if (!nzchar(forma)) return(character(0))
    z <- formas_mv_tokens_historicos[[forma]]
    if (is.null(z) || !length(z)) z <- forma
    z <- unique(monitora_relatorio_exoticas_normalizar_token(z))
    z[!is.na(z) & nzchar(z)]
  }

  monitora_painel_mv_choices_com_token <- function(token) {
    token <- monitora_painel_valor(token)
    choices <- formas_mv_choices
    token_rep <- monitora_painel_forma_representativa_mv(token)
    if (nzchar(token_rep) && !(token_rep %in% unname(choices))) {
      choices <- c(choices, stats::setNames(token_rep, token_rep))
    }
    choices
  }

  monitora_painel_valor_celula <- function(x, col, i) {
    if (is.na(col) || !(col %in% names(x)) || length(i) != 1L || is.na(i) || i < 1L || i > nrow(x)) return(NA_character_)
    as.character(x[[col]][i])
  }

  monitora_painel_tabela_exoticas <- function(x) {
    ### Triagem unificada dos registros atualmente selecionados no painel.
    ### Mantém o nome interno histórico da função para reduzir risco de quebra
    ### nos observadores existentes, mas passa a listar:
    ###   - formas de vida exóticas;
    ###   - formas de vida desconhecida;
    ###   - outras formas de vida.
    ###
    ### A montagem é restrita aos registros filtrados pela coleta ativa e usa
    ### data.table/listas pré-resolvidas para evitar resolução repetida de
    ### colunas no Shiny.
    if (nrow(x) == 0L) return(data.table::data.table())

    n <- nrow(x)
    campos_ctx <- list(
      COLETA = chaves$coleta,
      UC = chaves$uc,
      EA = chaves$ea,
      UA = chaves$ua,
      CICLO = chaves$ciclo,
      CAMPANHA = chaves$campanha,
      ANO = chaves$ano,
      `Data (data_hora)` = chaves$data_hora,
      ponto_amostral = chaves$ponto_amostral,
      ponto_metro = chaves$ponto_metro,
      uuid_registro = chaves$uuid_registro
    )

    valor_col <- function(col) {
      if (length(col) != 1L || is.na(col) || !nzchar(col) || !(col %in% names(x))) return(rep(NA_character_, n))
      as.character(x[[col]])
    }

    contexto_dt <- data.table::data.table(linha_filtro = seq_len(n), linha_indice_global = seq_len(n))
    for (nm in names(campos_ctx)) data.table::set(contexto_dt, j = nm, value = valor_col(campos_ctx[[nm]]))

    forma_cols_todas <- unique(na.omit(monitora_correcao_colunas_forma_vida_principais(x)))
    forma_cols_todas <- forma_cols_todas[forma_cols_todas %in% names(x)]

    meta_campos <- if (!is.null(meta_xls)) meta_xls$campos else NULL
    out <- list()

    ### 1) Exóticas: registros com token exotica em Encostam são triados.
    ### A classificação separa: (a) forma + sp vinculada, (b) forma sem sp,
    ### (c) erro: exótica em Encostam sem forma de vida exótica detalhada.
    tipo_col <- chaves$tipo_forma_vida
    tem_token_ex <- if (!is.na(tipo_col) && tipo_col %in% names(x)) {
      monitora_relatorio_exoticas_tem_token(x[[tipo_col]], c("exotica", "exoticas", "exotico", "exoticos"))
    } else {
      rep(FALSE, n)
    }
    if (any(tem_token_ex, na.rm = TRUE)) {
      cols_ex_x <- cols_forma_exotica[cols_forma_exotica %in% names(x)]
      forma_chr <- if (length(cols_ex_x)) monitora_relatorio_exoticas_colapsar_valores(x, cols_ex_x, incluir_nomes = FALSE) else rep(NA_character_, n)
      tem_forma_ex <- !monitora_correcao_vazio_vec(forma_chr)
      linhas_forma <- which(tem_token_ex & tem_forma_ex)
      linhas_sem_forma <- which(tem_token_ex & !tem_forma_ex)

      if (length(linhas_forma)) {
        tokens_por_linha <- lapply(forma_chr[linhas_forma], monitora_correcao_tokenizar)
        tokens_unicos <- sort(unique(unlist(tokens_por_linha, use.names = FALSE)))
        tokens_unicos <- tokens_unicos[!is.na(tokens_unicos) & nzchar(tokens_unicos)]

        hab_cols <- stats::setNames(rep(NA_character_, length(tokens_unicos)), tokens_unicos)
        esp_cols <- stats::setNames(vector("list", length(tokens_unicos)), tokens_unicos)
        if (length(tokens_unicos)) {
          hab_cols[] <- vapply(tokens_unicos, function(tok) monitora_correcao_resolver_coluna_habito(x, "exotica", tok, meta_campos, linha = NA_integer_, meta_xls = meta_xls), character(1))
          for (tok in tokens_unicos) esp_cols[[tok]] <- monitora_correcao_colunas_especie_exotica_por_forma(x, tok, mapa_colunas_painel)
        }

        exoticas <- vector("list", length(linhas_forma))
        for (kk in seq_along(linhas_forma)) {
          ii <- linhas_forma[kk]
          tokens <- unique(tokens_por_linha[[kk]])
          tokens <- tokens[!is.na(tokens) & nzchar(tokens)]
          if (!length(tokens)) next
          exoticas[[kk]] <- data.table::rbindlist(lapply(tokens, function(tok) {
            hab_col <- hab_cols[[tok]]
            esp_tok_cols <- esp_cols[[tok]]
            esp_tok_cols <- esp_tok_cols[esp_tok_cols %in% names(x)]
            esp_campos <- ""; esp_valores <- ""; tem_sp <- FALSE
            if (length(esp_tok_cols)) {
              vals <- monitora_relatorio_exoticas_normalizar_texto(unlist(x[ii, ..esp_tok_cols], use.names = FALSE))
              ok <- monitora_relatorio_exoticas_tem_especie_valida(vals)
              ok[is.na(ok)] <- FALSE
              if (any(ok)) {
                tem_sp <- TRUE
                esp_campos <- paste(esp_tok_cols[ok], collapse = " | ")
                esp_valores <- paste(paste0(esp_tok_cols[ok], " = ", vals[ok]), collapse = " | ")
              }
            }
            campos_tok <- if (length(cols_ex_x)) cols_ex_x[vapply(cols_ex_x, function(cc) monitora_relatorio_exoticas_tem_token(x[[cc]][ii], tok), logical(1))] else character(0)
            valores_tok <- if (length(campos_tok)) paste(paste0(campos_tok, " = ", as.character(unlist(x[ii, ..campos_tok], use.names = FALSE))), collapse = " | ") else ""
            data.table::data.table(
              linha_filtro = ii,
              tipo_triagem = "exotica",
              categoria_forma_vida = "exotica",
              token_detectado = tok,
              status_vinculo = ifelse(tem_sp, "exotica_com_forma_e_sp_vinculada", "exotica_com_forma_sem_sp_vinculada"),
              motivo_triagem = ifelse(tem_sp, "Encostam=exotica + forma exótica + espécie no atributo específico da forma", "Encostam=exotica + forma exótica sem espécie no atributo específico da forma"),
              campo_forma_vida = paste(campos_tok, collapse = " | "),
              valor_forma_vida_original = valores_tok,
              forma_vida_exotica = tok,
              forma_vida_exotica_original = valores_tok,
              campo_habito_exotica = hab_col,
              habito_exotica = monitora_painel_valor_celula(x, hab_col, ii),
              campo_especies_exoticas = esp_campos,
              especies_exoticas = esp_valores,
              campos_forma_vida_com_token = paste(campos_tok, collapse = " | "),
              valores_forma_vida_com_token = valores_tok,
              acao_assistida_sugerida = "mover_exotica_para_nativa"
            )
          }), fill = TRUE, use.names = TRUE)
        }
        exoticas <- exoticas[!vapply(exoticas, is.null, logical(1))]
        if (length(exoticas)) out[[length(out) + 1L]] <- data.table::rbindlist(exoticas, fill = TRUE, use.names = TRUE)
      }

      if (length(linhas_sem_forma)) {
        sem_forma <- data.table::data.table(
          linha_filtro = linhas_sem_forma,
          tipo_triagem = "exotica",
          categoria_forma_vida = "exotica",
          token_detectado = "exotica_sem_forma_detalhada",
          status_vinculo = "erro_exotica_sem_forma_vida_detalhada",
          motivo_triagem = "Erro de dado: Encostam contém exotica, mas a lista de formas de vida exóticas está vazia",
          campo_forma_vida = paste(cols_ex_x, collapse = " | "),
          valor_forma_vida_original = forma_chr[linhas_sem_forma],
          forma_vida_exotica = NA_character_,
          forma_vida_exotica_original = NA_character_,
          campo_habito_exotica = NA_character_,
          habito_exotica = NA_character_,
          campo_especies_exoticas = NA_character_,
          especies_exoticas = NA_character_,
          campos_forma_vida_com_token = tipo_col,
          valores_forma_vida_com_token = paste0(tipo_col, " = ", as.character(x[[tipo_col]][linhas_sem_forma])),
          acao_assistida_sugerida = "corrigir_forma_exotica_ausente"
        )
        out[[length(out) + 1L]] <- sem_forma
      }
    }

    ### 2) Desconhecidas e outras formas de vida: varre todas as colunas de
    ### forma de vida detectadas e registra os campos/valores onde os tokens
    ### apareceram. A geração é feita por grupo de token para evitar expandir
    ### desnecessariamente todos os registros.
    adicionar_tokens <- function(tokens, tipo_label, categoria_label, acao_label) {
      if (!length(forma_cols_todas)) return(NULL)
      tokens_norm <- unique(monitora_relatorio_exoticas_normalizar_token(tokens))
      tokens_norm <- tokens_norm[!is.na(tokens_norm) & nzchar(tokens_norm)]
      if (!length(tokens_norm)) return(NULL)
      info <- monitora_relatorio_colapsar_campos_com_tokens(x, forma_cols_todas, tokens_norm)
      linhas <- which(nzchar(info$tokens))
      if (!length(linhas)) return(NULL)
      data.table::data.table(
        linha_filtro = linhas,
        tipo_triagem = tipo_label,
        categoria_forma_vida = categoria_label,
        token_detectado = info$tokens[linhas],
        campo_forma_vida = info$campos[linhas],
        valor_forma_vida_original = info$valores[linhas],
        forma_vida_exotica = NA_character_,
        forma_vida_exotica_original = NA_character_,
        campo_habito_exotica = NA_character_,
        habito_exotica = NA_character_,
        campo_especies_exoticas = NA_character_,
        especies_exoticas = NA_character_,
        campos_forma_vida_com_token = info$campos[linhas],
        valores_forma_vida_com_token = info$valores[linhas],
        acao_assistida_sugerida = acao_label
      )
    }

    desconhecidas <- adicionar_tokens(
      c("desconhecida", "desconhecido"),
      "forma_vida_desconhecida",
      "desconhecida",
      "avaliar_token_desconhecido"
    )
    if (!is.null(desconhecidas) && nrow(desconhecidas)) out[[length(out) + 1L]] <- desconhecidas

    ### Dependentes de desconhecida preenchidos sem token explícito também
    ### entram na triagem de desconhecida. Isso antecipa o bloqueio de
    ### registros_validados e permite a operação assistida limpar descritores/
    ### fotos ao substituir por forma válida.
    desconhecidas_dep <- list()
    toks_desc_tri <- tryCatch(monitora_correcao_tokens_desconhecida(), error = function(e) c("desconhecida", "desconhecido"))
    for (cat_desc_tri in c("nativa", "exotica", "seca_morta")) {
      col_lista_desc <- tryCatch(monitora_correcao_coluna_forma_vida(x, cat_desc_tri), error = function(e) NA_character_)
      tem_tok_desc <- if (!is.na(col_lista_desc) && col_lista_desc %in% names(x)) tryCatch(monitora_correcao_contem_qualquer_token_vec(x[[col_lista_desc]], toks_desc_tri), error = function(e) rep(FALSE, n)) else rep(FALSE, n)
      tem_tok_desc[is.na(tem_tok_desc)] <- FALSE
      deps_desc <- tryCatch(monitora_correcao_colunas_desconhecida_por_categoria(x, cat_desc_tri, NULL), error = function(e) data.table::data.table())
      if (nrow(deps_desc)) {
        deps_desc <- deps_desc[coluna %in% names(x)]
        for (cc_dep in unique(deps_desc$coluna)) {
          preenchido_dep <- !monitora_correcao_vazio_vec(x[[cc_dep]]); preenchido_dep[is.na(preenchido_dep)] <- FALSE
          linhas_dep <- which(preenchido_dep & !tem_tok_desc)
          if (length(linhas_dep)) {
            desconhecidas_dep[[length(desconhecidas_dep) + 1L]] <- data.table::data.table(
              linha_filtro = linhas_dep,
              tipo_triagem = "forma_vida_desconhecida",
              categoria_forma_vida = cat_desc_tri,
              token_detectado = "dependente_desconhecida_sem_token",
              campo_forma_vida = cc_dep,
              valor_forma_vida_original = paste0(cc_dep, " = ", as.character(x[[cc_dep]][linhas_dep])),
              forma_vida_exotica = NA_character_,
              forma_vida_exotica_original = NA_character_,
              campo_habito_exotica = NA_character_,
              habito_exotica = NA_character_,
              campo_especies_exoticas = NA_character_,
              especies_exoticas = NA_character_,
              campos_forma_vida_com_token = cc_dep,
              valores_forma_vida_com_token = paste0(cc_dep, " = ", as.character(x[[cc_dep]][linhas_dep])),
              acao_assistida_sugerida = "corrigir_dependente_desconhecida_sem_token"
            )
          }
        }
      }
    }
    if (length(desconhecidas_dep)) out[[length(out) + 1L]] <- data.table::rbindlist(desconhecidas_dep, fill = TRUE, use.names = TRUE)


    outras <- adicionar_tokens(
      c("outra_forma_vida", "outras_formas_vida", "forma_vida_outros", "outra", "outro", "outras", "outros"),
      "outras_formas_vida",
      "outras_formas_vida",
      "avaliar_outras_formas_vida"
    )
    if (!is.null(outras) && nrow(outras)) out[[length(out) + 1L]] <- outras

    if (!length(out)) return(data.table::data.table())
    triagem <- data.table::rbindlist(out, fill = TRUE, use.names = TRUE)
    triagem <- contexto_dt[triagem, on = "linha_filtro"]
    if ("especies_exoticas" %in% names(triagem)) {
      triagem[, tem_especie_vinculada_painel := monitora_relatorio_exoticas_tem_especie_valida(especies_exoticas)]
    } else {
      triagem[, tem_especie_vinculada_painel := FALSE]
    }
    cols_ordem <- c(
      "tipo_triagem", "status_vinculo", "motivo_triagem", "categoria_forma_vida", "token_detectado", "COLETA", "UC", "EA", "UA", "CICLO", "CAMPANHA", "ANO",
      "Data (data_hora)", "ponto_amostral", "ponto_metro", "uuid_registro", "linha_filtro",
      "campo_forma_vida", "valor_forma_vida_original", "campos_forma_vida_com_token", "valores_forma_vida_com_token",
      "forma_vida_exotica", "forma_vida_exotica_original", "campo_habito_exotica", "habito_exotica",
      "campo_especies_exoticas", "especies_exoticas", "tem_especie_vinculada_painel", "acao_assistida_sugerida"
    )
    cols_ordem <- unique(c(cols_ordem[cols_ordem %in% names(triagem)], setdiff(names(triagem), cols_ordem)))
    data.table::setcolorder(triagem, cols_ordem)
    data.table::setorder(triagem, tipo_triagem, UC, UA, ANO, ponto_amostral, ponto_metro, token_detectado)
    triagem[]
  }

