    monitora_painel_assinatura_operacoes <- function(ops) {
      monitora_correcao_assinatura_operacoes(ops)
    }

    monitora_painel_agregar_operacoes_tokens <- function(ops) {
      ### Consolida operações repetidas no mesmo registro/campo antes de inseri-las
      ### na fila. Isso evita sequências do tipo "remove arvore" + "remove graminoide"
      ### com o mesmo valor_original_esperado, que geravam aviso de divergência após
      ### a primeira operação alterar o campo. A operação consolidada usa valor_novo
      ### multi-token, já suportado por monitora_correcao_remove_token_valor().
      ops <- data.table::as.data.table(ops)
      if (!nrow(ops)) return(ops)
      for (cc in c("acao", "valor_novo", "valor_original_esperado", "token_pai", "id_correcao", "ordem_operacao")) if (!(cc %in% names(ops))) data.table::set(ops, j = cc, value = NA_character_)
      grp_cols <- c(
        "tipo_correcao", "escopo_aplicacao", "coleta", "coleta_uuid", "uuid_registro",
        "ponto_amostral", "ponto_metro", "atributo_coluna_registros_corrig", "acao",
        "categoria_origem", "categoria_destino", "motivo"
      )
      for (cc in grp_cols) if (!(cc %in% names(ops))) data.table::set(ops, j = cc, value = NA_character_)
      acao_norm <- tolower(trimws(as.character(ops$acao)))
      idx_ag <- which(acao_norm %in% c("remove_token", "remover_token", "append_token", "adicionar_token"))
      if (length(idx_ag) < 2L) return(ops)
      y <- data.table::copy(ops[idx_ag])
      y[, .ordem_original_painel := idx_ag]
      y[, .grp_tmp := do.call(paste, c(lapply(.SD, function(v) { z <- as.character(v); z[is.na(z)] <- ""; z }), sep = "\r")), .SDcols = grp_cols]
      tab <- y[, .N, by = .grp_tmp]
      grupos_multi <- tab[N > 1L, .grp_tmp]
      if (!length(grupos_multi)) return(ops)
      y_ag <- y[.grp_tmp %in% grupos_multi]
      y_keep <- y[!(.grp_tmp %in% grupos_multi)]
      ag <- y_ag[, .SD[1L], by = .grp_tmp]
      vals <- y_ag[, .(
        valor_novo_agregado = monitora_correcao_colapsar_tokens(unlist(lapply(valor_novo, monitora_correcao_tokenizar), use.names = FALSE)),
        token_pai_agregado = monitora_correcao_colapsar_tokens(unlist(lapply(if ("token_pai" %in% names(.SD)) token_pai else valor_novo, monitora_correcao_tokenizar), use.names = FALSE)),
        ordem_min = suppressWarnings(min(as.integer(ordem_operacao), na.rm = TRUE)),
        n_ops_agregadas = .N
      ), by = .grp_tmp]
      ag[vals, on = ".grp_tmp", `:=`(
        valor_novo = i.valor_novo_agregado,
        token_pai = i.token_pai_agregado,
        ordem_operacao = ifelse(is.finite(i.ordem_min), as.character(i.ordem_min), ordem_operacao),
        motivo = paste0(motivo, " [", i.n_ops_agregadas, " operação(ões) de token agregada(s) antes da aplicação]")
      )]
      cols_tmp <- c(".grp_tmp", ".ordem_original_painel")
      for (cc in cols_tmp) {
        if (cc %in% names(ag)) ag[, (cc) := NULL]
        if (cc %in% names(y_keep)) y_keep[, (cc) := NULL]
      }
      out <- data.table::rbindlist(list(ops[-idx_ag], y_keep, ag), fill = TRUE, use.names = TRUE)
      if ("ordem_operacao" %in% names(out)) {
        out[, .ordem_num_tmp := suppressWarnings(as.integer(ordem_operacao))]
        data.table::setorder(out, id_correcao, .ordem_num_tmp, na.last = TRUE)
        out[, .ordem_num_tmp := NULL]
      }
      out[]
    }

    monitora_painel_normalizar_mvlote_antes_adicao <- function(ops, origem = "correção") {
      ops <- data.table::as.data.table(ops)
      if (!nrow(ops)) return(ops)
      idx_novo <- which(monitora_correcao_eh_operacao_movimento_forma_vida_lote(ops))
      if (!length(idx_novo)) return(ops)

      ### Dentro do próprio lote novo, manter apenas a intenção final por escopo
      ### diagnóstico. Isso impede que um duplo clique ou uma mudança de escolha
      ### produza histórico contraditório no correcoes_campos.csv.
      ops_norm <- monitora_correcao_normalizar_mvlote_sessao(ops, contexto = paste0("painel_adicao_", origem))
      aud_norm <- attr(ops_norm, "auditoria_normalizacao_mvlote")
      if (!is.null(aud_norm) && data.table::is.data.table(aud_norm) && nrow(aud_norm)) {
        try({
          rv$audit <- data.table::rbindlist(list(rv$audit, aud_norm), fill = TRUE, use.names = TRUE)
          monitora_correcao_console_msg("MVLOTE: ", nrow(aud_norm), " operação(ões) nova(s) substituída(s) antes de entrar na fila por escopo diagnóstico idêntico.")
        }, silent = TRUE)
      }
      ops <- data.table::as.data.table(ops_norm)
      idx_novo <- which(monitora_correcao_eh_operacao_movimento_forma_vida_lote(ops))
      if (!length(idx_novo)) return(ops)

      if (is.null(rv$correcoes) || !data.table::is.data.table(rv$correcoes) || !nrow(rv$correcoes)) return(ops)
      pend <- data.table::as.data.table(rv$correcoes)
      idx_pend <- which(monitora_correcao_eh_operacao_movimento_forma_vida_lote(pend))
      if (!length(idx_pend)) return(ops)
      sig_novo <- monitora_correcao_assinaturas_mvlote(ops[idx_novo])
      sig_pend <- monitora_correcao_assinaturas_mvlote(pend[idx_pend])
      remover_novos <- integer(0)
      remover_pend_rows <- integer(0)
      n_bloq_exata <- 0L
      n_subst <- 0L

      for (jj in seq_along(idx_novo)) {
        esc <- sig_novo$escopo[jj]
        sol <- sig_novo$solucao[jj]
        if (!nzchar(esc)) next
        pos <- which(sig_pend$escopo == esc)
        if (!length(pos)) next
        pos_exata <- pos[sig_pend$solucao[pos] == sol]
        if (length(pos_exata)) {
          remover_novos <- unique(c(remover_novos, idx_novo[jj]))
          n_bloq_exata <- n_bloq_exata + 1L
        } else {
          linhas_rm <- idx_pend[pos]
          ids_rm <- if ("id_correcao" %in% names(pend)) unique(as.character(pend$id_correcao[linhas_rm])) else character(0)
          ids_rm <- ids_rm[!is.na(ids_rm) & nzchar(ids_rm)]
          if (length(ids_rm) && "id_correcao" %in% names(pend)) {
            linhas_rm <- which(as.character(pend$id_correcao) %in% ids_rm)
          }
          remover_pend_rows <- unique(c(remover_pend_rows, linhas_rm))
          n_subst <- n_subst + 1L
        }
      }

      if (length(remover_pend_rows)) {
        rem <- pend[sort(unique(remover_pend_rows))]
        aud <- data.table::data.table(
          id_correcao = if ("id_correcao" %in% names(rem)) as.character(rem$id_correcao) else NA_character_,
          ordem_operacao = if ("ordem_operacao" %in% names(rem)) as.character(rem$ordem_operacao) else NA_character_,
          status = "substituida_por_operacao_posterior",
          mensagem = "MVLOTE pendente substituído no painel por nova operação com o mesmo escopo diagnóstico de linhas.",
          atributo = "__mover_forma_vida_lote__",
          linha_indice = NA_integer_, valor_antes = NA_character_, valor_depois = NA_character_, arquivo_correcao = "painel"
        )
        rv$audit <- data.table::rbindlist(list(rv$audit, aud), fill = TRUE, use.names = TRUE)
        rv$correcoes <- rv$correcoes[-sort(unique(remover_pend_rows))]
      }
      if (length(remover_novos)) ops <- ops[-sort(unique(remover_novos))]
      if (n_bloq_exata > 0L) {
        monitora_painel_notificar(paste0(n_bloq_exata, " MVLOTE(s) bloqueado(s): operação exatamente igual já está pendente para as mesmas linhas diagnósticas."), type = "warning", duration = 10)
        try(monitora_correcao_console_msg("MVLOTE: ", n_bloq_exata, " duplicata(s) exata(s) bloqueada(s) por escopo diagnóstico de linhas."), silent = TRUE)
      }
      if (n_subst > 0L) {
        monitora_painel_notificar(paste0(n_subst, " MVLOTE(s) pendente(s) substituído(s): mesma ocorrência diagnóstica, nova solução final."), type = "message", duration = 10)
        try(monitora_correcao_console_msg("MVLOTE: ", n_subst, " operação(ões) pendente(s) substituída(s) por nova solução no mesmo escopo diagnóstico."), silent = TRUE)
      }
      ops[]
    }

    monitora_painel_adicionar_ops_pendentes <- function(ops, origem = "correção") {
      if (is.null(ops)) return(0L)
      if (is.list(ops) && !data.table::is.data.table(ops)) {
        ops <- data.table::rbindlist(ops, fill = TRUE, use.names = TRUE)
      } else {
        ops <- data.table::as.data.table(ops)
      }
      if (!nrow(ops)) return(0L)
      ops <- monitora_painel_agregar_operacoes_tokens(ops)
      ops <- tryCatch(monitora_correcao_agrupar_operacoes_semanticas(ops), error = function(e) ops)
      ops <- monitora_painel_normalizar_mvlote_antes_adicao(ops, origem = origem)
      if (!nrow(ops)) return(0L)
      if ("atributo_coluna_registros_corrig" %in% names(ops)) {
        acao_op <- if ("acao" %in% names(ops)) ops$acao else rep("", nrow(ops))
        tipo_op <- if ("tipo_correcao" %in% names(ops)) ops$tipo_correcao else rep("", nrow(ops))
        exclusao_coleta_op <- mapply(
          function(acao_i, tipo_i) isTRUE(monitora_correcao_acao_exclusao_coleta(acao_i, tipo_i)),
          acao_op, tipo_op,
          USE.NAMES = FALSE
        )
        prot_op <- monitora_correcao_coluna_protegida(ops$atributo_coluna_registros_corrig) & !exclusao_coleta_op
        if (any(prot_op, na.rm = TRUE)) {
          n_prot <- sum(prot_op, na.rm = TRUE)
          ops <- ops[!prot_op]
          monitora_painel_notificar(paste0(n_prot, " ação(ões) bloqueada(s): coluna estrutural/protegida não pode ser corrigida no painel."), type = "error", duration = 10)
          if (!nrow(ops)) return(0L)
        }
      }
      sig_novas <- monitora_painel_assinatura_operacoes(ops)
      manter <- !duplicated(sig_novas)
      sig_existentes <- if (nrow(rv$correcoes)) monitora_painel_assinatura_operacoes(rv$correcoes) else character(0)
      manter <- manter & !(sig_novas %in% sig_existentes)
      n_bloq <- sum(!manter)
      ops_add <- ops[manter]
      if (nrow(ops_add)) {
        rv$correcoes <- data.table::rbindlist(list(rv$correcoes, ops_add), fill = TRUE, use.names = TRUE)
      }
      if (n_bloq > 0L) {
        monitora_painel_notificar(paste0(n_bloq, " ação(ões) repetida(s) não foram adicionadas às correções pendentes."), type = "warning", duration = 8)
      }
      nrow(ops_add)
    }

    monitora_painel_atributo_lote_sensivel <- function(col) {
      col <- as.character(col)[1L]
      if (is.na(col) || !nzchar(col)) return(FALSE)
      grepl("^UC$|^EA$|^UA$|^ANO$|^CICLO$|^CAMPANHA$|form_veg|data_hora|data \\(data_hora\\)|hor[aá]rio \\(data_hora\\)|data_do_registro|^data$|^hora$|coordenad|latitude|longitude|num_placa|protocolo", col, ignore.case = TRUE)
    }

    monitora_painel_escopo_efetivo_atributo <- function(atributo, escopo_input = monitora_painel_valor(input$escopo)) {
      atributo <- as.character(atributo)[1L]
      if (is.na(atributo) || !nzchar(atributo)) return(monitora_painel_valor(escopo_input))
      escopo <- monitora_painel_valor(escopo_input)
      papel_esc <- tryCatch(monitora_correcao_papel_coluna_canonico(atributo), error = function(e) "")
      categoria_esc <- tryCatch(monitora_painel_categoria_por_coluna_forma(atributo), error = function(e) NA_character_)
      if (identical(escopo, "linhas_pendentes_ocorrencia") && identical(papel_esc, "lista_principal_forma_vida") && categoria_esc %in% c("nativa", "exotica", "seca_morta")) return("linhas_pendentes_ocorrencia")
      info <- dict[atributo_coluna_registros_corrig == atributo]
      escopo_dict <- if (nrow(info) > 0L && "escopo_sugerido" %in% names(info)) info$escopo_sugerido[1L] else NA_character_
      if (isTRUE(monitora_painel_atributo_lote_sensivel(atributo)) || identical(escopo_dict, "coleta_inteira")) return("coleta_inteira")
      if (!nzchar(escopo)) "ponto" else escopo
    }

    monitora_painel_coletas_lote_validas <- function(vals, vals_validos) {
      vals <- unique(as.character(vals))
      vals <- vals[!is.na(vals) & nzchar(trimws(vals))]
      vals_validos <- unique(as.character(vals_validos))
      vals_validos <- vals_validos[!is.na(vals_validos) & nzchar(trimws(vals_validos))]
      vals[vals %in% vals_validos]
    }

    monitora_painel_valores_input <- function(vals) {
      vals <- unique(trimws(as.character(vals)))
      vals[!is.na(vals) & nzchar(vals)]
    }

    monitora_painel_resumo_lote_multicoletas <- function(x, coletas, atributo, n_esperado = 101L) {
      x <- data.table::as.data.table(x)
      coletas <- monitora_painel_coletas_lote_validas(coletas, monitora_painel_valores_coluna(x, chaves$coleta))
      atributo <- as.character(atributo)[1L]
      if (!length(coletas) || !monitora_painel_coluna_ok(chaves$coleta, x) || is.na(atributo) || !(atributo %in% names(x))) {
        return(data.table::data.table())
      }
      coleta_col <- chaves$coleta
      n_esperado <- suppressWarnings(as.integer(n_esperado)[1L])
      if (!is.finite(n_esperado) || n_esperado < 1L) n_esperado <- 101L
      colapsar <- function(v) monitora_correcao_colapsar_contexto_valores(v, max_valores = 8L)
      x_lote <- x[as.character(get(coleta_col)) %in% coletas]
      if (!nrow(x_lote)) return(data.table::data.table())
      res <- x_lote[, {
        vals <- as.character(get(atributo))
        vals_norm <- monitora_correcao_na_para_vazio(vals)
        vals_norm[is.na(vals_norm)] <- ""
        vals_norm <- trimws(vals_norm)
        .(
          n_linhas = .N,
          UC = if (monitora_painel_coluna_ok(chaves$uc, x_lote)) colapsar(get(chaves$uc)) else NA_character_,
          EA = if (monitora_painel_coluna_ok(chaves$ea, x_lote)) colapsar(get(chaves$ea)) else NA_character_,
          UA = if (monitora_painel_coluna_ok(chaves$ua, x_lote)) colapsar(get(chaves$ua)) else NA_character_,
          CICLO = if (monitora_painel_coluna_ok(chaves$ciclo, x_lote)) colapsar(get(chaves$ciclo)) else NA_character_,
          CAMPANHA = if (monitora_painel_coluna_ok(chaves$campanha, x_lote)) colapsar(get(chaves$campanha)) else NA_character_,
          ANO = if (monitora_painel_coluna_ok(chaves$ano, x_lote)) colapsar(get(chaves$ano)) else NA_character_,
          coleta_uuid = if (monitora_painel_coluna_ok(chaves$coleta_uuid, x_lote)) colapsar(get(chaves$coleta_uuid)) else NA_character_,
          n_valores_atuais = length(unique(vals_norm)),
          valor_atual = colapsar(vals)
        )
      }, by = .(coleta = as.character(get(coleta_col)))]
      ausentes <- setdiff(coletas, res$coleta)
      if (length(ausentes)) {
        res <- data.table::rbindlist(list(res, data.table::data.table(
          coleta = ausentes, n_linhas = 0L, UC = NA_character_, EA = NA_character_, UA = NA_character_,
          CICLO = NA_character_, CAMPANHA = NA_character_, ANO = NA_character_, coleta_uuid = NA_character_,
          n_valores_atuais = NA_integer_, valor_atual = NA_character_
        )), fill = TRUE, use.names = TRUE)
      }
      res[, n_linhas_esperado := n_esperado]
      res[, status_lote := data.table::fifelse(
        n_linhas != n_linhas_esperado,
        "bloqueio_n_linhas",
        data.table::fifelse(is.na(n_valores_atuais) | n_valores_atuais > 1L, "bloqueio_atributo_nao_uniforme", "ok")
      )]
      data.table::setorder(res, status_lote, coleta)
      res[]
    }

    monitora_painel_adicionar_movimento_pretriado <- function() {
      ### Converte uma ou mais linhas selecionadas na triagem de exóticas em
      ### operações auditáveis de movimento exótica -> nativa, preservando uma
      ### operação independente por ponto/forma de vida. A adição usa assinatura
      ### semântica para bloquear ações repetidas já pendentes na sessão.
      alvos <- if (!is.null(rv$movimento_alvo) && data.table::is.data.table(rv$movimento_alvo) && nrow(rv$movimento_alvo) > 0L) data.table::copy(rv$movimento_alvo) else data.table::data.table()
      if (!nrow(alvos)) return(FALSE)
      if ("tipo_triagem" %in% names(alvos)) alvos <- alvos[tipo_triagem == "exotica"]
      if ("status_vinculo" %in% names(alvos)) alvos <- alvos[!grepl("^erro_", status_vinculo)]
      if ("forma_vida_exotica" %in% names(alvos)) alvos <- alvos[!is.na(forma_vida_exotica) & nzchar(as.character(forma_vida_exotica))]
      if (!nrow(alvos)) {
        monitora_painel_notificar("Movimento exótica → nativa bloqueado: as linhas preparadas não são do tipo exótica.", type = "error", duration = 8)
        rv$movimento_alvo <- data.table::data.table()
        return(TRUE)
      }

      origem_val <- "exotica"
      destino_val <- "nativa"
      col_origem <- monitora_correcao_coluna_forma_vida(dt, origem_val)
      col_destino <- monitora_correcao_coluna_forma_vida(dt, destino_val)
      if (is.na(col_origem) || is.na(col_destino) || !(col_origem %in% names(dt)) || !(col_destino %in% names(dt))) {
        monitora_painel_notificar("Não foi possível localizar as colunas de forma de vida exótica/nativa; movimento bloqueado.", type = "error", duration = 8)
        return(TRUE)
      }

      ops_total <- list()
      bloqueadas <- 0L
      exige_habito <- character(0)
      for (aa in seq_len(nrow(alvos))) {
        alvo <- alvos[aa]
        forma_val <- monitora_painel_valor(alvo$forma_vida_exotica)
        uuid_val <- monitora_painel_valor(alvo$uuid_registro)
        coleta_val <- monitora_painel_valor(alvo$COLETA)
        ponto_val <- monitora_painel_valor(alvo$ponto_amostral)
        valor_original_origem <- monitora_painel_valor(alvo$forma_vida_exotica_original)
        if (!nzchar(forma_val)) { bloqueadas <- bloqueadas + 1L; next }

        linhas_globais <- integer(0)
        if (nzchar(uuid_val) && monitora_painel_coluna_ok(chaves$uuid_registro, dt)) {
          linhas_globais <- which(as.character(dt[[chaves$uuid_registro]]) == uuid_val)
        }
        if (length(linhas_globais) == 0L && nzchar(coleta_val) && nzchar(ponto_val) && monitora_painel_coluna_ok(chaves$coleta, dt) && monitora_painel_coluna_ok(chaves$ponto_amostral, dt)) {
          linhas_globais <- which(as.character(dt[[chaves$coleta]]) == coleta_val & as.character(dt[[chaves$ponto_amostral]]) == ponto_val)
        }
        if (length(linhas_globais) != 1L) { bloqueadas <- bloqueadas + 1L; next }

        forma_condicional <- forma_val %in% c("bromelioide", "erva_bromelioide", "cactacea", "orquidea", "samambaia")
        habito_val <- monitora_painel_valor(input$mv_habito)
        if (!nzchar(habito_val)) {
          habito_origem <- monitora_painel_valor(alvo$habito_exotica)
          if (nzchar(habito_origem) && habito_origem %in% c("terrestre", "epifita", "rupicola")) habito_val <- habito_origem
        }
        if (isTRUE(forma_condicional) && !nzchar(habito_val)) {
          exige_habito <- c(exige_habito, forma_val)
          next
        }

        motivo_val <- monitora_painel_valor(input$motivo)
        if (!nzchar(motivo_val)) motivo_val <- paste0("Movimento assistido a partir da triagem de exóticas: mover '", forma_val, "' de exótica para nativa.")
        id <- monitora_correcao_novo_id("MOVFV")
        esc <- "uuid_registro"
        uuid_arg <- ifelse(nzchar(uuid_val), uuid_val, NA_character_)
        ponto_arg <- ifelse(nzchar(ponto_val), ponto_val, NA_character_)
        valor_original_remove <- ifelse(nzchar(valor_original_origem), valor_original_origem, NA_character_)
        tokens_origem_remover <- unique(c(
          monitora_painel_forma_tokens_historicos_mv(forma_val),
          monitora_relatorio_exoticas_normalizar_token(forma_val),
          forma_val
        ))
        tokens_origem_remover <- unique(setdiff(tokens_origem_remover, MONITORA_TRIAGEM_TOKENS_OUTRAS))
        dep_destino <- NA_character_
        if (isTRUE(forma_condicional)) {
          dep_destino <- monitora_correcao_resolver_coluna_habito(dt, destino_val, forma_val, if (!is.null(meta_xls)) meta_xls$campos else NULL, linha = linhas_globais, meta_xls = meta_xls)
          if (!monitora_correcao_coluna_habito_segura(dt, dep_destino, destino_val, forma_val) || identical(dep_destino, col_destino)) {
            bloqueadas <- bloqueadas + 1L
            next
          }
        }
        op <- monitora_correcao_criar_operacao(
          id, input$responsavel, "movimento_forma_vida_atomico", 1L, esc, coleta_val,
          uuid_registro = uuid_arg, ponto_amostral = ponto_arg, atributo = "__mover_forma_vida__",
          acao = "mover_forma_vida", valor_original = valor_original_remove, valor_novo = forma_val,
          n_esperado = 1L, n_alvo = 1L, motivo = motivo_val,
          token_pai = forma_val, categoria_origem = origem_val, categoria_destino = destino_val,
          token_removido = monitora_correcao_colapsar_lista_serializada(tokens_origem_remover),
          campo_dependente_preenchido = ifelse(!is.na(dep_destino), dep_destino, NA_character_),
          habito_escolhido = ifelse(nzchar(habito_val), habito_val, NA_character_)
        )
        op <- monitora_correcao_anexar_contexto_operacao(op, dt, linhas_globais, chaves)
        ops_total <- c(ops_total, list(op))
      }

      if (length(exige_habito)) {
        monitora_painel_notificar(paste0("Movimento bloqueado para ", length(unique(exige_habito)), " forma(s) que exigem hábito. Informe terrestre/epifita/rupicola e tente novamente."), type = "error", duration = 12)
      }
      if (!length(ops_total)) {
        monitora_painel_notificar(paste0("Nenhuma linha pré-triada foi convertida em correção. Linhas bloqueadas: ", bloqueadas, "."), type = "error", duration = 10)
        return(TRUE)
      }
      n_add <- monitora_painel_adicionar_ops_pendentes(ops_total, origem = "movimento pretriado")
      rv$movimento_alvo <- data.table::data.table()
      n_pend <- monitora_painel_n_operacoes_semanticas(rv$correcoes)
      monitora_correcao_console_msg("Linha(s) pré-triada(s) convertida(s) em movimento assistido exótica -> nativa: ", n_add, " item(ns) auditável(is) novo(s); ", n_pend, " operação(ões) semântica(s) pendente(s) no total.")
      monitora_painel_notificar(paste0(n_add, " operação(ões) adicionada(s) a partir da triagem. Há ", n_pend, " operação(ões) semântica(s) pendente(s)."), type = if (n_add > 0L) "message" else "warning", duration = 10)
      monitora_painel_limpar_apos_correcao()
      return(TRUE)
    }

    monitora_painel_resolver_linhas_globais_triagem <- function(alvo) {
      if (is.null(alvo) || !nrow(alvo)) return(integer(0))
      if ("linha_indice_global" %in% names(alvo)) {
        li <- suppressWarnings(as.integer(alvo$linha_indice_global[1L]))
        if (!is.na(li) && li >= 1L && li <= nrow(dt)) return(li)
      }
      uuid_val <- monitora_painel_valor(alvo$uuid_registro)
      coleta_val <- monitora_painel_valor(alvo$COLETA)
      ponto_val <- monitora_painel_valor(alvo$ponto_amostral)
      linhas_globais <- integer(0)
      if (nzchar(uuid_val) && monitora_painel_coluna_ok(chaves$uuid_registro, dt)) {
        linhas_globais <- which(as.character(dt[[chaves$uuid_registro]]) == uuid_val)
      }
      if (length(linhas_globais) == 0L && nzchar(coleta_val) && nzchar(ponto_val) &&
          monitora_painel_coluna_ok(chaves$coleta, dt) && monitora_painel_coluna_ok(chaves$ponto_amostral, dt)) {
        linhas_globais <- which(as.character(dt[[chaves$coleta]]) == coleta_val & as.character(dt[[chaves$ponto_amostral]]) == ponto_val)
      }
      unique(linhas_globais)
    }

    monitora_painel_ops_limpar_dependentes_token <- function(id, responsavel, tipo, ordem_inicial, esc, coleta_val, uuid_arg, ponto_arg, token_val, categoria_val, motivo_val, n_exp = 1L, n_alvo = 1L) {
      ops <- list()
      if (!categoria_val %in% MONITORA_TRIAGEM_CATEGORIAS_FORMA || !nzchar(token_val)) return(ops)
      deps_cols <- monitora_correcao_colunas_dependentes_por_token(dt, categoria_val, token_val, meta_xls)
      deps_cols <- deps_cols[!is.na(deps_cols) & deps_cols %in% names(dt)]
      if (!length(deps_cols)) return(ops)
      ordem <- ordem_inicial
      for (dep_col in deps_cols) {
        ops[[length(ops) + 1L]] <- monitora_correcao_criar_operacao(
          id, responsavel, tipo, ordem, esc, coleta_val,
          uuid_registro = uuid_arg, ponto_amostral = ponto_arg, atributo = dep_col,
          acao = "clear", n_esperado = n_exp, n_alvo = n_alvo, motivo = motivo_val,
          token_pai = token_val, categoria_origem = categoria_val, categoria_destino = NA_character_
        )
        ordem <- ordem + 1L
      }
      ops
    }

    monitora_painel_ponto_tem_categoria_valida_apos_remocao <- function(linha_global, remocoes = data.table::data.table()) {
      if (length(linha_global) != 1L || is.na(linha_global) || linha_global < 1L || linha_global > nrow(dt)) return(TRUE)
      remocoes <- data.table::as.data.table(remocoes)
      if (!nrow(remocoes)) remocoes <- data.table::data.table(campo = character(), token = character())
      tem_valida <- FALSE
      for (cat in MONITORA_TRIAGEM_CATEGORIAS_FORMA) {
        cc <- monitora_painel_coluna_forma_categoria(cat, dt)
        if (is.na(cc) || !(cc %in% names(dt))) next
        toks <- monitora_correcao_tokenizar(dt[[cc]][linha_global])
        if (nrow(remocoes)) {
          toks_rem <- remocoes[campo == cc, token]
          toks <- setdiff(toks, toks_rem)
        }
        toks <- setdiff(monitora_relatorio_exoticas_normalizar_token(toks), MONITORA_TRIAGEM_TOKENS_INVALIDOS)
        toks <- toks[!is.na(toks) & nzchar(toks)]
        if (length(toks)) { tem_valida <- TRUE; break }
      }
      tipo_col <- chaves$tipo_forma_vida
      if (!tem_valida && !is.na(tipo_col) && tipo_col %in% names(dt)) {
        toks_tipo <- monitora_correcao_tokenizar(dt[[tipo_col]][linha_global])
        if (nrow(remocoes)) {
          toks_rem_tipo <- remocoes[campo == tipo_col, token]
          toks_tipo <- setdiff(toks_tipo, toks_rem_tipo)
        }
        ### nativa/exotica/seca_morta no tipo_forma_vida só são consideradas
        ### válidas se houver token real nas respectivas listas. Aqui contam
        ### solo_nu, serrapilheira/material botânico ou outros tokens materiais.
        toks_tipo_extra <- setdiff(toks_tipo, c(MONITORA_TRIAGEM_TOKENS_INVALIDOS, MONITORA_TRIAGEM_CATEGORIAS_FORMA))
        toks_tipo_extra <- toks_tipo_extra[!is.na(toks_tipo_extra) & nzchar(toks_tipo_extra)]
        if (length(toks_tipo_extra)) tem_valida <- TRUE
      }
      isTRUE(tem_valida)
    }

    monitora_painel_adicionar_substituicao_desconhecida <- function() {
      ex <- triagem_formas_vida_coleta()
      sel <- input$tabela_exoticas_rows_selected
      if (length(sel) < 1L || nrow(ex) == 0L || any(sel < 1L | sel > nrow(ex))) {
        monitora_painel_notificar("Selecione uma ou mais linhas de forma de vida desconhecida na triagem.", type = "error", duration = 8)
        return(NULL)
      }
      r <- ex[unique(as.integer(sel))]
      n_sel <- nrow(r)
      r <- r[tipo_triagem == "forma_vida_desconhecida"]
      if (nrow(r) < n_sel) {
        monitora_painel_notificar(paste0(n_sel - nrow(r), " linha(s) não eram de forma de vida desconhecida e foram ignoradas nesta ação."), type = "warning", duration = 8)
      }
      if (!nrow(r)) {
        monitora_painel_notificar("Esta ação só se aplica a linhas tipo_triagem = 'forma_vida_desconhecida'.", type = "error", duration = 8)
        return(NULL)
      }
      destino_val <- monitora_painel_valor(input$triagem_destino_desconhecida)
      forma_val <- monitora_painel_canonizar_forma_habito(monitora_painel_valor(input$triagem_forma_valida))
      habito_val <- monitora_painel_valor(input$triagem_habito)
      if (!destino_val %in% MONITORA_TRIAGEM_CATEGORIAS_FORMA || !nzchar(forma_val)) {
        monitora_painel_notificar("Escolha a lista de destino e uma forma de vida válida antes de substituir desconhecida.", type = "error", duration = 8)
        return(NULL)
      }
      if (monitora_painel_forma_exige_habito(forma_val) && !nzchar(habito_val)) {
        monitora_painel_notificar("A forma escolhida exige hábito: terrestre, epifita ou rupicola.", type = "error", duration = 10)
        return(NULL)
      }
      if (!monitora_painel_forma_exige_habito(forma_val) && nzchar(habito_val)) {
        monitora_painel_notificar("Hábito só pode ser informado para cactácea, erva bromelioide, orquídea ou samambaia. A correção foi bloqueada.", type = "error", duration = 10)
        return(NULL)
      }
      linhas_total <- integer(0)
      bloqueadas <- 0L
      for (aa in seq_len(nrow(r))) {
        li <- monitora_painel_resolver_linhas_globais_triagem(r[aa])
        if (length(li) != 1L) { bloqueadas <- bloqueadas + 1L; next }
        linhas_total <- c(linhas_total, li)
      }
      linhas_total <- unique(as.integer(linhas_total))
      linhas_total <- linhas_total[!is.na(linhas_total) & linhas_total >= 1L & linhas_total <= nrow(dt)]
      if (!length(linhas_total)) {
        monitora_painel_notificar(paste0("Nenhuma linha global foi localizada para substituição agrupada de desconhecida. Linhas bloqueadas: ", bloqueadas, "."), type = "error", duration = 10)
        return(NULL)
      }
      col_destino <- monitora_painel_coluna_forma_categoria(destino_val, dt)
      if (is.na(col_destino) || !monitora_correcao_coluna_principal_segura(dt, col_destino, destino_val)) {
        monitora_painel_notificar("Não foi possível localizar com segurança a lista principal de forma de vida de destino. Correção bloqueada para preservar integridade.", type = "error", duration = 10)
        return(NULL)
      }
      if (monitora_painel_forma_exige_habito(forma_val)) {
        dep_destino <- tryCatch(monitora_correcao_resolver_coluna_habito(dt, destino_val, forma_val, if (!is.null(meta_xls)) meta_xls$campos else NULL, linha = linhas_total[1L], meta_xls = meta_xls), error = function(e) NA_character_)
        if (!monitora_correcao_coluna_habito_segura(dt, dep_destino, destino_val, forma_val) || identical(dep_destino, col_destino)) {
          monitora_painel_notificar("Coluna de hábito segura não foi localizada para a forma de destino. Operação agrupada bloqueada.", type = "error", duration = 10)
          return(NULL)
        }
      } else {
        dep_destino <- NA_character_
      }
      motivo_val <- monitora_painel_valor(input$motivo)
      if (!nzchar(motivo_val)) motivo_val <- paste0("Triagem assistida em lote: substituir forma de vida desconhecida por '", forma_val, "' na lista ", destino_val, ".")
      coletas_desc <- if (!is.na(chaves$coleta) && chaves$coleta %in% names(dt)) unique(as.character(dt[[chaves$coleta]][linhas_total])) else character(0)
      uuids_desc <- if (!is.na(chaves$uuid_registro) && chaves$uuid_registro %in% names(dt)) unique(as.character(dt[[chaves$uuid_registro]][linhas_total])) else character(0)
      id <- monitora_correcao_novo_id("TRIDESC_LOTE")
      op <- monitora_correcao_criar_operacao(
        id, input$responsavel, "triagem_substituir_desconhecida_atomica", 1L, "linhas_pendentes_ocorrencia_diagnostica",
        coleta = if (length(coletas_desc)) monitora_correcao_colapsar_lista_serializada(coletas_desc) else NA_character_,
        uuid_registro = if (length(uuids_desc)) monitora_correcao_colapsar_lista_serializada(uuids_desc) else NA_character_,
        ponto_amostral = NA_character_, atributo = "__substituir_desconhecida__", acao = "substituir_desconhecida",
        valor_original = "desconhecida", valor_novo = forma_val, n_esperado = length(linhas_total), n_alvo = length(linhas_total),
        motivo = paste0(motivo_val, " [TRIDESC_LOTE: ", length(unique(coletas_desc)), " COLETA(s); ", length(linhas_total), " linha(s)-alvo; 1 operação semântica agrupada]"),
        token_pai = "desconhecida", categoria_origem = "desconhecida", categoria_destino = destino_val,
        tipo_triagem = "forma_vida_desconhecida", token_removido = "desconhecida",
        forma_valida_escolhida = forma_val, lista_destino = destino_val,
        campo_dependente_preenchido = ifelse(!is.na(dep_destino), dep_destino, NA_character_),
        habito_escolhido = ifelse(nzchar(habito_val), habito_val, NA_character_)
      )
      op[, `:=`(
        linhas_alvo_serializadas = monitora_correcao_colapsar_lista_serializada(as.character(linhas_total)),
        n_itens_auditaveis = length(linhas_total),
        operacao_semantica_agrupada = TRUE
      )]
      op <- monitora_correcao_anexar_contexto_operacao(op, dt, linhas_total, chaves)
      n_add <- monitora_painel_adicionar_ops_pendentes(list(op), origem = "triagem desconhecida agrupada")
      n_pend <- monitora_painel_n_operacoes_semanticas(rv$correcoes)
      monitora_painel_notificar(paste0("Substituição agrupada de desconhecida adicionada: ", length(linhas_total), " item(ns) auditável(is) em ", length(unique(coletas_desc)), " COLETA(s), 1 operação semântica. Há ", n_pend, " operação(ões) pendente(s)."), type = if (n_add > 0L) "message" else "warning", duration = 12)
      monitora_correcao_console_msg("Triagem desconhecida agrupada: ", n_add, " operação semântica; itens_auditaveis=", length(linhas_total), "; linhas bloqueadas=", bloqueadas, ".")
      monitora_painel_limpar_apos_correcao()
      invisible(NULL)
    }

    monitora_painel_criar_op_limpeza_outras_atomica <- function(id, linhas_alvo, escopo_val, coleta_serial = NA_character_, ponto_val = NA_character_, motivo_val = NA_character_) {
      linhas_alvo <- unique(as.integer(linhas_alvo))
      linhas_alvo <- linhas_alvo[!is.na(linhas_alvo) & linhas_alvo >= 1L & linhas_alvo <= nrow(dt)]
      if (!length(linhas_alvo)) return(NULL)
      if (!nzchar(monitora_painel_valor(motivo_val))) motivo_val <- "Limpeza atômica de outra(s) forma(s) de vida: remover tokens históricos e limpar descritores dependentes."

      ### v2.6.1: TRIOUT é gravada por ocorrência diagnóstica estável.
      ### Cada item recebe UUID/contexto próprios. A etapa de agrupamento semântico
      ### pode compactar os itens sob o mesmo id_correcao, mas preserva a lista de
      ### UUIDs/chaves; assim exclusões de COLETA não deslocam o alvo operacional.
      ops <- vector("list", length(linhas_alvo))
      linhas_serial_total <- monitora_correcao_colapsar_lista_serializada(as.character(linhas_alvo))
      for (ii in seq_along(linhas_alvo)) {
        li <- as.integer(linhas_alvo[ii])
        op_i <- monitora_correcao_criar_operacao(
          id,
          input$responsavel,
          "triagem_limpeza_outras_formas_vida_atomica",
          ii,
          "linhas_diagnosticas_ocorrencia",
          coleta = coleta_serial,
          ponto_amostral = ifelse(nzchar(monitora_painel_valor(ponto_val)), ponto_val, NA_character_),
          linha_indice = li,
          atributo = "__limpar_outras_formas_vida__",
          acao = "limpar_outras_formas_vida",
          valor_original = as.character(li),
          valor_novo = "outras_formas_vida",
          n_esperado = length(linhas_alvo),
          n_alvo = length(linhas_alvo),
          motivo = motivo_val,
          token_pai = "outra",
          categoria_origem = "outras_formas_vida",
          categoria_destino = NA_character_,
          tipo_triagem = "outras_formas_vida"
        )
        op_i[, `:=`(
          linhas_alvo_serializadas = as.character(li),
          linhas_alvo_serializadas_operacao = linhas_serial_total,
          n_itens_auditaveis = 1L,
          operacao_semantica_agrupada = TRUE,
          escopo_diagnostico_mvlote = NA_character_,
          categoria_base_diagnostica = "outras_formas_vida"
        )]
        op_i <- monitora_correcao_anexar_contexto_operacao(op_i, dt, li, chaves)
        data.table::set(op_i, j = "linha_indice", value = li)
        ops[[ii]] <- op_i
      }
      data.table::rbindlist(ops, fill = TRUE, use.names = TRUE)
    }

    monitora_painel_adicionar_limpeza_outras_escopo <- function() {
      motivo_val <- monitora_painel_valor(input$motivo)
      if (!nzchar(motivo_val)) motivo_val <- "Limpeza atômica de outra(s) forma(s) de vida no escopo selecionado."
      linhas_alvo <- integer(0)
      escopo_op <- "linhas_alvo"
      coleta_serial <- NA_character_
      ponto_val <- monitora_painel_valor(input$ponto)
      if (isTRUE(monitora_painel_usar_lote_coletas())) {
        coletas <- coletas_lote_selecionadas()
        if (!length(coletas)) {
          monitora_painel_notificar("Selecione COLETAS na lista 'COLETAS do lote'.", type = "error", duration = 8)
          return(NULL)
        }
        if (length(coletas) > 1L && !isTRUE(input$confirmar_abrangencia)) {
          monitora_painel_notificar("Lote com múltiplas COLETAS exige confirmação de abrangência.", type = "error", duration = 8)
          return(NULL)
        }
        if (is.na(chaves$coleta) || !(chaves$coleta %in% names(dt))) {
          monitora_painel_notificar("Coluna COLETA não localizada; limpeza em lote bloqueada.", type = "error", duration = 8)
          return(NULL)
        }
        linhas_alvo <- which(as.character(dt[[chaves$coleta]]) %chin% as.character(coletas))
        escopo_op <- "lote_coletas"
        coleta_serial <- monitora_correcao_colapsar_lista_serializada(coletas)
        if (identical(input$escopo, "ponto") && nzchar(ponto_val) && !is.na(chaves$ponto_amostral) && chaves$ponto_amostral %in% names(dt)) {
          linhas_alvo <- linhas_alvo[as.character(dt[[chaves$ponto_amostral]][linhas_alvo]) == ponto_val]
          escopo_op <- "multicoletas_atomico"
        }
      } else {
        coleta_val <- monitora_painel_valor(input$coleta)
        if (!nzchar(coleta_val) || is.na(chaves$coleta) || !(chaves$coleta %in% names(dt))) {
          monitora_painel_notificar("Selecione uma COLETA válida para a limpeza atômica.", type = "error", duration = 8)
          return(NULL)
        }
        linhas_alvo <- which(as.character(dt[[chaves$coleta]]) == coleta_val)
        coleta_serial <- coleta_val
        escopo_op <- if (identical(input$escopo, "ponto")) "ponto" else "coleta_inteira"
        if (identical(input$escopo, "ponto")) {
          if (!nzchar(ponto_val) || is.na(chaves$ponto_amostral) || !(chaves$ponto_amostral %in% names(dt))) {
            monitora_painel_notificar("Selecione um ponto amostral válido para escopo = ponto.", type = "error", duration = 8)
            return(NULL)
          }
          linhas_alvo <- linhas_alvo[as.character(dt[[chaves$ponto_amostral]][linhas_alvo]) == ponto_val]
        }
        if (length(linhas_alvo) > 1L && !isTRUE(input$confirmar_abrangencia)) {
          monitora_painel_notificar("Escopo com múltiplas linhas exige confirmação de abrangência.", type = "error", duration = 8)
          return(NULL)
        }
      }
      linhas_alvo <- unique(as.integer(linhas_alvo))
      linhas_alvo <- linhas_alvo[!is.na(linhas_alvo) & linhas_alvo >= 1L & linhas_alvo <= nrow(dt)]
      if (!length(linhas_alvo)) {
        monitora_painel_notificar("Nenhuma linha-alvo localizada para limpeza atômica.", type = "error", duration = 8)
        return(NULL)
      }
      cols_info <- monitora_correcao_colunas_limpeza_outras_formas(dt, if (!is.null(meta_xls)) meta_xls$campos else NULL)
      resumo <- monitora_correcao_contar_residuos_outras_formas(dt, linhas_alvo, cols_info)
      linhas_residuo <- monitora_correcao_linhas_residuo_outras_formas(dt, linhas_alvo, cols_info)
      if (resumo$linhas_com_residuo_total[1L] == 0L || !length(linhas_residuo)) {
        monitora_painel_notificar("O escopo selecionado não contém resíduos de outra(s) forma(s) de vida detectáveis.", type = "warning", duration = 8)
        return(NULL)
      }
      ### v2.6.1 motor único: a COLETA seleciona o universo, mas a operação
      ### TRIOUT gravada é apenas nas linhas diagnósticas com resíduo real.
      linhas_alvo_original <- linhas_alvo
      linhas_alvo <- unique(as.integer(linhas_residuo))
      escopo_op <- "linhas_diagnosticas_ocorrencia"
      id <- monitora_correcao_novo_id("TRIOUT_ATOM")
      op <- monitora_painel_criar_op_limpeza_outras_atomica(id, linhas_alvo, escopo_op, coleta_serial, ponto_val, motivo_val)
      if (is.null(op) || !nrow(op)) return(NULL)
      n_add <- monitora_painel_adicionar_ops_pendentes(list(op), origem = "limpeza atômica outras formas de vida")
      monitora_painel_notificar(paste0(n_add, " operação atômica adicionada para ", length(linhas_alvo), " linha(s) diagnóstica(s) com resíduo de outra forma de vida. Universo filtrado: ", length(linhas_alvo_original), " linha(s)."), type = if (n_add > 0L) "message" else "warning", duration = 10)
      monitora_correcao_console_msg("Limpeza atômica outras formas: ", n_add, " operação adicionada; linhas_alvo=", length(linhas_alvo), "; universo_filtrado=", length(linhas_alvo_original), "; residuos=", resumo$linhas_com_residuo_total[1L], ".")
      monitora_painel_limpar_apos_correcao()
      invisible(NULL)
    }

    monitora_painel_adicionar_remocao_outras <- function() {
      ex <- triagem_formas_vida_coleta()
      sel <- input$tabela_exoticas_rows_selected
      if (length(sel) < 1L || nrow(ex) == 0L || any(sel < 1L | sel > nrow(ex))) {
        monitora_painel_notificar("Selecione uma ou mais linhas de outras formas de vida na triagem.", type = "error", duration = 8)
        return(NULL)
      }
      r <- ex[unique(as.integer(sel))]
      n_sel <- nrow(r)
      r <- r[tipo_triagem == "outras_formas_vida"]
      if (nrow(r) < n_sel) {
        monitora_painel_notificar(paste0(n_sel - nrow(r), " linha(s) não eram de outras formas de vida e foram ignoradas nesta ação."), type = "warning", duration = 8)
      }
      if (!nrow(r)) {
        monitora_painel_notificar("Esta ação só se aplica a linhas tipo_triagem = 'outras_formas_vida'.", type = "error", duration = 8)
        return(NULL)
      }
      linhas_total <- integer(0)
      for (aa in seq_len(nrow(r))) {
        linhas_total <- c(linhas_total, monitora_painel_resolver_linhas_globais_triagem(r[aa]))
      }
      linhas_total <- unique(as.integer(linhas_total))
      linhas_total <- linhas_total[!is.na(linhas_total) & linhas_total >= 1L & linhas_total <= nrow(dt)]
      if (!length(linhas_total)) {
        monitora_painel_notificar("Nenhuma linha global foi localizada para as linhas selecionadas na triagem.", type = "error", duration = 8)
        return(NULL)
      }
      motivo_val <- monitora_painel_valor(input$motivo)
      if (!nzchar(motivo_val)) motivo_val <- "Triagem assistida: limpeza atômica de outra(s) forma(s) de vida selecionadas."
      cols_info <- monitora_correcao_colunas_limpeza_outras_formas(dt, if (!is.null(meta_xls)) meta_xls$campos else NULL)
      resumo <- monitora_correcao_contar_residuos_outras_formas(dt, linhas_total, cols_info)
      if (resumo$linhas_com_residuo_total[1L] == 0L) {
        monitora_painel_notificar("As linhas selecionadas não contêm resíduos detectáveis de outra(s) forma(s) de vida.", type = "warning", duration = 8)
        return(NULL)
      }
      id <- monitora_correcao_novo_id("TRIOUT_ATOM")
      coleta_serial <- if (chaves$coleta %in% names(dt)) monitora_correcao_colapsar_lista_serializada(unique(as.character(dt[[chaves$coleta]][linhas_total]))) else NA_character_
      op <- monitora_painel_criar_op_limpeza_outras_atomica(id, linhas_total, "linhas_alvo", coleta_serial, NA_character_, motivo_val)
      n_add <- monitora_painel_adicionar_ops_pendentes(list(op), origem = "triagem outras formas de vida atômica")
      monitora_painel_notificar(paste0(n_add, " operação atômica adicionada para limpar ", resumo$linhas_com_residuo_total[1L], " linha(s) selecionada(s) com outras formas de vida."), type = if (n_add > 0L) "message" else "warning", duration = 10)
      monitora_correcao_console_msg("Triagem outras formas de vida atômica: ", n_add, " operação adicionada; linhas_alvo=", length(linhas_total), "; residuos=", resumo$linhas_com_residuo_total[1L], ".")
      monitora_painel_limpar_apos_correcao()
      invisible(NULL)
    }

    monitora_painel_selecao_restringe <- function(vals, universo) {
      vals <- monitora_painel_valores_input(vals)
      universo <- monitora_painel_valores_input(universo)
      vals <- vals[vals %in% universo]
      length(vals) > 0L && length(universo) > 0L && length(setdiff(universo, vals)) > 0L
    }

    monitora_painel_filtrar_multi <- function(x, col, vals, universo = NULL) {
      x <- data.table::as.data.table(x)
      if (is.na(col) || !nzchar(col) || !(col %in% names(x))) return(x)
      universo <- if (is.null(universo)) monitora_painel_valores_coluna(x, col) else monitora_painel_valores_input(universo)
      vals <- monitora_painel_valores_input(vals)
      vals <- vals[vals %in% universo]
      if (!monitora_painel_selecao_restringe(vals, universo)) return(x)
      x[as.character(get(col)) %in% vals]
    }

    monitora_painel_preservar_selecao <- function(vals, universo) {
      vals <- monitora_painel_valores_input(vals)
      universo <- monitora_painel_valores_input(universo)
      vals[vals %in% universo]
    }

    monitora_painel_update_selectize_multi <- function(id, vals, selected = NULL, server = TRUE) {
      vals <- monitora_painel_valores_input(vals)
      selected <- monitora_painel_preservar_selecao(if (is.null(selected)) character(0) else selected, vals)
      shiny::updateSelectizeInput(session, id, choices = vals, selected = selected, server = server)
    }

