      x <- dados_filtrados()
      cols <- unique(na.omit(c(chaves$coleta, chaves$uc, chaves$ea, chaves$ano, chaves$ciclo, chaves$campanha, chaves$ua, chaves$ponto_amostral, chaves$ponto_metro, chaves$uuid_registro, input$atributo)))
