monitora_relatorio_exoticas_eh_coluna_especie <- function(cols) {
  z <- monitora_relatorio_exoticas_normalizar_token(cols)
  padrao <- grepl("(^|_)especies_exotica(_|$)", z) |
    grepl("(^|_)exotica_[a-z0-9_]*_outra_sp$", z) |
    (grepl("especies", z) & grepl("exotic", z)) |
    (grepl("outra_especie", z) & grepl("exotic", z))
  excluir <- z %in% c("id", "id_", "_id") |
    grepl("(^|_)id$", z) |
    grepl("foto", z) |
    grepl("^amostragem_registro_forma_vida_exotica", z) |
    grepl("^forma_vida_exotica", z) |
    grepl("desconhecida", z)
  padrao & !excluir
}

monitora_relatorio_exoticas_detectar_colunas_especies <- function(dt) {
  preferenciais <- monitora_relatorio_exoticas_campos_especies_preferenciais()
  cols <- monitora_relatorio_exoticas_resolver_colunas(dt, preferenciais, permitir_multiplas = TRUE)
  nms <- names(dt)
  nms_norm <- monitora_relatorio_exoticas_normalizar_token(nms)
  padrao <- grepl("(^|_)especies_exotica(_|$)", nms_norm) |
    grepl("(^|_)exotica_[a-z0-9_]*_outra_sp$", nms_norm) |
    (grepl("especies", nms_norm) & grepl("exotic", nms_norm)) |
    (grepl("outra_especie", nms_norm) & grepl("exotic", nms_norm))
  candidatos <- unique(c(cols, nms[padrao]))
  candidatos <- candidatos[candidatos %in% nms]
  candidatos <- candidatos[monitora_relatorio_exoticas_eh_coluna_especie(candidatos)]
  unique(candidatos)
}


### Cache leve de descoberta de colunas diagnósticas. Em conjuntos históricos
### amplos, concatenar todos os nomes de colunas como chave pode ultrapassar o
### limite interno do R para nomes de variáveis em environments (>10.000 bytes).
### Por isso a assinatura do esquema é reduzida a hash curto e todo acesso ao
### cache é protegido: cache é otimização, nunca pré-condição de execução.
.MONITORA_RELATORIO_COLUNAS_CACHE <- new.env(parent = emptyenv())
.MONITORA_RELATORIO_EXOTICAS_DETECTAR_COLUNAS_FORMA <- monitora_relatorio_exoticas_detectar_colunas_forma
.MONITORA_RELATORIO_EXOTICAS_DETECTAR_COLUNAS_ESPECIES <- monitora_relatorio_exoticas_detectar_colunas_especies
monitora_cache_hash_texto_curto <- function(txt) {
  txt <- enc2utf8(as.character(txt)[1L])
  if (is.na(txt)) txt <- ""
  rr <- as.integer(charToRaw(txt))
  if (!length(rr)) return("00000000_00000000")
  ii <- seq_along(rr)
  h1 <- sum((rr + 1L) * ((ii %% 104729L) + 1L)) %% 2147483647
  h2 <- sum((rr + 17L) * (((ii * 131L) %% 130363L) + 1L)) %% 2147483629
  paste0(sprintf("%08x", as.integer(h1)), "_", sprintf("%08x", as.integer(h2)))
}
monitora_relatorio_esquema_chave_cache <- function(dt, sufixo) {
  nm <- names(dt)
  assinatura <- paste0(length(nm), "::", paste(nm, collapse = "\r"))
  paste0("relatorio_", sufixo, "_", monitora_cache_hash_texto_curto(assinatura))
}
monitora_relatorio_cache_get <- function(key) {
  if (!isTRUE(monitora_global_get("MONITORA_CACHE_RELATORIOS_HABILITADO", TRUE))) return(NULL)
  key <- as.character(key)[1L]
  if (is.na(key) || !nzchar(key) || nchar(key, type = "bytes") > 200L) return(NULL)
  tryCatch({
    if (exists(key, envir = .MONITORA_RELATORIO_COLUNAS_CACHE, inherits = FALSE)) {
      get(key, envir = .MONITORA_RELATORIO_COLUNAS_CACHE, inherits = FALSE)
    } else NULL
  }, error = function(e) {
    if (exists("monitora_log_registrar_evento", mode = "function")) {
      monitora_log_registrar_evento("cache_relatorios", "AVISO", NA_character_, paste0("Falha ao consultar cache de colunas: ", conditionMessage(e)), "seguindo sem cache")
    }
    NULL
  })
}
monitora_relatorio_cache_set <- function(key, value) {
  if (!isTRUE(monitora_global_get("MONITORA_CACHE_RELATORIOS_HABILITADO", TRUE))) return(invisible(FALSE))
  key <- as.character(key)[1L]
  if (is.na(key) || !nzchar(key) || nchar(key, type = "bytes") > 200L) return(invisible(FALSE))
  tryCatch({
    assign(key, value, envir = .MONITORA_RELATORIO_COLUNAS_CACHE)
    invisible(TRUE)
  }, error = function(e) {
    if (exists("monitora_log_registrar_evento", mode = "function")) {
      monitora_log_registrar_evento("cache_relatorios", "AVISO", NA_character_, paste0("Falha ao gravar cache de colunas: ", conditionMessage(e)), "seguindo sem cache")
    }
    invisible(FALSE)
  })
}
monitora_relatorio_exoticas_detectar_colunas_forma <- function(dt) {
  key <- monitora_relatorio_esquema_chave_cache(dt, "forma")
  val_cache <- monitora_relatorio_cache_get(key)
  if (!is.null(val_cache)) return(val_cache)
  val <- tryCatch(monitora_correcao_colunas_forma_vida_categoria(dt, "exotica"), error = function(e) character(0))
  val <- val[!is.na(val) & nzchar(val) & val %in% names(dt)]
  if (!length(val)) val <- .MONITORA_RELATORIO_EXOTICAS_DETECTAR_COLUNAS_FORMA(dt)
  val <- unique(val)
  monitora_relatorio_cache_set(key, val)
  val
}
monitora_relatorio_exoticas_detectar_colunas_especies <- function(dt) {
  key <- monitora_relatorio_esquema_chave_cache(dt, "especies")
  val_cache <- monitora_relatorio_cache_get(key)
  if (!is.null(val_cache)) return(val_cache)
  mapa <- tryCatch(monitora_correcao_mapa_colunas_canonicas(dt), error = function(e) data.table::data.table())
  if (nrow(mapa)) {
    val <- mapa[papel_coluna == "especie_nome_popular" & (categoria == "exotica" | grepl("exotic|exotica|exotico", coluna_norm)), coluna_registros_corrig]
    val <- unique(val[!is.na(val) & nzchar(val) & val %in% names(dt)])
  } else {
    val <- character(0)
  }
  if (!length(val)) val <- .MONITORA_RELATORIO_EXOTICAS_DETECTAR_COLUNAS_ESPECIES(dt)
  val <- unique(val)
  monitora_relatorio_cache_set(key, val)
  val
}

monitora_relatorio_exoticas_tokens_forma <- function() {
  c(
    "graminoide", "erva_nao_graminoide", "ervas_de_passarinho", "bromelioide",
    "erva_bromelioide", "cactacea", "orquidea", "samambaia", "arbusto_abaixo",
    "arbusto_acima", "arvore_abaixo", "arvore_acima", "bambu", "liana", "lianas",
    "palmeira", "outros", "desconhecida"
  )
}

monitora_relatorio_exoticas_valor_especie_valido <- function(x) {
  z <- monitora_relatorio_exoticas_normalizar_texto(x)
  invalido <- monitora_relatorio_exoticas_sem_valor(z)
  zn <- monitora_relatorio_exoticas_normalizar_token(z)
  tokens_forma <- monitora_relatorio_exoticas_normalizar_token(monitora_relatorio_exoticas_tokens_forma())
  tokens_outra_sem_texto <- grepl("_outra_sp$", zn)
  invalido | zn %in% tokens_forma | tokens_outra_sem_texto
}

monitora_relatorio_exoticas_tem_especie_valida <- function(x) {
  !monitora_relatorio_exoticas_valor_especie_valido(x)
}

monitora_relatorio_exoticas_mapa_forma_especie <- function(especie_cols) {
  z <- monitora_relatorio_exoticas_normalizar_token(especie_cols)
  list(
    graminoide = especie_cols[(grepl("graminoide", z) & !grepl("nao_graminoide", z))],
    erva_nao_graminoide = especie_cols[grepl("erva_nao_graminoide|ervas_nao_graminoides|nao_graminoide", z)],
    arbusto_abaixo = especie_cols[grepl("arbusto", z) & grepl("abaixo|inferior|menor|0_5", z)],
    arbusto_acima = especie_cols[grepl("arbusto", z) & grepl("acima|superior|igual", z)],
    arvore_abaixo = especie_cols[grepl("arvore", z) & grepl("abaixo|menor|5cm|5_cm", z) & !grepl("acima|maior|igual", z)],
    arvore_acima = especie_cols[grepl("arvore", z) & grepl("acima|maior|igual", z)],
    bambu = especie_cols[grepl("bambu", z)],
    liana = especie_cols[grepl("liana", z)],
    lianas = especie_cols[grepl("liana", z)],
    ervas_de_passarinho = especie_cols[grepl("ervas_de_passarinho", z)],
    palmeira = especie_cols[grepl("palmeira", z)],
    bromelioide = especie_cols[grepl("bromelioide", z)],
    erva_bromelioide = especie_cols[grepl("bromelioide", z)],
    cactacea = especie_cols[grepl("cactacea|cacto", z)],
    orquidea = especie_cols[grepl("orquidea", z)],
    samambaia = especie_cols[grepl("samambaia", z)],
    outros = especie_cols[grepl("outros|outras|outra_especie_exotica", z)]
  )
}


monitora_relatorio_exoticas_colapsar_valores <- function(dt, cols, incluir_nomes = FALSE, validador = monitora_relatorio_exoticas_tem_valor) {
  n <- nrow(dt)
  if (!n) return(character(0))
  cols <- unique(cols[cols %in% names(dt)])
  if (!length(cols)) return(rep("", n))
  out <- rep("", n)
  for (cc in cols) {
    vals <- monitora_relatorio_exoticas_normalizar_texto(dt[[cc]])
    ok <- validador(vals)
    ok[is.na(ok)] <- FALSE
    if (!any(ok)) next
    add <- if (isTRUE(incluir_nomes)) paste0(cc, " = ", vals) else vals
    idx <- which(ok)
    vazio <- !nzchar(out[idx])
    if (any(vazio)) out[idx[vazio]] <- add[idx[vazio]]
    if (any(!vazio)) out[idx[!vazio]] <- paste(out[idx[!vazio]], add[idx[!vazio]], sep = " | ")
  }
  out
}

monitora_relatorio_exoticas_colapsar_campos <- function(dt, cols, validador = monitora_relatorio_exoticas_tem_valor) {
  n <- nrow(dt)
  if (!n) return(character(0))
  cols <- unique(cols[cols %in% names(dt)])
  if (!length(cols)) return(rep("", n))
  out <- rep("", n)
  for (cc in cols) {
    vals <- monitora_relatorio_exoticas_normalizar_texto(dt[[cc]])
    ok <- validador(vals)
    ok[is.na(ok)] <- FALSE
    if (!any(ok)) next
    idx <- which(ok)
    vazio <- !nzchar(out[idx])
    if (any(vazio)) out[idx[vazio]] <- cc
    if (any(!vazio)) out[idx[!vazio]] <- paste(out[idx[!vazio]], cc, sep = " | ")
  }
  out
}


monitora_relatorio_exoticas_especies_vinculadas_por_linha <- function(dt, forma_cols, especie_cols) {
  ### Vínculo estrito: só há espécie vinculada quando a linha possui token de
  ### forma de vida exótica e há valor taxonômico válido no campo específico
  ### daquela mesma forma. Campos abertos "outra espécie ... <forma> exótica"
  ### entram como vinculados quando têm texto preenchido válido.
  dt <- data.table::as.data.table(dt)
  n <- nrow(dt)
  if (!n || !length(forma_cols) || !length(especie_cols)) {
    return(list(tem = rep(FALSE, n), campos = rep("", n), valores = rep("", n)))
  }
  forma_cols <- unique(forma_cols[forma_cols %in% names(dt)])
  especie_cols <- unique(especie_cols[especie_cols %in% names(dt)])
  if (!length(forma_cols) || !length(especie_cols)) {
    return(list(tem = rep(FALSE, n), campos = rep("", n), valores = rep("", n)))
  }

  formas_txt <- monitora_relatorio_exoticas_colapsar_valores(dt, forma_cols, incluir_nomes = FALSE)
  mapa <- monitora_relatorio_exoticas_mapa_forma_especie(especie_cols)
  tem <- rep(FALSE, n)
  campos <- rep("", n)
  valores <- rep("", n)

  tokens_forma <- names(mapa)
  tokens_forma <- tokens_forma[!is.na(tokens_forma) & nzchar(tokens_forma)]
  for (forma in tokens_forma) {
    cols_i <- unique(mapa[[forma]])
    cols_i <- cols_i[cols_i %in% especie_cols]
    if (!length(cols_i)) next
    ativo <- monitora_relatorio_exoticas_tem_token(formas_txt, forma)
    if (!any(ativo, na.rm = TRUE)) next
    tem_i <- rep(FALSE, n)
    campos_i <- rep("", n)
    valores_i <- rep("", n)
    for (cc in cols_i) {
      vals <- monitora_relatorio_exoticas_normalizar_texto(dt[[cc]])
      ok <- ativo & monitora_relatorio_exoticas_tem_especie_valida(vals)
      ok[is.na(ok)] <- FALSE
      if (!any(ok)) next
      idx <- which(ok)
      tem_i[idx] <- TRUE
      campos_i[idx] <- ifelse(nzchar(campos_i[idx]), paste(campos_i[idx], cc, sep = " | "), cc)
      valores_i[idx] <- ifelse(nzchar(valores_i[idx]), paste(valores_i[idx], paste0(cc, " = ", vals[idx]), sep = " | "), paste0(cc, " = ", vals[idx]))
    }
    idx <- which(tem_i)
    if (length(idx)) {
      tem[idx] <- TRUE
      campos[idx] <- ifelse(nzchar(campos[idx]), paste(campos[idx], campos_i[idx], sep = " | "), campos_i[idx])
      valores[idx] <- ifelse(nzchar(valores[idx]), paste(valores[idx], valores_i[idx], sep = " | "), valores_i[idx])
    }
  }
  list(tem = tem, campos = campos, valores = valores)
}


monitora_relatorio_exoticas_preparar_saida <- function(dt, colunas_saida) {
  colunas_saida <- unique(colunas_saida[!is.na(colunas_saida) & nzchar(colunas_saida)])
  faltantes <- setdiff(colunas_saida, names(dt))
  if (length(faltantes)) {
    for (cc in faltantes) data.table::set(dt, j = cc, value = NA_character_)
  }
  dt[, ..colunas_saida]
}

monitora_relatorio_contexto_padronizar <- function(dt) {
  dt <- data.table::as.data.table(dt)
  chaves_rel <- monitora_correcao_colunas_chave(dt)
  campos_contexto <- c(
    UC = chaves_rel$uc,
    EA = chaves_rel$ea,
    UA = chaves_rel$ua,
    CICLO = chaves_rel$ciclo,
    CAMPANHA = chaves_rel$campanha,
    ANO = chaves_rel$ano,
    "Data (data_hora)" = chaves_rel$data_hora,
    "Ponto amostral" = chaves_rel$ponto_amostral,
    "Ponto metro" = chaves_rel$ponto_metro
  )
  for (nm in names(campos_contexto)) {
    col_src <- campos_contexto[[nm]]
    if (!(nm %in% names(dt))) data.table::set(dt, j = nm, value = NA_character_)
    if (!is.na(col_src) && nzchar(col_src) && col_src %in% names(dt)) {
      data.table::set(dt, j = nm, value = as.character(dt[[col_src]]))
    }
  }
  dt[]
}

monitora_relatorio_formas_vida_detectar_colunas_todas <- function(dt) {
  nms <- names(dt)
  if (!length(nms)) return(character(0))
  cols_chave <- unique(na.omit(c(
    monitora_correcao_colunas_forma_vida_categoria(dt, "nativa"),
    monitora_correcao_colunas_forma_vida_categoria(dt, "exotica"),
    monitora_correcao_colunas_forma_vida_categoria(dt, "seca_morta")
  )))
  z <- monitora_relatorio_exoticas_normalizar_token(nms)
  padrao <- (grepl("forma_vida", z) | grepl("formas_de_vida", z)) &
    !grepl("especie|species|foto|imagem|image|uuid|id$", z)
  unique(c(cols_chave, nms[padrao]))
}

monitora_relatorio_colapsar_campos_com_tokens <- function(dt, cols, tokens) {
  n <- nrow(dt)
  if (!n) return(list(campos = character(0), valores = character(0), tokens = character(0)))
  cols <- unique(cols[cols %in% names(dt)])
  tokens_norm <- unique(monitora_relatorio_exoticas_normalizar_token(tokens))
  tokens_norm <- tokens_norm[!is.na(tokens_norm) & nzchar(tokens_norm)]
  campos <- valores <- tokens_out <- rep("", n)
  if (!length(cols) || !length(tokens_norm)) return(list(campos = campos, valores = valores, tokens = tokens_out))
  for (cc in cols) {
    tok_lst <- monitora_relatorio_exoticas_tokenizar(dt[[cc]])
    hit <- vapply(tok_lst, function(v) any(v %in% tokens_norm), logical(1))
    if (!any(hit, na.rm = TRUE)) next
    vals <- monitora_relatorio_exoticas_normalizar_texto(dt[[cc]])
    toks_hit <- vapply(tok_lst, function(v) paste(sort(unique(v[v %in% tokens_norm])), collapse = "; "), character(1))
    idx <- which(hit)
    campos[idx] <- ifelse(nzchar(campos[idx]), paste(campos[idx], cc, sep = " | "), cc)
    valores[idx] <- ifelse(nzchar(valores[idx]), paste(valores[idx], paste0(cc, " = ", vals[idx]), sep = " | "), paste0(cc, " = ", vals[idx]))
    tokens_out[idx] <- ifelse(nzchar(tokens_out[idx]), paste(tokens_out[idx], toks_hit[idx], sep = "; "), toks_hit[idx])
  }
  list(campos = campos, valores = valores, tokens = tokens_out)
}


monitora_cache_arquivo_sessao <- function(prefixo, ext = ".csv") {
  d <- file.path(MONITORA_CORRECOES_DIR, "cache_sessao")
  dir.create(d, showWarnings = FALSE, recursive = TRUE)
  file.path(d, paste0(prefixo, "_", MONITORA_EXEC_ID, ext))
}

monitora_cache_registrar_arquivos_antigos_ignorados <- function(arquivos, modo) {
  arquivos <- unique(as.character(arquivos))
  arquivos <- arquivos[file.exists(arquivos)]
  if (!length(arquivos)) return(invisible(data.table::data.table()))
  aud <- data.table::data.table(
    arquivo = arquivos,
    tamanho_bytes = as.numeric(file.info(arquivos)$size),
    modificado_em = as.character(file.info(arquivos)$mtime),
    modo = modo,
    acao = "ignorado_no_modo_cache_incremental",
    observacao = "Arquivos antigos de correção não são reaplicados automaticamente; somente arquivos criados na sessão atual são aplicáveis."
  )
  destino <- file.path(MONITORA_LOG_DIR, paste0("correcoes_antigas_ignoradas_", modo, "_", MONITORA_EXEC_ID, ".csv"))
  try(monitora_fwrite(aud, destino, na = ""), silent = TRUE)
  try(monitora_fwrite(aud, file.path(MONITORA_CORRECOES_DIR, paste0("correcoes_antigas_ignoradas_", modo, ".csv")), na = ""), silent = TRUE)
  invisible(aud)
}

monitora_cache_arquivo_tem_linhas <- function(arq) {
  isTRUE(file.exists(arq)) && isTRUE(file.info(arq)$size > 0) &&
    isTRUE(tryCatch(nrow(data.table::fread(arq, nrows = 1L, encoding = "UTF-8", showProgress = FALSE)) > 0L, error = function(e) FALSE))
}

monitora_cache_gerar_relatorios_pos_se_preciso <- function(registros_corrig, arquivo_correcoes, relatorios_pre = NULL, modo = "cache") {
  gerar_suporte <- isTRUE(get0("MONITORA_GERAR_RELATORIOS_SUPORTE_PAINEL", ifnotfound = TRUE, inherits = TRUE))
  gerar_pos <- isTRUE(get0("MONITORA_GERAR_RELATORIOS_POS_CORRECOES", ifnotfound = TRUE, inherits = TRUE))
  if (!isTRUE(gerar_suporte)) return(invisible(NULL))
  if (!isTRUE(gerar_pos)) return(invisible(NULL))
  tem_corr <- monitora_cache_arquivo_tem_linhas(arquivo_correcoes)
  if (!isTRUE(tem_corr)) {
    aud <- data.table::data.table(
      momento = format(Sys.time(), "%Y-%m-%d %H:%M:%S"),
      modo = modo,
      status = "nao_gerado_sem_correcoes_novas",
      arquivo_correcoes = arquivo_correcoes,
      observacao = "Painel fechado sem correções novas na sessão; relatórios pós-correções não foram recomputados."
    )
    try(monitora_fwrite(aud, file.path(MONITORA_CORRECOES_DIR, "relatorios_pos_correcoes_nao_gerados_sem_correcoes_novas.csv"), na = ""), silent = TRUE)
    return(invisible(aud))
  }
  if (isTRUE(get0("MONITORA_OPCAO_OTIMIZAR_RELATORIOS_SUPORTE_POS", ifnotfound = "S", inherits = TRUE) == "S") &&
      !monitora_correcao_arquivo_afeta_relatorios_suporte(arquivo_correcoes)) {
    MONITORA_RELATORIOS_SUPORTE_POS_CORRECOES <<- relatorios_pre
    monitora_correcao_console_msg("Relatórios pós-correções de apoio pulados no modo ", modo, ": as correções não alteraram formas de vida, espécies, hábitos ou Encostam.")
    monitora_perf_registrar_checkpoint("relatorios_suporte_pos_correcoes_pulados", paste0("relatórios pós-correções reutilizados sem recomputação no modo ", modo), registros_corrig)
    return(invisible(relatorios_pre))
  }

  # Em modos curtos de cache/incremental, esta função pode ser executada antes do
  # bloco da execução completa onde as rotinas pesadas de relatório são definidas.
  # O modo deve continuar multi-run seguro: não abortar por função ainda ausente e
  # registrar auditoria clara. Em execução completa, a função já estará definida.
  if (!exists("monitora_relatorios_suporte_painel_gravar", mode = "function", inherits = TRUE)) {
    aud <- data.table::data.table(
      momento = format(Sys.time(), "%Y-%m-%d %H:%M:%S"),
      modo = modo,
      status = "nao_gerado_funcao_relatorio_indisponivel_no_ramo_cache",
      arquivo_correcoes = arquivo_correcoes,
      observacao = "Correções da sessão foram aplicadas, mas relatórios pós-correções não foram recomputados neste ramo curto porque monitora_relatorios_suporte_painel_gravar ainda não estava definida. O checkpoint registros_corrig.csv segue válido; rode painel_incremental_registros_corrig ou execução completa para relatório final."
    )
    try(monitora_fwrite(aud, file.path(MONITORA_CORRECOES_DIR, "relatorios_pos_correcoes_nao_gerados_funcao_indisponivel_cache.csv"), na = ""), silent = TRUE)
    try(monitora_fwrite(aud, file.path(MONITORA_LOG_DIR, paste0("relatorios_pos_correcoes_nao_gerados_funcao_indisponivel_cache_", MONITORA_EXEC_ID, ".csv")), na = ""), silent = TRUE)
    monitora_correcao_console_msg("Relatórios pós-correções não foram recomputados no modo ", modo, ": função de relatório ainda indisponível neste ramo curto; auditoria gravada e execução continuará.")
    monitora_perf_registrar_checkpoint("relatorios_suporte_pos_correcoes_nao_gerados_cache", paste0("relatórios pós-correções não recomputados no modo ", modo, " por função indisponível no ramo curto"), registros_corrig)
    return(invisible(aud))
  }

  MONITORA_RELATORIOS_SUPORTE_POS_CORRECOES <<- monitora_relatorios_suporte_painel_gravar(registros_corrig, fase = "pos_correcoes", atualizar_saida_principal = FALSE)
  if (exists("monitora_relatorios_comparar_pre_pos_correcoes", mode = "function", inherits = TRUE)) {
    MONITORA_COMPARACAO_RELATORIOS_PRE_POS_CORRECOES <<- tryCatch(monitora_relatorios_comparar_pre_pos_correcoes(MONITORA_CORRECOES_DIR), error = function(e) data.table::data.table(erro = conditionMessage(e)))
  } else {
    MONITORA_COMPARACAO_RELATORIOS_PRE_POS_CORRECOES <<- data.table::data.table(status = "comparacao_nao_gerada_funcao_indisponivel_no_ramo_cache")
  }
  monitora_perf_registrar_checkpoint("relatorios_suporte_pos_correcoes", paste0("relatórios de apoio atualizados no modo ", modo), registros_corrig)
  invisible(MONITORA_RELATORIOS_SUPORTE_POS_CORRECOES)
}

monitora_painel_cache_incremental_executar <- function(registros_corrig, meta_xls, modo, relatorios_pre = NULL, validacao_espacial_pre = NULL, cache_arq = NA_character_) {
  registros_corrig <- data.table::as.data.table(registros_corrig)
  MONITORA_META_XLSFORMS_CORRECOES <<- meta_xls
  MONITORA_DEPENDENCIAS_CORRECOES <<- tryCatch(monitora_correcao_unificar_dependencias(MONITORA_META_XLSFORMS_CORRECOES$dependencias), error = function(e) data.table::data.table())
  MONITORA_RELATORIOS_SUPORTE_PRE_PAINEL <<- relatorios_pre
  MONITORA_VALIDACAO_ESPACIAL_PRE_PAINEL_RESULTADO <<- validacao_espacial_pre
  if (is.list(MONITORA_VALIDACAO_ESPACIAL_PRE_PAINEL_RESULTADO) && !is.null(MONITORA_VALIDACAO_ESPACIAL_PRE_PAINEL_RESULTADO$validacao)) {
    validacao_esp_painel <<- data.table::as.data.table(MONITORA_VALIDACAO_ESPACIAL_PRE_PAINEL_RESULTADO$validacao)
  }
  arquivo_campos_sessao <- monitora_cache_arquivo_sessao(paste0("correcoes_campos_", modo))
  arquivo_esp_sessao <- monitora_cache_arquivo_sessao(paste0("correcoes_espaciais_", modo))
  try(unlink(c(arquivo_campos_sessao, arquivo_esp_sessao)), silent = TRUE)
  monitora_cache_registrar_arquivos_antigos_ignorados(c(MONITORA_ARQUIVO_CORRECOES_CAMPOS, MONITORA_ARQUIVO_CORRECOES_ESPACIAIS), modo = modo)
  old_esp <- get0("MONITORA_ARQUIVO_CORRECOES_ESPACIAIS", ifnotfound = file.path(MONITORA_INPUT_DIR, "correcoes_espaciais.csv"), inherits = TRUE)
  MONITORA_ARQUIVO_CORRECOES_ESPACIAIS <<- arquivo_esp_sessao
  on.exit({ MONITORA_ARQUIVO_CORRECOES_ESPACIAIS <<- old_esp }, add = TRUE)
  if (identical(modo, "abrir_painel_cache")) {
    monitora_correcao_console_msg("Modo abrir_painel_cache detectado: correções antigas em input/ serão ignoradas nesta sessão; somente correções novas do painel serão aplicadas.")
    monitora_correcao_console_msg("Cache pré-painel carregado: ", cache_arq, ". Abrindo painel sem reconstruir leitura, padronização, validação espacial pré-painel nem relatórios pré-painel.")
  } else {
    monitora_correcao_console_msg("Modo painel_incremental_registros_corrig detectado: painel aberto a partir de registros_corrig.csv já corrigido; correções antigas em input/ serão ignoradas nesta sessão.")
  }
  if (!isTRUE(get0("MONITORA_VALIDAR_ESPACIAL_COLETAS", ifnotfound = FALSE, inherits = TRUE))) {
    monitora_correcao_console_msg("Este modo não força MONITORA_OPCAO_VALIDAR_ESPACIAL_COLETAS=S; validação/aplicação espacial permanece conforme configuração explícita do usuário.")
  }
  monitora_registros_importados_garantir_pre_painel(NULL, contexto = modo)
  monitora_publicacao_p_auditar_schema_pre_painel(registros_corrig, contexto = paste0("pre_painel_", modo))
  MONITORA_CORRECOES_GERADAS_PAINEL <<- monitora_correcao_painel(registros_corrig, MONITORA_META_XLSFORMS_CORRECOES, arquivo_campos_sessao)
  if (exists("monitora_correcao_gravar_trilha_semantica", mode = "function", inherits = TRUE) &&
      isTRUE(nrow(data.table::as.data.table(MONITORA_CORRECOES_GERADAS_PAINEL)) > 0L)) {
    try(monitora_correcao_gravar_trilha_semantica(MONITORA_CORRECOES_GERADAS_PAINEL, arquivo_origem = arquivo_campos_sessao, fase = "sessao_painel_incremental", status = "salva_pelo_painel", contexto = modo), silent = TRUE)
  }
  tem_corr_campos <- isTRUE(nrow(MONITORA_CORRECOES_GERADAS_PAINEL) > 0L) && monitora_cache_arquivo_tem_linhas(arquivo_campos_sessao)
  if (tem_corr_campos) {
    monitora_correcao_console_msg("Aplicando somente correções de campos criadas nesta sessão: ", arquivo_campos_sessao, ".")
    registros_corrig <- monitora_correcao_preparar_schema_edicao_painel(registros_corrig, MONITORA_META_XLSFORMS_CORRECOES, contexto = paste0("pre_aplicacao_correcoes_", modo))
    registros_corrig <- monitora_correcao_aplicar_arquivo(registros_corrig, arquivo_campos_sessao, MONITORA_META_XLSFORMS_CORRECOES$campos)
    monitora_correcao_console_msg("Correções de campos da sessão aplicadas; correções antigas em input/ não foram reaplicadas.")
    monitora_correcao_auditar_persistencia_limpeza_outras_formas(registros_corrig, arquivo_campos_sessao, MONITORA_META_XLSFORMS_CORRECOES$campos, contexto = paste0("pos_aplicacao_", modo), abortar = TRUE)
    MONITORA_AUDITORIA_SEMANTICA_FORMAS_VIDA <<- monitora_correcao_auditar_formas_vida_semantica(registros_corrig, contexto = paste0("pos_correcoes_", modo, "_", MONITORA_EXEC_ID), abortar = TRUE)
  } else {
    monitora_correcao_console_msg("Nenhuma correção de campos nova nesta sessão; nenhum correcoes_campos.csv antigo será aplicado.")
  }
  if (isTRUE(get0("MONITORA_VALIDAR_CONDICIONAIS_CORRECOES", ifnotfound = TRUE, inherits = TRUE)) && nrow(MONITORA_DEPENDENCIAS_CORRECOES) > 0 && tem_corr_campos) {
    monitora_correcao_console_msg("Validando dependências condicionais após correções da sessão.")
    MONITORA_AUDITORIA_DEPENDENCIAS_CONDICIONAIS <<- monitora_correcao_validar_dependencias(registros_corrig, MONITORA_DEPENDENCIAS_CORRECOES, MONITORA_META_XLSFORMS_CORRECOES$campos)
  } else {
    MONITORA_AUDITORIA_DEPENDENCIAS_CONDICIONAIS <<- data.table::data.table()
  }
  monitora_cache_gerar_relatorios_pos_se_preciso(registros_corrig, arquivo_campos_sessao, relatorios_pre = relatorios_pre, modo = modo)
  if (isTRUE(get0("MONITORA_VALIDAR_ESPACIAL_COLETAS", ifnotfound = FALSE, inherits = TRUE))) {
    if (monitora_cache_arquivo_tem_linhas(arquivo_esp_sessao)) {
      monitora_esp_msg("Aplicando somente correções espaciais criadas nesta sessão: ", arquivo_esp_sessao, ".")
      res_esp_cache <- monitora_espacial_aplicar_correcoes_atomicas(registros_corrig, arquivo = arquivo_esp_sessao, abortar_falha = TRUE, coletas_excluidas = monitora_esp_coletas_excluidas_ultima_auditoria())
      registros_corrig <- res_esp_cache$registros_corrig
    } else {
      monitora_esp_msg("Nenhuma correção espacial nova nesta sessão; nenhum correcoes_espaciais.csv antigo será aplicado.")
    }
    MONITORA_VALIDACAO_ESPACIAL_POS_PAINEL_RESULTADO <<- monitora_espacial_executar(registros_corrig, momento = "pos_painel", forcar = TRUE, output_dir = MONITORA_OUTPUT_DIR, log_dir = MONITORA_LOG_DIR)
    if (is.list(MONITORA_VALIDACAO_ESPACIAL_PRE_PAINEL_RESULTADO) && is.list(MONITORA_VALIDACAO_ESPACIAL_POS_PAINEL_RESULTADO)) {
      try(MONITORA_COMPARACAO_VALIDACAO_ESPACIAL_PRE_POS <<- monitora_espacial_comparar_pre_pos(MONITORA_VALIDACAO_ESPACIAL_PRE_PAINEL_RESULTADO$validacao, MONITORA_VALIDACAO_ESPACIAL_POS_PAINEL_RESULTADO$validacao), silent = TRUE)
    }
  }
  fase_dup <- paste0("pos_correcoes_", modo)
  try(MONITORA_AUDITORIA_COLETAS_UA_ANO_DUPLICADAS_POS_CORRECOES <<- monitora_auditar_coletas_ua_ano_duplicadas(registros_corrig, fase = fase_dup, abortar = FALSE), silent = TRUE)
  monitora_execucao_gravar_checkpoint_parcial(registros_corrig, produto = "registros_corrig.csv", motivo = modo)
  MONITORA_EXECUCAO_ENCERRADA_CONTROLADAMENTE <<- TRUE
  message("Execução parcial concluída de forma controlada a partir do modo ", modo, ".")
  invisible(registros_corrig)
}

if (identical(MONITORA_MODO_EXECUCAO, "abrir_painel_cache")) {
  cache_dirs <- tryCatch(monitora_cache_painel_dirs_busca(criar = TRUE), error = function(e) unique(c(file.path(MONITORA_OUTPUT_DIR, "90_cache", "cache_painel"), file.path(MONITORA_OUTPUT_DIR, "cache_painel"))))
  cache_arq <- trimws(as.character(get0("MONITORA_CACHE_PAINEL_ARQUIVO", ifnotfound = "", inherits = TRUE))[1L])
  if (!nzchar(cache_arq)) {
    cand <- unique(unlist(lapply(cache_dirs, function(dd) {
      if (!dir.exists(dd)) return(character(0))
      list.files(dd, pattern = "^cache_painel_.*\\.rds$", full.names = TRUE)
    }), use.names = FALSE))
    cand <- cand[file.exists(cand)]
    if (length(cand)) cache_arq <- cand[order(file.info(cand)$mtime, decreasing = TRUE)][1L]
  }
  if (!nzchar(cache_arq) || !file.exists(cache_arq)) {
    stop("Modo abrir_painel_cache solicitado, mas nenhum cache_painel_*.rds foi encontrado. Procurei em output/90_cache/cache_painel/ e em output/cache_painel/. Execute uma vez em painel_e_parar para gerar o cache.", call. = FALSE)
  }
  cache_obj <- readRDS(cache_arq)
  if (!is.list(cache_obj) || is.null(cache_obj$registros_corrig) || is.null(cache_obj$meta_xls)) {
    stop("Cache de painel inválido: faltam registros_corrig ou meta_xls.", call. = FALSE)
  }
  registros_corrig <- monitora_painel_cache_incremental_executar(
    registros_corrig = data.table::as.data.table(cache_obj$registros_corrig),
    meta_xls = cache_obj$meta_xls,
    modo = "abrir_painel_cache",
    relatorios_pre = cache_obj$relatorios_pre,
    validacao_espacial_pre = cache_obj$validacao_espacial_pre,
    cache_arq = cache_arq
  )
}

if (identical(MONITORA_MODO_EXECUCAO, "painel_incremental_registros_corrig")) {
  cand_inc <- list.files(MONITORA_INPUT_DIR, pattern = "^registros_corrig.*\\.csv$", full.names = TRUE, ignore.case = TRUE)
  if (!length(cand_inc)) {
    stop("Modo painel_incremental_registros_corrig solicitado, mas nenhum registros_corrig*.csv foi encontrado em input/. Copie o output/registros_corrig.csv da rodada anterior para input/ antes de rodar.", call. = FALSE)
  }
  if (length(cand_inc) > 1L) {
    stop("Modo painel_incremental_registros_corrig exige exatamente um registros_corrig*.csv em input/. Foram encontrados: ", paste(basename(cand_inc), collapse = ", "), call. = FALSE)
  }
  arq_inc <- cand_inc[1L]
  registros_corrig <- data.table::fread(arq_inc, encoding = "UTF-8", na.strings = c("", "NA"), colClasses = "character", showProgress = FALSE)
  registros_corrig <- data.table::as.data.table(registros_corrig)
  if (!("COLETA" %in% names(registros_corrig))) {
    stop("O arquivo incremental ", basename(arq_inc), " não possui coluna obrigatória COLETA. Use um registros_corrig.csv produzido pelo script.", call. = FALSE)
  }
  MONITORA_META_XLSFORMS_CORRECOES <- monitora_correcao_xlsforms_embutidos_cache_publicacao_ae()
  MONITORA_DEPENDENCIAS_CORRECOES <- monitora_correcao_unificar_dependencias(MONITORA_META_XLSFORMS_CORRECOES$dependencias)
  MONITORA_DICIONARIO_ATRIBUTOS_CORRECOES <- monitora_correcao_dicionario_atributos(registros_corrig, MONITORA_META_XLSFORMS_CORRECOES)
  try(monitora_fwrite(MONITORA_DICIONARIO_ATRIBUTOS_CORRECOES, file.path(MONITORA_CORRECOES_DIR, "dicionario_atributos_registros_corrig_incremental.csv"), na = ""), silent = TRUE)
  relatorios_inc_pre <- NULL
  if (isTRUE(get0("MONITORA_GERAR_RELATORIOS_SUPORTE_PAINEL", ifnotfound = TRUE, inherits = TRUE))) {
    if (exists("monitora_relatorios_suporte_painel_gravar", mode = "function", inherits = TRUE)) {
      relatorios_inc_pre <- monitora_relatorios_suporte_painel_gravar(registros_corrig, fase = "pre_painel_incremental", atualizar_saida_principal = FALSE)
    } else {
      aud_inc_rel <- data.table::data.table(
        momento = format(Sys.time(), "%Y-%m-%d %H:%M:%S"),
        modo = "painel_incremental_registros_corrig",
        fase = "pre_painel_incremental",
        status = "nao_gerado_funcao_relatorio_indisponivel_no_ramo_incremental",
        arquivo_base = arq_inc,
        observacao = "Relatórios de apoio pré-painel incremental não foram recomputados porque monitora_relatorios_suporte_painel_gravar ainda não estava definida no ramo curto. O painel incremental será aberto com triagens internas recalculadas e relatorios_pre = NULL."
      )
      try(monitora_fwrite(aud_inc_rel, file.path(MONITORA_CORRECOES_DIR, "relatorios_pre_painel_incremental_nao_gerados_funcao_indisponivel.csv"), na = ""), silent = TRUE)
      try(monitora_fwrite(aud_inc_rel, file.path(MONITORA_LOG_DIR, paste0("relatorios_pre_painel_incremental_nao_gerados_funcao_indisponivel_", MONITORA_EXEC_ID, ".csv")), na = ""), silent = TRUE)
      monitora_correcao_console_msg("Relatórios pré-painel incremental não foram recomputados: função de relatório ainda indisponível neste ramo curto; painel abrirá com diagnóstico/triagem internos recalculados.")
    }
  }
  validacao_inc_pre <- NULL
  if (isTRUE(get0("MONITORA_VALIDAR_ESPACIAL_COLETAS", ifnotfound = FALSE, inherits = TRUE))) {
    monitora_correcao_console_msg("Validação espacial pré-painel incremental será gravada em output/validacao_espacial/pre_painel_incremental.")
    validacao_inc_pre <- monitora_espacial_executar(registros_corrig, momento = "pre_painel_incremental", forcar = TRUE, output_dir = MONITORA_OUTPUT_DIR, log_dir = MONITORA_LOG_DIR)
  }
  try(monitora_cache_painel_salvar(registros_corrig, MONITORA_META_XLSFORMS_CORRECOES, relatorios_pre = relatorios_inc_pre, validacao_espacial_pre = validacao_inc_pre), silent = TRUE)
  registros_corrig <- monitora_painel_cache_incremental_executar(
    registros_corrig = registros_corrig,
    meta_xls = MONITORA_META_XLSFORMS_CORRECOES,
    modo = "painel_incremental_registros_corrig",
    relatorios_pre = relatorios_inc_pre,
    validacao_espacial_pre = validacao_inc_pre,
    cache_arq = arq_inc
  )
}

if (!(MONITORA_MODO_EXECUCAO %in% c("abrir_painel_cache", "painel_incremental_registros_corrig"))) {

monitora_txt_normalizar_vazio <- function(x) {
  x <- as.character(x)
  x <- stringr::str_squish(x)
  x[x %in% c("", "NA", "Na", "na", "N/A", "n/a", "NULL", "null", "NaN", "nan")] <- NA_character_
  x
}

monitora_txt_nome_coluna_base <- function(x) {
  x <- as.character(x)
  x <- stringr::str_replace_all(x, '\\"{4}', '\\"\\"')
  x <- stringr::str_squish(x)
  # Remove sufixos introduzidos por leitores de CSV/XLSX para nomes repetidos, como uc...5.
  # Não remove sufixos .2, pois no formulário eles podem distinguir perguntas diferentes.
  x <- stringr::str_replace(x, "\\.\\.\\.[0-9]+$", "")
  x
}

monitora_vetor_coalesce <- function(...) {
  vals <- list(...)
  if (length(vals) == 0) return(character())
  n <- max(vapply(vals, length, integer(1)))
  vals <- lapply(vals, function(v) rep_len(as.character(v), n))
  out <- rep(NA_character_, n)
  for (v in vals) {
    v <- monitora_txt_normalizar_vazio(v)
    idx <- is.na(out) & !is.na(v)
    out[idx] <- v[idx]
  }
  out
}

monitora_dt_consolidar_colunas_duplicadas <- function(dt) {
  # Consolidação adaptativa de colunas duplicadas.
  #
  # Em bases muito grandes, a consolidação completa de todas as colunas duplicadas pode
  # gerar picos altos de memória ao materializar vetores inteiros para cada grupo
  # duplicado. A estratégia adotada evita esse padrão:
  #   1) em bases grandes, só consolida automaticamente grupos críticos para a
  #      análise; grupos não críticos são preservados com nomes originais e
  #      registrados como "adiados", sem coalesce;
  #   2) para grupos críticos em bases grandes, faz coalesce por blocos de linhas,
  #      sem criar vetor consolidado do tamanho da tabela inteira;
  #   3) por padrão não concatena valores conflitantes com "__CONFLITO__" em bases
  #      grandes, pois isso pode multiplicar strings e RAM; os conflitos ficam em
  #      auditoria.
  dt <- monitora_dt_referenciar(dt)

  # Tratamento de cabeçalhos duplicados: alguns CSVs do SISMONITORA podem chegar com nomes de
  # colunas exatamente repetidos no próprio cabeçalho. data.table permite esse
  # estado, mas operações como dt[, (cols) := NULL] falham quando `cols` contém
  # o mesmo nome mais de uma vez. Além disso, dt[[nome]] sempre recupera a
  # primeira coluna com aquele nome, impedindo coalesce correto por posição.
  #
  # Estratégia: guardar os nomes originais para formar os grupos de fusão e,
  # antes de operar por referência, tornar os nomes fisicamente únicos por
  # posição. Assim, colunas originalmente iguais continuam no mesmo grupo, mas
  # passam a ser endereçáveis sem ambiguidade.
  original_names_raw <- names(dt)
  original_names <- original_names_raw
  if (anyDuplicated(original_names_raw)) {
    original_names <- make.unique(original_names_raw, sep = "__dup")
    data.table::setnames(dt, original_names)
  }

  base_names <- monitora_txt_nome_coluna_base(original_names_raw)

  protected <- grepl("^MONITORA_", original_names_raw) | original_names_raw %in% c(".id")
  base_names[protected] <- original_names[protected]

  n_linhas_dt <- nrow(dt)
  n_colunas_dt <- ncol(dt)
  objeto_mb <- tryCatch(round(as.numeric(object.size(dt)) / 1024^2, 1), error = function(e) NA_real_)

  modo_merge <- Sys.getenv("MONITORA_MERGE_DUPLICATE_COLUMNS_MODO", unset = "auto")
  limite_obj_mb <- suppressWarnings(as.numeric(Sys.getenv("MONITORA_MERGE_DUP_COLS_SELECTIVE_MB", unset = "4096")))
  limite_ncols <- suppressWarnings(as.integer(Sys.getenv("MONITORA_MERGE_DUP_COLS_SELECTIVE_NCOLS", unset = "350")))
  chunk_n <- suppressWarnings(as.integer(Sys.getenv("MONITORA_MERGE_DUP_COLS_CHUNK_ROWS", unset = "50000")))
  if (is.na(chunk_n) || chunk_n < 1000L) chunk_n <- 50000L

  seletivo <- FALSE
  if (identical(modo_merge, "seletivo")) seletivo <- TRUE
  if (identical(modo_merge, "completo")) seletivo <- FALSE
  if (identical(modo_merge, "auto")) {
    seletivo <- (!is.na(objeto_mb) && objeto_mb >= limite_obj_mb) || (!is.na(n_colunas_dt) && n_colunas_dt >= limite_ncols)
  }

  # Bases/canônicos que são necessários para identificação, deduplicação,
  # estatísticas e compatibilidade dos formatos SISMONITORA. Em modo seletivo,
  # estes grupos ainda são consolidados; demais grupos duplicados ficam preservados
  # e auditados para evitar pico de RAM.
  critical_aliases <- c(
    "uc", "ua", "ciclo", "campanha", "coleta", "uuid", "coleta_uuid",
    "registro_uuid", "data", "data do registro", "data_do_registro",
    "data (data_hora)", "horario (data_hora)", "horário (data_hora)",
    "protocolo", "formulario", "formulário",
    "amostragem/registro/ponto_amostral", "amostragem/registro/ponto_metro",
    "amostragem/registro/uuid", "ponto_amostral", "ponto_metro",
    "coordenada inicial da amostragem (amostragem)",
    "coordenada final da amostragem (amostragem)",
    "amostragem/ponto_inicio_transecto", "amostragem/ponto_fim_transecto",
    "ponto inicio transecto", "ponto fim transecto",
    "ponto_inicio_transecto", "ponto_fim_transecto",
    "categoria", "forma de vida", "forma_de_vida", "origem",
    "amostragem/registro/categoria", "amostragem/registro/forma_de_vida",
    "amostragem/registro/origem", "familia", "família", "genero", "gênero",
    "especie", "espécie", "nome_cientifico", "nome científico",
    "seca_morta", "seca/morta", "nativa", "exotica", "exótica"
  )
  critical_canon <- unique(monitora_txt_canonicalizar_coluna(critical_aliases))

  groups <- split(original_names, base_names)
  audit_list <- vector("list", length(groups))
  audit_i <- 0L

  make_safe_name <- function(target, current_col) {
    if (is.na(target) || !nzchar(target)) target <- paste0("COLUNA_SEM_NOME_", seq_along(names(dt))[1])
    if (identical(target, current_col)) return(target)
    if (!(target %in% names(dt))) return(target)
    i <- 2L
    candidate <- paste0(target, "__merge", i)
    while (candidate %in% names(dt)) {
      i <- i + 1L
      candidate <- paste0(target, "__merge", i)
    }
    candidate
  }

  merge_group_i <- 0L
  for (base_col in names(groups)) {
    merge_group_i <- merge_group_i + 1L
    if (merge_group_i == 1L || merge_group_i %% 25L == 0L) {
      # Não passa o objeto inteiro aqui: object.size(dt) em tabela de muitos GB
      # é caro e pode aumentar pressão de memória. O tamanho já foi medido uma vez.
      monitora_recurso_controlar(paste0("merge_duplicate_columns_grupo_", merge_group_i), risco = "alto", objeto = NULL, force_log = FALSE)
    }

    cols_orig <- groups[[base_col]]
    cols <- cols_orig[cols_orig %in% names(dt)]
    if (length(cols) == 0) next

    safe_col <- base_col
    if (is.na(safe_col) || !nzchar(safe_col)) safe_col <- paste0("COLUNA_SEM_NOME_", which(names(groups) == base_col)[1])

    if (length(cols) == 1) {
      current_col <- cols[1]
      # Em modo seletivo e tabela grande, evita renomear colunas não críticas
      # apenas para remover sufixo ...N; isso reduz risco de colisões e mantém
      # rastreabilidade do cabeçalho original.
      base_can <- monitora_txt_canonicalizar_coluna(safe_col)
      if (!isTRUE(seletivo) || base_can %in% critical_canon || grepl("^MONITORA_", current_col) || current_col %in% c(".id")) {
        new_name <- make_safe_name(safe_col, current_col)
        if (!identical(current_col, new_name)) data.table::setnames(dt, current_col, new_name)
      }
      next
    }

    base_can <- monitora_txt_canonicalizar_coluna(safe_col)
    cols_can <- unique(monitora_txt_canonicalizar_coluna(cols))
    grupo_critico <- base_can %in% critical_canon || any(cols_can %in% critical_canon)

    if (isTRUE(seletivo) && !isTRUE(grupo_critico)) {
      # Não coalesce grupos não críticos em bases enormes. Manter as colunas como
      # vieram do fread/rbindlist é mais seguro que materializar vetores enormes.
      audit_i <- audit_i + 1L
      audit_list[[audit_i]] <- data.table::data.table(
        coluna = safe_col,
        nomes_originais = paste(cols_orig, collapse = " | "),
        n_colunas_fundidas = 0L,
        linhas_com_conflito = NA_integer_,
        exemplos = NA_character_,
        acao = "adiado_modo_seletivo",
        motivo = paste0("base grande: objeto_mb=", objeto_mb, "; ncol=", n_colunas_dt)
      )
      next
    }

    primary <- cols[1]
    dup_cols <- cols[-1]
    conflito_total_n <- 0L
    exemplos_conflito <- character()

    # Tabelas pequenas/médias: caminho vetorial mais rápido.
    usar_chunk <- isTRUE(seletivo) || (!is.na(objeto_mb) && objeto_mb >= limite_obj_mb)
    if (!usar_chunk) {
      merged <- monitora_txt_normalizar_vazio(as.character(dt[[primary]]))
      for (col in dup_cols) {
        v <- monitora_txt_normalizar_vazio(as.character(dt[[col]]))
        fill_idx <- is.na(merged) & !is.na(v)
        if (any(fill_idx)) merged[fill_idx] <- v[fill_idx]
        conflito <- !is.na(merged) & !is.na(v) & merged != v
        n_conf <- sum(conflito, na.rm = TRUE)
        if (n_conf > 0) {
          conflito_total_n <- conflito_total_n + n_conf
          if (length(exemplos_conflito) < 5L) {
            exemplos_conflito <- unique(c(exemplos_conflito, utils::head(unique(paste(merged[conflito], v[conflito], sep = "__CONFLITO__")), 5L)))
            exemplos_conflito <- utils::head(exemplos_conflito, 5L)
          }
          # Concatenação de conflito mantida só no caminho pequeno/médio.
          merged[conflito] <- paste(merged[conflito], v[conflito], sep = "__CONFLITO__")
        }
        rm(v, fill_idx, conflito)
      }
      data.table::set(dt, j = primary, value = as.character(merged))
      rm(merged)
    } else {
      # Caminho em blocos: processa apenas blocos de linhas e atualiza a coluna
      # primária por referência. Isso evita criar um vetor consolidado do tamanho
      # completo da tabela para cada grupo duplicado.
      seq_starts <- seq.int(1L, n_linhas_dt, by = chunk_n)
      for (col in dup_cols) {
        for (st in seq_starts) {
          en <- min(st + chunk_n - 1L, n_linhas_dt)
          ii <- st:en
          p <- monitora_txt_normalizar_vazio(dt[[primary]][ii])
          v <- monitora_txt_normalizar_vazio(dt[[col]][ii])

          fill_idx <- is.na(p) & !is.na(v)
          if (any(fill_idx)) {
            data.table::set(dt, i = ii[fill_idx], j = primary, value = v[fill_idx])
          }

          conflito <- !is.na(p) & !is.na(v) & p != v
          n_conf <- sum(conflito, na.rm = TRUE)
          if (n_conf > 0) {
            conflito_total_n <- conflito_total_n + n_conf
            if (length(exemplos_conflito) < 5L) {
              exemplos_conflito <- unique(c(exemplos_conflito, utils::head(unique(paste(p[conflito], v[conflito], sep = "__CONFLITO__")), 5L)))
              exemplos_conflito <- utils::head(exemplos_conflito, 5L)
            }
            # Em bases grandes não concatena conflitos na tabela principal:
            # manter o valor primário evita explosão de strings. A auditoria
            # registra a existência e exemplos dos conflitos.
          }

          rm(p, v, fill_idx, conflito)
        }
        if (monitora_recurso_deve_gc()) gc(verbose = FALSE)
      }
    }

    dt[, (dup_cols) := NULL]

    new_name <- make_safe_name(safe_col, primary)
    if (!identical(primary, new_name) && primary %in% names(dt)) {
      data.table::setnames(dt, primary, new_name)
    }

    audit_i <- audit_i + 1L
    audit_list[[audit_i]] <- data.table::data.table(
      coluna = new_name,
      nomes_originais = paste(cols_orig, collapse = " | "),
      n_colunas_fundidas = length(cols_orig),
      linhas_com_conflito = as.integer(conflito_total_n),
      exemplos = paste(utils::head(exemplos_conflito, 5L), collapse = " | "),
      acao = ifelse(usar_chunk, "fundido_chunked", "fundido_vetorial"),
      motivo = paste0("seletivo=", seletivo, "; critico=", grupo_critico, "; objeto_mb=", objeto_mb)
    )

    rm(conflito_total_n, exemplos_conflito)
    if (monitora_recurso_deve_gc()) gc(verbose = FALSE)
  }

  audit <- if (audit_i > 0L) data.table::rbindlist(audit_list[seq_len(audit_i)], fill = TRUE, use.names = TRUE) else data.table::data.table(
    coluna = character(), nomes_originais = character(), n_colunas_fundidas = integer(),
    linhas_com_conflito = integer(), exemplos = character(), acao = character(), motivo = character()
  )
  attr(dt, "audit_duplicate_columns") <- audit
  dt
}


monitora_dt_remover_colunas_tecnicas_legadas <- function(dt, momento = "importacao") {
  dt <- monitora_dt_referenciar(dt)
  # Arquivos pós-tratamento usados como entrada podem trazer colunas técnicas
  # de execuções anteriores, como .id.1, .id.2 etc. Elas não representam
  # dados do protocolo nem a origem da execucao atual. A coluna .id da execucao
  # atual é preservada/reconstruida separadamente.
  legacy_cols <- grep("^\\.id\\.[0-9]+$", names(dt), value = TRUE)
  if (length(legacy_cols) > 0) {
    monitora_log_registrar_evento(
      "limpeza_colunas_tecnicas_legadas",
      "INFO",
      NA_character_,
      paste0(length(legacy_cols), " coluna(s) tecnica(s) legada(s) removida(s) em ", momento, ": ", paste(legacy_cols, collapse = ", ")),
      "colunas .id.N provenientes de execucoes anteriores nao foram mantidas no produto atual"
    )
    dt[, (legacy_cols) := NULL]
  }
  dt
}


monitora_txt_remover_acentos <- function(x) {
  y <- iconv(x, from = "", to = "ASCII//TRANSLIT")
  y[is.na(y)] <- x[is.na(y)]
  y
}

monitora_txt_canonicalizar_coluna <- function(x) {
  y <- monitora_txt_nome_coluna_base(x)
  y <- tolower(monitora_txt_remover_acentos(y))
  y <- stringr::str_replace_all(y, "[[:space:]]+", " ")
  y <- stringr::str_squish(y)
  y
}

monitora_dt_consolidar_aliases_colunas <- function(dt) {
  # Consolidação de aliases com menor uso de memória.
  # Evita materializar várias colunas grandes ao mesmo tempo durante a consolidação.
  # A consolidação é feita par a par, com remoção imediata das colunas auxiliares.
  # Isso reduz o pico de memória em bases grandes.
  dt <- monitora_dt_referenciar(dt)
  canon <- monitora_txt_canonicalizar_coluna(names(dt))
  alias_map <- list(
    "COLETA" = c("coleta", "id_coleta", "id coleta", "codigo coleta", "código coleta", "amostragem/coleta"),
    "UC" = c("uc", "unidade de conservacao", "unidade de conservação"),
    "UA" = c("ua", "unidade amostral", "amostragem/unidade_amostral"),
    "CICLO" = c("ciclo", "ano ciclo", "ano_ciclo"),
    "CAMPANHA" = c("campanha"),
    "PROTOCOLO" = c("protocolo", "formulario", "formulário"),
    "UUID" = c("uuid", "registro uuid", "registro_uuid"),
    "coleta_uuid" = c("coleta uuid", "coleta_uuid", "uuid_coleta", "amostragem/uuid"),
    "Data (data_hora)" = c("data (data_hora)", "data_hora/data", "amostragem/registro/data", "data"),
    "Horário (data_hora)" = c("horario (data_hora)", "horário (data_hora)", "data_hora/hora", "amostragem/registro/hora", "hora"),
    "Coordenada inicial da amostragem (amostragem)" = c("coordenada inicial da amostragem (amostragem)", "amostragem/ponto_inicio_transecto", "ponto inicio transecto", "ponto_inicio_transecto"),
    "Coordenada final da amostragem (amostragem)" = c("coordenada final da amostragem (amostragem)", "amostragem/ponto_fim_transecto", "ponto fim transecto", "ponto_fim_transecto"),
    # Aliases de registro amostral precisam ser consolidados antes da deduplicação.
    # Não misturar UUID de coleta (UUID/uuid) com uuid do registro amostral.
    "ponto_amostral (amostragem/registro)" = c("ponto_amostral (amostragem/registro)", "amostragem/registro/ponto_amostral", "ponto_amostral"),
    "ponto_metro (amostragem/registro)" = c("ponto_metro (amostragem/registro)", "amostragem/registro/ponto_metro", "ponto_metro"),
    "uuid (amostragem/registro)" = c("uuid (amostragem/registro)", "amostragem/registro/uuid")
  )
  alias_i <- 0L
  for (target in names(alias_map)) {
    alias_i <- alias_i + 1L
    monitora_recurso_controlar(paste0("consolidate_aliases_", alias_i, "_", target), risco = "alto", objeto = dt, force_log = FALSE)
    idx <- which(canon %in% monitora_txt_canonicalizar_coluna(alias_map[[target]]))
    if (length(idx) == 0) next
    alias_cols <- names(dt)[idx]
    alias_cols <- alias_cols[alias_cols %in% names(dt)]
    if (length(alias_cols) == 0) next

    if (!(target %in% names(dt))) {
      first_col <- alias_cols[1]
      if (!identical(first_col, target)) {
        if (target %in% names(dt)) {
          # proteção redundante contra colisão
          data.table::setnames(dt, first_col, paste0(target, "__alias"))
        } else {
          data.table::setnames(dt, first_col, target)
        }
      }
      alias_cols <- setdiff(alias_cols, first_col)
    }

    for (col in alias_cols) {
      if (!(col %in% names(dt)) || identical(col, target)) next
      alvo <- monitora_txt_normalizar_vazio(as.character(dt[[target]]))
      aux <- monitora_txt_normalizar_vazio(as.character(dt[[col]]))
      fill_idx <- is.na(alvo) & !is.na(aux)
      if (any(fill_idx)) alvo[fill_idx] <- aux[fill_idx]
      data.table::set(dt, j = target, value = alvo)
      dt[, (col) := NULL]
      monitora_log_registrar_evento("consolidacao_aliases", "INFO", NA_character_, paste0(target, " consolidado de: ", col), "coluna auxiliar removida apos coalesce")
      rm(alvo, aux, fill_idx)
      if (monitora_recurso_deve_gc()) gc(verbose = FALSE)
    }

    # Recalcula nomes canônicos porque colunas podem ter sido removidas/renomeadas.
    canon <- monitora_txt_canonicalizar_coluna(names(dt))
  }
  dt
}


# Deduplicação semântica compatível com exportação em lote.
# Não usa UUID de coleta como UUID de registro amostral.

### Detecção formal do tipo de entrada por nome de arquivo e cabeçalho.
### O objetivo é distinguir: exportação individual do SISMONITORA, exportação em lote
### de exportação em lote e arquivos pós-tratamento registros_corrig*.csv usados como entrada.
monitora_io_detectar_tipo_csv <- function(path) {
  base <- basename(path)
  header <- tryCatch(
    names(fread(path, nrows = 0, encoding = "UTF-8", check.names = FALSE, showProgress = FALSE)),
    error = function(e) character()
  )
  header_canon <- monitora_txt_canonicalizar_coluna(header)

  if (grepl("registros[._-]?corrig|corrigido|corrigida|pos[._-]?trat|p[oó]s[._-]?trat|registros_corrig", base, ignore.case = TRUE) ||
      any(header %in% c("MONITORA_TIPO_ENTRADA", "MONITORA_ARQUIVO_ENTRADA", "MONITORA_ARQUIVO_ORIGEM_EXECUCAO"))) {
    return("pos_tratamento_script")
  }

  # Exportação em lote: normalmente CSV consolidado com caminhos internos
  # do formulário e colunas com sufixos de nomes repetidos, como uc...5.
  if (any(header %in% c("amostragem/registro/ponto_amostral", "amostragem/registro/ponto_metro", "amostragem/registro/uuid", "coleta_uuid", "data_do_registro")) ||
      any(grepl("^uc\\.\\.\\.[0-9]+$", header))) {
    return("bruto_lote_sismonitora")
  }

  # Exportação individual tradicional: CSVs de uma coleta, frequentemente extraídos de ZIPs
  # internos,
  # com colunas em maiúsculas no cabeçalho principal.
  if (all(c("UUID", "COLETA", "UC", "CICLO", "CAMPANHA", "UA") %in% header) ||
      all(c("uuid", "coleta", "uc", "ciclo", "campanha", "ua") %in% header_canon)) {
    return("bruto_individual_sismonitora")
  }

  "desconhecido"
}

monitora_io_resumir_fontes_por_tipo <- function(csv_audit) {
  if (is.null(csv_audit) || nrow(csv_audit) == 0 || !"tipo_entrada" %in% names(csv_audit)) return(invisible(NULL))
  resumo <- csv_audit[, .(
    n_arquivos = .N,
    n_linhas = sum(as.integer(n_linhas), na.rm = TRUE),
    n_colunas_min = suppressWarnings(min(as.integer(n_colunas), na.rm = TRUE)),
    n_colunas_max = suppressWarnings(max(as.integer(n_colunas), na.rm = TRUE)),
    arquivos_exemplo = paste(utils::head(basename, 10), collapse = " | ")
  ), by = tipo_entrada]
  resumo[is.infinite(n_colunas_min), n_colunas_min := NA_integer_]
  resumo[is.infinite(n_colunas_max), n_colunas_max := NA_integer_]
  monitora_fwrite(resumo, file.path(MONITORA_LOG_DIR, paste0("auditoria_tipos_entrada_", MONITORA_EXEC_ID, ".csv")))
  monitora_log_registrar_evento("tipos_entrada", "INFO", NA_character_, paste(paste0(resumo$tipo_entrada, ": ", resumo$n_arquivos, " arquivo(s)"), collapse = " | "), "ver auditoria_tipos_entrada")
  invisible(resumo)
}


# Normaliza nomes públicos dos tipos de entrada, preservando compatibilidade com
# arquivos tratados por edições anteriores do script.
monitora_io_normalizar_tipo_entrada <- function(tipo) {
  tipo <- as.character(tipo)
  tipo[tipo == paste0("bruto_lote_sismonitora", "_", "d", "ev")] <- "bruto_lote_sismonitora"
  tipo
}

# Anota o tipo de entrada antes da deduplicação, permitindo auditoria pré-deduplicação real.
# A coluna MONITORA_TIPO_ENTRADA precisa existir antes das auditorias de compatibilidade.
# Sem essa coluna, a auditoria pré-deduplicação ficaria limitada.
monitora_io_anotar_tipo_entrada <- function(dt, arquivos_entrada = NULL) {
  dt <- monitora_dt_referenciar(dt)
  if ("MONITORA_TIPO_ENTRADA" %in% names(dt) && any(!is.na(dt$MONITORA_TIPO_ENTRADA))) {
    data.table::set(dt, j = "MONITORA_TIPO_ENTRADA", value = monitora_io_normalizar_tipo_entrada(dt$MONITORA_TIPO_ENTRADA))
    return(dt)
  }
  source_col <- if ("MONITORA_ARQUIVO_ENTRADA" %in% names(dt)) {
    "MONITORA_ARQUIVO_ENTRADA"
  } else if (".id" %in% names(dt)) {
    ".id"
  } else {
    NA_character_
  }
  if (is.na(source_col)) {
    # Evita cópia rasa de data.table ao adicionar coluna em objeto já copiado pelo R.
    data.table::setalloccol(dt, ncol(dt) + 8L)
    data.table::set(dt, j = "MONITORA_TIPO_ENTRADA", value = rep("desconhecido", nrow(dt)))
    monitora_log_registrar_evento("tipos_entrada", "AVISO", NA_character_, "Coluna de proveniência ausente; MONITORA_TIPO_ENTRADA definido como desconhecido", "auditoria pre_dedup limitada")
    return(dt)
  }
  id_chr <- basename(as.character(dt[[source_col]]))
  tipo <- rep("desconhecido", nrow(dt))
  if (!is.null(arquivos_entrada) && all(c("basename", "tipo_entrada") %in% names(arquivos_entrada))) {
    tipo_map <- setNames(as.character(arquivos_entrada$tipo_entrada), basename(as.character(arquivos_entrada$basename)))
    idx <- match(id_chr, names(tipo_map))
    tipo[!is.na(idx)] <- tipo_map[idx[!is.na(idx)]]
  }
  tipo <- monitora_io_normalizar_tipo_entrada(tipo)
  # setalloccol() + set() reduz o risco de cópia rasa ao adicionar colunas em data.table.
  data.table::setalloccol(dt, ncol(dt) + 8L)
  data.table::set(dt, j = "MONITORA_TIPO_ENTRADA", value = tipo)
  dt
}


monitora_auditoria_compatibilidade_fontes <- function(dt, fase = "pre_dedup") {
  dt <- monitora_dt_referenciar(dt)
  fase <- as.character(fase)[1]
  if (is.na(fase) || fase == "") fase <- "sem_fase"
  fase_segura <- gsub("[^A-Za-z0-9_]+", "_", fase)

  if (!"MONITORA_TIPO_ENTRADA" %in% names(dt)) {
    aud <- data.table(
      fase = fase,
      status_global = "sem_coluna_MONITORA_TIPO_ENTRADA",
      n_registros_total = nrow(dt)
    )
    monitora_fwrite(aud, file.path(MONITORA_LOG_DIR, paste0("auditoria_compatibilidade_fontes_", fase_segura, "_", MONITORA_EXEC_ID, ".csv")))
    monitora_log_registrar_evento("compatibilidade_fontes", "AVISO", NA_character_, "Coluna MONITORA_TIPO_ENTRADA ausente; auditoria limitada", paste0("fase=", fase))
    return(invisible(aud))
  }

  tipos <- sort(unique(na.omit(as.character(dt$MONITORA_TIPO_ENTRADA))))

  get_col <- function(nm) if (nm %in% names(dt)) dt[[nm]] else rep(NA_character_, nrow(dt))
  primeira_col_existente <- function(alternativas) {
    alternativas[alternativas %in% names(dt)][1]
  }

  ponto_col <- primeira_col_existente(c(
    "ponto_amostral (amostragem/registro)",
    "Ponto amostral (amostragem/registro)",
    "amostragem/registro/ponto_amostral",
    "ponto_amostral",
    "ponto_metro (amostragem/registro)",
    "Ponto metro (amostragem/registro)",
    "amostragem/registro/ponto_metro",
    "ponto_metro"
  ))
  uc_col <- primeira_col_existente(c("UC", "uc", "uc...5", "uc...17"))
  ciclo_col <- primeira_col_existente(c("CICLO", "ciclo"))
  campanha_col <- primeira_col_existente(c("CAMPANHA", "campanha"))
  ua_col <- primeira_col_existente(c("UA", "ua"))

  cols_minimas <- c(uc_col, ciclo_col, campanha_col, ua_col, ponto_col)
  if (any(is.na(cols_minimas))) {
    aud <- data.table(
      fase = fase,
      status_global = "colunas_minimas_ausentes",
      coluna_uc = ifelse(is.na(uc_col), NA_character_, uc_col),
      coluna_ciclo = ifelse(is.na(ciclo_col), NA_character_, ciclo_col),
      coluna_campanha = ifelse(is.na(campanha_col), NA_character_, campanha_col),
      coluna_ua = ifelse(is.na(ua_col), NA_character_, ua_col),
      coluna_ponto = ifelse(is.na(ponto_col), NA_character_, ponto_col),
      tipos_entrada = paste(tipos, collapse = " | "),
      n_registros_total = nrow(dt)
    )
    monitora_fwrite(aud, file.path(MONITORA_LOG_DIR, paste0("auditoria_compatibilidade_fontes_", fase_segura, "_", MONITORA_EXEC_ID, ".csv")))
    monitora_log_registrar_evento("compatibilidade_fontes", "AVISO", NA_character_, "Colunas mínimas ausentes; auditoria de compatibilidade limitada", paste0("fase=", fase))
    return(invisible(aud))
  }

  norm_key <- function(x) stringr::str_squish(toupper(as.character(monitora_txt_normalizar_vazio(x))))
  tmp <- data.table(
    UC = norm_key(get_col(uc_col)),
    CICLO = norm_key(get_col(ciclo_col)),
    CAMPANHA = norm_key(get_col(campanha_col)),
    UA = norm_key(get_col(ua_col)),
    ponto = norm_key(get_col(ponto_col)),
    MONITORA_TIPO_ENTRADA = as.character(dt$MONITORA_TIPO_ENTRADA)
  )
  tmp <- tmp[!is.na(UC) & !is.na(CICLO) & !is.na(CAMPANHA) & !is.na(UA) & !is.na(ponto) & !is.na(MONITORA_TIPO_ENTRADA)]

  if (nrow(tmp) == 0) {
    aud <- data.table(
      fase = fase,
      status_global = "sem_registros_validos_para_auditoria",
      tipos_entrada = paste(tipos, collapse = " | "),
      n_registros_total = nrow(dt)
    )
    monitora_fwrite(aud, file.path(MONITORA_LOG_DIR, paste0("auditoria_compatibilidade_fontes_", fase_segura, "_", MONITORA_EXEC_ID, ".csv")))
    monitora_log_registrar_evento("compatibilidade_fontes", "AVISO", NA_character_, "Nenhum registro válido para auditoria de compatibilidade", paste0("fase=", fase))
    return(invisible(aud))
  }

  aud <- tmp[, .(
    n_registros = .N,
    n_pontos_distintos = uniqueN(ponto)
  ), by = .(UC, CICLO, CAMPANHA, UA, MONITORA_TIPO_ENTRADA)]

  aud_reg_wide <- dcast(aud, UC + CICLO + CAMPANHA + UA ~ MONITORA_TIPO_ENTRADA, value.var = "n_registros", fill = 0)
  aud_pts_wide <- dcast(aud, UC + CICLO + CAMPANHA + UA ~ MONITORA_TIPO_ENTRADA, value.var = "n_pontos_distintos", fill = 0)

  reg_tipo_cols <- setdiff(names(aud_reg_wide), c("UC", "CICLO", "CAMPANHA", "UA"))
  setnames(aud_reg_wide, reg_tipo_cols, paste0("n_registros__", reg_tipo_cols))
  pts_tipo_cols <- setdiff(names(aud_pts_wide), c("UC", "CICLO", "CAMPANHA", "UA"))
  setnames(aud_pts_wide, pts_tipo_cols, paste0("n_pontos__", pts_tipo_cols))

  aud_wide <- merge(aud_reg_wide, aud_pts_wide, by = c("UC", "CICLO", "CAMPANHA", "UA"), all = TRUE)
  aud_wide[, fase := fase]
  setcolorder(aud_wide, c("fase", "UC", "CICLO", "CAMPANHA", "UA", setdiff(names(aud_wide), c("fase", "UC", "CICLO", "CAMPANHA", "UA"))))

  reg_cols <- grep("^n_registros__", names(aud_wide), value = TRUE)
  pts_cols <- grep("^n_pontos__", names(aud_wide), value = TRUE)

  if (length(reg_cols) >= 2) {
    aud_wide[, status := fifelse(rowSums(.SD > 0) == length(reg_cols), "presente_em_todas_as_fontes", "ausente_em_alguma_fonte"), .SDcols = reg_cols]
    aud_wide[, registros_min := do.call(pmin, c(.SD, na.rm = TRUE)), .SDcols = reg_cols]
    aud_wide[, registros_max := do.call(pmax, c(.SD, na.rm = TRUE)), .SDcols = reg_cols]
    aud_wide[registros_min != registros_max, status := "divergencia_n_registros"]
    if (length(pts_cols) >= 2) {
      aud_wide[, pontos_min := do.call(pmin, c(.SD, na.rm = TRUE)), .SDcols = pts_cols]
      aud_wide[, pontos_max := do.call(pmax, c(.SD, na.rm = TRUE)), .SDcols = pts_cols]
      aud_wide[pontos_min != pontos_max & status == "presente_em_todas_as_fontes", status := "divergencia_n_pontos"]
    }
  } else {
    aud_wide[, status := "fonte_unica_apos_filtro_ou_deduplicacao"]
    if (length(reg_cols) == 1) {
      aud_wide[, registros_min := get(reg_cols[1])]
      aud_wide[, registros_max := get(reg_cols[1])]
    }
    if (length(pts_cols) == 1) {
      aud_wide[, pontos_min := get(pts_cols[1])]
      aud_wide[, pontos_max := get(pts_cols[1])]
    }
  }

  saida <- file.path(MONITORA_LOG_DIR, paste0("auditoria_compatibilidade_fontes_", fase_segura, "_", MONITORA_EXEC_ID, ".csv"))
  monitora_fwrite(aud_wide, saida)
  monitora_log_registrar_evento("compatibilidade_fontes", "INFO", NA_character_, paste0(nrow(aud_wide), " grupos UC+CICLO+CAMPANHA+UA auditados; fase=", fase), basename(saida))
  invisible(aud_wide)
}

# Relatório-resumo de achados relevantes para verificação e validação.
# Consolida, em um único CSV, os principais achados espalhados nos demais relatórios.
# Inclui CSV interno, ZIP externo baixado e ZIP interno, quando existirem.
monitora_auditoria_criar_resumo_achados <- function() {
  add_row <- function(categoria, severidade = "INFO", status = NA_character_, fase = NA_character_,
                      UC = NA_character_, CICLO = NA_character_, CAMPANHA = NA_character_, UA = NA_character_, COLETA = NA_character_,
                      tipo_entrada = NA_character_, n_registros = NA_integer_, n_pontos = NA_integer_,
                      arquivo_csv = NA_character_, nome_csv = NA_character_,
                      arquivo_entrada_externo = NA_character_, nome_arquivo_entrada_externo = NA_character_,
                      arquivo_zip_externo = NA_character_, nome_zip_externo = NA_character_,
                      arquivo_zip_interno = NA_character_, nome_zip_interno = NA_character_,
                      caminho_relativo_extraido = NA_character_,
                      arquivo_csv_mantido = NA_character_, arquivo_csv_excluido = NA_character_,
                      nome_csv_mantido = NA_character_, nome_csv_excluido = NA_character_,
                      nome_zip_externo_mantido = NA_character_, nome_zip_externo_excluido = NA_character_,
                      nome_zip_interno_mantido = NA_character_, nome_zip_interno_excluido = NA_character_,
                      md5 = NA_character_, detalhe = NA_character_, relatorio_origem = NA_character_, acao_recomendada = NA_character_) {
    data.table(
      categoria = as.character(categoria),
      severidade = as.character(severidade),
      status = as.character(status),
      fase = as.character(fase),
      UC = as.character(UC),
      CICLO = as.character(CICLO),
      CAMPANHA = as.character(CAMPANHA),
      UA = as.character(UA),
      COLETA = as.character(COLETA),
      tipo_entrada = as.character(tipo_entrada),
      n_registros = suppressWarnings(as.integer(n_registros)),
      n_pontos = suppressWarnings(as.integer(n_pontos)),
      arquivo_csv = as.character(arquivo_csv),
      nome_csv = as.character(nome_csv),
      arquivo_entrada_externo = as.character(arquivo_entrada_externo),
      nome_arquivo_entrada_externo = as.character(nome_arquivo_entrada_externo),
      arquivo_zip_externo = as.character(arquivo_zip_externo),
      nome_zip_externo = as.character(nome_zip_externo),
      arquivo_zip_interno = as.character(arquivo_zip_interno),
      nome_zip_interno = as.character(nome_zip_interno),
      caminho_relativo_extraido = as.character(caminho_relativo_extraido),
      arquivo_csv_mantido = as.character(arquivo_csv_mantido),
      arquivo_csv_excluido = as.character(arquivo_csv_excluido),
      nome_csv_mantido = as.character(nome_csv_mantido),
      nome_csv_excluido = as.character(nome_csv_excluido),
      nome_zip_externo_mantido = as.character(nome_zip_externo_mantido),
      nome_zip_externo_excluido = as.character(nome_zip_externo_excluido),
      nome_zip_interno_mantido = as.character(nome_zip_interno_mantido),
      nome_zip_interno_excluido = as.character(nome_zip_interno_excluido),
      md5 = as.character(md5),
      detalhe = as.character(detalhe),
      relatorio_origem = as.character(relatorio_origem),
      acao_recomendada = as.character(acao_recomendada)
    )
  }

  rows <- list()
  origem_tipos <- paste0("auditoria_tipos_entrada_", MONITORA_EXEC_ID, ".csv")
  origem_csv <- paste0("auditoria_arquivos_csv_", MONITORA_EXEC_ID, ".csv")
  origem_dup_exatos <- paste0("auditoria_arquivos_csv_duplicados_exatos_", MONITORA_EXEC_ID, ".csv")
  origem_rel <- paste0("relatorio_execucao_", MONITORA_EXEC_ID, ".csv")

  if (exists("csv_audit") && is.data.table(csv_audit) && nrow(csv_audit) > 0 && "tipo_entrada" %in% names(csv_audit)) {
    tipos <- csv_audit[, .(
      n_arquivos = .N,
      n_linhas = sum(as.integer(n_linhas), na.rm = TRUE),
      n_colunas_min = suppressWarnings(min(as.integer(n_colunas), na.rm = TRUE)),
      n_colunas_max = suppressWarnings(max(as.integer(n_colunas), na.rm = TRUE)),
      exemplos_csv = paste(utils::head(basename, 5), collapse = " | "),
      exemplos_zip_externo = paste(unique(na.omit(utils::head(nome_zip_externo, 5))), collapse = " | "),
      exemplos_zip_interno = paste(unique(na.omit(utils::head(nome_zip_interno, 5))), collapse = " | ")
    ), by = tipo_entrada]
    for (i in seq_len(nrow(tipos))) {
      rows[[length(rows) + 1]] <- add_row(
        categoria = "resumo_tipo_entrada",
        severidade = "INFO",
        status = "detectado",
        tipo_entrada = tipos$tipo_entrada[i],
        n_registros = tipos$n_linhas[i],
        nome_zip_externo = tipos$exemplos_zip_externo[i],
        nome_zip_interno = tipos$exemplos_zip_interno[i],
        detalhe = paste0(tipos$n_arquivos[i], " arquivo(s); colunas min/max=", tipos$n_colunas_min[i], "/", tipos$n_colunas_max[i], "; exemplos_csv=", tipos$exemplos_csv[i]),
        relatorio_origem = paste(origem_tipos, origem_csv, sep = " | "),
        acao_recomendada = "Conferir se os tipos detectados correspondem às entradas esperadas. Use nome_zip_externo/nome_zip_interno para localizar os pacotes baixados."
      )
    }
  }

  if (exists("MONITORA_AUDITORIA_DUPLICIDADES_ARQUIVO") && is.data.table(MONITORA_AUDITORIA_DUPLICIDADES_ARQUIVO) && nrow(MONITORA_AUDITORIA_DUPLICIDADES_ARQUIVO) > 0) {
    for (i in seq_len(nrow(MONITORA_AUDITORIA_DUPLICIDADES_ARQUIVO))) {
      d <- MONITORA_AUDITORIA_DUPLICIDADES_ARQUIVO[i]
      rows[[length(rows) + 1]] <- add_row(
        categoria = "csv_duplicado_exato",
        severidade = "AVISO",
        status = "arquivo_excluido_da_importacao",
        UC = if ("UC" %in% names(d)) d$UC else NA_character_,
        CICLO = if ("CICLO" %in% names(d)) d$CICLO else NA_character_,
        CAMPANHA = if ("CAMPANHA" %in% names(d)) d$CAMPANHA else NA_character_,
        UA = if ("UA" %in% names(d)) d$UA else NA_character_,
        COLETA = if ("COLETA" %in% names(d)) d$COLETA else NA_character_,
        tipo_entrada = if ("tipo_entrada" %in% names(d)) d$tipo_entrada else NA_character_,
        n_registros = if ("n_linhas" %in% names(d)) d$n_linhas else NA_integer_,
        arquivo_csv_mantido = d$arquivo_mantido,
        arquivo_csv_excluido = d$arquivo_excluido,
        nome_csv_mantido = d$basename_mantido,
        nome_csv_excluido = d$basename_excluido,
        nome_zip_externo_mantido = if ("nome_zip_externo_mantido" %in% names(d)) d$nome_zip_externo_mantido else NA_character_,
        nome_zip_externo_excluido = if ("nome_zip_externo_excluido" %in% names(d)) d$nome_zip_externo_excluido else NA_character_,
        nome_zip_interno_mantido = if ("nome_zip_interno_mantido" %in% names(d)) d$nome_zip_interno_mantido else NA_character_,
        nome_zip_interno_excluido = if ("nome_zip_interno_excluido" %in% names(d)) d$nome_zip_interno_excluido else NA_character_,
        md5 = d$md5,
        detalhe = "Dois ou mais CSVs tinham mesmo MD5 e mesmo tamanho em bytes; o primeiro foi mantido e o(s) seguinte(s) excluído(s) antes da consolidação.",
        relatorio_origem = paste(origem_rel, origem_csv, origem_dup_exatos, sep = " | "),
        acao_recomendada = "Localizar pelo nome_zip_externo/nome_zip_interno e confirmar se é duplicidade de exportação; verificar se alguma UA esperada ficou ausente no conjunto individual."
      )
    }
  }

  processa_compat <- function(obj_name, fase_nome) {
    if (!exists(obj_name, inherits = TRUE)) return(NULL)
    aud <- get(obj_name, inherits = TRUE)
    if (!data.table::is.data.table(aud)) data.table::setDT(aud)
    if (nrow(aud) == 0 || !"status" %in% names(aud)) return(NULL)
    origem <- paste0("auditoria_compatibilidade_fontes_", fase_nome, "_", MONITORA_EXEC_ID, ".csv")
    problem <- aud[!is.na(status) & !status %in% c("presente_em_todas_as_fontes", "fonte_unica_apos_filtro_ou_deduplicacao")]
    if (nrow(problem) == 0) {
      return(add_row(
        categoria = "compatibilidade_fontes",
        severidade = "INFO",
        status = "sem_divergencias_relevantes",
        fase = fase_nome,
        n_registros = nrow(aud),
        detalhe = paste0(nrow(aud), " grupo(s) auditado(s) sem divergências relevantes nesta fase."),
        relatorio_origem = origem,
        acao_recomendada = "Nenhuma ação necessária para esta fase."
      ))
    }
    out <- list()
    reg_cols <- grep("^n_registros__", names(problem), value = TRUE)
    pts_cols <- grep("^n_pontos__", names(problem), value = TRUE)
    for (i in seq_len(nrow(problem))) {
      r <- problem[i]
      det_regs <- if (length(reg_cols) > 0) paste(paste0(sub("^n_registros__", "", reg_cols), "=", as.character(unlist(r[, ..reg_cols]))), collapse = "; ") else NA_character_
      det_pts <- if (length(pts_cols) > 0) paste(paste0(sub("^n_pontos__", "", pts_cols), "=", as.character(unlist(r[, ..pts_cols]))), collapse = "; ") else NA_character_
      rows_lacuna <- NULL
      out[[length(out) + 1]] <- add_row(
        categoria = "compatibilidade_fontes",
        severidade = ifelse(as.character(r$status) %in% c("divergencia_n_registros", "ausente_em_alguma_fonte"), "AVISO", "INFO"),
        status = as.character(r$status),
        fase = fase_nome,
        UC = if ("UC" %in% names(r)) r$UC else NA_character_,
        CICLO = if ("CICLO" %in% names(r)) r$CICLO else NA_character_,
        CAMPANHA = if ("CAMPANHA" %in% names(r)) r$CAMPANHA else NA_character_,
        UA = if ("UA" %in% names(r)) r$UA else NA_character_,
        n_registros = if ("registros_max" %in% names(r)) r$registros_max else NA_integer_,
        n_pontos = if ("pontos_max" %in% names(r)) r$pontos_max else NA_integer_,
        detalhe = paste0("Registros por fonte: ", det_regs, " | Pontos por fonte: ", det_pts),
        relatorio_origem = origem,
        acao_recomendada = "Conferir a UA/fonte indicada; se uma fonte estiver zerada, verificar duplicidade exata ou ausência no pacote de entrada."
      )
    }
    rbindlist(out, fill = TRUE)
  }
  comp_pre <- processa_compat("MONITORA_AUDITORIA_COMPATIBILIDADE_FONTES_PRE", "pre_dedup")
  if (!is.null(comp_pre)) rows[[length(rows) + 1]] <- comp_pre
  comp_pos <- processa_compat("MONITORA_AUDITORIA_COMPATIBILIDADE_FONTES_POST", "pos_dedup")
  if (!is.null(comp_pos)) rows[[length(rows) + 1]] <- comp_pos

  if (exists("MONITORA_DUPLICIDADES_SEMANTICAS_RESUMO") && is.data.table(MONITORA_DUPLICIDADES_SEMANTICAS_RESUMO) && nrow(MONITORA_DUPLICIDADES_SEMANTICAS_RESUMO) > 0) {
    sem <- MONITORA_DUPLICIDADES_SEMANTICAS_RESUMO
    rows[[length(rows) + 1]] <- add_row(
      categoria = "duplicidade_semantica",
      severidade = "AVISO",
      status = "linhas_sobrepostas_removidas_por_preferencia_de_fonte",
      n_registros = sum(as.integer(sem$n_chaves), na.rm = TRUE),
      detalhe = paste(paste0(sem$tipos_entrada, ": ", sem$n_chaves, " chave(s)"), collapse = " | "),
      relatorio_origem = paste0("auditoria_duplicidades_semanticas_", MONITORA_EXEC_ID, ".csv"),
      acao_recomendada = "Verificar se a sobreposição é esperada. Em entradas combinadas individual+lote, é normal haver chaves duplicadas e manter a fonte prioritária."
    )
  }

  if (exists("MONITORA_AUDITORIA_ANOS_INVALIDOS") && is.data.table(MONITORA_AUDITORIA_ANOS_INVALIDOS) && nrow(MONITORA_AUDITORIA_ANOS_INVALIDOS) > 0) {
    anos <- MONITORA_AUDITORIA_ANOS_INVALIDOS
    rows[[length(rows) + 1]] <- add_row(
      categoria = "anos_invalidos",
      severidade = "AVISO",
      status = "ano_invalido_ou_data_nao_convertida",
      n_registros = nrow(anos),
      detalhe = paste0(nrow(anos), " combinação(ões) com ANO inválido/NA ou fora da faixa plausível."),
      relatorio_origem = paste0("auditoria_anos_invalidos_", MONITORA_EXEC_ID, ".csv"),
      acao_recomendada = "Corrigir a data original ou verificar erro de parsing antes de aceitar estatísticas temporais e gráficos."
    )
  }

  if (exists("MONITORA_AUDITORIA_COMPLETUDE_101_PONTOS") && is.data.table(MONITORA_AUDITORIA_COMPLETUDE_101_PONTOS) && nrow(MONITORA_AUDITORIA_COMPLETUDE_101_PONTOS) > 0) {
    pts101 <- MONITORA_AUDITORIA_COMPLETUDE_101_PONTOS
    for (i in seq_len(nrow(pts101))) {
      r <- pts101[i]
      rows[[length(rows) + 1]] <- add_row(
        categoria = "completude_101_pontos",
        severidade = "AVISO",
        status = "grupo_com_pontos_ausentes_duplicados_ou_fora_da_faixa",
        UC = if ("UC" %in% names(r)) r$UC else NA_character_,
        CICLO = if ("CICLO" %in% names(r)) r$CICLO else NA_character_,
        CAMPANHA = if ("CAMPANHA" %in% names(r)) r$CAMPANHA else NA_character_,
        UA = if ("UA" %in% names(r)) r$UA else NA_character_,
        n_registros = if ("n_registros" %in% names(r)) r$n_registros else NA_integer_,
        n_pontos = if ("n_pontos" %in% names(r)) r$n_pontos else NA_integer_,
        detalhe = paste0("pontos_ausentes=", if ("pontos_ausentes" %in% names(r)) r$pontos_ausentes else "", "; pontos_duplicados=", if ("pontos_duplicados" %in% names(r)) r$pontos_duplicados else "", "; pontos_fora_1_101=", if ("pontos_fora_1_101" %in% names(r)) r$pontos_fora_1_101 else ""),
        relatorio_origem = paste0("auditoria_completude_101_pontos_", MONITORA_EXEC_ID, ".csv"),
        acao_recomendada = "Conferir e corrigir a UA/ano para garantir exatamente 101 pontos válidos antes de aceitar os produtos."
      )
    }
  }

  if (exists("MONITORA_LOG_EXECUCAO") && is.data.table(MONITORA_LOG_EXECUCAO) && nrow(MONITORA_LOG_EXECUCAO) > 0 && all(c("severidade", "etapa") %in% names(MONITORA_LOG_EXECUCAO))) {
    avisos <- MONITORA_LOG_EXECUCAO[severidade %in% c("AVISO", "ERRO") & !etapa %in% c("duplicidade_arquivo", "deduplicacao_semantica")]
    if (nrow(avisos) > 0) {
      for (i in seq_len(nrow(avisos))) {
        rows[[length(rows) + 1]] <- add_row(
          categoria = paste0("relatorio_execucao_", tolower(avisos$severidade[i])),
          severidade = avisos$severidade[i],
          status = avisos$etapa[i],
          arquivo_csv = if ("arquivo" %in% names(avisos)) avisos$arquivo[i] else NA_character_,
          nome_csv = if ("arquivo" %in% names(avisos)) basename(avisos$arquivo[i]) else NA_character_,
          detalhe = if ("detalhe" %in% names(avisos)) avisos$detalhe[i] else NA_character_,
          relatorio_origem = origem_rel,
          acao_recomendada = if (avisos$severidade[i] == "ERRO") "Verificar antes de aceitar a execução." else "Revisar se o aviso afeta a validação da execução."
        )
      }
    }
  }

  if (length(rows) == 0) {
    resumo <- add_row(
      categoria = "resumo_achados",
      severidade = "INFO",
      status = "sem_achados_relevantes",
      detalhe = "Nenhum achado relevante foi identificado nas auditorias disponíveis.",
      acao_recomendada = "Nenhuma ação necessária."
    )
  } else {
    resumo <- rbindlist(rows, fill = TRUE)
  }

  resumo[, id_achado := sprintf("ACH-%04d", seq_len(.N))]
  setcolorder(resumo, c("id_achado", setdiff(names(resumo), "id_achado")))
  saida_log <- file.path(MONITORA_LOG_DIR, paste0("auditoria_resumo_achados_relevantes_", MONITORA_EXEC_ID, ".csv"))
  saida_out <- file.path(MONITORA_OUTPUT_DIR, "auditoria_resumo_achados_relevantes_ultima_execucao.csv")
  monitora_fwrite(resumo, saida_log)
  monitora_fwrite(resumo, saida_out)
  monitora_log_registrar_evento("resumo_achados_validacao", "INFO", saida_log, paste0(nrow(resumo), " achado(s) consolidado(s) para verificação/validação"), "também exportado em output/auditoria_resumo_achados_relevantes_ultima_execucao.csv")
  invisible(resumo)
}



### v2.6.1
### v2.6.1 -----------------------------
### Sanitização contratual obrigatória antes de registros_validados.csv.
### A exportação 21FEV25 não deve herdar diretamente campos históricos de
### "outra forma de vida" nem dependentes de "desconhecida" quando o token
### correspondente já foi removido. Esta etapa atua em registros_corrig, usando
### data.table por referência, antes do mapeamento para o schema SISMONITORA.
monitora_registros_validados_forma_outros_tokens_atuais <- function() {
  c("musgos", "hepaticas", "antoceros", "liquens", "fungos")
}

monitora_registros_validados_coluna_forma_outros_atual <- function(dt, dicionario = NULL) {
  dt <- data.table::as.data.table(dt)
  nms <- names(dt)
  if (!length(nms)) return(NA_character_)
  cols_info <- tryCatch(monitora_correcao_colunas_limpeza_outras_formas(dt, dicionario), error = function(e) data.table::data.table())
  if (nrow(cols_info)) {
    cand <- cols_info[classe == "campo_atual_forma_vida_outros" & coluna %in% nms, unique(coluna)]
    if (length(cand)) return(cand[1L])
  }
  aliases <- c(
    "amostragem/registro/forma_vida_outros",
    "forma_vida_outros",
    "Outras plantas terrestres, líquens e/ou fungos\u200b: (amostragem/registro)",
    "Outras plantas terrestres, líquens e/ou fungos: (amostragem/registro)"
  )
  hit <- aliases[aliases %in% nms]
  if (length(hit)) return(hit[1L])
  nms_norm <- monitora_correcao_normalizar_nome_coluna(nms)
  idx <- which(nms_norm %in% monitora_correcao_normalizar_nome_coluna(aliases))
  if (length(idx)) return(nms[idx[1L]])
  NA_character_
}

monitora_registros_validados_sanitizar_valor_forma_outros <- function(x) {
  if (length(x) == 0L || is.na(x[1L])) return(NA_character_)
  x <- as.character(x[1L])
  if (!nzchar(trimws(x))) return(NA_character_)
  atuais <- monitora_registros_validados_forma_outros_tokens_atuais()
  atuais_norm <- monitora_correcao_normalizar_descritor_outra_forma(atuais)
  mapa <- stats::setNames(atuais, atuais_norm)
  toks <- monitora_correcao_tokenizar(x)
  if (!length(toks)) return(NA_character_)
  out <- character(0)
  for (tt in toks) {
    nn <- monitora_correcao_normalizar_descritor_outra_forma(tt)
    if (!length(nn) || is.na(nn[1L]) || !nzchar(nn[1L])) next
    if (nn[1L] %in% names(mapa)) {
      out <- c(out, unname(mapa[[nn[1L]]]))
      next
    }
    cls <- monitora_correcao_classificar_descritor_outra_forma(tt)
    tk <- as.character(cls$token_xlsform21[1L])
    if (!is.na(tk) && nzchar(tk)) out <- c(out, monitora_correcao_tokenizar(tk))
  }
  out <- unique(out[out %in% atuais])
  if (!length(out)) return(NA_character_)
  paste(out, collapse = " ")
}

monitora_registros_validados_sanitizar_forma_outros_atual <- function(dt,
                                                                       linhas = NULL,
                                                                       dicionario = NULL,
                                                                       id_correcao = "v2.5.4",
                                                                       arquivo_correcao = "pos_painel_pre_registros_corrig") {
  dt <- monitora_dt_referenciar(dt)
  if (is.null(linhas)) linhas <- seq_len(nrow(dt))
  linhas <- unique(as.integer(linhas))
  linhas <- linhas[!is.na(linhas) & linhas >= 1L & linhas <= nrow(dt)]
  audit <- data.table::data.table(
    id_correcao = character(), ordem_operacao = character(), status = character(), mensagem = character(),
    atributo = character(), linha_indice = integer(), valor_antes = character(), valor_depois = character(), arquivo_correcao = character()
  )
  afetacoes <- data.table::data.table(linha_indice = integer(), atributo = character())
  if (!length(linhas)) return(list(dt = dt[], audit = audit, afetacoes = afetacoes, linhas = integer(), falha = FALSE))
  cc <- monitora_registros_validados_coluna_forma_outros_atual(dt, dicionario)
  if (is.na(cc) || !(cc %in% names(dt))) return(list(dt = dt[], audit = audit, afetacoes = afetacoes, linhas = integer(), falha = FALSE))
  antes <- as.character(dt[[cc]][linhas])
  depois <- vapply(antes, monitora_registros_validados_sanitizar_valor_forma_outros, character(1), USE.NAMES = FALSE)
  mudou <- monitora_correcao_na_para_vazio(antes) != monitora_correcao_na_para_vazio(depois)
  if (any(mudou, na.rm = TRUE)) {
    idx <- linhas[mudou]
    data.table::set(dt, i = idx, j = cc, value = depois[mudou])
    audit <- data.table::data.table(
      id_correcao = as.character(id_correcao),
      ordem_operacao = NA_character_,
      status = "forma_vida_outros_atual_sanitizado_pos_painel_pre_registros_corrig",
      mensagem = "Campo atual forma_vida_outros sanitizado antes de registros_validados.csv: preserva apenas tokens atuais 21FEV25 e remove/converte resíduos legados.",
      atributo = cc,
      linha_indice = idx,
      valor_antes = antes[mudou],
      valor_depois = depois[mudou],
      arquivo_correcao = as.character(arquivo_correcao)
    )
    afetacoes <- data.table::data.table(linha_indice = idx, atributo = cc)
  }
  list(dt = dt[], audit = audit[], afetacoes = afetacoes[], linhas = unique(afetacoes$linha_indice), falha = FALSE)
}


### v2.6.1 --------------------------
### Regra taxonômica/contratual 21FEV25: não há Velloziaceae exótica conhecida
### para o escopo tratado. Registros históricos com canela_de_ema em formas
### exóticas devem migrar para a lista de formas nativas antes da validação do
### contrato de registros_corrig.csv.
monitora_publicacao_ab_tokens_canela_de_ema_historicos <- function() {
  c("canela_de_ema", "vela_de_ema", "canela-de-ema", "velosia", "vellosia")
}

monitora_publicacao_ab_valor_tem_canela_de_ema <- function(x) {
  toks <- monitora_correcao_tokenizar(x)
  if (!length(toks)) return(FALSE)
  toks_norm <- monitora_correcao_normalizar_nome_coluna(toks)
  any(toks_norm %in% monitora_correcao_normalizar_nome_coluna(monitora_publicacao_ab_tokens_canela_de_ema_historicos()))
}

monitora_publicacao_ab_remover_canela_de_ema_valor <- function(x) {
  toks <- monitora_correcao_tokenizar(x)
  if (!length(toks)) return(NA_character_)
  toks_norm <- monitora_correcao_normalizar_nome_coluna(toks)
  remover <- toks_norm %in% monitora_correcao_normalizar_nome_coluna(monitora_publicacao_ab_tokens_canela_de_ema_historicos())
  out <- toks[!remover]
  if (!length(out)) return(NA_character_)
  monitora_correcao_colapsar_tokens(out)
}

monitora_publicacao_ab_migrar_canela_de_ema_exotica_para_nativa <- function(dt,
                                                                       linhas = NULL,
                                                                       dicionario = NULL,
                                                                       id_correcao = "v2.5.4",
                                                                       arquivo_correcao = "pos_painel_pre_registros_corrig") {
  dt <- monitora_dt_referenciar(dt)
  audit <- data.table::data.table(
    id_correcao = character(), ordem_operacao = character(), status = character(), mensagem = character(),
    atributo = character(), linha_indice = integer(), valor_antes = character(), valor_depois = character(),
    arquivo_correcao = character(), categoria_origem = character(), categoria_destino = character(), token_migrado = character()
  )
  afetacoes <- data.table::data.table(linha_indice = integer(), atributo = character())
  if (!nrow(dt)) return(list(dt = dt[], audit = audit, afetacoes = afetacoes, linhas = integer(), falha = FALSE))
  if (is.null(linhas)) linhas <- seq_len(nrow(dt))
  linhas <- unique(as.integer(linhas))
  linhas <- linhas[!is.na(linhas) & linhas >= 1L & linhas <= nrow(dt)]
  if (!length(linhas)) return(list(dt = dt[], audit = audit, afetacoes = afetacoes, linhas = integer(), falha = FALSE))

  col_exotica <- tryCatch(monitora_correcao_coluna_forma_vida(dt, "exotica"), error = function(e) NA_character_)
  col_nativa <- tryCatch(monitora_correcao_coluna_forma_vida(dt, "nativa"), error = function(e) NA_character_)
  chaves <- tryCatch(monitora_correcao_colunas_chave(dt), error = function(e) list(tipo_forma_vida = NA_character_))
  tipo_col <- chaves$tipo_forma_vida
  if (is.na(col_exotica) || !(col_exotica %in% names(dt)) || is.na(col_nativa) || !(col_nativa %in% names(dt))) {
    audit <- data.table::data.table(
      id_correcao = as.character(id_correcao), ordem_operacao = NA_character_,
      status = "falha_colunas_forma_vida_nao_localizadas",
      mensagem = "Migração canela-de-ema exótica→nativa não executada: colunas principais de forma de vida exótica/nativa não localizadas.",
      atributo = "__forma_vida_exotica_nativa__", linha_indice = NA_integer_, valor_antes = NA_character_, valor_depois = NA_character_,
      arquivo_correcao = as.character(arquivo_correcao), categoria_origem = "exotica", categoria_destino = "nativa", token_migrado = "canela_de_ema"
    )
    return(list(dt = dt[], audit = audit[], afetacoes = afetacoes, linhas = integer(), falha = TRUE))
  }

  vals_exotica <- as.character(dt[[col_exotica]][linhas])
  ### Normalização por valores distintos: evita reprocessar 31 mil linhas quando
  ### a lista exótica tem poucas combinações repetidas.
  vals_chave <- monitora_correcao_na_para_vazio(vals_exotica)
  vals_distintos <- unique(vals_chave)
  mapa_canela <- stats::setNames(
    vapply(vals_distintos, monitora_publicacao_ab_valor_tem_canela_de_ema, logical(1), USE.NAMES = FALSE),
    vals_distintos
  )
  tem_canela <- unname(mapa_canela[vals_chave])
  tem_canela[is.na(tem_canela)] <- FALSE
  idx <- linhas[tem_canela]
  if (!length(idx)) return(list(dt = dt[], audit = audit, afetacoes = afetacoes, linhas = integer(), falha = FALSE))

  antes_exotica <- as.character(dt[[col_exotica]][idx])
  antes_nativa <- as.character(dt[[col_nativa]][idx])
  depois_exotica <- vapply(antes_exotica, monitora_publicacao_ab_remover_canela_de_ema_valor, character(1), USE.NAMES = FALSE)
  depois_nativa <- vapply(antes_nativa, monitora_correcao_append_token_valor, character(1), token = "canela_de_ema", USE.NAMES = FALSE)

  mudou_exotica <- monitora_correcao_na_para_vazio(antes_exotica) != monitora_correcao_na_para_vazio(depois_exotica)
  mudou_nativa <- monitora_correcao_na_para_vazio(antes_nativa) != monitora_correcao_na_para_vazio(depois_nativa)

  if (any(mudou_exotica, na.rm = TRUE)) {
    data.table::set(dt, i = idx[mudou_exotica], j = col_exotica, value = depois_exotica[mudou_exotica])
    audit <- data.table::rbindlist(list(audit, data.table::data.table(
      id_correcao = as.character(id_correcao), ordem_operacao = NA_character_,
      status = "canela_de_ema_removida_de_exotica",
      mensagem = "Token histórico canela_de_ema removido de forma_vida_exotica; Velloziaceae exótica não é aceita no contrato XLSForm 21FEV25.",
      atributo = col_exotica, linha_indice = idx[mudou_exotica], valor_antes = antes_exotica[mudou_exotica], valor_depois = depois_exotica[mudou_exotica],
      arquivo_correcao = as.character(arquivo_correcao), categoria_origem = "exotica", categoria_destino = "nativa", token_migrado = "canela_de_ema"
    )), fill = TRUE, use.names = TRUE)
    afetacoes <- data.table::rbindlist(list(afetacoes, data.table::data.table(linha_indice = idx[mudou_exotica], atributo = col_exotica)), fill = TRUE, use.names = TRUE)
  }

  if (any(mudou_nativa, na.rm = TRUE)) {
    data.table::set(dt, i = idx[mudou_nativa], j = col_nativa, value = depois_nativa[mudou_nativa])
    audit <- data.table::rbindlist(list(audit, data.table::data.table(
      id_correcao = as.character(id_correcao), ordem_operacao = NA_character_,
      status = "canela_de_ema_garantida_em_nativa",
      mensagem = "Token canela_de_ema migrado para forma_vida_nativa por regra contratual/taxonômica definida para registros históricos.",
      atributo = col_nativa, linha_indice = idx[mudou_nativa], valor_antes = antes_nativa[mudou_nativa], valor_depois = depois_nativa[mudou_nativa],
      arquivo_correcao = as.character(arquivo_correcao), categoria_origem = "exotica", categoria_destino = "nativa", token_migrado = "canela_de_ema"
    )), fill = TRUE, use.names = TRUE)
    afetacoes <- data.table::rbindlist(list(afetacoes, data.table::data.table(linha_indice = idx[mudou_nativa], atributo = col_nativa)), fill = TRUE, use.names = TRUE)
  }

  if (!is.na(tipo_col) && tipo_col %in% names(dt)) {
    antes_tipo <- as.character(dt[[tipo_col]][idx])
    monitora_correcao_recalcular_tipo_forma_vida(dt, idx)
    depois_tipo <- as.character(dt[[tipo_col]][idx])
    mudou_tipo <- monitora_correcao_na_para_vazio(antes_tipo) != monitora_correcao_na_para_vazio(depois_tipo)
    if (any(mudou_tipo, na.rm = TRUE)) {
      audit <- data.table::rbindlist(list(audit, data.table::data.table(
        id_correcao = as.character(id_correcao), ordem_operacao = NA_character_,
        status = "tipo_forma_vida_recalculado_pos_migracao_canela_de_ema",
        mensagem = "Encostam/tipo_forma_vida recalculado após migração contratual canela-de-ema exótica→nativa.",
        atributo = tipo_col, linha_indice = idx[mudou_tipo], valor_antes = antes_tipo[mudou_tipo], valor_depois = depois_tipo[mudou_tipo],
        arquivo_correcao = as.character(arquivo_correcao), categoria_origem = "exotica", categoria_destino = "nativa", token_migrado = "canela_de_ema"
      )), fill = TRUE, use.names = TRUE)
      afetacoes <- data.table::rbindlist(list(afetacoes, data.table::data.table(linha_indice = idx[mudou_tipo], atributo = tipo_col)), fill = TRUE, use.names = TRUE)
    }
  }

  list(dt = dt[], audit = audit[], afetacoes = unique(afetacoes), linhas = unique(idx), falha = FALSE)
}
### FIM v2.6.1 ----------------------

monitora_registros_validados_gravar_auditoria_pre_sanitizacao <- function(audit, nome, output_dir = MONITORA_OUTPUT_DIR, log_dir = MONITORA_LOG_DIR, exec_id = MONITORA_EXEC_ID) {
  audit <- data.table::as.data.table(audit)
  if (!nrow(audit)) return(invisible(audit))
  dir.create(output_dir, recursive = TRUE, showWarnings = FALSE)
  dir.create(log_dir, recursive = TRUE, showWarnings = FALSE)
  arq_log <- file.path(log_dir, paste0(nome, "_", exec_id, ".csv"))
  arq_out <- file.path(output_dir, paste0(nome, ".csv"))
  try(monitora_fwrite(audit, arq_log, na = ""), silent = TRUE)
  try(monitora_fwrite(audit, arq_out, na = ""), silent = TRUE)
  invisible(audit)
}

monitora_registros_validados_sanitizar_pre_exportacao <- function(registros_corrig,
                                                                  output_dir = MONITORA_OUTPUT_DIR,
                                                                  log_dir = MONITORA_LOG_DIR,
                                                                  exec_id = MONITORA_EXEC_ID,
                                                                  dicionario = NULL,
                                                                  fechar_contrato = TRUE) {
  dt <- monitora_dt_referenciar(registros_corrig)
  if (!nrow(dt)) return(dt)
  linhas_global <- seq_len(nrow(dt))
  afetadas <- integer(0)
  aud_outras <- data.table::data.table()
  aud_desconhecida <- data.table::data.table()
  aud_canela <- data.table::data.table()

  res_outras <- tryCatch(
    monitora_correcao_aplicar_limpeza_outras_formas_atomica(
      dt,
      linhas = linhas_global,
      id_correcao = "v2.5.4",
      arquivo_correcao = "pos_painel_pre_registros_corrig",
      dicionario = dicionario
    ),
    error = function(e) list(audit = data.table::data.table(status = "falha_antes_registros_validados_outras_formas", mensagem = conditionMessage(e)), linhas = integer(), afetacoes = data.table::data.table(), falha = TRUE)
  )
  aud_outras <- data.table::rbindlist(list(aud_outras, data.table::as.data.table(res_outras$audit)), fill = TRUE, use.names = TRUE)
  afetadas <- unique(c(afetadas, as.integer(res_outras$linhas)))

  res_atual <- tryCatch(
    monitora_registros_validados_sanitizar_forma_outros_atual(
      dt,
      linhas = linhas_global,
      dicionario = dicionario,
      id_correcao = "v2.5.4",
      arquivo_correcao = "pos_painel_pre_registros_corrig"
    ),
    error = function(e) list(audit = data.table::data.table(status = "falha_antes_registros_validados_forma_outros_atual", mensagem = conditionMessage(e)), linhas = integer(), afetacoes = data.table::data.table(), falha = TRUE)
  )
  aud_outras <- data.table::rbindlist(list(aud_outras, data.table::as.data.table(res_atual$audit)), fill = TRUE, use.names = TRUE)
  afetadas <- unique(c(afetadas, as.integer(res_atual$linhas)))

  if (length(res_atual$linhas)) {
    res_recalc <- tryCatch(
      monitora_correcao_aplicar_limpeza_outras_formas_atomica(
        dt,
        linhas = unique(as.integer(res_atual$linhas)),
        id_correcao = "v2.5.4",
        arquivo_correcao = "pos_painel_pre_registros_corrig",
        dicionario = dicionario
      ),
      error = function(e) list(audit = data.table::data.table(status = "falha_antes_registros_validados_recalculo_outras_formas", mensagem = conditionMessage(e)), linhas = integer(), afetacoes = data.table::data.table(), falha = TRUE)
    )
    aud_outras <- data.table::rbindlist(list(aud_outras, data.table::as.data.table(res_recalc$audit)), fill = TRUE, use.names = TRUE)
    afetadas <- unique(c(afetadas, as.integer(res_recalc$linhas), as.integer(res_atual$linhas)))
  }

  res_canela <- tryCatch(
    monitora_publicacao_ab_migrar_canela_de_ema_exotica_para_nativa(
      dt,
      linhas = linhas_global,
      dicionario = dicionario,
      id_correcao = "v2.5.4",
      arquivo_correcao = "pos_painel_pre_registros_corrig"
    ),
    error = function(e) list(audit = data.table::data.table(status = "falha_migracao_canela_de_ema_exotica_nativa", mensagem = conditionMessage(e)), linhas = integer(), afetacoes = data.table::data.table(), falha = TRUE)
  )
  aud_canela <- data.table::rbindlist(list(aud_canela, data.table::as.data.table(res_canela$audit)), fill = TRUE, use.names = TRUE)
  afetadas <- unique(c(afetadas, as.integer(res_canela$linhas)))
  if (!is.null(res_canela$afetacoes) && nrow(data.table::as.data.table(res_canela$afetacoes))) {
    afetadas <- unique(c(afetadas, as.integer(data.table::as.data.table(res_canela$afetacoes)$linha_indice)))
  }

  res_desc <- tryCatch(
    monitora_correcao_sanitizar_dependentes_desconhecida(
      dt,
      linhas = linhas_global,
      categorias = c("nativa", "exotica", "seca_morta"),
      id_correcao = "v2.5.4",
      ordem_operacao = NA_character_,
      arquivo_correcao = "pos_painel_pre_registros_corrig",
      dicionario = dicionario,
      registrar_preservadas = FALSE
    ),
    error = function(e) list(audit = data.table::data.table(status = "falha_pos_painel_pre_corrig_desconhecida", mensagem = conditionMessage(e)), afetacoes = data.table::data.table(), falha = TRUE)
  )
  aud_desconhecida <- data.table::rbindlist(list(aud_desconhecida, data.table::as.data.table(res_desc$audit)), fill = TRUE, use.names = TRUE)
  if (!is.null(res_desc$afetacoes) && nrow(data.table::as.data.table(res_desc$afetacoes))) {
    afetadas <- unique(c(afetadas, as.integer(data.table::as.data.table(res_desc$afetacoes)$linha_indice)))
  }

  afetadas <- unique(as.integer(afetadas))
  afetadas <- afetadas[!is.na(afetadas) & afetadas >= 1L & afetadas <= nrow(dt)]
  if (length(afetadas) && isTRUE(fechar_contrato) && exists("monitora_publicacao_c_normalizar_contratos_pre_exportacao", mode = "function")) {
    try(monitora_publicacao_c_normalizar_contratos_pre_exportacao(dt, contexto = "pos_painel_pre_registros_corrig_sanitizacao", linhas = afetadas, forcar_global = FALSE), silent = TRUE)
  }

  monitora_registros_validados_gravar_auditoria_pre_sanitizacao(aud_outras, "auditoria_registros_validados_pre_sanitizacao_outras_formas", output_dir, log_dir, exec_id)
  monitora_registros_validados_gravar_auditoria_pre_sanitizacao(aud_desconhecida, "auditoria_registros_validados_pre_sanitizacao_desconhecida", output_dir, log_dir, exec_id)
  monitora_registros_validados_gravar_auditoria_pre_sanitizacao(aud_outras, "auditoria_registros_corrig_sanitizacao_contratual_outras_formas", output_dir, log_dir, exec_id)
  monitora_registros_validados_gravar_auditoria_pre_sanitizacao(aud_desconhecida, "auditoria_registros_corrig_sanitizacao_contratual_desconhecida", output_dir, log_dir, exec_id)
  monitora_registros_validados_gravar_auditoria_pre_sanitizacao(aud_canela, "auditoria_registros_corrig_migracao_canela_de_ema_exotica_nativa", output_dir, log_dir, exec_id)

  resumo <- data.table::data.table(
    exec_id = as.character(exec_id),
    contexto = "pos_painel_pre_registros_corrig",
    n_linhas = nrow(dt),
    n_linhas_afetadas = length(afetadas),
    n_eventos_outras_formas = nrow(aud_outras),
    n_eventos_desconhecida = nrow(aud_desconhecida),
    n_eventos_migracao_canela_de_ema = nrow(aud_canela),
    n_linhas_migracao_canela_de_ema = if ("linha_indice" %in% names(aud_canela)) data.table::uniqueN(as.integer(aud_canela$linha_indice[!is.na(aud_canela$linha_indice)])) else 0L,
    timestamp = format(Sys.time(), "%Y-%m-%d %H:%M:%S")
  )
  monitora_registros_validados_gravar_auditoria_pre_sanitizacao(resumo, "auditoria_registros_validados_pre_sanitizacao_resumo", output_dir, log_dir, exec_id)
  monitora_registros_validados_gravar_auditoria_pre_sanitizacao(resumo, "auditoria_registros_corrig_sanitizacao_contratual_resumo", output_dir, log_dir, exec_id)
  if (length(afetadas) && exists("monitora_publicacao_z_marcar_registros_corrig_sujo", mode = "function")) {
    cols_dirty_sanitizacao <- intersect(
      c("Encostam", "tipo_forma_vida", "forma_vida_nativa", "forma_vida_exotica", "forma_vida_seca_morta"),
      names(dt)
    )
    monitora_publicacao_z_marcar_registros_corrig_sujo(
      "sanitizacao_contratual_pos_painel_pre_registros_corrig",
      linhas = afetadas,
      colunas = cols_dirty_sanitizacao,
      outras_formas = nrow(aud_outras) > 0L,
      desconhecida = nrow(aud_desconhecida) > 0L,
      encostam = TRUE,
      registros_validados = TRUE
    )
  }
  dt
}
