monitora_validados_opcao_ativa <- function() {
  opcao <- get0("MONITORA_OPCAO_GERAR_REGISTROS_VALIDADOS", ifnotfound = "N", inherits = TRUE)
  opcao <- toupper(trimws(as.character(opcao)[1]))
  identical(opcao, "S")
}

monitora_validados_limpar_ausencia_saida <- function(x) {
  y <- as.character(x)
  y[is.na(y)] <- ""
  y <- trimws(y)
  z <- tolower(y)
  y[z %in% c("", "na", "n/a", "null", "nan") | y %in% c("---")] <- ""
  y
}

monitora_validados_normalizar_nome <- function(x) {
  x <- as.character(x)
  x <- gsub("<[^>]+>", " ", x, perl = TRUE)
  x <- gsub("&nbsp;", " ", x, fixed = TRUE)
  x <- gsub("[​-‍﻿]", "", x, perl = TRUE)
  y <- suppressWarnings(iconv(x, from = "", to = "ASCII//TRANSLIT"))
  y[is.na(y)] <- x[is.na(y)]
  y <- tolower(y)
  y <- gsub("__dup[0-9]+$", "", y, perl = TRUE)
  y <- gsub("\\.[0-9]+$", "", y, perl = TRUE)
  y <- gsub("[^a-z0-9]+", "_", y, perl = TRUE)
  y <- gsub("_+", "_", y, perl = TRUE)
  y <- gsub("^_|_$", "", y, perl = TRUE)
  y
}

monitora_validados_unir_aliases <- function(a, b) {
  out <- a
  for (nm in names(b)) {
    out[[nm]] <- unique(c(out[[nm]], b[[nm]]))
  }
  out
}

monitora_validados_aliases <- function() {
  monitora_validados_unir_aliases(
    monitora_validados_aliases_xlsform_historico(),
    monitora_validados_aliases_adicionais()
  )
}

monitora_validados_colunas_versãos <- function(col_template) {
  aliases <- monitora_validados_aliases()
  cand <- unique(c(
    col_template,
    aliases[[col_template]],
    toupper(col_template),
    gsub("_", " ", col_template, fixed = TRUE),
    gsub("/", " ", col_template, fixed = TRUE)
  ))
  cand[!is.na(cand) & nzchar(cand)]
}

monitora_validados_resolver_coluna <- function(nomes_dt, col_template) {
  if (is.null(nomes_dt) || !length(nomes_dt)) return(NA_character_)
  cand <- monitora_validados_colunas_versãos(col_template)
  hit <- cand[cand %in% nomes_dt]
  if (length(hit)) return(hit[1])
  nomes_lower <- tolower(nomes_dt)
  for (cc in cand) {
    hit_i <- which(nomes_lower == tolower(cc))
    if (length(hit_i)) return(nomes_dt[hit_i[1]])
  }
  nomes_norm <- monitora_validados_normalizar_nome(nomes_dt)
  cand_norm <- monitora_validados_normalizar_nome(cand)
  hit_i <- match(cand_norm, nomes_norm, nomatch = 0L)
  hit_i <- hit_i[hit_i > 0L]
  if (length(hit_i)) return(nomes_dt[hit_i[1]])
  NA_character_
}

monitora_validados_primeira_coluna <- function(dt, candidatos) {
  for (cc in candidatos) {
    col <- monitora_validados_resolver_coluna(names(dt), cc)
    if (!is.na(col) && col %in% names(dt)) return(col)
  }
  NA_character_
}

monitora_validados_pegar <- function(dt, candidatos, n = nrow(dt)) {
  col <- monitora_validados_primeira_coluna(dt, candidatos)
  if (is.na(col) || !(col %in% names(dt))) return(list(valor = rep("", n), coluna = NA_character_))
  list(valor = monitora_validados_limpar_ausencia_saida(dt[[col]]), coluna = col)
}


monitora_validados_hora_hms_millis_tz_regex <- function() {
  "^(?:[01][0-9]|2[0-3]):[0-5][0-9]:[0-5][0-9][.][0-9]{3}-03:00$"
}

monitora_validados_normalizar_hora_hms_millis_tz <- function(x, tz_padrao = "-03:00") {
  y <- monitora_validados_limpar_ausencia_saida(x)
  y[is.na(y)] <- ""
  vazio <- !nzchar(y)
  out <- y
  if (all(vazio)) return(out)

  tz_padrao <- as.character(tz_padrao)[1]
  if (is.na(tz_padrao) || !grepl("^[+-][0-9]{2}:[0-9]{2}$", tz_padrao, perl = TRUE)) tz_padrao <- "-03:00"

  yy <- trimws(y[!vazio])
  yy <- gsub("T", " ", yy, fixed = TRUE)
  yy <- gsub(",", ".", yy, fixed = TRUE)

  ## v2.6.1: contrato único para data_hora/hora. Aceita HH:MM,
  ## HH:MM:SS, HH:MM:SS.mmm, hora com fuso -0300/-03:00, datetime
  ## completo/ISO com T e separador histórico com hífen (HH-MM ou
  ## HH-MM-SS). Emite sempre HH:MM:SS.mmm-03:00. Valores não
  ## interpretáveis são preservados para bloqueio explícito pelo validador.
  yy <- sub(
    "^([0-9]{1,2})-([0-9]{2})(?:-([0-9]{2})([.][0-9]{1,9})?)?\\s*([+-][0-9]{2}:?[0-9]{2}|Z)?$",
    "\\1:\\2:\\3\\4\\5",
    yy,
    perl = TRUE
  )
  yy <- sub(":([+-][0-9]{2}:?[0-9]{2}|Z)$", ":00\\1", yy, perl = TRUE)
  yy <- sub(":$", ":00", yy, perl = TRUE)
  yy <- sub(
    "([[:space:]])([0-9]{1,2})-([0-9]{2})(?:-([0-9]{2})([.][0-9]{1,9})?)?\\s*([+-][0-9]{2}:?[0-9]{2}|Z)?$",
    "\\1\\2:\\3:\\4\\5\\6",
    yy,
    perl = TRUE
  )
  yy <- sub(":([+-][0-9]{2}:?[0-9]{2}|Z)$", ":00\\1", yy, perl = TRUE)
  yy <- sub(":$", ":00", yy, perl = TRUE)

  pat <- "(^|[^0-9+-])([0-9]{1,2}):([0-9]{2})(?::([0-9]{2})([.][0-9]{1,9})?)?\\s*([+-][0-9]{2}:?[0-9]{2}|Z)?"
  m <- regexec(pat, yy, perl = TRUE)
  r <- regmatches(yy, m)
  ok <- lengths(r) > 0L

  if (any(ok)) {
    idx_ok <- which(ok)
    norm <- yy[idx_ok]
    for (jj in seq_along(idx_ok)) {
      z <- r[[idx_ok[jj]]]
      hh <- suppressWarnings(as.integer(z[3L]))
      mi <- suppressWarnings(as.integer(z[4L]))
      ss_txt <- if (length(z) >= 5L && nzchar(z[5L])) z[5L] else "00"
      ss <- suppressWarnings(as.integer(ss_txt))
      frac <- if (length(z) >= 6L) z[6L] else ""

      valido <- !is.na(hh) && !is.na(mi) && !is.na(ss) &&
        hh >= 0L && hh <= 23L && mi >= 0L && mi <= 59L && ss >= 0L && ss <= 59L

      if (isTRUE(valido)) {
        ms <- if (nzchar(frac)) sub("^[.]", "", frac, perl = TRUE) else ""
        ms <- substr(paste0(ms, "000"), 1L, 3L)
        norm[jj] <- sprintf("%02d:%02d:%02d.%s%s", hh, mi, ss, ms, tz_padrao)
      }
    }
    yy[idx_ok] <- norm
  }

  out[!vazio] <- yy
  out[is.na(out)] <- ""
  out
}

monitora_validados_auditar_hora_hms_millis_tz <- function(original,
                                                           normalizado,
                                                           atributo = "data_hora/hora",
                                                           coluna_origem = NA_character_) {
  ori <- monitora_validados_limpar_ausencia_saida(original)
  nor <- monitora_validados_limpar_ausencia_saida(normalizado)
  ori[is.na(ori)] <- ""
  nor[is.na(nor)] <- ""
  contrato <- monitora_validados_hora_hms_millis_tz_regex()
  tem_origem <- nzchar(ori)
  ok <- nzchar(nor) & grepl(contrato, nor, perl = TRUE)
  incompat <- tem_origem & !ok
  normalizados <- tem_origem & ok
  alterados <- normalizados & ori != nor

  exemplos_idx <- which(incompat)
  if (!length(exemplos_idx)) exemplos_idx <- which(alterados)
  exemplos <- character()
  if (length(exemplos_idx)) {
    exemplos <- unique(paste0(ori[exemplos_idx], " -> ", nor[exemplos_idx]))
  }

  data.table::data.table(
    atributo = as.character(atributo)[1],
    coluna_origem_registros_corrig = ifelse(is.na(as.character(coluna_origem)[1]) || !nzchar(as.character(coluna_origem)[1]), NA_character_, as.character(coluna_origem)[1]),
    contrato_saida = "HH:MM:SS.mmm-03:00",
    regex_contrato = contrato,
    n_total = length(ori),
    n_vazios = sum(!tem_origem),
    n_normalizados = sum(normalizados),
    n_alterados_pela_normalizacao = sum(alterados),
    n_incompativeis = sum(incompat),
    exemplos_protegidos = paste(utils::head(exemplos, 10L), collapse = " | "),
    bloqueante = sum(incompat) > 0L,
    motivo_bloqueio = if (sum(incompat) > 0L) "hora_incompativel_com_contrato_hms_millis_tz" else ""
  )
}

monitora_validados_formatar_valor <- function(x, formato = "texto", largura = NA_integer_) {
  y <- monitora_validados_limpar_ausencia_saida(x)
  vazio <- !nzchar(y)
  if (identical(formato, "datetime_iso_espaco")) {
    y[!vazio] <- gsub("T", " ", y[!vazio], fixed = TRUE)
    y[!vazio] <- sub("^([0-9]{4}-[0-9]{2}-[0-9]{2})[[:space:]]+([0-9]{2}:[0-9]{2}:[0-9]{2}).*$", "\\1 \\2", y[!vazio], perl = TRUE)
    y[!vazio & grepl("^[0-9]{4}-[0-9]{2}-[0-9]{2}$", y, perl = TRUE)] <- paste0(y[!vazio & grepl("^[0-9]{4}-[0-9]{2}-[0-9]{2}$", y, perl = TRUE)], " 00:00:00")
  } else if (identical(formato, "data_iso")) {
    idx_dt <- !vazio & grepl("^[0-9]{4}-[0-9]{2}-[0-9]{2}", y, perl = TRUE)
    y[idx_dt] <- sub("^([0-9]{4}-[0-9]{2}-[0-9]{2}).*$", "\\1", y[idx_dt], perl = TRUE)
  } else if (identical(formato, "hora_hms_millis_tz")) {
    y <- monitora_validados_normalizar_hora_hms_millis_tz(y, tz_padrao = "-03:00")
  } else if (identical(formato, "inteiro_texto_zero_esquerda")) {
    idx <- !vazio & grepl("^[0-9]+(\\.0+)?$", y, perl = TRUE)
    dig <- sub("\\.0+$", "", y[idx], perl = TRUE)
    if (!is.na(largura) && largura > 1L && length(dig)) {
      dig <- paste0(vapply(pmax(0L, largura - nchar(dig)), function(nz) paste(rep("0", nz), collapse = ""), character(1)), dig)
    }
    y[idx] <- dig
  } else if (identical(formato, "inteiro_texto")) {
    idx <- !vazio & grepl("^[0-9]+(\\.0+)?$", y, perl = TRUE)
    y[idx] <- sub("\\.0+$", "", y[idx], perl = TRUE)
  } else if (identical(formato, "numero_texto_ponto")) {
    y[!vazio] <- gsub(",", ".", y[!vazio], fixed = TRUE)
    y[!vazio] <- sub("^([0-9]+)\\.0+$", "\\1", y[!vazio], perl = TRUE)
  }
  y[is.na(y)] <- ""
  y
}

### v2.6.1: ativação tardia do wrapper por valores distintos. Este ponto fica
### depois da definição original de monitora_validados_formatar_valor; a seção
### de helpers v2.6.1 é carregada antes, então o if inicial pode ter sido falso.
if (exists("monitora_validados_formatar_valor", mode = "function") &&
    !exists("monitora_validados_formatar_valor_base_publicacao_aj", mode = "function")) {
  monitora_validados_formatar_valor_base_publicacao_aj <- monitora_validados_formatar_valor
  monitora_validados_formatar_valor <- function(x, formato = "texto", largura = NA_integer_) {
    n <- length(x)
    if (n < 512L) return(monitora_validados_formatar_valor_base_publicacao_aj(x, formato, largura))
    y0 <- monitora_validados_limpar_ausencia_saida(x)
    y0[is.na(y0)] <- ""
    u <- unique(y0)
    if (length(u) > max(512L, as.integer(n * 0.80))) {
      return(monitora_validados_formatar_valor_base_publicacao_aj(x, formato, largura))
    }
    fu <- monitora_validados_formatar_valor_base_publicacao_aj(u, formato, largura)
    fu[is.na(fu)] <- ""
    unname(fu[match(y0, u)])
  }
}

monitora_validados_hex8_num <- function(num) {
  digs <- strsplit("0123456789abcdef", "", fixed = TRUE)[[1]]
  vapply(num, function(z) {
    z <- floor(as.numeric(z) %% 4294967296)
    out <- rep("0", 8L)
    for (ii in 8L:1L) {
      r <- z %% 16
      out[ii] <- digs[r + 1L]
      z <- floor(z / 16)
    }
    paste0(out, collapse = "")
  }, character(1))
}

monitora_validados_hash32 <- function(x, salt = "") {
  x <- paste0(as.character(salt), "||", as.character(x))
  vapply(x, function(s) {
    raw <- charToRaw(enc2utf8(s))
    h <- 2166136261
    if (length(raw)) {
      for (bb in as.integer(raw)) {
        h <- bitwXor(as.integer(h %% 2147483647), as.integer(bb))
        h <- (as.numeric(h) * 16777619) %% 4294967296
      }
    }
    monitora_validados_hex8_num(h)
  }, character(1), USE.NAMES = FALSE)
}

monitora_validados_uuid_deterministico <- function(chave, nivel = "registro") {
  chave <- monitora_validados_limpar_ausencia_saida(chave)
  chave[!nzchar(chave)] <- paste0("sem_chave_", seq_along(chave))
  h1 <- monitora_validados_hash32(chave, paste0(nivel, "_1"))
  h2 <- monitora_validados_hash32(chave, paste0(nivel, "_2"))
  h3 <- monitora_validados_hash32(chave, paste0(nivel, "_3"))
  h4 <- monitora_validados_hash32(chave, paste0(nivel, "_4"))
  h5 <- monitora_validados_hash32(chave, paste0(nivel, "_5"))
  paste0(h1, "-", substr(h2, 1L, 4L), "-", substr(h3, 1L, 4L), "-", substr(h4, 1L, 4L), "-", h5, substr(h2, 5L, 8L))
}

monitora_validados_uuid_valido <- function(x) {
  x <- monitora_validados_limpar_ausencia_saida(x)
  nzchar(x) & grepl("^[0-9a-fA-F]{8}-[0-9a-fA-F]{4}-[0-9a-fA-F]{4}-[0-9a-fA-F]{4}-[0-9a-fA-F]{12}$", x, perl = TRUE)
}

monitora_validados_chave_coleta <- function(dt) {
  n <- nrow(dt)
  campos <- c("PROTOCOLO", "UC", "CICLO", "CAMPANHA", "EA", "UA", "COLETA")
  vals <- lapply(campos, function(cc) {
    col <- monitora_validados_primeira_coluna(dt, c(cc, tolower(cc)))
    if (!is.na(col) && col %in% names(dt)) monitora_validados_limpar_ausencia_saida(dt[[col]]) else rep("", n)
  })
  do.call(paste, c(vals, sep = "|"))
}

monitora_validados_chave_registro <- function(dt) {
  n <- nrow(dt)
  campos <- list(
    c("PROTOCOLO", "protocolo"), c("UC", "uc"), c("CICLO", "ciclo"), c("CAMPANHA", "campanha"),
    c("EA", "ea"), c("UA", "ua"), c("COLETA", "coleta"),
    c("ponto_amostral (amostragem/registro)", "amostragem/registro/ponto_amostral"),
    c("ponto_metro (amostragem/registro)", "amostragem/registro/ponto_metro")
  )
  vals <- lapply(campos, function(cands) {
    col <- monitora_validados_primeira_coluna(dt, cands)
    if (!is.na(col) && col %in% names(dt)) monitora_validados_limpar_ausencia_saida(dt[[col]]) else rep("", n)
  })
  do.call(paste, c(vals, sep = "|"))
}

monitora_validados_uuid_por_coleta_ou_sintetico <- function(dt, alvo = c("coleta_uuid", "uuid")) {
  alvo <- match.arg(alvo)
  n <- nrow(dt)
  coleta <- monitora_validados_pegar(dt, c("COLETA", "coleta"), n)$valor
  chave_coleta <- monitora_validados_chave_coleta(dt)
  candidatos <- if (identical(alvo, "coleta_uuid")) {
    c("coleta_uuid", "COLETA_UUID", "uuid_coleta", "UUID_COLETA")
  } else {
    c("uuid", "UUID_COLETA_FORMULARIO", "uuid_formulario", "uuid_coleta_formulario")
  }
  col <- monitora_validados_primeira_coluna(dt, candidatos)
  v_sint <- monitora_validados_uuid_deterministico(chave_coleta, paste0(alvo, "_deterministico"))
  if (!is.na(col) && col %in% names(dt)) {
    v <- monitora_validados_limpar_ausencia_saida(dt[[col]])
    ok_uuid <- nzchar(v) & monitora_validados_uuid_valido(v)
    aux <- data.table::data.table(coleta = coleta, valor = v)
    aux <- aux[nzchar(coleta) & ok_uuid]
    if (nrow(aux)) {
      card <- aux[, .(n_valores = data.table::uniqueN(valor), valor = valor[1L]), by = coleta]
      if (nrow(card[n_valores > 1L]) == 0L) {
        setkey(card, coleta)
        idx_fill <- which(!ok_uuid & nzchar(coleta))
        if (length(idx_fill)) {
          preench <- card[data.table::data.table(coleta = coleta[idx_fill]), on = "coleta", valor]
          ok <- !is.na(preench) & nzchar(preench)
          if (any(ok)) v[idx_fill[ok]] <- preench[ok]
        }
        v[!monitora_validados_uuid_valido(v)] <- v_sint[!monitora_validados_uuid_valido(v)]
        return(list(valor = v, coluna = col, estrategia = paste0("mapeada_complementada_", alvo, "_deterministico_por_coleta")))
      }
    }
  }
  list(valor = v_sint, coluna = NA_character_, estrategia = paste0("sintetizada_", alvo, "_deterministico_por_coleta"))
}

monitora_validados_uuid_registro_ou_sintetico <- function(dt) {
  n <- nrow(dt)
  candidatos <- c("amostragem/registro/uuid", "uuid (amostragem/registro)", "UUID_REGISTRO", "uuid_registro", "UUID")
  for (cc in candidatos) {
    col <- monitora_validados_primeira_coluna(dt, cc)
    if (!is.na(col) && col %in% names(dt)) {
      v <- monitora_validados_limpar_ausencia_saida(dt[[col]])
      ok <- nzchar(v) & !grepl("\\|", v, fixed = FALSE) & monitora_validados_uuid_valido(v)
      if (all(ok) && data.table::uniqueN(v) == length(v)) {
        return(list(valor = v, coluna = col, estrategia = "mapeada_uuid_unico_por_registro"))
      }
    }
  }
  v <- monitora_validados_uuid_deterministico(monitora_validados_chave_registro(dt), "uuid_registro_deterministico")
  list(valor = v, coluna = NA_character_, estrategia = "sintetizada_uuid_deterministico_por_registro")
}

monitora_validados_derive_datetime <- function(dt, alvo = c("data_do_registro", "data_do_recebimento")) {
  alvo <- match.arg(alvo)
  n <- nrow(dt)
  direto <- monitora_validados_pegar(dt, c(alvo, toupper(alvo), gsub("_", " ", alvo, fixed = TRUE)), n)
  v <- monitora_validados_formatar_valor(direto$valor, "datetime_iso_espaco")
  if (any(nzchar(v))) return(list(valor = v, coluna = direto$coluna, estrategia = "mapeada_datetime"))
  if (identical(alvo, "data_do_registro")) {
    rec <- monitora_validados_pegar(dt, c("data_do_recebimento", "DATA DO RECEBIMENTO", "Data do recebimento"), n)
    v <- monitora_validados_formatar_valor(rec$valor, "datetime_iso_espaco")
    if (any(nzchar(v))) return(list(valor = v, coluna = rec$coluna, estrategia = "derivada_de_data_do_recebimento"))
  }
  data <- monitora_validados_pegar(dt, c("data_hora/data", "Data (data_hora)", "DATA_MONITORA_PARSEADA"), n)
  hora <- monitora_validados_pegar(dt, c("data_hora/hora", "Horário (data_hora)", "Hora (data_hora)"), n)
  d <- monitora_validados_formatar_valor(data$valor, "data_iso")
  h <- monitora_validados_formatar_valor(hora$valor, "hora_hms_millis_tz")
  h <- sub("^([0-9]{2}:[0-9]{2}:[0-9]{2}).*$", "\\1", h, perl = TRUE)
  h[!grepl("^[0-9]{2}:[0-9]{2}:[0-9]{2}$", h, perl = TRUE)] <- "00:00:00"
  v <- ifelse(nzchar(d), paste(d, h), "")
  list(valor = v, coluna = paste(c(data$coluna, hora$coluna)[!is.na(c(data$coluna, hora$coluna))], collapse = " + "), estrategia = "derivada_de_data_hora_campo")
}

monitora_validados_derive_data_hora <- function(dt, alvo = c("data", "hora")) {
  alvo <- match.arg(alvo)
  n <- nrow(dt)
  if (identical(alvo, "data")) {
    cols <- c("data_hora/data", "Data (data_hora)", "DATA_MONITORA_PARSEADA", "data_do_registro", "DATA DO REGISTRO", "DATA DO RECEBIMENTO")
    p <- monitora_validados_pegar(dt, cols, n)
    return(list(valor = monitora_validados_formatar_valor(p$valor, "data_iso"), coluna = p$coluna, estrategia = ifelse(is.na(p$coluna), "sem_origem", "mapeada_ou_derivada_data")))
  }
  cols <- c("data_hora/hora", "Horário (data_hora)", "Hora (data_hora)", "data_do_registro", "DATA DO REGISTRO", "DATA DO RECEBIMENTO")
  p <- monitora_validados_pegar(dt, cols, n)
  v <- monitora_validados_formatar_valor(p$valor, "hora_hms_millis_tz")
  if (!any(nzchar(v))) v <- rep("00:00:00.000-03:00", n)
  list(valor = v, coluna = p$coluna, estrategia = ifelse(is.na(p$coluna), "sintetizada_hora_padrao_00", "mapeada_ou_derivada_hora"))
}

monitora_validados_numero_ua <- function(dt, n = nrow(dt)) {
  ua <- monitora_validados_pegar(dt, c("UA", "ua"), n)
  v <- monitora_validados_limpar_ausencia_saida(ua$valor)
  out <- rep("", n)
  idx <- nzchar(v) & grepl("UA[-_ ]*0*[0-9]+", toupper(v), perl = TRUE)
  if (any(idx)) {
    out[idx] <- sub("^.*UA[-_ ]*0*([0-9]+).*$", "\\1", toupper(v[idx]), perl = TRUE)
  }
  list(valor = out, coluna = ua$coluna)
}

monitora_validados_extrair_digitos <- function(x) {
  y <- monitora_validados_limpar_ausencia_saida(x)
  out <- rep("", length(y))
  idx_num <- nzchar(y) & grepl("^[0-9]+([,.]0+)?$", y, perl = TRUE)
  if (any(idx_num)) {
    out[idx_num] <- sub("[,.]0+$", "", y[idx_num], perl = TRUE)
  }
  idx_emb <- !nzchar(out) & nzchar(y) & grepl("[0-9]+", y, perl = TRUE)
  if (any(idx_emb)) {
    out[idx_emb] <- sub("^.*?([0-9]+).*$", "\\1", y[idx_emb], perl = TRUE)
  }
  out
}

monitora_validados_formatar_inteiro_largura <- function(x, largura = NA_integer_) {
  y <- monitora_validados_extrair_digitos(x)
  idx <- nzchar(y)
  if (!is.na(largura) && largura > 1L && any(idx)) {
    y[idx] <- paste0(vapply(pmax(0L, largura - nchar(y[idx])), function(nz) paste(rep("0", nz), collapse = ""), character(1)), y[idx])
  }
  y
}

monitora_validados_coalesce_nao_vazio <- function(vals, n) {
  out <- rep("", n)
  for (vv in vals) {
    vv <- monitora_validados_limpar_ausencia_saida(vv)
    idx <- !nzchar(out) & nzchar(vv)
    if (any(idx)) out[idx] <- vv[idx]
  }
  out
}

monitora_validados_preencher_por_coleta <- function(dt, v, padrao = "") {
  v <- monitora_validados_limpar_ausencia_saida(v)
  n <- length(v)
  coleta <- monitora_validados_pegar(dt, c("COLETA", "coleta"), n)$valor
  if (length(coleta) == n && any(!nzchar(v) & nzchar(coleta))) {
    aux <- data.table::data.table(.coleta = coleta, .valor = v)
    mapa <- aux[nzchar(.coleta) & nzchar(.valor), .(.valor = .valor[1L]), by = .coleta]
    if (nrow(mapa)) {
      setkey(mapa, .coleta)
      idx <- which(!nzchar(v) & nzchar(coleta))
      preench <- mapa[data.table::data.table(.coleta = coleta[idx]), on = ".coleta", .valor]
      ok <- !is.na(preench) & nzchar(preench)
      if (any(ok)) v[idx[ok]] <- preench[ok]
    }
  }
  if (nzchar(padrao)) v[!nzchar(v)] <- padrao
  v
}

monitora_validados_coalesce_vetor <- function(..., n) {
  vals <- list(...)
  out <- rep("", n)
  for (vv in vals) {
    vv <- monitora_validados_limpar_ausencia_saida(vv)
    idx <- !nzchar(out) & nzchar(vv)
    if (any(idx)) out[idx] <- vv[idx]
  }
  out
}

monitora_validados_derivar_num_placa <- function(dt, alvo = c("num_placa", "num_placa_formatado")) {
  alvo <- match.arg(alvo)
  n <- nrow(dt)
  p_fmt <- monitora_validados_pegar(dt, c("Número da plaqueta formatado (amostragem)", "amostragem/num_placa_formatado", "num_placa_formatado"), n)
  p_num <- monitora_validados_pegar(dt, c("Número da plaqueta (amostragem)", "amostragem/num_placa", "num_placa"), n)
  p_ua <- monitora_validados_numero_ua(dt, n)

  ## v2.6.1: não preservar texto inválido em campos de plaqueta. Usa-se
  ## extração numérica defensiva e fallback para UA; isso mantém o contrato
  ## de inteiro textual com zero à esquerda sem inventar valores quando já há
  ## número recuperável.
  if (identical(alvo, "num_placa")) {
    v <- monitora_validados_coalesce_nao_vazio(list(
      monitora_validados_extrair_digitos(p_num$valor),
      monitora_validados_extrair_digitos(p_fmt$valor),
      monitora_validados_extrair_digitos(p_ua$valor)
    ), n = n)
    v <- monitora_validados_formatar_inteiro_largura(v, 3L)
    origem <- paste(unique(c(p_num$coluna, p_fmt$coluna, p_ua$coluna)[!is.na(c(p_num$coluna, p_fmt$coluna, p_ua$coluna))]), collapse = " + ")
    return(list(valor = v, coluna = origem, estrategia = "mapeada_ou_derivada_num_placa_por_digitos_ua"))
  }

  v <- monitora_validados_coalesce_nao_vazio(list(
    monitora_validados_extrair_digitos(p_fmt$valor),
    monitora_validados_extrair_digitos(p_num$valor),
    monitora_validados_extrair_digitos(p_ua$valor)
  ), n = n)
  v <- monitora_validados_formatar_inteiro_largura(v, 4L)
  origem <- paste(unique(c(p_fmt$coluna, p_num$coluna, p_ua$coluna)[!is.na(c(p_fmt$coluna, p_num$coluna, p_ua$coluna))]), collapse = " + ")
  list(valor = v, coluna = origem, estrategia = "mapeada_ou_derivada_num_placa_formatado_por_digitos_ua")
}


monitora_validados_norm_ascii <- function(x) {
  x <- as.character(x)
  x[is.na(x)] <- ""
  y <- iconv(x, from = "", to = "ASCII//TRANSLIT", sub = "")
  y[is.na(y)] <- ""
  y <- tolower(y)
  y <- gsub("[^a-z0-9]+", "_", y, perl = TRUE)
  y <- gsub("^_+|_+$", "", y, perl = TRUE)
  y
}

monitora_validados_xlsform21_meta <- function() {
  cache <- get0("MONITORA_PUBLICACAO_AE_XLSFORM21_META_CACHE", ifnotfound = NULL, inherits = TRUE)
  if (is.list(cache) && !is.null(cache$campos) && !is.null(cache$opcoes)) return(cache)
  if (exists("monitora_correcao_xlsforms_embutidos", mode = "function")) {
    meta <- monitora_correcao_xlsforms_embutidos_cache_publicacao_ae()
  } else {
    meta <- list(campos = data.table::data.table(), opcoes = data.table::data.table(), dependencias = data.table::data.table(), arquivos = data.table::data.table())
  }
  if (is.null(meta$campos)) meta$campos <- data.table::data.table()
  if (is.null(meta$opcoes)) meta$opcoes <- data.table::data.table()
  meta$campos <- data.table::as.data.table(meta$campos)
  meta$opcoes <- data.table::as.data.table(meta$opcoes)
  if (!is.null(meta$dependencias)) meta$dependencias <- data.table::as.data.table(meta$dependencias)
  if (!is.null(meta$arquivos)) meta$arquivos <- data.table::as.data.table(meta$arquivos)
  assign("MONITORA_PUBLICACAO_AE_XLSFORM21_META_CACHE", meta, envir = .GlobalEnv)
  meta
}

monitora_validados_xlsform21_campo <- function(atributo, meta = NULL) {
  att_chr <- as.character(atributo)[1L]
  cache_key <- paste0("MONITORA_PUBLICACAO_AE_XLSFORM21_CAMPO__", gsub("[^A-Za-z0-9]+", "_", att_chr))
  cache <- get0(cache_key, ifnotfound = NULL, inherits = TRUE)
  if (!is.null(cache) && data.table::is.data.table(cache)) return(cache)
  if (is.null(meta)) meta <- monitora_validados_xlsform21_meta()
  campos <- data.table::as.data.table(meta$campos)
  if (!nrow(campos)) return(data.table::data.table())
  for (cc in c("arquivo_xlsform", "name", "caminho_registro", "tipo_base", "list_name")) if (!(cc %in% names(campos))) campos[, (cc) := ""]
  alvo_nome <- sub("^.*/", "", att_chr)
  alvo_caminho <- att_chr
  if ("arquivo_21fev25_publicacao_ae" %in% names(campos)) {
    ans <- campos[arquivo_21fev25_publicacao_ae == TRUE & (name == alvo_nome | caminho_registro == alvo_caminho)]
  } else {
    ans <- campos[grepl("21FEV25", arquivo_xlsform) & (name == alvo_nome | caminho_registro == alvo_caminho)]
  }
  assign(cache_key, ans, envir = .GlobalEnv)
  ans
}

monitora_validados_xlsform21_mapa_lista <- function(lista, meta = NULL) {
  lista <- as.character(lista)[1]
  cache_key <- paste0("MONITORA_PUBLICACAO_AE_XLSFORM21_MAPA_LISTA__", gsub("[^A-Za-z0-9]+", "_", lista))
  cache <- get0(cache_key, ifnotfound = NULL, inherits = TRUE)
  if (!is.null(cache) && data.table::is.data.table(cache)) return(cache)
  if (is.null(meta)) meta <- monitora_validados_xlsform21_meta()
  op <- data.table::as.data.table(meta$opcoes)
  if (!nrow(op)) return(data.table::data.table(norm = character(), name = character(), list_name = character()))
  for (cc in c("arquivo_xlsform", "list_name", "name", "label")) if (!(cc %in% names(op))) op[, (cc) := ""]
  if ("arquivo_21fev25_publicacao_ae" %in% names(op)) {
    op <- op[arquivo_21fev25_publicacao_ae == TRUE & list_name == lista & nzchar(name)]
  } else {
    op <- op[grepl("21FEV25", arquivo_xlsform) & list_name == lista & nzchar(name)]
  }
  if (!nrow(op)) return(data.table::data.table(norm = character(), name = character(), list_name = character()))
  base <- data.table::rbindlist(list(
    op[, .(norm = monitora_validados_norm_ascii(name), name = as.character(name), list_name = lista)],
    op[, .(norm = monitora_validados_norm_ascii(label), name = as.character(name), list_name = lista)]
  ), fill = TRUE)
  ## Aliases históricos e variações frequentes vindas de registros_corrig/planilhas.
  extras <- data.table::data.table(norm = character(), name = character(), list_name = character())
  add <- function(norm, name) data.table::data.table(norm = monitora_validados_norm_ascii(norm), name = name, list_name = lista)
  if (identical(lista, "form_veg")) {
    extras <- data.table::rbindlist(list(extras, add(c("campestre", "Campestre"), "campestre"), add(c("savanica", "savânica", "Savanica", "Savânica"), "savanica")), fill = TRUE)
  }
  if (identical(lista, "impacto_manejo_uso")) {
    extras <- data.table::rbindlist(list(extras, add(c("nao", "não", "Nao", "Não"), "não"), add(c("sim", "Sim"), "sim")), fill = TRUE)
  }
  if (identical(lista, "especie")) {
    extras <- data.table::rbindlist(list(extras, add(c("nao", "não", "Nao", "Não"), "nao"), add(c("sim", "Sim"), "sim")), fill = TRUE)
  }
  if (lista %in% c("forma_vida_nativa", "forma_vida_exotica", "forma_vida_seca_morta")) {
    extras <- data.table::rbindlist(list(extras, add(c("erva_bromelioide", "bromelia", "bromelioide"), "bromelioide"), add(c("outra", "outra_forma_vida"), "")), fill = TRUE)
  }
  if (identical(lista, "forma_vida_outros")) {
    extras <- data.table::rbindlist(list(extras, add(c("Musgos (\"lodo\")", "Musgos (\"\"lodo\"\")", "musgos lodo", "musgos"), "musgos"), add(c("Hepáticas (possuem filídios ou talóides)", "hepaticas", "hepaticas possuem filidios ou taloides"), "hepaticas")), fill = TRUE)
  }
  if (identical(lista, "tipos_impacto_manejo_uso")) {
    extras <- data.table::rbindlist(list(extras, add(c("Extrativismo", "extrativismo"), "extrativismo"), add(c("Outros", "outros"), "outros")), fill = TRUE)
  }
  ans <- data.table::rbindlist(list(base, extras), fill = TRUE)
  ans <- ans[nzchar(norm) & !is.na(name)]
  data.table::setorderv(ans, c("list_name", "norm", "name"))
  ans <- unique(ans, by = c("list_name", "norm"))
  assign(cache_key, ans, envir = .GlobalEnv)
  ans
}

monitora_validados_xlsform21_choices <- function(lista, meta = NULL) {
  lista <- as.character(lista)[1]
  cache_key <- paste0("MONITORA_PUBLICACAO_AE_XLSFORM21_CHOICES__", gsub("[^A-Za-z0-9]+", "_", lista))
  cache <- get0(cache_key, ifnotfound = NULL, inherits = TRUE)
  if (!is.null(cache) && is.character(cache)) return(cache)
  if (is.null(meta)) meta <- monitora_validados_xlsform21_meta()
  op <- data.table::as.data.table(meta$opcoes)
  if (!nrow(op)) return(character(0))
  for (cc in c("arquivo_xlsform", "list_name", "name")) if (!(cc %in% names(op))) op[, (cc) := ""]
  if ("arquivo_21fev25_publicacao_ae" %in% names(op)) {
    ans <- unique(as.character(op[arquivo_21fev25_publicacao_ae == TRUE & list_name == lista & nzchar(name), name]))
  } else {
    ans <- unique(as.character(op[grepl("21FEV25", arquivo_xlsform) & list_name == lista & nzchar(name), name]))
  }
  assign(cache_key, ans, envir = .GlobalEnv)
  ans
}

monitora_validados_normalizar_select_vetor <- function(x, lista, multiple = TRUE, meta = NULL) {
  x0 <- monitora_validados_limpar_ausencia_saida(x)
  if (!length(x0)) return(character(0))
  mapa <- monitora_validados_xlsform21_mapa_lista(lista, meta)
  choices <- monitora_validados_xlsform21_choices(lista, meta)
  if (!length(choices)) return(x0)
  choices_placeholder <- length(choices) <= 2L && all(choices %in% c("num_key", "label"))
  if (isTRUE(choices_placeholder)) return(x0)
  vals_ok_publicacao_ae <- unique(x0[nzchar(x0)])
  if (length(vals_ok_publicacao_ae)) {
    if (isTRUE(multiple)) {
      toks_ok_publicacao_ae <- unique(unlist(strsplit(vals_ok_publicacao_ae, "\\s+", perl = TRUE), use.names = FALSE))
      toks_ok_publicacao_ae <- toks_ok_publicacao_ae[nzchar(toks_ok_publicacao_ae)]
      if (length(toks_ok_publicacao_ae) && all(toks_ok_publicacao_ae %chin% choices)) return(x0)
    } else {
      if (all(vals_ok_publicacao_ae %chin% choices)) return(x0)
    }
  }

  mapa <- data.table::as.data.table(mapa)
  for (cc in c("norm", "name")) if (!(cc %in% names(mapa))) mapa[, (cc) := ""]
  mapa <- mapa[nzchar(norm) & nzchar(name)]
  if (nrow(mapa)) {
    mapa[, n_norm := nchar(norm, type = "chars", allowNA = TRUE, keepNA = FALSE)]
    data.table::setorder(mapa, -n_norm, norm, name)
  }
  choice_order <- stats::setNames(seq_along(choices), choices)

  normalizar_fragmento <- function(v) {
    v <- monitora_validados_limpar_ausencia_saida(v)
    if (!nzchar(v)) return(character(0))
    if (!isTRUE(multiple)) {
      nv <- as.character(monitora_validados_norm_ascii(v))[1L]
      if (!is.na(nv) && nzchar(nv) && nrow(mapa)) {
        ii <- match(nv, mapa$norm, nomatch = 0L)
        if (ii > 0L) return(as.character(mapa$name[ii]))
      }
      if (v %chin% choices) return(v)
      return(v)
    }

    nv <- as.character(monitora_validados_norm_ascii(v))[1L]
    if (is.na(nv) || !nzchar(nv)) return(character(0))
    out <- character(0)

    ## v2.6.1:
    ## valores históricos de select_multiple podem misturar tokens atuais com
    ## labels completos do XLSForm separados por vírgula ou por espaço, por
    ## exemplo "arbusto_acima Árvore com diâmetro ... (D30), lianas". A rotina
    ## anterior quebrava por palavra e preservava pedaços do label como tokens
    ## inválidos. Aqui tentamos primeiro reconhecer labels/frases inteiras do
    ## mapa XLSForm; só depois quebramos o resíduo em tokens.
    if (nrow(mapa)) {
      ii_exato <- match(nv, mapa$norm, nomatch = 0L)
      if (ii_exato > 0L) return(as.character(mapa$name[ii_exato]))

      resto <- paste0("_", nv, "_")
      for (ii in seq_len(nrow(mapa))) {
        mm <- as.character(mapa$norm[ii])
        nn <- as.character(mapa$name[ii])
        if (is.na(mm) || !nzchar(mm) || is.na(nn) || !nzchar(nn)) next
        ## nomes curtos também são considerados, mas depois dos labels longos
        ## por causa da ordenação decrescente por nchar(norm).
        pad <- paste0("_", mm, "_")
        if (grepl(pad, resto, fixed = TRUE)) {
          out <- c(out, nn)
          resto <- gsub(pad, "_", resto, fixed = TRUE)
        }
      }
      resto <- gsub("_+", "_", resto, perl = TRUE)
      resto <- gsub("^_|_$", "", resto, perl = TRUE)
    } else {
      resto <- nv
    }

    partes <- unlist(strsplit(gsub("[|;,]+", " ", gsub("_", " ", resto, fixed = TRUE), perl = TRUE), "\\s+", perl = TRUE), use.names = FALSE)
    partes <- partes[nzchar(partes)]
    if (length(partes) && nrow(mapa)) {
      for (pp in partes) {
        np <- as.character(monitora_validados_norm_ascii(pp))[1L]
        if (is.na(np) || !nzchar(np)) next
        ii <- match(np, mapa$norm, nomatch = 0L)
        if (ii > 0L) {
          out <- c(out, as.character(mapa$name[ii]))
        } else if (pp %chin% choices) {
          out <- c(out, pp)
        } else if (np %chin% choices) {
          out <- c(out, np)
        } else {
          ## preserva resíduo não reconhecido para que a auditoria continue
          ## bloqueando verdadeiros valores fora do domínio.
          out <- c(out, pp)
        }
      }
    } else if (length(partes)) {
      out <- c(out, partes)
    }

    out <- unique(out[!is.na(out) & nzchar(out)])
    if (!length(out)) return(character(0))
    ord <- choice_order[out]
    out[order(ifelse(is.na(ord), length(choices) + seq_along(out), ord))]
  }

  norm_one <- function(v) {
    v <- monitora_validados_limpar_ausencia_saida(v)
    if (!nzchar(v)) return("")
    if (!isTRUE(multiple)) {
      z <- normalizar_fragmento(v)
      return(if (length(z)) z[1L] else "")
    }
    blocos <- unlist(strsplit(gsub("[\\r\\n]+", " ", v, perl = TRUE), "\\s*(?:[|;,]+)\\s*", perl = TRUE), use.names = FALSE)
    blocos <- blocos[nzchar(blocos)]
    if (!length(blocos)) blocos <- v
    out <- unique(unlist(lapply(blocos, normalizar_fragmento), use.names = FALSE))
    out <- out[!is.na(out) & nzchar(out)]
    if (!length(out)) return("")
    ord <- choice_order[out]
    out <- out[order(ifelse(is.na(ord), length(choices) + seq_along(out), ord))]
    paste(out, collapse = " ")
  }

  vals <- unique(x0)
  res <- vapply(vals, norm_one, character(1), USE.NAMES = FALSE)
  unname(res[match(x0, vals)])
}

monitora_validados_tem_token <- function(x, token) {
  ### v2.6.1: caminho genérico sem regex para selected() de select_multiple.
  ### Vale para contratos 2022/2023/2024/2025 porque todos usam tokens separados por espaço.
  x <- monitora_validados_limpar_ausencia_saida(x)
  if (!length(x)) return(logical(0))
  token <- as.character(token)[1L]
  if (is.na(token) || !nzchar(token)) return(rep(FALSE, length(x)))
  alvo <- paste0(" ", token, " ")
  grepl(alvo, paste0(" ", x, " "), fixed = TRUE, useBytes = TRUE)
}

monitora_validados_adicionar_token <- function(x, token, lista_ordem = NULL) {
  x <- monitora_validados_limpar_ausencia_saida(x)
  tem <- monitora_validados_tem_token(x, token)
  y <- ifelse(tem, x, trimws(paste(x, token)))
  if (!is.null(lista_ordem) && length(lista_ordem)) {
    y <- monitora_validados_ordenar_multiselect(y, lista_ordem)
  }
  y
}

monitora_validados_remover_token <- function(x, token, lista_ordem = NULL) {
  x <- monitora_validados_limpar_ausencia_saida(x)
  vals <- unique(x)
  limpa <- function(v) {
    if (!nzchar(v)) return("")
    p <- unlist(strsplit(v, "\\s+", perl = TRUE), use.names = FALSE)
    p <- p[nzchar(p) & p != token]
    if (!length(p)) return("")
    if (!is.null(lista_ordem) && length(lista_ordem)) {
      ord <- stats::setNames(seq_along(lista_ordem), lista_ordem)[p]
      p <- p[order(ifelse(is.na(ord), length(lista_ordem) + seq_along(p), ord))]
    }
    paste(unique(p), collapse = " ")
  }
  res <- vapply(vals, limpa, character(1), USE.NAMES = FALSE)
  unname(res[match(x, vals)])
}

monitora_validados_ordenar_multiselect <- function(x, lista_ordem) {
  x <- monitora_validados_limpar_ausencia_saida(x)
  vals <- unique(x)
  ordem <- stats::setNames(seq_along(lista_ordem), lista_ordem)
  f <- function(v) {
    if (!nzchar(v)) return("")
    p <- unique(unlist(strsplit(v, "\\s+", perl = TRUE), use.names = FALSE))
    p <- p[nzchar(p)]
    if (!length(p)) return("")
    ord <- ordem[p]
    p <- p[order(ifelse(is.na(ord), length(lista_ordem) + seq_along(p), ord))]
    paste(p, collapse = " ")
  }
  res <- vapply(vals, f, character(1), USE.NAMES = FALSE)
  unname(res[match(x, vals)])
}

monitora_validados_campos_dependentes_categoria <- function(cols, categoria) {
  pref <- paste0("amostragem/registro/forma_vida_", categoria, "_")
  grep(paste0("^", pref), cols, value = TRUE)
}

monitora_validados_aplicar_regras_xlsform21 <- function(out, schema) {
  meta <- monitora_validados_xlsform21_meta()
  cols <- names(out)
  ajustes <- vector("list", 32L)
  kk <- 0L
  registrar <- function(regra, atributo, n_ajustes, detalhe = "") {
    if (!is.finite(n_ajustes) || n_ajustes <= 0L) return(invisible(NULL))
    kk <<- kk + 1L
    ajustes[[kk]] <<- data.table::data.table(regra = regra, atributo = atributo, n_ajustes = as.integer(n_ajustes), detalhe = detalhe)
    invisible(NULL)
  }
  ## 1. Normalização de campos select_one/select_multiple para os names do XLSForm 21FEV25.
  for (att in cols) {
    campo <- monitora_validados_xlsform21_campo(att, meta)
    if (!nrow(campo)) next
    campo <- campo[1L]
    if (!(campo$tipo_base %in% c("select_one", "select_multiple")) || !nzchar(campo$list_name)) next
    antes <- out[[att]]
    depois <- monitora_validados_normalizar_select_vetor(antes, campo$list_name, multiple = identical(campo$tipo_base, "select_multiple"), meta = meta)
    registrar("normalizacao_dominio_xlsform21", att, sum(antes != depois, na.rm = TRUE), campo$list_name)
    data.table::set(out, j = att, value = depois)
  }
  tipo_col <- "amostragem/registro/tipo_forma_vida"
  tipo_choices <- monitora_validados_xlsform21_choices("tipo_forma_vida", meta)
  if (tipo_col %in% cols) {
    tipo <- out[[tipo_col]]
    ## Remover token histórico indevido em sublistas e mapear bromelioide.
    for (cc in c("amostragem/registro/forma_vida_nativa", "amostragem/registro/forma_vida_exotica", "amostragem/registro/forma_vida_seca_morta")) {
      if (cc %in% cols) {
        antes <- out[[cc]]
        depois <- monitora_validados_remover_token(antes, "serrapilheira", monitora_validados_xlsform21_choices(sub("^.*/", "", cc), meta))
        depois <- monitora_validados_remover_token(depois, "outra", monitora_validados_xlsform21_choices(sub("^.*/", "", cc), meta))
        registrar("remocao_token_invalido_sublista_forma_vida", cc, sum(antes != depois, na.rm = TRUE), "serrapilheira/outra")
        data.table::set(out, j = cc, value = depois)
      }
    }
    nativa <- if ("amostragem/registro/forma_vida_nativa" %in% cols) nzchar(out[["amostragem/registro/forma_vida_nativa"]]) else rep(FALSE, nrow(out))
    exotica <- if ("amostragem/registro/forma_vida_exotica" %in% cols) nzchar(out[["amostragem/registro/forma_vida_exotica"]]) else rep(FALSE, nrow(out))
    seca <- if ("amostragem/registro/forma_vida_seca_morta" %in% cols) nzchar(out[["amostragem/registro/forma_vida_seca_morta"]]) else rep(FALSE, nrow(out))
    serr <- if ("amostragem/registro/forma_serrapilheira" %in% cols) nzchar(out[["amostragem/registro/forma_serrapilheira"]]) else rep(FALSE, nrow(out))
    outros <- if ("amostragem/registro/forma_vida_outros" %in% cols) nzchar(out[["amostragem/registro/forma_vida_outros"]]) else rep(FALSE, nrow(out))
    antes_tipo <- tipo
    solo_original <- monitora_validados_tem_token(tipo, "solo_nu")
    serr_original <- monitora_validados_tem_token(tipo, "serrapilheira")
    outra_original <- monitora_validados_tem_token(tipo, "outra_forma_vida")
    ## Reconstroi o multiselect superior a partir dos campos inferiores já
    ## normalizados para o XLSForm 21FEV25. Isso remove categorias históricas
    ## que ficaram sem sublista válida, como seca_morta/exotica com sublista
    ## apenas "serrapilheira", e migra "outra" histórica para outra_forma_vida.
    tipo_novo <- rep("", nrow(out))
    tipo_novo <- ifelse(serr | serr_original, monitora_validados_adicionar_token(tipo_novo, "serrapilheira", tipo_choices), tipo_novo)
    tipo_novo <- ifelse(nativa, monitora_validados_adicionar_token(tipo_novo, "nativa", tipo_choices), tipo_novo)
    tipo_novo <- ifelse(exotica, monitora_validados_adicionar_token(tipo_novo, "exotica", tipo_choices), tipo_novo)
    tipo_novo <- ifelse(seca, monitora_validados_adicionar_token(tipo_novo, "seca_morta", tipo_choices), tipo_novo)
    tipo_novo <- ifelse(outros | outra_original, monitora_validados_adicionar_token(tipo_novo, "outra_forma_vida", tipo_choices), tipo_novo)
    tem_alguma_categoria <- nzchar(tipo_novo)
    tipo_novo <- ifelse(!tem_alguma_categoria & solo_original, monitora_validados_adicionar_token(tipo_novo, "solo_nu", tipo_choices), tipo_novo)
    tem_solo <- monitora_validados_tem_token(tipo_novo, "solo_nu")
    tem_outro_tipo <- Reduce(`|`, lapply(c("serrapilheira", "nativa", "exotica", "seca_morta", "outra_forma_vida"), function(tt) monitora_validados_tem_token(tipo_novo, tt)))
    tipo_novo <- ifelse(tem_solo & tem_outro_tipo, monitora_validados_remover_token(tipo_novo, "solo_nu", tipo_choices), tipo_novo)
    registrar("sincronizacao_tipo_forma_vida_com_campos_inferiores", tipo_col, sum(antes_tipo != tipo_novo, na.rm = TRUE), "reconstroi a partir dos campos inferiores XLSForm 21FEV25; remove categorias sem sublista valida")
    tipo <- tipo_novo
    data.table::set(out, j = tipo_col, value = tipo)
    ## Relevance de serrapilheira/outros e categorias principais.
    if ("amostragem/registro/forma_serrapilheira" %in% cols) {
      antes <- out[["amostragem/registro/forma_serrapilheira"]]
      rel <- monitora_validados_tem_token(tipo, "serrapilheira")
      depois <- ifelse(rel & !nzchar(antes), "serrapilheira", ifelse(rel, antes, ""))
      registrar("relevance_forma_serrapilheira", "amostragem/registro/forma_serrapilheira", sum(antes != depois, na.rm = TRUE), "selected(tipo_forma_vida, 'serrapilheira')")
      data.table::set(out, j = "amostragem/registro/forma_serrapilheira", value = depois)
    }
    if ("amostragem/registro/forma_vida_outros" %in% cols) {
      antes <- out[["amostragem/registro/forma_vida_outros"]]
      rel <- monitora_validados_tem_token(tipo, "outra_forma_vida")
      depois <- ifelse(rel, antes, "")
      registrar("relevance_forma_vida_outros", "amostragem/registro/forma_vida_outros", sum(antes != depois, na.rm = TRUE), "selected(tipo_forma_vida, 'outra_forma_vida')")
      data.table::set(out, j = "amostragem/registro/forma_vida_outros", value = depois)
    }
    for (cat in c("nativa", "exotica", "seca_morta")) {
      main <- paste0("amostragem/registro/forma_vida_", cat)
      if (!(main %in% cols)) next
      rel <- monitora_validados_tem_token(tipo, cat)
      antes <- out[[main]]
      depois <- ifelse(rel, antes, "")
      registrar("relevance_lista_principal_forma_vida", main, sum(antes != depois, na.rm = TRUE), paste0("selected(tipo_forma_vida, '", cat, "')"))
      data.table::set(out, j = main, value = depois)
      dep_cols <- monitora_validados_campos_dependentes_categoria(cols, cat)
      if (length(dep_cols)) {
        for (dc in dep_cols) {
          antes_dep <- out[[dc]]
          form <- sub(paste0("^amostragem/registro/forma_vida_", cat, "_"), "", dc)
          form <- sub("_sp$", "", form)
          rel_dep <- rel & monitora_validados_tem_token(out[[main]], form)
          depois_dep <- ifelse(rel_dep, antes_dep, "")
          registrar("relevance_dependente_forma_vida", dc, sum(antes_dep != depois_dep, na.rm = TRUE), paste0("selected(", main, ", '", form, "')"))
          data.table::set(out, j = dc, value = depois_dep)
        }
      }
    }
  }
  ## 2. Relevance de impactos/manejo.
  impact_col <- "impact_manejo_uso/impacto_manejo_uso"
  tipos_col <- "impact_manejo_uso/tipos_impacto_manejo_uso"
  if (impact_col %in% cols) {
    impact <- out[[impact_col]]
    tipos <- if (tipos_col %in% cols) out[[tipos_col]] else rep("", nrow(out))
    antes <- impact
    impact <- ifelse(nzchar(tipos), "sim", ifelse(!nzchar(impact), "não", impact))
    registrar("sincronizacao_impacto_com_tipos", impact_col, sum(antes != impact, na.rm = TRUE), "tipos preenchidos implicam impacto=sim; vazio implica não")
    data.table::set(out, j = impact_col, value = impact)
    if (tipos_col %in% cols) {
      antes_t <- out[[tipos_col]]
      depois_t <- ifelse(impact == "sim", antes_t, "")
      registrar("relevance_tipos_impacto_manejo_uso", tipos_col, sum(antes_t != depois_t, na.rm = TRUE), "${impacto_manejo_uso}=sim")
      data.table::set(out, j = tipos_col, value = depois_t)
    }
    for (cc in c("impact_manejo_uso/tipos_impacto_manejo_uso_descricao", "impact_manejo_uso/tipos_impacto_manejo_uso_outro")) {
      if (cc %in% cols) {
        antes_c <- out[[cc]]
        if (identical(cc, "impact_manejo_uso/tipos_impacto_manejo_uso_outro") && tipos_col %in% cols) {
          rel_c <- impact == "sim" & monitora_validados_tem_token(out[[tipos_col]], "outros")
        } else {
          rel_c <- impact == "sim"
        }
        depois_c <- ifelse(rel_c, antes_c, "")
        registrar("relevance_impacto_manejo_uso_dependente", cc, sum(antes_c != depois_c, na.rm = TRUE), "relevance XLSForm 21FEV25")
        data.table::set(out, j = cc, value = depois_c)
      }
    }
  }
  ajustes_dt <- if (kk) data.table::rbindlist(ajustes[seq_len(kk)], fill = TRUE) else data.table::data.table(regra = character(), atributo = character(), n_ajustes = integer(), detalhe = character())
  list(out = out, ajustes = ajustes_dt, meta = meta)
}

monitora_validados_validar_dominios_xlsform21 <- function(out, schema, meta = NULL) {
  if (is.null(meta)) meta <- monitora_validados_xlsform21_meta()
  problemas <- vector("list", ncol(out))
  k <- 0L
  for (att in names(out)) {
    campo <- monitora_validados_xlsform21_campo(att, meta)
    if (!nrow(campo)) next
    campo <- campo[1L]
    if (!(campo$tipo_base %in% c("select_one", "select_multiple")) || !nzchar(campo$list_name)) next
    choices <- monitora_validados_xlsform21_choices(campo$list_name, meta)
    if (!length(choices)) next
    ## Listas dinâmicas do XLSForm embutido aparecem como placeholders
    ## (num_key/label). O domínio real vem do Sismonitora/base operacional,
    ## portanto não deve bloquear o CSV validado.
    choices_placeholder <- length(choices) <= 2L && all(choices %in% c("num_key", "label"))
    if (isTRUE(choices_placeholder)) next
    x <- monitora_validados_limpar_ausencia_saida(out[[att]])
    vals <- unique(x[nzchar(x)])
    if (!length(vals)) next
    if (identical(campo$tipo_base, "select_one")) {
      invalid <- setdiff(vals, choices)
      exemplos_invalidos <- invalid
    } else {
      toks <- unique(unlist(strsplit(vals, "\\s+", perl = TRUE), use.names = FALSE))
      toks <- toks[nzchar(toks)]
      invalid <- setdiff(toks, choices)
      exemplos_invalidos <- vals[grepl(paste(invalid, collapse = "|"), vals, perl = TRUE)]
    }
    if (length(invalid)) {
      k <- k + 1L
      motivo <- if (identical(att, "amostragem/registro/forma_vida_outros")) {
        "residuo_outra_forma_vida_sem_sanitizacao_previa"
      } else {
        "token_fora_dominio_xlsform21"
      }
      problemas[[k]] <- data.table::data.table(
        atributo = att, list_name = campo$list_name, tipo_base = campo$tipo_base,
        n_tokens_invalidos = length(invalid), tokens_invalidos = paste(utils::head(invalid, 20L), collapse = " | "),
        exemplos = paste(utils::head(exemplos_invalidos, 5L), collapse = " | "),
        bloqueante = TRUE, motivo_bloqueio = motivo
      )
    }
  }
  if (!k) return(data.table::data.table(atributo = character(), list_name = character(), tipo_base = character(), n_tokens_invalidos = integer(), tokens_invalidos = character(), exemplos = character(), bloqueante = logical(), motivo_bloqueio = character()))
  data.table::rbindlist(problemas[seq_len(k)], fill = TRUE)
}

monitora_validados_validar_condicionais_xlsform21 <- function(out) {
  problemas <- list()
  k <- 0L
  add <- function(regra, atributo, idx, detalhe = "") {
    n <- sum(idx, na.rm = TRUE)
    if (!n) return(invisible(NULL))
    k <<- k + 1L
    exemplos <- ""
    if ("coleta" %in% names(out)) exemplos <- paste(utils::head(out[["coleta"]][which(idx)], 10L), collapse = " | ")
    problemas[[k]] <<- data.table::data.table(regra = regra, atributo = atributo, n_problemas = as.integer(n), exemplos_coleta = exemplos, detalhe = detalhe, bloqueante = TRUE, motivo_bloqueio = regra)
    invisible(NULL)
  }
  tipo_col <- "amostragem/registro/tipo_forma_vida"
  if (tipo_col %in% names(out)) {
    tipo <- out[[tipo_col]]
    tem_solo <- monitora_validados_tem_token(tipo, "solo_nu")
    tem_outro <- Reduce(`|`, lapply(c("serrapilheira", "nativa", "exotica", "seca_morta", "outra_forma_vida"), function(tt) monitora_validados_tem_token(tipo, tt)))
    add("solo_nu_com_outra_categoria", tipo_col, tem_solo & tem_outro, "solo_nu é exclusivo")
    pares <- list(
      serrapilheira = "amostragem/registro/forma_serrapilheira",
      outra_forma_vida = "amostragem/registro/forma_vida_outros",
      nativa = "amostragem/registro/forma_vida_nativa",
      exotica = "amostragem/registro/forma_vida_exotica",
      seca_morta = "amostragem/registro/forma_vida_seca_morta"
    )
    for (tok in names(pares)) {
      cc <- pares[[tok]]
      if (cc %in% names(out)) {
        add("campo_obrigatorio_relevante_vazio", cc, monitora_validados_tem_token(tipo, tok) & !nzchar(out[[cc]]), paste0("selected(tipo_forma_vida, '", tok, "')"))
        add("campo_irrelevante_preenchido", cc, !monitora_validados_tem_token(tipo, tok) & nzchar(out[[cc]]), paste0("not selected(tipo_forma_vida, '", tok, "')"))
      }
    }
  }
  impact_col <- "impact_manejo_uso/impacto_manejo_uso"
  tipos_col <- "impact_manejo_uso/tipos_impacto_manejo_uso"
  if (impact_col %in% names(out) && tipos_col %in% names(out)) {
    impact <- out[[impact_col]]
    tipos <- out[[tipos_col]]
    add("tipos_impacto_obrigatorio_quando_impacto_sim", tipos_col, impact == "sim" & !nzchar(tipos), "${impacto_manejo_uso}=sim")
    add("tipos_impacto_irrelevante_quando_impacto_nao", tipos_col, impact != "sim" & nzchar(tipos), "${impacto_manejo_uso}!=sim")
  }
  if (!k) return(data.table::data.table(regra = character(), atributo = character(), n_problemas = integer(), exemplos_coleta = character(), detalhe = character(), bloqueante = logical(), motivo_bloqueio = character()))
  data.table::rbindlist(problemas[seq_len(k)], fill = TRUE)
}



monitora_validados_auditar_sanitizacao_desconhecida <- function(out) {
  out <- data.table::as.data.table(out)
  cols <- names(out)
  categorias <- c("nativa", "exotica", "seca_morta")
  problemas <- vector("list", length(categorias) * 3L)
  kk <- 0L
  normaliza <- function(x) {
    x <- as.character(x); x[is.na(x)] <- ""; x <- tolower(x); x <- iconv(x, from = "", to = "ASCII//TRANSLIT"); x[is.na(x)] <- ""; gsub("[^a-z0-9]+", "_", x, perl = TRUE)
  }
  for (cat in categorias) {
    main <- paste0("amostragem/registro/forma_vida_", cat)
    if (!(main %in% cols)) next
    tem_desc <- monitora_validados_tem_token(out[[main]], "desconhecida")
    nms_norm <- normaliza(cols)
    cat_pat <- if (identical(cat, "seca_morta")) "seca.*morta|seca_ou_morta|seca_e_morta" else cat
    dep_cols <- cols[
      grepl("desconhecid|indeterminad|nao_identific|nao_identificado", nms_norm, perl = TRUE) &
        grepl(cat_pat, nms_norm, perl = TRUE) &
        grepl("foto|imagem|image|upload|arquivo|anexo|midia|media|descr|descricao|descritor|observ|obs", nms_norm, perl = TRUE)
    ]
    dep_cols <- setdiff(dep_cols, main)
    for (dc in dep_cols) {
      preenchido <- nzchar(monitora_validados_limpar_ausencia_saida(out[[dc]]))
      viol <- preenchido & !tem_desc
      if (any(viol, na.rm = TRUE)) {
        kk <- kk + 1L
        problemas[[kk]] <- data.table::data.table(
          tipo = "dependente_desconhecida_preenchido_sem_token",
          categoria = cat,
          atributo = dc,
          n_linhas = sum(viol, na.rm = TRUE),
          exemplos = paste(utils::head(which(viol), 10L), collapse = " | "),
          motivo_bloqueio = "foto/descritor de forma de vida desconhecida preenchido sem token desconhecida na categoria correspondente"
        )
      }
    }
  }
  if (kk) data.table::rbindlist(problemas[seq_len(kk)], fill = TRUE, use.names = TRUE) else data.table::data.table(tipo = character(), categoria = character(), atributo = character(), n_linhas = integer(), exemplos = character(), motivo_bloqueio = character())
}

monitora_validados_auditar_sanitizacao_outras_formas <- function(out, meta = NULL) {
  ## Diagnóstico específico para resíduos de versões antigas do XLSForm.
  ## Nas primeiras versões, "outra forma de vida" permitia texto livre em campos
  ## descritivos. Na versão 21FEV25, esses campos/textos livres não fazem parte
  ## do contrato final de registros_validados.csv. Portanto, valores como
  ## "Musgo", "M" ou erros de digitação não são convertidos automaticamente em
  ## tokens atuais; devem ser triados pela rotina de sanitização antes da
  ## exportação final.
  vazio <- data.table::data.table(
    COLETA = character(), UC = character(), CICLO = character(), CAMPANHA = character(),
    EA = character(), UA = character(), ponto_amostral = character(), ponto_metro = character(),
    atributo = character(), valor_residual = character(), tokens_invalidos = character(),
    motivo_bloqueio = character(), orientacao = character()
  )
  att <- "amostragem/registro/forma_vida_outros"
  if (!(att %in% names(out))) return(vazio)
  if (is.null(meta)) meta <- monitora_validados_xlsform21_meta()
  choices <- monitora_validados_xlsform21_choices("forma_vida_outros", meta)
  if (!length(choices)) return(vazio)
  x <- monitora_validados_limpar_ausencia_saida(out[[att]])
  vals <- unique(x[nzchar(x)])
  if (!length(vals)) return(vazio)
  tokenizar <- function(v) {
    toks <- unlist(strsplit(gsub("[|;,]+", " ", v, perl = TRUE), "\\s+", perl = TRUE), use.names = FALSE)
    unique(toks[nzchar(toks)])
  }
  invalidos_por_valor <- vapply(vals, function(v) {
    inv <- setdiff(tokenizar(v), choices)
    if (!length(inv)) "" else paste(inv, collapse = " | ")
  }, character(1), USE.NAMES = FALSE)
  inv_map <- stats::setNames(invalidos_por_valor, vals)
  inv_linha <- unname(inv_map[x])
  inv_linha[is.na(inv_linha)] <- ""
  idx <- which(nzchar(x) & nzchar(inv_linha))
  if (!length(idx)) return(vazio)
  pegar <- function(cc) if (cc %in% names(out)) as.character(out[[cc]]) else rep("", nrow(out))
  data.table::data.table(
    COLETA = pegar("coleta")[idx],
    UC = pegar("uc")[idx],
    CICLO = pegar("ciclo")[idx],
    CAMPANHA = pegar("campanha")[idx],
    EA = pegar("estacao_amostral")[idx],
    UA = pegar("unidade_amostral")[idx],
    ponto_amostral = pegar("amostragem/registro/ponto_amostral")[idx],
    ponto_metro = pegar("amostragem/registro/ponto_metro")[idx],
    atributo = att,
    valor_residual = x[idx],
    tokens_invalidos = inv_linha[idx],
    motivo_bloqueio = "residuo_outra_forma_vida_sem_sanitizacao_previa",
    orientacao = "Aplicar a rotina de sanitização/triagem de outra forma de vida em registros_corrig antes de gerar registros_validados.csv; não converter texto livre legado automaticamente."
  )
}


monitora_validados_pegar_preferir_preenchido <- function(dt, candidatos, n = nrow(dt)) {
  ## v2.6.1:
  ## o painel pode criar colunas canônicas minúsculas vazias (ea/ua), enquanto
  ## registros_corrig mantém as colunas operacionais preenchidas em maiúsculas
  ## (EA/UA). Para exportação contratual, preferir a coluna com valores reais.
  melhor <- list(valor = rep("", n), coluna = NA_character_)
  melhor_n <- -1L
  vistos <- character(0)
  for (cand in candidatos) {
    col <- monitora_validados_resolver_coluna(names(dt), cand)
    if (is.na(col) || !nzchar(col) || !(col %in% names(dt)) || col %in% vistos) next
    vistos <- c(vistos, col)
    v <- monitora_validados_limpar_ausencia_saida(dt[[col]])
    n_preen <- sum(nzchar(v))
    if (n_preen > melhor_n) {
      melhor <- list(valor = v, coluna = col)
      melhor_n <- n_preen
      if (n_preen >= n) break
    }
  }
  melhor
}

monitora_validados_derivar_ou_mapear_coluna <- function(dt, atributo, formato, largura) {
  n <- nrow(dt)
  if (identical(atributo, "data_do_registro")) return(monitora_validados_derive_datetime(dt, "data_do_registro"))
  if (identical(atributo, "data_do_recebimento")) return(monitora_validados_derive_datetime(dt, "data_do_recebimento"))
  if (identical(atributo, "data_hora/data")) return(monitora_validados_derive_data_hora(dt, "data"))
  if (identical(atributo, "data_hora/hora")) return(monitora_validados_derive_data_hora(dt, "hora"))
  if (identical(atributo, "coleta_uuid")) return(monitora_validados_uuid_por_coleta_ou_sintetico(dt, "coleta_uuid"))
  if (identical(atributo, "uuid")) return(monitora_validados_uuid_por_coleta_ou_sintetico(dt, "uuid"))
  if (identical(atributo, "amostragem/registro/uuid")) return(monitora_validados_uuid_registro_ou_sintetico(dt))

  if (identical(atributo, "uc")) {
    p <- monitora_validados_pegar_preferir_preenchido(dt, c("UC", "uc", "unidade_conservacao", "Unidade de Conservação"), n)
    v <- monitora_validados_preencher_por_coleta(dt, p$valor, padrao = "nao_informada")
    return(list(valor = v, coluna = p$coluna, estrategia = "mapeada_uc_preferindo_coluna_preenchida"))
  }
  if (identical(atributo, "ea")) {
    p <- monitora_validados_pegar_preferir_preenchido(dt, c("EA", "ea", "estacao_amostral", "estação amostral"), n)
    v <- monitora_validados_preencher_por_coleta(dt, p$valor, padrao = "nao_informada")
    return(list(valor = v, coluna = p$coluna, estrategia = "mapeada_ea_preferindo_coluna_preenchida"))
  }
  if (identical(atributo, "ua")) {
    p <- monitora_validados_pegar_preferir_preenchido(dt, c("UA", "ua", "unidade_amostral", "unidade amostral"), n)
    v <- monitora_validados_preencher_por_coleta(dt, p$valor, padrao = "nao_informada")
    return(list(valor = v, coluna = p$coluna, estrategia = "mapeada_ua_preferindo_coluna_preenchida"))
  }

  if (identical(atributo, "ciclo")) {
    p <- monitora_validados_pegar(dt, c("CICLO", "ciclo", "amostragem/ciclo"), n)
    v <- monitora_validados_preencher_por_coleta(dt, p$valor, padrao = "nao_informado")
    return(list(valor = v, coluna = p$coluna, estrategia = "mapeada_completada_por_coleta_ou_nao_informado"))
  }
  if (identical(atributo, "campanha")) {
    p <- monitora_validados_pegar(dt, c("CAMPANHA", "campanha", "amostragem/campanha"), n)
    v <- monitora_validados_preencher_por_coleta(dt, p$valor, padrao = "nao_informada")
    return(list(valor = v, coluna = p$coluna, estrategia = "mapeada_completada_por_coleta_ou_nao_informada"))
  }

  ## Campos de controle/domínio do XLSForm alvo 21FEV25.
  ## Devem ser resolvidos antes do mapeamento genérico, pois registros_corrig
  ## pode conter "NA" textual, protocolo histórico ou proveniência interna.
  if (identical(atributo, "validado")) {
    p <- monitora_validados_pegar(dt, c("validado", "VALIDADO"), n)
    v <- monitora_validados_limpar_ausencia_saida(p$valor)
    v[!nzchar(v)] <- "nao"
    v <- tolower(v)
    v[!(v %in% c("sim", "nao"))] <- "nao"
    return(list(valor = v, coluna = p$coluna, estrategia = "mapeada_ou_sintetizada_padrao_nao"))
  }
  if (identical(atributo, "controle_versao")) {
    p <- monitora_validados_pegar(dt, c("controle_versao", "CONTROLE_VERSAO"), n)
    v <- monitora_validados_formatar_valor(p$valor, "inteiro_texto")
    v[!nzchar(v)] <- "2025022101"
    return(list(valor = v, coluna = p$coluna, estrategia = "mapeada_ou_sintetizada_versao_xlsform_21FEV25"))
  }
  if (identical(atributo, "protocolo")) {
    return(list(valor = rep("PLANTASHERBACEASELENHOSAS_CAMPSAV_21FEV25", n), coluna = NA_character_, estrategia = "sintetizada_protocolo_xlsform_21FEV25"))
  }
  if (identical(atributo, "planilha_upload")) {
    tipo <- monitora_validados_pegar(dt, c("MONITORA_TIPO_ENTRADA", "planilha_upload"), n)
    tv <- tolower(monitora_validados_limpar_ausencia_saida(tipo$valor))
    v <- ifelse(grepl("planilha|digital", tv, perl = TRUE), "sim", "nao")
    return(list(valor = v, coluna = tipo$coluna, estrategia = "sintetizada_dominio_planilha_upload"))
  }
  if (identical(atributo, "amostragem/num_placa")) {
    return(monitora_validados_derivar_num_placa(dt, "num_placa"))
  }
  if (identical(atributo, "amostragem/num_placa_formatado")) {
    return(monitora_validados_derivar_num_placa(dt, "num_placa_formatado"))
  }
  if (identical(atributo, "amostragem/registro/forma_vida_outros")) {
    ## v2.6.1: registros_validados.csv não herda diretamente campos históricos
    ## de "outra forma de vida". Esses campos são consumidos e auditados pela
    ## sanitização validados em registros_corrig. A saída validada deve usar
    ## somente o campo atual 21FEV25 já sanitizado.
    atual <- monitora_validados_pegar(dt, c(
      "amostragem/registro/forma_vida_outros",
      "Outras plantas terrestres, líquens e/ou fungos\u200b: (amostragem/registro)",
      "Outras plantas terrestres, líquens e/ou fungos: (amostragem/registro)"
    ), n)
    return(list(valor = atual$valor, coluna = atual$coluna, estrategia = "mapeada_campo_atual_pos_sanitizacao_antes_registros_validados"))
  }
  if (identical(atributo, "amostragem/registro/forma_serrapilheira")) {
    atual <- monitora_validados_pegar(dt, c(
      "amostragem/registro/forma_serrapilheira",
      "Materiais botânicos em decomposição no solo observados: (amostragem/registro)",
      "Material botânico em decomposição no solo observado: (amostragem/registro)"
    ), n)
    tipo <- monitora_validados_pegar(dt, c(
      "amostragem/registro/tipo_forma_vida",
      "**Encostam** na vareta: (amostragem/registro)"
    ), n)
    nat <- monitora_validados_pegar(dt, c("amostragem/registro/forma_vida_nativa", "Formas de vida de plantas <span style=\"\"color:red\"\">nativas:</span> (amostragem/registro)"), n)
    exo <- monitora_validados_pegar(dt, c("amostragem/registro/forma_vida_exotica", "Formas de vida de plantas <span style=\"\"color:red\"\">exóticas:</span> (amostragem/registro)"), n)
    seca <- monitora_validados_pegar(dt, c("amostragem/registro/forma_vida_seca_morta", "Formas de vida de plantas <span style=\"\"color:red\"\">secas ou mortas:</span> (amostragem/registro)"), n)
    v <- monitora_validados_limpar_ausencia_saida(atual$valor)
    contem_serrapilheira <- monitora_validados_tem_token(tipo$valor, "serrapilheira") |
      monitora_validados_tem_token(nat$valor, "serrapilheira") |
      monitora_validados_tem_token(exo$valor, "serrapilheira") |
      monitora_validados_tem_token(seca$valor, "serrapilheira")
    idx <- !nzchar(v) & contem_serrapilheira
    if (any(idx)) v[idx] <- "serrapilheira"
    origem <- paste(unique(c(atual$coluna, tipo$coluna, nat$coluna, exo$coluna, seca$coluna)[!is.na(c(atual$coluna, tipo$coluna, nat$coluna, exo$coluna, seca$coluna))]), collapse = " + ")
    return(list(valor = v, coluna = origem, estrategia = "mapeada_ou_derivada_serrapilheira_historica"))
  }
  if (identical(atributo, "amostragem/especie")) return(list(valor = rep("sim", n), coluna = NA_character_, estrategia = "sintetizada_padrao_sim"))

  col <- monitora_validados_resolver_coluna(names(dt), atributo)
  if (!is.na(col) && col %in% names(dt)) {
    return(list(valor = monitora_validados_formatar_valor(dt[[col]], formato, largura), coluna = col, estrategia = "mapeada"))
  }

  list(valor = rep("", n), coluna = NA_character_, estrategia = "opcional_sem_origem_vazio")
}

monitora_validados_validar_formatos_saida <- function(out, schema) {
  problemas <- vector("list", nrow(schema))
  k <- 0L
  for (ii in seq_len(nrow(schema))) {
    col <- schema$atributo[ii]
    fmt <- schema$formato[ii]
    x <- as.character(out[[col]])
    x <- x[!is.na(x) & nzchar(x)]
    ok <- TRUE
    if (length(x)) {
      if (identical(fmt, "datetime_iso_espaco")) ok <- all(grepl("^[0-9]{4}-[0-9]{2}-[0-9]{2} [0-9]{2}:[0-9]{2}:[0-9]{2}$", x, perl = TRUE))
      if (identical(fmt, "data_iso")) ok <- all(grepl("^[0-9]{4}-[0-9]{2}-[0-9]{2}$", x, perl = TRUE))
      if (identical(fmt, "hora_hms_millis_tz")) ok <- all(grepl(monitora_validados_hora_hms_millis_tz_regex(), x, perl = TRUE))
      if (identical(fmt, "inteiro_texto")) ok <- all(grepl("^[0-9]+$", x, perl = TRUE))
      if (identical(fmt, "inteiro_texto_zero_esquerda")) ok <- all(grepl("^[0-9]+$", x, perl = TRUE) & (is.na(schema$largura[ii]) | nchar(x) >= schema$largura[ii]))
      if (identical(fmt, "numero_texto_ponto")) ok <- all(grepl("^[0-9]+(\\.[0-9]+)?$", x, perl = TRUE))
      if (identical(fmt, "uuid_texto")) ok <- all(monitora_validados_uuid_valido(x))
    }
    if (!isTRUE(ok)) {
      k <- k + 1L
      problemas[[k]] <- data.table::data.table(
        posicao = schema$posicao[ii], atributo = col, formato_esperado = fmt,
        n_valores_nao_vazios = length(x), exemplos = paste(utils::head(unique(x), 5L), collapse = " | "),
        bloqueante = TRUE, motivo_bloqueio = "formato_incompativel"
      )
    }
  }
  if (!k) {
    return(data.table::data.table(
      posicao = integer(), atributo = character(), formato_esperado = character(),
      n_valores_nao_vazios = integer(), exemplos = character(),
      bloqueante = logical(), motivo_bloqueio = character()
    ))
  }
  data.table::rbindlist(problemas[seq_len(k)], fill = TRUE)
}

monitora_validados_auditar_cardinalidade <- function(out) {
  coleta <- out[["coleta"]]
  aux <- data.table::data.table(
    atributo = c("coleta_uuid", "uuid", "amostragem/registro/uuid"),
    nivel_esperado = c("um_valor_por_coleta", "um_valor_por_coleta", "um_valor_por_linha"),
    status = "ok",
    n_problemas = 0L,
    detalhe = ""
  )
  for (att in c("coleta_uuid", "uuid")) {
    dt <- data.table::data.table(coleta = coleta, valor = out[[att]])
    bad <- dt[nzchar(coleta) & nzchar(valor), .(n_valores = data.table::uniqueN(valor)), by = coleta][n_valores > 1L]
    aux[atributo == att, `:=`(status = if (nrow(bad)) "falha" else "ok", n_problemas = nrow(bad), detalhe = if (nrow(bad)) paste(utils::head(bad$coleta, 5L), collapse = " | ") else "")]
  }
  vreg <- out[["amostragem/registro/uuid"]]
  dup <- sum(duplicated(vreg[nzchar(vreg)]))
  vaz <- sum(!nzchar(vreg))
  aux[atributo == "amostragem/registro/uuid", `:=`(status = if ((dup + vaz) > 0L) "falha" else "ok", n_problemas = dup + vaz, detalhe = paste0("duplicados=", dup, "; vazios=", vaz))]
  aux
}


### v2.6.1 --------------------
### Auditoria contratual do produto registros_corrig.csv nos atributos que
### alimentam registros_validados.csv. Ela reaproveita as interpretações,
### normalizações e validações do exportador validado, mas materializa o status no
### nível do produto de origem para deixar explícito que registros_validados.csv é
### apenas a exportação estruturada quando registros_corrig já está coerente.
monitora_publicacao_z_atributos_problema <- function(dt, preferir = c("atributo", "att", "campo")) {
  dt <- tryCatch(data.table::as.data.table(dt), error = function(e) data.table::data.table())
  if (!nrow(dt)) return(character())
  cc <- intersect(preferir, names(dt))
  if (!length(cc)) return(character())
  unique(as.character(dt[[cc[1L]]]))
}

monitora_publicacao_z_motivos_por_atributo <- function(dt, atributo) {
  dt <- tryCatch(data.table::as.data.table(dt), error = function(e) data.table::data.table())
  if (!nrow(dt) || !("atributo" %in% names(dt))) return("")
  z <- dt[as.character(atributo) == as.character(dt$atributo)]
  if (!nrow(z)) return("")
  cols_motivo <- intersect(c("motivo_bloqueio", "regra", "tipo", "detalhe"), names(z))
  vals <- character()
  for (cc in cols_motivo) vals <- c(vals, as.character(z[[cc]]))
  vals <- unique(vals[!is.na(vals) & nzchar(vals)])
  paste(vals, collapse = "; ")
}



### v2.6.1 -------------------------------------------------------------
### Governança de bloqueios de registros_validados.csv. Bloqueios contratuais
### da exportação validada NÃO podem impedir a materialização de
### registros_corrig.csv; eles apenas bloqueiam registros_validados.csv e geram
### auditoria explícita para correção posterior.
monitora_registros_validados_gravar_bloqueios <- function(resumo = NULL,
                                                           vazias_obrig = NULL,
                                                           problemas_fmt = NULL,
                                                           problemas_dom = NULL,
                                                           problemas_cond = NULL,
                                                           problemas_sanitizacao_outras = NULL,
                                                           problemas_sanitizacao_desconhecida = NULL,
                                                           card = NULL,
                                                           problemas_chave = NULL,
                                                           mensagem = "",
                                                           contexto = "bloqueio_registros_validados",
                                                           output_dir = get0("MONITORA_OUTPUT_DIR", ifnotfound = "output", inherits = TRUE),
                                                           log_dir = get0("MONITORA_LOG_DIR", ifnotfound = "log", inherits = TRUE),
                                                           exec_id = get0("MONITORA_EXEC_ID", ifnotfound = format(Sys.time(), "%Y%m%d_%H%M%S"), inherits = TRUE)) {
  dir.create(output_dir, recursive = TRUE, showWarnings = FALSE)
  dir.create(log_dir, recursive = TRUE, showWarnings = FALSE)
  dir.create(file.path(output_dir, "03_auditorias", "contrato_xlsform"), recursive = TRUE, showWarnings = FALSE)
  dir.create(file.path(output_dir, "02_painel_correcoes", "ocorrencias_diagnosticas", "pos_painel"), recursive = TRUE, showWarnings = FALSE)
  linhas <- list()
  add <- function(origem, dt, atributo_col = "atributo", motivo_padrao = origem) {
    dd <- tryCatch(data.table::as.data.table(dt), error = function(e) data.table::data.table())
    if (!nrow(dd)) return(invisible(NULL))
    atributo <- if (atributo_col %in% names(dd)) as.character(dd[[atributo_col]]) else if ("att" %in% names(dd)) as.character(dd$att) else rep(NA_character_, nrow(dd))
    motivo_cols <- intersect(c("motivo_bloqueio", "regra", "tipo", "detalhe", "mensagem", "status"), names(dd))
    detalhe <- if (length(motivo_cols)) apply(as.data.frame(dd[, ..motivo_cols]), 1L, function(z) paste(unique(z[!is.na(z) & nzchar(z)]), collapse = "; ")) else rep("", nrow(dd))
    if (!length(detalhe)) detalhe <- rep("", nrow(dd))
    linhas[[length(linhas) + 1L]] <<- data.table::data.table(
      exec_id = as.character(exec_id), contexto = as.character(contexto)[1L],
      produto = "registros_validados.csv", status = "bloqueado",
      origem_bloqueio = as.character(origem), atributo = atributo,
      n_linhas = as.integer(nrow(dd)), detalhe = detalhe,
      mensagem_geral = as.character(mensagem)[1L], timestamp = format(Sys.time(), "%Y-%m-%d %H:%M:%S")
    )
    invisible(NULL)
  }
  add("obrigatorio_vazio", vazias_obrig)
  add("formato_invalido", problemas_fmt)
  add("dominio_xlsform_invalido", problemas_dom)
  add("condicional_xlsform_invalido", problemas_cond)
  add("sanitizacao_outras_formas", problemas_sanitizacao_outras)
  add("sanitizacao_desconhecida", problemas_sanitizacao_desconhecida)
  ### v2.6.1: a auditoria de cardinalidade grava também linhas OK.
  ### O relatório de bloqueios deve receber somente falhas reais, senão
  ### coleta_uuid/uuid aparecem como bloqueados apesar de status == ok.
  card_bloq <- tryCatch(data.table::as.data.table(card), error = function(e) data.table::data.table())
  if (nrow(card_bloq)) {
    if ("status" %in% names(card_bloq)) {
      card_bloq <- card_bloq[is.na(status) | as.character(status) != "ok"]
    } else if ("n_problemas" %in% names(card_bloq)) {
      card_bloq <- card_bloq[suppressWarnings(as.integer(n_problemas)) > 0L]
    }
  }
  add("cardinalidade_uuid", card_bloq)
  add("chave_unica", problemas_chave)
  bloq <- if (length(linhas)) data.table::rbindlist(linhas, fill = TRUE, use.names = TRUE) else data.table::data.table(
    exec_id = as.character(exec_id), contexto = as.character(contexto)[1L], produto = "registros_validados.csv",
    status = "ok", origem_bloqueio = character(), atributo = character(), n_linhas = integer(), detalhe = character(), mensagem_geral = character(), timestamp = character()
  )
  resumo_dt <- tryCatch(data.table::as.data.table(resumo), error = function(e) data.table::data.table())
  if (nrow(bloq)) {
    data.table::fwrite(bloq, file.path(output_dir, "03_auditorias", "contrato_xlsform", "auditoria_registros_validados_bloqueios.csv"), sep = ",", quote = "auto", na = "")
    data.table::fwrite(bloq, file.path(log_dir, paste0("auditoria_registros_validados_bloqueios_", exec_id, ".csv")), sep = ",", quote = "auto", na = "")
  }
  if (nrow(resumo_dt)) {
    resumo_dt[, `:=`(produto = "registros_validados.csv", status_validacao = ifelse(any(suppressWarnings(as.integer(n_bloqueios)) > 0L, na.rm = TRUE), "bloqueado", "ok"), contexto_bloqueio = as.character(contexto)[1L])]
    data.table::fwrite(resumo_dt, file.path(output_dir, "03_auditorias", "contrato_xlsform", "resumo_registros_validados_bloqueios.csv"), sep = ",", quote = "auto", na = "")
  }
  ### Ocorrência diagnóstica específica para o caso que antes aparecia tarde
  ### demais: descritor/foto de desconhecida sem token desconhecida. Não corrige
  ### automaticamente; explicita a pendência contratual para próxima ação.
  desc <- tryCatch(data.table::as.data.table(problemas_sanitizacao_desconhecida), error = function(e) data.table::data.table())
  if (nrow(desc)) {
    desc_out <- data.table::copy(desc)
    desc_out[, `:=`(exec_id = as.character(exec_id), tipo_ocorrencia = "desconhecida_dependente_sem_token", status = "bloqueia_registros_validados", timestamp = format(Sys.time(), "%Y-%m-%d %H:%M:%S"))]
    data.table::fwrite(desc_out, file.path(output_dir, "02_painel_correcoes", "ocorrencias_diagnosticas", "pos_painel", "registros_desconhecida_dependente_sem_token_pos_painel.csv"), sep = ",", quote = "auto", na = "")
  }
  assign("MONITORA_REGISTROS_VALIDADOS_BLOQUEADO", nrow(bloq) > 0L, envir = .GlobalEnv)
  assign("MONITORA_REGISTROS_VALIDADOS_BLOQUEIOS_ULTIMA", bloq, envir = .GlobalEnv)
  assign("MONITORA_REGISTROS_VALIDADOS_GERADO", FALSE, envir = .GlobalEnv)
  if (exists("monitora_publicacao_g_log", mode = "function") && nrow(bloq)) {
    monitora_publicacao_g_log("registros_validados.csv bloqueado sem bloquear registros_corrig.csv [", contexto, "]: ", nrow(bloq), " linha(s) de auditoria de bloqueio; ver 03_auditorias/contrato_xlsform/auditoria_registros_validados_bloqueios.csv")
  }
  invisible(bloq)
}
### FIM v2.6.1 ---------------------------------------------------------

monitora_registros_corrig_gravar_auditoria_contrato_xlsform21 <- function(auditoria,
                                                                           vazias_obrig = NULL,
                                                                           problemas_fmt = NULL,
                                                                           problemas_dom = NULL,
                                                                           problemas_cond = NULL,
                                                                           problemas_sanitizacao_outras = NULL,
                                                                           problemas_sanitizacao_desconhecida = NULL,
                                                                           card = NULL,
                                                                           problemas_chave = NULL,
                                                                           ajustes_xlsform21 = NULL,
                                                                           output_dir = MONITORA_OUTPUT_DIR,
                                                                           log_dir = MONITORA_LOG_DIR,
                                                                           exec_id = MONITORA_EXEC_ID,
                                                                           contexto = "pre_materializacao_registros_corrig") {
  aud <- data.table::as.data.table(auditoria)
  if (!nrow(aud)) return(invisible(data.table::data.table()))
  dir.create(output_dir, recursive = TRUE, showWarnings = FALSE)
  dir.create(log_dir, recursive = TRUE, showWarnings = FALSE)

  attrs_fmt <- monitora_publicacao_z_atributos_problema(problemas_fmt)
  attrs_dom <- monitora_publicacao_z_atributos_problema(problemas_dom)
  attrs_cond <- monitora_publicacao_z_atributos_problema(problemas_cond)
  attrs_san_outras <- monitora_publicacao_z_atributos_problema(problemas_sanitizacao_outras)
  attrs_san_desc <- monitora_publicacao_z_atributos_problema(problemas_sanitizacao_desconhecida)
  attrs_obrig <- monitora_publicacao_z_atributos_problema(vazias_obrig)
  attrs_card <- character()
  card_dt <- tryCatch(data.table::as.data.table(card), error = function(e) data.table::data.table())
  if (nrow(card_dt) && all(c("atributo", "status") %in% names(card_dt))) attrs_card <- unique(as.character(card_dt[status != "ok"]$atributo))
  chave_bloq <- tryCatch(nrow(data.table::as.data.table(problemas_chave)) > 0L, error = function(e) FALSE)

  aj <- tryCatch(data.table::as.data.table(ajustes_xlsform21), error = function(e) data.table::data.table())
  if (nrow(aj) && all(c("atributo", "n_ajustes") %in% names(aj))) {
    aj_sum <- aj[, .(n_ajustes_xlsform21 = sum(suppressWarnings(as.integer(n_ajustes)), na.rm = TRUE)), by = atributo]
  } else {
    aj_sum <- data.table::data.table(atributo = character(), n_ajustes_xlsform21 = integer())
  }

  contrato <- data.table::copy(aud)
  contrato[, `:=`(
    produto = "registros_corrig.csv",
    contexto = as.character(contexto)[1L],
    mapeado = !is.na(coluna_origem_registros_corrig) | grepl("^(sintetizada|derivada|mapeada_ou_derivada|mapeada_campo_atual|opcional_sem_origem)", as.character(estrategia), perl = TRUE),
    formato_ok = !(atributo %in% unique(c(attrs_fmt, attrs_obrig))),
    dominio_ok = !(atributo %in% attrs_dom),
    condicional_ok = !(atributo %in% attrs_cond),
    sanitizacao_ok = !(atributo %in% unique(c(attrs_san_outras, attrs_san_desc))),
    uuid_cardinalidade_ok = !(atributo %in% attrs_card),
    chave_unica_ok = TRUE,
    bloqueante = FALSE,
    motivo = ""
  )]
  if (isTRUE(chave_bloq) && "coleta" %in% contrato$atributo) contrato[atributo == "coleta", chave_unica_ok := FALSE]
  if (nrow(aj_sum)) contrato <- merge(contrato, aj_sum, by = "atributo", all.x = TRUE, sort = FALSE) else contrato[, n_ajustes_xlsform21 := 0L]
  contrato[is.na(n_ajustes_xlsform21), n_ajustes_xlsform21 := 0L]

  contrato[, bloqueante := !formato_ok | !dominio_ok | !condicional_ok | !sanitizacao_ok | !uuid_cardinalidade_ok | !chave_unica_ok]
  if (nrow(contrato)) {
    motivos <- vapply(contrato$atributo, function(aa) {
      m <- character()
      if (aa %in% attrs_obrig) m <- c(m, "atributo_obrigatorio_vazio_apos_interpretacao")
      if (aa %in% attrs_fmt) m <- c(m, monitora_publicacao_z_motivos_por_atributo(problemas_fmt, aa))
      if (aa %in% attrs_dom) m <- c(m, monitora_publicacao_z_motivos_por_atributo(problemas_dom, aa))
      if (aa %in% attrs_cond) m <- c(m, monitora_publicacao_z_motivos_por_atributo(problemas_cond, aa))
      if (aa %in% attrs_san_outras) m <- c(m, monitora_publicacao_z_motivos_por_atributo(problemas_sanitizacao_outras, aa))
      if (aa %in% attrs_san_desc) m <- c(m, monitora_publicacao_z_motivos_por_atributo(problemas_sanitizacao_desconhecida, aa))
      if (aa %in% attrs_card) m <- c(m, "uuid_cardinalidade_invalida")
      if (isTRUE(chave_bloq) && identical(aa, "coleta")) m <- c(m, "duplicidade_coleta_ponto_amostral")
      m <- unique(m[!is.na(m) & nzchar(m)])
      paste(m, collapse = "; ")
    }, character(1L))
    contrato[, motivo := motivos]
  }
  contrato[, status_contrato := ifelse(bloqueante, "bloqueante", "ok")]
  contrato_logico <- data.table::copy(contrato)
  contrato_auditoria <- monitora_privacidade_sanitizar_auditoria(contrato, mascarar_exemplos = FALSE)

  resumo <- data.table::data.table(
    exec_id = as.character(exec_id),
    produto = "registros_corrig.csv",
    contrato = "atributos_que_alimentam_registros_validados_xlsform21",
    contexto = as.character(contexto)[1L],
    n_atributos = nrow(contrato_logico),
    n_bloqueios = sum(contrato_logico$bloqueante, na.rm = TRUE),
    n_formato_invalido = sum(!contrato_logico$formato_ok, na.rm = TRUE),
    n_dominio_invalido = sum(!contrato_logico$dominio_ok, na.rm = TRUE),
    n_condicional_invalido = sum(!contrato_logico$condicional_ok, na.rm = TRUE),
    n_sanitizacao_invalida = sum(!contrato_logico$sanitizacao_ok, na.rm = TRUE),
    n_ajustes_xlsform21 = sum(suppressWarnings(as.integer(contrato_logico$n_ajustes_xlsform21)), na.rm = TRUE),
    status = ifelse(any(contrato_logico$bloqueante, na.rm = TRUE), "bloqueante", "ok"),
    timestamp = format(Sys.time(), "%Y-%m-%d %H:%M:%S")
  )

  arq_log <- file.path(log_dir, paste0("auditoria_registros_corrig_contrato_xlsform21_", exec_id, ".csv"))
  arq_out <- file.path(output_dir, "auditoria_registros_corrig_contrato_xlsform21.csv")
  arq_resumo_log <- file.path(log_dir, paste0("auditoria_registros_corrig_contrato_xlsform21_resumo_", exec_id, ".csv"))
  arq_resumo_out <- file.path(output_dir, "auditoria_registros_corrig_contrato_xlsform21_resumo.csv")
  data.table::fwrite(contrato_auditoria, arq_log, sep = ",", quote = "auto", na = "")
  data.table::fwrite(contrato_auditoria, arq_out, sep = ",", quote = "auto", na = "")
  data.table::fwrite(resumo, arq_resumo_log, sep = ",", quote = "auto", na = "")
  data.table::fwrite(resumo, arq_resumo_out, sep = ",", quote = "auto", na = "")
  if (exists("monitora_log_registrar_evento", mode = "function")) {
    monitora_log_registrar_evento(
      "registros_corrig_contrato_xlsform21",
      ifelse(any(contrato_logico$bloqueante, na.rm = TRUE), "ERRO", "INFO"),
      arq_log,
      paste0("auditoria contratual de registros_corrig nos atributos do Contrato XLSForm 2025 (21FEV25): ", nrow(contrato_logico), " atributo(s), bloqueios=", sum(contrato_logico$bloqueante, na.rm = TRUE)),
      "registros_validados herda de registros_corrig saneado"
    )
  }
  invisible(list(auditoria = contrato_auditoria, resumo = resumo))
}
### FIM v2.6.1 ----------------

monitora_registros_validados_contrato_corrig_liberado <- function(contrato_corrig_validado = FALSE) {
  if (!isTRUE(contrato_corrig_validado)) return(FALSE)
  if (isTRUE(get0("MONITORA_REGISTROS_CORRIG_PENDENCIAS_IMPEDITIVAS", ifnotfound = FALSE, inherits = TRUE))) return(FALSE)
  xlsform_val <- get0("MONITORA_REGISTROS_CORRIG_CONTRATO_VALIDADO_XLSFORM21", ifnotfound = NA, inherits = TRUE)
  if (is.na(xlsform_val)) return(TRUE)
  isTRUE(xlsform_val)
}

monitora_registros_validados_exportar <- function(registros_corrig,
                                                  output_dir = MONITORA_OUTPUT_DIR,
                                                  log_dir = MONITORA_LOG_DIR,
                                                  exec_id = MONITORA_EXEC_ID,
                                                  abortar = TRUE,
                                                  forcar = FALSE,
                                                  somente_auditar_contrato_corrig = FALSE,
                                                  contrato_corrig_validado = FALSE) {
  if (!monitora_validados_opcao_ativa() && !isTRUE(somente_auditar_contrato_corrig)) return(invisible(NULL))
  if (isTRUE(get0("MONITORA_REGISTROS_VALIDADOS_GERADO", ifnotfound = FALSE, inherits = TRUE)) && !isTRUE(forcar)) {
    return(invisible(get0("MONITORA_REGISTROS_VALIDADOS_ULTIMA_AUDITORIA", ifnotfound = NULL, inherits = TRUE)))
  }
  if (!requireNamespace("data.table", quietly = TRUE)) stop("Pacote data.table é obrigatório para registros_validados.csv.", call. = FALSE)
  registros_corrig <- data.table::as.data.table(registros_corrig)
  schema <- monitora_validados_schema_embutido()
  cols <- schema$atributo
  n <- nrow(registros_corrig)
  dir.create(output_dir, showWarnings = FALSE, recursive = TRUE)
  dir.create(log_dir, showWarnings = FALSE, recursive = TRUE)

  if (!isTRUE(somente_auditar_contrato_corrig) &&
      !monitora_registros_validados_contrato_corrig_liberado(contrato_corrig_validado)) {
    assign("MONITORA_REGISTROS_VALIDADOS_GERADO", FALSE, envir = .GlobalEnv)
    resumo_pend <- get0("MONITORA_REGISTROS_CORRIG_PENDENCIAS_IMPEDITIVAS_RESUMO", ifnotfound = data.table::data.table(), inherits = TRUE)
    if (exists("monitora_publicacao_ab_logar_resumo_pendencias", mode = "function")) {
      monitora_publicacao_ab_logar_resumo_pendencias(resumo_pend, contexto = "bloqueio_registros_validados")
    }
    if (exists("monitora_publicacao_g_log", mode = "function")) {
      monitora_publicacao_g_log("registros_validados.csv nao sera criado: registros_corrig nao possui contrato validado ou contem pendencias impeditivas.")
    }
    if (exists("monitora_registros_validados_diagnostico_nao_gerado", mode = "function")) {
      try(monitora_registros_validados_diagnostico_nao_gerado(contexto = "bloqueio_contrato_corrig"), silent = TRUE)
    }
    if (isTRUE(abortar)) stop("registros_validados.csv bloqueado: registros_corrig nao validado ou com pendencias impeditivas.", call. = FALSE)
    return(invisible(list(bloqueado = TRUE, motivo = "contrato_corrig_nao_liberado", resumo = resumo_pend)))
  }


  ### v2.6.1: regra final de produto. Se registros_corrig já foi aprovado pelo
  ### contrato, registros_validados.csv não deriva, não escolhe alias e não
  ### sanitiza nada: apenas seleciona e reordena os 129 atributos do template.
  if (!isTRUE(somente_auditar_contrato_corrig) && isTRUE(contrato_corrig_validado) &&
      isTRUE(get0("MONITORA_REGISTROS_CORRIG_CONTRATO_VALIDADO_XLSFORM21", ifnotfound = FALSE, inherits = TRUE))) {
    return(monitora_publicacao_v262_exportar_registros_validados_selecao(
      registros_corrig = registros_corrig,
      schema = schema,
      output_dir = output_dir,
      log_dir = log_dir,
      exec_id = exec_id
    ))
  }

  ### v2.6.1: quando registros_corrig já foi saneado e validado pelo contrato
  ### XLSForm21 antes da materialização, registros_validados.csv deve herdar a
  ### matriz já montada/formatada na validação contratual. Isso evita repetir a
  ### interpretação completa do schema quando nada mudou desde o selo.
  cache_validados <- get0("MONITORA_REGISTROS_VALIDADOS_CACHE_PRE_CONTRATO", ifnotfound = NULL, inherits = TRUE)
  assinatura_atual <- if (exists("monitora_publicacao_z_assinatura_registros_corrig", mode = "function")) {
    tryCatch(monitora_publicacao_z_assinatura_registros_corrig(registros_corrig), error = function(e) NA_character_)
  } else NA_character_
  if (!isTRUE(somente_auditar_contrato_corrig) && isTRUE(contrato_corrig_validado) &&
      isTRUE(get0("MONITORA_REGISTROS_CORRIG_CONTRATO_VALIDADO_XLSFORM21", ifnotfound = FALSE, inherits = TRUE)) &&
      !is.null(cache_validados) && is.list(cache_validados) &&
      identical(as.character(cache_validados$assinatura_registros_corrig)[1L], as.character(assinatura_atual)[1L]) &&
      inherits(cache_validados$out, c("data.frame", "data.table"))) {
    out_cache <- data.table::as.data.table(cache_validados$out)
    data.table::setcolorder(out_cache, cols)
    caminho_saida <- if (exists("monitora_produtos_path_canonico", mode = "function")) {
      monitora_produtos_path_canonico("registros_validados.csv", output_dir)
    } else {
      file.path(output_dir, "01_produtos_dados", "registros_validados.csv")
    }
    dir.create(dirname(caminho_saida), recursive = TRUE, showWarnings = FALSE)
    data.table::fwrite(out_cache, caminho_saida, sep = ",", quote = "auto", na = "", bom = FALSE)
    header_saida <- names(data.table::fread(caminho_saida, sep = ",", nrows = 0, encoding = "UTF-8", check.names = FALSE, showProgress = FALSE, data.table = TRUE))
    if (!identical(header_saida, cols)) {
      stop("Cabeçalho de registros_validados.csv difere do schema SISMONITORA embutido; exportação bloqueada.", call. = FALSE)
    }
    MONITORA_REGISTROS_VALIDADOS_GERADO <<- TRUE
    MONITORA_REGISTROS_VALIDADOS_ULTIMA_AUDITORIA <<- cache_validados$auditoria
    if (exists("monitora_log_registrar_evento", mode = "function")) {
      monitora_log_registrar_evento("registros_validados_exportado", "INFO", caminho_saida, paste0("registros_validados.csv gerado por herança de registros_corrig validado com ", nrow(out_cache), " linhas e ", ncol(out_cache), " colunas"), "cache contratual v2.5.4; sem revalidação semântica")
    }
    return(invisible(MONITORA_REGISTROS_VALIDADOS_ULTIMA_AUDITORIA))
  }

  pre_sanitizacao_ja_aplicada <- isTRUE(get0("MONITORA_REGISTROS_VALIDADOS_PRE_SANITIZACAO_APLICADA", ifnotfound = FALSE, inherits = TRUE))
  if (!isTRUE(pre_sanitizacao_ja_aplicada)) {
    ### Segurança metodológica: registros_validados não pode acionar saneamento
    ### tardio. A base deve chegar aqui já sem pendências impeditivas e com selo
    ### de registros_corrig aprovado ou a exportação é bloqueada pela auditoria.
    if (exists("monitora_publicacao_g_log", mode = "function")) {
      monitora_publicacao_g_log("sanitização automática pré-registros_validados bloqueada; registros_validados exige registros_corrig previamente aprovado.")
    }
    if (isTRUE(abortar)) stop("registros_validados.csv bloqueado: registros_corrig não possui pré-sanitização/selo aprovado; resolva pendências no painel.", call. = FALSE)
    return(invisible(list(bloqueado = TRUE, motivo = "sem_selo_previo_registros_corrig")))
  } else if (exists("monitora_publicacao_g_log", mode = "function")) {
    monitora_publicacao_g_log("registros_validados herda registros_corrig previamente auditado; sem sanitização tardia automática")
  }
  n <- nrow(registros_corrig)

  if (exists("monitora_publicacao_aj_constroi_matriz_validados", mode = "function")) {
    matriz_publicacao_aj <- monitora_publicacao_aj_constroi_matriz_validados(
      registros_corrig = registros_corrig,
      schema = schema,
      somente_auditar_contrato_corrig = somente_auditar_contrato_corrig
    )
    out <- matriz_publicacao_aj$out
    auditoria <- matriz_publicacao_aj$auditoria
  } else {
    out <- data.table::as.data.table(stats::setNames(rep(list(rep("", n)), length(cols)), cols))
    auditoria <- vector("list", length(cols))
    for (ii in seq_along(cols)) {
      col_tpl <- cols[ii]
      res <- monitora_validados_derivar_ou_mapear_coluna(registros_corrig, col_tpl, schema$formato[ii], schema$largura[ii])
      novo <- monitora_validados_formatar_valor(res$valor, schema$formato[ii], schema$largura[ii])
      data.table::set(out, j = col_tpl, value = novo)
      estrategia_res <- if (is.null(res$estrategia) || is.na(res$estrategia) || !nzchar(as.character(res$estrategia)[1])) "mapeada" else as.character(res$estrategia)[1]
      auditoria[[ii]] <- data.table::data.table(
        posicao = schema$posicao[ii], atributo = col_tpl,
        coluna_origem_registros_corrig = ifelse(is.null(res$coluna) || is.na(res$coluna) || !nzchar(res$coluna), NA_character_, as.character(res$coluna)),
        estrategia = estrategia_res,
        status_mapeamento = if (any(nzchar(novo))) estrategia_res else "opcional_sem_origem_vazio",
        formato_esperado = schema$formato[ii], largura = schema$largura[ii], obrigatorio_valor = schema$obrigatorio_valor[ii],
        n_linhas_saida = n, n_vazios_saida = sum(!nzchar(novo)), n_distintos_saida = data.table::uniqueN(novo[nzchar(novo)]),
        exemplos = paste(utils::head(unique(novo[nzchar(novo)]), 5L), collapse = " | "),
        bloqueante = FALSE, motivo_bloqueio = ""
      )
    }
    data.table::setcolorder(out, cols)
    auditoria <- data.table::rbindlist(auditoria, fill = TRUE, use.names = TRUE)
  }
  if (isTRUE(somente_auditar_contrato_corrig) && exists("monitora_publicacao_ac_perf_checkpoint", mode = "function")) {
    monitora_publicacao_ac_perf_checkpoint("contrato_xlsform_matriz_mapeamento", "matriz de atributos do template construída/mapeda para auditoria de registros_corrig", out)
  }

  hora_origem <- monitora_validados_pegar(registros_corrig, c("data_hora/hora", "Horário (data_hora)", "Hora (data_hora)", "data_do_registro", "DATA DO REGISTRO", "DATA DO RECEBIMENTO"), n)
  auditoria_hora <- monitora_validados_auditar_hora_hms_millis_tz(
    original = hora_origem$valor,
    normalizado = out[["data_hora/hora"]],
    atributo = "data_hora/hora",
    coluna_origem = hora_origem$coluna
  )

  regras_xlsform21 <- monitora_validados_aplicar_regras_xlsform21(out, schema)
  out <- regras_xlsform21$out
  ajustes_xlsform21 <- regras_xlsform21$ajustes
  meta_xlsform21 <- regras_xlsform21$meta
  if (isTRUE(somente_auditar_contrato_corrig) && exists("monitora_publicacao_ac_perf_checkpoint", mode = "function")) {
    monitora_publicacao_ac_perf_checkpoint("contrato_xlsform_regras_relevance_normalizacao", "regras/relevance/normalizações XLSForm aplicadas à matriz contratual", out)
  }

  ## Recalcula métricas da auditoria de mapeamento após normalização/relevance.
  ## v2.6.1: em auditoria contratual pré-registros_corrig, a integridade depende
  ## de vazios/bloqueios. uniqueN/exemplos em 129 colunas são diagnóstico rico,
  ## mas custoso; por padrão, ficam leves nesse modo e continuam completos na
  ## exportação final sem cache, quando ela realmente precisar rodar.
  auditoria_leve_publicacao_ae <- isTRUE(somente_auditar_contrato_corrig) &&
    exists("monitora_publicacao_ae_auditoria_mapeamento_leve", mode = "function") &&
    isTRUE(monitora_publicacao_ae_auditoria_mapeamento_leve())
  for (ii in seq_len(nrow(auditoria))) {
    aa <- auditoria$atributo[ii]
    vv <- monitora_validados_limpar_ausencia_saida(out[[aa]])
    data.table::set(auditoria, i = ii, j = "n_vazios_saida", value = sum(!nzchar(vv)))
    if (isTRUE(auditoria_leve_publicacao_ae)) {
      data.table::set(auditoria, i = ii, j = "n_distintos_saida", value = NA_integer_)
      data.table::set(auditoria, i = ii, j = "exemplos", value = "[auditoria_leve_publicacao_ae; exemplos calculados apenas em bloqueios]")
    } else {
      data.table::set(auditoria, i = ii, j = "n_distintos_saida", value = data.table::uniqueN(vv[nzchar(vv)]))
      data.table::set(auditoria, i = ii, j = "exemplos", value = paste(utils::head(unique(vv[nzchar(vv)]), 5L), collapse = " | "))
    }
  }

  vazias_obrig <- auditoria[obrigatorio_valor == TRUE & n_vazios_saida > 0L]
  if (nrow(vazias_obrig)) {
    vazias_obrig[, `:=`(bloqueante = TRUE, motivo_bloqueio = "atributo_obrigatorio_vazio_apos_interpretacao")]
    auditoria[vazias_obrig, on = .(posicao, atributo), `:=`(bloqueante = TRUE, motivo_bloqueio = i.motivo_bloqueio)]
  }

  problemas_fmt <- monitora_validados_validar_formatos_saida(out, schema)
  card <- monitora_validados_auditar_cardinalidade(out)
  problemas_card <- card[status != "ok"]

  chave_dupl <- out[, .N, by = .(coleta, ponto_amostral = `amostragem/registro/ponto_amostral`)][nzchar(coleta) & nzchar(ponto_amostral) & N > 1L]
  problemas_chave <- data.table::data.table(
    tipo = character(), n_problemas = integer(), exemplos = character()
  )
  if (nrow(chave_dupl)) {
    problemas_chave <- data.table::data.table(
      tipo = "duplicidade_coleta_ponto_amostral",
      n_problemas = nrow(chave_dupl),
      exemplos = paste(utils::head(paste(chave_dupl$coleta, chave_dupl$ponto_amostral, sep = ":"), 10L), collapse = " | ")
    )
  }

  problemas_dom <- monitora_validados_validar_dominios_xlsform21(out, schema, meta_xlsform21)
  if (isTRUE(somente_auditar_contrato_corrig) && exists("monitora_publicacao_ac_perf_checkpoint", mode = "function")) {
    monitora_publicacao_ac_perf_checkpoint("contrato_xlsform_validacao_dominios", "domínios XLSForm validados por valores distintos/tokens", out)
  }
  problemas_cond <- monitora_validados_validar_condicionais_xlsform21(out)
  if (isTRUE(somente_auditar_contrato_corrig) && exists("monitora_publicacao_ac_perf_checkpoint", mode = "function")) {
    monitora_publicacao_ac_perf_checkpoint("contrato_xlsform_validacao_condicionais", "condicionais/relevance finais validadas", out)
  }
  problemas_sanitizacao_outras <- monitora_validados_auditar_sanitizacao_outras_formas(out, meta_xlsform21)
  problemas_sanitizacao_desconhecida <- monitora_validados_auditar_sanitizacao_desconhecida(out)
  if (isTRUE(somente_auditar_contrato_corrig) && exists("monitora_publicacao_ac_perf_checkpoint", mode = "function")) {
    monitora_publicacao_ac_perf_checkpoint("contrato_xlsform_validacao_sanitizacao", "sanitizações finais de outras formas/desconhecida auditadas", out)
  }

  auditoria <- monitora_privacidade_sanitizar_auditoria(auditoria)
  auditoria_hora <- monitora_privacidade_sanitizar_auditoria(auditoria_hora, mascarar_exemplos = FALSE)
  problemas_fmt <- monitora_privacidade_sanitizar_auditoria(problemas_fmt)
  problemas_dom <- monitora_privacidade_sanitizar_auditoria(problemas_dom)
  problemas_cond <- monitora_privacidade_sanitizar_auditoria(problemas_cond)
  problemas_sanitizacao_outras <- monitora_privacidade_sanitizar_auditoria(problemas_sanitizacao_outras)
  problemas_sanitizacao_desconhecida <- monitora_privacidade_sanitizar_auditoria(problemas_sanitizacao_desconhecida)
  ajustes_xlsform21 <- monitora_privacidade_sanitizar_auditoria(ajustes_xlsform21, mascarar_exemplos = FALSE)
  card <- monitora_privacidade_sanitizar_auditoria(card)
  problemas_chave <- monitora_privacidade_sanitizar_auditoria(problemas_chave)

  auditoria_contrato_corrig <- NULL
  if (exists("monitora_registros_corrig_gravar_auditoria_contrato_xlsform21", mode = "function")) {
    auditoria_contrato_corrig <- monitora_registros_corrig_gravar_auditoria_contrato_xlsform21(
      auditoria = auditoria,
      vazias_obrig = vazias_obrig,
      problemas_fmt = problemas_fmt,
      problemas_dom = problemas_dom,
      problemas_cond = problemas_cond,
      problemas_sanitizacao_outras = problemas_sanitizacao_outras,
      problemas_sanitizacao_desconhecida = problemas_sanitizacao_desconhecida,
      card = card,
      problemas_chave = problemas_chave,
      ajustes_xlsform21 = ajustes_xlsform21,
      output_dir = output_dir,
      log_dir = log_dir,
      exec_id = exec_id,
      contexto = if (isTRUE(somente_auditar_contrato_corrig)) "pre_materializacao_registros_corrig" else "assert_final_export_registros_validados"
    )
  }

  caminhos <- list(
    mapeamento_log = file.path(log_dir, paste0("auditoria_registros_validados_mapeamento_", exec_id, ".csv")),
    mapeamento_out = file.path(output_dir, "auditoria_registros_validados_mapeamento.csv"),
    formatos_log = file.path(log_dir, paste0("auditoria_registros_validados_formatos_", exec_id, ".csv")),
    hora_log = file.path(log_dir, paste0("auditoria_registros_validados_hora_", exec_id, ".csv")),
    hora_out = file.path(output_dir, "auditoria_registros_validados_hora.csv"),
    dominios_log = file.path(log_dir, paste0("auditoria_registros_validados_xlsform_dominios_", exec_id, ".csv")),
    condicionais_log = file.path(log_dir, paste0("auditoria_registros_validados_xlsform_condicionais_", exec_id, ".csv")),
    sanitizacao_outras_log = file.path(log_dir, paste0("auditoria_registros_validados_sanitizacao_outras_formas_", exec_id, ".csv")),
    sanitizacao_desconhecida_log = file.path(log_dir, paste0("auditoria_registros_validados_sanitizacao_desconhecida_", exec_id, ".csv")),
    ajustes_xlsform21_log = file.path(log_dir, paste0("auditoria_registros_validados_xlsform_ajustes_", exec_id, ".csv")),
    cardinalidade_log = file.path(log_dir, paste0("auditoria_registros_validados_uuid_cardinalidade_", exec_id, ".csv")),
    chave_log = file.path(log_dir, paste0("auditoria_registros_validados_chaves_", exec_id, ".csv")),
    resumo_log = file.path(log_dir, paste0("auditoria_registros_validados_resumo_", exec_id, ".csv")),
    resumo_out = file.path(output_dir, "auditoria_registros_validados_resumo.csv")
  )
  data.table::fwrite(auditoria, caminhos$mapeamento_log, sep = ",", quote = "auto", na = "")
  data.table::fwrite(auditoria, caminhos$mapeamento_out, sep = ",", quote = "auto", na = "")
  data.table::fwrite(problemas_fmt, caminhos$formatos_log, sep = ",", quote = "auto", na = "")
  data.table::fwrite(auditoria_hora, caminhos$hora_log, sep = ",", quote = "auto", na = "")
  data.table::fwrite(auditoria_hora, caminhos$hora_out, sep = ",", quote = "auto", na = "")
  data.table::fwrite(problemas_dom, caminhos$dominios_log, sep = ",", quote = "auto", na = "")
  data.table::fwrite(problemas_cond, caminhos$condicionais_log, sep = ",", quote = "auto", na = "")
  data.table::fwrite(problemas_sanitizacao_outras, caminhos$sanitizacao_outras_log, sep = ",", quote = "auto", na = "")
  data.table::fwrite(problemas_sanitizacao_desconhecida, caminhos$sanitizacao_desconhecida_log, sep = ",", quote = "auto", na = "")
  data.table::fwrite(ajustes_xlsform21, caminhos$ajustes_xlsform21_log, sep = ",", quote = "auto", na = "")
  data.table::fwrite(card, caminhos$cardinalidade_log, sep = ",", quote = "auto", na = "")
  data.table::fwrite(problemas_chave, caminhos$chave_log, sep = ",", quote = "auto", na = "")

  n_bloq <- nrow(vazias_obrig) + nrow(problemas_fmt) + nrow(problemas_dom) + nrow(problemas_cond) + nrow(problemas_card) + nrow(problemas_chave) + nrow(problemas_sanitizacao_outras) + nrow(problemas_sanitizacao_desconhecida)
  resumo <- data.table::data.table(
    exec_id = as.character(exec_id), produto = "registros_validados.csv",
    schema = "Contrato XLSForm/SISMONITORA 2025 (21FEV25)",
    n_linhas_registros_corrig = nrow(registros_corrig), n_linhas_saida = nrow(out),
    n_colunas_schema = length(cols), n_colunas_saida = ncol(out),
    n_colunas_mapeadas_ou_derivadas = auditoria[n_vazios_saida < n_linhas_saida, .N],
    n_colunas_opcionais_vazias = auditoria[n_vazios_saida == n_linhas_saida & obrigatorio_valor == FALSE, .N],
    n_ajustes_xlsform21 = if (nrow(ajustes_xlsform21)) sum(ajustes_xlsform21$n_ajustes) else 0L,
    n_linhas_sanitizacao_outras_formas_pendente = nrow(problemas_sanitizacao_outras),
    n_linhas_sanitizacao_desconhecida_pendente = nrow(problemas_sanitizacao_desconhecida),
    n_bloqueios_formatos = nrow(problemas_fmt),
    n_hora_total = auditoria_hora$n_total[1],
    n_hora_vazios = auditoria_hora$n_vazios[1],
    n_hora_normalizados = auditoria_hora$n_normalizados[1],
    n_hora_alterados_pela_normalizacao = auditoria_hora$n_alterados_pela_normalizacao[1],
    n_hora_incompativeis = auditoria_hora$n_incompativeis[1],
    n_bloqueios_dominios_xlsform21 = nrow(problemas_dom),
    n_bloqueios_condicionais_xlsform21 = nrow(problemas_cond),
    n_bloqueios_sanitizacao_outras_formas = as.integer(nrow(problemas_sanitizacao_outras) > 0L),
    n_bloqueios_sanitizacao_desconhecida = nrow(problemas_sanitizacao_desconhecida),
    n_bloqueios = n_bloq,
    auditoria_mapeamento = monitora_privacidade_caminho_relativo(caminhos$mapeamento_log),
    auditoria_formatos = monitora_privacidade_caminho_relativo(caminhos$formatos_log),
    auditoria_hora = monitora_privacidade_caminho_relativo(caminhos$hora_log),
    auditoria_dominios_xlsform21 = monitora_privacidade_caminho_relativo(caminhos$dominios_log),
    auditoria_condicionais_xlsform21 = monitora_privacidade_caminho_relativo(caminhos$condicionais_log),
    auditoria_sanitizacao_outras_formas = monitora_privacidade_caminho_relativo(caminhos$sanitizacao_outras_log),
    auditoria_sanitizacao_desconhecida = monitora_privacidade_caminho_relativo(caminhos$sanitizacao_desconhecida_log),
    auditoria_ajustes_xlsform21 = monitora_privacidade_caminho_relativo(caminhos$ajustes_xlsform21_log),
    auditoria_cardinalidade = monitora_privacidade_caminho_relativo(caminhos$cardinalidade_log),
    timestamp = format(Sys.time(), "%Y-%m-%d %H:%M:%S")
  )
  data.table::fwrite(resumo, caminhos$resumo_log, sep = ",", quote = "auto", na = "")
  data.table::fwrite(resumo, caminhos$resumo_out, sep = ",", quote = "auto", na = "")

  ### v2.6.1: modo de auditoria contratual de registros_corrig. Nesta chamada,
  ### o exportador monta a mesma matriz que alimentará registros_validados.csv,
  ### grava as auditorias e bloqueia antes da materialização de registros_corrig
  ### caso algum atributo do template 21FEV25 esteja inválido.
  if (isTRUE(somente_auditar_contrato_corrig)) {
    if (n_bloq > 0L) {
      msg <- paste0(
        "registros_corrig.csv bloqueado: ", n_bloq,
        " problema(s) bloqueante(s) nos atributos que alimentam registros_validados.csv após sanitização pós-painel e regras XLSForm 21FEV25. ",
        if (nrow(problemas_sanitizacao_outras) > 0L) "Há resíduos de outra forma de vida de versões antigas sem sanitização prévia. " else "",
        if (nrow(problemas_sanitizacao_desconhecida) > 0L) "Há foto/descritor de forma de vida desconhecida preenchido sem token desconhecida na categoria correspondente. " else "",
        "Auditorias: ",
        caminhos$mapeamento_log, "; ", caminhos$formatos_log, "; ", caminhos$hora_log, "; ", caminhos$dominios_log, "; ", caminhos$condicionais_log, "; ", caminhos$sanitizacao_outras_log, "; ", caminhos$sanitizacao_desconhecida_log, "; ", caminhos$cardinalidade_log,
        "; contrato registros_corrig: ", file.path(log_dir, paste0("auditoria_registros_corrig_contrato_xlsform21_", exec_id, ".csv"))
      )
      bloq <- tryCatch(monitora_registros_validados_gravar_bloqueios(
        resumo = resumo,
        vazias_obrig = vazias_obrig,
        problemas_fmt = problemas_fmt,
        problemas_dom = problemas_dom,
        problemas_cond = problemas_cond,
        problemas_sanitizacao_outras = problemas_sanitizacao_outras,
        problemas_sanitizacao_desconhecida = problemas_sanitizacao_desconhecida,
        card = card,
        problemas_chave = problemas_chave,
        mensagem = msg,
        contexto = "auditoria_contrato_corrig_bloqueio_registros_validados",
        output_dir = output_dir,
        log_dir = log_dir,
        exec_id = exec_id
      ), error = function(e) data.table::data.table())
      assign("MONITORA_REGISTROS_CORRIG_CONTRATO_VALIDADO_XLSFORM21", FALSE, envir = .GlobalEnv)
      assign("MONITORA_REGISTROS_CORRIG_CONTRATO_CONTEXTO", "sem_pendencias_impeditivas_mas_bloqueio_registros_validados", envir = .GlobalEnv)
      warning(msg, call. = FALSE)
      return(invisible(list(auditoria = auditoria, resumo = resumo, contrato_registros_corrig = auditoria_contrato_corrig, bloqueios_registros_validados = bloq)))
    }
    assinatura_cache <- if (exists("monitora_publicacao_z_assinatura_registros_corrig", mode = "function")) {
      tryCatch(monitora_publicacao_z_assinatura_registros_corrig(registros_corrig), error = function(e) NA_character_)
    } else NA_character_
    assign("MONITORA_REGISTROS_CORRIG_CONTRATO_VALIDADO_XLSFORM21", TRUE, envir = .GlobalEnv)
    assign("MONITORA_REGISTROS_VALIDADOS_CACHE_PRE_CONTRATO", list(
      assinatura_registros_corrig = assinatura_cache,
      out = data.table::copy(out),
      auditoria = list(auditoria = auditoria, resumo = resumo, contrato_registros_corrig = auditoria_contrato_corrig),
      timestamp = format(Sys.time(), "%Y-%m-%d %H:%M:%S")
    ), envir = .GlobalEnv)
    if (exists("monitora_log_registrar_evento", mode = "function")) {
      monitora_log_registrar_evento("registros_corrig_contrato_aprovado", "INFO", caminhos$resumo_log, paste0("registros_corrig aprovado no Contrato XLSForm/SISMONITORA 2025 antes da materialização; bloqueios=0; atributos=", length(cols)), "v2.5.4 pre-materializacao")
    }
    return(invisible(list(auditoria = auditoria, resumo = resumo, contrato_registros_corrig = auditoria_contrato_corrig)))
  }

  if (n_bloq > 0L) {
    msg <- paste0(
      "registros_validados.csv bloqueado: ", n_bloq,
      " problema(s) bloqueante(s) após interpretação de registros_corrig e regras XLSForm 21FEV25. ",
      if (nrow(problemas_sanitizacao_outras) > 0L) "Há resíduos de outra forma de vida de versões antigas sem sanitização prévia. " else "",
      if (nrow(problemas_sanitizacao_desconhecida) > 0L) "Há foto/descritor de forma de vida desconhecida preenchido sem token desconhecida na categoria correspondente. " else "",
      "Auditorias: ",
      caminhos$mapeamento_log, "; ", caminhos$formatos_log, "; ", caminhos$hora_log, "; ", caminhos$dominios_log, "; ", caminhos$condicionais_log, "; ", caminhos$sanitizacao_outras_log, "; ", caminhos$sanitizacao_desconhecida_log, "; ", caminhos$cardinalidade_log
    )
    bloq <- tryCatch(monitora_registros_validados_gravar_bloqueios(
      resumo = resumo,
      vazias_obrig = vazias_obrig,
      problemas_fmt = problemas_fmt,
      problemas_dom = problemas_dom,
      problemas_cond = problemas_cond,
      problemas_sanitizacao_outras = problemas_sanitizacao_outras,
      problemas_sanitizacao_desconhecida = problemas_sanitizacao_desconhecida,
      card = card,
      problemas_chave = problemas_chave,
      mensagem = msg,
      contexto = "bloqueio_exportacao_registros_validados",
      output_dir = output_dir,
      log_dir = log_dir,
      exec_id = exec_id
    ), error = function(e) data.table::data.table())
    assign("MONITORA_REGISTROS_VALIDADOS_GERADO", FALSE, envir = .GlobalEnv)
    warning(msg, call. = FALSE)
    return(invisible(list(auditoria = auditoria, resumo = resumo, bloqueios_registros_validados = bloq)))
  }

  caminho_saida <- if (exists("monitora_produtos_path_canonico", mode = "function")) {
      monitora_produtos_path_canonico("registros_validados.csv", output_dir)
    } else {
      file.path(output_dir, "01_produtos_dados", "registros_validados.csv")
    }
    dir.create(dirname(caminho_saida), recursive = TRUE, showWarnings = FALSE)
  data.table::fwrite(out, caminho_saida, sep = ",", quote = "auto", na = "", bom = FALSE)
  header_saida <- names(data.table::fread(caminho_saida, sep = ",", nrows = 0, encoding = "UTF-8", check.names = FALSE, showProgress = FALSE, data.table = TRUE))
  if (!identical(header_saida, cols)) {
    stop("Cabeçalho de registros_validados.csv difere do schema SISMONITORA embutido; exportação bloqueada.", call. = FALSE)
  }
  MONITORA_REGISTROS_VALIDADOS_GERADO <<- TRUE
  MONITORA_REGISTROS_VALIDADOS_ULTIMA_AUDITORIA <<- list(produto = caminho_saida, auditoria = auditoria, resumo = resumo, contrato_registros_corrig = auditoria_contrato_corrig)
  if (exists("monitora_log_registrar_evento", mode = "function")) {
    monitora_log_registrar_evento("registros_validados_exportado", "INFO", caminho_saida, paste0("registros_validados.csv gerado com ", nrow(out), " linhas e ", ncol(out), " colunas"), "schema embutido; entrada=registros_corrig")
  }
  invisible(MONITORA_REGISTROS_VALIDADOS_ULTIMA_AUDITORIA)
}

}
### Fim da exportação opcional: registros_validados.csv ---------------------



### v2.6.1 -------------------------------------------------------------
### Permite preservar o trabalho do bolsista como checkpoint quando ainda houver
### pendências impeditivas. Essas pendências bloqueiam registros_validados.csv e
### produtos finais, mas não impedem a gravação marcada de registros_corrig.csv.
if (!exists("MONITORA_PERMITIR_REGISTROS_CORRIG_CHECKPOINT_PENDENTE", inherits = FALSE)) MONITORA_PERMITIR_REGISTROS_CORRIG_CHECKPOINT_PENDENTE <- TRUE

### Auditoria de pendências impeditivas para registros_corrig.csv.
### Regra operacional consolidada:
### - registros_corrig.csv pode ser materializado como checkpoint de trabalho;
### - se houver pendências impeditivas, o arquivo recebe selo/flags explícitos;
### - registros_validados.csv e produtos finais contratuais não são liberados;
### - nenhuma dessas pendências é saneada automaticamente no fechamento.
monitora_publicacao_ab_coluna_segura <- function(dt, col) {
  if (is.null(col) || is.na(col) || !nzchar(as.character(col)[1L]) || !(as.character(col)[1L] %in% names(dt))) return(rep(NA_character_, nrow(dt)))
  as.character(dt[[as.character(col)[1L]]])
}

monitora_publicacao_ab_tem_forma_categoria <- function(dt, categoria) {
  cols <- tryCatch(monitora_correcao_colunas_forma_vida_categoria(dt, categoria), error = function(e) character(0))
  cols <- unique(cols[!is.na(cols) & nzchar(cols) & cols %in% names(dt)])
  if (!length(cols)) return(rep(FALSE, nrow(dt)))
  out <- rep(FALSE, nrow(dt))
  for (cc in cols) out <- out | !monitora_correcao_vazio_vec(dt[[cc]])
  out[is.na(out)] <- FALSE
  out
}

monitora_publicacao_ab_auditar_pendencias_impeditivas_complementares_101_encostam <- function(dt, contexto = "pre_registros_corrig") {
  if (!requireNamespace("data.table", quietly = TRUE)) return(data.table::data.table())
  dt <- data.table::as.data.table(dt)
  if (!nrow(dt)) return(data.table::data.table())
  rotulos <- c(
    atributo_101_nao_resolvido             = "Atributo 101 não resolvido",
    atributo_101_alias_conflitante         = "Atributo 101 com aliases conflitantes",
    cadastro_uc_ausente_ou_invalida        = "Cadastro UC ausente ou inválida",
    cadastro_ea_ausente_ou_invalida        = "Cadastro EA ausente ou inválida",
    cadastro_ua_ausente_ou_invalida        = "Cadastro UA ausente ou inválida",
    cadastro_ciclo_ausente_ou_invalido     = "Cadastro ciclo ausente ou inválido",
    cadastro_campanha_ausente_ou_invalida  = "Cadastro campanha ausente ou inválida",
    atributo_101_formato_invalido          = "Atributo 101 com formato inválido",
    atributo_101_valor_fora_dominio        = "Atributo 101 com valor fora do domínio",
    encostam_desatualizado                 = "Encostam desatualizado",
    encostam_token_sem_inferior            = "Encostam: token sem inferior correspondente",
    encostam_inferior_sem_token            = "Encostam: inferior sem token",
    encostam_solo_nu_conflitante           = "Encostam: solo nu conflitante",
    encostam_token_desconhecido            = "Encostam: token desconhecido",
    encostam_desconhecida_superior_only    = "Encostam: desconhecida superior-only",
    encostam_outra_forma_vida              = "Encostam: outra forma de vida",
    encostam_coluna_nao_resolvida          = "Encostam: coluna não resolvida"
  )
  normalizar_pend <- function(aud, ctx) {
    aud <- data.table::as.data.table(aud)
    if (!("severidade" %in% names(aud))) return(data.table::data.table())
    aud <- aud[severidade == "impeditiva"]
    if (!nrow(aud)) return(data.table::data.table())
    obter <- function(col) if (col %in% names(aud)) as.character(aud[[col]]) else rep(NA_character_, nrow(aud))
    lin <- if ("linha" %in% names(aud)) suppressWarnings(as.integer(aud[["linha"]])) else rep(NA_integer_, nrow(aud))
    tp  <- as.character(aud[["tipo_pendencia"]])
    rot <- rotulos[tp]
    rot[is.na(rot)] <- tp[is.na(rot)]
    atr <- if ("coluna_materializada" %in% names(aud)) obter("coluna_materializada") else if ("coluna_encostam" %in% names(aud)) obter("coluna_encostam") else rep(NA_character_, nrow(aud))
    enc <- if ("valor_atual" %in% names(aud)) obter("valor_atual") else rep(NA_character_, nrow(aud))
    corr <- if ("corrigivel_no_painel" %in% names(aud)) as.logical(aud[["corrigivel_no_painel"]]) else rep(NA, nrow(aud))
    data.table::data.table(
      contexto            = ctx,
      severidade          = as.character(aud[["severidade"]]),
      tipo_pendencia      = tp,
      rotulo_pendencia    = unname(rot),
      linha_indice        = lin,
      COLETA              = obter("COLETA"),
      UC                  = obter("UC"),
      EA                  = obter("EA"),
      UA                  = obter("UA"),
      ANO                 = rep(NA_character_, nrow(aud)),
      CICLO               = obter("CICLO"),
      CAMPANHA            = obter("CAMPANHA"),
      ponto_amostral      = rep(NA_character_, nrow(aud)),
      atributo            = atr,
      Encostam            = enc,
      mensagem            = obter("mensagem"),
      corrigivel_no_painel = corr,
      acao_sugerida       = obter("acao_sugerida")
    )
  }
  pend <- list()
  if (exists("monitora_registros_corrig_auditar_atributos_101", mode = "function")) {
    aud101 <- tryCatch(
      monitora_registros_corrig_auditar_atributos_101(data.table::copy(dt)),
      error = function(e) data.table::data.table()
    )
    if (data.table::is.data.table(aud101) && nrow(aud101)) {
      norm101 <- normalizar_pend(aud101, contexto)
      if (nrow(norm101)) pend[[length(pend) + 1L]] <- norm101
    }
  }
  if (exists("monitora_registros_corrig_auditar_encostam_derivado", mode = "function")) {
    aud_enc <- tryCatch(
      monitora_registros_corrig_auditar_encostam_derivado(data.table::copy(dt)),
      error = function(e) data.table::data.table()
    )
    if (data.table::is.data.table(aud_enc) && nrow(aud_enc)) {
      norm_enc <- normalizar_pend(aud_enc, contexto)
      if (nrow(norm_enc)) pend[[length(pend) + 1L]] <- norm_enc
    }
  }
  if (!length(pend)) return(data.table::data.table())
  data.table::rbindlist(pend, fill = TRUE, use.names = TRUE)
}

monitora_publicacao_ab_auditar_pendencias_impeditivas <- function(dt,
                                                                  contexto = "pre_registros_corrig",
                                                                  output_dir = get0("MONITORA_OUTPUT_DIR", ifnotfound = "output", inherits = TRUE),
                                                                  log_dir = get0("MONITORA_LOG_DIR", ifnotfound = "log", inherits = TRUE),
                                                                  gravar = TRUE,
                                                                  marcar_base = TRUE) {
  if (!requireNamespace("data.table", quietly = TRUE)) stop("Pacote data.table é obrigatório para auditar pendências impeditivas.", call. = FALSE)
  dt <- data.table::as.data.table(dt)
  n <- nrow(dt)
  chaves <- tryCatch(monitora_correcao_colunas_chave(dt), error = function(e) list())
  get_col <- function(nm) {
    val <- chaves[[nm]]
    if (is.null(val) || is.na(val) || !nzchar(as.character(val)[1L]) || !(as.character(val)[1L] %in% names(dt))) return(rep(NA_character_, n))
    as.character(dt[[as.character(val)[1L]]])
  }
  coleta <- get_col("coleta")
  uc <- get_col("uc")
  ea <- get_col("ea")
  ua <- get_col("ua")
  ano <- get_col("ano")
  ciclo <- get_col("ciclo")
  campanha <- get_col("campanha")
  ponto <- get_col("ponto_amostral")
  tipo_col <- chaves[["tipo_forma_vida"]]
  tipo <- if (!is.null(tipo_col) && !is.na(tipo_col) && nzchar(as.character(tipo_col)[1L]) && as.character(tipo_col)[1L] %in% names(dt)) as.character(dt[[as.character(tipo_col)[1L]]]) else rep(NA_character_, n)

  issues <- list()
  add_issue <- function(tipo_pendencia, rotulo, mask, mensagem, atributo = NA_character_, severidade = "impeditiva") {
    mask <- as.logical(mask)
    mask[is.na(mask)] <- FALSE
    if (length(mask) != n) mask <- rep(FALSE, n)
    idx <- which(mask)
    if (!length(idx)) return(invisible(NULL))
    issues[[length(issues) + 1L]] <<- data.table::data.table(
      contexto = contexto,
      severidade = severidade,
      tipo_pendencia = tipo_pendencia,
      rotulo_pendencia = rotulo,
      linha_indice = idx,
      COLETA = coleta[idx],
      UC = uc[idx],
      EA = ea[idx],
      UA = ua[idx],
      ANO = ano[idx],
      CICLO = ciclo[idx],
      CAMPANHA = campanha[idx],
      ponto_amostral = ponto[idx],
      atributo = atributo,
      Encostam = tipo[idx],
      mensagem = mensagem
    )
    invisible(NULL)
  }

  ### UAs duplicadas: múltiplas COLETAS no mesmo conjunto UC+UA+ANO.
  if (n && all(!vapply(list(uc, ua, ano, coleta), function(x) all(is.na(x)), logical(1)))) {
    aux <- data.table::data.table(linha_indice = seq_len(n), UC = uc, UA = ua, ANO = ano, COLETA = coleta)
    aux <- aux[!is.na(UC) & nzchar(UC) & !is.na(UA) & nzchar(UA) & !is.na(ANO) & nzchar(ANO) & !is.na(COLETA) & nzchar(COLETA)]
    if (nrow(aux)) {
      grupos_dup <- aux[, .(n_coletas = data.table::uniqueN(COLETA)), by = .(UC, UA, ANO)][n_coletas > 1L]
      if (nrow(grupos_dup)) {
        idx_dup <- aux[grupos_dup, on = .(UC, UA, ANO), linha_indice]
        mask_dup <- rep(FALSE, n); mask_dup[idx_dup] <- TRUE
        add_issue(
          "uas_duplicadas_mesmo_ano",
          "UAs duplicadas no mesmo ano",
          mask_dup,
          "Há múltiplas COLETAS para a mesma UC+UA+ANO; resolver por exclusão/correção assistida antes de considerar registros_corrig final.",
          atributo = "UC+UA+ANO+COLETA"
        )
      }
    }
  }

  ### Ponto sem interceptação: campo superior Encostam/tipo_forma_vida vazio.
  add_issue(
    "ponto_sem_interceptacao",
    "Ponto amostral sem interceptação",
    monitora_correcao_vazio_vec(tipo),
    "Ponto sem categoria de interceptação em Encostam/tipo_forma_vida; corrigir a partir do registro original ou excluir a COLETA.",
    atributo = ifelse(is.null(tipo_col), NA_character_, as.character(tipo_col)[1L])
  )


  tem_token <- function(tokens) {
    if (all(is.na(tipo))) return(rep(FALSE, n))
    tryCatch(monitora_relatorio_exoticas_tem_token(tipo, tokens), error = function(e) rep(FALSE, n))
  }
  forma_nativa <- monitora_publicacao_ab_tem_forma_categoria(dt, "nativa")
  forma_exotica <- monitora_publicacao_ab_tem_forma_categoria(dt, "exotica")
  forma_seca <- monitora_publicacao_ab_tem_forma_categoria(dt, "seca_morta")

  add_issue(
    "nativa_sem_forma_vida",
    "Nativa sem forma de vida",
    tem_token(c("nativa", "nativas", "nativo", "nativos")) & !forma_nativa,
    "Encostam contém nativa, mas não há forma de vida nativa correspondente; conferir planilha original e corrigir a forma de vida ou excluir a COLETA.",
    atributo = "forma_vida_nativa"
  )
  add_issue(
    "exotica_sem_forma_vida",
    "Exótica sem forma de vida",
    tem_token(c("exotica", "exoticas", "exotico", "exoticos")) & !forma_exotica,
    "Encostam contém exotica, mas não há forma de vida exótica correspondente; conferir planilha original e corrigir a forma de vida ou excluir a COLETA.",
    atributo = "forma_vida_exotica"
  )
  add_issue(
    "seca_morta_sem_forma_vida",
    "Seca ou morta sem forma de vida",
    tem_token(c("seca_morta", "seca", "secas", "seco", "secos", "morta", "mortas", "morto", "mortos")) & !forma_seca,
    "Encostam contém seca_morta/seca/morta, mas não há forma de vida seca ou morta correspondente; conferir planilha original e corrigir a forma de vida ou excluir a COLETA.",
    atributo = "forma_vida_seca_morta"
  )

  ### Resíduos históricos de outra forma de vida: não sanitizar automaticamente.
  cols_info <- tryCatch(monitora_correcao_colunas_limpeza_outras_formas(dt, NULL), error = function(e) data.table::data.table())
  mask_outra <- rep(FALSE, n)
  cols_outra <- character(0)
  if (nrow(cols_info)) {
    tokens_outra <- tryCatch(monitora_correcao_tokens_residuo_historico_outras_formas(), error = function(e) c("outra_forma_vida", "outras_formas_vida", "outra", "outro", "outras", "outros"))
    listas <- cols_info[classe == "lista_principal_forma_vida" & coluna %in% names(dt), unique(coluna)]
    descritores <- cols_info[classe == "descritor_outra_forma_vida" & coluna %in% names(dt), unique(coluna)]
    fotos <- cols_info[classe == "foto_outra_forma_vida" & coluna %in% names(dt), unique(coluna)]
    for (cc in listas) {
      hit <- tryCatch(monitora_correcao_contem_qualquer_token_vec(dt[[cc]], tokens_outra), error = function(e) rep(FALSE, n))
      hit[is.na(hit)] <- FALSE
      if (any(hit)) cols_outra <- c(cols_outra, cc)
      mask_outra <- mask_outra | hit
    }
    for (cc in unique(c(descritores, fotos))) {
      hit <- !monitora_correcao_vazio_vec(dt[[cc]])
      hit[is.na(hit)] <- FALSE
      if (any(hit)) cols_outra <- c(cols_outra, cc)
      mask_outra <- mask_outra | hit
    }
  }
  add_issue(
    "outra_forma_vida",
    "Outra forma de vida",
    mask_outra,
    "Há resíduo histórico de outra forma de vida; aplicar sanitização assistida no painel ou corrigir manualmente antes de considerar registros_corrig final.",
    atributo = paste(unique(cols_outra), collapse = " | ")
  )

  comp_101_enc <- tryCatch(
    monitora_publicacao_ab_auditar_pendencias_impeditivas_complementares_101_encostam(dt, contexto = contexto),
    error = function(e) data.table::data.table()
  )
  if (data.table::is.data.table(comp_101_enc) && nrow(comp_101_enc)) {
    issues[[length(issues) + 1L]] <- comp_101_enc
  }

  audit <- if (length(issues)) data.table::rbindlist(issues, fill = TRUE, use.names = TRUE) else data.table::data.table(
    contexto = character(), severidade = character(), tipo_pendencia = character(), rotulo_pendencia = character(), linha_indice = integer(),
    COLETA = character(), UC = character(), EA = character(), UA = character(), ANO = character(), CICLO = character(), CAMPANHA = character(),
    ponto_amostral = character(), atributo = character(), Encostam = character(), mensagem = character()
  )
  if (nrow(audit)) {
    audit[, COLETA := as.character(COLETA)]
    audit[, chave_linha := paste(tipo_pendencia, linha_indice, sep = "::")]
    audit <- unique(audit, by = "chave_linha")
    audit[, chave_linha := NULL]
  }
  resumo <- if (nrow(audit)) {
    audit[, .(
      n_linhas = .N,
      n_coletas = data.table::uniqueN(COLETA[!is.na(COLETA) & nzchar(COLETA)]),
      coletas_exemplo = paste(utils::head(unique(COLETA[!is.na(COLETA) & nzchar(COLETA)]), 20L), collapse = " | "),
      mensagem = mensagem[1L]
    ), by = .(contexto, severidade, tipo_pendencia, rotulo_pendencia)][order(tipo_pendencia)]
  } else {
    data.table::data.table(contexto = contexto, severidade = character(), tipo_pendencia = character(), rotulo_pendencia = character(), n_linhas = integer(), n_coletas = integer(), coletas_exemplo = character(), mensagem = character())
  }

  if (isTRUE(marcar_base)) {
    status_val <- if (nrow(audit)) "corrigido_com_pendencias_impeditivas" else "corrigido_sem_pendencias_impeditivas"
    data.table::set(dt, j = "monitora_status_registros_corrig", value = rep(status_val, n))
    data.table::set(dt, j = "monitora_pendencia_impeditiva", value = rep(FALSE, n))
    data.table::set(dt, j = "monitora_pendencia_impeditiva_tipo", value = rep("", n))
    data.table::set(dt, j = "monitora_pendencia_impeditiva_msg", value = rep("", n))
    if (nrow(audit)) {
      por_linha <- audit[, .(
        tipo = paste(unique(tipo_pendencia), collapse = " | "),
        msg = paste(unique(mensagem), collapse = " | ")
      ), by = linha_indice]
      idx <- por_linha$linha_indice
      data.table::set(dt, i = idx, j = "monitora_pendencia_impeditiva", value = TRUE)
      data.table::set(dt, i = idx, j = "monitora_pendencia_impeditiva_tipo", value = por_linha$tipo)
      data.table::set(dt, i = idx, j = "monitora_pendencia_impeditiva_msg", value = por_linha$msg)
    }
  }

  if (isTRUE(gravar)) {
    dir.create(output_dir, recursive = TRUE, showWarnings = FALSE)
    dir.create(log_dir, recursive = TRUE, showWarnings = FALSE)
    arq_aud <- file.path(output_dir, "auditoria_pendencias_impeditivas_registros_corrig.csv")
    arq_res <- file.path(output_dir, "resumo_pendencias_impeditivas_registros_corrig.csv")
    data.table::fwrite(audit, arq_aud, na = "")
    data.table::fwrite(resumo, arq_res, na = "")
    exec_id <- get0("MONITORA_EXEC_ID", ifnotfound = format(Sys.time(), "%Y%m%d_%H%M%S"), inherits = TRUE)
    try(data.table::fwrite(audit, file.path(log_dir, paste0("auditoria_pendencias_impeditivas_registros_corrig_", exec_id, ".csv")), na = ""), silent = TRUE)
    try(data.table::fwrite(resumo, file.path(log_dir, paste0("resumo_pendencias_impeditivas_registros_corrig_", exec_id, ".csv")), na = ""), silent = TRUE)
  }

  assign("MONITORA_REGISTROS_CORRIG_PENDENCIAS_IMPEDITIVAS", nrow(audit) > 0L, envir = .GlobalEnv)
  assign("MONITORA_REGISTROS_CORRIG_PENDENCIAS_IMPEDITIVAS_AUDITORIA", audit, envir = .GlobalEnv)
  assign("MONITORA_REGISTROS_CORRIG_PENDENCIAS_IMPEDITIVAS_RESUMO", resumo, envir = .GlobalEnv)
  invisible(list(auditoria = audit, resumo = resumo, n_pendencias = nrow(audit), dt = dt))
}

monitora_publicacao_ab_logar_resumo_pendencias <- function(resumo, contexto = "registros_corrig") {
  resumo <- tryCatch(data.table::as.data.table(resumo), error = function(e) data.table::data.table())
  if (!nrow(resumo)) return(invisible(NULL))
  msg <- paste(paste0(resumo$rotulo_pendencia, ": ", resumo$n_coletas, " coleta(s), ", resumo$n_linhas, " linha(s)"), collapse = "; ")
  if (exists("monitora_publicacao_g_log", mode = "function")) {
    monitora_publicacao_g_log("ATENÇÃO: registros_corrig.csv será/foi tratado como checkpoint com pendências impeditivas [", contexto, "]: ", msg)
  } else if (exists("monitora_correcao_console_msg", mode = "function")) {
    monitora_correcao_console_msg("ATENÇÃO: registros_corrig.csv será/foi tratado como checkpoint com pendências impeditivas [", contexto, "]: ", msg)
  } else {
    message("ATENÇÃO: registros_corrig.csv com pendências impeditivas [", contexto, "]: ", msg)
  }
  invisible(NULL)
}
### FIM v2.6.1 ---------------------------------------------------------




### v2.6.1 -------------------------------------------------------------
### Auditoria cadastral não bloqueante com sanitização automática inequívoca.
### Escopo: valores aparentemente deslocados entre campos cadastrais. Regras
### seguras são aplicadas diretamente em registros_corrig; demais ocorrências
### geram relatório de alerta, mas não bloqueiam registros_corrig.csv nem
### registros_validados.csv.
monitora_publicacao_ac_sanitizar_cadastro_nao_bloqueante <- function(dt,
                                                                    contexto = "fechamento_registros_corrig",
                                                                    output_dir = get0("MONITORA_OUTPUT_DIR", ifnotfound = "output", inherits = TRUE),
                                                                    log_dir = get0("MONITORA_LOG_DIR", ifnotfound = output_dir, inherits = TRUE),
                                                                    exec_id = get0("MONITORA_EXEC_ID", ifnotfound = format(Sys.time(), "%Y%m%d_%H%M%S"), inherits = TRUE)) {
  if (!inherits(dt, c("data.frame", "data.table"))) return(invisible(list(dt = dt, auditoria = data.table::data.table(), ocorrencias = data.table::data.table())))
  if (!requireNamespace("data.table", quietly = TRUE)) return(invisible(list(dt = dt, auditoria = data.table::data.table(), ocorrencias = data.table::data.table())))
  dt <- data.table::as.data.table(dt)
  n <- nrow(dt)
  if (!n) return(invisible(list(dt = dt, auditoria = data.table::data.table(), ocorrencias = data.table::data.table())))

  col1 <- function(cands) {
    cc <- cands[cands %in% names(dt)]
    if (length(cc)) cc[1L] else NA_character_
  }
  chr <- function(col) {
    if (is.na(col) || !(col %in% names(dt))) rep("", n) else {
      x <- as.character(dt[[col]])
      x[is.na(x)] <- ""
      trimws(x)
    }
  }
  norm <- function(x) {
    x <- as.character(x); x[is.na(x)] <- ""; trimws(x)
  }
  ano_rx <- function(x, rx) {
    x <- norm(x)
    out <- rep(NA_character_, length(x))
    ok <- grepl(rx, x, perl = TRUE)
    out[ok] <- sub(rx, "\\1", x[ok], perl = TRUE)
    out
  }
  empty_dt <- function() data.table::data.table(
    exec_id = character(), contexto = character(), linha_indice = integer(), COLETA = character(), UC = character(),
    CICLO_antes = character(), CICLO_depois = character(), CAMPANHA_antes = character(), CAMPANHA_depois = character(),
    EA_antes = character(), EA_depois = character(), UA_antes = character(), UA_depois = character(),
    atributo_corrigido = character(), valor_original = character(), valor_corrigido = character(), regra_aplicada = character(), acao = character()
  )
  empty_occ <- function() data.table::data.table(
    exec_id = character(), contexto = character(), linha_indice = integer(), COLETA = character(), UC = character(), CICLO = character(), CAMPANHA = character(), EA = character(), UA = character(),
    Data = character(), ANO = character(), form_veg = character(), atributo = character(), valor_observado = character(), padrao_detectado = character(),
    atributo_ao_qual_parece_pertencer = character(), severidade = character(), acao_sugerida = character(), motivo_nao_corrigido = character(), bloqueia_produto = logical()
  )

  c_coleta <- col1(c("COLETA", "coleta", "coleta_uuid"))
  c_uc <- col1(c("UC", "uc"))
  c_ciclo <- col1(c("CICLO", "ciclo"))
  c_campanha <- col1(c("CAMPANHA", "campanha"))
  c_ea <- col1(c("EA", "ea"))
  c_ua <- col1(c("UA", "ua"))
  c_data <- col1(c("Data (data_hora)", "data_hora/data", "DATA_MONITORA_PARSEADA", "data"))
  c_ano <- col1(c("ANO", "ano"))
  c_form <- col1(c("form_veg", "FORM_VEG", "formacao_vegetal"))

  rx_ciclo <- "^Ciclo-([0-9]{4})_VgCS$"
  rx_camp <- "^Campanha-([0-9]{4})_VgCS$"
  rx_ea <- "^EA-[0-9]{3}_Cps$"
  rx_ua <- "^UA-[0-9]{3}_VgCS$"
  rx_any_ciclo <- "^Ciclo-[0-9]{4}_VgCS$"
  rx_any_camp <- "^Campanha-[0-9]{4}_VgCS$"

  add_audit <- function(idx, atributo, antes, depois, regra) {
    idx <- as.integer(idx[!is.na(idx) & idx >= 1L & idx <= n])
    if (!length(idx)) return(empty_dt())
    data.table::data.table(
      exec_id = as.character(exec_id), contexto = as.character(contexto)[1L], linha_indice = idx,
      COLETA = chr(c_coleta)[idx], UC = chr(c_uc)[idx],
      CICLO_antes = ciclo0[idx], CICLO_depois = chr(c_ciclo)[idx],
      CAMPANHA_antes = campanha0[idx], CAMPANHA_depois = chr(c_campanha)[idx],
      EA_antes = ea0[idx], EA_depois = chr(c_ea)[idx],
      UA_antes = ua0[idx], UA_depois = chr(c_ua)[idx],
      atributo_corrigido = atributo, valor_original = as.character(antes)[idx], valor_corrigido = as.character(depois)[idx],
      regra_aplicada = regra, acao = "sanitizado_automaticamente"
    )
  }

  ciclo0 <- chr(c_ciclo); campanha0 <- chr(c_campanha); ea0 <- chr(c_ea); ua0 <- chr(c_ua)
  aud <- empty_dt()

  if (!is.na(c_ciclo) && !is.na(c_campanha)) {
    # Regra C: ciclo e campanha trocados, anos coincidentes.
    ano_ciclo_como_camp <- ano_rx(ciclo0, rx_camp)
    ano_camp_como_ciclo <- ano_rx(campanha0, rx_ciclo)
    idx <- which(!is.na(ano_ciclo_como_camp) & !is.na(ano_camp_como_ciclo) & ano_ciclo_como_camp == ano_camp_como_ciclo)
    if (length(idx)) {
      novo_ciclo <- paste0("Ciclo-", ano_ciclo_como_camp, "_VgCS")
      novo_camp <- paste0("Campanha-", ano_ciclo_como_camp, "_VgCS")
      aud <- data.table::rbindlist(list(aud, add_audit(idx, "CICLO", ciclo0, novo_ciclo, "ciclo_campanha_trocados_mesmo_ano")), fill = TRUE)
      data.table::set(dt, i = idx, j = c_ciclo, value = novo_ciclo[idx])
      aud <- data.table::rbindlist(list(aud, add_audit(idx, "CAMPANHA", campanha0, novo_camp, "ciclo_campanha_trocados_mesmo_ano")), fill = TRUE)
      data.table::set(dt, i = idx, j = c_campanha, value = novo_camp[idx])
    }
    ciclo1 <- chr(c_ciclo); campanha1 <- chr(c_campanha)
    # Regra A: campanha com padrão de ciclo, confirmada pelo ciclo do mesmo ano.
    ano_camp_ciclo <- ano_rx(campanha1, rx_ciclo)
    ano_ciclo <- ano_rx(ciclo1, rx_ciclo)
    idx <- which(!is.na(ano_camp_ciclo) & !is.na(ano_ciclo) & ano_camp_ciclo == ano_ciclo)
    if (length(idx)) {
      novo <- paste0("Campanha-", ano_camp_ciclo, "_VgCS")
      aud <- data.table::rbindlist(list(aud, add_audit(idx, "CAMPANHA", campanha1, novo, "campanha_com_padrao_de_ciclo_mesmo_ano")), fill = TRUE)
      data.table::set(dt, i = idx, j = c_campanha, value = novo[idx])
    }
    ciclo2 <- chr(c_ciclo); campanha2 <- chr(c_campanha)
    # Regra B: ciclo com padrão de campanha, confirmada pela campanha do mesmo ano.
    ano_ciclo_camp <- ano_rx(ciclo2, rx_camp)
    ano_camp <- ano_rx(campanha2, rx_camp)
    idx <- which(!is.na(ano_ciclo_camp) & !is.na(ano_camp) & ano_ciclo_camp == ano_camp)
    if (length(idx)) {
      novo <- paste0("Ciclo-", ano_ciclo_camp, "_VgCS")
      aud <- data.table::rbindlist(list(aud, add_audit(idx, "CICLO", ciclo2, novo, "ciclo_com_padrao_de_campanha_mesmo_ano")), fill = TRUE)
      data.table::set(dt, i = idx, j = c_ciclo, value = novo[idx])
    }
  }

  if (!is.na(c_ea) && !is.na(c_ua)) {
    ea1 <- chr(c_ea); ua1 <- chr(c_ua)
    idx <- which(grepl(rx_ua, ea1, perl = TRUE) & grepl(rx_ea, ua1, perl = TRUE))
    if (length(idx)) {
      novo_ea <- ua1; novo_ua <- ea1
      aud <- data.table::rbindlist(list(aud, add_audit(idx, "EA", ea1, novo_ea, "ea_ua_trocados_padroes_mutuamente_inequivocos")), fill = TRUE)
      data.table::set(dt, i = idx, j = c_ea, value = novo_ea[idx])
      aud <- data.table::rbindlist(list(aud, add_audit(idx, "UA", ua1, novo_ua, "ea_ua_trocados_padroes_mutuamente_inequivocos")), fill = TRUE)
      data.table::set(dt, i = idx, j = c_ua, value = novo_ua[idx])
    }
  }

  # Ocorrências suspeitas remanescentes, não bloqueantes.
  ciclo <- chr(c_ciclo); campanha <- chr(c_campanha); ea <- chr(c_ea); ua <- chr(c_ua)
  uc <- chr(c_uc); coleta <- chr(c_coleta); data_v <- chr(c_data); ano_v <- chr(c_ano); form <- chr(c_form)
  occ <- empty_occ()
  add_occ <- function(idx, atributo, valor, padrao, pertence, motivo) {
    idx <- as.integer(idx[!is.na(idx) & idx >= 1L & idx <= n])
    if (!length(idx)) return(empty_occ())
    data.table::data.table(
      exec_id = as.character(exec_id), contexto = as.character(contexto)[1L], linha_indice = idx,
      COLETA = coleta[idx], UC = uc[idx], CICLO = ciclo[idx], CAMPANHA = campanha[idx], EA = ea[idx], UA = ua[idx],
      Data = data_v[idx], ANO = ano_v[idx], form_veg = form[idx], atributo = atributo,
      valor_observado = as.character(valor)[idx], padrao_detectado = padrao,
      atributo_ao_qual_parece_pertencer = pertence, severidade = "alerta_cadastral", acao_sugerida = "revisar_origem_ou_autorizar_correcao_cadastral",
      motivo_nao_corrigido = motivo, bloqueia_produto = FALSE
    )
  }
  if (!is.na(c_campanha)) {
    idx <- which(grepl(rx_any_ciclo, campanha, perl = TRUE))
    occ <- data.table::rbindlist(list(occ, add_occ(idx, "CAMPANHA", campanha, "valor_com_padrao_de_CICLO", "CICLO", "nao_corrigido_por_ano_ausente_divergente_ou_ciclo_nao_confirmatorio")), fill = TRUE)
  }
  if (!is.na(c_ciclo)) {
    idx <- which(grepl(rx_any_camp, ciclo, perl = TRUE))
    occ <- data.table::rbindlist(list(occ, add_occ(idx, "CICLO", ciclo, "valor_com_padrao_de_CAMPANHA", "CAMPANHA", "nao_corrigido_por_ano_ausente_divergente_ou_campanha_nao_confirmatoria")), fill = TRUE)
  }
  if (!is.na(c_ea)) {
    idx <- which(grepl(rx_ua, ea, perl = TRUE))
    occ <- data.table::rbindlist(list(occ, add_occ(idx, "EA", ea, "valor_com_padrao_de_UA", "UA", "nao_corrigido_por_ua_ausente_ou_nao_confirmatoria")), fill = TRUE)
  }
  if (!is.na(c_ua)) {
    idx <- which(grepl(rx_ea, ua, perl = TRUE))
    occ <- data.table::rbindlist(list(occ, add_occ(idx, "UA", ua, "valor_com_padrao_de_EA", "EA", "nao_corrigido_por_ea_ausente_ou_nao_confirmatoria")), fill = TRUE)
  }
  if (!is.na(c_uc)) {
    idx <- which(grepl(rx_any_ciclo, uc, perl = TRUE) | grepl(rx_any_camp, uc, perl = TRUE) | grepl(rx_ea, uc, perl = TRUE) | grepl(rx_ua, uc, perl = TRUE))
    occ <- data.table::rbindlist(list(occ, add_occ(idx, "UC", uc, "valor_com_padrao_de_outro_atributo_cadastral", "CICLO/CAMPANHA/EA/UA", "uc_nao_corrigida_automaticamente_sem_fonte_externa")), fill = TRUE)
  }
  if (!is.na(c_form)) {
    form_l <- tolower(form)
    idx <- which(nzchar(form_l) & !(form_l %in% c("campestre", "savanica", "nao_informado", "nao_informada")))
    occ <- data.table::rbindlist(list(occ, add_occ(idx, "form_veg", form, "valor_fora_do_conjunto_esperado", "form_veg", "form_veg_nao_corrigida_automaticamente_sem_fonte_externa")), fill = TRUE)
  }
  if (!is.na(c_data) && !is.na(c_ano)) {
    ano_data <- rep(NA_character_, length(data_v))
    ok_data <- grepl("^[0-9]{4}-[0-9]{2}-[0-9]{2}$", data_v)
    ano_data[ok_data] <- substr(data_v[ok_data], 1L, 4L)
    ano_limpo <- sub("^.*?([0-9]{4}).*$", "\\1", ano_v)
    ano_limpo[!grepl("[0-9]{4}", ano_v)] <- NA_character_
    idx <- which(!is.na(ano_data) & !is.na(ano_limpo) & nzchar(ano_limpo) & ano_data != ano_limpo)
    occ <- data.table::rbindlist(list(occ, add_occ(idx, "ANO", ano_v, "ano_incompativel_com_data_hora_data", "data_hora/data", "ano_nao_corrigido_automaticamente_sem_regra_de_precedencia")), fill = TRUE)
  }

  # Remover alertas que foram corrigidos nesta execução.
  if (nrow(occ) && nrow(aud)) {
    ch_a <- paste(aud$linha_indice, aud$atributo_corrigido, sep = "||")
    ch_o <- paste(occ$linha_indice, occ$atributo, sep = "||")
    occ <- occ[!(ch_o %in% ch_a)]
  }

  dir_cad <- file.path(output_dir, "03_auditorias", "cadastro")
  dir.create(dir_cad, recursive = TRUE, showWarnings = FALSE)
  dir.create(log_dir, recursive = TRUE, showWarnings = FALSE)
  aud_out <- if (exists("monitora_privacidade_sanitizar_auditoria", mode = "function")) monitora_privacidade_sanitizar_auditoria(aud, mascarar_exemplos = FALSE) else aud
  occ_out <- if (exists("monitora_privacidade_sanitizar_auditoria", mode = "function")) monitora_privacidade_sanitizar_auditoria(occ, mascarar_exemplos = FALSE) else occ
  data.table::fwrite(aud_out, file.path(dir_cad, "auditoria_sanitizacao_cadastral_automatica.csv"), na = "")
  data.table::fwrite(occ_out, file.path(dir_cad, "ocorrencias_cadastrais_suspeitas.csv"), na = "")
  try(data.table::fwrite(aud_out, file.path(log_dir, paste0("auditoria_sanitizacao_cadastral_automatica_", exec_id, ".csv")), na = ""), silent = TRUE)
  try(data.table::fwrite(occ_out, file.path(log_dir, paste0("ocorrencias_cadastrais_suspeitas_", exec_id, ".csv")), na = ""), silent = TRUE)

  resumo <- data.table::rbindlist(list(
    if (nrow(aud_out)) aud_out[, .(n_linhas = .N, n_coletas = data.table::uniqueN(COLETA[nzchar(COLETA)]), acao = "sanitizado_automaticamente", bloqueia_produto = FALSE), by = .(tipo_ocorrencia = regra_aplicada)] else data.table::data.table(),
    if (nrow(occ_out)) occ_out[, .(n_linhas = .N, n_coletas = data.table::uniqueN(COLETA[nzchar(COLETA)]), acao = "relatorio_alerta_nao_bloqueante", bloqueia_produto = FALSE), by = .(tipo_ocorrencia = padrao_detectado)] else data.table::data.table()
  ), fill = TRUE)
  if (!nrow(resumo)) resumo <- data.table::data.table(tipo_ocorrencia = "sem_ocorrencias_cadastrais", n_linhas = 0L, n_coletas = 0L, acao = "nenhuma", bloqueia_produto = FALSE)
  data.table::fwrite(resumo, file.path(dir_cad, "resumo_auditoria_cadastral.csv"), na = "")
  try(data.table::fwrite(resumo, file.path(log_dir, paste0("resumo_auditoria_cadastral_", exec_id, ".csv")), na = ""), silent = TRUE)

  assign("MONITORA_AUDITORIA_CADASTRAL_AUTOMATICA", aud_out, envir = .GlobalEnv)
  assign("MONITORA_OCORRENCIAS_CADASTRAIS_SUSPEITAS", occ_out, envir = .GlobalEnv)
  assign("MONITORA_AUDITORIA_CADASTRAL_RESUMO", resumo, envir = .GlobalEnv)
  if (exists("monitora_publicacao_g_log", mode = "function")) {
    monitora_publicacao_g_log("Auditoria cadastral não bloqueante: ", nrow(aud_out), " linha(s) sanitizada(s) automaticamente; ", nrow(occ_out), " alerta(s) cadastral(is) registrado(s). Produtos não serão bloqueados por esses alertas.")
  } else if (exists("monitora_correcao_console_msg", mode = "function")) {
    monitora_correcao_console_msg("Auditoria cadastral não bloqueante: ", nrow(aud_out), " linha(s) sanitizada(s); ", nrow(occ_out), " alerta(s).")
  }
  invisible(list(dt = dt, auditoria = aud_out, ocorrencias = occ_out, resumo = resumo))
}
### FIM v2.6.1 ---------------------------------------------------------



### v2.6.1 -------------------------------------------------------------
### Fechamento contratual centrado em registros_corrig.
### A organização dos 129 atributos do template SISMONITORA/XLSForm 2025
### acontece no próprio registros_corrig. registros_validados.csv, quando
### liberado, passa a ser apenas seleção e reordenação desses atributos.
monitora_publicacao_v262_chr <- function(x) {
  x <- as.character(x)
  x[is.na(x)] <- ""
  trimws(x)
}

monitora_publicacao_v262_vazio <- function(x) {
  !nzchar(monitora_publicacao_v262_chr(x))
}

monitora_publicacao_v262_coluna_existente <- function(dt, candidatos) {
  nms <- names(dt)
  for (cand in candidatos) {
    col <- tryCatch(monitora_validados_resolver_coluna(nms, cand), error = function(e) NA_character_)
    if (!is.na(col) && nzchar(col) && col %in% nms) return(col)
    if (cand %in% nms) return(cand)
  }
  NA_character_
}

monitora_publicacao_v262_coalesce_colunas <- function(dt, candidatos, n = nrow(dt)) {
  out <- rep("", n)
  origem <- rep(NA_character_, n)
  for (cand in candidatos) {
    col <- monitora_publicacao_v262_coluna_existente(dt, cand)
    if (is.na(col) || !nzchar(col) || !(col %in% names(dt))) next
    v <- if (exists("monitora_validados_limpar_ausencia_saida", mode = "function")) {
      monitora_validados_limpar_ausencia_saida(dt[[col]])
    } else {
      monitora_publicacao_v262_chr(dt[[col]])
    }
    idx <- !nzchar(out) & nzchar(v)
    if (any(idx, na.rm = TRUE)) {
      out[idx] <- v[idx]
      origem[idx] <- col
    }
  }
  list(valor = out, origem = origem)
}

monitora_publicacao_v262_norm_ascii <- function(x) {
  x <- monitora_publicacao_v262_chr(x)
  x <- tolower(x)
  y <- iconv(x, from = "", to = "ASCII//TRANSLIT")
  y[is.na(y)] <- x[is.na(y)]
  y <- gsub("<[^>]+>", " ", y, perl = TRUE)
  y <- gsub("[_]+", "_", y, perl = TRUE)
  y
}

monitora_publicacao_v262_tokens_forma_vida <- function(x, categoria = c("nativa", "exotica", "seca_morta")) {
  categoria <- match.arg(categoria)
  validos <- c(
    "graminoide", "erva_nao_graminoide", "arbusto_abaixo", "arbusto_acima",
    "arvore_abaixo", "arvore_acima", "bambu", "bromelioide", "cactacea",
    "lianas", "ervas_de_passarinho", "orquidea", "palmeira", "samambaia",
    if (categoria %in% c("nativa", "seca_morta")) "canela_de_ema" else character(),
    "desconhecida"
  )
  y <- monitora_publicacao_v262_norm_ascii(x)
  y_tok <- gsub("[^a-z0-9_]+", " ", y, perl = TRUE)
  partes <- strsplit(y_tok, "\\s+", perl = TRUE)
  out <- character(length(y))
  for (i in seq_along(y)) {
    val <- y[i]
    toks <- unique(partes[[i]][nzchar(partes[[i]])])
    achou <- character(0)
    ## Tokens já normalizados.
    achou <- c(achou, intersect(validos, toks))
    ## Rótulos legados do XLSForm/ODK exportados em texto: converter para tokens.
    if (grepl("nao[^a-z0-9]+graminoide|nao_graminoide", val, perl = TRUE)) achou <- c(achou, "erva_nao_graminoide")
    if (grepl("graminoide|gramine|ciperac|juncac", val, perl = TRUE) && !grepl("nao[^a-z0-9]+graminoide|nao_graminoide", val, perl = TRUE)) achou <- c(achou, "graminoide")
    if (grepl("arbusto", val, perl = TRUE) && grepl("inferior|abaixo|menor[^a-z0-9]+que[^a-z0-9]+50", val, perl = TRUE)) achou <- c(achou, "arbusto_abaixo")
    if (grepl("arbusto", val, perl = TRUE) && grepl("superior|igual|acima|maior[^a-z0-9]+que[^a-z0-9]+50", val, perl = TRUE)) achou <- c(achou, "arbusto_acima")
    if (grepl("arvore", val, perl = TRUE) && grepl("menor", val, perl = TRUE)) achou <- c(achou, "arvore_abaixo")
    if (grepl("arvore", val, perl = TRUE) && grepl("igual|maior|acima", val, perl = TRUE)) achou <- c(achou, "arvore_acima")
    if (grepl("bambu|taquara", val, perl = TRUE)) achou <- c(achou, "bambu")
    if (grepl("bromelioide|bromeli", val, perl = TRUE)) achou <- c(achou, "bromelioide")
    if (grepl("cact", val, perl = TRUE)) achou <- c(achou, "cactacea")
    if (grepl("liana|cipo|trepadeira", val, perl = TRUE)) achou <- c(achou, "lianas")
    if (grepl("passarinho|hemiparas", val, perl = TRUE)) achou <- c(achou, "ervas_de_passarinho")
    if (grepl("orquid", val, perl = TRUE)) achou <- c(achou, "orquidea")
    if (grepl("palmeir", val, perl = TRUE)) achou <- c(achou, "palmeira")
    if (grepl("samamba", val, perl = TRUE)) achou <- c(achou, "samambaia")
    if (categoria %in% c("nativa", "seca_morta") && grepl("velosia|vellozi|canela[^a-z0-9]+de[^a-z0-9]+ema", val, perl = TRUE)) achou <- c(achou, "canela_de_ema")
    if (grepl("desconhecid|indeterminad|nao[^a-z0-9]+identific", val, perl = TRUE)) achou <- c(achou, "desconhecida")
    achou <- validos[validos %in% unique(achou)]
    if (length(achou)) {
      out[i] <- paste(achou, collapse = " ")
    } else {
      ## Se não foi possível reconhecer nenhum token/label conhecido, preservar
      ## o valor original para que a auditoria bloqueie explicitamente.
      out[i] <- monitora_publicacao_v262_chr(x[i])
    }
  }
  out
}

monitora_publicacao_v262_sincronizar_template_2025_registros_corrig <- function(dt,
                                                                                contexto = "fechamento_registros_corrig_v262",
                                                                                output_dir = get0("MONITORA_OUTPUT_DIR", ifnotfound = "output", inherits = TRUE),
                                                                                log_dir = get0("MONITORA_LOG_DIR", ifnotfound = "log", inherits = TRUE),
                                                                                exec_id = get0("MONITORA_EXEC_ID", ifnotfound = format(Sys.time(), "%Y%m%d_%H%M%S"), inherits = TRUE)) {
  if (!requireNamespace("data.table", quietly = TRUE)) stop("Pacote data.table é obrigatório.", call. = FALSE)
  dt <- data.table::as.data.table(dt)
  schema <- tryCatch(monitora_validados_schema_embutido(), error = function(e) NULL)
  if (!inherits(schema, "data.frame") || !("atributo" %in% names(schema))) return(dt)
  schema <- data.table::as.data.table(schema)
  n <- nrow(dt)
  audit <- list(); k <- 0L
  registrar <- function(atributo, acao, coluna_origem = NA_character_, n_alteradas = 0L, detalhe = "") {
    k <<- k + 1L
    audit[[k]] <<- data.table::data.table(
      contexto = contexto,
      atributo = as.character(atributo)[1L],
      acao = as.character(acao)[1L],
      coluna_origem = as.character(coluna_origem)[1L],
      n_linhas_alteradas = as.integer(n_alteradas)[1L],
      detalhe = as.character(detalhe)[1L],
      timestamp = format(Sys.time(), "%Y-%m-%d %H:%M:%S")
    )
  }
  ## Garantir presença física dos 129 atributos contratuais em registros_corrig.
  for (att in as.character(schema$atributo)) {
    if (!(att %in% names(dt))) {
      data.table::set(dt, j = att, value = rep("", n))
      registrar(att, "criar_coluna_contratual_vazia", NA_character_, n, "atributo do template SISMONITORA/XLSForm 2025 ausente em registros_corrig")
    }
  }
  alias <- list(
    uc = c("uc", "UC", "Unidade de Conservação", "unidade_conservacao"),
    ciclo = c("ciclo", "CICLO", "amostragem/ciclo"),
    campanha = c("campanha", "CAMPANHA", "amostragem/campanha"),
    ea = c("ea", "EA", "estacao_amostral", "estação amostral"),
    ua = c("ua", "UA", "unidade_amostral", "unidade amostral"),
    usuario = c("usuario", "USUARIO"),
    validado = c("validado", "VALIDADO"),
    validador = c("validador", "VALIDADOR"),
    data_validacao = c("data_validacao", "DATA_VALIDACAO"),
    obs_validacao = c("obs_validacao", "OBS_VALIDACAO")
  )
  for (att in names(alias)) {
    if (!(att %in% names(dt))) next
    antes <- monitora_publicacao_v262_chr(dt[[att]])
    co <- monitora_publicacao_v262_coalesce_colunas(dt, alias[[att]], n)
    depois <- antes
    idx <- !nzchar(depois) & nzchar(co$valor)
    if (any(idx, na.rm = TRUE)) depois[idx] <- co$valor[idx]
    if (identical(att, "validado")) {
      depois <- tolower(depois)
      depois[!nzchar(depois)] <- "nao"
      depois[!(depois %in% c("sim", "nao"))] <- "nao"
    }
    data.table::set(dt, j = att, value = depois)
    registrar(att, "sincronizar_aliases_em_registros_corrig", paste(unique(co$origem[!is.na(co$origem)]), collapse = " | "), sum(antes != depois, na.rm = TRUE), "preenche atributo contratual vazio a partir de alias operacional preenchido")
    ## Manter alias operacional maiúsculo coerente quando existir e o atributo
    ## contratual tiver valor. Isso preserva auditorias antigas e novas.
    alvo_fisico <- switch(att, uc = "UC", ciclo = "CICLO", campanha = "CAMPANHA", ea = "EA", ua = "UA", usuario = "USUARIO", NA_character_)
    if (!is.na(alvo_fisico) && alvo_fisico %in% names(dt)) {
      antes_f <- monitora_publicacao_v262_chr(dt[[alvo_fisico]])
      depois_f <- antes_f
      idx_f <- nzchar(depois) & (monitora_publicacao_v262_vazio(depois_f) | depois_f != depois)
      if (any(idx_f, na.rm = TRUE)) depois_f[idx_f] <- depois[idx_f]
      data.table::set(dt, j = alvo_fisico, value = depois_f)
      registrar(att, "sincronizar_alias_operacional_a_partir_do_contratual", alvo_fisico, sum(antes_f != depois_f, na.rm = TRUE), "mantém coluna operacional coerente com atributo do template")
    }
  }
  ## Atributos contratuais de estrutura/interceptação que aparecem no
  ## SISMONITORA exportado com rótulos legados ou aliases operacionais. Eles
  ## precisam ser materializados em registros_corrig antes das auditorias
  ## impeditivas; registros_validados só pode selecionar/reordenar.
  alias_estrutura_interceptacao <- list(
    "coleta" = c("coleta", "COLETA"),
    "protocolo" = c("protocolo", "PROTOCOLO"),
    "amostragem/registro/ponto_amostral" = c(
      "amostragem/registro/ponto_amostral",
      "ponto_amostral (amostragem/registro)",
      "ponto_amostral",
      "Ponto amostral (amostragem/registro)"
    ),
    "amostragem/registro/ponto_metro" = c(
      "amostragem/registro/ponto_metro",
      "ponto_metro (amostragem/registro)",
      "ponto_metro",
      "Ponto metro (amostragem/registro)"
    ),
    "amostragem/registro/tipo_forma_vida" = c(
      "amostragem/registro/tipo_forma_vida",
      "**Encostam** na vareta: (amostragem/registro)",
      "Encostam",
      "encostam",
      "tipo_forma_vida"
    )
  )
  for (att in names(alias_estrutura_interceptacao)) {
    if (!(att %in% names(dt))) next
    antes <- monitora_publicacao_v262_chr(dt[[att]])
    co <- monitora_publicacao_v262_coalesce_colunas(dt, alias_estrutura_interceptacao[[att]], n)
    depois <- antes
    idx <- !nzchar(depois) & nzchar(co$valor)
    if (any(idx, na.rm = TRUE)) depois[idx] <- co$valor[idx]
    if (identical(att, "amostragem/registro/tipo_forma_vida")) {
      depois <- tolower(trimws(depois))
      depois <- gsub("[;|,]+", " ", depois, perl = TRUE)
      depois <- gsub("\\s+", " ", depois, perl = TRUE)
      depois <- trimws(depois)
    }
    data.table::set(dt, j = att, value = depois)
    registrar(
      att,
      "sincronizar_alias_estrutura_interceptacao_em_registros_corrig",
      paste(unique(co$origem[!is.na(co$origem)]), collapse = " | "),
      sum(antes != depois, na.rm = TRUE),
      "preenche atributo contratual estrutural/interceptação a partir de alias operacional preenchido"
    )
  }

  ## v2.6.1: datas e formação vegetacional precisam estar resolvidas no
  ## próprio registros_corrig antes da matriz contratual. A rotina anterior criava
  ## colunas canônicas vazias e a auditoria passava a preferi-las às colunas
  ## históricas preenchidas, gerando falso bloqueio de data_do_registro,
  ## data_do_recebimento, data_hora/data e form_veg.
  alias_data_formveg <- list(
    "data_hora/data" = list(
      candidatos = c("data_hora/data", "Data (data_hora)", "DATA_MONITORA_PARSEADA", "Data", "data", "DATA"),
      formato = "data_iso",
      detalhe = "preenche data_hora/data a partir da data operacional preenchida"
    ),
    "form_veg" = list(
      candidatos = c("form_veg", "Qual a formação vegetacional onde está situado o transecto?", "FORM_VEG", "formacao_vegetal", "formação vegetacional", "formacao vegetacional"),
      formato = "texto",
      detalhe = "preenche form_veg a partir do rótulo/alias operacional preenchido"
    )
  )
  for (att in names(alias_data_formveg)) {
    if (!(att %in% names(dt))) next
    antes <- monitora_publicacao_v262_chr(dt[[att]])
    co <- monitora_publicacao_v262_coalesce_colunas(dt, alias_data_formveg[[att]]$candidatos, n)
    val <- monitora_publicacao_v262_chr(co$valor)
    if (identical(alias_data_formveg[[att]]$formato, "data_iso") && exists("monitora_validados_formatar_valor", mode = "function")) {
      val <- monitora_validados_formatar_valor(val, "data_iso")
      val[is.na(val)] <- ""
    }
    depois <- antes
    idx <- !nzchar(depois) & nzchar(val)
    if (any(idx, na.rm = TRUE)) depois[idx] <- val[idx]
    data.table::set(dt, j = att, value = depois)
    registrar(att, "sincronizar_alias_data_formveg_em_registros_corrig", paste(unique(co$origem[!is.na(co$origem)]), collapse = " | "), sum(antes != depois, na.rm = TRUE), alias_data_formveg[[att]]$detalhe)
  }

  ## Após resolver data_hora/data, materializar os dois datetimes obrigatórios em
  ## registros_corrig. Isto continua sendo organização do produto mestre, não
  ## derivação tardia de registros_validados.
  for (att in c("data_do_registro", "data_do_recebimento")) {
    if (!(att %in% names(dt))) next
    antes <- monitora_publicacao_v262_chr(dt[[att]])
    res <- tryCatch(monitora_validados_derive_datetime(dt, att), error = function(e) NULL)
    if (is.list(res) && "valor" %in% names(res)) {
      val <- monitora_publicacao_v262_chr(res$valor)
      depois <- antes
      idx <- !nzchar(depois) & nzchar(val)
      if (any(idx, na.rm = TRUE)) depois[idx] <- val[idx]
      data.table::set(dt, j = att, value = depois)
      registrar(att, "materializar_datetime_obrigatorio_em_registros_corrig", ifelse(is.null(res$coluna), NA_character_, as.character(res$coluna)[1L]), sum(antes != depois, na.rm = TRUE), "preenche datetime obrigatório a partir de data_hora/data e data_hora/hora já resolvidos")
    }
  }

  ## Campos principais select_multiple: converter rótulos XLSForm legados em
  ## tokens contratuais dentro do próprio registros_corrig.
  formas <- list(
    "amostragem/registro/forma_vida_nativa" = list(cat = "nativa", candidatos = c("amostragem/registro/forma_vida_nativa", "Formas de vida de plantas <span style=\"\"color:red\"\">nativas:</span> (amostragem/registro)", "Formas de vida de plantas nativas: (amostragem/registro)")),
    "amostragem/registro/forma_vida_exotica" = list(cat = "exotica", candidatos = c("amostragem/registro/forma_vida_exotica", "Formas de vida de plantas <span style=\"\"color:red\"\">exóticas:</span> (amostragem/registro)", "Formas de vida de plantas exóticas: (amostragem/registro)")),
    "amostragem/registro/forma_vida_seca_morta" = list(cat = "seca_morta", candidatos = c("amostragem/registro/forma_vida_seca_morta", "Formas de vida de plantas <span style=\"\"color:red\"\">secas ou mortas:</span> (amostragem/registro)", "Formas de vida de plantas secas ou mortas: (amostragem/registro)"))
  )
  for (att in names(formas)) {
    if (!(att %in% names(dt))) next
    antes <- monitora_publicacao_v262_chr(dt[[att]])
    co <- monitora_publicacao_v262_coalesce_colunas(dt, formas[[att]]$candidatos, n)
    base <- antes
    idx <- !nzchar(base) & nzchar(co$valor)
    if (any(idx, na.rm = TRUE)) base[idx] <- co$valor[idx]
    depois <- monitora_publicacao_v262_tokens_forma_vida(base, categoria = formas[[att]]$cat)
    data.table::set(dt, j = att, value = depois)
    registrar(att, "normalizar_select_multiple_em_registros_corrig", paste(unique(co$origem[!is.na(co$origem)]), collapse = " | "), sum(antes != depois, na.rm = TRUE), "converte labels legados do XLSForm em tokens antes de validar/exportar")
  }
  ## Estratégias conhecidas que já eram derivadas para registros_validados agora
  ## são materializadas em registros_corrig, quando vazias, usando o mesmo motor.
  especiais_materializar <- intersect(as.character(schema$atributo), c(
    "data_do_registro", "data_do_recebimento", "data_hora/data", "data_hora/hora",
    "coleta_uuid", "uuid", "amostragem/registro/uuid", "protocolo",
    "planilha_upload", "controle_versao", "amostragem/num_placa",
    "amostragem/num_placa_formatado", "amostragem/registro/forma_serrapilheira",
    "amostragem/registro/forma_vida_outros", "amostragem/especie"
  ))
  for (att in especiais_materializar) {
    if (!(att %in% names(dt))) next
    antes <- monitora_publicacao_v262_chr(dt[[att]])
    if (any(!nzchar(antes), na.rm = TRUE)) {
      res <- tryCatch(monitora_validados_derivar_ou_mapear_coluna(dt, att, schema[atributo == att]$formato[1L], schema[atributo == att]$largura[1L]), error = function(e) NULL)
      if (is.list(res) && "valor" %in% names(res)) {
        val <- monitora_publicacao_v262_chr(res$valor)
        depois <- antes
        idx <- !nzchar(depois) & nzchar(val)
        if (any(idx, na.rm = TRUE)) depois[idx] <- val[idx]
        data.table::set(dt, j = att, value = depois)
        registrar(att, "materializar_derivacao_contratual_em_registros_corrig", ifelse(is.null(res$coluna), NA_character_, as.character(res$coluna)[1L]), sum(antes != depois, na.rm = TRUE), "evita derivação tardia exclusiva de registros_validados")
      }
    }
  }
  aud <- if (length(audit)) data.table::rbindlist(audit, fill = TRUE) else data.table::data.table()
  try({
    dir.create(file.path(output_dir, "03_auditorias", "contrato_xlsform"), recursive = TRUE, showWarnings = FALSE)
    dir.create(log_dir, recursive = TRUE, showWarnings = FALSE)
    data.table::fwrite(aud, file.path(output_dir, "03_auditorias", "contrato_xlsform", "auditoria_sincronizacao_template2025_registros_corrig.csv"), sep = ",", quote = "auto", na = "")
    data.table::fwrite(aud, file.path(log_dir, paste0("auditoria_sincronizacao_template2025_registros_corrig_", exec_id, ".csv")), sep = ",", quote = "auto", na = "")
  }, silent = TRUE)
  if (exists("monitora_publicacao_g_log", mode = "function")) {
    monitora_publicacao_g_log("[v2.6.1] registros_corrig sincronizado com template 2025 (aliases estruturais/interceptação): atributos=", length(schema$atributo), "; eventos_auditoria=", nrow(aud), ".")
  }
  dt
}

monitora_publicacao_v262_responsavel_validacao <- function() {
  limpar <- function(x) {
    x <- trimws(as.character(x))
    x <- x[!is.na(x) & nzchar(x)]
    x
  }
  audit <- get0("MONITORA_AUDITORIA_CORRECOES_CAMPOS_ULTIMA", ifnotfound = NULL, inherits = TRUE)
  if (inherits(audit, "data.frame") && "responsavel" %in% names(audit)) {
    vals <- limpar(audit$responsavel)
    if (length(vals)) return(vals[1L])
  }
  validador_explicito <- limpar(c(
    get0("MONITORA_RESPONSAVEL_VALIDACAO", ifnotfound = "", inherits = TRUE),
    Sys.getenv("MONITORA_RESPONSAVEL_VALIDACAO", unset = "")
  ))
  if (length(validador_explicito)) return(validador_explicito[1L])
  responsavel_correcao <- limpar(get0("MONITORA_RESPONSAVEL_CORRECAO", ifnotfound = "", inherits = TRUE))
  if (length(responsavel_correcao)) return(responsavel_correcao[1L])
  ""
}

monitora_publicacao_v262_preencher_metadados_validacao_registros_corrig <- function(dt,
                                                                                    contexto = "checkpoint_aprovado_contrato_2025",
                                                                                    output_dir = get0("MONITORA_OUTPUT_DIR", ifnotfound = "output", inherits = TRUE),
                                                                                    log_dir = get0("MONITORA_LOG_DIR", ifnotfound = "log", inherits = TRUE),
                                                                                    exec_id = get0("MONITORA_EXEC_ID", ifnotfound = format(Sys.time(), "%Y%m%d_%H%M%S"), inherits = TRUE)) {
  if (!requireNamespace("data.table", quietly = TRUE)) stop("Pacote data.table é obrigatório.", call. = FALSE)
  dt <- data.table::as.data.table(dt)
  n <- nrow(dt)
  for (cc in c("validado", "validador", "data_validacao", "obs_validacao")) {
    if (!(cc %in% names(dt))) data.table::set(dt, j = cc, value = rep("", n))
  }
  validador <- monitora_publicacao_v262_responsavel_validacao()
  data_validacao <- format(Sys.Date(), "%Y-%m-%d")
  hash_curto <- ""
  if (requireNamespace("digest", quietly = TRUE)) {
    hash_curto <- tryCatch(substr(digest::digest(dt, algo = "sha256"), 1L, 12L), error = function(e) "")
  }
  obs <- "checkpoint_ok"

  antes <- data.table::data.table(
    validado = dt[["validado"]],
    validador = dt[["validador"]],
    data_validacao = dt[["data_validacao"]],
    obs_validacao = dt[["obs_validacao"]]
  )
  data.table::set(dt, j = "validado", value = rep("sim", n))
  data.table::set(dt, j = "data_validacao", value = rep(data_validacao, n))
  data.table::set(dt, j = "obs_validacao", value = rep(obs, n))
  if (nzchar(validador)) data.table::set(dt, j = "validador", value = rep(validador, n))

  audit <- data.table::data.table(
    contexto = contexto,
    atributo = c("validado", "data_validacao", "validador", "obs_validacao"),
    acao = "preencher_metadados_validacao_em_registros_corrig",
    valor_aplicado = c("sim", data_validacao, if (nzchar(validador)) "[informado]" else "", obs),
    hash_interno_registros_corrig = c(hash_curto, hash_curto, hash_curto, hash_curto),
    n_linhas_alteradas = c(
      sum(as.character(antes$validado) != "sim", na.rm = TRUE),
      sum(as.character(antes$data_validacao) != data_validacao, na.rm = TRUE),
      if (nzchar(validador)) sum(as.character(antes$validador) != validador, na.rm = TRUE) else 0L,
      sum(as.character(antes$obs_validacao) != obs, na.rm = TRUE)
    ),
    timestamp = format(Sys.time(), "%Y-%m-%d %H:%M:%S")
  )
  try(monitora_registros_validados_gravar_auditoria_pre_sanitizacao(audit, "auditoria_registros_corrig_metadados_validacao", output_dir, log_dir, exec_id), silent = TRUE)
  if (exists("monitora_log_registrar_evento", mode = "function")) {
    nivel <- if (nzchar(validador)) "INFO" else "AVISO"
    msg <- if (nzchar(validador)) {
      "Metadados administrativos de validação preenchidos em registros_corrig aprovado."
    } else {
      "Metadados administrativos de validação preenchidos em registros_corrig aprovado; validador vazio por não haver fonte explícita."
    }
    monitora_log_registrar_evento("registros_corrig_metadados_validacao", nivel, NA_character_, msg, contexto)
  }
  dt[]
}

monitora_publicacao_v262_exportar_registros_validados_selecao <- function(registros_corrig,
                                                                          schema,
                                                                          output_dir,
                                                                          log_dir,
                                                                          exec_id) {
  if (!requireNamespace("data.table", quietly = TRUE)) stop("Pacote data.table é obrigatório.", call. = FALSE)
  dt <- data.table::as.data.table(registros_corrig)
  schema <- data.table::as.data.table(schema)
  cols <- as.character(schema$atributo)
  faltantes <- setdiff(cols, names(dt))
  if (length(faltantes)) {
    stop("registros_validados.csv bloqueado: registros_corrig não contém atributo(s) do template: ", paste(faltantes, collapse = ", "), call. = FALSE)
  }
  out <- data.table::copy(dt[, ..cols])
  data.table::setcolorder(out, cols)
  caminho_saida <- if (exists("monitora_produtos_path_canonico", mode = "function")) {
    monitora_produtos_path_canonico("registros_validados.csv", output_dir)
  } else {
    file.path(output_dir, "01_produtos_dados", "registros_validados.csv")
  }
  dir.create(dirname(caminho_saida), recursive = TRUE, showWarnings = FALSE)
  dir.create(log_dir, recursive = TRUE, showWarnings = FALSE)
  data.table::fwrite(out, caminho_saida, sep = ",", quote = "auto", na = "", bom = FALSE)
  header_saida <- names(data.table::fread(caminho_saida, sep = ",", nrows = 0, encoding = "UTF-8", check.names = FALSE, showProgress = FALSE, data.table = TRUE))
  if (!identical(header_saida, cols)) {
    stop("Cabeçalho de registros_validados.csv difere do schema SISMONITORA embutido; exportação bloqueada.", call. = FALSE)
  }
  auditoria <- data.table::data.table(
    exec_id = exec_id,
    produto = "registros_validados.csv",
    modo_geracao = "selecao_reordenacao_de_registros_corrig_v2.6.1",
    n_linhas = nrow(out),
    n_colunas = ncol(out),
    caminho = caminho_saida,
    timestamp = format(Sys.time(), "%Y-%m-%d %H:%M:%S")
  )
  try({
    dir.create(file.path(output_dir, "03_auditorias", "contrato_xlsform"), recursive = TRUE, showWarnings = FALSE)
    data.table::fwrite(auditoria, file.path(output_dir, "03_auditorias", "contrato_xlsform", "auditoria_registros_validados_exportacao_selecao.csv"), na = "")
    data.table::fwrite(auditoria, file.path(log_dir, paste0("auditoria_registros_validados_exportacao_selecao_", exec_id, ".csv")), na = "")
  }, silent = TRUE)
  MONITORA_REGISTROS_VALIDADOS_GERADO <<- TRUE
  MONITORA_REGISTROS_VALIDADOS_ULTIMA_AUDITORIA <<- auditoria
  if (exists("monitora_log_registrar_evento", mode = "function")) {
    monitora_log_registrar_evento("registros_validados_exportado", "INFO", caminho_saida, paste0("registros_validados.csv gerado por seleção/reordenação de registros_corrig: ", nrow(out), " linhas e ", ncol(out), " colunas"), "v2.6.1; sem derivação tardia")
  }
  invisible(auditoria)
}
### FIM v2.6.1 ---------------------------------------------------------

### v2.6.1 ----------------------------
### Fechamento único pós-painel/pre-materialização. Esta função torna
### registros_corrig.csv o produto mestre: sanitiza, fecha invariantes, audita
### contrato XLSForm21 nos atributos que alimentam registros_validados.csv e só
### então libera a gravação do CSV corrigido. registros_validados.csv passa a
### herdar a matriz já aprovada, sem refazer reparo semântico tardio.
monitora_publicacao_aa_preparar_validar_registros_corrig <- function(registros_corrig,
                                                               contexto = "pre_materializacao_registros_corrig",
                                                               output_dir = MONITORA_OUTPUT_DIR,
                                                               log_dir = MONITORA_LOG_DIR,
                                                               exec_id = MONITORA_EXEC_ID,
                                                               abortar = TRUE) {
  if (!inherits(registros_corrig, c("data.frame", "data.table"))) {
    stop("Validação contratual de registros_corrig exige data.frame/data.table.", call. = FALSE)
  }
  if (!requireNamespace("data.table", quietly = TRUE)) stop("Pacote data.table é obrigatório para fechamento contratual.", call. = FALSE)
  dt <- data.table::as.data.table(registros_corrig)
  dir.create(output_dir, recursive = TRUE, showWarnings = FALSE)
  dir.create(log_dir, recursive = TRUE, showWarnings = FALSE)

  ### Auditoria/sanitização cadastral não bloqueante. Corrige somente casos
  ### inequívocos (ex.: CAMPANHA com padrão de CICLO do mesmo ano) e registra
  ### demais deslocamentos aparentes em relatório próprio, sem bloquear produto.
  if (exists("monitora_publicacao_ac_sanitizar_cadastro_nao_bloqueante", mode = "function")) {
    res_cad <- tryCatch(
      monitora_publicacao_ac_sanitizar_cadastro_nao_bloqueante(dt, contexto = contexto, output_dir = output_dir, log_dir = log_dir, exec_id = exec_id),
      error = function(e) {
        if (exists("monitora_log_registrar_evento", mode = "function")) {
          try(monitora_log_registrar_evento("auditoria_cadastral_nao_bloqueante", "AVISO", NA_character_, paste0("Falha na auditoria/sanitização cadastral não bloqueante: ", conditionMessage(e)), contexto), silent = TRUE)
        }
        list(dt = dt)
      }
    )
    if (is.list(res_cad) && "dt" %in% names(res_cad)) dt <- data.table::as.data.table(res_cad$dt)
  }

  if (exists("monitora_publicacao_v262_sincronizar_template_2025_registros_corrig", mode = "function")) {
    dt <- monitora_publicacao_v262_sincronizar_template_2025_registros_corrig(dt, contexto = paste0(contexto, "_pre_auditoria_impeditiva"), output_dir = output_dir, log_dir = log_dir, exec_id = exec_id)
  }
  if (exists("monitora_publicacao_g_log", mode = "function")) {
    monitora_publicacao_g_log("fechamento mestre registros_corrig: contexto=", contexto, "; linhas=", nrow(dt))
  }
  if (exists("monitora_publicacao_ac_perf_checkpoint", mode = "function")) {
    monitora_publicacao_ac_perf_checkpoint("checkpoint_registros_corrig_inicio", paste0("início do fechamento contratual de registros_corrig; contexto=", contexto), dt)
  }

  ### Auditoria impeditiva antes de qualquer sanitização/recalculo automático.
  ### Pendências detectadas aqui NÃO são saneadas silenciosamente: o arquivo
  ### registros_corrig.csv pode ser salvo como checkpoint marcado; a geração de
  ### registros_validados.csv é decidida pelo bloco contratual XLSForm21 próprio.
  pend_imp <- monitora_publicacao_ab_auditar_pendencias_impeditivas(
    dt,
    contexto = contexto,
    output_dir = output_dir,
    log_dir = log_dir,
    gravar = TRUE,
    marcar_base = TRUE
  )
  if (isTRUE(pend_imp$n_pendencias > 0L)) {
    monitora_publicacao_ab_logar_resumo_pendencias(pend_imp$resumo, contexto = contexto)
    assign("MONITORA_REGISTROS_CORRIG_CONTRATO_VALIDADO_XLSFORM21", FALSE, envir = .GlobalEnv)
    assign("MONITORA_REGISTROS_CORRIG_CONTRATO_CONTEXTO", paste0(contexto, "_checkpoint_com_pendencias_impeditivas"), envir = .GlobalEnv)
    assign("MONITORA_REGISTROS_VALIDADOS_GERADO", FALSE, envir = .GlobalEnv)
    if (exists("monitora_publicacao_ac_perf_checkpoint", mode = "function")) {
      monitora_publicacao_ac_perf_checkpoint("auditoria_pendencias_impeditivas_registros_corrig", "pendências impeditivas detectadas; saneamento automático bloqueado e registros_corrig será checkpoint marcado", dt)
    }
    if (exists("monitora_registros_corrig_reordenar_colunas", mode = "function")) {
      monitora_registros_corrig_reordenar_colunas(dt)
    }
    if (exists("monitora_publicacao_ac_gravar_dirty_flags", mode = "function")) {
      try(monitora_publicacao_ac_gravar_dirty_flags(output_dir = output_dir, log_dir = log_dir, exec_id = exec_id, contexto = paste0(contexto, "_checkpoint_com_pendencias_impeditivas")), silent = TRUE)
    }
    return(invisible(list(registros_corrig = dt, auditoria = pend_imp)))
  }

  ### Não há pendências impeditivas: a partir daqui o fechamento contratual pode
  ### recompor superiores e auditar o produto sem mascarar erro de campo.
  ### Sanitização contratual/taxonômica conhecida: canela-de-ema histórica em
  ### forma_vida_exotica deve migrar para nativa antes da auditoria XLSForm21,
  ### pois Velloziaceae exótica não compõe o contrato de 2025.
  if (exists("monitora_publicacao_ab_migrar_canela_de_ema_exotica_para_nativa", mode = "function")) {
    res_canela_corrig <- tryCatch(
      monitora_publicacao_ab_migrar_canela_de_ema_exotica_para_nativa(
        dt,
        linhas = seq_len(nrow(dt)),
        dicionario = NULL,
        id_correcao = "CANELA_EXOTICA_NATIVA_CONTRATUAL",
        arquivo_correcao = paste0(contexto, "_fechamento_registros_corrig")
      ),
      error = function(e) list(dt = dt, audit = data.table::data.table(status = "falha_migracao_canela_de_ema_exotica_nativa", mensagem = conditionMessage(e)), linhas = integer(), afetacoes = data.table::data.table(), falha = TRUE)
    )
    if (is.list(res_canela_corrig) && "dt" %in% names(res_canela_corrig)) dt <- data.table::as.data.table(res_canela_corrig$dt)
    if (is.list(res_canela_corrig) && "audit" %in% names(res_canela_corrig)) {
      try(monitora_registros_validados_gravar_auditoria_pre_sanitizacao(data.table::as.data.table(res_canela_corrig$audit), "auditoria_registros_corrig_migracao_canela_de_ema_exotica_nativa", output_dir, log_dir, exec_id), silent = TRUE)
    }
    if (exists("monitora_publicacao_g_log", mode = "function")) {
      n_can <- tryCatch(length(unique(as.integer(res_canela_corrig$linhas))), error = function(e) 0L)
      if (n_can > 0L) monitora_publicacao_g_log("Migração contratual canela-de-ema exótica→nativa aplicada no fechamento de registros_corrig: ", n_can, " linha(s).")
    }
  }
  assign("MONITORA_REGISTROS_VALIDADOS_PRE_SANITIZACAO_APLICADA", TRUE, envir = .GlobalEnv)
  if (exists("monitora_publicacao_ac_perf_checkpoint", mode = "function")) {
    monitora_publicacao_ac_perf_checkpoint("auditoria_pendencias_impeditivas_registros_corrig", "sem pendências impeditivas; fechamento contratual liberado", dt)
  }

  ### Fechamento de invariantes do produto corrigido. Só é executado após
  ### auditoria impeditiva zerada, evitando apagar nativa/exotica/seca_morta ou
  ### outra forma de vida sem operação assistida registrada.
  if (exists("monitora_publicacao_c_normalizar_contratos_pre_exportacao", mode = "function")) {
    if (exists("monitora_publicacao_z_selo_registros_corrig_valido", mode = "function") &&
        isTRUE(monitora_publicacao_z_selo_registros_corrig_valido(dt)) &&
        isTRUE(get0("MONITORA_REGISTROS_CORRIG_CONTRATO_VALIDADO_XLSFORM21", ifnotfound = FALSE, inherits = TRUE))) {
      if (exists("monitora_publicacao_g_log", mode = "function")) {
        monitora_publicacao_g_log("fechamento mestre registros_corrig reutilizado; selo contratual válido; contexto=", contexto)
      }
    } else {
      monitora_publicacao_c_normalizar_contratos_pre_exportacao(dt, contexto = contexto)
    }
  }

  if (exists("monitora_publicacao_v262_sincronizar_template_2025_registros_corrig", mode = "function")) {
    dt <- monitora_publicacao_v262_sincronizar_template_2025_registros_corrig(dt, contexto = paste0(contexto, "_pos_invariantes_pre_auditoria_xlsform"), output_dir = output_dir, log_dir = log_dir, exec_id = exec_id)
  }
  if (exists("monitora_publicacao_ac_perf_checkpoint", mode = "function")) {
    monitora_publicacao_ac_perf_checkpoint("fechamento_contratual_registros_corrig", "fechamento de invariantes/Encostam/sincronizações pré-materialização", dt)
  }

  if (exists("monitora_registros_corrig_reordenar_colunas", mode = "function")) {
    monitora_registros_corrig_reordenar_colunas(dt)
  }
  if (exists("monitora_publicacao_ac_perf_checkpoint", mode = "function")) {
    monitora_publicacao_ac_perf_checkpoint("reordenacao_registros_corrig_pre_materializacao", "reordenação técnica de colunas antes da auditoria contratual", dt)
  }

  ### Auditoria contratual do Contrato XLSForm/SISMONITORA 2025 antes da escrita de registros_corrig.csv.
  ### A chamada usa o mesmo montador dos validados em modo somente auditoria; em
  ### caso de pendência, para aqui e informa os relatórios ao bolsista.
  if (exists("monitora_registros_validados_exportar", mode = "function")) {
    val <- monitora_registros_validados_exportar(
      dt,
      output_dir = output_dir,
      log_dir = log_dir,
      exec_id = exec_id,
      abortar = FALSE,
      forcar = TRUE,
      somente_auditar_contrato_corrig = TRUE,
      contrato_corrig_validado = FALSE
    )
  } else {
    val <- NULL
  }
  if (exists("monitora_publicacao_ac_perf_checkpoint", mode = "function")) {
    monitora_publicacao_ac_perf_checkpoint("auditoria_contrato_registros_corrig_xlsform21", "auditoria contratual do Contrato XLSForm/SISMONITORA 2025 dos atributos que alimentam registros_validados", dt)
  }

  n_bloq_val <- tryCatch({
    rr <- data.table::as.data.table(val$resumo)
    if ("n_bloqueios" %in% names(rr)) sum(suppressWarnings(as.integer(rr$n_bloqueios)), na.rm = TRUE) else 0L
  }, error = function(e) 0L)
  if (isTRUE(n_bloq_val > 0L)) {
    assign("MONITORA_REGISTROS_CORRIG_CONTRATO_VALIDADO_XLSFORM21", FALSE, envir = .GlobalEnv)
    assign("MONITORA_REGISTROS_CORRIG_CONTRATO_CONTEXTO", paste0(contexto, "_sem_pendencias_impeditivas_bloqueio_registros_validados"), envir = .GlobalEnv)
    assign("MONITORA_REGISTROS_VALIDADOS_GERADO", FALSE, envir = .GlobalEnv)
    if (exists("monitora_publicacao_ac_gravar_dirty_flags", mode = "function")) {
      try(monitora_publicacao_ac_gravar_dirty_flags(output_dir = output_dir, log_dir = log_dir, exec_id = exec_id, contexto = paste0(contexto, "_bloqueio_registros_validados")), silent = TRUE)
    }
    if (exists("monitora_publicacao_g_log", mode = "function")) {
      monitora_publicacao_g_log("registros_corrig.csv liberado para materialização; registros_validados.csv bloqueado por ", n_bloq_val, " problema(s) contratuais. O bloqueio será registrado sem abortar o checkpoint.")
    }
    return(invisible(list(registros_corrig = dt, auditoria = val)))
  }

  if (exists("monitora_publicacao_v262_preencher_metadados_validacao_registros_corrig", mode = "function")) {
    dt <- monitora_publicacao_v262_preencher_metadados_validacao_registros_corrig(
      dt,
      contexto = paste0(contexto, "_checkpoint_aprovado_contrato_2025"),
      output_dir = output_dir,
      log_dir = log_dir,
      exec_id = exec_id
    )
  }
  if (exists("monitora_publicacao_z_gravar_selo_registros_corrig", mode = "function")) {
    monitora_publicacao_z_gravar_selo_registros_corrig(dt, contexto = paste0(contexto, "_aprovado_xlsform21"))
  }
  assign("MONITORA_REGISTROS_CORRIG_CONTRATO_VALIDADO_XLSFORM21", TRUE, envir = .GlobalEnv)
  assign("MONITORA_REGISTROS_CORRIG_CONTRATO_CONTEXTO", paste0(contexto, "_aprovado_xlsform21"), envir = .GlobalEnv)
  if (exists("monitora_publicacao_ac_gravar_dirty_flags", mode = "function")) {
    try(monitora_publicacao_ac_gravar_dirty_flags(output_dir = output_dir, log_dir = log_dir, exec_id = exec_id, contexto = paste0(contexto, "_aprovado_xlsform21")), silent = TRUE)
  }
  if (exists("monitora_publicacao_ac_perf_checkpoint", mode = "function")) {
    monitora_publicacao_ac_perf_checkpoint("selo_dirty_flags_registros_corrig", "selo contratual gravado e dirty flags resumidos", dt)
  }
  invisible(list(registros_corrig = dt, auditoria = val))
}


### v2.6.1 -------------------------------------------------------------
### Estado final canônico de registros_validados.csv. Evita falso aviso de
### bloqueio quando o contrato XLSForm21 já aprovou e o produto validado foi
### materializado em 01_produtos_dados antes da exportação final de
### registros_corrig.csv. A função é somente leitora/confirmatória: não altera
### o painel, TRIOUT, PENDFV, MVLOTE nem o contrato.
monitora_registros_validados_materializado_sem_bloqueio <- function(output_dir = get0("MONITORA_OUTPUT_DIR", ifnotfound = "output", inherits = TRUE)) {
  output_dir <- as.character(output_dir)[1L]
  caminhos_produto <- unique(c(
    if (exists("monitora_produtos_path_canonico", mode = "function")) tryCatch(monitora_produtos_path_canonico("registros_validados.csv", output_dir), error = function(e) NA_character_) else NA_character_,
    if (exists("monitora_produtos_path_raiz", mode = "function")) tryCatch(monitora_produtos_path_raiz("registros_validados.csv", output_dir), error = function(e) NA_character_) else NA_character_,
    file.path(output_dir, "01_produtos_dados", "registros_validados.csv"),
    file.path(output_dir, "registros_validados.csv")
  ))
  caminhos_produto <- caminhos_produto[!is.na(caminhos_produto) & nzchar(caminhos_produto)]
  produto_existe <- any(file.exists(caminhos_produto))

  gerado_global <- isTRUE(get0("MONITORA_REGISTROS_VALIDADOS_GERADO", ifnotfound = FALSE, inherits = TRUE))

  n_bloq_global <- NA_integer_
  ult <- get0("MONITORA_REGISTROS_VALIDADOS_ULTIMA_AUDITORIA", ifnotfound = NULL, inherits = TRUE)
  if (is.list(ult) && !is.null(ult$resumo)) {
    n_bloq_global <- tryCatch({
      rr <- data.table::as.data.table(ult$resumo)
      if ("n_bloqueios" %in% names(rr)) sum(suppressWarnings(as.integer(rr$n_bloqueios)), na.rm = TRUE) else NA_integer_
    }, error = function(e) NA_integer_)
  }

  caminhos_resumo <- unique(c(
    file.path(output_dir, "auditoria_registros_validados_resumo.csv"),
    file.path(output_dir, "03_auditorias", "contrato_xlsform", "auditoria_registros_validados_resumo.csv"),
    file.path(output_dir, "99_legacy_compat", "auditoria_registros_validados_resumo.csv")
  ))
  n_bloq_arquivo <- NA_integer_
  for (arq in caminhos_resumo[file.exists(caminhos_resumo)]) {
    nb <- tryCatch({
      rr <- data.table::fread(arq, nrows = 5, showProgress = FALSE, data.table = TRUE)
      if ("n_bloqueios" %in% names(rr)) sum(suppressWarnings(as.integer(rr$n_bloqueios)), na.rm = TRUE) else NA_integer_
    }, error = function(e) NA_integer_)
    if (!is.na(nb)) { n_bloq_arquivo <- nb; break }
  }

  sem_bloqueio <- isTRUE(gerado_global) || (!is.na(n_bloq_global) && n_bloq_global == 0L) || (!is.na(n_bloq_arquivo) && n_bloq_arquivo == 0L)
  isTRUE(produto_existe && sem_bloqueio)
}
### FIM v2.6.1 ---------------------------------------------------------

monitora_publicacao_aa_exportar_registros_corrig_aprovado <- function(registros_corrig,
                                                                caminho_saida,
                                                                contexto = "materializacao_registros_corrig",
                                                                abortar = TRUE) {
  dt <- data.table::as.data.table(registros_corrig)
  pendente_imp <- isTRUE(get0("MONITORA_REGISTROS_CORRIG_PENDENCIAS_IMPEDITIVAS", ifnotfound = FALSE, inherits = TRUE))
  contrato_corrig_ok <- isTRUE(get0("MONITORA_REGISTROS_CORRIG_CONTRATO_VALIDADO_XLSFORM21", ifnotfound = FALSE, inherits = TRUE)) &&
    !(exists("monitora_publicacao_z_selo_registros_corrig_valido", mode = "function") &&
      !isTRUE(monitora_publicacao_z_selo_registros_corrig_valido(dt)))
  validados_materializado_ok <- if (exists("monitora_registros_validados_materializado_sem_bloqueio", mode = "function")) {
    isTRUE(monitora_registros_validados_materializado_sem_bloqueio(output_dir = get0("MONITORA_OUTPUT_DIR", ifnotfound = dirname(caminho_saida), inherits = TRUE)))
  } else FALSE
  if (!isTRUE(pendente_imp) && isTRUE(validados_materializado_ok)) {
    contrato_corrig_ok <- TRUE
    assign("MONITORA_REGISTROS_CORRIG_CONTRATO_VALIDADO_XLSFORM21", TRUE, envir = .GlobalEnv)
    assign("MONITORA_REGISTROS_VALIDADOS_GERADO", TRUE, envir = .GlobalEnv)
  }
  ### v2.6.1: o exportador de registros_corrig.csv não deve emitir
  ### warning sobre registros_validados.csv. A geração/bloqueio real de
  ### registros_validados é decidida pelo bloco contratual próprio, com auditoria
  ### XLSForm21. Este ponto só grava registros_corrig; manter warning aqui gerava
  ### falso positivo no final da execução, mesmo com registros_validados.csv
  ### materializado e n_bloqueios=0.
  contrato_validados_bloqueado <- FALSE
  if (!isTRUE(pendente_imp) && !isTRUE(contrato_corrig_ok) && !isTRUE(validados_materializado_ok)) {
    if (exists("monitora_log_registrar_evento", mode = "function")) {
      try(monitora_log_registrar_evento(
        "registros_corrig_export_sem_trava_validados", "INFO", as.character(caminho_saida)[1L],
        paste0("Exportação de registros_corrig.csv sem pendências impeditivas no contexto ", contexto,
               "; status de registros_validados.csv será determinado apenas pelo bloco do Contrato XLSForm/SISMONITORA 2025 próprio."),
        "warning legado de falso bloqueio de registros_validados suprimido no exportador de registros_corrig"
      ), silent = TRUE)
    }
  }
  if (pendente_imp && exists("monitora_publicacao_ab_logar_resumo_pendencias", mode = "function")) {
    monitora_publicacao_ab_logar_resumo_pendencias(get0("MONITORA_REGISTROS_CORRIG_PENDENCIAS_IMPEDITIVAS_RESUMO", ifnotfound = data.table::data.table(), inherits = TRUE), contexto = contexto)
  }
  if (pendente_imp && !("monitora_status_registros_corrig" %in% names(dt)) &&
      exists("monitora_publicacao_ab_auditar_pendencias_impeditivas", mode = "function")) {
    try(monitora_publicacao_ab_auditar_pendencias_impeditivas(
      dt,
      contexto = paste0(contexto, "_remarcacao_pre_export"),
      output_dir = get0("MONITORA_OUTPUT_DIR", ifnotfound = dirname(caminho_saida), inherits = TRUE),
      log_dir = get0("MONITORA_LOG_DIR", ifnotfound = dirname(caminho_saida), inherits = TRUE),
      gravar = FALSE,
      marcar_base = TRUE
    ), silent = TRUE)
  }
  dt_export <- if (exists("monitora_publicacao_ae_preparar_registros_corrig_para_csv", mode = "function")) {
    monitora_publicacao_ae_preparar_registros_corrig_para_csv(
      dt,
      contexto = contexto,
      output_dir = get0("MONITORA_OUTPUT_DIR", ifnotfound = dirname(caminho_saida), inherits = TRUE),
      log_dir = get0("MONITORA_LOG_DIR", ifnotfound = dirname(caminho_saida), inherits = TRUE),
      exec_id = get0("MONITORA_EXEC_ID", ifnotfound = format(Sys.time(), "%Y%m%d_%H%M%S"), inherits = TRUE)
    )
  } else {
    dt
  }
  if (exists("monitora_produtos_resolver_pipes_por_ponto", mode = "function")) {
    dt_export <- monitora_produtos_resolver_pipes_por_ponto(
      dt_export,
      produto = "registros_corrig.csv",
      output_dir = get0("MONITORA_OUTPUT_DIR", ifnotfound = dirname(caminho_saida), inherits = TRUE),
      log_dir = get0("MONITORA_LOG_DIR", ifnotfound = dirname(caminho_saida), inherits = TRUE),
      exec_id = get0("MONITORA_EXEC_ID", ifnotfound = format(Sys.time(), "%Y%m%d_%H%M%S"), inherits = TRUE),
      contexto = paste0(contexto, "_pipes_operacionais"),
      corrigir = TRUE
    )
  }
  monitora_fwrite(dt_export, caminho_saida, row.names = FALSE, na = "NA")
  if (exists("monitora_log_registrar_evento", mode = "function")) {
    if (isTRUE(pendente_imp)) {
      monitora_log_registrar_evento("registros_corrig_exportado_checkpoint_pendente", "AVISO", caminho_saida, paste0("registros_corrig.csv materializado como checkpoint de trabalho COM PENDÊNCIAS IMPEDITIVAS: ", nrow(dt), " linhas e ", ncol(dt), " colunas; ver auditoria_pendencias_impeditivas_registros_corrig.csv; registros_validados.csv bloqueado"), contexto)
    } else {
      monitora_log_registrar_evento("registros_corrig_exportado_aprovado", "INFO", caminho_saida, paste0("registros_corrig.csv materializado após contrato aprovado: ", nrow(dt), " linhas e ", ncol(dt), " colunas; registros_validados.csv liberado/materializado quando habilitado; ausências físicas exportadas como NA"), contexto)
    }
  }
  invisible(TRUE)
}
### FIM v2.6.1 ------------------------

monitora_deduplicar_registros_amostrais <- function(dt, arquivos_entrada = NULL) {
  # Deduplicação semântica com tabela auxiliar estreita.
  # A tabela auxiliar contém apenas colunas necessárias para ordenar e selecionar registros.
  # Isso evita copiar todas as colunas durante a deduplicação.
  dt <- monitora_dt_referenciar(dt)
  source_col <- if ("MONITORA_ARQUIVO_ENTRADA" %in% names(dt)) {
    "MONITORA_ARQUIVO_ENTRADA"
  } else if (".id" %in% names(dt)) {
    ".id"
  } else {
    NA_character_
  }
  if (is.na(source_col)) {
    monitora_log_registrar_evento("deduplicacao_semantica", "AVISO", NA_character_, "Coluna de proveniência ausente; deduplicacao semantica por arquivo nao executada", "mantido sem alteracao")
    return(dt)
  }

  id_chr <- as.character(dt[[source_col]])
  tipo <- rep("desconhecido", nrow(dt))
  if (!is.null(arquivos_entrada) && all(c("basename", "tipo_entrada") %in% names(arquivos_entrada))) {
    tipo_map <- setNames(as.character(arquivos_entrada$tipo_entrada), as.character(arquivos_entrada$basename))
    tipo[!is.na(tipo_map[id_chr])] <- tipo_map[id_chr[!is.na(tipo_map[id_chr])]]
  }
  tipo <- monitora_io_normalizar_tipo_entrada(tipo)
  data.table::set(dt, j = "MONITORA_TIPO_ENTRADA", value = tipo)

  norm_key <- function(x) {
    x <- monitora_txt_normalizar_vazio(x)
    x <- stringr::str_squish(toupper(as.character(x)))
    x
  }
  get_col <- function(nm) if (nm %in% names(dt)) dt[[nm]] else rep(NA_character_, nrow(dt))

  ponto_col <- if ("ponto_amostral (amostragem/registro)" %in% names(dt)) {
    "ponto_amostral (amostragem/registro)"
  } else if ("ponto_metro (amostragem/registro)" %in% names(dt)) {
    "ponto_metro (amostragem/registro)"
  } else {
    NA_character_
  }

  uuid_registro <- monitora_txt_normalizar_vazio(monitora_vetor_coalesce(
    get_col("uuid (amostragem/registro)"),
    get_col("amostragem/registro/uuid")
  ))
  uuid_fallback <- monitora_txt_normalizar_vazio(monitora_vetor_coalesce(get_col("UUID"), get_col("uuid")))
  uuid_fallback[as.character(dt$MONITORA_TIPO_ENTRADA) == "bruto_lote_sismonitora"] <- NA_character_
  uuid_reg <- monitora_txt_normalizar_vazio(monitora_vetor_coalesce(uuid_registro, uuid_fallback))
  key_uuid <- ifelse(!is.na(uuid_reg), paste0("UUID_REGISTRO::", uuid_reg), NA_character_)
  rm(uuid_registro, uuid_fallback, uuid_reg); monitora_recurso_gc("dedup_chave_uuid")

  key_uc <- norm_key(get_col("UC"))
  key_ciclo <- norm_key(get_col("CICLO"))
  key_campanha <- norm_key(get_col("CAMPANHA"))
  key_ua <- norm_key(get_col("UA"))
  key_coleta <- norm_key(monitora_vetor_coalesce(get_col("COLETA"), get_col("coleta"), get_col("coleta_uuid")))
  key_ponto <- if (!is.na(ponto_col)) norm_key(get_col(ponto_col)) else rep(NA_character_, nrow(dt))
  key_campos_ok <- !is.na(key_uc) & !is.na(key_ciclo) & !is.na(key_campanha) & !is.na(key_ua) & !is.na(key_ponto)
  key_campos <- rep(NA_character_, nrow(dt))
  key_campos_com_coleta_ok <- key_campos_ok & !is.na(key_coleta) & nzchar(key_coleta)
  key_campos[key_campos_com_coleta_ok] <- paste(key_uc[key_campos_com_coleta_ok], key_ciclo[key_campos_com_coleta_ok], key_campanha[key_campos_com_coleta_ok], key_ua[key_campos_com_coleta_ok], key_coleta[key_campos_com_coleta_ok], key_ponto[key_campos_com_coleta_ok], sep = "||")
  key_campos_sem_coleta_ok <- key_campos_ok & is.na(key_campos)
  key_campos[key_campos_sem_coleta_ok] <- paste(key_uc[key_campos_sem_coleta_ok], key_ciclo[key_campos_sem_coleta_ok], key_campanha[key_campos_sem_coleta_ok], key_ua[key_campos_sem_coleta_ok], key_ponto[key_campos_sem_coleta_ok], sep = "||")
  # Para deduplicar corretamente exportações em lote e exportações individuais, a chave semântica
  # usa COLETA/coleta_uuid quando disponível. Isso mantém a deduplicação automática de registros
  # genuinamente idênticos da mesma coleta, mas evita colapsar automaticamente COLETAS distintas
  # que tenham recebido a mesma denominação de UA no mesmo ano por erro de campo.
  key <- ifelse(!is.na(key_campos), ifelse(key_campos_com_coleta_ok, paste0("UC_CICLO_CAMPANHA_UA_COLETA_PONTO::", key_campos), paste0("UC_CICLO_CAMPANHA_UA_PONTO::", key_campos)), ifelse(!is.na(key_uuid), key_uuid, NA_character_))
  rm(key_uuid, key_uc, key_ciclo, key_campanha, key_ua, key_coleta, key_ponto, key_campos_ok, key_campos_com_coleta_ok, key_campos_sem_coleta_ok, key_campos); monitora_recurso_gc("dedup_chave_campos")

  prioridade <- data.table::fifelse(tipo == "pos_tratamento_script", 1L,
                                    data.table::fifelse(tipo == "bruto_lote_sismonitora", 2L,
                                                        data.table::fifelse(tipo == "bruto_individual_sismonitora", 3L, 9L)))
  aux <- data.table::data.table(
    MONITORA_ORDEM_ORIGINAL = seq_len(nrow(dt)),
    MONITORA_CHAVE_DEDUP = key,
    MONITORA_PRIORIDADE_DEDUP = prioridade,
    MONITORA_TIPO_ENTRADA = tipo,
    MONITORA_FONTE = id_chr
  )
  rm(key, prioridade, tipo, id_chr); monitora_recurso_gc("dedup_aux_estreito_criado")

  cand <- aux[!is.na(MONITORA_CHAVE_DEDUP)]
  if (nrow(cand) == 0) {
    monitora_log_registrar_evento("deduplicacao_semantica", "AVISO", NA_character_, "Nenhuma chave amostral confiavel encontrada para deduplicacao semantica", "mantido sem alteracao")
    rm(aux, cand); monitora_recurso_gc("dedup_sem_chaves")
    return(dt)
  }

  data.table::setorder(cand, MONITORA_CHAVE_DEDUP, MONITORA_PRIORIDADE_DEDUP, MONITORA_ORDEM_ORIGINAL)
  manter_ordem <- cand[, .SD[1L], by = MONITORA_CHAVE_DEDUP]$MONITORA_ORDEM_ORIGINAL
  duplicadas <- cand[, .N, by = MONITORA_CHAVE_DEDUP][N > 1L]

  if (nrow(duplicadas) > 0) {
    n_dup_total <- nrow(duplicadas)
    exportar_chaves <- head(duplicadas$MONITORA_CHAVE_DEDUP, MONITORA_MAX_CHAVES_AUDITORIA_DUP_SEMANTICA)
    detalhes <- cand[MONITORA_CHAVE_DEDUP %in% exportar_chaves,
      .(
        n_registros = .N,
        arquivos = paste(unique(as.character(MONITORA_FONTE)), collapse = " | "),
        tipos_entrada = paste(unique(MONITORA_TIPO_ENTRADA), collapse = " | "),
        linhas_originais = paste(MONITORA_ORDEM_ORIGINAL, collapse = " | "),
        linha_mantida = min(MONITORA_ORDEM_ORIGINAL[order(MONITORA_PRIORIDADE_DEDUP, MONITORA_ORDEM_ORIGINAL)])
      ),
      by = MONITORA_CHAVE_DEDUP
    ][n_registros > 1L]
    detalhes[, auditoria_truncada := n_dup_total > MONITORA_MAX_CHAVES_AUDITORIA_DUP_SEMANTICA]
    detalhes[, n_chaves_duplicadas_total := n_dup_total]
    detalhes[, n_chaves_duplicadas_exportadas := nrow(detalhes)]
    monitora_fwrite(detalhes, file.path(MONITORA_LOG_DIR, paste0("auditoria_duplicidades_semanticas_", MONITORA_EXEC_ID, ".csv")))
    if (n_dup_total > MONITORA_MAX_CHAVES_AUDITORIA_DUP_SEMANTICA) {
      monitora_log_registrar_evento("deduplicacao_semantica", "AVISO", NA_character_, paste0("Auditoria de duplicidades semânticas truncada: ", n_dup_total, " chaves duplicadas no total; ", nrow(detalhes), " exportadas"), "aumentar MONITORA_MAX_CHAVES_AUDITORIA_DUP_SEMANTICA se precisar do detalhe completo")
    }
    monitora_log_registrar_evento(
      "deduplicacao_semantica",
      "AVISO",
      NA_character_,
      paste0(n_dup_total, " chaves amostrais duplicadas detectadas; ", nrow(detalhes), " exportadas na auditoria; mantida uma linha por chave"),
      "preferência: pos_tratamento_script > bruto_lote_sismonitora > bruto_individual_sismonitora > desconhecido; ver auditoria_duplicidades_semanticas"
    )
    rm(detalhes); monitora_recurso_gc("auditoria_duplicidades_semanticas")
  }

  sem_chave <- aux[is.na(MONITORA_CHAVE_DEDUP), MONITORA_ORDEM_ORIGINAL]
  keep <- sort(unique(c(sem_chave, manter_ordem)))
  removidas_n <- nrow(dt) - length(keep)
  if (removidas_n > 0) {
    monitora_log_registrar_evento("deduplicacao_semantica", "INFO", NA_character_, paste0(removidas_n, " linhas removidas por duplicidade semantica"), "linhas sem chave confiavel foram mantidas")
  }
  rm(aux, cand, duplicadas, sem_chave, manter_ordem); monitora_recurso_gc("dedup_antes_subconjunto_final")
  out <- dt[keep]
  out[]
}

monitora_data_ano_plausivel <- function(d, ano_min = 2000L, ano_max = lubridate::year(Sys.Date()) + 1L) {
  ano <- suppressWarnings(as.integer(format(d, "%Y")))
  !is.na(d) & !is.na(ano) & ano >= ano_min & ano <= ano_max
}


monitora_deduplicar_final_por_ponto_ano <- function(dt) {
  # Trava final de integridade antes da construção de registros_corrig_stat.
  # Objetivo: impedir que a mesma unidade amostral/ponto/ano entre duas vezes
  # quando arquivos pós-tratamento são combinados com brutos individuais/lote.
  # A deduplicação inicial ocorre antes de algumas padronizações e pode deixar
  # passar sobreposições raras; esta etapa usa os campos já normalizados e ANO.
  dt <- monitora_dt_referenciar(dt)

  ponto_col <- if ("ponto_amostral (amostragem/registro)" %in% names(dt)) {
    "ponto_amostral (amostragem/registro)"
  } else if ("ponto_metro (amostragem/registro)" %in% names(dt)) {
    "ponto_metro (amostragem/registro)"
  } else {
    NA_character_
  }

  by_cols <- c("UC", "CICLO", "CAMPANHA", "UA", "ANO")
  by_cols <- by_cols[by_cols %in% names(dt)]
  if (is.na(ponto_col) || length(by_cols) < 4L) {
    monitora_log_registrar_evento(
      "deduplicacao_final_ponto_ano",
      "AVISO",
      NA_character_,
      paste0("Campos insuficientes para deduplicação final: by_cols=", paste(by_cols, collapse = ", "), "; ponto_col=", ponto_col),
      "mantido sem alteração"
    )
    return(dt)
  }

  norm_key <- function(x) {
    x <- monitora_txt_normalizar_vazio(x)
    stringr::str_squish(toupper(as.character(x)))
  }

  aux <- data.table::data.table(MONITORA_ORDEM_ORIGINAL = seq_len(nrow(dt)))
  for (cc in by_cols) {
    data.table::set(aux, j = cc, value = norm_key(dt[[cc]]))
  }
  data.table::set(aux, j = "ponto", value = norm_key(dt[[ponto_col]]))

  campos_chave <- c(by_cols, "ponto")
  ok <- Reduce(`&`, lapply(campos_chave, function(cc) !is.na(aux[[cc]]) & nzchar(aux[[cc]])))
  aux[, MONITORA_CHAVE_FINAL := NA_character_]
  if (any(ok)) {
    aux[ok, MONITORA_CHAVE_FINAL := do.call(paste, c(.SD, sep = "||")), .SDcols = campos_chave]
  }

  tipo <- if ("MONITORA_TIPO_ENTRADA" %in% names(dt)) monitora_io_normalizar_tipo_entrada(dt[["MONITORA_TIPO_ENTRADA"]]) else rep("desconhecido", nrow(dt))
  fonte <- if ("MONITORA_ARQUIVO_ENTRADA" %in% names(dt)) {
    as.character(dt[["MONITORA_ARQUIVO_ENTRADA"]])
  } else if (".id" %in% names(dt)) {
    as.character(dt[[".id"]])
  } else {
    rep(NA_character_, nrow(dt))
  }

  prioridade <- data.table::fifelse(tipo == "pos_tratamento_script", 1L,
    data.table::fifelse(tipo == "bruto_lote_sismonitora", 2L,
      data.table::fifelse(tipo == "bruto_individual_sismonitora", 3L, 9L)
    )
  )
  data.table::set(aux, j = "MONITORA_TIPO_ENTRADA", value = tipo)
  data.table::set(aux, j = "MONITORA_FONTE", value = fonte)
  data.table::set(aux, j = "MONITORA_PRIORIDADE_DEDUP", value = prioridade)
  coleta_col <- if ("COLETA" %in% names(dt)) "COLETA" else NA_character_
  data.table::set(aux, j = "MONITORA_COLETA", value = if (!is.na(coleta_col)) as.character(dt[[coleta_col]]) else NA_character_)
  aux[, MONITORA_BLOQUEAR_DEDUP_COLETA_UA_ANO := FALSE]
  if (all(c("UC", "UA", "ANO") %in% names(aux)) && !all(is.na(aux$MONITORA_COLETA))) {
    grupos_coleta <- aux[!is.na(UC) & nzchar(UC) & !is.na(UA) & nzchar(UA) & !is.na(ANO) & nzchar(ANO) & !is.na(MONITORA_COLETA) & nzchar(MONITORA_COLETA),
      .(n_coletas = data.table::uniqueN(MONITORA_COLETA)), by = .(UC, UA, ANO)][n_coletas > 1L]
    if (nrow(grupos_coleta) > 0L) {
      aux[grupos_coleta, on = .(UC, UA, ANO), MONITORA_BLOQUEAR_DEDUP_COLETA_UA_ANO := TRUE]
      monitora_log_registrar_evento(
        "deduplicacao_final_ponto_ano",
        "AVISO",
        NA_character_,
        paste0(nrow(grupos_coleta), " combinação(ões) UC+UA+ANO com múltiplas COLETAS detectada(s); deduplicação automática por ponto bloqueada para esses casos"),
        "esses conflitos devem ser resolvidos no painel e serão travados após correções"
      )
    }
  }

  cand <- aux[!is.na(MONITORA_CHAVE_FINAL)]
  if (nrow(cand) == 0) {
    monitora_log_registrar_evento("deduplicacao_final_ponto_ano", "AVISO", NA_character_, "Nenhuma chave final UC/CICLO/CAMPANHA/UA/ANO/ponto confiável encontrada", "mantido sem alteração")
    rm(aux, cand); monitora_recurso_gc("dedup_final_sem_chaves")
    return(dt)
  }

  duplicadas_todas <- cand[, .(N = .N, bloquear_dedup_coleta_ua_ano = any(MONITORA_BLOQUEAR_DEDUP_COLETA_UA_ANO, na.rm = TRUE)), by = MONITORA_CHAVE_FINAL][N > 1L]
  duplicadas_bloqueadas <- duplicadas_todas[bloquear_dedup_coleta_ua_ano == TRUE]
  duplicadas <- duplicadas_todas[bloquear_dedup_coleta_ua_ano == FALSE]
  if (nrow(duplicadas_bloqueadas) > 0L) {
    detalhes_bloq <- cand[MONITORA_CHAVE_FINAL %in% duplicadas_bloqueadas$MONITORA_CHAVE_FINAL, .(
      n_registros = .N,
      coletas = paste(sort(unique(MONITORA_COLETA[!is.na(MONITORA_COLETA) & nzchar(MONITORA_COLETA)])), collapse = " | "),
      tipos_entrada = paste(unique(MONITORA_TIPO_ENTRADA), collapse = " | "),
      arquivos = paste(unique(as.character(MONITORA_FONTE)), collapse = " | "),
      linhas_originais = paste(MONITORA_ORDEM_ORIGINAL, collapse = " | "),
      motivo_bloqueio = "múltiplas COLETAS para a mesma UC+UA+ANO; não remover automaticamente"
    ), by = MONITORA_CHAVE_FINAL]
    saida_bloq <- file.path(MONITORA_LOG_DIR, paste0("auditoria_deduplicacao_final_bloqueada_coletas_ua_ano_", MONITORA_EXEC_ID, ".csv"))
    monitora_fwrite(detalhes_bloq, saida_bloq)
    monitora_fwrite(detalhes_bloq, file.path(MONITORA_OUTPUT_DIR, "auditoria_deduplicacao_final_bloqueada_coletas_ua_ano_ultima_execucao.csv"))
    monitora_log_registrar_evento("deduplicacao_final_ponto_ano", "AVISO", saida_bloq, paste0(nrow(duplicadas_bloqueadas), " chave(s) finais duplicadas não deduplicadas por conflito de COLETAS em UC+UA+ANO"), "resolver no painel; trava pós-correções impedirá estatísticas se persistir")
    rm(detalhes_bloq)
  }
  if (nrow(duplicadas) == 0) {
    monitora_log_registrar_evento("deduplicacao_final_ponto_ano", "INFO", NA_character_, "Nenhuma duplicidade final segura UC/CICLO/CAMPANHA/UA/ANO/ponto encontrada para remoção automática", "conflitos de COLETAS por UC+UA+ANO foram preservados para triagem")
    rm(aux, cand, duplicadas_todas, duplicadas, duplicadas_bloqueadas); monitora_recurso_gc("dedup_final_sem_duplicidade")
    return(dt)
  }

  cand_auto <- cand[MONITORA_CHAVE_FINAL %in% duplicadas$MONITORA_CHAVE_FINAL | !(MONITORA_CHAVE_FINAL %in% duplicadas_todas$MONITORA_CHAVE_FINAL)]
  data.table::setorder(cand_auto, MONITORA_CHAVE_FINAL, MONITORA_PRIORIDADE_DEDUP, MONITORA_ORDEM_ORIGINAL)
  manter_ordem <- cand_auto[, .SD[1L], by = MONITORA_CHAVE_FINAL]$MONITORA_ORDEM_ORIGINAL
  sem_chave <- aux[is.na(MONITORA_CHAVE_FINAL), MONITORA_ORDEM_ORIGINAL]
  manter_bloqueadas <- if (exists("duplicadas_bloqueadas") && nrow(duplicadas_bloqueadas) > 0L) cand[MONITORA_CHAVE_FINAL %in% duplicadas_bloqueadas$MONITORA_CHAVE_FINAL, MONITORA_ORDEM_ORIGINAL] else integer(0)
  keep <- sort(unique(c(sem_chave, manter_ordem, manter_bloqueadas)))

  exportar_chaves <- head(duplicadas$MONITORA_CHAVE_FINAL, MONITORA_MAX_CHAVES_AUDITORIA_DUP_SEMANTICA)
  detalhes <- cand[MONITORA_CHAVE_FINAL %in% exportar_chaves,
    .(
      n_registros = .N,
      tipos_entrada = paste(unique(MONITORA_TIPO_ENTRADA), collapse = " | "),
      arquivos = paste(unique(as.character(MONITORA_FONTE)), collapse = " | "),
      linhas_originais = paste(MONITORA_ORDEM_ORIGINAL, collapse = " | "),
      linha_mantida = MONITORA_ORDEM_ORIGINAL[order(MONITORA_PRIORIDADE_DEDUP, MONITORA_ORDEM_ORIGINAL)][1L],
      tipo_mantido = MONITORA_TIPO_ENTRADA[order(MONITORA_PRIORIDADE_DEDUP, MONITORA_ORDEM_ORIGINAL)][1L],
      arquivo_mantido = MONITORA_FONTE[order(MONITORA_PRIORIDADE_DEDUP, MONITORA_ORDEM_ORIGINAL)][1L]
    ),
    by = MONITORA_CHAVE_FINAL
  ][n_registros > 1L]
  detalhes[, auditoria_truncada := nrow(duplicadas) > MONITORA_MAX_CHAVES_AUDITORIA_DUP_SEMANTICA]
  detalhes[, n_chaves_duplicadas_total := nrow(duplicadas)]
  detalhes[, n_chaves_duplicadas_exportadas := nrow(detalhes)]

  saida <- file.path(MONITORA_LOG_DIR, paste0("auditoria_deduplicacao_final_ponto_ano_", MONITORA_EXEC_ID, ".csv"))
  monitora_fwrite(detalhes, saida)
  monitora_fwrite(detalhes, file.path(MONITORA_OUTPUT_DIR, "auditoria_deduplicacao_final_ponto_ano_ultima_execucao.csv"))

  removidas_n <- nrow(dt) - length(keep)
  monitora_log_registrar_evento(
    "deduplicacao_final_ponto_ano",
    "AVISO",
    saida,
    paste0(nrow(duplicadas), " chaves UC/CICLO/CAMPANHA/UA/ANO/ponto duplicadas detectadas; ", removidas_n, " linha(s) removida(s) antes de registros_corrig_stat"),
    "preferência final: pos_tratamento_script > bruto_lote_sismonitora > bruto_individual_sismonitora > desconhecido"
  )

  rm(aux, cand, cand_auto, duplicadas_todas, duplicadas, duplicadas_bloqueadas, detalhes, manter_ordem, manter_bloqueadas, sem_chave); monitora_recurso_gc("dedup_final_antes_subconjunto")
  out <- dt[keep]
  out[]
}


monitora_auditar_coletas_ua_ano_duplicadas <- function(dt, fase = "pos_correcoes", abortar = FALSE) {
  dt <- data.table::as.data.table(dt)
  chaves <- tryCatch(monitora_correcao_colunas_chave(dt), error = function(e) list())
  coleta_col <- if (!is.null(chaves$coleta) && !is.na(chaves$coleta) && chaves$coleta %in% names(dt)) chaves$coleta else if ("COLETA" %in% names(dt)) "COLETA" else NA_character_
  ua_col <- if (!is.null(chaves$ua) && !is.na(chaves$ua) && chaves$ua %in% names(dt)) chaves$ua else if ("UA" %in% names(dt)) "UA" else NA_character_
  ano_col <- if (!is.null(chaves$ano) && !is.na(chaves$ano) && chaves$ano %in% names(dt)) chaves$ano else if ("ANO" %in% names(dt)) "ANO" else NA_character_
  uc_col <- if (!is.null(chaves$uc) && !is.na(chaves$uc) && chaves$uc %in% names(dt)) chaves$uc else if ("UC" %in% names(dt)) "UC" else NA_character_
  fase_segura <- gsub("[^A-Za-z0-9_]+", "_", as.character(fase))
  saida_log_vazio <- file.path(MONITORA_LOG_DIR, paste0("auditoria_coletas_ua_ano_duplicadas_", fase_segura, "_", MONITORA_EXEC_ID, ".csv"))
  saida_out_vazio <- file.path(MONITORA_OUTPUT_DIR, paste0("auditoria_coletas_ua_ano_duplicadas_", fase_segura, "_ultima_execucao.csv"))

  aud_vazio_template <- function() {
    data.table::data.table(
      UC = character(), UA = character(), ANO = character(),
      n_coletas = integer(), n_linhas = integer(), coletas = character(),
      coleta_uuid = character(), EAs = character(), ciclos = character(), campanhas = character(),
      arquivos = character(), tipos_entrada = character(), datas_data_hora = character(),
      DATA_MONITORA_PARSEADA = character(), ANO_recalculado_de_Data = character(),
      n_linhas_ano_divergente = integer(), linhas_ano_divergente = character(),
      linhas_indice = character(), acao_recomendada = character()
    )
  }

  gravar_vazio <- function(motivo) {
    aud_vazio <- aud_vazio_template()
    try(monitora_fwrite(aud_vazio, saida_log_vazio, na = ""), silent = TRUE)
    try(monitora_fwrite(aud_vazio, saida_out_vazio, na = ""), silent = TRUE)
    if (exists("MONITORA_CORRECOES_DIR", inherits = TRUE)) {
      try(monitora_fwrite(aud_vazio, file.path(MONITORA_CORRECOES_DIR, paste0("auditoria_coletas_ua_ano_duplicadas_", fase_segura, ".csv")), na = ""), silent = TRUE)
    }
    monitora_log_registrar_evento("coletas_ua_ano_duplicadas", "INFO", saida_log_vazio, motivo, "CSV vazio gravado para auditoria pós-correções")
    aud_vazio
  }

  if (any(is.na(c(coleta_col, ua_col, ano_col, uc_col)))) {
    monitora_log_registrar_evento(
      "coletas_ua_ano_duplicadas",
      "AVISO",
      NA_character_,
      paste0("Campos insuficientes para auditar COLETAS com UA duplicada no mesmo ANO: UC=", uc_col, "; UA=", ua_col, "; ANO=", ano_col, "; COLETA=", coleta_col),
      "auditoria não executada"
    )
    return(data.table::data.table())
  }

  norm <- function(x) {
    # Normalização mínima e rápida para chaves de auditoria. Evita stringr::str_squish()
    # sobre dezenas de milhares de linhas quando a auditoria geralmente retorna vazia.
    x <- as.character(x)
    x <- trimws(x)
    x[is.na(x) | !nzchar(x)] <- NA_character_
    toupper(x)
  }
  norm_coleta <- function(x) {
    x <- as.character(x)
    x <- trimws(x)
    x[is.na(x) | !nzchar(x)] <- NA_character_
    x
  }

  # Caminho rápido real: usa vetores base para detectar se existe mais de uma
  # COLETA por UC+UA+ANO. Em bases sem conflito, retorna antes de qualquer
  # data.table::unique(), join, parse de data ou montagem de contexto detalhado.
  v_uc <- norm(dt[[uc_col]])
  v_ua <- norm(dt[[ua_col]])
  v_ano <- norm(dt[[ano_col]])
  v_coleta <- norm_coleta(dt[[coleta_col]])
  valido <- !is.na(v_uc) & !is.na(v_ua) & !is.na(v_ano) & !is.na(v_coleta)
  if (!any(valido)) {
    rm(v_uc, v_ua, v_ano, v_coleta, valido)
    return(gravar_vazio(paste0("Nenhuma linha elegível para auditoria de COLETA duplicada por UC+UA+ANO detectada em ", fase)))
  }

  idx_validos <- which(valido)
  chave_coleta <- paste(v_uc[valido], v_ua[valido], v_ano[valido], v_coleta[valido], sep = "
")
  manter_coleta_unica <- !duplicated(chave_coleta)
  grupo_unico <- paste(v_uc[valido][manter_coleta_unica], v_ua[valido][manter_coleta_unica], v_ano[valido][manter_coleta_unica], sep = "
")
  grupo_duplicado_flag <- duplicated(grupo_unico) | duplicated(grupo_unico, fromLast = TRUE)
  if (!any(grupo_duplicado_flag)) {
    rm(v_uc, v_ua, v_ano, v_coleta, valido, idx_validos, chave_coleta, manter_coleta_unica, grupo_unico, grupo_duplicado_flag)
    return(gravar_vazio(paste0("Nenhuma COLETA duplicada por UC+UA+ANO detectada em ", fase)))
  }

  grupos_chave <- unique(grupo_unico[grupo_duplicado_flag])
  aux <- data.table::data.table(
    linha_indice = idx_validos,
    UC = v_uc[valido],
    UA = v_ua[valido],
    ANO = v_ano[valido],
    COLETA = v_coleta[valido]
  )
  aux[, MONITORA_GRUPO_UA_ANO := paste(UC, UA, ANO, sep = "
")]
  det <- aux[MONITORA_GRUPO_UA_ANO %in% grupos_chave]
  grupos <- det[, .(n_linhas = .N, n_coletas = data.table::uniqueN(COLETA)), by = .(UC, UA, ANO)][n_coletas > 1L]
  if (!nrow(grupos)) {
    rm(v_uc, v_ua, v_ano, v_coleta, valido, idx_validos, chave_coleta, manter_coleta_unica, grupo_unico, grupo_duplicado_flag, grupos_chave, aux, det, grupos)
    return(gravar_vazio(paste0("Nenhuma COLETA duplicada por UC+UA+ANO detectada em ", fase)))
  }
  det <- det[grupos, on = .(UC, UA, ANO), nomatch = 0L]
  det[, MONITORA_GRUPO_UA_ANO := NULL]
  rm(v_uc, v_ua, v_ano, v_coleta, valido, idx_validos, chave_coleta, manter_coleta_unica, grupo_unico, grupo_duplicado_flag, grupos_chave)
  idx <- det$linha_indice
  n_idx <- length(idx)

  contexto_col <- function(nome) {
    if (!is.null(chaves[[nome]]) && !is.na(chaves[[nome]]) && chaves[[nome]] %in% names(dt)) {
      as.character(dt[[chaves[[nome]]]][idx])
    } else {
      rep(NA_character_, n_idx)
    }
  }

  data_col <- if (!is.null(chaves$data_hora) && !is.na(chaves$data_hora) && chaves$data_hora %in% names(dt)) chaves$data_hora else NA_character_
  data_val <- if (!is.na(data_col)) as.character(dt[[data_col]][idx]) else rep(NA_character_, n_idx)
  data_parseada_val <- if ("DATA_MONITORA_PARSEADA" %in% names(dt)) as.character(dt[["DATA_MONITORA_PARSEADA"]][idx]) else rep(NA_character_, n_idx)

  ano_recalc_val <- rep(NA_character_, n_idx)
  if ("DATA_MONITORA_PARSEADA" %in% names(dt)) {
    ano_recalc_val <- tryCatch(as.character(lubridate::year(as.Date(dt[["DATA_MONITORA_PARSEADA"]][idx]))), error = function(e) rep(NA_character_, n_idx))
  }
  if (all(is.na(ano_recalc_val)) && !is.na(data_col) && exists("monitora_data_parsear", mode = "function")) {
    ano_recalc_val <- tryCatch(as.character(lubridate::year(monitora_data_parsear(dt[[data_col]][idx]))), error = function(e) rep(NA_character_, n_idx))
  }
  ano_recalc_norm <- norm(ano_recalc_val)

  det[, `:=`(
    Data_data_hora = data_val,
    DATA_MONITORA_PARSEADA = data_parseada_val,
    ANO_recalculado_de_Data = ano_recalc_norm,
    diverge_ano_data = ANO != ano_recalc_norm,
    EA = contexto_col("ea"),
    CICLO = contexto_col("ciclo"),
    CAMPANHA = contexto_col("campanha"),
    coleta_uuid = contexto_col("coleta_uuid"),
    arquivo_origem = if ("MONITORA_ARQUIVO_ENTRADA" %in% names(dt)) as.character(dt[["MONITORA_ARQUIVO_ENTRADA"]][idx]) else if (".id" %in% names(dt)) as.character(dt[[".id"]][idx]) else rep(NA_character_, n_idx),
    tipo_entrada = if ("MONITORA_TIPO_ENTRADA" %in% names(dt)) as.character(dt[["MONITORA_TIPO_ENTRADA"]][idx]) else rep(NA_character_, n_idx)
  )]
  det[is.na(ANO_recalculado_de_Data), diverge_ano_data := FALSE]

  aud <- det[, .(
    n_coletas = data.table::uniqueN(COLETA),
    n_linhas = .N,
    coletas = paste(sort(unique(COLETA)), collapse = " | "),
    coleta_uuid = paste(sort(unique(coleta_uuid[!is.na(coleta_uuid) & nzchar(coleta_uuid)])), collapse = " | "),
    EAs = paste(sort(unique(EA[!is.na(EA) & nzchar(EA)])), collapse = " | "),
    ciclos = paste(sort(unique(CICLO[!is.na(CICLO) & nzchar(CICLO)])), collapse = " | "),
    campanhas = paste(sort(unique(CAMPANHA[!is.na(CAMPANHA) & nzchar(CAMPANHA)])), collapse = " | "),
    arquivos = paste(sort(unique(arquivo_origem[!is.na(arquivo_origem) & nzchar(arquivo_origem)])), collapse = " | "),
    tipos_entrada = paste(sort(unique(tipo_entrada[!is.na(tipo_entrada) & nzchar(tipo_entrada)])), collapse = " | "),
    datas_data_hora = paste(sort(unique(Data_data_hora[!is.na(Data_data_hora) & nzchar(Data_data_hora)])), collapse = " | "),
    DATA_MONITORA_PARSEADA = paste(sort(unique(DATA_MONITORA_PARSEADA[!is.na(DATA_MONITORA_PARSEADA) & nzchar(DATA_MONITORA_PARSEADA)])), collapse = " | "),
    ANO_recalculado_de_Data = paste(sort(unique(ANO_recalculado_de_Data[!is.na(ANO_recalculado_de_Data) & nzchar(ANO_recalculado_de_Data)])), collapse = " | "),
    n_linhas_ano_divergente = sum(diverge_ano_data, na.rm = TRUE),
    linhas_ano_divergente = paste(sort(unique(linha_indice[diverge_ano_data %in% TRUE])), collapse = " | "),
    linhas_indice = paste(sort(unique(linha_indice)), collapse = " | "),
    acao_recomendada = "Resolver no painel: corrigir Data (data_hora), excluir COLETA equivocada, corrigir UA da COLETA ou revisar metadados superiores. Se Data (data_hora) for corrigida, DATA_MONITORA_PARSEADA e ANO são recalculados antes da trava pós-correções."
  ), by = .(UC, UA, ANO)]
  data.table::setorder(aud, UC, UA, ANO)

  saida_log <- file.path(MONITORA_LOG_DIR, paste0("auditoria_coletas_ua_ano_duplicadas_", fase_segura, "_", MONITORA_EXEC_ID, ".csv"))
  saida_out <- file.path(MONITORA_OUTPUT_DIR, paste0("auditoria_coletas_ua_ano_duplicadas_", fase_segura, "_ultima_execucao.csv"))
  try(monitora_fwrite(aud, saida_log, na = ""), silent = TRUE)
  try(monitora_fwrite(aud, saida_out, na = ""), silent = TRUE)
  if (exists("MONITORA_CORRECOES_DIR", inherits = TRUE)) {
    try(monitora_fwrite(aud, file.path(MONITORA_CORRECOES_DIR, paste0("auditoria_coletas_ua_ano_duplicadas_", fase_segura, ".csv")), na = ""), silent = TRUE)
  }

  msg <- paste0(
    nrow(aud), " combinação(ões) UC+UA+ANO com mais de uma COLETA detectada(s) em ", fase,
    ". Esses casos NÃO são deduplicados automaticamente, pois podem indicar UA selecionada incorretamente ou reamostragem indevida da mesma UA no mesmo ano. ",
    "Resolva no painel por exclusão de COLETA, correção do atributo UA ou outra modificação auditável. Auditoria: ", saida_log
  )
  permitir_checkpoint_pendente <- isTRUE(get0("MONITORA_PERMITIR_REGISTROS_CORRIG_CHECKPOINT_PENDENTE", ifnotfound = TRUE, inherits = TRUE))
  nivel_log <- if (isTRUE(abortar) && !isTRUE(permitir_checkpoint_pendente)) "ERRO" else "AVISO"
  acao_log <- if (isTRUE(permitir_checkpoint_pendente)) {
    "pendência impeditiva para registros_corrig final; será incorporada ao checkpoint marcado quando registros_corrig.csv for materializado"
  } else {
    "triagem obrigatória antes de estatísticas"
  }
  monitora_log_registrar_evento("coletas_ua_ano_duplicadas", nivel_log, saida_log, msg, acao_log)
  if (isTRUE(abortar) && !isTRUE(permitir_checkpoint_pendente)) {
    stop(paste0("COLETAS com UA duplicada no mesmo ANO não resolvidas. ", msg), call. = FALSE)
  }
  aud[]
}

monitora_data_parsear <- function(x) {
  x0 <- monitora_txt_normalizar_vazio(x)
  x1 <- stringr::str_squish(x0)
  x1 <- stringr::str_replace(x1, "T", " ")
  x1 <- stringr::str_replace(x1, "Z$", "")
  x_date_only <- stringr::str_replace(x1, "^([^ ]+).*$", "\\1")
  out <- rep(as.IDate(NA), length(x1))

  # Datas numéricas do Excel: dias desde 1899-12-30.
  suppressWarnings(num <- as.numeric(x1))
  is_excel <- !is.na(num) & num > 20000 & num < 80000
  if (any(is_excel)) {
    d_excel <- as.IDate(as.Date(num[is_excel], origin = "1899-12-30"))
    ok_excel <- monitora_data_ano_plausivel(d_excel)
    out[which(is_excel)[ok_excel]] <- d_excel[ok_excel]
  }

  # Datas com ano de 4 dígitos no final, comuns em CSVs manipulados em planilhas.
  # valores como 3/3/2020 em ano 0003.
  idx_final4 <- which(is.na(out) & !is.na(x_date_only) & grepl("^\\d{1,2}[/-]\\d{1,2}[/-]\\d{4}$", x_date_only))
  if (length(idx_final4) > 0) {
    v <- x_date_only[idx_final4]
    suppressWarnings(d_br <- as.IDate(v, format = "%d/%m/%Y"))
    suppressWarnings(d_us <- as.IDate(v, format = "%m/%d/%Y"))
    # Para dia e mês iguais, d_br == d_us; ainda assim adota-se explicitamente d/m/Y.
    ok_br <- monitora_data_ano_plausivel(d_br)
    ok_us <- monitora_data_ano_plausivel(d_us)
    amb <- ok_br & ok_us & d_br != d_us
    if (any(amb, na.rm = TRUE)) {
      monitora_log_registrar_evento(
        "datas", "AVISO", NA_character_,
        paste0(sum(amb), " datas ambiguas dd/mm/yyyy vs mm/dd/yyyy; adotado dd/mm/yyyy por padrão brasileiro"),
        "verificar registros se o arquivo tiver sido exportado/configurado em locale norte-americano"
      )
    }
    escolhido <- rep(as.IDate(NA), length(v))
    escolhido[ok_br] <- d_br[ok_br]
    escolhido[!ok_br & ok_us] <- d_us[!ok_br & ok_us]
    ok_escolhido <- monitora_data_ano_plausivel(escolhido)
    out[idx_final4[ok_escolhido]] <- escolhido[ok_escolhido]
  }

  # ISO primeiro, depois padrão brasileiro, depois padrão norte-americano.
  # Formatos com ano de 4 dígitos ao final já foram priorizados acima.
  formats <- c(
    "%Y-%m-%d", "%Y/%m/%d", "%Y.%m.%d",
    "%Y-%m-%d %H:%M:%S", "%Y/%m/%d %H:%M:%S", "%Y-%m-%d %H:%M",
    "%d/%m/%Y", "%d-%m-%Y", "%d.%m.%Y",
    "%d/%m/%y", "%d-%m-%y", "%d.%m.%y",
    "%m/%d/%Y", "%m-%d-%Y", "%m.%d.%Y",
    "%m/%d/%y", "%m-%d-%y", "%m.%d.%y",
    "%d/%m/%Y %H:%M:%S", "%d-%m-%Y %H:%M:%S", "%d/%m/%Y %H:%M",
    "%m/%d/%Y %H:%M:%S", "%m-%d-%Y %H:%M:%S", "%m/%d/%Y %H:%M"
  )
  for (fmt in formats) {
    idx <- which(is.na(out) & !is.na(x1))
    if (length(idx) == 0) break
    suppressWarnings(parsed <- as.IDate(x1[idx], format = fmt))
    ok <- monitora_data_ano_plausivel(parsed)
    if (any(ok)) out[idx[ok]] <- parsed[ok]
  }

  # padronizados.
  for (fmt in formats[1:18]) {
    idx <- which(is.na(out) & !is.na(x_date_only))
    if (length(idx) == 0) break
    suppressWarnings(parsed <- as.IDate(x_date_only[idx], format = fmt))
    ok <- monitora_data_ano_plausivel(parsed)
    if (any(ok)) out[idx[ok]] <- parsed[ok]
  }

  n_fail <- sum(is.na(out) & !is.na(x1))
  if (n_fail > 0) {
    monitora_log_registrar_evento("datas", "AVISO", NA_character_, paste0(n_fail, " datas nao convertidas ou com ano fora da faixa plausivel"), "ANO ficará NA nesses registros; ver auditoria_anos_invalidos")
  }
  out
}


monitora_recalcular_derivados_data_hora <- function(dt, contexto = "recalculo_data_hora") {
  dt <- monitora_dt_referenciar(dt)
  chaves <- tryCatch(monitora_correcao_colunas_chave(dt), error = function(e) list(data_hora = NA_character_))
  data_col <- if (!is.null(chaves$data_hora) && !is.na(chaves$data_hora) && chaves$data_hora %in% names(dt)) chaves$data_hora else NA_character_
  if (is.na(data_col) || !nzchar(data_col)) {
    if (exists("monitora_log_registrar_evento", mode = "function")) {
      monitora_log_registrar_evento("datas", "AVISO", NA_character_, paste0("Coluna de data não encontrada para recálculo em ", contexto), "DATA_MONITORA_PARSEADA/ANO mantidos")
    }
    return(dt[])
  }
  ano_antes <- if ("ANO" %in% names(dt)) as.character(dt[["ANO"]]) else rep(NA_character_, nrow(dt))
  data_antes <- if ("DATA_MONITORA_PARSEADA" %in% names(dt)) as.character(dt[["DATA_MONITORA_PARSEADA"]]) else rep(NA_character_, nrow(dt))
  data_depois <- monitora_data_parsear(dt[[data_col]])
  ano_depois <- as.character(lubridate::year(data_depois))
  data.table::set(dt, j = "DATA_MONITORA_PARSEADA", value = data_depois)
  data.table::set(dt, j = "ANO", value = ano_depois)
  diferente <- function(a, b) {
    a <- as.character(a); b <- as.character(b)
    (is.na(a) != is.na(b)) | (!is.na(a) & !is.na(b) & a != b)
  }
  mudou <- diferente(ano_antes, ano_depois) | diferente(data_antes, as.character(data_depois))
  if (any(mudou, na.rm = TRUE)) {
    idx <- which(mudou)
    aud <- data.table::data.table(
      contexto = contexto,
      linha_indice = idx,
      coluna_data = data_col,
      Data_data_hora = as.character(dt[[data_col]][idx]),
      DATA_MONITORA_PARSEADA_antes = data_antes[idx],
      DATA_MONITORA_PARSEADA_depois = as.character(data_depois[idx]),
      ANO_antes = ano_antes[idx],
      ANO_depois = ano_depois[idx]
    )
    if (exists("MONITORA_LOG_DIR", inherits = TRUE) && exists("MONITORA_EXEC_ID", inherits = TRUE)) {
      arq <- file.path(MONITORA_LOG_DIR, paste0("auditoria_recalculo_data_hora_", gsub("[^A-Za-z0-9_]+", "_", contexto), "_", MONITORA_EXEC_ID, ".csv"))
      try(monitora_fwrite(aud, arq, na = ""), silent = TRUE)
      if (exists("MONITORA_CORRECOES_DIR", inherits = TRUE)) {
        try(monitora_fwrite(aud, file.path(MONITORA_CORRECOES_DIR, "auditoria_recalculo_data_hora_ultima_execucao.csv"), na = ""), silent = TRUE)
      }
    }
    if (exists("monitora_log_registrar_evento", mode = "function")) {
      monitora_log_registrar_evento("datas", "INFO", NA_character_, paste0(length(idx), " linha(s) com DATA_MONITORA_PARSEADA/ANO recalculados em ", contexto), "derivado de Data (data_hora)")
    }
  }
  dt[]
}

monitora_geo_normalizar_coordenada <- function(x) {
  x0 <- monitora_txt_normalizar_vazio(x)
  out <- rep(NA_character_, length(x0))
  sep_type <- rep(NA_character_, length(x0))
  token_count <- rep(NA_integer_, length(x0))
  for (i in seq_along(x0)) {
    v <- x0[i]
    if (is.na(v)) next
    v <- stringr::str_squish(v)
    nums <- stringr::str_extract_all(v, "[-+]?\\d+(?:[\\.,]\\d+)?")[[1]]
    token_count[i] <- length(nums)
    if (grepl(";", v)) sep_type[i] <- "ponto_e_virgula"
    else if (grepl("\\|", v)) sep_type[i] <- "pipe"
    else if (grepl(",", v) && grepl("\\.", v)) sep_type[i] <- "virgula_separador_decimal_ponto"
    else if (grepl("[-+]?\\d+,\\d+", v) && !grepl("\\.", v)) sep_type[i] <- "virgula_decimal_ou_separador"
    else sep_type[i] <- "espaco"
    if (length(nums) < 2) next
    nums <- gsub(",", ".", nums, fixed = TRUE)
    nums <- nums[1:min(length(nums), 4)]
    out[i] <- paste(nums, collapse = " ")
  }
  attr(out, "coord_audit") <- data.table(separador_detectado = sep_type, n_tokens = token_count)
  out
}

monitora_io_extrair_zips_recursivos <- function(source_dirs, extract_dir) {
  if (dir.exists(extract_dir)) unlink(extract_dir, recursive = TRUE, force = TRUE)
  dir.create(extract_dir, recursive = TRUE, showWarnings = FALSE)
  seen <- character()
  repeat {
    zips <- unique(unlist(lapply(source_dirs, function(d) {
      if (!dir.exists(d)) character() else list.files(d, pattern = "\\.zip$", recursive = TRUE, full.names = TRUE, ignore.case = TRUE)
    })))
    zips <- zips[!grepl(paste0("^", normalizePath(extract_dir, winslash = "/", mustWork = FALSE)), normalizePath(zips, winslash = "/", mustWork = FALSE))]
    inner <- list.files(extract_dir, pattern = "\\.zip$", recursive = TRUE, full.names = TRUE, ignore.case = TRUE)
    zips <- unique(c(zips, inner))
    todo <- setdiff(normalizePath(zips, winslash = "/", mustWork = FALSE), seen)
    if (length(todo) == 0) break
    for (zf in todo) {
      dest <- file.path(extract_dir, tools::file_path_sans_ext(basename(zf)))
      dir.create(dest, recursive = TRUE, showWarnings = FALSE)
      ok <- tryCatch({ unzip(zf, exdir = dest); TRUE }, error = function(e) { monitora_log_registrar_evento("extracao_zip", "ERRO", zf, conditionMessage(e), "arquivo ignorado"); FALSE })
      if (ok) monitora_log_registrar_evento("extracao_zip", "INFO", zf, paste0("extraido em ", dest), "OK")
      seen <- c(seen, zf)
    }
  }
  invisible(seen)
}

# Identifica a cadeia de origem de cada CSV, incluindo ZIP externo e ZIP interno quando houver.
# Isso facilita a conferência operacional: o relatório mostra tanto o CSV interno quanto o ZIP
# baixado pelo usuário.
monitora_io_mapear_origem_arquivo <- function(paths, source_dirs = MONITORA_IO_DIRETORIOS_FONTE, extract_dir = MONITORA_EXTRACT_DIR) {
  paths_norm <- normalizePath(paths, winslash = "/", mustWork = FALSE)
  extract_norm <- normalizePath(extract_dir, winslash = "/", mustWork = FALSE)

  zip_sources <- unique(unlist(lapply(source_dirs, function(d) {
    if (!dir.exists(d)) character() else list.files(d, pattern = "\\.zip$", recursive = TRUE, full.names = TRUE, ignore.case = TRUE)
  })))
  zip_sources_norm <- normalizePath(zip_sources, winslash = "/", mustWork = FALSE)

  # Quando a origem é o diretório do script, list.files(..., recursive=TRUE)
  # também encontra ZIPs internos já extraídos em extracted/. Esses ZIPs internos não devem
  # ser tratados como "ZIP externo baixado pelo usuário". Mantê-los em zip_sources fazia
  # um ZIP interno aparecer como nome_zip_externo, em vez do pacote externo original
  # fornecido pelo usuário.
  if (length(zip_sources_norm) > 0) {
    bad_prefixes <- normalizePath(c(MONITORA_EXTRACT_DIR, MONITORA_OUTPUT_DIR, MONITORA_LOG_DIR), winslash = "/", mustWork = FALSE)
    keep <- rep(TRUE, length(zip_sources_norm))
    for (bp in bad_prefixes) {
      keep <- keep & !startsWith(zip_sources_norm, paste0(bp, "/")) & zip_sources_norm != bp
    }
    zip_sources_norm <- zip_sources_norm[keep]
  }

  zip_sources_base <- basename(zip_sources_norm)
  zip_sources_stem <- tools::file_path_sans_ext(zip_sources_base)

  # Indexa o conteúdo dos ZIPs externos originais.
  # Isso permite mapear um ZIP interno de coleta, como registros_j7n30yrt.zip,
  # de volta ao pacote baixado pelo usuário, mesmo que a extração recursiva
  # tenha colocado o CSV em extracted/registros_j7n30yrt/registros_*.csv.
  zip_index <- data.table::data.table(
    zip_externo = character(),
    nome_zip_externo = character(),
    item_zip = character(),
    nome_item_zip = character(),
    stem_item_zip = character()
  )
  if (length(zip_sources_norm) > 0) {
    for (zs in zip_sources_norm) {
      lst <- tryCatch(utils::unzip(zs, list = TRUE), error = function(e) NULL)
      if (!is.null(lst) && "Name" %in% names(lst) && nrow(lst) > 0) {
        zi <- data.table::data.table(
          zip_externo = zs,
          nome_zip_externo = basename(zs),
          item_zip = as.character(lst$Name),
          nome_item_zip = basename(as.character(lst$Name))
        )
        zi[, stem_item_zip := tools::file_path_sans_ext(nome_item_zip)]
        zip_index <- data.table::rbindlist(list(zip_index, zi), use.names = TRUE, fill = TRUE)
      }
    }
  }

  # ZIPs encontrados dentro da área extraída. Estes normalmente são ZIPs internos
  # de coleta, como registros_j7n30yrt.zip, contidos no pacote externo baixado.
  zip_extraidos <- if (dir.exists(extract_dir)) list.files(extract_dir, pattern = "\\.zip$", recursive = TRUE, full.names = TRUE, ignore.case = TRUE) else character()
  zip_extraidos_norm <- normalizePath(zip_extraidos, winslash = "/", mustWork = FALSE)
  zip_extraidos_base <- basename(zip_extraidos_norm)
  zip_extraidos_stem <- tools::file_path_sans_ext(zip_extraidos_base)

  top_zip_full_path <- function(nome_zip) {
    if (is.na(nome_zip) || !nzchar(nome_zip)) return(NA_character_)
    m <- which(zip_sources_base == nome_zip)
    if (length(m) > 0) return(zip_sources_norm[m[1]])
    NA_character_
  }

  external_from_inner_zip_name <- function(inner_zip_name) {
    if (is.na(inner_zip_name) || !nzchar(inner_zip_name) || nrow(zip_index) == 0) return(list(nome = NA_character_, arquivo = NA_character_))
    m <- zip_index[nome_item_zip == inner_zip_name]
    if (nrow(m) > 0) return(list(nome = m$nome_zip_externo[1], arquivo = m$zip_externo[1]))
    inner_stem <- tools::file_path_sans_ext(inner_zip_name)
    m <- zip_index[stem_item_zip == inner_stem]
    if (nrow(m) > 0) return(list(nome = m$nome_zip_externo[1], arquivo = m$zip_externo[1]))
    list(nome = NA_character_, arquivo = NA_character_)
  }

  external_from_rel_parts <- function(parts) {
    if (length(parts) < 1) return(list(nome = NA_character_, arquivo = NA_character_))

    # Caso 1: o primeiro componente do caminho extraído é o stem do pacote externo.
    cand_ext <- paste0(parts[1], ".zip")
    if (parts[1] %in% zip_sources_stem) {
      return(list(nome = cand_ext, arquivo = top_zip_full_path(cand_ext)))
    }

    # Caso 2: o primeiro componente é o stem do ZIP interno; procurar esse ZIP
    # dentro dos pacotes externos originais.
    cand_inner <- paste0(parts[1], ".zip")
    ext <- external_from_inner_zip_name(cand_inner)
    if (!is.na(ext$nome) && nzchar(ext$nome)) return(ext)

    # Caso 3: algum componente intermediário pode ser o stem do pacote externo.
    for (pp in parts) {
      cand <- paste0(pp, ".zip")
      if (pp %in% zip_sources_stem) {
        return(list(nome = cand, arquivo = top_zip_full_path(cand)))
      }
    }

    list(nome = NA_character_, arquivo = NA_character_)
  }

  inner_zip_from_rel_parts <- function(parts, nome_zip_externo = NA_character_) {
    if (length(parts) < 1) return(list(nome = NA_character_, arquivo = NA_character_))

    # Para CSVs extraídos de ZIP interno, o primeiro componente costuma ser
    # o stem do ZIP de coleta.
    cand_inner_name <- paste0(parts[1], ".zip")
    hits <- which(zip_extraidos_base == cand_inner_name | zip_extraidos_stem == parts[1])
    if (length(hits) > 0) {
      cand <- zip_extraidos_norm[hits]
      if (!is.na(nome_zip_externo) && nzchar(nome_zip_externo)) {
        top_stem <- tools::file_path_sans_ext(nome_zip_externo)
        preferred <- cand[grepl(paste0("/", top_stem, "/"), cand, fixed = TRUE)]
        if (length(preferred) > 0) cand <- preferred
      }
      return(list(nome = basename(cand[1]), arquivo = cand[1]))
    }

    # Se não houver o ZIP interno fisicamente no diretório extraído, mas ele
    # aparece indexado dentro do ZIP externo, ainda assim registrar o nome.
    ext <- external_from_inner_zip_name(cand_inner_name)
    if (!is.na(ext$nome) && nzchar(ext$nome)) {
      return(list(nome = cand_inner_name, arquivo = NA_character_))
    }

    list(nome = NA_character_, arquivo = NA_character_)
  }

  out <- data.table(
    arquivo = paths,
    arquivo_csv = paths_norm,
    nome_csv = basename(paths_norm),
    arquivo_entrada_externo = NA_character_,
    nome_arquivo_entrada_externo = NA_character_,
    arquivo_zip_externo = NA_character_,
    nome_zip_externo = NA_character_,
    arquivo_zip_interno = NA_character_,
    nome_zip_interno = NA_character_,
    caminho_relativo_extraido = NA_character_
  )

  for (i in seq_along(paths_norm)) {
    pn <- paths_norm[i]

    if (startsWith(pn, paste0(extract_norm, "/"))) {
      rel <- substring(pn, nchar(paste0(extract_norm, "/")) + 1)
      parts <- strsplit(rel, "/", fixed = TRUE)[[1]]
      out$caminho_relativo_extraido[i] <- rel

      ext <- external_from_rel_parts(parts)
      if (!is.na(ext$nome) && nzchar(ext$nome)) {
        out$nome_zip_externo[i] <- ext$nome
        out$arquivo_zip_externo[i] <- ext$arquivo
        out$nome_arquivo_entrada_externo[i] <- ext$nome
        out$arquivo_entrada_externo[i] <- ext$arquivo
      }

      inn <- inner_zip_from_rel_parts(parts, out$nome_zip_externo[i])
      if (!is.na(inn$nome) && nzchar(inn$nome)) {
        # Não registrar o pacote externo como ZIP interno quando o CSV está
        # diretamente no pacote externo, como no lote SISMONITORA.
        if (is.na(out$nome_zip_externo[i]) || !identical(inn$nome, out$nome_zip_externo[i])) {
          out$nome_zip_interno[i] <- inn$nome
          out$arquivo_zip_interno[i] <- inn$arquivo
        }
      }

      if ((is.na(out$arquivo_entrada_externo[i]) || !nzchar(out$arquivo_entrada_externo[i])) &&
          (!is.na(out$arquivo_zip_interno[i]) && nzchar(out$arquivo_zip_interno[i]))) {
        out$arquivo_entrada_externo[i] <- out$arquivo_zip_interno[i]
        out$nome_arquivo_entrada_externo[i] <- out$nome_zip_interno[i]
      }

    } else {
      out$arquivo_entrada_externo[i] <- pn
      out$nome_arquivo_entrada_externo[i] <- basename(pn)
      if (grepl("\\.zip$", pn, ignore.case = TRUE)) {
        out$arquivo_zip_externo[i] <- pn
        out$nome_zip_externo[i] <- basename(pn)
      }
    }
  }
  out[]
}

### v2.6.1 ----------------------------------
### Modos registros_corrig_* e painel_incremental_* retomam de um produto
### corrigido já produzido pelo script. Essa entrada não reconstrói
### registros_importados.csv e não mistura correções antigas com a sessão atual.
if (!exists("monitora_auditoria_anos_invalidos", mode = "function", inherits = TRUE)) {
  monitora_auditoria_anos_invalidos <- function(dt) {
    dt <- monitora_dt_referenciar(dt)
    if (!("ANO" %in% names(dt))) return(invisible(data.table::data.table()))
    ano_num <- suppressWarnings(as.integer(dt[["ANO"]]))
    ano_min <- 2000L
    ano_max <- lubridate::year(Sys.Date()) + 1L
    invalido <- is.na(ano_num) | ano_num < ano_min | ano_num > ano_max
    if (!any(invalido, na.rm = TRUE)) return(invisible(data.table::data.table()))
    cols <- intersect(
      c("UC", "CICLO", "CAMPANHA", "UA", "COLETA", "Data (data_hora)", "DATA_MONITORA_PARSEADA", "ANO", "MONITORA_ARQUIVO_ENTRADA", "MONITORA_TIPO_ENTRADA"),
      names(dt)
    )
    aud <- unique(dt[invalido, ..cols])
    data.table::set(aud, j = "ano_min_plausivel", value = ano_min)
    data.table::set(aud, j = "ano_max_plausivel", value = ano_max)
    data.table::set(aud, j = "acao_recomendada", value = "Corrigir a data original ou verificar erro de parsing; registros com ANO inválido/NA não devem ser usados para gráficos ou estatísticas temporais sem validação.")
    saida <- file.path(MONITORA_LOG_DIR, paste0("auditoria_anos_invalidos_", MONITORA_EXEC_ID, ".csv"))
    monitora_fwrite(aud, saida)
    monitora_fwrite(aud, file.path(MONITORA_OUTPUT_DIR, "auditoria_anos_invalidos_ultima_execucao.csv"))
    monitora_log_registrar_evento("anos_invalidos", "AVISO", saida, paste0(nrow(aud), " combinações com ANO inválido/NA ou fora da faixa plausível"), "ver auditoria_anos_invalidos")
    invisible(aud)
  }
}
if (!exists("monitora_auditoria_completude_101_pontos", mode = "function", inherits = TRUE)) {
  monitora_auditoria_completude_101_pontos <- function(dt) {
    dt <- monitora_dt_referenciar(dt)
    ponto_col <- if ("ponto_amostral (amostragem/registro)" %in% names(dt)) {
      "ponto_amostral (amostragem/registro)"
    } else if ("ponto_metro (amostragem/registro)" %in% names(dt)) {
      "ponto_metro (amostragem/registro)"
    } else {
      NA_character_
    }
    required <- c("UC", "CICLO", "CAMPANHA", "UA", "ANO")
    if (is.na(ponto_col) || !all(required %in% names(dt))) return(invisible(data.table::data.table()))
    fonte_col <- if ("MONITORA_ARQUIVO_ENTRADA" %in% names(dt)) "MONITORA_ARQUIVO_ENTRADA" else NA_character_
    aux <- dt[, c(required, ponto_col, if (!is.na(fonte_col)) fonte_col else NULL), with = FALSE]
    data.table::setnames(aux, ponto_col, "ponto_original")
    data.table::set(aux, j = "ponto_num", value = suppressWarnings(as.integer(gsub("[^0-9]+", "", as.character(aux$ponto_original)))))
    by_cols <- required
    resumo <- aux[, .(
      n_registros = .N,
      n_pontos = data.table::uniqueN(ponto_num[!is.na(ponto_num)]),
      pontos_fora_1_101 = paste(sort(unique(ponto_num[!is.na(ponto_num) & !ponto_num %between% c(1L, 101L)])), collapse = " | "),
      arquivos_origem = if (!is.na(fonte_col)) paste(sort(unique(na.omit(as.character(get(fonte_col))))), collapse = " | ") else NA_character_
    ), by = by_cols]
    dup <- aux[!is.na(ponto_num), .N, by = c(by_cols, "ponto_num")][N > 1L]
    dup_sum <- dup[, .(pontos_duplicados = paste(sort(unique(ponto_num)), collapse = " | ")), by = by_cols]
    resumo <- merge(resumo, dup_sum, by = by_cols, all.x = TRUE, sort = FALSE)
    resumo[is.na(pontos_duplicados), pontos_duplicados := ""]
    resumo[, pontos_ausentes := ""]
    prob_idx <- which(resumo$n_pontos != 101L | resumo$n_registros != 101L | nzchar(resumo$pontos_duplicados) | nzchar(resumo$pontos_fora_1_101))
    if (length(prob_idx) > 0L) {
      chaves_prob <- resumo[prob_idx, ..by_cols]
      aux_prob <- merge(aux, chaves_prob, by = by_cols, all.y = TRUE, sort = FALSE)
      miss <- aux_prob[, .(
        pontos_ausentes = paste(setdiff(1:101, sort(unique(ponto_num[!is.na(ponto_num) & ponto_num %between% c(1L, 101L)]))), collapse = " | ")
      ), by = by_cols]
      resumo <- merge(resumo, miss, by = by_cols, all.x = TRUE, suffixes = c("", "_calc"), sort = FALSE)
      resumo[!is.na(pontos_ausentes_calc), pontos_ausentes := pontos_ausentes_calc]
      resumo[, pontos_ausentes_calc := NULL]
    }
    aud <- resumo[n_pontos != 101L | n_registros != 101L | nzchar(pontos_duplicados) | nzchar(pontos_ausentes) | nzchar(pontos_fora_1_101)]
    if (nrow(aud) > 0L) {
      data.table::set(aud, j = "acao_recomendada", value = "Conferir se a UA/ano possui exatamente 101 pontos; corrigir pontos ausentes, duplicados ou fora de 1:101 antes de aceitar análises e gráficos.")
      saida <- file.path(MONITORA_LOG_DIR, paste0("auditoria_completude_101_pontos_", MONITORA_EXEC_ID, ".csv"))
      monitora_fwrite(aud, saida)
      monitora_fwrite(aud, file.path(MONITORA_OUTPUT_DIR, "auditoria_completude_101_pontos_ultima_execucao.csv"))
      monitora_log_registrar_evento("completude_101_pontos", "AVISO", saida, paste0(nrow(aud), " grupos UC+CICLO+CAMPANHA+UA+ANO com n_registros/n_pontos diferente de 101, duplicidade ou lacuna"), "ver auditoria_completude_101_pontos")
    }
    invisible(aud)
  }
}

monitora_registros_corrig_entrada_arquivo <- function() {
  cand <- list.files(MONITORA_INPUT_DIR, pattern = "^registros_corrig.*\\.csv$", full.names = TRUE, ignore.case = TRUE)
  if (!length(cand)) {
    stop("Modo ", MONITORA_MODO_EXECUCAO, " solicitado, mas nenhum registros_corrig*.csv foi encontrado em input/. Copie output/registros_corrig.csv para input/ antes de rodar.", call. = FALSE)
  }
  if (length(cand) > 1L) {
    stop("Modo ", MONITORA_MODO_EXECUCAO, " exige exatamente um registros_corrig*.csv em input/. Foram encontrados: ", paste(basename(cand), collapse = ", "), call. = FALSE)
  }
  normalizePath(cand[1L], winslash = "/", mustWork = TRUE)
}

monitora_registros_corrig_carregar_entrada <- function(modo) {
  MONITORA_IO_DIRETORIOS_FONTE <<- MONITORA_INPUT_DIR
  arq <- monitora_registros_corrig_entrada_arquivo()
  dt <- data.table::fread(arq, encoding = "UTF-8", na.strings = c("", "NA"), colClasses = "character", showProgress = FALSE)
  dt <- data.table::as.data.table(dt)
  if (!("COLETA" %in% names(dt))) {
    stop("O arquivo ", basename(arq), " não possui coluna obrigatória COLETA. Use um registros_corrig.csv produzido pelo script.", call. = FALSE)
  }
  if (!("MONITORA_TIPO_ENTRADA" %in% names(dt))) data.table::set(dt, j = "MONITORA_TIPO_ENTRADA", value = "registros_corrig")
  if (!("MONITORA_ARQUIVO_ENTRADA" %in% names(dt))) data.table::set(dt, j = "MONITORA_ARQUIVO_ENTRADA", value = basename(arq))
  aud <- data.table::data.table(
    arquivo = arq,
    nome_arquivo = basename(arq),
    modo_execucao = modo,
    n_linhas = nrow(dt),
    n_colunas = ncol(dt),
    tamanho_bytes = as.numeric(file.info(arq)$size),
    status = "carregado_como_registros_corrig",
    observacao = "Entrada retomada a partir de registros_corrig.csv; registros_importados.csv não é reconstruído e correções antigas não são reaplicadas implicitamente."
  )
  monitora_fwrite(aud, file.path(MONITORA_LOG_DIR, paste0("auditoria_registros_corrig_entrada_", MONITORA_EXEC_ID, ".csv")), na = "")
  monitora_fwrite(aud, file.path(MONITORA_OUTPUT_DIR, "auditoria_registros_corrig_entrada_ultima_execucao.csv"), na = "")
  monitora_log_registrar_evento("registros_corrig_entrada", "INFO", arq, paste0("registros_corrig carregado com ", nrow(dt), " linhas e ", ncol(dt), " colunas"), "retomada por produto corrigido")
  if (exists("monitora_registros_importados_auditar_nao_aplicavel", mode = "function")) {
    monitora_registros_importados_auditar_nao_aplicavel(
      output_dir = MONITORA_OUTPUT_DIR,
      log_dir = MONITORA_LOG_DIR,
      exec_id = MONITORA_EXEC_ID,
      modo = modo,
      arquivo_entrada = arq
    )
  }
  monitora_publicacao_p_auditar_schema_pre_painel(dt, contexto = paste0("entrada_registros_corrig_", modo))
  dt[]
}

if (isTRUE(MONITORA_MODO_USA_REGISTROS_CORRIG_ENTRADA)) {
  registros_corrig <- monitora_registros_corrig_carregar_entrada(MONITORA_MODO_EXECUCAO)
  MONITORA_AUDITORIA_ANOS_INVALIDOS <- monitora_auditoria_anos_invalidos(registros_corrig)
  MONITORA_AUDITORIA_COMPLETUDE_101_PONTOS <- monitora_auditoria_completude_101_pontos(registros_corrig)
  monitora_perf_registrar_checkpoint("leitura_registros_corrig_entrada", paste0("retomada por registros_corrig.csv no modo ", MONITORA_MODO_EXECUCAO), registros_corrig)
} else {

### Origem dos dados: arquivos de entrada são aceitos
### exclusivamente em input/. Arquivos ZIP/CSV/XLSX/XLS na raiz do diretório do
### script bloqueiam a execução para forçar conferência operacional explícita do
### conteúdo de input/ antes de cada rodada.
MONITORA_IO_DIRETORIOS_FONTE <- MONITORA_INPUT_DIR
monitora_input_conteudo <- if (dir.exists(MONITORA_INPUT_DIR)) {
  list.files(MONITORA_INPUT_DIR, recursive = TRUE, all.files = FALSE, no.. = TRUE)
} else character()
monitora_root_input_like <- list.files(
  MONITORA_BASE_DIR,
  pattern = "\\.(zip|csv|xlsx|xls)$",
  recursive = FALSE,
  full.names = TRUE,
  ignore.case = TRUE
)
if (length(monitora_root_input_like) > 0L) {
  aud_root <- data.table::data.table(
    arquivo = normalizePath(monitora_root_input_like, winslash = "/", mustWork = FALSE),
    nome_arquivo = basename(monitora_root_input_like),
    motivo = "arquivo_de_entrada_na_raiz_nao_aceito",
    acao_requerida = "mover para input/ se deve ser usado; remover da raiz se não deve ser usado"
  )
  monitora_fwrite(aud_root, file.path(MONITORA_LOG_DIR, paste0("arquivos_entrada_na_raiz_bloqueados_", MONITORA_EXEC_ID, ".csv")))
  monitora_fwrite(aud_root, file.path(MONITORA_OUTPUT_DIR, "arquivos_entrada_na_raiz_bloqueados_ultima_execucao.csv"))
  stop(
    "Arquivos ZIP/CSV/XLSX/XLS encontrados na raiz do diretório do script. ",
    "A entrada agora deve ficar exclusivamente em input/. ",
    "Mova os arquivos que deseja processar para input/ e remova os demais da raiz. ",
    "Ver log/arquivos_entrada_na_raiz_bloqueados_*.csv.",
    call. = FALSE
  )
}
if (length(monitora_input_conteudo) == 0L) {
  stop(
    "Nenhum arquivo encontrado em input/. A pasta input/ foi criada pelo script se não existia. ",
    "Coloque os ZIP/CSV/XLSX do SISMONITORA ou registros_corrig*.csv em input/ e execute novamente.",
    call. = FALSE
  )
}
monitora_log_registrar_evento("configuracao", "INFO", MONITORA_IO_DIRETORIOS_FONTE, "diretorio de origem selecionado", "input/ obrigatório")
monitora_perf_registrar_checkpoint("configuracao_inicial", paste0("origem obrigatória: ", MONITORA_IO_DIRETORIOS_FONTE))

### Extração recursiva de ZIPs, incluindo ZIPs internos dentro de ZIPs.
monitora_io_extrair_zips_recursivos(MONITORA_IO_DIRETORIOS_FONTE, MONITORA_EXTRACT_DIR)
monitora_recurso_controlar("apos_extracao_recursiva_zips", risco = "normal", force_log = TRUE)
monitora_perf_registrar_checkpoint("extracao_recursiva_zips", "extração de ZIPs externos e internos")

### Conversão defensiva de XLSX para CSV apenas nas áreas de entrada/extração, não em output/log.
xlsx_files <- list.files(c(MONITORA_IO_DIRETORIOS_FONTE, MONITORA_EXTRACT_DIR), pattern = "\\.xlsx$", recursive = TRUE, full.names = TRUE, ignore.case = TRUE)
xlsx_files <- xlsx_files[!grepl("/(output|log)/", normalizePath(xlsx_files, winslash = "/", mustWork = FALSE))]
for (xlsx_file in xlsx_files) {
  csv_file <- sub("\\.xlsx$", ".csv", xlsx_file, ignore.case = TRUE)
  if (!file.exists(csv_file)) {
    data <- read_excel(xlsx_file)
    data.table::fwrite(data.table::as.data.table(monitora_sanitizar_ausencias_produto(data)), file = csv_file, na = "NA")
    monitora_log_registrar_evento("conversao_xlsx", "INFO", xlsx_file, paste0("convertido para ", csv_file), "OK")
  } else {
    monitora_log_registrar_evento("conversao_xlsx", "INFO", xlsx_file, paste0("CSV ja existente: ", csv_file), "mantido")
  }
}
monitora_rm_seguro("data", "csv_file", "xlsx_file", "xlsx_files")
monitora_perf_registrar_checkpoint("conversao_xlsx", "conversão defensiva de XLSX para CSV, quando aplicável")

### Leitura e concatenação dos CSVs de entrada.
### Importante: arquivos registros_corrig*.csv são aceitos como entrada válida apenas quando colocados em
### input/, pois é comum usar produtos pós-tratamento como base para nova rodada.
### Apenas output/, log/ e produtos analíticos/relatórios são excluídos automaticamente.
all_csvfiles <- list.files(c(MONITORA_IO_DIRETORIOS_FONTE, MONITORA_EXTRACT_DIR), pattern = "\\.csv$", recursive = TRUE, full.names = TRUE, ignore.case = TRUE)
all_csvfiles_norm <- normalizePath(all_csvfiles, winslash = "/", mustWork = FALSE)
all_csvfiles_base <- basename(all_csvfiles_norm)

# Exclusões de diretórios gerenciados pelo próprio script.
# Importante: quando MONITORA_IO_DIRETORIOS_FONTE = MONITORA_BASE_DIR, list.files(recursive=TRUE)
# também encontraria produtos antigos em output/, log/ e extrações antigas.
exclude_dirs <- grepl("/(output|log|plots_png)/", all_csvfiles_norm)

# v2.6.1: a pasta de oráculo/referência pode ficar dentro de input/ para
# comparação diagnóstica, mas seus CSVs nunca são dados de campo.
exclude_oraculo <- grepl("/(oraculo_replay|referencia_replay|diagnostico_run_referencia)/", all_csvfiles_norm, ignore.case = TRUE)

# Exclusões de produtos analíticos/relatórios conhecidos.
# NÃO exclui registros_corrig*.csv: estes podem ser insumos válidos de nova rodada
# quando o usuário os coloca deliberadamente em input/.
exclude_outputs <- grepl(
  "^(registros_corrig_stat|sum_|cob_|prop_rel_|relatorio_execucao|auditoria_|duplicidades_|conflitos_)",
  all_csvfiles_base,
  ignore.case = TRUE
)

# v2.6.1: arquivos de controle de correção/replay não são dados de campo.
# Eles podem ficar em input/ para controlar a reaplicação, mas nunca podem ser
# lidos na concatenação de registros do SISMONITORA. A v2.6.1/v2.6.3 aceitava
# input/correcoes_semanticas.csv como candidato a CSV de dados, o que contaminava
# registros_importados.csv com colunas como id_correcao, tipo_correcao, acao,
# responsavel e uuid_registro.
monitora_io_eh_csv_controle_correcao <- function(nome_arquivo) {
  bn <- tolower(basename(as.character(nome_arquivo)))
  grepl(
    paste0(
      "^(",
      "correcoes_semanticas",
      "|correcoes_campos",
      "|correcoes_espaciais",
      "|modelo_correcoes_campos",
      "|auditoria_reaplicacao",
      "|auditoria_correcoes_campos",
      ")",
      "([_.].*)?\\.csv$"
    ),
    bn,
    perl = TRUE
  )
}
exclude_controle_correcao <- monitora_io_eh_csv_controle_correcao(all_csvfiles_base)

csvfiles_excluidos <- unique(all_csvfiles[exclude_dirs | exclude_oraculo | exclude_outputs | exclude_controle_correcao])
if (length(csvfiles_excluidos) > 0) {
  motivos_excl <- ifelse(
    exclude_controle_correcao[match(csvfiles_excluidos, all_csvfiles)],
    "arquivo_controle_correcao_replay_nao_importado_como_dado",
    ifelse(
      exclude_oraculo[match(csvfiles_excluidos, all_csvfiles)],
      "arquivo_oraculo_replay_nao_importado_como_dado",
      ifelse(
        grepl("^(registros_corrig_stat|sum_|cob_|prop_rel_|relatorio_execucao|auditoria_|duplicidades_|conflitos_)",
              basename(csvfiles_excluidos), ignore.case = TRUE),
        "produto_analitico_saida_ou_relatorio",
        "diretorio_gerenciado_output_log"
      )
    )
  )
  monitora_fwrite(
    data.table(
      arquivo = csvfiles_excluidos,
      motivo = motivos_excl
    ),
    file.path(MONITORA_LOG_DIR, paste0("arquivos_csv_excluidos_da_importacao_", MONITORA_EXEC_ID, ".csv"))
  )
  monitora_fwrite(
    data.table(
      arquivo = csvfiles_excluidos,
      motivo = motivos_excl
    ),
    file.path(MONITORA_OUTPUT_DIR, "arquivos_csv_excluidos_da_importacao_ultima_execucao.csv")
  )
  if (any(motivos_excl == "arquivo_controle_correcao_replay_nao_importado_como_dado")) {
    monitora_log_registrar_evento(
      "filtro_csv_entrada",
      "INFO",
      paste(basename(csvfiles_excluidos[motivos_excl == "arquivo_controle_correcao_replay_nao_importado_como_dado"]), collapse = " | "),
      paste0(sum(motivos_excl == "arquivo_controle_correcao_replay_nao_importado_como_dado"), " CSV(s) de controle de correção/replay excluído(s) da importação de dados"),
      "arquivo usado apenas como controle de reaplicação, não como registro SISMONITORA"
    )
  }
  if (any(motivos_excl == "arquivo_oraculo_replay_nao_importado_como_dado")) {
    monitora_log_registrar_evento(
      "filtro_csv_entrada",
      "INFO",
      paste(basename(csvfiles_excluidos[motivos_excl == "arquivo_oraculo_replay_nao_importado_como_dado"]), collapse = " | "),
      paste0(sum(motivos_excl == "arquivo_oraculo_replay_nao_importado_como_dado"), " CSV(s) da run-oráculo excluído(s) da importação de dados"),
      "arquivos usados apenas como oráculo diagnóstico, não como registros SISMONITORA"
    )
  }
  monitora_log_registrar_evento(
    "filtro_csv_entrada",
    "INFO",
    NA_character_,
    paste0(length(csvfiles_excluidos), " CSVs excluidos da importacao por filtro de output/log/produtos/controle de correções"),
    "ver arquivos_csv_excluidos_da_importacao"
  )
}

csvfiles <- unique(all_csvfiles[!exclude_dirs & !exclude_oraculo & !exclude_outputs & !exclude_controle_correcao])
monitora_recurso_controlar("filtro_csv_entrada", risco = if (length(csvfiles) > 1000) "alto" else "normal", force_log = TRUE)
monitora_perf_registrar_checkpoint("filtro_csv_entrada", paste0(length(csvfiles), " CSV(s) candidatos após filtros"))

# Classificação formal de origem por nome de arquivo e cabeçalho.
