### extração do ANO a partir da DATA. O SISMONITORA exportou datas em diferentes formatos. A função
### a seguir faz a coerção dos formatos identificados

if ("Data (data_hora)" %in% names(registros_corrig) || (!is.na(monitora_correcao_colunas_chave(registros_corrig)$data_hora) && monitora_correcao_colunas_chave(registros_corrig)$data_hora %in% names(registros_corrig))) {
  registros_corrig <- monitora_recalcular_derivados_data_hora(registros_corrig, contexto = "extracao_ano_data")
} else {
  registros_corrig[, ANO := NA_character_]
  monitora_log_registrar_evento("datas", "ERRO", NA_character_, "Coluna Data (data_hora) ausente", "ANO criado como NA")
}
monitora_perf_registrar_checkpoint("extracao_ano_data", "coerção de datas e criação/padronização do campo ANO", registros_corrig)
# Deduplicação final: após ANO estar calculado e antes das auditorias/estatísticas,
# remove sobreposições residuais por UC+CICLO+CAMPANHA+UA+ANO+ponto.
registros_corrig <- monitora_deduplicar_final_por_ponto_ano(registros_corrig)
registros_corrig <- monitora_dt_remover_colunas_tecnicas_legadas(registros_corrig, "pos_deduplicacao_final_ponto_ano")
monitora_recurso_controlar("deduplicacao_final_ponto_ano", risco = "alto", objeto = registros_corrig, force_log = TRUE)
monitora_perf_registrar_checkpoint("deduplicacao_final_ponto_ano", "trava final por UC+CICLO+CAMPANHA+UA+ANO+ponto antes das estatísticas", registros_corrig)

MONITORA_AUDITORIA_ANOS_INVALIDOS <- monitora_auditoria_anos_invalidos(registros_corrig)
MONITORA_AUDITORIA_COMPLETUDE_101_PONTOS <- monitora_auditoria_completude_101_pontos(registros_corrig)
monitora_perf_registrar_checkpoint("auditoria_datas_pontos", "auditoria de ANO plausível e completude de 101 pontos", registros_corrig)

}

### Tratamento robusto das coordenadas manipuladas em SISMONITORA/Excel/R.
### A função preserva latitude/longitude quando há apenas 2 tokens e aceita 4 tokens quando
### altitude/acurácia existem.
### Também detecta separador por registro e registra auditoria, evitando substituir vírgulas
### decimais cegamente.
coord_cols <- c(
  "Coordenada inicial da amostragem (amostragem)",
  "Coordenada final da amostragem (amostragem)"
)
coord_audit_all_list <- if (isTRUE(MONITORA_AUDITORIA_COORDENADAS_COMPLETA)) list() else NULL
coord_audit_all_i <- 0L
coord_audit_summary_list <- list()
coord_audit_summary_i <- 0L
for (cc in coord_cols) {
  if (cc %in% names(registros_corrig)) {
    normalizada <- monitora_geo_normalizar_coordenada(registros_corrig[[cc]])
    ca <- attr(normalizada, "coord_audit")
    ca[, coluna := cc]
    if (isTRUE(MONITORA_AUDITORIA_COORDENADAS_COMPLETA)) {
      ca[, arquivo_origem := as.character(registros_corrig$.id)]
      coord_audit_all_i <- coord_audit_all_i + 1L
      coord_audit_all_list[[coord_audit_all_i]] <- ca
    }
    coord_audit_summary_i <- coord_audit_summary_i + 1L
    coord_audit_summary_list[[coord_audit_summary_i]] <- ca[, .N, by = .(coluna, separador_detectado, n_tokens)]
    registros_corrig[[cc]] <- normalizada
    rm(ca, normalizada); monitora_recurso_gc(paste0("coordenadas_", cc))
  } else {
    monitora_log_registrar_evento("coordenadas", "AVISO", NA_character_, paste0("Coluna ausente: ", cc), "mantida ausente")
  }
}
coord_audit_all <- if (isTRUE(MONITORA_AUDITORIA_COORDENADAS_COMPLETA) && coord_audit_all_i > 0L) {
  data.table::rbindlist(coord_audit_all_list[seq_len(coord_audit_all_i)], fill = TRUE, use.names = TRUE)
} else NULL
coord_audit_summary <- if (coord_audit_summary_i > 0L) {
  data.table::rbindlist(coord_audit_summary_list[seq_len(coord_audit_summary_i)], fill = TRUE, use.names = TRUE)
} else data.table::data.table()
rm(coord_audit_all_list, coord_audit_summary_list, coord_audit_all_i, coord_audit_summary_i)
if (nrow(coord_audit_summary) > 0) {
  monitora_fwrite(coord_audit_summary, file.path(MONITORA_LOG_DIR, paste0("auditoria_coordenadas_resumo_", MONITORA_EXEC_ID, ".csv")))
  monitora_log_registrar_evento("coordenadas", "INFO", NA_character_, paste0(nrow(coord_audit_summary), " linhas de resumo de auditoria de coordenadas geradas"), "ver auditoria_coordenadas_resumo")
}
if (isTRUE(MONITORA_AUDITORIA_COORDENADAS_COMPLETA) && !is.null(coord_audit_all) && nrow(coord_audit_all) > 0) {
  monitora_fwrite(coord_audit_all, file.path(MONITORA_LOG_DIR, paste0("auditoria_coordenadas_", MONITORA_EXEC_ID, ".csv")))
  monitora_log_registrar_evento("coordenadas", "INFO", NA_character_, paste0(nrow(coord_audit_all), " registros de auditoria completa de coordenadas gerados"), "ver auditoria_coordenadas; para lotes grandes, manter MONITORA_AUDITORIA_COORDENADAS_COMPLETA=false")
}
rm(coord_cols, coord_audit_all, coord_audit_summary); monitora_recurso_gc("coordenadas_fim")


monitora_relatorio_exoticas_normalizar_texto <- function(x) {
  x <- as.character(x)
  x[is.na(x)] <- ""
  x <- gsub("\\s+", " ", x, perl = TRUE)
  trimws(x)
}

monitora_relatorio_exoticas_sem_valor <- function(x) {
  z <- monitora_relatorio_exoticas_normalizar_texto(x)
  zl <- tolower(z)
  !nzchar(z) | zl %in% c(
    "na", "nan", "null", "none", "n/a", "não se aplica", "nao se aplica",
    "sem registro", "sem_registro", "não informado", "nao informado",
    "---", "--", "-", ".", "...", "_", "[]", "{}", "false", "falso", "0"
  )
}

monitora_relatorio_exoticas_tem_valor <- function(x) {
  !monitora_relatorio_exoticas_sem_valor(x)
}

monitora_relatorio_exoticas_normalizar_token <- function(x) {
  x <- as.character(x)
  x[is.na(x)] <- ""
  x2 <- suppressWarnings(iconv(x, from = "", to = "ASCII//TRANSLIT"))
  x[!is.na(x2)] <- x2[!is.na(x2)]
  x <- tolower(x)
  x <- gsub("[^a-z0-9_]+", "_", x, perl = TRUE)
  x <- gsub("_+", "_", x, perl = TRUE)
  x <- gsub("^_|_$", "", x, perl = TRUE)
  x
}

monitora_relatorio_exoticas_tokenizar <- function(x) {
  z <- monitora_relatorio_exoticas_normalizar_texto(x)
  z2 <- suppressWarnings(iconv(z, from = "", to = "ASCII//TRANSLIT"))
  z[!is.na(z2)] <- z2[!is.na(z2)]
  z <- tolower(z)
  z <- gsub("[,;|/]+", " ", z, perl = TRUE)
  z <- gsub("\\s+", " ", z, perl = TRUE)
  z <- trimws(z)
  lapply(strsplit(z, " ", fixed = TRUE), function(v) {
    v <- v[!is.na(v) & nzchar(v)]
    v <- monitora_relatorio_exoticas_normalizar_token(v)
    v[!is.na(v) & nzchar(v)]
  })
}

monitora_relatorio_exoticas_tem_token <- function(x, tokens) {
  tokens <- unique(monitora_relatorio_exoticas_normalizar_token(tokens))
  tokens <- tokens[!is.na(tokens) & nzchar(tokens)]
  n <- length(x)
  if (!length(tokens)) return(rep(FALSE, n))

  ### Caminho vetorizado por regex para evitar lapply()+vapply()
  ### linha-a-linha em relatórios pré/pós-painel. A normalização preserva a regra
  ### operacional de token completo: "exotica" não casa como substring de outra palavra.
  if (isTRUE(get0("MONITORA_OPCAO_RELATORIOS_SUPORTE_TOKEN_REGEX_VETORIZADO", ifnotfound = "S", inherits = TRUE) == "S")) {
    z <- as.character(x)
    z[is.na(z)] <- ""
    z2 <- suppressWarnings(iconv(z, from = "", to = "ASCII//TRANSLIT"))
    z[!is.na(z2)] <- z2[!is.na(z2)]
    z <- tolower(z)
    z <- gsub("[,;|/]+", " ", z, perl = TRUE)
    z <- gsub("[^a-z0-9_]+", " ", z, perl = TRUE)
    z <- gsub("\\s+", " ", z, perl = TRUE)
    z <- trimws(z)
    if (!length(z)) return(logical(0))
    tok_regex <- paste(tokens, collapse = "|")
    return(grepl(paste0("(^|\\s)(", tok_regex, ")($|\\s)"), z, perl = TRUE))
  }

  lx <- monitora_relatorio_exoticas_tokenizar(x)
  vapply(lx, function(v) any(v %in% tokens), logical(1))
}

monitora_relatorio_exoticas_resolver_colunas <- function(dt, candidatos = character(0), permitir_multiplas = TRUE) {
  nms <- names(dt)
  if (!length(nms) || !length(candidatos)) return(character(0))
  out <- character(0)
  nms_norm <- monitora_relatorio_exoticas_normalizar_token(nms)

  for (cand in candidatos) {
    if (is.na(cand) || !nzchar(as.character(cand))) next
    cand <- as.character(cand)
    if (cand %in% nms) {
      out <- c(out, cand)
      if (!isTRUE(permitir_multiplas)) return(out[1])
      next
    }

    hit_ci <- nms[tolower(nms) == tolower(cand)]
    if (length(hit_ci)) {
      out <- c(out, hit_ci[1])
      if (!isTRUE(permitir_multiplas)) return(out[1])
      next
    }

    cand_norm <- monitora_relatorio_exoticas_normalizar_token(cand)
    hit_norm <- which(nms_norm == cand_norm)
    if (length(hit_norm)) {
      out <- c(out, nms[hit_norm[1]])
      if (!isTRUE(permitir_multiplas)) return(out[1])
      next
    }
  }

  unique(out)
}

monitora_relatorio_exoticas_detectar_colunas_forma <- function(dt) {
  preferenciais <- c(
    "amostragem/registro/forma_vida_exotica",
    "forma_vida_exotica",
    "Formas de vida de plantas <span style=\"\"color:red\"\">exóticas:</span> (amostragem/registro)",
    "Formas de vida de plantas <span style=\"color:red\">exóticas:</span> (amostragem/registro)",
    "Formas de vida de plantas <span style=\"\"color:red\"\">exoticas:</span> (amostragem/registro)",
    "Formas de vida de plantas exóticas: (amostragem/registro)",
    "Formas de vida de plantas exoticas: (amostragem/registro)"
  )
  cols <- monitora_relatorio_exoticas_resolver_colunas(dt, preferenciais, permitir_multiplas = TRUE)
  nms <- names(dt)
  nms_norm <- monitora_relatorio_exoticas_normalizar_token(nms)
  padrao <- grepl("formas_de_vida_de_plantas.*exotic", nms_norm) |
    grepl("^amostragem_registro_forma_vida_exotica$", nms_norm) |
    grepl("^forma_vida_exotica$", nms_norm)
  unique(c(cols, nms[padrao]))
}

