    n_UA_pareadas = integer(),
    media_linha_base = numeric(),
    media_ano_2 = numeric(),
    diferenca = numeric(),
    diferenca_pp = numeric(),
    ci95_lower = numeric(),
    ci95_upper = numeric(),
    ci95_lower_pp = numeric(),
    ci95_upper_pp = numeric(),
    p_valor_perm_pareado = numeric(),
